window.GITA={"translators":{"purohit":{"name":"Shri Purohit Swami","year":1935,"n":701,"src":"Faber & Faber (open data, bhagavadgita.io)"},"sivananda":{"name":"Swami Sivananda","year":1942,"n":701,"src":"Divine Life Society (open data)"},"adidevananda":{"name":"Swami Adidevananda","year":1974,"n":701,"src":"Sri Ramakrishna Math (open data)"},"gambirananda":{"name":"Swami Gambhirananda","year":1984,"n":701,"src":"Advaita Ashrama (open data)"},"sankaranarayan":{"name":"Dr. S. Sankaranarayan","year":1995,"n":701,"src":"open data, bhagavadgita.io"},"telang":{"name":"Kashinath Telang","year":1882,"n":1,"src":"Sacred Books of the East (PD)"},"arnold":{"name":"Edwin Arnold","year":1885,"n":13,"src":"The Song Celestial (PD)"}},"order":["purohit","sivananda","adidevananda","gambirananda","sankaranarayan","telang","arnold"],"chapters":[{"n":1,"sa":"Arjuna Viṣāda Yoga","en":"Arjuna's despair","from":1,"to":47},{"n":2,"sa":"Sāṅkhya Yoga","en":"The counsel of knowledge","from":48,"to":119},{"n":3,"sa":"Karma Yoga","en":"The path of action","from":120,"to":162},{"n":4,"sa":"Jñāna Karma Sannyāsa Yoga","en":"Knowledge and renunciation","from":163,"to":204},{"n":5,"sa":"Karma Sannyāsa Yoga","en":"Renouncing the fruits","from":205,"to":233},{"n":6,"sa":"Dhyāna Yoga","en":"Meditation","from":234,"to":280},{"n":7,"sa":"Jñāna Vijñāna Yoga","en":"Knowing and realizing","from":281,"to":310},{"n":8,"sa":"Akṣara Brahma Yoga","en":"The imperishable","from":311,"to":338},{"n":9,"sa":"Rāja Vidyā Yoga","en":"The royal secret","from":339,"to":372},{"n":10,"sa":"Vibhūti Yoga","en":"The divine glories","from":373,"to":414},{"n":11,"sa":"Viśvarūpa Darśana Yoga","en":"The cosmic vision","from":415,"to":469},{"n":12,"sa":"Bhakti Yoga","en":"The path of love","from":470,"to":489},{"n":13,"sa":"Kṣetra Kṣetrajña Vibhāga Yoga","en":"The field and its knower","from":490,"to":524},{"n":14,"sa":"Guṇatraya Vibhāga Yoga","en":"The three strands","from":525,"to":551},{"n":15,"sa":"Puruṣottama Yoga","en":"The supreme person","from":552,"to":571},{"n":16,"sa":"Daivāsura Sampad Vibhāga Yoga","en":"The bright and the dark","from":572,"to":595},{"n":17,"sa":"Śraddhātraya Vibhāga Yoga","en":"The threefold faith","from":596,"to":623},{"n":18,"sa":"Mokṣa Sannyāsa Yoga","en":"Freedom and surrender","from":624,"to":701}],"verses":[{"ch":1,"vn":1,"dev":"धृतराष्ट्र उवाच\nधर्मक्षेत्रे कुरुक्षेत्रे समवेता युयुत्सवः।\nमामकाः पाण्डवाश्चैव किमकुर्वत सञ्जय","iast":"dhṛitarāśhtra uvācha\ndharma-kṣhetre kuru-kṣhetre samavetā yuyutsavaḥ\nmāmakāḥ pāṇḍavāśhchaiva kimakurvata sañjaya","v":[{"k":"purohit","t":"The King Dhritarashtra asked, \"O Sanjaya! What happened on the sacred battlefield of Kurukshetra when my people and the Pandavas gathered?\""},{"k":"sivananda","t":"Dhritarashtra said, \"What did my people and the sons of Pandu do when they had assembled together, eager for battle, on the holy plain of Kurukshetra, O Sanjaya?\""},{"k":"adidevananda","t":"Dhṛtarāṣṭra said: \"O Sanjaya, what did my people and the Pāṇḍavas do, gathered together on the holy field of Kurukshetra, eager for battle?\""},{"k":"gambirananda","t":"Dhṛtarāṣṭra said: O Sanjaya, what did my sons and the sons of Pandu do when they assembled on the sacred field of Kurukshetra, eager for battle?"},{"k":"sankaranarayan","t":"Dhritarashtra said, \"O Sanjaya, what did my sons and the sons of Pandu do in the Kurukshetra, the field of righteousness, where the entire warring class had assembled?\""}]},{"ch":1,"vn":2,"dev":"सञ्जय उवाच\nदृष्ट्वा तु पाण्डवानीकं व्यूढं दुर्योधनस्तदा।\nआचार्यमुपसङ्गम्य राजा वचनमब्रवीत्","iast":"sañjaya uvācha\ndṛiṣhṭvā tu pāṇḍavānīkaṁ vyūḍhaṁ duryodhanastadā\nāchāryamupasaṅgamya rājā vachanamabravīt","v":[{"k":"purohit","t":"Sanjaya replied: \"When Prince Duryodhana saw the Pandavas' army paraded, he approached his preceptor Guru Drona and spoke these words:"},{"k":"sivananda","t":"Sanjaya said: Having seen the army of the Pandavas drawn up in battle array, King Duryodhana approached his teacher, Drona, and spoke these words."},{"k":"adidevananda","t":"Sanjaya said: King Duryodhana, upon seeing the Pandava army in battle array, approached his teacher Drona and said these words."},{"k":"gambirananda","t":"Sanjaya said: But then, seeing the army of the Pandavas in battle array, King Duryodhana approached the teacher, Drona, and spoke."},{"k":"sankaranarayan","t":"Sanjaya said: Seeing the army of the sons of Pandu marshaled in military array, the prince Duryodhana approached the teacher Drona and spoke these words at that time:"}]},{"ch":1,"vn":3,"dev":"पश्यैतां पाण्डुपुत्राणामाचार्य महतीं चमूम्।\nव्यूढां द्रुपदपुत्रेण तव शिष्येण धीमता","iast":"paśhyaitāṁ pāṇḍu-putrāṇām āchārya mahatīṁ chamūm\nvyūḍhāṁ drupada-putreṇa tava śhiṣhyeṇa dhīmatā","v":[{"k":"purohit","t":"Revered Father! Behold this mighty host of the Pandavas, paraded by the son of King Drupada, your wise disciple."},{"k":"sivananda","t":"Behold, O Teacher! This mighty army of the sons of Pandu, arrayed by the son of Drupada, thy wise disciple."},{"k":"adidevananda","t":"Behold, O teacher, this mighty army of the Pandavas, arrayed by the son of Drupada, your intelligent disciple."},{"k":"gambirananda","t":"O teacher, behold this vast army of the sons of Pandu, arrayed for battle by the intelligent disciple of Drupada."},{"k":"sankaranarayan","t":"O teacher! Behold this mighty army of the sons of Pandu, marshaled in a military array by Drupada's son, your intelligent pupil."}]},{"ch":1,"vn":4,"dev":"अत्र शूरा महेष्वासा भीमार्जुनसमा युधि।\nयुयुधानो विराटश्च द्रुपदश्च महारथः","iast":"atra śhūrā maheṣhvāsā bhīmārjuna-samā yudhi\nyuyudhāno virāṭaśhcha drupadaśhcha mahā-rathaḥ","v":[{"k":"purohit","t":"In it are heroes and great bowmen; the equals in battle of Arjuna, Bheema, Yuyudhana, Virata, and Drupada—all great soldiers."},{"k":"sivananda","t":"Here are heroes, mighty archers, equal in battle to Bhima and Arjuna, Yuyudhana (Satyaki), Virata, and Drupada—all mighty warriors."},{"k":"adidevananda","t":"There (in that army) are heroes, great bowmen, such as Bhima and Arjuna; Yuyudhana, Virata, and Drupada, a mighty warrior;"},{"k":"gambirananda","t":"Here are the heroes wielding great bows, who in battle are peers of Bhima and Arjuna: Yuyudhana (Satyaki) and Virata, and the maharatha (great chariot-rider) Drupada;"},{"k":"sankaranarayan","t":"Here are the heroes and mighty archers, comparable in war to Bhima and Arjuna: Yuyudhana, the king of the Virata country, and Drupada, the mighty warrior."}]},{"ch":1,"vn":5,"dev":"धृष्टकेतुश्चेकितानः काशिराजश्च वीर्यवान्।\nपुरुजित्कुन्तिभोजश्च शैब्यश्च नरपुङ्गवः","iast":"dhṛiṣhṭaketuśhchekitānaḥ kāśhirājaśhcha vīryavān\npurujit kuntibhojaśhcha śhaibyaśhcha nara-puṅgavaḥ\nyudhāmanyuśhcha vikrānta uttamaujāśhcha vīryavān","v":[{"k":"purohit","t":"Dhrishtaketu, Chekitan, the valiant king of Benares, Purujit, Kuntibhoja, and Shaibya—a master of many."},{"k":"sivananda","t":"Dhrishtaketu, Chekitana, the valiant king of Kasi, Purujit, Kuntibhoja, and Saibya—the best of men."},{"k":"adidevananda","t":"Dhrstaketu, Cekitana, the valiant king of Kasi, Purujit, Kuntibhoja, and Saibya, the best among men;"},{"k":"gambirananda","t":"Dhrstaketu, Cekitana, and the valiant king of Kasi (Varanasi); Purujit, Kuntibhoja, and Saibya, the choicest of men;"},{"k":"sankaranarayan","t":"Dhrstaketu, Cekitana, the valorous king of Kasi, Kuntibhoja, the conqueror of many, and the Sibi king, the best among men;"}]},{"ch":1,"vn":6,"dev":"युधामन्युश्च विक्रान्त उत्तमौजाश्च वीर्यवान्।\nसौभद्रो द्रौपदेयाश्च सर्व एव महारथाः","iast":"saubhadro draupadeyāśhcha sarva eva mahā-rathāḥ","v":[{"k":"purohit","t":"Yudhamanyu, Uttamouja, Soubhadra, and the sons of Droupadi—all famous men."},{"k":"sivananda","t":"The strong Yudhamanyu and the brave Uttamaujas, the son of Subhadra (Abhimanyu, the son of Subhadra and Arjuna), and the sons of Draupadi, all of them great charioteers (great heroes).\""},{"k":"adidevananda","t":"Yudhamanyu, the valiant one, and Uttamaujas, the strong one; and also the son of Subhadra, as well as the sons of Draupadi, all mighty warriors."},{"k":"gambirananda","t":"And the valiant Yudhamanyu, and the chivalrous Uttamaujas; the son of Subhadra (Abhimanyu) and the sons of Draupadi—all of them are, indeed, maharathas."},{"k":"sankaranarayan","t":"And Yudhamanyu, the heroic, and Uttamaujas, the valiant, the son of Subhadra, and the sons of Draupadi—all of them are indeed mighty warriors."}]},{"ch":1,"vn":7,"dev":"अस्माकं तु विशिष्टा ये तान्निबोध द्विजोत्तम।\nनायका मम सैन्यस्य संज्ञार्थं तान्ब्रवीमि ते","iast":"asmākaṁ tu viśhiṣhṭā ye tānnibodha dwijottama\nnāyakā mama sainyasya sanjñārthaṁ tānbravīmi te","v":[{"k":"purohit","t":"No changes needed."},{"k":"sivananda","t":"Know also, O best among the twice-born! the names of those who are the most distinguished amongst ourselves, the leaders of my army; these I name to you for your information."},{"k":"adidevananda","t":"Know, O best of Brahmanas, those who are important on our side—those who are the commanders of my army. I shall name them to refresh your memory."},{"k":"gambirananda","t":"But, O best among the Brahmanas, please be appraised of those who are foremost among us, the founders of my army. I speak of them to you by way of illustration."},{"k":"sankaranarayan","t":"O best among the twice-born! Please take note of the most distinguished amongst us, who are the generals of my army and who are accepted as leaders by the heroes in my mighty army; I shall name them to you."}]},{"ch":1,"vn":8,"dev":"भवान्भीष्मश्च कर्णश्च कृपश्च समितिञ्जयः।\nअश्वत्थामा विकर्णश्च सौमदत्तिस्तथैव च","iast":"bhavānbhīṣhmaśhcha karṇaśhcha kṛipaśhcha samitiñjayaḥ\naśhvatthāmā vikarṇaśhcha saumadattis tathaiva cha","v":[{"k":"purohit","t":"You come first; then Bheeshma, Karna, Kripa, great warriors; Ashwaththama, Vikarna, and the son of Somadhatta;"},{"k":"sivananda","t":"\"Thou thyself, Bhishma, Karna, Kripa, the victorious in war, Asvatthama, Vikarna, and Bhurisrava, the son of Somadatta—all these are ready for battle.\""},{"k":"adidevananda","t":"Yourself, Bhisma, Karna, the victorious Krpa, Asvatthama, Vikarna, and Jayadratha, the son of Somadatta;"},{"k":"gambirananda","t":"(They are): Your venerable self, Bhisma, Karna, and Krpa, who is ever victorious in battle; Asvatthama, Vikarna, Saumadatti, and Jayadratha."},{"k":"sankaranarayan","t":"Your good self, Bhisma, Karna, Krpa, Salya, Jayadratha, Asvatthaman, Vikarna, and Somadatta's son, the valiant ones."}]},{"ch":1,"vn":9,"dev":"अन्ये च बहवः शूरा मदर्थे त्यक्तजीविताः।\nनानाशस्त्रप्रहरणाः सर्वे युद्धविशारदाः","iast":"anye cha bahavaḥ śhūrā madarthe tyaktajīvitāḥ\nnānā-śhastra-praharaṇāḥ sarve yuddha-viśhāradāḥ","v":[{"k":"purohit","t":"And many others, all ready to die for My sake; all armed, all skilled in warfare."},{"k":"sivananda","t":"And also many other heroes, ready to give up their lives for my sake, armed with various weapons and missiles, all well-skilled in battle."},{"k":"adidevananda","t":"And there are many other heroes who are determined to give up their lives for my sake. They are all experts in using manifold missiles and dexterous in battle."},{"k":"gambirananda","t":"There are many heroes who have dedicated their lives to me, possessing various kinds of weapons and missiles, all of whom are skilled in battle."},{"k":"sankaranarayan","t":"And many other heroes, giving up their lives for my sake, fighting with various weapons, all highly skilled in different forms of warfare."}]},{"ch":1,"vn":10,"dev":"अपर्याप्तं तदस्माकं बलं भीष्माभिरक्षितम्।\nपर्याप्तं त्विदमेतेषां बलं भीमाभिरक्षितम्","iast":"aparyāptaṁ tadasmākaṁ balaṁ bhīṣhmābhirakṣhitam\nparyāptaṁ tvidameteṣhāṁ balaṁ bhīmābhirakṣhitam","v":[{"k":"purohit","t":"Yet our army seems weaker, though commanded by Bhishma; their army seems stronger, though commanded by Bhima."},{"k":"sivananda","t":"Our army, marshalled by Bhishma, is insufficient, whereas theirs, marshalled by Bhima, is sufficient."},{"k":"adidevananda","t":"Our force is inadequate, guarded by Bhisma, while their force is adequate, guarded by Bhima."},{"k":"gambirananda","t":"Therefore, our army, under the complete protection of Bhisma and others, is limitless. But this army of the enemies, under the protection of Bhima and others, is limited."},{"k":"sankaranarayan","t":"Thus, the army guarded by Bhima is unlimited for us, whereas the army guarded by Bhisma is sufficient for them, the Pandavas."}]},{"ch":1,"vn":11,"dev":"अयनेषु च सर्वेषु यथाभागमवस्थिताः।\nभीष्ममेवाभिरक्षन्तु भवन्तः सर्व एव हि","iast":"ayaneṣhu cha sarveṣhu yathā-bhāgamavasthitāḥ\nbhīṣhmamevābhirakṣhantu bhavantaḥ sarva eva hi","v":[{"k":"purohit","t":"Therefore, let the rank and file stand firm in their posts according to battalions, and all you generals around Bheeshma."},{"k":"sivananda","t":"Therefore, do all of you, stationed in your respective positions in the several divisions of the army, protect Bhishma alone."},{"k":"adidevananda","t":"Therefore, all of you, taking your places firmly in your respective divisions, should guard Bhisma at all costs."},{"k":"gambirananda","t":"However, venerable sirs, all of you without exception, while occupying all the positions in the different directions as allotted to you respectively, please protect Bhisma in particular."},{"k":"sankaranarayan","t":"Stationed firmly in all their respective paths, each one of them should guard Bhisma above all, without exception."}]},{"ch":1,"vn":12,"dev":"तस्य संजनयन्हर्षं कुरुवृद्धः पितामहः।\nसिंहनादं विनद्योच्चैः शङ्खं दध्मौ प्रतापवान्","iast":"tasya sañjanayan harṣhaṁ kuru-vṛiddhaḥ pitāmahaḥ\nsiṁha-nādaṁ vinadyochchaiḥ śhaṅkhaṁ dadhmau pratāpavān","v":[{"k":"purohit","t":"Then, to enliven his spirits, the brave Grandfather Bheeshma, the eldest of the Kuru clan, blew his conch, its sound resembling that of a lion's roar."},{"k":"sivananda","t":"His glorious grandsire, the oldest of the Kauravas, roared like a lion to cheer Duryodhana and blew his conch."},{"k":"adidevananda","t":"Then the valiant grandsire Bhisma, the senior-most of the Kuru clan, roared like a lion and blew his conch with the intention of cheering up Duryodhana."},{"k":"gambirananda","t":"The valiant grandfather, the eldest of the Kurus, loudly sounding a lion's roar, blew the conch to raise his (Duryodhana's) spirits."},{"k":"sankaranarayan","t":"Generating joy in him, the powerful paternal grandfather (Bhisma), the senior-most among the Kurus, roared like a lion and blew his conchshell loudly."}]},{"ch":1,"vn":13,"dev":"ततः शङ्खाश्च भेर्यश्च पणवानकगोमुखाः।\nसहसैवाभ्यहन्यन्त स शब्दस्तुमुलोऽभवत्","iast":"tataḥ śhaṅkhāśhcha bheryaśhcha paṇavānaka-gomukhāḥ\nsahasaivābhyahanyanta sa śhabdastumulo 'bhavat","v":[{"k":"purohit","t":"And immediately, all the conches, drums, trumpets, and horns blared forth in a tumultuous uproar."},{"k":"sivananda","t":"Then, suddenly, conches, kettledrums, tabors, drums, and cow horns blared forth from the Kaurava side, and the sound was tremendous."},{"k":"adidevananda","t":"Then suddenly conchs, kettle drums, trumpets, tabors, and blow horns blared forth, and the sound was terrific."},{"k":"gambirananda","t":"Just immediately afterward, conch shells, kettledrums, tabors, trumpets, and cow-horns blared forth, creating a tumultuous sound."},{"k":"sankaranarayan","t":"Then, all of a sudden, the conch-shells, drums, tambourines, trumpets, and cow-horns sounded in unison; the sound was tumultuous."}]},{"ch":1,"vn":14,"dev":"ततः श्वेतैर्हयैर्युक्ते महति स्यन्दने स्थितौ।\nमाधवः पाण्डवश्चैव दिव्यौ शङ्खौ प्रदध्मतुः","iast":"tataḥ śhvetairhayairyukte mahati syandane sthitau\nmādhavaḥ pāṇḍavaśhchaiva divyau śhaṅkhau pradadhmatuḥ","v":[{"k":"purohit","t":"Then, seated in their spacious war chariot, yoked with white horses, Lord Shri Krishna and Arjuna sounded their divine conch shells."},{"k":"sivananda","t":"Then, Madhava (Krishna) and the son of Pandu (Arjuna), seated in the magnificent chariot yoked with white horses, blew divine conches."},{"k":"adidevananda","t":"Then Sri Krishna and Arjuna, stationed in their great chariot yoked with white horses, blew their divine conchs."},{"k":"gambirananda","t":"Then Madhava (Krishna) and the son of Pandu (Arjuna), stationed in their magnificent chariot with white horses yoked to it, blew their divine conchs loudly."},{"k":"sankaranarayan","t":"Then, mounted on a mighty chariot, yoked with white horses, Madhava (Krishna) and the son of Pandu (Arjuna) blew their heavenly conch shells."}]},{"ch":1,"vn":15,"dev":"पाञ्चजन्यं हृषीकेशो देवदत्तं धनंजयः।\nपौण्ड्रं दध्मौ महाशङ्खं भीमकर्मा वृकोदरः","iast":"pāñchajanyaṁ hṛiṣhīkeśho devadattaṁ dhanañjayaḥ\npauṇḍraṁ dadhmau mahā-śhaṅkhaṁ bhīma-karmā vṛikodaraḥ","v":[{"k":"purohit","t":"Lord Shri Krishna blew his Panchajanya, and Arjuna blew his Devadatta; brave Bheema blew his renowned shell, Poundra."},{"k":"sivananda","t":"Hrishikesha blew the Panchajanya, Arjuna blew the Devadatta, and Bhima, the wolf-bellied doer of terrible deeds, blew the great conch Paundra."},{"k":"adidevananda","t":"Sri Krishna blew his conch, Pancajanya, Arjuna his Devadatta, and Bhima of terrible deeds blew his great conch, Paundra."},{"k":"gambirananda","t":"Hrsikesa (Krsna) blew the conch Pancajanya; Dhananjaya (Arjuna) blew the conch Devadatta; and Vrkodara (Bhima) of terrible deeds blew the great conch Paundra."},{"k":"sankaranarayan","t":"Hrsikesa (Krsna) blew the Pancajanya; Dhananjaya (Arjuna) blew the Devadatta; and Bhima, of the terrible deeds, blew the mighty conchshell, Paundra."}]},{"ch":1,"vn":16,"dev":"अनन्तविजयं राजा कुन्तीपुत्रो युधिष्ठिरः।\nनकुलः सहदेवश्च सुघोषमणिपुष्पकौ","iast":"anantavijayaṁ rājā kuntī-putro yudhiṣhṭhiraḥ\nnakulaḥ sahadevaśhcha sughoṣha-maṇipuṣhpakau","v":[{"k":"purohit","t":"The King Dharmaraja, the son of Kunti, blew the Anantavijaya, Nakula, and Sahadeva, the Sughosa and Manipushpaka, respectively."},{"k":"sivananda","t":"King Yudhishthira, the son of Kunti, blew the Anantavijaya; Nakula and Sahadeva blew the Sughosha and the Manipushpaka."},{"k":"adidevananda","t":"King Yudhisthira, the son of Kunti, blew his conch, Anantavijaya, and Nakula and Sahadeva blew their conchs, Sughosa and Manipuspaka."},{"k":"gambirananda","t":"King Yudhisthira, son of Kunti, blew the Anantavijaya; Nakula and Sahadeva blew the Sughosa and the Manipuspaka, respectively."},{"k":"sankaranarayan","t":"Kunti's son, the king Yudhisthira, blew the Anantavijaya; Nakula and Sahadeva blew the Sughosa and Manipuspaka, respectively."}]},{"ch":1,"vn":17,"dev":"काश्यश्च परमेष्वासः शिखण्डी च महारथः।\nधृष्टद्युम्नो विराटश्च सात्यकिश्चापराजितः","iast":"kāśhyaśhcha parameṣhvāsaḥ śhikhaṇḍī cha mahā-rathaḥ\ndhṛiṣhṭadyumno virāṭaśhcha sātyakiśh chāparājitaḥ","v":[{"k":"purohit","t":"And the Maharaja of Benares, the great archer, Shikhandi, the great soldier, Dhrishtayumna, Virata, and Satyaki, the invincible one,"},{"k":"sivananda","t":"The king of Kasi, an excellent archer, Sikhandi, the mighty car-warrior, Dhrishtadyumna, Virata, and Satyaki, the unconquered."},{"k":"adidevananda","t":"And the King of Kasi, the supreme bowman, Sikandi the mighty warrior, Dhrstadyumna, and Virata; and Satyaki, the invincible;"},{"k":"gambirananda","t":"And the King of Kashi, wielding a great bow, and the great chariot-rider Sikhandin, Dhrstadyumna, Virata, and Satyaki the unconquered;"},{"k":"sankaranarayan","t":"And the king of Kasi, a great archer, and Sikhandin, a mighty warrior; Dhrstadyumna and the king of Virata, and the unconquered Satyaki;"}]},{"ch":1,"vn":18,"dev":"द्रुपदो द्रौपदेयाश्च सर्वशः पृथिवीपते।\nसौभद्रश्च महाबाहुः शङ्खान्दध्मुः पृथक्पृथक्","iast":"drupado draupadeyāśhcha sarvaśhaḥ pṛithivī-pate\nsaubhadraśhcha mahā-bāhuḥ śhaṅkhāndadhmuḥ pṛithak pṛithak","v":[{"k":"purohit","t":"And, O King! Drupada's sons, Droupadi's sons, and the great soldier Soubhadra blew their conches."},{"k":"sivananda","t":"Drupada and the sons of Draupadi, O Lord of the Earth, and the son of Subhadra, the mighty-armed, blew their conches each separately."},{"k":"adidevananda","t":"Drupada and the sons of Draupadi, as well as the strong-armed son of Subhadra—all, O King, blew their respective conchs again and again."},{"k":"gambirananda","t":"Drupada and the sons of Draupadi, as well as the mighty-armed son of Subhadra, all of them together, O king, blew their respective conchs."},{"k":"sankaranarayan","t":"The Pancala king, a mighty archer, and Draupad's five sons, as well as the mighty-armed son of Subhadra, each blew their own conch-shells individually."}]},{"ch":1,"vn":19,"dev":"स घोषो धार्तराष्ट्राणां हृदयानि व्यदारयत्।\nनभश्च पृथिवीं चैव तुमुलो व्यनुनादयन्","iast":"sa ghoṣho dhārtarāṣhṭrāṇāṁ hṛidayāni vyadārayat\nnabhaśhcha pṛithivīṁ chaiva tumulo nunādayan","v":[{"k":"purohit","t":"The tumult rent the hearts of the sons of Dhritarashtra, shaking heaven and earth with its echoing violence."},{"k":"sivananda","t":"The tumultuous sound rent the hearts of Dhritarashtra's party, reverberating through both heaven and earth."},{"k":"adidevananda","t":"And that tumultuous uproar, reverberating through heaven and earth, rent the hearts of Dhrtarastra's sons."},{"k":"gambirananda","t":"That tremendous sound pierced the hearts of the sons of Dhrtarastra as it reverberated through the sky and the earth."},{"k":"sankaranarayan","t":"Resonating in both the sky and the earth, the tumultuous sound shattered the hearts of Dhrtarastra's men."}]},{"ch":1,"vn":20,"dev":"अथ व्यवस्थितान् दृष्ट्वा धार्तराष्ट्रान्कपिध्वजः।\nप्रवृत्ते शस्त्रसंपाते धनुरुद्यम्य पाण्डवः","iast":"atha vyavasthitān dṛiṣhṭvā dhārtarāṣhṭrān kapi-dhwajaḥ\npravṛitte śhastra-sampāte dhanurudyamya pāṇḍavaḥ\nhṛiṣhīkeśhaṁ tadā vākyam idam āha mahī-pate","v":[{"k":"purohit","t":"Then, upon beholding the sons of Dhritarashtra, drawn up on the battlefield, ready to fight, Arjuna, whose flag bore the image of Hanuman,"},{"k":"sivananda","t":"Then, seeing the people of Dhritarashtra's party standing arrayed and the discharge of weapons about to begin, Arjuna, the son of Pandu whose ensign was a monkey, took up his bow and said the following to Krishna, O Lord of the Earth."},{"k":"adidevananda","t":"Then Arjuna, whose banner crest was Hanuman, on beholding the sons of Dhrtarastra arrayed, took up his bow, while missiles were beginning to fly."},{"k":"gambirananda","t":"O King, thereafter, seeing Dhrtarastra's men standing in their positions, with all the weapons ready for action, the son of Pandu, Arjuna, who had the insignia of Hanuman on his chariot-flag, raised his bow and said the following to Hrsikesa."},{"k":"sankaranarayan","t":"O king! Then, observing Dhrtarastra's men arrayed when the armed clash had virtually begun, at that time, Pandu's son, the monkey-bannered one (Arjuna), raising his bow, spoke these sentences."}]},{"ch":1,"vn":21,"dev":"अर्जुन उवाच\nहृषीकेशं तदा वाक्यमिदमाह महीपते।\nसेनयोरुभयोर्मध्ये रथं स्थापय मेऽच्युत","iast":"arjuna uvācha\nsenayor ubhayor madhye rathaṁ sthāpaya me 'chyuta","v":[{"k":"purohit","t":"Raising his bow, he spoke this to the Lord Shri Krishna: O Infallible Lord of the earth! Please draw up my chariot between the two armies."},{"k":"sivananda","t":"Arjuna said, \"O Krishna, place my chariot in the middle between the two armies, so that I may behold those who stand here, desirous to fight, and know with whom I must fight when the battle is about to commence.\""},{"k":"adidevananda","t":"And he spoke, O Lord of the Earth, these words to Sri Krishna: Arjuna said, \"Draw up my chariot, O Krishna, between the two armies."},{"k":"gambirananda","t":"Arjuna said, \"O Acyuta, please place my chariot between both the armies.\""},{"k":"sankaranarayan","t":"Arjuna said, O Acyuta! Please halt my chariot at a central place between the two armies, so that I may scrutinize these men who are standing with a desire to fight and with whom I have to engage in this great war-effort."}]},{"ch":1,"vn":22,"dev":"यावदेतान्निरीक्षेऽहं योद्धुकामानवस्थितान्।\nकैर्मया सह योद्धव्यमस्मिन्रणसमुद्यमे","iast":"yāvadetān nirīkṣhe 'haṁ yoddhu-kāmān avasthitān\nkairmayā saha yoddhavyam asmin raṇa-samudyame","v":[{"k":"purohit","t":"So that I may observe those who must fight on my side and those who must fight against me."},{"k":"sivananda","t":"Arjuna said, \"O Krishna, place my chariot in the middle between the two armies, so that I may behold those who stand here, desirous to fight, and know with whom I must fight when the battle is about to commence.\""},{"k":"adidevananda","t":"So that I may have a good look at those who are standing, eager to fight, and know with whom I must fight in this enterprise of war."},{"k":"gambirananda","t":"Until I survey those who stand intent on fighting and those who are about to engage in battle with me in this impending war."},{"k":"sankaranarayan","t":"I shall scrutinize those who are ready to fight, who have assembled here and are eager to achieve in the battle what is dear to the evil-minded son of Dhrtarastra."}]},{"ch":1,"vn":23,"dev":"योत्स्यमानानवेक्षेऽहं य एतेऽत्र समागताः।\nधार्तराष्ट्रस्य दुर्बुद्धेर्युद्धे प्रियचिकीर्षवः","iast":"yotsyamānān avekṣhe 'haṁ ya ete 'tra samāgatāḥ\ndhārtarāṣhṭrasya durbuddher yuddhe priya-chikīrṣhavaḥ","v":[{"k":"purohit","t":"And gaze upon this array of soldiers, eager to please the sons of Dhritarashtra who are sinful."},{"k":"sivananda","t":"For I desire to observe those who are assembled here to fight, wishing to please in battle the evil-minded Duryodhana—the son of Dhritarashtra."},{"k":"adidevananda","t":"I wish to see those gathered here ready to fight in this battle in order to please the evil-minded son of Dhrtarashtra."},{"k":"gambirananda","t":"These who have assembled here and want to accomplish in the war what is dear to the perverted son of Dhrtarastra, I find them to be intent on fighting."},{"k":"sankaranarayan","t":"Sanjaya said, \"O descendant of Bharata (Dhrtarastra)! Thus instructed by Gudakesa (Arjuna), Hrsikesa halted the best chariot at a place in between the two armies, in front of Bhisma and Drona and all the rulers of the earth. He then said, 'O son of Prtha! Behold these Kurus, assembled.'\""}]},{"ch":1,"vn":24,"dev":"संजय उवाच\nएवमुक्तो हृषीकेशो गुडाकेशेन भारत।\nसेनयोरुभयोर्मध्ये स्थापयित्वा रथोत्तमम्","iast":"sañjaya uvācha\nevam ukto hṛiṣhīkeśho guḍākeśhena bhārata\nsenayor ubhayor madhye sthāpayitvā rathottamam","v":[{"k":"purohit","t":"Sanjaya said: \"Having listened to Arjuna's request, Lord Shri Krishna drew up His bright chariot in the midst between the two armies."},{"k":"sivananda","t":"Sanjaya said, Thus addressed by Arjuna, Krishna stationed the best of chariots, O Dhritarashtra, in the midst of the two armies."},{"k":"adidevananda","t":"Sanjaya said: Thus addressed by Arjuna, Sri Krishna drew up the best of chariots between the two armies, in full view of Bhisma, Drona, and all the other kings, O Dhrtarastra. He then said, \"O Arjuna, behold these assembled Kauravas.\""},{"k":"gambirananda","t":"Sanjaya said, \"O scion of the line of Bharata, Hrishikesa, being told so by Gudakesa (Arjuna), placed the excellent chariot between the two armies, in front of Bhishma and Drona as well as all the rulers of the earth, and said, 'O Partha, behold these assembled Kurus!'\""},{"k":"sankaranarayan","t":"Sanjaya said, \"O descendant of Bharata (Dhrtarastra)! Thus instructed by Gudakesa (Arjuna), Hrsikesa halted the best chariot at a place in between the two armies, in front of Bhisma and Drona and all the rulers of the earth. He then said, 'O son of Prtha! Behold these Kurus, assembled.\""}]},{"ch":1,"vn":25,"dev":"भीष्मद्रोणप्रमुखतः सर्वेषां च महीक्षिताम्।\nउवाच पार्थ पश्यैतान्समवेतान्कुरूनिति","iast":"bhīṣhma-droṇa-pramukhataḥ sarveṣhāṁ cha mahī-kṣhitām\nuvācha pārtha paśhyaitān samavetān kurūn iti","v":[{"k":"purohit","t":"Where Bheeshma and Drona had led all the rulers of the earth, they spoke thus: O Arjuna! Behold, these members of the family of Kuru are assembled."},{"k":"sivananda","t":"In front of Bhishma and Drona, and all the rulers of the earth, he said: \"O Arjuna, son of Pritha, behold these Kurus gathered together.\""},{"k":"adidevananda","t":"Sanjaya said: Thus addressed by Arjuna, Sri Krishna drew up the best of chariots between the two armies, in full view of Bhisma, Drona, and all the other kings, O Dhrtarastra. He then said, \"O Arjuna, behold these assembled Kauravas.\""},{"k":"gambirananda","t":"Sanjaya said, \"O scion of the line of Bharata (Dhrtarashtra), Hrsikesa, being told so by Gudakesa (Arjuna), placed the excellent chariot between the two armies, in front of Bhisma and Drona as well as all the rulers of the earth, and said, 'O Partha (Arjuna), behold these assembled people of the Kuru dynasty.'\""},{"k":"sankaranarayan","t":"There in both the armies, the son of Prtha observed his fathers, paternal grandfathers, teachers, maternal uncles, brothers, sons, sons' sons, and comrades, fathers-in-law, and also friends."}]},{"ch":1,"vn":26,"dev":"तत्रापश्यत्स्थितान्पार्थः पितृ़नथ पितामहान्।\nआचार्यान्मातुलान्भ्रातृ़न्पुत्रान्पौत्रान्सखींस्तथा","iast":"tatrāpaśhyat sthitān pārthaḥ pitṝīn atha pitāmahān\nāchāryān mātulān bhrātṝīn putrān pautrān sakhīṁs tathā\nśhvaśhurān suhṛidaśh chaiva senayor ubhayor api","v":[{"k":"purohit","t":"There, Arjuna noticed fathers, grandfathers, uncles, cousins, sons, grandsons, teachers, and friends."},{"k":"sivananda","t":"Then, Arjuna (son of Pritha) saw there (in the armies) stationed fathers, grandfathers, teachers, maternal uncles, brothers, sons, grandsons, and friends."},{"k":"adidevananda","t":"Then, as Arjuna looked on, he saw standing there fathers, grandfathers, teachers, uncles, brothers, sons, grandsons, and comrades."},{"k":"gambirananda","t":"Then Arjuna saw, marshalled among both the armies, his uncles, grandfathers, teachers, maternal uncles, brothers, cousins, sons, grandsons, comrades, fathers-in-law, and friends."},{"k":"sankaranarayan","t":"Noticing all those kinsmen arrayed in the army, the son of Kunti was overwhelmed with immense compassion and, despondent, he uttered this:"}]},{"ch":1,"vn":27,"dev":"श्वशुरान्सुहृदश्चैव सेनयोरुभयोरपि।\nतान्समीक्ष्य स कौन्तेयः सर्वान्बन्धूनवस्थितान्","iast":"tān samīkṣhya sa kaunteyaḥ sarvān bandhūn avasthitān\nkṛipayā parayāviṣhṭo viṣhīdann idam abravīt","v":[{"k":"purohit","t":"Fathers-in-law and benefactors were arrayed on both sides, and Arjuna then gazed at all those kinsmen before him."},{"k":"sivananda","t":"He saw fathers-in-law and friends in both the armies. The son of Kunti, Arjuna, seeing all those kinsmen thus standing arrayed, spoke sorrowfully, deeply filled with pity."},{"k":"adidevananda","t":"Fathers-in-law and dear friends in both armies, when Arjuna saw all these kinsmen arrayed,"},{"k":"gambirananda","t":"The son of Kunti, Arjuna, seeing all those relatives arrayed there, became overwhelmed by supreme compassion and sorrowfully said this:"},{"k":"sankaranarayan","t":"Arjuna said, \"O Krishna! On seeing these war-mongering kinsfolk of mine arrayed in the armies, my limbs fail and my mouth goes dry.\""}]},{"ch":1,"vn":28,"dev":"अर्जुन उवाच\nकृपया परयाऽऽविष्टो विषीदन्निदमब्रवीत्।\nदृष्ट्वेमं स्वजनं कृष्ण युयुत्सुं समुपस्थितम्","iast":"arjuna uvācha\ndṛiṣhṭvemaṁ sva-janaṁ kṛiṣhṇa yuyutsuṁ samupasthitam","v":[{"k":"purohit","t":"And his heart melted with pity, and sadly he spoke: \"O my Lord! When I see all these, my own people, thirsting for battle,"},{"k":"sivananda","t":"Arjuna said, \"O Krishna, seeing my kinsmen arrayed here, eager to fight,"},{"k":"adidevananda","t":"He was filled with deep compassion and said these words in despair:"},{"k":"gambirananda","t":"Arjuna said, \"O Krsna, seeing these relatives and friends who have assembled here with the intention of fighting, my limbs become languid and my mouth becomes completely dry.\""},{"k":"sankaranarayan","t":"Shivers and goosebumps arise in my body; the Gandiva slips from my hand and my skin is burning all over."}]},{"ch":1,"vn":29,"dev":"सीदन्ति मम गात्राणि मुखं च परिशुष्यति।\nवेपथुश्च शरीरे मे रोमहर्षश्च जायते","iast":"sīdanti mama gātrāṇi mukhaṁ cha pariśhuṣhyati\nvepathuśh cha śharīre me roma-harṣhaśh cha jāyate","v":[{"k":"purohit","t":"My limbs are failing me, my throat is parched, my body is trembling, and my hair is standing on end."},{"k":"sivananda","t":"My limbs fail, my mouth is parched, my body quivers, and my hair stands on end."},{"k":"adidevananda","t":"My limbs have weakened, my mouth has become parched, my body is trembling, and my hairs are standing on end."},{"k":"gambirananda","t":"And there is trembling in my body, and my hair stands on end; the Gandiva (bow) slips from my hand and my skin burns intensely."},{"k":"sankaranarayan","t":"I am unable even to stand steady; my mind seems to be confused; and I see adverse omens, O Kesava!"}]},{"ch":1,"vn":30,"dev":"गाण्डीवं स्रंसते हस्तात्त्वक्चैव परिदह्यते।\nन च शक्नोम्यवस्थातुं भ्रमतीव च मे मनः","iast":"gāṇḍīvaṁ sraṁsate hastāt tvak chaiva paridahyate\nna cha śhaknomy avasthātuṁ bhramatīva cha me manaḥ","v":[{"k":"purohit","t":"The bow Gandiva slips from my hand, and my skin burns. I cannot remain still, for my mind is in tumult."},{"k":"sivananda","t":"The Gandiva slips from my hand, and my skin burns all over; I am unable to stand, and my mind is reeling, as it were."},{"k":"adidevananda","t":"The bow Gandiva slips from my hand and my skin is burning. I can no longer stand. My mind seems to be reeling."},{"k":"gambirananda","t":"Moreover, O Kesava (Krishna), I am not able to stand firmly, and my mind seems to be whirling. And I observe the omens to be adverse."},{"k":"sankaranarayan","t":"I do not foresee any good in killing my own kinsmen in the battle. O Krsna! I neither wish for victory, nor kingdom, nor the pleasures thereof."}]},{"ch":1,"vn":31,"dev":"निमित्तानि च पश्यामि विपरीतानि केशव।\nन च श्रेयोऽनुपश्यामि हत्वा स्वजनमाहवे","iast":"nimittāni cha paśhyāmi viparītāni keśhava\nna cha śhreyo 'nupaśhyāmi hatvā sva-janam āhave","v":[{"k":"purohit","t":"The omens are unfavorable; what good can come from the slaughter of my people on this battlefield?"},{"k":"sivananda","t":"And I see ill omens, O Kesava. I do not see any good in slaying my kinsmen in battle."},{"k":"adidevananda","t":"I see, Kṛṣṇa, inauspicious omens. I foresee no good in slaying my kinsmen in battle."},{"k":"gambirananda","t":"Besides, I do not see any good to be derived from killing my own people in battle. O Krsna, I do not hanker after victory, nor even a kingdom, nor pleasures."},{"k":"sankaranarayan","t":"O Govinda! What use is the kingdom to us? What use are its pleasures and life even?"}]},{"ch":1,"vn":32,"dev":"न काङ्क्षे विजयं कृष्ण न च राज्यं सुखानि च।\nकिं नो राज्येन गोविन्द किं भोगैर्जीवितेन वा","iast":"na kāṅkṣhe vijayaṁ kṛiṣhṇa na cha rājyaṁ sukhāni cha\nkiṁ no rājyena govinda kiṁ bhogair jīvitena vā","v":[{"k":"purohit","t":"Ah, my Lord! I do not crave victory, nor a kingdom, nor any pleasure. What would a kingdom, happiness, or life be to me?"},{"k":"sivananda","t":"I desire not victory, O Krishna, nor kingdom, nor pleasures.\nWhat use is dominion to us, O Krishna, or pleasures or even life?"},{"k":"adidevananda","t":"I desire no victory, nor empire, nor pleasures. What have we to do with empire, O Krishna, or enjoyment, or even life?"},{"k":"gambirananda","t":"O Govinda! What need do we have of a kingdom, or what need of enjoyments and livelihood? Those for whom kingdom, enjoyments, and pleasures are desired by us—such as teachers, uncles, fathers-in-law, grandsons, brothers-in-law, as well as relatives—those very ones stand arrayed for battle, risking their lives and wealth."},{"k":"sankaranarayan","t":"For whose sake we seek kingdom, its pleasures and happiness, the very same persons now stand arrayed to fight, giving up their lives and wealth."}]},{"ch":1,"vn":33,"dev":"येषामर्थे काङ्क्षितं नो राज्यं भोगाः सुखानि च।\nत इमेऽवस्थिता युद्धे प्राणांस्त्यक्त्वा धनानि च","iast":"yeṣhām arthe kāṅkṣhitaṁ no rājyaṁ bhogāḥ sukhāni cha\nta ime 'vasthitā yuddhe prāṇāṁs tyaktvā dhanāni cha","v":[{"k":"purohit","t":"When those for whose sake I desire these things stand here, about to sacrifice their property and lives:"},{"k":"sivananda","t":"Those for whose sake we desire kingdom, enjoyments, and pleasures stand here in battle, having renounced life and wealth."},{"k":"adidevananda","t":"Those for whose sake we desire empire, enjoyment, and pleasures, stand here in war, renouncing life and wealth."},{"k":"gambirananda","t":"- O Govinda! What need do we have of a kingdom, or what need of enjoyments and livelihood? Those for whom kingdom, enjoyments, and pleasures are desired by us—such as teachers, uncles, fathers-in-law, grandsons, brothers-in-law, as well as relatives—those very ones stand arrayed for battle, risking their lives and wealth."},{"k":"sankaranarayan","t":"These are our teachers, fathers, sons, paternal grandfathers, maternal uncles, fathers-in-law, sons' sons, wives' brothers, and other relatives."}]},{"ch":1,"vn":34,"dev":"आचार्याः पितरः पुत्रास्तथैव च पितामहाः।\nमातुलाः श्चशुराः पौत्राः श्यालाः सम्बन्धिनस्तथा","iast":"āchāryāḥ pitaraḥ putrās tathaiva cha pitāmahāḥ\nmātulāḥ śhvaśhurāḥ pautrāḥ śhyālāḥ sambandhinas tathā","v":[{"k":"purohit","t":"Teachers, fathers, grandfathers, sons, grandsons, uncles, fathers-in-law, brothers-in-law, and other relatives."},{"k":"sivananda","t":"Teachers, fathers, sons, and grandfathers, maternal uncles, fathers-in-law, grandsons, brothers-in-law, and other relatives—"},{"k":"adidevananda","t":"all these are to be regarded as one's own self.\nTeachers, fathers, sons, grandfathers, uncles, fathers-in-law, grandsons, brothers-in-law, and other kinsmen—all these are to be regarded as one's own self."},{"k":"gambirananda","t":"- O Govinda! What need do we have of a kingdom, or what need of enjoyments and livelihood? Those for whom kingdom, enjoyments, and pleasures are desired by us—such as teachers, uncles, fathers-in-law, grandsons, brothers-in-law, as well as relatives—those very ones stand arrayed for battle, risking their lives and wealth."},{"k":"sankaranarayan","t":"O slayer of Mandhu (Krsna)! I do not desire to slay these men, even though they slay me, not even for the sake of the kingdom of the three worlds, let alone for the sake of the earth."}]},{"ch":1,"vn":35,"dev":"एतान्न हन्तुमिच्छामि घ्नतोऽपि मधुसूदन।\nअपि त्रैलोक्यराज्यस्य हेतोः किं नु महीकृते","iast":"etān na hantum ichchhāmi ghnato 'pi madhusūdana\napi trailokya-rājyasya hetoḥ kiṁ nu mahī-kṛite","v":[{"k":"purohit","t":"I would not kill them, even for three worlds; why then for this earth alone? It matters not if I myself am killed."},{"k":"sivananda","t":"These I do not wish to kill, O Krishna, even though they kill me, for the sake of dominion over the three worlds; leave alone killing them for the sake of the earth.\""},{"k":"adidevananda","t":"I would not slay them, even if they might slay me, for the sovereignty of the three worlds—how much less for this earth, O Krsna?"},{"k":"gambirananda","t":"O Madhusudana, even if I am killed, I do not want to kill these even for the sake of a kingdom extending across the three worlds; let alone doing so for the earth!"},{"k":"sankaranarayan","t":"What joy would we gain by slaying Dhrtarastra's sons, O Janardana?"}]},{"ch":1,"vn":36,"dev":"निहत्य धार्तराष्ट्रान्नः का प्रीतिः स्याज्जनार्दन।\nपापमेवाश्रयेदस्मान्हत्वैतानाततायिनः","iast":"nihatya dhārtarāṣhṭrān naḥ kā prītiḥ syāj janārdana\npāpam evāśhrayed asmān hatvaitān ātatāyinaḥ","v":[{"k":"purohit","t":"My Lord! What happiness can come from the death of these sons of Dhritarashtra? We shall be committing a sin if we kill these desperate men."},{"k":"sivananda","t":"By killing these sons of Dhritarashtra, what pleasure could be ours, O Janardana? Only sin would accrue to us from killing these felons."},{"k":"adidevananda","t":"If we were to kill the sons of Dhrtarastra, what joy would be ours, O Krsna? Sin alone would accrue to us if we killed these murderous felons."},{"k":"gambirananda","t":"O Janardana, what happiness will we gain by killing the sons of Dhrtarastra? We will only incur sin by killing these wrongdoers."},{"k":"sankaranarayan","t":"Nothing but sin would slay these desperadoes and take hold of us; therefore, we should not slay Dhrtarastra's sons, our own relatives."}]},{"ch":1,"vn":37,"dev":"तस्मान्नार्हा वयं हन्तुं धार्तराष्ट्रान्स्वबान्धवान्।\nस्वजनं हि कथं हत्वा सुखिनः स्याम माधव","iast":"tasmān nārhā vayaṁ hantuṁ dhārtarāṣhṭrān sa-bāndhavān\nsva-janaṁ hi kathaṁ hatvā sukhinaḥ syāma mādhava","v":[{"k":"purohit","t":"We are worthy of a nobler feat than slaughtering our relatives—the sons of Dhritarashtra; for, my Lord, how can we be happy if we kill our kinsmen?"},{"k":"sivananda","t":"Therefore, we should not kill the sons of Dhritarashtra, our relatives; for how can we be happy by killing our own kin, O Madhava (Krishna)?"},{"k":"adidevananda","t":"Therefore, it is not befitting for us to slay our kin, the sons of Dhrtarastra. For if we kill our kinsmen, O Krsna, how can we be happy?"},{"k":"gambirananda","t":"Therefore, it is not proper for us to kill the sons of Dhrtarastra, who are our own relatives. For, O Madhava, how can we be happy by killing our kinsmen?"},{"k":"sankaranarayan","t":"How could we be truly happy, O Madhava, after slaying our own kinsmen?"}]},{"ch":1,"vn":38,"dev":"यद्यप्येते न पश्यन्ति लोभोपहतचेतसः।\nकुलक्षयकृतं दोषं मित्रद्रोहे च पातकम्","iast":"yady apy ete na paśhyanti lobhopahata-chetasaḥ\nkula-kṣhaya-kṛitaṁ doṣhaṁ mitra-drohe cha pātakam","v":[{"k":"purohit","t":"Although these men, blinded by greed, see no guilt in destroying their kin or fighting against their friends,"},{"k":"sivananda","t":"Though they, with intelligence overpowered by greed, see no evil in the destruction of families and no sin in hostility to friends,"},{"k":"adidevananda","t":"Though these people, whose minds are overpowered by greed, see no evil in the destruction of a clan and no sin in treachery to friends,"},{"k":"gambirananda","t":"- O Janardana, although these people, whose hearts have become perverted by greed, do not see the evil arising from destroying the family and sinning in hostility towards friends, yet how can we, who clearly see the evil arising from destroying the family, remain unaware of the need to abstain from this sin?"},{"k":"sankaranarayan","t":"Of course, these (Dhrtarastra's sons), with their intellects overpowered by greed, do not see the evil consequences ensuing from the ruin of the family and the sin of cheating friends."}]},{"ch":1,"vn":39,"dev":"कथं न ज्ञेयमस्माभिः पापादस्मान्निवर्तितुम्।\nकुलक्षयकृतं दोषं प्रपश्यद्भिर्जनार्दन","iast":"kathaṁ na jñeyam asmābhiḥ pāpād asmān nivartitum\nkula-kṣhaya-kṛitaṁ doṣhaṁ prapaśhyadbhir janārdana","v":[{"k":"purohit","t":"Should we not, whose eyes are open and who consider it wrong to annihilate our family, turn away from such a great crime?"},{"k":"sivananda","t":"Why should we not, who clearly see the evil in the destruction of families, learn to turn away from this sin, O Janardana (Krishna)?"},{"k":"adidevananda","t":"Why should we not learn to shun this crime—we who see the evil of ruining a clan, O Krishna?"},{"k":"gambirananda","t":"- O Janardana, although these people, whose hearts have become perverted by greed, do not see the evil arising from destroying the family and sinning in hostility towards friends, yet how can we, who clearly see the evil arising from destroying the family, remain unaware of the need to abstain from this sin?"},{"k":"sankaranarayan","t":"But, perceiving clearly the evil consequences ensuing from the ruin of the family, should we not have sense enough to refrain from this sinful act, O Janardana?"}]},{"ch":1,"vn":40,"dev":"कुलक्षये प्रणश्यन्ति कुलधर्माः सनातनाः।\nधर्मे नष्टे कुलं कृत्स्नमधर्मोऽभिभवत्युत","iast":"kula-kṣhaye praṇaśhyanti kula-dharmāḥ sanātanāḥ\ndharme naṣhṭe kulaṁ kṛitsnam adharmo 'bhibhavaty uta","v":[{"k":"purohit","t":"The destruction of our kindred means the destruction of the traditions of our ancient lineage, and when these are lost, irreligion will overrun our homes."},{"k":"sivananda","t":"In the destruction of a family, the immemorial religious rites of that family perish; on the destruction of spirituality, impiety indeed, overwhelms the whole family."},{"k":"adidevananda","t":"With the ruin of a clan, its ancient traditions perish, and when traditions perish, lawlessness overtakes the whole clan."},{"k":"gambirananda","t":"From the ruin of the family, the traditional rites and duties are totally destroyed. When rites and duties are destroyed, vice overwhelms the entire family."},{"k":"sankaranarayan","t":"When a family ruins, the eternal duties of the family perish; when the duties perish, impiety inevitably dominates the entire family."}]},{"ch":1,"vn":41,"dev":"अधर्माभिभवात्कृष्ण प्रदुष्यन्ति कुलस्त्रियः।\nस्त्रीषु दुष्टासु वार्ष्णेय जायते वर्णसङ्करः","iast":"adharmābhibhavāt kṛiṣhṇa praduṣhyanti kula-striyaḥ\nstrīṣhu duṣhṭāsu vārṣhṇeya jāyate varṇa-saṅkaraḥ","v":[{"k":"purohit","t":"When irreligion spreads, the women of the house start to stray; when they lose their purity, adulteration of the lineage follows."},{"k":"sivananda","t":"O Krishna, by the prevalence of impiety, the women of the family become corrupt; and, when women are corrupted, O Varshenya (descendant of Vrishni), intermingling of castes arises."},{"k":"adidevananda","t":"When lawlessness prevails, O Krsna, the women of the clan become corrupted; when women become corrupted, there arises an intermixing of classes."},{"k":"gambirananda","t":"O Krishna, when vice predominates, the women of the family become corrupt. O descendant of the Vrsnis, when women become corrupted, it results in the intermingling of castes."},{"k":"sankaranarayan","t":"O Krsna, due to the domination of impiety, the women of the family become corrupt. O member of the Vrsni-clan, when the women become corrupt, there arises the intermixture of castes."}]},{"ch":1,"vn":42,"dev":"सङ्करो नरकायैव कुलघ्नानां कुलस्य च।\nपतन्ति पितरो ह्येषां लुप्तपिण्डोदकक्रियाः","iast":"saṅkaro narakāyaiva kula-ghnānāṁ kulasya cha\npatanti pitaro hy eṣhāṁ lupta-piṇḍodaka-kriyāḥ","v":[{"k":"purohit","t":"Promiscuity ruins both the family and those who defile it; while the souls of our ancestors droop, due to the lack of funeral cakes and ablutions."},{"k":"sivananda","t":"Confusion of castes leads to hell for the slayers of the family, for their forebears fall, deprived of the offerings of rice-balls and libations of water."},{"k":"adidevananda","t":"This mixing of classes leads to hell for the clan itself and its destroyers; for the spirits of their ancestors fall degraded, deprived of the ritual offerings of food and water."},{"k":"gambirananda","t":"And the intermingling in the family leads the ruiners of the family verily into hell. The forefathers of these fall down (into hell) due to being deprived of the offerings of rice-balls and water."},{"k":"sankaranarayan","t":"The intermixture leads the family-ruiners and their families to nothing but hell; for, their ancestors (their individual souls) fall down [in hell], being deprived of the rites of offering rice-balls and water [intended for them]."}]},{"ch":1,"vn":43,"dev":"दोषैरेतैः कुलघ्नानां वर्णसङ्करकारकैः।\nउत्साद्यन्ते जातिधर्माः कुलधर्माश्च शाश्वताः","iast":"doṣhair etaiḥ kula-ghnānāṁ varṇa-saṅkara-kārakaiḥ\nutsādyante jāti-dharmāḥ kula-dharmāśh cha śhāśhvatāḥ","v":[{"k":"purohit","t":"By the destruction of our lineage and the pollution of our blood, ancient class traditions and family purity alike perish."},{"k":"sivananda","t":"By these evil deeds of the destroyers of the family, which cause confusion of castes, the eternal religious rites of the caste and the family are destroyed."},{"k":"adidevananda","t":"By the sins of the clan-destroyers who bring about intermixing of classes, the ancient traditions of the clans and classes are destroyed."},{"k":"gambirananda","t":"Due to the misdeeds of the ruiners of the family, which cause intermingling of castes, the traditional rites and duties of the castes and families are destroyed."},{"k":"sankaranarayan","t":"On account of these evils of the family-ruiners that cause the intermixing of castes, the eternal caste-duties and family-duties fall into disuse."}]},{"ch":1,"vn":44,"dev":"उत्सन्नकुलधर्माणां मनुष्याणां जनार्दन।\nनरकेऽनियतं वासो भवतीत्यनुशुश्रुम","iast":"utsanna-kula-dharmāṇāṁ manuṣhyāṇāṁ janārdana\nnarake 'niyataṁ vāso bhavatītyanuśhuśhruma","v":[{"k":"purohit","t":"The wise say, my Lord, that they are forever lost whose ancient traditions have been lost."},{"k":"sivananda","t":"We have heard, O Janardana, that those men in whose families the religious practices have been destroyed are inevitably destined to dwell in hell for an unknown period."},{"k":"adidevananda","t":"For those whose clan laws are destroyed, dwelling in hell is ordained, O Krishna; thus, we have heard."},{"k":"gambirananda","t":"O Janardana, we have heard that living in hell is inevitable for those whose family duties are destroyed."},{"k":"sankaranarayan","t":"O Janardana! Dwelling in hell is certain for men whose family duties have fallen into disuse; this we have heard."}]},{"ch":1,"vn":45,"dev":"अहो बत महत्पापं कर्तुं व्यवसिता वयम्।\nयद्राज्यसुखलोभेन हन्तुं स्वजनमुद्यताः","iast":"aho bata mahat pāpaṁ kartuṁ vyavasitā vayam\nyad rājya-sukha-lobhena hantuṁ sva-janam udyatāḥ","v":[{"k":"purohit","t":"Alas, it is strange that we should be willing to kill our own countrymen and commit a great sin, in order to enjoy the pleasures of kingdom."},{"k":"sivananda","t":"Alas! We are involved in a great sin, for we are prepared to kill our kinsmen, out of greed for the pleasures of a kingdom."},{"k":"adidevananda","t":"Alas! We have resolved to commit a great sin, for we are ready to slay our kin out of desire for sovereignty and enjoyment."},{"k":"gambirananda","t":"What a pity that we have resolved to commit a great sin, eager to kill our own kith and kin out of greed for the pleasures of a kingdom!"},{"k":"sankaranarayan","t":"Alas! What a great sin have we resolved to commit! For, out of greed for the joy of the kingdom, we are striving to slay our own kinfolk!"}]},{"ch":1,"vn":46,"dev":"यदि मामप्रतीकारमशस्त्रं शस्त्रपाणयः।\nधार्तराष्ट्रा रणे हन्युस्तन्मे क्षेमतरं भवेत्","iast":"yadi mām apratīkāram aśhastraṁ śhastra-pāṇayaḥ\ndhārtarāṣhṭrā raṇe hanyus tan me kṣhemataraṁ bhavet","v":[{"k":"purohit","t":"If, on the contrary, the sons of Dhritarashtra, with weapons in hand, should slay me, unarmed and unresisting, surely that would be better for my welfare!"},{"k":"sivananda","t":"If the sons of Dhritarashtra, with weapons in hand, should slay me in battle, unresisting and unarmed, that would be better for me."},{"k":"adidevananda","t":"If the well-armed sons of Dhrtarastra should slay me in battle, unresisting and unarmed, that would be better for me."},{"k":"gambirananda","t":"If, in this battle, the sons of Dhrtarastra, armed with weapons, kill me, who am non-resistant and unarmed, that will be more beneficial for me."},{"k":"sankaranarayan","t":"It would be more beneficial for me if Dhrtarastra's men, with weapons in their hands, should slay me, unresisting and unarmed."}]},{"ch":1,"vn":47,"dev":"सञ्जय उवाच\nएवमुक्त्वाऽर्जुनः संख्ये रथोपस्थ उपाविशत्।\nविसृज्य सशरं चापं शोकसंविग्नमानसः","iast":"sañjaya uvācha\nevam uktvārjunaḥ saṅkhye rathopastha upāviśhat\nvisṛijya sa-śharaṁ chāpaṁ śhoka-saṁvigna-mānasaḥ","v":[{"k":"purohit","t":"Sanjaya said: \"Having spoken thus, Arjuna sank into the seat of his chariot, discarding his bow and arrow, overwhelmed with grief in the midst of the armies.\""},{"k":"sivananda","t":"Sanjaya said, Having thus spoken in the midst of the battlefield, Arjuna cast away his bow and arrow and, his mind overwhelmed with sorrow, sat down on the seat of the chariot."},{"k":"adidevananda","t":"Sanjaya said: Having spoken thus on the battlefield, Arjuna threw aside his bow and arrows and sat down on the chariot seat, his heart overwhelmed with grief."},{"k":"gambirananda","t":"Sanjaya narrated: Having said so, Arjuna, with a mind afflicted by sorrow, sat down on the chariot in the midst of the battle, casting aside his bow along with the arrows."},{"k":"sankaranarayan","t":"Sanjaya said, Having said this much about the battle, and letting his bow and arrows fall, Arjuna sat down on the back of the chariot, his mind agitated with grief."}]},{"ch":2,"vn":1,"dev":"सञ्जय उवाच\nतं तथा कृपयाऽविष्टमश्रुपूर्णाकुलेक्षणम्।\nविषीदन्तमिदं वाक्यमुवाच मधुसूदनः","iast":"sañjaya uvācha\ntaṁ tathā kṛipayāviṣhṭamaśhru pūrṇākulekṣhaṇam\nviṣhīdantamidaṁ vākyam uvācha madhusūdanaḥ","v":[{"k":"purohit","t":"Sanjaya then told how the Lord Shri Krishna, seeing Arjuna overwhelmed with compassion, his eyes dimmed with flowing tears and full of despondency, consoled him:"},{"k":"sivananda","t":"Sanjaya said: To him, who was thus overcome with pity, despondent, with eyes full of tears and agitated, Madhusudana (the destroyer of Madhu) or Krishna spoke these words."},{"k":"adidevananda","t":"Sanjaya said: To him, who was overcome with pity, whose eyes were wet with tears, who was sorrow-stricken and bore a bewildered look, Sri Krishna spoke as follows:"},{"k":"gambirananda","t":"Sanjaya said: To him who had been filled with pity, whose eyes were filled with tears and showed distress, and who was sorrowing, Madhusudana uttered these words."},{"k":"sankaranarayan","t":"Sanjaya said: To him, who was thus possessed by compassion, whose eyes were confused and filled with tears, and who was sinking in despondency, Madhusudana spoke the following words."}]},{"ch":2,"vn":2,"dev":"श्री भगवानुवाच\nकुतस्त्वा कश्मलमिदं विषमे समुपस्थितम्।\nअनार्यजुष्टमस्वर्ग्यमकीर्तिकरमर्जुन","iast":"śhrī bhagavān uvācha\nkutastvā kaśhmalamidaṁ viṣhame samupasthitam\nanārya-juṣhṭamaswargyam akīrti-karam arjuna","v":[{"k":"purohit","t":"The Lord said: My beloved friend! Why yield to this weakness, on the eve of battle, which does no credit to those who call themselves Aryans and only brings them infamy, barring them from the gates of heaven?"},{"k":"sivananda","t":"The Blessed Lord said, \"From whence has this perilous strait come upon you, this dejection which is unworthy of you, disgraceful, and which will close the gates of heaven upon you, O Arjuna?\""},{"k":"adidevananda","t":"The Lord said, \"Whence comes this despondency upon you, O Arjuna, in this crisis? It is unfitting for a noble person; it is disgraceful and it obstructs one's attainment of heaven.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"O Arjuna, in this perilous place, whence has this impurity come to you, entertained by unenlightened persons, which does not lead to heaven and brings infamy?\""},{"k":"sankaranarayan","t":"The Bhagavat said, \"O Arjuna! At this critical moment, whence did this sinful act come to you, which is practiced by men of low birth and leads to hell, and is inglorious?\""}]},{"ch":2,"vn":3,"dev":"क्लैब्यं मा स्म गमः पार्थ नैतत्त्वय्युपपद्यते।\nक्षुद्रं हृदयदौर्बल्यं त्यक्त्वोत्तिष्ठ परन्तप","iast":"klaibyaṁ mā sma gamaḥ pārtha naitat tvayyupapadyate\nkṣhudraṁ hṛidaya-daurbalyaṁ tyaktvottiṣhṭha parantapa","v":[{"k":"purohit","t":"O Arjuna! Why give way to unmanliness? O thou, who art the terror of thy enemies! Shake off such shameful effeminacy and make ready to act!"},{"k":"sivananda","t":"Do not yield to impotence, O Arjuna, son of Pritha. It does not befit you. Cast off this mean weakness of the heart! Stand up, O conqueror of foes!"},{"k":"adidevananda","t":"Do not yield to unmanliness, O Arjuna, it does not befit you. Shake off this base faint-heartedness and arise, O conqueror of foes!"},{"k":"gambirananda","t":"O Partha, do not yield to unmanliness. This does not befit you. O scorcher of foes, arise, giving up the petty weakness of heart."},{"k":"sankaranarayan","t":"Do not stoop to unmanliness, O son of Kunti! It does not befit you. Shunning the petty weakness of heart, arise, O scorcher of foes!"}]},{"ch":2,"vn":4,"dev":"अर्जुन उवाच\nकथं भीष्ममहं संख्ये द्रोणं च मधुसूदन।\nइषुभिः प्रतियोत्स्यामि पूजार्हावरिसूदन","iast":"arjuna uvācha\nkathaṁ bhīṣhmam ahaṁ sankhye droṇaṁ cha madhusūdana\niṣhubhiḥ pratiyotsyāmi pūjārhāvari-sūdana","v":[{"k":"purohit","t":"Arjuna argued: My Lord! How can I, when the battle rages, send an arrow through Bheeshma and Drona, whom I should revere?"},{"k":"sivananda","t":"Arjuna said, \"O Madhusudana, how can I fight in battle with arrows against Bhishma and Drona, who are worthy of being worshipped, O destroyer of enemies?\""},{"k":"adidevananda","t":"Arjuna said, \"O slayer of foes, how can I aim arrows in battle against Bhisma and Drona, who are worthy of reverence?\""},{"k":"gambirananda","t":"Arjuna said, \"O Madhusudana, O destroyer of enemies, how can I fight with arrows in battle against Bhisma and Drona, who are worthy of adoration?\""},{"k":"sankaranarayan","t":"Arjuna said, \"How can I fight in battle with arrows against Bhisma and Drona, both of whom are worthy of reverence? O slayer of Mandhu, O slayer of foes!\""}]},{"ch":2,"vn":5,"dev":"गुरूनहत्वा हि महानुभावान्\nश्रेयो भोक्तुं भैक्ष्यमपीह लोके।\nहत्वार्थकामांस्तु गुरूनिहैव\nभुञ्जीय भोगान् रुधिरप्रदिग्धान्","iast":"gurūnahatvā hi mahānubhāvān\nśhreyo bhoktuṁ bhaikṣhyamapīha loke\nhatvārtha-kāmāṁstu gurūnihaiva\nbhuñjīya bhogān rudhira-pradigdhān","v":[{"k":"purohit","t":"Rather, I would be content with a beggar's crust than to kill these teachers of mine, these precious noble souls! To slay these masters who are my benefactors would be to stain the sweetness of life's pleasures with their blood."},{"k":"sivananda","t":"Better it is, indeed, in this world to accept alms than to slay the most noble teachers. But if I were to kill them, even in this world, all my enjoyments of wealth and fulfilled desires would be stained with their blood."},{"k":"adidevananda","t":"It is better even to live on a beggar's fare in this world than to slay these most venerable teachers. If I were to slay my teachers, though they may be degraded by desire for wealth, I would only be enjoying blood-stained pleasures here."},{"k":"gambirananda","t":"Rather than killing the noble-minded elders, it is better in this world to live even on alms. But by killing them, we shall only be enjoying here the pleasures of wealth and desirable things drenched in blood."},{"k":"sankaranarayan","t":"It is indeed good to go about begging in this world without killing the elders of great dignity; however, I would not enjoy, with greed for wealth, the blood-stained objects of pleasure by killing my elders."}]},{"ch":2,"vn":6,"dev":"न चैतद्विद्मः कतरन्नो गरीयो\nयद्वा जयेम यदि वा नो जयेयुः।\nयानेव हत्वा न जिजीविषाम\nस्तेऽवस्थिताः प्रमुखे धार्तराष्ट्राः","iast":"na chaitadvidmaḥ kataranno garīyo\nyadvā jayema yadi vā no jayeyuḥ\nyāneva hatvā na jijīviṣhāmas\nte 'vasthitāḥ pramukhe dhārtarāṣhṭrāḥ","v":[{"k":"purohit","t":"Nor can I say whether it would be better for them to conquer me or for me to conquer them, since I would no longer care to live if I killed these sons of Dhritarashtra, who are now preparing for battle."},{"k":"sivananda","t":"I can hardly tell which would be better, that we should conquer them or that they should conquer us. Even the sons of Dhritarashtra, whom we do not wish to slay, stand facing us."},{"k":"adidevananda","t":"We do not know which of the two is better for us: whether our vanquishing them or their vanquishing us. The very sons of Dhrtarastra, whom, if we were to slay, we would not wish to live, even they are standing in array against us."},{"k":"gambirananda","t":"We do not know which is better for us, whether we shall win or they shall conquer us. Those very sons of Dhrtarastra, whom we do not wish to kill, stand in confrontation."},{"k":"sankaranarayan","t":"Whether we should conquer in the battle, or they should conquer us—we do not know which is better for us. For, having killed whom, we would not wish to live at all, the same persons stand before us as Dhrtarastra's men."}]},{"ch":2,"vn":7,"dev":"कार्पण्यदोषोपहतस्वभावः\nपृच्छामि त्वां धर्मसंमूढचेताः।\nयच्छ्रेयः स्यान्निश्िचतं ब्रूहि तन्मे\nशिष्यस्तेऽहं शाधि मां त्वां प्रपन्नम्","iast":"kārpaṇya-doṣhopahata-svabhāvaḥ\npṛichchhāmi tvāṁ dharma-sammūḍha-chetāḥ\nyach-chhreyaḥ syānniśhchitaṁ brūhi tanme\nśhiṣhyaste 'haṁ śhādhi māṁ tvāṁ prapannam","v":[{"k":"purohit","t":"My heart is oppressed with pity, and my mind is confused as to what my duty is. Therefore, my Lord, tell me what is best for my spiritual welfare, for I am Your disciple. Please direct me, I pray."},{"k":"sivananda","t":"My heart is overpowered by the taint of pity; my mind is confused as to my duty. I ask Thee: Tell me decisively what is good for me. I am Thy disciple; instruct me, who has taken refuge in Thee."},{"k":"adidevananda","t":"With my heart stricken by the fault of weak compassion, my mind perplexed about my duty, I implore you to tell me for certain what is good for me. I am your disciple; teach me, who have taken refuge in you."},{"k":"gambirananda","t":"With my nature overpowered by weak commiseration, my mind bewildered about duty, I supplicate You. Tell me for certain what is better; I am Your disciple, having taken refuge in You. Instruct me."},{"k":"sankaranarayan","t":"With my very nature, overpowered by the taint of pity, and with my mind, utterly confused as to the right action at this present juncture, I ask you: Tell me definitely what would be good for me; I am your pupil; please teach me, who is taking refuge in You."}]},{"ch":2,"vn":8,"dev":"न हि प्रपश्यामि ममापनुद्या\nद्यच्छोकमुच्छोषणमिन्द्रियाणाम्।\nअवाप्य भूमावसपत्नमृद्धम्\nराज्यं सुराणामपि चाधिपत्यम्","iast":"na hi prapaśhyāmi mamāpanudyād\nyach-chhokam uchchhoṣhaṇam-indriyāṇām\navāpya bhūmāv-asapatnamṛiddhaṁ\nrājyaṁ surāṇāmapi chādhipatyam","v":[{"k":"purohit","t":"For even if I were to attain the monarchy of the visible world, or the sovereignty over the invisible world, it would not drive away the anguish that is now paralyzing my senses."},{"k":"sivananda","t":"I do not see that this sorrow that burns up my senses would be removed, even if I were to attain prosperous and unrivaled dominion on earth or lordship over the gods."},{"k":"adidevananda","t":"Even if I were to win unchallenged sovereignty of a prosperous earth or even lordship over the Devas, I do not feel that it would dispel the grief that withers up my senses."},{"k":"gambirananda","t":"For I do not see anything that, even after acquiring on this earth a prosperous kingdom free from enemies and even sovereignty over the gods, can remove my sorrow that is blasting the senses."},{"k":"sankaranarayan","t":"I do not clearly see what would drive out my grief, the scorcher of my senses, even after achieving a prosperous and unrivaled kingship on this earth and also the overlordship of the gods in the heavens."}]},{"ch":2,"vn":9,"dev":"सञ्जय उवाच\nएवमुक्त्वा हृषीकेशं गुडाकेशः परन्तप।\nन योत्स्य इति गोविन्दमुक्त्वा तूष्णीं बभूव ह","iast":"sañjaya uvācha\nevam-uktvā hṛiṣhīkeśhaṁ guḍākeśhaḥ parantapa\nna yotsya iti govindam uktvā tūṣhṇīṁ babhūva ha","v":[{"k":"purohit","t":"Sanjaya continued: \"Arjuna, the conqueror of all enemies, then told the Lord of All-Hearts that he would not fight, and became silent, O King!"},{"k":"sivananda","t":"Sanjaya said: Having spoken thus to Hrishikesha, the Lord of the senses, Arjuna, the conqueror of sleep and destroyer of foes, said, \"I will not fight,\" and became silent."},{"k":"adidevananda","t":"Sanjaya said, Having thus spoken to Sri Krsna, Arjuna, the conqueror of sleep and the scorcher of foes, said, \"I will not fight,\" and became silent."},{"k":"gambirananda","t":"Sanjaya said: Having spoken thus to Hrsikesa (Krsna), Gudakesa (Arjuna), the afflictor of foes, verily became silent, telling Govinda, 'I shall not fight.'"},{"k":"sankaranarayan","t":"Sanjaya said, \"O scorcher of foes, Dhrtarastra! Having spoken to Hrsikesa, the master of sense-organs, Govinda, in this manner, and having declared, 'I will not fight,' Gudakesa became silent!\""}]},{"ch":2,"vn":10,"dev":"तमुवाच हृषीकेशः प्रहसन्निव भारत।\nसेनयोरुभयोर्मध्ये विषीदन्तमिदं वचः","iast":"tam-uvācha hṛiṣhīkeśhaḥ prahasanniva bhārata\nsenayorubhayor-madhye viṣhīdantam-idaṁ vachaḥ","v":[{"k":"purohit","t":"Thereupon, the Lord, with a gracious smile, addressed him who was so much depressed in the midst of the two armies."},{"k":"sivananda","t":"To him who was despondent in the midst of the two armies, Krishna, smiling, O Bharata, spoke these words."},{"k":"adidevananda","t":"O King, to him who was thus sorrowing between the two armies, Sri Krishna spoke the following words, as if smiling (by way of ridicule)."},{"k":"gambirananda","t":"O descendant of Bharata, Hrsikesa, mocking as it were, said these words to him who was sorrowing between the two armies:"},{"k":"sankaranarayan","t":"O descendant of Bharata, Hrsikesa, as if smiling, spoke to him who was sinking in despondency between two armies."}]},{"ch":2,"vn":11,"dev":"श्री भगवानुवाच\nअशोच्यानन्वशोचस्त्वं प्रज्ञावादांश्च भाषसे।\nगतासूनगतासूंश्च नानुशोचन्ति पण्डिताः","iast":"śhrī bhagavān uvācha\naśhochyān-anvaśhochas-tvaṁ prajñā-vādānśh cha bhāṣhase\ngatāsūn-agatāsūnśh-cha nānuśhochanti paṇḍitāḥ","v":[{"k":"purohit","t":"Lord Shri Krishna said: Why grieve for those for whom no grief is due, yet professing wisdom? The wise grieve neither for the dead nor the living."},{"k":"sivananda","t":"The Blessed Lord said, \"You have grieved for those who should not be grieved for; yet, you speak words of wisdom. The wise grieve neither for the living nor for the dead.\""},{"k":"adidevananda","t":"The Lord said, \"You grieve for those who should not be grieved for; yet you speak words of wisdom. The wise grieve neither for the dead nor for the living.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"You grieve for those who are not to be grieved for; and you speak words of wisdom! The learned do not grieve for the departed nor for those who have not departed."},{"k":"sankaranarayan","t":"While lamenting for those who cannot be lamented on and those who do not deserve to be lamented on, you do not speak like a wise man! The learned do not lament for those who have departed life and those who have not departed life."},{"k":"arnold","t":"Thou grievest where no grief should be! thou speak'st\nWords lacking wisdom! for the wise in heart\nMourn not for those that live, nor those that die."}]},{"ch":2,"vn":12,"dev":"न त्वेवाहं जातु नासं न त्वं नेमे जनाधिपाः।\nन चैव न भविष्यामः सर्वे वयमतः परम्","iast":"na tvevāhaṁ jātu nāsaṁ na tvaṁ neme janādhipāḥ\nna chaiva na bhaviṣhyāmaḥ sarve vayamataḥ param","v":[{"k":"purohit","t":"There was never a time when I was not, nor you, nor these princes were not; there will never be a time when we shall cease to exist."},{"k":"sivananda","t":"Nor, at any time, was I not, nor thou, nor these rulers of men; nor, verily, shall we ever cease to be hereafter."},{"k":"adidevananda","t":"There never was a time when I did not exist, nor you, nor any of these kings. Nor will there be any time in the future when all of us shall cease to exist."},{"k":"gambirananda","t":"But certainly it is not a fact that I did not exist at any time; nor you, nor these rulers of men. And surely it is not that we all shall cease to exist after this."},{"k":"sankaranarayan","t":"Never indeed at any time did I not exist, nor you, nor these kings; and never shall we all not exist hereafter."}]},{"ch":2,"vn":13,"dev":"देहिनोऽस्मिन्यथा देहे कौमारं यौवनं जरा।\nतथा देहान्तरप्राप्तिर्धीरस्तत्र न मुह्यति","iast":"dehino 'smin yathā dehe kaumāraṁ yauvanaṁ jarā\ntathā dehāntara-prāptir dhīras tatra na muhyati","v":[{"k":"purohit","t":"As the soul experiences infancy, youth, and old age in this body, so finally it passes into another; the wise have no delusion about this."},{"k":"sivananda","t":"Just as the embodied soul passes through childhood, youth, and old age in this body, so too does it pass into another body; the steadfast one does not grieve over this."},{"k":"adidevananda","t":"Just as the self associated with a body passes through childhood, youth, and old age, so too, at death, it passes into another body. A wise man is not deluded by that."},{"k":"gambirananda","t":"As boyhood, youth, and decrepitude are to an embodied being in this present body, so is the acquisition of another body. Therefore, an intelligent person does not get deluded."},{"k":"sankaranarayan","t":"Just as boyhood, youth, and old age come to the embodied soul in this body, so too is the attainment of another body; the wise man is not deluded by this."}]},{"ch":2,"vn":14,"dev":"मात्रास्पर्शास्तु कौन्तेय शीतोष्णसुखदुःखदाः।\nआगमापायिनोऽनित्यास्तांस्तितिक्षस्व भारत","iast":"mātrā-sparśhās tu kaunteya śhītoṣhṇa-sukha-duḥkha-dāḥ\nāgamāpāyino 'nityās tans-titikṣhasva bhārata","v":[{"k":"purohit","t":"Those external relations that bring cold and heat, pain and happiness come and go; they are not permanent. Endure them bravely, O Prince!"},{"k":"sivananda","t":"The contact of the senses with the objects, O son of Kunti, which causes heat and cold, pleasure and pain, has a beginning and an end; they are impermanent; endure them bravely, O Arjuna."},{"k":"adidevananda","t":"The contact of the senses with their objects, O Arjuna, gives rise to feelings of cold and heat, pleasure and pain. They come and go, never lasting long. Endure them, O Arjuna."},{"k":"gambirananda","t":"But the contacts of the organs with the objects are the producers of cold and heat, happiness, and sorrow. They have a beginning and an end and are transient. Bear them, O descendant of Bharata."},{"k":"sankaranarayan","t":"O son of Kunti! The touches with the matras cause feelings of cold and heat, pleasure and pain; they are of the nature of coming and going and are transient. Bear them, O Descendant of Bharata!"}]},{"ch":2,"vn":15,"dev":"यं हि न व्यथयन्त्येते पुरुषं पुरुषर्षभ।\nसमदुःखसुखं धीरं सोऽमृतत्वाय कल्पते","iast":"yaṁ hi na vyathayantyete puruṣhaṁ puruṣharṣhabha\nsama-duḥkha-sukhaṁ dhīraṁ so 'mṛitatvāya kalpate","v":[{"k":"purohit","t":"The hero whose soul is unmoved by circumstances, who accepts pleasure and pain with equanimity, is only fit for immortality."},{"k":"sivananda","t":"That firm man, whom surely these afflictions do not, O chief among men, to whom pleasure and pain are the same, is fit for attaining immortality."},{"k":"adidevananda","t":"For, he whom these do not affect, O chief of men, and to whom pain and pleasure are equal - that steadfast man alone is worthy of immortality."},{"k":"gambirananda","t":"O Arjuna, who is foremost among men, verily, the person whom these do not torment, the wise man to whom sorrow and happiness are the same—he is fit for immortality."},{"k":"sankaranarayan","t":"O best among persons! That wise person becomes immortal, whom these situations do not trouble, and to whom pleasure and pain are equal."}]},{"ch":2,"vn":16,"dev":"नासतो विद्यते भावो नाभावो विद्यते सतः।\nउभयोरपि दृष्टोऽन्तस्त्वनयोस्तत्त्वदर्शिभिः","iast":"nāsato vidyate bhāvo nābhāvo vidyate sataḥ\nubhayorapi dṛiṣhṭo 'nta stvanayos tattva-darśhibhiḥ","v":[{"k":"purohit","t":"That which is not shall never be; that which is shall never cease to be. These truths are self-evident to the wise."},{"k":"sivananda","t":"The unreal has no being; there is no non-being of the real; the truth about both has been seen by the knowers of the truth (or the seers of the essence)."},{"k":"adidevananda","t":"The unreal never comes into being, the real never ceases to be. The truth about these two is seen by the seers."},{"k":"gambirananda","t":"There is no being of the unreal; the real has no non-existence. Yet, the nature of both has been realized by the seers of Truth."},{"k":"sankaranarayan","t":"Birth does not happen to what is non-existent, and destruction to what is existent; the finality of these two has been seen by the seers of reality."}]},{"ch":2,"vn":17,"dev":"अविनाशि तु तद्विद्धि येन सर्वमिदं ततम्।\nविनाशमव्ययस्यास्य न कश्चित् कर्तुमर्हति","iast":"avināśhi tu tadviddhi yena sarvam idaṁ tatam\nvināśham avyayasyāsya na kaśhchit kartum arhati","v":[{"k":"purohit","t":"The Spirit, which pervades all that is seen, is imperishable. Nothing can destroy it."},{"k":"sivananda","t":"Know that to be indestructible, by which all this is pervaded. No one can cause the destruction of that, the Imperishable."},{"k":"adidevananda","t":"Know that to be indestructible by which all this is pervaded. No one can cause the destruction of this immutable."},{"k":"gambirananda","t":"But know that to be indestructible by which all this is pervaded. No one can bring about the destruction of this immutable."},{"k":"sankaranarayan","t":"And know That to be indestructible, by Which all this (universe) is pervaded; no one is capable of causing destruction to this unchanging One."}]},{"ch":2,"vn":18,"dev":"अन्तवन्त इमे देहा नित्यस्योक्ताः शरीरिणः।\nअनाशिनोऽप्रमेयस्य तस्माद्युध्यस्व भारत","iast":"antavanta ime dehā nityasyoktāḥ śharīriṇaḥ\nanāśhino 'prameyasya tasmād yudhyasva bhārata","v":[{"k":"purohit","t":"The material bodies that this Eternal, Indestructible, and Immeasurable Spirit inhabits are all finite; therefore, fight, O valiant man!"},{"k":"sivananda","t":"These bodies of the embodied Self, which are eternal, indestructible, and immeasurable, are said to have an end. Therefore, fight, O Arjuna."},{"k":"adidevananda","t":"These bodies of the Jiva (the embodied self) are said to have an end, while the Jiva itself is eternal, indestructible, and incomprehensible. Therefore, fight, O Bharata (Arjuna)."},{"k":"gambirananda","t":"These destructible bodies are said to belong to the everlasting, indestructible, and indeterminable embodied One. Therefore, O descendant of Bharata, join the battle."},{"k":"sankaranarayan","t":"These physical bodies, which have an end and suffer destruction, are declared to belong to the eternal, embodied Soul, which is indestructible and incomprehensible. Therefore, fight, O descendant of Bharata!"}]},{"ch":2,"vn":19,"dev":"य एनं वेत्ति हन्तारं यश्चैनं मन्यते हतम्।\nउभौ तौ न विजानीतो नायं हन्ति न हन्यते","iast":"ya enaṁ vetti hantāraṁ yaśh chainaṁ manyate hatam\nubhau tau na vijānīto nāyaṁ hanti na hanyate","v":[{"k":"purohit","t":"He who thinks that the Spirit kills, and he who thinks of it as killed, are both ignorant. The Spirit neither kills nor is it killed."},{"k":"sivananda","t":"He who takes the Self to be the slayer and he who thinks it is slain, neither of them knows. It does not slay, nor is it slain."},{"k":"adidevananda","t":"He who considers It (the self) to be the slayer, and he who thinks of It as slain—both are ignorant. For, the self neither slays nor is being slain."},{"k":"gambirananda","t":"He who thinks of this One as the killer, and he who thinks of this One as the one being killed, both of them do not know. This One neither kills nor is It killed."},{"k":"sankaranarayan","t":"Whoever views This as the slayer and whoever believes This to be the slain, both of them do not understand: This does not slay, nor is This slain."}]},{"ch":2,"vn":20,"dev":"न जायते म्रियते वा कदाचि\nन्नायं भूत्वा भविता वा न भूयः।\nअजो नित्यः शाश्वतोऽयं पुराणो\nन हन्यते हन्यमाने शरीरे","iast":"na jāyate mriyate vā kadāchin\nnāyaṁ bhūtvā bhavitā vā na bhūyaḥ\najo nityaḥ śhāśhvato 'yaṁ purāṇo\nna hanyate hanyamāne śharīre","v":[{"k":"purohit","t":"It was not born; it will never die, nor, once having been, can it cease to exist. Unborn, eternal, ever-enduring, yet most ancient, the spirit does not die when the body is dead."},{"k":"sivananda","t":"It is not born, nor does it ever die; after having been, it again does not cease to be; unborn, eternal, changeless, and ancient, it is not killed when the body is killed."},{"k":"adidevananda","t":"It is never born; it never dies; having come into existence once, it never ceases to exist. Unborn, eternal, perpetual, and primordial, it is not destroyed when the body is destroyed."},{"k":"gambirananda","t":"Never is this One born, nor does It ever die; nor, having come into existence, does It cease to be. This One is birthless, eternal, undecaying, and ancient; It is not killed when the body is killed."},{"k":"sankaranarayan","t":"This is neither born nor ever dies; nor, having not been at one time, will it come to be again. It is unborn, destructionless, eternal, and ancient, and is not slain even when the body is slain."},{"k":"arnold","t":"Never the spirit was born; the spirit shall cease to be never;\nNever was time it was not; End and Beginning are dreams!\nBirthless and deathless and changeless remaineth the spirit for ever;\nDeath hath not touched it at all, dead though the house of it seems!"}]},{"ch":2,"vn":21,"dev":"वेदाविनाशिनं नित्यं य एनमजमव्ययम्।\nकथं स पुरुषः पार्थ कं घातयति हन्ति कम्","iast":"vedāvināśhinaṁ nityaṁ ya enam ajam avyayam\nkathaṁ sa puruṣhaḥ pārtha kaṁ ghātayati hanti kam","v":[{"k":"purohit","t":"He who knows the Spirit to be indestructible, immortal, unborn, and always the same, how should he kill or cause to be killed?"},{"k":"sivananda","t":"Whoever knows it to be indestructible, eternal, unborn, and inexhaustible, how can that person slay, O Arjuna, or cause to be slain?"},{"k":"adidevananda","t":"He who knows this self to be indestructible, unborn, unchanging, and thus eternal—how, O Arjuna, does he cause anyone to be killed, and whom does he kill?"},{"k":"gambirananda","t":"O Partha, he who knows this One as indestructible, eternal, birthless, and undecaying—how can that person kill, or cause to be killed, whom?"},{"k":"sankaranarayan","t":"Whoever realizes this to be changeless, destructionless, unborn, and immutable, how can that person be slain? How can they slay anyone else? O son of Prtha!"}]},{"ch":2,"vn":22,"dev":"वासांसि जीर्णानि यथा विहाय\nनवानि गृह्णाति नरोऽपराणि।\nतथा शरीराणि विहाय जीर्णा\nन्यन्यानि संयाति नवानि देही","iast":"vāsānsi jīrṇāni yathā vihāya\nnavāni gṛihṇāti naro 'parāṇi\ntathā śharīrāṇi vihāya jīrṇānya\nnyāni sanyāti navāni dehī","v":[{"k":"purohit","t":"As a man discards his threadbare robes and puts on new ones, so the Spirit throws off its worn-out bodies and takes on fresh ones."},{"k":"sivananda","t":"Just as a man casts off worn-out clothes and puts on new ones, so too the embodied Self casts off worn-out bodies and enters others that are new."},{"k":"adidevananda","t":"As a man casts off worn-out garments and puts on new ones, so does the embodied self cast off its worn-out bodies and enter into new ones."},{"k":"gambirananda","t":"As after rejecting worn-out clothes, a man takes up other new ones, likewise, after rejecting worn-out bodies, the embodied one unites with other new ones."},{"k":"sankaranarayan","t":"Just as a man rejects tattered garments and takes on new ones, so too, the embodied Self, discarding worn-out bodies, rightly obtains new ones."},{"k":"arnold","t":"Nay, but as when one layeth\nHis worn-out robes away,\nAnd taking new ones, sayeth,\n\"These will I wear to-day!\"\nSo putteth by the spirit\nLightly its garb of flesh,\nAnd passeth to inherit\nA residence afresh."}]},{"ch":2,"vn":23,"dev":"नैनं छिन्दन्ति शस्त्राणि नैनं दहति पावकः।\nन चैनं क्लेदयन्त्यापो न शोषयति मारुतः","iast":"nainaṁ chhindanti śhastrāṇi nainaṁ dahati pāvakaḥ\nna chainaṁ kledayantyāpo na śhoṣhayati mārutaḥ","v":[{"k":"purohit","t":"Weapons cannot cleave it, fire cannot burn it, water cannot drench it, and wind cannot dry it."},{"k":"sivananda","t":"Weapons cannot cut it, fire cannot burn it, water cannot wet it, wind cannot dry it."},{"k":"adidevananda","t":"Weapons cannot cleave It, fire cannot burn It, waters cannot wet It, and wind cannot dry It."},{"k":"gambirananda","t":"Weapons cannot cut It, fire cannot burn It, water cannot moisten It, and air cannot dry It."},{"k":"sankaranarayan","t":"Weapons cannot cut This; fire cannot burn This; water cannot make This wet; and the wind cannot make This dry."},{"k":"arnold","t":"I say to thee weapons reach not the Life;\nFlame burns it not, waters cannot o'erwhelm,\nNor dry winds wither it."}]},{"ch":2,"vn":24,"dev":"अच्छेद्योऽयमदाह्योऽयमक्लेद्योऽशोष्य एव च।\nनित्यः सर्वगतः स्थाणुरचलोऽयं सनातनः","iast":"achchhedyo 'yam adāhyo 'yam akledyo 'śhoṣhya eva cha\nnityaḥ sarva-gataḥ sthāṇur achalo 'yaṁ sanātanaḥ","v":[{"k":"purohit","t":"It is impenetrable; it cannot be drowned, scorched, or dried. It is eternal, all-pervasive, unchanging, immovable, and most ancient."},{"k":"sivananda","t":"This Self cannot be cut, burned, wetted, nor dried up; it is eternal, all-pervasive, stable, immovable, and ancient."},{"k":"adidevananda","t":"It cannot be cleaved; It cannot be burned; It cannot be wetted, and It cannot be dried; It is eternal, all-pervasive, stable, immovable, and primordial."},{"k":"gambirananda","t":"It cannot be cut, burned, moistened, or dried up; it is eternal, omnipresent, stationary, unmoving, and unchanging."},{"k":"sankaranarayan","t":"This cannot be cut; this cannot be burnt; this cannot be made wet nor dried; this is eternal, all-pervading, stable, immovable, and everlasting."}]},{"ch":2,"vn":25,"dev":"अव्यक्तोऽयमचिन्त्योऽयमविकार्योऽयमुच्यते।\nतस्मादेवं विदित्वैनं नानुशोचितुमर्हसि","iast":"avyakto 'yam achintyo 'yam avikāryo 'yam uchyate\ntasmādevaṁ viditvainaṁ nānuśhochitum arhasi","v":[{"k":"purohit","t":"It is named the Unmanifest, the Unthinkable, and the immutable. Therefore, knowing the Spirit as such, you have no cause to grieve."},{"k":"sivananda","t":"This Self is said to be unmanifested, unthinkable, and unchangeable. Therefore, knowing this to be so, you should not grieve."},{"k":"adidevananda","t":"This (self) is said to be unmanifest, inconceivable, and unchanging. Therefore, knowing it thus, it does not befit you to grieve."},{"k":"gambirananda","t":"It is said that This is unmanifest; This is inconceivable; This is unchangeable. Therefore, having known This thus, you ought not to grieve."},{"k":"sankaranarayan","t":"This is declared to be non-evident, imponderable, and unchangeable. Therefore, understanding this as such, you should not lament."}]},{"ch":2,"vn":26,"dev":"अथ चैनं नित्यजातं नित्यं वा मन्यसे मृतम्।\nतथापि त्वं महाबाहो नैवं शोचितुमर्हसि","iast":"atha chainaṁ nitya-jātaṁ nityaṁ vā manyase mṛitam\ntathāpi tvaṁ mahā-bāho naivaṁ śhochitum arhasi","v":[{"k":"purohit","t":"Even if thou thinkest of it as constantly being born and constantly dying, O Mighty Man, thou still hast no cause to grieve."},{"k":"sivananda","t":"But even if thou thinkest of It as constantly being born and constantly dying, even then, O mighty-armed one, thou shouldst not grieve."},{"k":"adidevananda","t":"Or, if you consider this self as constantly being born and constantly dying, O mighty-armed one, it still does not become you to feel grief."},{"k":"gambirananda","t":"On the other hand, if you think this One is born continually or constantly dies, even then, O mighty-armed one, you should not grieve."},{"k":"sankaranarayan","t":"On the other hand, if you deem this as being born constantly or as dying constantly, even then, O mighty-armed one, you should not lament."}]},{"ch":2,"vn":27,"dev":"जातस्य हि ध्रुवो मृत्युर्ध्रुवं जन्म मृतस्य च।\nतस्मादपरिहार्येऽर्थे न त्वं शोचितुमर्हसि","iast":"jātasya hi dhruvo mṛityur dhruvaṁ janma mṛitasya cha\ntasmād aparihārye 'rthe na tvaṁ śhochitum arhasi","v":[{"k":"purohit","t":"For death is certain for that which is born, just as birth is certain for that which is dead. Therefore, do not grieve for what is inevitable."},{"k":"sivananda","t":"For the born, death is certain, and for the dead, birth is certain; therefore, you should not grieve over the inevitable."},{"k":"adidevananda","t":"For, death is certain for the born, and rebirth is certain for the dead; therefore, you should not grieve for what is inevitable."},{"k":"gambirananda","t":"For the death of anyone born is certain, and the rebirth of the dead is certain. Therefore, you should not grieve over an inevitable fact."},{"k":"sankaranarayan","t":"Death is certain indeed for what is born; and birth is certain for the dead. Therefore, you should not lament over something that is unavoidable."}]},{"ch":2,"vn":28,"dev":"अव्यक्तादीनि भूतानि व्यक्तमध्यानि भारत।\nअव्यक्तनिधनान्येव तत्र का परिदेवना","iast":"avyaktādīni bhūtāni vyakta-madhyāni bhārata\navyakta-nidhanānyeva tatra kā paridevanā","v":[{"k":"purohit","t":"The end and beginning of beings are unknown; we only see the intervening formations. So, what is there to grieve about?"},{"k":"sivananda","t":"Beings are unmanifest in their beginning, manifest in their middle state, O Arjuna, and unmanifest again in their end. What is there to grieve about?"},{"k":"adidevananda","t":"O Arjuna, beings have an unknown beginning, a known middle, and an unknown end. What is there to grieve about in all this?"},{"k":"gambirananda","t":"O descendant of Bharata, all beings remain unmanifested in the beginning; they become manifested in the middle. After death, they certainly become unmanifested. What lamentation can there be for them?"},{"k":"sankaranarayan","t":"O descendant of Bharata! The beings have an unmanifest beginning, a manifest middle, and an unmanifest end. Therefore, why mourn?"}]},{"ch":2,"vn":29,"dev":"आश्चर्यवत्पश्यति कश्चिदेन\nमाश्चर्यवद्वदति तथैव चान्यः।\nआश्चर्यवच्चैनमन्यः श्रृणोति\nश्रुत्वाप्येनं वेद न चैव कश्चित्","iast":"āśhcharya-vat paśhyati kaśhchid enan\nāśhcharya-vad vadati tathaiva chānyaḥ\nāśhcharya-vach chainam anyaḥ śhṛiṇoti\nśhrutvāpyenaṁ veda na chaiva kaśhchit","v":[{"k":"purohit","t":"One hears of the Spirit with surprise, another thinks it marvelous, the third listens without comprehending. Thus, though many are told about it, scarcely is there one who knows it."},{"k":"sivananda","t":"One sees this (the Self) as a wonder; another speaks of it as a wonder; another hears of it as a wonder; yet, having heard, none understands it at all."},{"k":"adidevananda","t":"One regards This (self) as a wonder; another speaks of It as a wonder; yet another hears of It as a wonder; and even after hearing of It, one does not know It."},{"k":"gambirananda","t":"Someone visualizes it as a wonder; someone else talks of it as a wonder; someone else hears of it as a wonder; and yet someone else does not even realize it after hearing about it."},{"k":"sankaranarayan","t":"This someone observes as a wonder; similarly, another speaks of This as a wonder; another hears This as a wonder; but even after hearing, not even one understands This."}]},{"ch":2,"vn":30,"dev":"देही नित्यमवध्योऽयं देहे सर्वस्य भारत।\nतस्मात्सर्वाणि भूतानि न त्वं शोचितुमर्हसि","iast":"dehī nityam avadhyo 'yaṁ dehe sarvasya bhārata\ntasmāt sarvāṇi bhūtāni na tvaṁ śhochitum arhasi","v":[{"k":"purohit","t":"Do not be anxious about these armies; the spirit in man is imperishable."},{"k":"sivananda","t":"This indweller in the body of everyone is ever indestructible, O Arjuna; therefore, you should not grieve for any creature."},{"k":"adidevananda","t":"The self in the body, O Arjuna, is eternal and indestructible. This is the case for all selves in all bodies. Therefore, it is not fitting for you to feel grief for any being."},{"k":"gambirananda","t":"O descendant of Bharata, this embodied Self existing in everyone's body can never be killed; therefore, you ought not to grieve for all these beings."},{"k":"sankaranarayan","t":"O descendant of Bharata! This embodied One in the body of everyone is ever incapable of being slain. Therefore, you should not lament over all beings."}]},{"ch":2,"vn":31,"dev":"स्वधर्ममपि चावेक्ष्य न विकम्पितुमर्हसि।\nधर्म्याद्धि युद्धाछ्रेयोऽन्यत्क्षत्रियस्य न विद्यते","iast":"swa-dharmam api chāvekṣhya na vikampitum arhasi\ndharmyāddhi yuddhāch chhreyo 'nyat kṣhatriyasya na vidyate","v":[{"k":"purohit","t":"You must look at your duty. Nothing can be more welcome to a soldier than a righteous war. Therefore, wavering in this resolve is unworthy, O Arjuna!"},{"k":"sivananda","t":"Further, having regard to your duty, you should not waver, for there is nothing higher for a Kshatriya than a righteous war."},{"k":"adidevananda","t":"Further, considering also your own duty, it does not befit you to waver. For, to a Kshatriya, there is no greater good than a righteous war."},{"k":"gambirananda","t":"Even considering your own duty, you should not waver, since there is nothing better for a Ksatriya than a righteous battle."},{"k":"sankaranarayan","t":"Further, considering your own duty, you should not waver. Indeed, for a Kshatriya there is no duty superior to fighting a righteous war."}]},{"ch":2,"vn":32,"dev":"यदृच्छया चोपपन्नं स्वर्गद्वारमपावृतम्।\nसुखिनः क्षत्रियाः पार्थ लभन्ते युद्धमीदृशम्","iast":"yadṛichchhayā chopapannaṁ swarga-dvāram apāvṛitam\nsukhinaḥ kṣhatriyāḥ pārtha labhante yuddham īdṛiśham","v":[{"k":"purohit","t":"Blessed are the soldiers who find their opportunity; this opportunity has opened for thee the gates of heaven."},{"k":"sivananda","t":"Happy are the Kshatriyas, O Arjuna! who are called to fight in such a battle that comes of its own accord as an open door to heaven."},{"k":"adidevananda","t":"Happy are the Ksatriyas, O Arjuna, to whom such a war comes of its own accord; it opens the gates to heaven."},{"k":"gambirananda","t":"O son of Partha, happy are the Kshatriyas who come across such a battle, which presents itself unsought and is an open gate to heaven."},{"k":"sankaranarayan","t":"O son of Prtha! By good fortune, Ksatriyas, desirous of happiness, get a war of this type, which has come of its own accord and which is an open door to heaven."}]},{"ch":2,"vn":33,"dev":"अथ चैत्त्वमिमं धर्म्यं संग्रामं न करिष्यसि।\nततः स्वधर्मं कीर्तिं च हित्वा पापमवाप्स्यसि","iast":"atha chet tvam imaṁ dharmyaṁ saṅgrāmaṁ na kariṣhyasi\ntataḥ sva-dharmaṁ kīrtiṁ cha hitvā pāpam avāpsyasi","v":[{"k":"purohit","t":"Refuse to fight in this righteous cause, and you will be a traitor, losing fame, incurring only sin."},{"k":"sivananda","t":"But if you will not fight this righteous war, then having abandoned your own duty and reputation, you will incur sin."},{"k":"adidevananda","t":"But if you do not fight this righteous war, you will be turning away from your duty and honor, and will incur sin."},{"k":"gambirananda","t":"On the other hand, if you do not fight this righteous battle, then you will incur sin, forsaking your own duty and fame."},{"k":"sankaranarayan","t":"On the other hand, if you do not fight this righteous war, then you will incur sin by shirking your own duty and forfeiting your fame."}]},{"ch":2,"vn":34,"dev":"अकीर्तिं चापि भूतानि कथयिष्यन्ति तेऽव्ययाम्।\nसंभावितस्य चाकीर्तिर्मरणादतिरिच्यते","iast":"akīrtiṁ chāpi bhūtāni\nkathayiṣhyanti te 'vyayām\nsambhāvitasya chākīrtir\nmaraṇād atirichyate","v":[{"k":"purohit","t":"Men will talk forever of thy disgrace; and to the noble, dishonor is worse than death."},{"k":"sivananda","t":"People will also recount your everlasting dishonor; and for one who has been honored, dishonor is worse than death."},{"k":"adidevananda","t":"Further, people will speak ill of you for all time, and for one accustomed to being honored, dishonor is worse than death."},{"k":"gambirananda","t":"People also will speak of your unending infamy, and to an honored person, infamy is worse than death."},{"k":"sankaranarayan","t":"The creatures will speak of your endless ill-fame; and for one who has been highly esteemed, ill-fame is worse than death."}]},{"ch":2,"vn":35,"dev":"भयाद्रणादुपरतं मंस्यन्ते त्वां महारथाः।\nयेषां च त्वं बहुमतो भूत्वा यास्यसि लाघवम्","iast":"bhayād raṇād uparataṁ mansyante tvāṁ mahā-rathāḥ\nyeṣhāṁ cha tvaṁ bahu-mato bhūtvā yāsyasi lāghavam","v":[{"k":"purohit","t":"Great generals will think that you have fled from the battlefield out of cowardice; though once honored, you will seem despicable."},{"k":"sivananda","t":"The great chariot-warriors will think that you have withdrawn from the battle out of fear, and you will be held in low esteem by those who have held you in high regard."},{"k":"adidevananda","t":"The great warriors will think that you have fled from battle out of fear. Those who held you in high esteem will now speak of you disparagingly."},{"k":"gambirananda","t":"The great chariot-riders will think of you as having desisted from the fight out of fear, and you will fall into disgrace before them whom you had been estimable to."},{"k":"sankaranarayan","t":"The mighty charioteers will think of you as having withdrawn from the battle out of fear; having been highly esteemed by these men, you will be viewed lightly."}]},{"ch":2,"vn":36,"dev":"अवाच्यवादांश्च बहून् वदिष्यन्ति तवाहिताः।\nनिन्दन्तस्तव सामर्थ्यं ततो दुःखतरं नु किम्","iast":"avāchya-vādānśh cha bahūn vadiṣhyanti tavāhitāḥ\nnindantastava sāmarthyaṁ tato duḥkhataraṁ nu kim","v":[{"k":"purohit","t":"Your enemies will spread scandal and mock your courage. Is there anything more humiliating?"},{"k":"sivananda","t":"Your enemies, scoffing at your power, will speak many abusive words—what could be more painful than this?"},{"k":"adidevananda","t":"Your enemies, slandering your prowess, will use words that should never be uttered. What could be more painful than that?"},{"k":"gambirananda","t":"And your enemies will speak many indecent words while denigrating your power. What can be more painful than that?"},{"k":"sankaranarayan","t":"Your enemies will slander your abilities and speak of you in many sayings that should not be spoken. Is there anything more painful than that?"}]},{"ch":2,"vn":37,"dev":"हतो वा प्राप्स्यसि स्वर्गं जित्वा वा भोक्ष्यसे महीम्।\nतस्मादुत्तिष्ठ कौन्तेय युद्धाय कृतनिश्चयः","iast":"hato vā prāpsyasi swargaṁ jitvā vā bhokṣhyase mahīm\ntasmād uttiṣhṭha kaunteya yuddhāya kṛita-niśhchayaḥ","v":[{"k":"purohit","t":"If you are killed, you will attain Heaven; if you are victorious, you will enjoy the kingdom of earth. Therefore, arise, O Son of Kunti, and fight!"},{"k":"sivananda","t":"Slain, you will obtain heaven; victorious, you will enjoy the earth; therefore, stand up, O son of Kunti, resolved to fight."},{"k":"adidevananda","t":"If slain, you will win heaven; or if victorious, you will enjoy the earth. Therefore, arise, O Arjuna, resolved to fight."},{"k":"gambirananda","t":"Either by being killed, you will attain heaven, or by winning, you will enjoy the earth. Therefore, O Arjuna, rise up with determination to fight."},{"k":"sankaranarayan","t":"If you are slain, you shall attain heaven; or if you conquer, you shall enjoy the earth. Therefore, O son of Kunti, stand up with resolution made in favor of fighting the battle."}]},{"ch":2,"vn":38,"dev":"सुखदुःखे समे कृत्वा लाभालाभौ जयाजयौ।\nततो युद्धाय युज्यस्व नैवं पापमवाप्स्यसि","iast":"sukha-duḥkhe same kṛitvā lābhālābhau jayājayau\ntato yuddhāya yujyasva naivaṁ pāpam avāpsyasi","v":[{"k":"purohit","t":"Look upon pleasure and pain, victory and defeat, with an equal eye. Be prepared for the combat, and you will commit no sin."},{"k":"sivananda","t":"Having made pleasure and pain, gain and loss, victory and defeat equal, engage in battle for the sake of battle; thus, you shall not incur sin."},{"k":"adidevananda","t":"Holding pleasure and pain, gain and loss, victory and defeat as equal, gird yourself up for the battle. Thus, you shall not incur any sin."},{"k":"gambirananda","t":"Treating happiness and sorrow, gain and loss, and conquest and defeat with equanimity, then engage in battle. Thus, you will not incur sin."},{"k":"sankaranarayan","t":"Viewing pleasure and pain, gain and loss, victory and defeat alike, you should get yourself ready for the battle. Thus, you will not incur sin."}]},{"ch":2,"vn":39,"dev":"एषा तेऽभिहिता सांख्ये बुद्धिर्योगे त्विमां श्रृणु।\nबुद्ध्यायुक्तो यया पार्थ कर्मबन्धं प्रहास्यसि","iast":"eṣhā te 'bhihitā sānkhye\nbuddhir yoge tvimāṁ śhṛiṇu\nbuddhyā yukto yayā pārtha\nkarma-bandhaṁ prahāsyasi","v":[{"k":"purohit","t":"I have told you the philosophy of knowledge. Now, listen, and I will explain the philosophy of action, by means of which, O Arjuna, you will break through the bondage of all action."},{"k":"sivananda","t":"This, which has been taught to you, is wisdom concerning Sankhya. Now listen to wisdom concerning Yoga, endowed with which, O Arjuna, you shall cast off the bonds of action."},{"k":"adidevananda","t":"This Buddhi concerning the Self (Sankhya) has been imparted to you. Now listen to this with regard to Yoga, by following which you will get rid of the bondage of Karma."},{"k":"gambirananda","t":"O Partha, this wisdom has been imparted to you from the standpoint of Self-realization. But listen to this wisdom from the standpoint of Yoga, endowed with which, you will get rid of the bondage of action."},{"k":"sankaranarayan","t":"Listen, how this knowledge, imparted to you for your Sankhya, is also for the Yoga; endowed with this knowledge, you shall cast off the bondage of action, O son of Prtha!"}]},{"ch":2,"vn":40,"dev":"नेहाभिक्रमनाशोऽस्ति प्रत्यवायो न विद्यते।\nस्वल्पमप्यस्य धर्मस्य त्रायते महतो भयात्","iast":"nehābhikrama-nāśho 'sti pratyavāyo na vidyate\nsvalpam apyasya dharmasya trāyate mahato bhayāt","v":[{"k":"purohit","t":"On this path, endeavour is never wasted nor repressed. Even a little practice of it protects one from great danger."},{"k":"sivananda","t":"In this, there is no loss of effort, nor is there any harm produced, nor any transgression. Even a little of this knowledge protects one from great fear."},{"k":"adidevananda","t":"Here, there is no loss of effort, nor any accrual of evil. Even a little of this Dharma (called Karma Yoga) protects one from the great fear."},{"k":"gambirananda","t":"Here, there is no waste of effort; nor is there any harm. Even a little of this righteousness saves one from great fear."},{"k":"sankaranarayan","t":"Here, there is no loss due to transgression, and there is no contrary downward course (sin); even a little of this righteous thing can save one from great danger."}]},{"ch":2,"vn":41,"dev":"व्यवसायात्मिका बुद्धिरेकेह कुरुनन्दन।\nबहुशाखा ह्यनन्ताश्च बुद्धयोऽव्यवसायिनाम्","iast":"vyavasāyātmikā buddhir ekeha kuru-nandana\nbahu-śhākhā hyanantāśh cha buddhayo 'vyavasāyinām","v":[{"k":"purohit","t":"By its means, the straying intellect becomes steadied in contemplating one object only; whereas the minds of the irresolute stray into innumerable bypaths."},{"k":"sivananda","t":"Here, O joy of the Kurus, there is only one single-pointed determination; many-branched and endless are the thoughts of the indecisive."},{"k":"adidevananda","t":"In this (Karma Yoga), O Arjuna, the resolute mind is single-pointed; the minds of the irresolute are multi-branched and endless."},{"k":"gambirananda","t":"O scion of the Kuru dynasty, in this there is a single, one-pointed conviction. The thoughts of the irresolute ones, however, have many branches indeed and are innumerable."},{"k":"sankaranarayan","t":"O source of joy to the Kurus! The knowledge in the form of determination is one; however, the knowledge (thoughts) of those who lack determination has many branches and has no end."}]},{"ch":2,"vn":42,"dev":"यामिमां पुष्पितां वाचं प्रवदन्त्यविपश्चितः।\nवेदवादरताः पार्थ नान्यदस्तीति वादिनः","iast":"yāmimāṁ puṣhpitāṁ vāchaṁ pravadanty-avipaśhchitaḥ\nveda-vāda-ratāḥ pārtha nānyad astīti vādinaḥ\nkāmātmānaḥ swarga-parā janma-karma-phala-pradām\nkriyā-viśheṣha-bahulāṁ bhogaiśhwarya-gatiṁ prati","v":[{"k":"purohit","t":"Only the ignorant speak in figurative language; it is they who extol the letter of the scriptures, saying, \"There is nothing deeper than this.\""},{"k":"sivananda","t":"The unwise, taking pleasure in the eulogizing words of the Vedas, utter flowery speech, saying, \"There is nothing else,\" O Arjuna."},{"k":"adidevananda","t":"- O Partha, the unwise, who rejoice in the letter of the Vedas, say, \"There is nothing else.\" They are full only of worldly desires and they hanker for heaven. They speak flowery words that offer mirth as the fruit of work. They look upon the Vedas as consisting entirely of varied rites for the attainment of pleasure and power. Those who cling so to pleasure and power are attracted by that speech (offering heavenly rewards) and are unable to develop the resolute will of a concentrated mind."},{"k":"gambirananda","t":"O son of Prtha, those undiscerning people who utter this flowery talk, which promises birth as a result of rites and duties, and is full of various special rites meant for the attainment of enjoyment and affluence, remain engrossed in the utterances of the Vedas and declare that nothing else exists; their minds are full of desires and they have heaven as their goal."},{"k":"sankaranarayan","t":"-. O son of Prtha! Those whose very nature is desire, whose goal is heaven, who esteem only the Vedic declaration [of fruits], who declare that there is nothing else, who proclaim this flowery speech about the paths to the lordship of the objects of enjoyment—paths that are full of different actions—and who desire action alone as a fruit of their birth—they are men without insight."}]},{"ch":2,"vn":43,"dev":"कामात्मानः स्वर्गपरा जन्मकर्मफलप्रदाम्।\nक्रियाविशेषबहुलां भोगैश्वर्यगतिं प्रति","iast":"kāmātmānaḥ svarga-parā\njanma-karma-phala-pradām\nkriyā-viśeṣa-bahulāṁ\nbhogaiśvarya-gatiṁ prati","v":[{"k":"purohit","t":"Consulting only their own desires, they construct their own heaven, devising arduous and complex rites to secure their own pleasure and power; and the only result is rebirth."},{"k":"sivananda","t":"Full of desires, with heaven as their goal, (they speak words that are directed to ends) leading to new births as the result of their works, and prescribe various methods abounding in specific actions, for the attainment of pleasure and power."},{"k":"adidevananda","t":"- O Partha, the unwise, who rejoice in the letter of the Vedas, say, \"There is nothing else.\" They are full only of worldly desires and they yearn for heaven. They speak flowery words that offer mirth as the fruit of work. They view the Vedas as consisting entirely of varied rites for the attainment of pleasure and power. Those who cling so to pleasure and power are attracted by that speech (offering heavenly rewards) and are unable to develop the resolute will of a focused mind."},{"k":"gambirananda","t":"O son of Prtha, those undiscerning people who utter this flowery talk, which promises birth as a result of rites and duties, and is full of various special rites meant for the attainment of enjoyment and affluence, remain engrossed in the utterances of the Vedas and declare that nothing else exists; their minds are full of desires and they have heaven as their goal."},{"k":"sankaranarayan","t":"-. O son of Prtha! Those whose very nature is desire, whose goal is heaven, who esteem only the Vedic declaration [of fruits], who declare that there is nothing else, who proclaim this flowery speech about the paths to the lordship of the objects of enjoyment—paths that are full of different actions—and who desire action alone as a fruit of their birth—they are men without insight."}]},{"ch":2,"vn":44,"dev":"भोगैश्वर्यप्रसक्तानां तयापहृतचेतसाम्।\nव्यवसायात्मिका बुद्धिः समाधौ न विधीयते","iast":"bhogaiśwvarya-prasaktānāṁ tayāpahṛita-chetasām\nvyavasāyātmikā buddhiḥ samādhau na vidhīyate","v":[{"k":"purohit","t":"While their minds are absorbed with thoughts of power and personal enjoyment, they cannot focus their discrimination on one point."},{"k":"sivananda","t":"For those who are attached to pleasure and power, whose minds are drawn away by such teachings, their determinate reason is not formed which is steadily bent on meditation and Samadhi (superconscious state)."},{"k":"adidevananda","t":"- O Partha, the unwise, who rejoice in the letter of the Vedas, say, \"There is nothing else.\" They are full only of worldly desires and they hanker for heaven. They speak flowery words that offer mirth as the fruit of work. They look upon the Vedas as consisting entirely of varied rites for the attainment of pleasure and power. Those who cling so to pleasure and power are attracted by that speech (offering heavenly rewards) and are unable to develop the resolute will of a concentrated mind."},{"k":"gambirananda","t":"One-pointed conviction does not become established in the minds of those who delight in enjoyment and affluence, and whose intellects are carried away by it."},{"k":"sankaranarayan","t":"Those who are very attached to the ownership of enjoyable objects and whose minds have been carried away by that (flowery speech) - their knowledge, in the form of determination, is not prescribed for concentration."}]},{"ch":2,"vn":45,"dev":"त्रैगुण्यविषया वेदा निस्त्रैगुण्यो भवार्जुन।\nनिर्द्वन्द्वो नित्यसत्त्वस्थो निर्योगक्षेम आत्मवान्","iast":"trai-guṇya-viṣhayā vedā nistrai-guṇyo bhavārjuna\nnirdvandvo nitya-sattva-stho niryoga-kṣhema ātmavān","v":[{"k":"purohit","t":"The Vedic Scriptures tell of the three constituents of life—the Qualities. Rise above all of them, O Arjuna, above all the pairs of opposing sensations; be steadfast in truth, free from worldly anxieties, and centered in the Self."},{"k":"sivananda","t":"The Vedas deal with the three attributes; be thou above these three attributes. O Arjuna, free yourself from the pairs of opposites and ever remain in the quality of Sattva, freed from acquisition and preservation, and be established in the Self."},{"k":"adidevananda","t":"The Vedas have the three Gunas as their sphere, O Arjuna. You must be free from the three Gunas and be free from the pairs of opposites. Abide in pure Sattva; never care to acquire things and to protect what has been acquired, but be established in the Self."},{"k":"gambirananda","t":"O Arjuna, the Vedas [Meaning only the portion dealing with rites and duties (karma-kanda).] have the three qualities as their object. You become free from worldliness, free from the pairs of duality, ever-poised in the quality of sattva, without (desire for) acquisition and protection, and self-collected."},{"k":"sankaranarayan","t":"The Vedas bind through the three strands. Therefore, O Arjuna, be free from the three strands, free from the pairs of opposites; be established in this eternal Being; be free from acquisition and preservation; and possess the Self."}]},{"ch":2,"vn":46,"dev":"यावानर्थ उदपाने सर्वतः संप्लुतोदके।\nतावान्सर्वेषु वेदेषु ब्राह्मणस्य विजानतः","iast":"yāvān artha udapāne sarvataḥ samplutodake\ntāvānsarveṣhu vedeṣhu brāhmaṇasya vijānataḥ","v":[{"k":"purohit","t":"As a man can drink water from any side of a full tank, so the skilled theologian can extract from any scripture that which will serve their purpose."},{"k":"sivananda","t":"To the Brahmana who has known the Self, all the Vedas are of as much use as a reservoir of water would be in a place where there is a flood."},{"k":"adidevananda","t":"What use does a thirsty person have for a water reservoir when all sides of it are flooded—that is the only use of all the Vedas for a Brahmana who knows."},{"k":"gambirananda","t":"A Brahmana with realization has that much utility in all the Vedas as a person has in a well when there is a flood all around."},{"k":"sankaranarayan","t":"What portion of a reservoir, flooded with water everywhere, is useful for a man in thirst? That much portion alone in all the Vedas is useful for an intelligent student of the Vedas."}]},{"ch":2,"vn":47,"dev":"कर्मण्येवाधिकारस्ते मा फलेषु कदाचन।\nमा कर्मफलहेतुर्भूर्मा ते सङ्गोऽस्त्वकर्मणि","iast":"karmaṇy-evādhikāras te mā phaleṣhu kadāchana\nmā karma-phala-hetur bhūr mā te saṅgo 'stvakarmaṇi","v":[{"k":"purohit","t":"But you have only the right to work, but none to the fruit of it. Let not the fruit of your action be your motive; nor be you enamored of inaction."},{"k":"sivananda","t":"Your right is only to work, but not to its results; do not let the results of action be your motive, nor let your attachment be to inaction."},{"k":"adidevananda","t":"You have the right to work alone, but not to the fruits of it. Do not be driven by the results of your work, nor have attachment to inaction."},{"k":"gambirananda","t":"Your right is only to act, not to the results. Do not be the cause of the results of action. Do not have any inclination towards inaction."},{"k":"sankaranarayan","t":"Let your claim rest on action alone and never on the fruits; you should never be the cause of the fruits of action; let not your attachment be to inaction."},{"k":"arnold","t":"But thou, want not! ask not! Find full reward\nOf doing right in right! Let right deeds be\nThy motive, not the fruit which comes from them.\nAnd live in action! Labour! Make thine acts\nThy piety, casting all self aside,\nContemning gain and merit; equable\nIn good or evil: equability\nIs Yog, is piety!"},{"k":"telang","t":"Your business is with action alone; not by any means with fruit. Let not the fruit of action be your motive (to action). Let not your attachment be (fixed) on inaction."}]},{"ch":2,"vn":48,"dev":"योगस्थः कुरु कर्माणि सङ्गं त्यक्त्वा धनञ्जय।\nसिद्ध्यसिद्ध्योः समो भूत्वा समत्वं योग उच्यते","iast":"yoga-sthaḥ kuru karmāṇi saṅgaṁ tyaktvā dhanañjaya\nsiddhy-asiddhyoḥ samo bhūtvā samatvaṁ yoga uchyate","v":[{"k":"purohit","t":"Revised:\nPerform all your actions with your mind concentrated on the Divine, renouncing attachment and looking upon success and failure with an equal eye. Spirituality implies equanimity."},{"k":"sivananda","t":"Perform action, O Arjuna, being steadfast in Yoga, abandoning attachment and balanced in success and failure; evenness of mind is called Yoga."},{"k":"adidevananda","t":"Abandoning attachment and established in Yoga, perform works, viewing success and failure with an even mind. Evenness of mind is said to be Yoga."},{"k":"gambirananda","t":"By being established in Yoga, O Dhananjaya (Arjuna), undertake actions, casting off attachment and remaining equanimous in success and failure. Equanimity is called Yoga."},{"k":"sankaranarayan","t":"O Dhananjaya! Establish yourself in the Yoga, perform actions while abandoning attachment, and remain even-minded in success and failure; for, even-mindedness is said to be the Yoga."},{"k":"arnold","t":"And live in action! Labour! Make thine acts\nThy piety, casting all self aside,\nContemning gain and merit; equable\nIn good or evil: equability\nIs Yog, is piety!"}]},{"ch":2,"vn":49,"dev":"दूरेण ह्यवरं कर्म बुद्धियोगाद्धनञ्जय।\nबुद्धौ शरणमन्विच्छ कृपणाः फलहेतवः","iast":"dūreṇa hy-avaraṁ karma buddhi-yogād dhanañjaya\nbuddhau śharaṇam anvichchha kṛipaṇāḥ phala-hetavaḥ","v":[{"k":"purohit","t":"Physical action is far inferior to an intellect concentrated on the Divine. Therefore, have recourse to Pure Intelligence. It is only the small-minded who work for reward."},{"k":"sivananda","t":"Far lower than the Yoga of wisdom is action, O Arjuna. Seek thou refuge in wisdom; wretched are those whose motive is the fruit."},{"k":"adidevananda","t":"Action done with attachment, O Arjuna, is far inferior to action done with evenness of mind. Seek refuge in evenness of mind; those who act with a motive for results are miserable."},{"k":"gambirananda","t":"O Dhananjaya, indeed, action is inferior to the yoga of wisdom. Take refuge in wisdom. Those who thirst for rewards are pitiable."},{"k":"sankaranarayan","t":"O Dhananjaya! The inferior action stays away at a distance due to the yoga of one's contact with the determining faculty; in the determining faculty, you must seek refuge; wretched are those who are the cause of the fruits of action."}]},{"ch":2,"vn":50,"dev":"बुद्धियुक्तो जहातीह उभे सुकृतदुष्कृते।\nतस्माद्योगाय युज्यस्व योगः कर्मसु कौशलम्","iast":"buddhi-yukto jahātīha ubhe sukṛita-duṣhkṛite\ntasmād yogāya yujyasva yogaḥ karmasu kauśhalam","v":[{"k":"purohit","t":"When a person attains Pure Reason, they renounce in this world the results of both good and evil. Cling to Right Action. Spirituality is the true art of living."},{"k":"sivananda","t":"Endowed with wisdom and evenness of mind, one casts off in this life both good and evil deeds; therefore, devote yourself to Yoga; Yoga is skill in action."},{"k":"adidevananda","t":"A person with an evenness of mind discards both good and evil here and now. Therefore, strive for Yoga; for Yoga is skill in action."},{"k":"gambirananda","t":"Possessed of wisdom, one rejects here both virtue and vice. Therefore, devote yourself to (Karma-) yoga; for yoga is skilfulness in action."},{"k":"sankaranarayan","t":"Whoever is endowed with the faculty of determination casts off both good and bad actions. Therefore, strive for Yoga, which is proficiency in action."}]},{"ch":2,"vn":51,"dev":"कर्मजं बुद्धियुक्ता हि फलं त्यक्त्वा मनीषिणः।\nजन्मबन्धविनिर्मुक्ताः पदं गच्छन्त्यनामयम्","iast":"karma-jaṁ buddhi-yuktā hi phalaṁ tyaktvā manīṣhiṇaḥ\njanma-bandha-vinirmuktāḥ padaṁ gachchhanty-anāmayam","v":[{"k":"purohit","t":"The sages, guided by pure intellect, renounce the fruits of their actions; and, thus freed from the shackles of rebirth, they attain the highest bliss."},{"k":"sivananda","t":"The wise, possessing knowledge, having abandoned the fruits of their actions, and being freed from the bonds of birth, go to the place which is beyond all evil."},{"k":"adidevananda","t":"The wise, who possess evenness of mind, relinquish the fruits born of action, and are freed from the bondage of birth, going to the region beyond all ills."},{"k":"gambirananda","t":"For those devoted to wisdom, they become enlightened men by giving up the fruits of their actions, and thus they reach a state beyond evil, having been freed from the bondage of birth."},{"k":"sankaranarayan","t":"By renouncing the fruits of their actions, the intelligent ones, endowed with the power of determination and freed from the bonds of birth, go to a place that is free from illness."}]},{"ch":2,"vn":52,"dev":"यदा ते मोहकलिलं बुद्धिर्व्यतितरिष्यति।\nतदा गन्तासि निर्वेदं श्रोतव्यस्य श्रुतस्य च","iast":"yadā te moha-kalilaṁ buddhir vyatitariṣhyati\ntadā gantāsi nirvedaṁ śhrotavyasya śhrutasya cha","v":[{"k":"purohit","t":"When your reason has crossed the entanglements of illusion, then you will become indifferent to both the philosophies you have heard and those you may yet hear."},{"k":"sivananda","t":"When your intellect passes beyond the mire of delusion, then you will attain indifference to what has been heard and what has yet to be heard."},{"k":"adidevananda","t":"When your intellect has passed beyond the tangle of delusion, you will yourself feel disgusted with what you have heard and what you will hear."},{"k":"gambirananda","t":"When your mind goes beyond the turbidity of delusion, then you will acquire dispassion for what has to be heard and what has already been heard."},{"k":"sankaranarayan","t":"When your determining faculty surpasses the impenetrable thicket of delusion, then you will attain an attitude of futility regarding what needs to be heard and what has been heard."}]},{"ch":2,"vn":53,"dev":"श्रुतिविप्रतिपन्ना ते यदा स्थास्यति निश्चला।\nसमाधावचला बुद्धिस्तदा योगमवाप्स्यसि","iast":"śhruti-vipratipannā te yadā sthāsyati niśhchalā\nsamādhāv-achalā buddhis tadā yogam avāpsyasi","v":[{"k":"purohit","t":"When the intellect, bewildered by the multiplicity of holy scriptures, stands unperturbed in blissful contemplation of the infinite, then you have attained spirituality."},{"k":"sivananda","t":"When your intellect, which is perplexed by the Vedic texts you have read, stands immovable and steady in the Self, then you will attain Self-realization."},{"k":"adidevananda","t":"When your intellect, having been well enlightened by hearing from Me and firmly placed, stands unshaken in a concentrated mind, then you will attain the vision of the Self."},{"k":"gambirananda","t":"When your mind, which has become bewildered by hearing, becomes unshakable and steadfast in the Self, then you will attain Yoga that arises from discrimination."},{"k":"sankaranarayan","t":"When your determining faculty, which had been previously confused by your hearing of scriptural declarations of fruits, stands stable in concentration, then you shall attain Yoga."}]},{"ch":2,"vn":54,"dev":"अर्जुन उवाच\nस्थितप्रज्ञस्य का भाषा समाधिस्थस्य केशव।\nस्थितधीः किं प्रभाषेत किमासीत व्रजेत किम्","iast":"arjuna uvācha\nsthita-prajñasya kā bhāṣhā samādhi-sthasya keśhava\nsthita-dhīḥ kiṁ prabhāṣheta kim āsīta vrajeta kim","v":[{"k":"purohit","t":"Arjuna asked: My Lord! How can we recognize the saint who has attained Pure Intellect, who has reached this state of Bliss, and whose mind is steady? How does he talk, how does he live, and how does he act?"},{"k":"sivananda","t":"Arjuna said, \"O Krishna, what is the description of one who has steady wisdom and is merged in the superconscious state? How does one of steady wisdom speak, how do they sit, and how do they walk?\""},{"k":"adidevananda","t":"Arjuna said, \"What is the mode of speech of one who is of firm wisdom, established in the control of the mind? What does a man of firm wisdom speak, O Krsna? How does he sit? How does he move?\""},{"k":"gambirananda","t":"Arjuna said, \"O Kesava, what is the description of a man of steady wisdom who is self-absorbed? How does he speak, sit, and move about?\""},{"k":"sankaranarayan","t":"Arjuna said, \"O Kesava! What is the meaning of sthita-prajna (a man-of-stabilized-intellect) when applied to a man fixed in concentration? What does sthira-dhih (the fixed-minded) imply? Where does the fixed-minded abide? And what is their goal?\""}]},{"ch":2,"vn":55,"dev":"श्री भगवानुवाच\nप्रजहाति यदा कामान् सर्वान् पार्थ मनोगतान्।\nआत्मन्येवात्मना तुष्टः स्थितप्रज्ञस्तदोच्यते","iast":"śhrī bhagavān uvācha\nprajahāti yadā kāmān sarvān pārtha mano-gatān\nātmany-evātmanā tuṣhṭaḥ sthita-prajñas tadochyate","v":[{"k":"purohit","t":"Lord Shri Krishna replied: When a person has given up the desires of their heart and is content with the Self alone, they have surely reached the highest state."},{"k":"sivananda","t":"The Blessed Lord said, \"When a man completely casts off, O Arjuna, all the desires of the mind and is satisfied in the Self by the Self, then he is said to be one of steady wisdom.\""},{"k":"adidevananda","t":"The Lord said, \"When a man renounces all the desires of the mind and is content with himself, then he is said to possess firm wisdom.\""},{"k":"gambirananda","t":"The Blessed One said, \"O Partha, when one fully renounces all the desires that have entered the mind and remains satisfied in the Self alone, then he is called a man of steady wisdom.\""},{"k":"sankaranarayan","t":"The Bhagavat said, \"O son of Prtha! When a man casts off all desires existing in his mind and remains content in the Self by the self (mind), then he is called a man of stabilized intellect.\""}]},{"ch":2,"vn":56,"dev":"दुःखेष्वनुद्विग्नमनाः सुखेषु विगतस्पृहः।\nवीतरागभयक्रोधः स्थितधीर्मुनिरुच्यते","iast":"duḥkheṣhv-anudvigna-manāḥ sukheṣhu vigata-spṛihaḥ\nvīta-rāga-bhaya-krodhaḥ sthita-dhīr munir uchyate","v":[{"k":"purohit","t":"The sage whose mind is unruffled in suffering, whose desire is not aroused by enjoyment, who is without attachment, anger, or fear—take him to be one who stands at a lofty level."},{"k":"sivananda","t":"He whose mind is not shaken by adversity, who does not long for pleasures, and is free from attachment, fear, and anger, is called a sage of steady wisdom."},{"k":"adidevananda","t":"He whose mind is not perturbed by pain, who has no longing for pleasures, who is free from desire, fear, and anger—he is called a sage of firm wisdom."},{"k":"gambirananda","t":"That monk is called a man of steady wisdom when his mind is unperturbed even in sorrow, he is free from longing for delights, and has gone beyond attachment, fear, and anger."},{"k":"sankaranarayan","t":"He whose mind is undisturbed amidst sorrows, who is free from desire amidst pleasures, and from whom longing, fear, and wrath have departed—he is said to be a firm-minded sage."}]},{"ch":2,"vn":57,"dev":"यः सर्वत्रानभिस्नेहस्तत्तत्प्राप्य शुभाशुभम्।\nनाभिनन्दति न द्वेष्टि तस्य प्रज्ञा प्रतिष्ठिता","iast":"yaḥ sarvatrānabhisnehas tat tat prāpya śhubhāśhubham\nnābhinandati na dveṣhṭi tasya prajñā pratiṣhṭhitā","v":[{"k":"purohit","t":"He who, wherever he goes, is not attached to any person or place by ties of flesh; who accepts good and evil alike, neither welcoming the one nor shrinking from the other—take him to be one who is merged in the Infinite."},{"k":"sivananda","t":"He who is everywhere without attachment, upon encountering anything good or bad, neither rejoices nor hastens; his wisdom is firm."},{"k":"adidevananda","t":"He who has no love on any side, who, upon finding good or evil, neither rejoices nor hates—his wisdom is firmly set."},{"k":"gambirananda","t":"The wisdom of that person remains established who has no attachment to anything anywhere, who neither welcomes nor rejects anything, whatever good or bad, when they come across it."},{"k":"sankaranarayan","t":"He who has no desire for anything, and who neither rejoices nor hates upon obtaining this or that, good or bad—his intellect is properly stabilized."}]},{"ch":2,"vn":58,"dev":"यदा संहरते चायं कूर्मोऽङ्गानीव सर्वशः।\nइन्द्रियाणीन्द्रियार्थेभ्यस्तस्य प्रज्ञा प्रतिष्ठिता","iast":"yadā sanharate chāyaṁ kūrmo 'ṅgānīva sarvaśhaḥ\nindriyāṇīndriyārthebhyas tasya prajñā pratiṣhṭhitā","v":[{"k":"purohit","t":"He who can withdraw his senses from the attraction of their objects, as the tortoise draws its limbs within its shell—take it that such a one has attained perfection."},{"k":"sivananda","t":"When, like the tortoise which withdraws all its limbs on all sides, he withdraws his senses from the sense-objects, then his wisdom becomes steady."},{"k":"adidevananda","t":"When one is able to draw their senses away from the objects of sense on all sides, like a tortoise draws in its limbs, then their wisdom is firmly established."},{"k":"gambirananda","t":"And when one fully withdraws their senses from the objects of the senses, just as a tortoise withdraws its limbs, then their wisdom remains established."},{"k":"sankaranarayan","t":"When he withdraws all his senses from sense-objects, just as a tortoise withdraws all its limbs, then he is declared to be a man of stabilized intellect."}]},{"ch":2,"vn":59,"dev":"विषया विनिवर्तन्ते निराहारस्य देहिनः।\nरसवर्जं रसोऽप्यस्य परं दृष्ट्वा निवर्तते","iast":"viṣhayā vinivartante nirāhārasya dehinaḥ\nrasa-varjaṁ raso 'pyasya paraṁ dṛiṣhṭvā nivartate","v":[{"k":"purohit","t":"The objects of sense turn away from him who is abstinent. Even the taste for them is lost in him who has seen the Truth."},{"k":"sivananda","t":"The objects of the senses turn away from the abstinent man, leaving the longing behind; but his longing also turns away upon seeing the Supreme."},{"k":"adidevananda","t":"The objects of the senses, except for the pleasure they bring, turn away from the abstinent dweller in the body. Even the pleasure turns away from him when the Self, which is supreme over the senses, is seen."},{"k":"gambirananda","t":"The objects recede from an abstinent person, except for the taste for them. Even this taste falls away after realization of the Absolute."},{"k":"sankaranarayan","t":"Leaving their taste behind, the sense-objects retreat from the embodied one who abstains from food; his taste too disappears when he beholds the Supreme."}]},{"ch":2,"vn":60,"dev":"यततो ह्यपि कौन्तेय पुरुषस्य विपश्चितः।\nइन्द्रियाणि प्रमाथीनि हरन्ति प्रसभं मनः","iast":"yatato hyapi kaunteya puruṣhasya vipaśhchitaḥ\nindriyāṇi pramāthīni haranti prasabhaṁ manaḥ","v":[{"k":"purohit","t":"O Arjuna! The mind of one who is attempting to conquer it is forcibly carried away, in spite of their efforts, by their tumultuous senses."},{"k":"sivananda","t":"The turbulent senses, O Arjuna, can violently carry away the mind of a wise person, even though they are striving to control them."},{"k":"adidevananda","t":"The turbulent senses, O Arjuna, can forcibly carry away the mind of even a wise man, though he is ever striving."},{"k":"gambirananda","t":"For, O son of Kunti, the turbulent senses can violently snatch away the mind of an intelligent person, even while they are striving diligently."},{"k":"sankaranarayan","t":"For, the turbulent sense-organs can forcibly carry away even the mind of this discerning person, O son of Kunti!"}]},{"ch":2,"vn":61,"dev":"तानि सर्वाणि संयम्य युक्त आसीत मत्परः।\nवशे हि यस्येन्द्रियाणि तस्य प्रज्ञा प्रतिष्ठिता","iast":"tāni sarvāṇi sanyamya yukta āsīta mat-paraḥ\nvaśhe hi yasyendriyāṇi tasya prajñā pratiṣhṭhitā","v":[{"k":"purohit","t":"Restraining them all, let him steadfastly meditate on Me; for whoever conquers their senses achieves perfection."},{"k":"sivananda","t":"Having restrained them all, he should sit steadfast, intent on Me; his wisdom is steady whose senses are under control."},{"k":"adidevananda","t":"Having controlled all the senses, let him remain in contemplation, regarding Me as supreme; for his knowledge is firmly established when his senses are under control."},{"k":"gambirananda","t":"Controlling all of them, one should remain focused on Me as the supreme. For, the wisdom of one whose senses are under control becomes steadfast."},{"k":"sankaranarayan","t":"Restraining the same organs by the mind, the master of Yoga would sit, making Me their goal; for the intellect of that person is stabilized whose sense-organs are under control."}]},{"ch":2,"vn":62,"dev":"ध्यायतो विषयान्पुंसः सङ्गस्तेषूपजायते।\nसङ्गात् संजायते कामः कामात्क्रोधोऽभिजायते","iast":"dhyāyato viṣhayān puṁsaḥ saṅgas teṣhūpajāyate\nsaṅgāt sañjāyate kāmaḥ kāmāt krodho 'bhijāyate","v":[{"k":"purohit","t":"When a person dwells on the objects of sense, they create an attraction for them; this attraction develops into desire, and desire breeds anger."},{"k":"sivananda","t":"When one thinks of objects, attachment to them arises; from attachment, desire is born; from desire, anger arises."},{"k":"adidevananda","t":"To one who is thinking about sense-objects, attachment to them arises; from attachment arises desire, and from desire arises anger."},{"k":"gambirananda","t":"- In the case of a person who dwells on objects, there arises attachment to them. From attachment grows hankering, and from hankering springs anger."},{"k":"sankaranarayan","t":"In a person meditating on sense-objects, attachment to them is born in succession; from attachment springs passion; from passion arises wrath."},{"k":"arnold","t":"If one\nPonders on objects of the sense, there springs\nAttraction; from attraction grows desire,\nDesire flames to fierce passion, passion breeds\nRecklessness;"}]},{"ch":2,"vn":63,"dev":"क्रोधाद्भवति संमोहः संमोहात्स्मृतिविभ्रमः।\nस्मृतिभ्रंशाद् बुद्धिनाशो बुद्धिनाशात्प्रणश्यति","iast":"krodhād bhavati sammohaḥ sammohāt smṛiti-vibhramaḥ\nsmṛiti-bhranśhād buddhi-nāśho buddhi-nāśhāt praṇaśhyati","v":[{"k":"purohit","t":"Anger induces delusion; delusion leads to loss of memory; loss of memory results in the shattering of reason; and the destruction of reason leads to destruction."},{"k":"sivananda","t":"Anger leads to delusion, which causes loss of memory; this, in turn, leads to the destruction of discrimination, resulting in destruction."},{"k":"adidevananda","t":"Anger leads to delusion, which causes the loss of memory; the loss of memory leads to the destruction of discrimination, and with the destruction of discrimination, one is lost."},{"k":"gambirananda","t":"From anger follows delusion; from delusion, a failure of memory; from the failure of memory, the loss of understanding; and from the loss of understanding, one perishes."},{"k":"sankaranarayan","t":"From wrath comes delusion; from delusion, the loss of memory; from the loss of memory, the loss of capacity to decide; due to the loss of capacity to decide, he perishes outright."},{"k":"arnold","t":"then the memory--all betrayed--\nLets noble purpose go, and saps the mind,\nTill purpose, mind, and man are all undone."}]},{"ch":2,"vn":64,"dev":"रागद्वेषवियुक्तैस्तु विषयानिन्द्रियैश्चरन्।\nआत्मवश्यैर्विधेयात्मा प्रसादमधिगच्छति","iast":"rāga-dveṣha-viyuktais tu viṣhayān indriyaiśh charan\nātma-vaśhyair-vidheyātmā prasādam adhigachchhati","v":[{"k":"purohit","t":"But the self-controlled soul, who moves among sense objects, free from attachment or repulsion, wins eternal peace."},{"k":"sivananda","t":"But the self-controlled man, moving among objects with the senses restrained and free from attraction and repulsion, attains peace."},{"k":"adidevananda","t":"But he who goes through the sense-objects with the senses free from love and hate, disciplined and controlled, attains serenity."},{"k":"gambirananda","t":"But by perceiving objects with the organs that are free from attraction and repulsion, and are under his own control, the self-controlled person attains serenity."},{"k":"sankaranarayan","t":"On the contrary, one who moves about and consumes the sense-objects through their sense-organs, freed from desire and hatred and controlled in the Self—such a one, with a disciplined mind, attains serenity of disposition."}]},{"ch":2,"vn":65,"dev":"प्रसादे सर्वदुःखानां हानिरस्योपजायते।\nप्रसन्नचेतसो ह्याशु बुद्धिः पर्यवतिष्ठते","iast":"prasāde sarva-duḥkhānāṁ hānir asyopajāyate\nprasanna-chetaso hyāśhu buddhiḥ paryavatiṣhṭhate","v":[{"k":"purohit","t":"Having attained peace, he becomes free from misery; for when the mind gains peace, right discrimination follows."},{"k":"sivananda","t":"In that peace, all pains are destroyed; for the intellect of the tranquil-minded soon becomes steady."},{"k":"adidevananda","t":"In that serenity, all sorrow is lost; for in the case of the person with a serene mind, the Buddhi is quickly established."},{"k":"gambirananda","t":"When there is serenity, all his sorrows are eradicated, for the wisdom of one with a serene mind soon becomes firmly established."},{"k":"sankaranarayan","t":"Upon attaining serenity, all miseries are extinguished in succession; the ability to make decisions is quickly stabilized in the mind of one who is serene."}]},{"ch":2,"vn":66,"dev":"नास्ति बुद्धिरयुक्तस्य न चायुक्तस्य भावना।\nन चाभावयतः शान्तिरशान्तस्य कुतः सुखम्","iast":"nāsti buddhir-ayuktasya na chāyuktasya bhāvanā\nna chābhāvayataḥ śhāntir aśhāntasya kutaḥ sukham","v":[{"k":"purohit","t":"Right discrimination is not for him who cannot concentrate. Without concentration, there cannot be meditation; he who cannot meditate must not expect peace; and without peace, how can one expect happiness?"},{"k":"sivananda","t":"There is no knowledge of the Self for the unsteady, and no meditation is possible for the unsteady, and no peace for the unmeditative, and how can there be happiness for one who has no peace?"},{"k":"adidevananda","t":"There is no Buddhi for the unintegrated, nor is there contemplation of the self for him, and without contemplation of the self, there is no peace; and for one who lacks peace, where is the happiness?"},{"k":"gambirananda","t":"For the unsteady there is no wisdom, and there is no meditation for the unsteady person. And for an unmeditative person there is no peace. How can there be happiness for one without peace?"},{"k":"sankaranarayan","t":"The ability to make decisions is not for one who is not a master of Yoga; and concentration of the mind is not for one who is not a master of Yoga; and peace is not for one who does not concentrate; whence could happiness come to one who has no peace?"}]},{"ch":2,"vn":67,"dev":"इन्द्रियाणां हि चरतां यन्मनोऽनुविधीयते।\nतदस्य हरति प्रज्ञां वायुर्नावमिवाम्भसि","iast":"indriyāṇāṁ hi charatāṁ yan mano 'nuvidhīyate\ntadasya harati prajñāṁ vāyur nāvam ivāmbhasi","v":[{"k":"purohit","t":"As a ship at sea is tossed by the tempest, so the reason is carried away by the mind when preyed upon by straying senses."},{"k":"sivananda","t":"For the mind, which follows in the wake of the wandering senses, carries away his discrimination, as the wind carries away a boat on the waters."},{"k":"adidevananda","t":"For, when the mind follows the senses, experiencing their objects, his understanding is carried away by them, just as the wind carries away a ship on the waters."},{"k":"gambirananda","t":"For, the mind which follows in the wake of the wandering senses carries away his wisdom like a boat on the waters."},{"k":"sankaranarayan","t":"That mind, which is directed to follow the wandering sense-organs—that mind carries away his knowledge just as the wind carries away a ship on the waters."}]},{"ch":2,"vn":68,"dev":"तस्माद्यस्य महाबाहो निगृहीतानि सर्वशः।\nइन्द्रियाणीन्द्रियार्थेभ्यस्तस्य प्रज्ञा प्रतिष्ठिता","iast":"tasmād yasya mahā-bāho nigṛihītāni sarvaśhaḥ\nindriyāṇīndriyārthebhyas tasya prajñā pratiṣhṭhitā","v":[{"k":"purohit","t":"Therefore, O Mighty-Armed One, he whose senses are detached from their objects—take it that his reason is purified."},{"k":"sivananda","t":"Therefore, O mighty-armed Arjuna, his knowledge is steady whose senses are completely restrained from sense objects."},{"k":"adidevananda","t":"Therefore, O mighty-armed one, he whose senses are restrained from going after their objects on all sides, his wisdom is firmly established."},{"k":"gambirananda","t":"Therefore, O mighty-armed one, this wisdom becomes established when all its senses are withdrawn from their objects."},{"k":"sankaranarayan","t":"Therefore, O mighty-armed one, the intellect of that person is stabilized, all of whose sense-organs, starting from the sense-objects, have been well restrained."}]},{"ch":2,"vn":69,"dev":"या निशा सर्वभूतानां तस्यां जागर्ति संयमी।\nयस्यां जाग्रति भूतानि सा निशा पश्यतो मुनेः","iast":"yā niśhā sarva-bhūtānāṁ tasyāṁ jāgarti sanyamī\nyasyāṁ jāgrati bhūtāni sā niśhā paśhyato muneḥ","v":[{"k":"purohit","t":"The saint is awake when the world sleeps, and he disregards that for which the world lives."},{"k":"sivananda","t":"That which is night to all beings, in that the self-controlled man is awake; when all beings are awake, that is night for the sage who sees."},{"k":"adidevananda","t":"What is night for all beings, in it the one who is controlled is awake; when all beings are awake, that is the night for the sage who sees."},{"k":"gambirananda","t":"The self-restrained man stays awake during what is night for all creatures. That which creatures stay awake for, it is night to the discerning sage."},{"k":"sankaranarayan","t":"What is night for every other being, in that a man of self-restraint is awake; wherein every other being is awake, that is night for the sage who sees the truth."}]},{"ch":2,"vn":70,"dev":"आपूर्यमाणमचलप्रतिष्ठं\nसमुद्रमापः प्रविशन्ति यद्वत्।\nतद्वत्कामा यं प्रविशन्ति सर्वे\nस शान्तिमाप्नोति न कामकामी","iast":"āpūryamāṇam achala-pratiṣhṭhaṁ\nsamudram āpaḥ praviśhanti yadvat\ntadvat kāmā yaṁ praviśhanti sarve\nsa śhāntim āpnoti na kāma-kāmī","v":[{"k":"purohit","t":"He attains peace into whom desires flow as rivers into the ocean, which, though brimming with water, remains ever the same; not he whom desires carry away."},{"k":"sivananda","t":"He attains peace into whom all desires enter, just as waters enter the ocean which, filled from all sides, remains unmoved; but not the man who is full of desires."},{"k":"adidevananda","t":"He into whom all desires enter, just as the waters enter the full and undisturbed sea, attains peace, and not he who longs after objects of desire."},{"k":"gambirananda","t":"That man attains peace into whom all desires enter, just as waters flow into the sea that remains unchanged even when filled from all sides. Not so one who is desirous of objects."},{"k":"sankaranarayan","t":"Just as waters enter into the ocean which is being filled continuously yet firmly established, so too he into whom all objects of desire enter—he attains peace; not he who longs for the objects of desire."},{"k":"arnold","t":"And like the ocean, day by day receiving\nFloods from all lands, which never overflows\nIts boundary-line not leaping, and not leaving,\nFed by the rivers, but unswelled by those;--\nSo is the perfect one!"}]},{"ch":2,"vn":71,"dev":"विहाय कामान्यः सर्वान्पुमांश्चरति निःस्पृहः।\nनिर्ममो निरहंकारः स शांतिमधिगच्छति","iast":"vihāya kāmān yaḥ sarvān pumānśh charati niḥspṛihaḥ\nnirmamo nirahankāraḥ sa śhāntim adhigachchhati","v":[{"k":"purohit","t":"He attains peace who, giving up desire, moves through the world without aspiration, possessing nothing that he can call his own and is free from pride."},{"k":"sivananda","t":"That person attains peace who, abandoning all desires, moves about without longing, without the sense of ownership, and without egoism."},{"k":"adidevananda","t":"The one who, abandoning all desires, abides without longing, possession, and the sense of 'I' and 'mine', wins peace."},{"k":"gambirananda","t":"That man attains peace who, after rejecting all desires, moves about free from hankering, without the idea of 'me' and 'mine', and devoid of pride."},{"k":"sankaranarayan","t":"That person, who, by abandoning all desires, consumes [objects] without longing, without a sense of ownership, and without egotism, attains peace."}]},{"ch":2,"vn":72,"dev":"एषा ब्राह्मी स्थितिः पार्थ नैनां प्राप्य विमुह्यति।\nस्थित्वाऽस्यामन्तकालेऽपि ब्रह्मनिर्वाणमृच्छति","iast":"eṣhā brāhmī sthitiḥ pārtha naināṁ prāpya vimuhyati\nsthitvāsyām anta-kāle 'pi brahma-nirvāṇam ṛichchhati","v":[{"k":"purohit","t":"O Arjuna! This is the state of the Self, the Supreme Spirit, to which, if one attains, it shall never be taken away. Even at the time of leaving the body, one will remain firmly enthroned there and become one with the Eternal."},{"k":"sivananda","t":"O son of Pritha, this is the eternal state, the Brahmic seat. Attaining this, one is not deluded. Being established in it, one attains oneness with Brahman even at the end of life."},{"k":"adidevananda","t":"This is the Brahmic state, O Arjuna. No one attaining to this is deluded. By abiding in this state even at the hour of death, one will attain the Self."},{"k":"gambirananda","t":"O Partha, this is the state of being established in Brahman. One does not become deluded after attaining this; one attains identification with Brahman by being established in this state even in the closing years of one's life."},{"k":"sankaranarayan","t":"O son of Prtha! This is the Brahmanic state; having attained this, one never gets deluded again. Even by remaining in this [state] for a while, one attains at the time of death the Brahman, the Transcendent One."}]},{"ch":3,"vn":1,"dev":"अर्जुन उवाच\nज्यायसी चेत्कर्मणस्ते मता बुद्धिर्जनार्दन।\nतत्किं कर्मणि घोरे मां नियोजयसि केशव","iast":"arjuna uvācha\njyāyasī chet karmaṇas te matā buddhir janārdana\ntat kiṁ karmaṇi ghore māṁ niyojayasi keśhava","v":[{"k":"purohit","t":"Arjuna questioned: My Lord! If wisdom is superior to action, why do you advise me to engage in this terrible fight?"},{"k":"sivananda","t":"Arjuna said: If Thou thinkest that knowledge is superior to action, O Krishna, why then, O Kesava, doest Thou ask me to engage in this terrible action?"},{"k":"adidevananda","t":"Arjuna said, \"O Krsna, if you deem knowledge to be superior to action, why then do you urge me to engage in this terrible deed?\""},{"k":"gambirananda","t":"Arjuna said, \"O Janardana (Krishna), if it is Your opinion that wisdom is superior to action, why do You urge me to take such horrible action, O Kesava?\""},{"k":"sankaranarayan","t":"Arjuna said, \"O Janardana, if you hold knowledge to be superior to action, then why do you engage me in such terrible action, O Kesava?\""}]},{"ch":3,"vn":2,"dev":"व्यामिश्रेणेव वाक्येन बुद्धिं मोहयसीव मे।\nतदेकं वद निश्िचत्य येन श्रेयोऽहमाप्नुयाम्","iast":"vyāmiśhreṇeva vākyena buddhiṁ mohayasīva me\ntad ekaṁ vada niśhchitya yena śhreyo 'ham āpnuyām","v":[{"k":"purohit","t":"Your language confuses me and confounds my reason. Therefore, please tell me the only way by which I can, without doubt, secure my spiritual welfare."},{"k":"sivananda","t":"With this seemingly perplexing speech, you seem to be confusing my understanding; therefore, tell me one certain way by which I may attain bliss."},{"k":"adidevananda","t":"You confuse my mind with statements that seem to contradict each other; tell me for certain the one way by which I could reach the highest good."},{"k":"gambirananda","t":"You bewilder my understanding, as it were, with a seemingly conflicting statement! Tell me for certain which one of these I may use to attain the highest Good."},{"k":"sankaranarayan","t":"You seem to be confounding my intellect with Your seemingly confusing speech. Therefore, tell me with certainty that one thing by which I may attain the good (emancipation)."}]},{"ch":3,"vn":3,"dev":"श्री भगवानुवाच\nलोकेऽस्मिन्द्विविधा निष्ठा पुरा प्रोक्ता मयानघ।\nज्ञानयोगेन सांख्यानां कर्मयोगेन योगिनाम्","iast":"śhrī bhagavān uvācha\nloke'smin dvi-vidhā niṣhṭhā purā proktā mayānagha\njñāna-yogena sāṅkhyānāṁ karma-yogena yoginām","v":[{"k":"purohit","t":"Lord Shri Krishna replied: In this world, as I have said, there is a twofold path, O sinless one! There is the path of wisdom for those who meditate, and the path of action for those who work."},{"k":"sivananda","t":"The Blessed Lord said, \"In this world, there is a twofold path, as I said before, O sinless one: the path of knowledge of the Sankhyas and the path of action of the Yogins.\""},{"k":"adidevananda","t":"The Lord said, \"In this world, a two-fold way was of yore laid down by Me, O sinless one: Jnana Yoga for the Sankhyas and Karma Yoga for the Yogins.\""},{"k":"gambirananda","t":"The Blessed Lord said, O unblemished one, two kinds of steadfastness in this world were spoken of by Me in days gone by—through the Yoga of Knowledge for the men of realization; through the Yoga of Action for the yogis."},{"k":"sankaranarayan","t":"The Bhagavat said, \"The two-fold path in this world—the one with Yoga of knowledge for men of reflection and the other with Yoga of action for men of Yoga—has been declared by Me to be one, O sinless one!\""}]},{"ch":3,"vn":4,"dev":"न कर्मणामनारम्भान्नैष्कर्म्यं पुरुषोऽश्नुते।\nन च संन्यसनादेव सिद्धिं समधिगच्छति","iast":"na karmaṇām anārambhān naiṣhkarmyaṁ puruṣho 'śhnute\nna cha sannyasanād eva siddhiṁ samadhigachchhati","v":[{"k":"purohit","t":"No one can attain freedom from action by abstaining from action, nor can they reach perfection by simply not acting."},{"k":"sivananda","t":"Man does not reach actionlessness by not performing actions; nor does he attain perfection by mere renunciation."},{"k":"adidevananda","t":"No one experiences freedom from action (Naiskarmya) by abstaining from work; and no one ever attains success through mere renunciation of work."},{"k":"gambirananda","t":"A person does not attain freedom from action by abstaining from action; nor does he attain fulfillment merely through renunciation."},{"k":"sankaranarayan","t":"A person attains actionlessness not just by abstaining from actions, but also by renunciation, he attains success (emancipation)."}]},{"ch":3,"vn":5,"dev":"न हि कश्िचत्क्षणमपि जातु तिष्ठत्यकर्मकृत्।\nकार्यते ह्यवशः कर्म सर्वः प्रकृतिजैर्गुणैः","iast":"na hi kaśhchit kṣhaṇam api jātu tiṣhṭhatyakarma-kṛit\nkāryate hyavaśhaḥ karma sarvaḥ prakṛiti-jair guṇaiḥ","v":[{"k":"purohit","t":"He cannot remain inactive even for a moment, for the qualities of Nature will compel him to act, whether he wills it or not."},{"k":"sivananda","t":"Verily, no one can remain for even a moment without performing action; for everyone is made to act helplessly, indeed, by the qualities born of Nature."},{"k":"adidevananda","t":"No one can remain still for even a moment without doing work; for everyone is compelled to act, despite themselves, by the Gunas born of Nature."},{"k":"gambirananda","t":"For no one ever remains even for a moment without doing work, for all are made to work under compulsion by the gunas born of Nature."},{"k":"sankaranarayan","t":"For, no one can ever remain, even for a moment, as a non-performer of action; because everyone, not being master of themselves, is forced to perform action by the strands born of the Prakriti (Material cause)."}]},{"ch":3,"vn":6,"dev":"कर्मेन्द्रियाणि संयम्य य आस्ते मनसा स्मरन्।\nइन्द्रियार्थान्विमूढात्मा मिथ्याचारः स उच्यते","iast":"karmendriyāṇi sanyamya ya āste manasā smaran\nindriyārthān vimūḍhātmā mithyāchāraḥ sa uchyate","v":[{"k":"purohit","t":"He who remains motionless, refusing to act, yet brooding over sensuous objects, is that deluded soul simply a hypocrite."},{"k":"sivananda","t":"He who, restraining the organs of action, sits thinking of the sense-objects in his mind, he of deluded understanding is called a hypocrite."},{"k":"adidevananda","t":"He who, controlling the organs of action, lets his mind dwell on the objects of the senses, is a deluded person and a hypocrite."},{"k":"gambirananda","t":"One who, after withdrawing the organs of action, sits mentally recollecting the objects of the senses, is called a hypocrite, for they have a deluded mind."},{"k":"sankaranarayan","t":"Controlling their organs of action, whoever sits with their mind pondering over sense objects—that person is a man of deluded soul and is called a man of deluded action."}]},{"ch":3,"vn":7,"dev":"यस्त्विन्द्रियाणि मनसा नियम्यारभतेऽर्जुन।\nकर्मेन्द्रियैः कर्मयोगमसक्तः स विशिष्यते","iast":"yas tvindriyāṇi manasā niyamyārabhate 'rjuna\nkarmendriyaiḥ karma-yogam asaktaḥ sa viśhiṣhyate","v":[{"k":"purohit","t":"But, O Arjuna! All honor to him whose mind controls his senses, for he is thereby beginning to practice Karma-Yoga, the Path of Right Action, keeping himself always unattached."},{"k":"sivananda","t":"But whoever, controlling the senses by the mind, O Arjuna, engages himself in Karma Yoga with the organs of action, without attachment, he excels."},{"k":"adidevananda","t":"But he who, subduing his senses by the mind, O Arjuna, begins to practice Karma Yoga through the organs of action and who is free from attachment, excels."},{"k":"gambirananda","t":"But, O Arjuna, one who engages in Karma-yoga, controlling the organs of action with the mind and becoming unattached, excels."},{"k":"sankaranarayan","t":"But, controlling the sense-organs with the mind, whoever undertakes the Yoga of action with the action-senses, he, the detached one, is superior, O Arjuna!"}]},{"ch":3,"vn":8,"dev":"नियतं कुरु कर्म त्वं कर्म ज्यायो ह्यकर्मणः।\nशरीरयात्रापि च ते न प्रसिद्ध्येदकर्मणः","iast":"niyataṁ kuru karma tvaṁ karma jyāyo hyakarmaṇaḥ\nśharīra-yātrāpi cha te na prasiddhyed akarmaṇaḥ","v":[{"k":"purohit","t":"Do your duty as prescribed, for action for duty's sake is superior to inaction. Even the maintenance of the body would be impossible if one remained inactive."},{"k":"sivananda","t":"Perform your bounden duty, for action is superior to inaction, and even the maintenance of the body would not be possible for you through inaction."},{"k":"adidevananda","t":"You must perform your obligatory action; for action is superior to non-action (Jñāna Yoga). For a person following non-action, not even the sustenance of the body is possible."},{"k":"gambirananda","t":"You should perform your obligatory duties, for action is superior to inaction. Moreover, even the maintenance of your body will not be possible without action."},{"k":"sankaranarayan","t":"You must perform the action that has been enjoined upon you. For, action is superior to inaction; and even the maintenance of your body cannot be properly accomplished through inaction."}]},{"ch":3,"vn":9,"dev":"यज्ञार्थात्कर्मणोऽन्यत्र लोकोऽयं कर्मबन्धनः।\nतदर्थं कर्म कौन्तेय मुक्तसंगः समाचर","iast":"yajñārthāt karmaṇo 'nyatra loko 'yaṁ karma-bandhanaḥ\ntad-arthaṁ karma kaunteya mukta-saṅgaḥ samāchara","v":[{"k":"purohit","t":"In this world, people are fettered by their actions, unless they are performed as a sacrifice. Therefore, O Arjuna, let your actions be done without attachment, as a sacrifice only."},{"k":"sivananda","t":"The world is bound by actions other than those performed for the sake of sacrifice; do thou, therefore, O son of Kunti (Arjuna), perform actions for that sake alone, free from attachment."},{"k":"adidevananda","t":"This world is held in the bondage of work only when work is not performed as a sacrifice. O Arjuna, you must perform work for this purpose, free from attachment."},{"k":"gambirananda","t":"This man becomes bound by actions other than those intended for God. Without being attached, O son of Kunti, perform actions for Him."},{"k":"sankaranarayan","t":"The world is fettered by action which is different from Yajna-action; therefore, O son of Kunti, free from attachment, perform Yajna-action properly."}]},{"ch":3,"vn":10,"dev":"सहयज्ञाः प्रजाः सृष्ट्वा पुरोवाच प्रजापतिः।\nअनेन प्रसविष्यध्वमेष वोऽस्त्विष्टकामधुक्","iast":"saha-yajñāḥ prajāḥ sṛiṣhṭvā purovācha prajāpatiḥ\nanena prasaviṣhyadhvam eṣha vo 'stviṣhṭa-kāma-dhuk","v":[{"k":"purohit","t":"In the beginning, when God created all beings through the sacrifice of Himself, He said to them: \"You can procreate through sacrifice, and it shall satisfy all your desires.\""},{"k":"sivananda","t":"The Creator, having in the beginning created mankind together with sacrifice, said, \"By this shall you propagate; let this be the milch cow of your desires—the cow that yields all the desired objects.\""},{"k":"adidevananda","t":"In the beginning, the Lord of all beings created man along with the sacrifice and said, \"By this shall you prosper; this shall be the cow of plenty, granting all your desires.\""},{"k":"gambirananda","t":"In days of yore, having created the beings together with the sacrifices, Prajapati said, \"By this, you shall multiply. Let this be your yielder of coveted objects of desire.\""},{"k":"sankaranarayan","t":"Having created creatures formerly [at the time of creation], together with the necessary action, the Lord of creatures declared: \"By means of this, you shall propagate yourselves; and let this be your wish-fulfilling cow.\""}]},{"ch":3,"vn":11,"dev":"देवान्भावयतानेन ते देवा भावयन्तु वः।\nपरस्परं भावयन्तः श्रेयः परमवाप्स्यथ","iast":"devān bhāvayatānena te devā bhāvayantu vaḥ\nparasparaṁ bhāvayantaḥ śhreyaḥ param avāpsyatha","v":[{"k":"purohit","t":"Worship the powers of Nature, and let them nourish you in return; thus, supporting each other, you shall attain your highest welfare."},{"k":"sivananda","t":"With this, nourish the gods, and may the gods nourish you; thus, nourishing each other, you shall attain the highest good."},{"k":"adidevananda","t":"By this, please the gods, and they will support you. Thus, nourishing each other, you may obtain the highest good."},{"k":"gambirananda","t":"'You nourish the gods with this. Let those gods nourish you in return. By mutually nourishing each other, you shall attain the supreme Good.'"},{"k":"sankaranarayan","t":"'You should gratify the devas with this, and let the devas gratify you; thus, mutually gratifying each other, you will attain the highest good.'"}]},{"ch":3,"vn":12,"dev":"इष्टान्भोगान्हि वो देवा दास्यन्ते यज्ञभाविताः।\nतैर्दत्तानप्रदायैभ्यो यो भुङ्क्ते स्तेन एव सः","iast":"iṣhṭān bhogān hi vo devā dāsyante yajña-bhāvitāḥ\ntair dattān apradāyaibhyo yo bhuṅkte stena eva saḥ","v":[{"k":"purohit","t":"For, fed by sacrifice, nature will give you all the enjoyment you desire. But he who enjoys what she gives without returning is, indeed, a thief."},{"k":"sivananda","t":"The gods, nourished by the sacrifice, will give you the desired objects. So, he who enjoys the objects given by the gods without offering anything in return is indeed a thief."},{"k":"adidevananda","t":"The gods, pleased by the sacrifice, will bestow upon you the enjoyments you desire. He who enjoys the bounty of the gods without giving them anything in return is but a thief."},{"k":"gambirananda","t":"'Being nourished by sacrifices, the gods will indeed give you the coveted enjoyments. He is certainly a thief who enjoys what has been given by them without offering it to them.'"},{"k":"sankaranarayan","t":"The devas, gratified with necessary action, will grant you the things sacrificed. Therefore, whoever enjoys their gifts without offering them to these devas is surely a thief."}]},{"ch":3,"vn":13,"dev":"यज्ञशिष्टाशिनः सन्तो मुच्यन्ते सर्वकिल्बिषैः।\nभुञ्जते ते त्वघं पापा ये पचन्त्यात्मकारणात्","iast":"yajña-śhiṣhṭāśhinaḥ santo muchyante sarva-kilbiṣhaiḥ\nbhuñjate te tvaghaṁ pāpā ye pachantyātma-kāraṇāt","v":[{"k":"purohit","t":"The sages who enjoy the food that remains after the sacrifice is made are freed from all sins; whereas, the selfish who spread their feast only for themselves feed on sin alone."},{"k":"sivananda","t":"The righteous who eat the remnants of the sacrifice are freed from all sins; but those sinful ones who cook food solely for their own sake indeed consume sin."},{"k":"adidevananda","t":"Pious people who eat the remnants of sacrifices are freed from all sins, whereas those who are sinful and cook only for their own sake will only incur sin."},{"k":"gambirananda","t":"By partaking in the remnants of sacrifices, they become freed from all sins. But those who are unholy and cook for themselves incur sin."},{"k":"sankaranarayan","t":"The righteous persons, who eat the remnants of the actions to be performed necessarily, are freed from all sins. But those who cook, intending for their own selves, are sinners and consume sin."}]},{"ch":3,"vn":14,"dev":"अन्नाद्भवन्ति भूतानि पर्जन्यादन्नसम्भवः।\nयज्ञाद्भवति पर्जन्यो यज्ञः कर्मसमुद्भवः","iast":"annād bhavanti bhūtāni parjanyād anna-sambhavaḥ\nyajñād bhavati parjanyo yajñaḥ karma-samudbhavaḥ","v":[{"k":"purohit","t":"All creatures are the product of food; food is the product of rain; rain comes from sacrifice, and sacrifice is the noblest form of action."},{"k":"sivananda","t":"From food come forth beings; from rain, food is produced; from sacrifice arises rain, and sacrifice is born of action."},{"k":"adidevananda","t":"All beings arise from food; food is produced from rain; rain comes from sacrifice; and sacrifice is born of action."},{"k":"gambirananda","t":"From food are born the creatures; the origin of food is from rain; rain originates from sacrifice; sacrifice has action as its source."},{"k":"sankaranarayan","t":"From food arise the things that are born; from the rain-cloud the food arises; from the sacrifice the rain-cloud arises; the sacrifice arises from action."}]},{"ch":3,"vn":15,"dev":"कर्म ब्रह्मोद्भवं विद्धि ब्रह्माक्षरसमुद्भवम्।\nतस्मात्सर्वगतं ब्रह्म नित्यं यज्ञे प्रतिष्ठितम्","iast":"karma brahmodbhavaṁ viddhi brahmākṣhara-samudbhavam\ntasmāt sarva-gataṁ brahma nityaṁ yajñe pratiṣhṭhitam","v":[{"k":"purohit","t":"All actions originate from the Supreme Spirit, which is Imperishable, and in sacrificial actions, the all-pervasive Spirit is consciously present."},{"k":"sivananda","t":"Know that action comes from Brahma, and Brahma comes from the Imperishable. Therefore, the all-pervasive Brahma ever rests in sacrifice."},{"k":"adidevananda","t":"Know that activity springs from Brahman, i.e., the physical body; Brahman arises from the imperishable Self; therefore, the all-pervading Brahman is ever established in sacrifice."},{"k":"gambirananda","t":"Know that action has the Vedas as its origin; the Vedas have the Immutable as their source. Hence, the all-pervading Vedas are forever based on sacrifice."},{"k":"sankaranarayan","t":"Action arises from the Brahman; you should know this; the Brahman arises from that which does not stream forth; therefore, the all-pervading Brahman is permanently based on the sacrifice."}]},{"ch":3,"vn":16,"dev":"एवं प्रवर्तितं चक्रं नानुवर्तयतीह यः।\nअघायुरिन्द्रियारामो मोघं पार्थ स जीवति","iast":"evaṁ pravartitaṁ chakraṁ nānuvartayatīha yaḥ\naghāyur indriyārāmo moghaṁ pārtha sa jīvati","v":[{"k":"purohit","t":"Thus, he who does not help the revolving wheel of sacrifice, but instead leads a sinful life, rejoicing in the gratification of his senses, O Arjuna, is breathing in vain."},{"k":"sivananda","t":"He who does not follow the wheel thus set in motion, who is of sinful life, rejoicing in the senses, lives in vain, O Arjuna."},{"k":"adidevananda","t":"He who does not follow the wheel thus set in motion here, lives in sin, satisfying the senses, O Arjuna; he lives in vain."},{"k":"gambirananda","t":"O Partha, he who does not follow the wheel thus set in motion lives in vain, their life is sinful, and they indulge in the senses."},{"k":"sankaranarayan","t":"Whoever does not keep the wheel of life rolling, which has been set in motion in this world, is a man of sinful life, rejoicing in the senses; and he lives in vain, O son of Prtha!"}]},{"ch":3,"vn":17,"dev":"यस्त्वात्मरतिरेव स्यादात्मतृप्तश्च मानवः।\nआत्मन्येव च सन्तुष्टस्तस्य कार्यं न विद्यते","iast":"yas tvātma-ratir eva syād ātma-tṛiptaśh cha mānavaḥ\nātmanyeva cha santuṣhṭas tasya kāryaṁ na vidyate","v":[{"k":"purohit","t":"On the other hand, the soul who meditates on the Self is content to serve the Self and rests satisfied in the Self; there is nothing more for them to accomplish."},{"k":"sivananda","t":"But for that man who rejoices only in the Self, who is satisfied with the Self and is content in the Self alone, indeed there is nothing to do."},{"k":"adidevananda","t":"But the man whose delight is only in the Self, who is satisfied with the Self, who rejoices in the Self, for him nothing remains to be accomplished."},{"k":"gambirananda","t":"But that man who rejoices only in the Self, is satisfied with the Self, and is content only in the Self—for him there is no duty to perform."},{"k":"sankaranarayan","t":"But the man who simply rejoices in the Self, is satisfied in the Self, and delights in the Self alone—there exists no action for him to be performed."}]},{"ch":3,"vn":18,"dev":"नैव तस्य कृतेनार्थो नाकृतेनेह कश्चन।\nन चास्य सर्वभूतेषु कश्िचदर्थव्यपाश्रयः","iast":"naiva tasya kṛitenārtho nākṛiteneha kaśhchana\nna chāsya sarva-bhūteṣhu kaśhchid artha-vyapāśhrayaḥ","v":[{"k":"purohit","t":"He has nothing to gain from the performance or non-performance of action; his welfare does not depend on any contribution that an earthly creature can make."},{"k":"sivananda","t":"For him, there is no interest whatsoever in what is done or not done; nor does he depend on any being for any purpose."},{"k":"adidevananda","t":"He has no purpose to gain from work done or left undone, nor does he have to rely on any end."},{"k":"gambirananda","t":"For him, there is no concern here at all with performing action, nor any with non-performance. Moreover, he has no dependence on any object to serve any purpose."},{"k":"sankaranarayan","t":"No purpose is served for him by what he has done or by what he has not done. For him, there is hardly any dependence on any purpose among all beings."}]},{"ch":3,"vn":19,"dev":"तस्मादसक्तः सततं कार्यं कर्म समाचर।\nअसक्तो ह्याचरन्कर्म परमाप्नोति पूरुषः","iast":"tasmād asaktaḥ satataṁ kāryaṁ karma samāchara\nasakto hyācharan karma param āpnoti pūruṣhaḥ","v":[{"k":"purohit","t":"Therefore, do your duty perfectly, without worrying about the results, for he who does his duty without attachment attains the Supreme."},{"k":"sivananda","t":"Therefore, without attachment, always perform the actions that should be done; for by performing actions without attachment, one reaches the Supreme."},{"k":"adidevananda","t":"Therefore, do your work without attachment, which ought to be done. For, a person who works without attachment attains the Supreme."},{"k":"gambirananda","t":"Therefore, remaining unattached, always perform the obligatory duty; for, by performing one's duty without attachment, a person attains the highest."},{"k":"sankaranarayan","t":"Therefore, always remaining unattached, you should perform the action that is to be performed; for, the person performing action without attachment attains the Supreme."}]},{"ch":3,"vn":20,"dev":"कर्मणैव हि संसिद्धिमास्थिता जनकादयः।\nलोकसंग्रहमेवापि संपश्यन्कर्तुमर्हसि","iast":"karmaṇaiva hi sansiddhim āsthitā janakādayaḥ\nloka-saṅgraham evāpi sampaśhyan kartum arhasi","v":[{"k":"purohit","t":"King Janaka and others attained perfection through action alone. Even for the sake of enlightening the world, it is your duty to act."},{"k":"sivananda","t":"Janaka and others attained perfection indeed through action alone; even with the intention of protecting the masses, you should perform action."},{"k":"adidevananda","t":"Indeed, Janaka and others reached perfection through Karma Yoga alone. Even recognizing its necessity for guiding the world, you must perform action."},{"k":"gambirananda","t":"For Janaka and others strove to attain liberation through action itself. You should perform your duties, keeping in view the prevention of mankind from going astray."},{"k":"sankaranarayan","t":"Janaka and others attained emancipation through action alone. Moreover, you should act with the intention of upholding the world."}]},{"ch":3,"vn":21,"dev":"यद्यदाचरति श्रेष्ठस्तत्तदेवेतरो जनः।\nस यत्प्रमाणं कुरुते लोकस्तदनुवर्तते","iast":"yad yad ācharati śhreṣhṭhas tat tad evetaro janaḥ\nsa yat pramāṇaṁ kurute lokas tad anuvartate","v":[{"k":"purohit","t":"For whatever a great man does, others imitate; people conform to the standard he has set."},{"k":"sivananda","t":"Whatever a great man does, others also do; whatever he establishes as the standard, the world follows."},{"k":"adidevananda","t":"Whatever a great man does, others do too. Whatever standard he sets, the world follows it."},{"k":"gambirananda","t":"Whatever a superior person does, another person does the same! Whatever they uphold as authority, an ordinary person follows that."},{"k":"sankaranarayan","t":"Whatever a great man does, others of lesser stature follow suit; whatever standard he sets, the world follows it."},{"k":"arnold","t":"What the wise choose\nThe unwise people take; what best men do\nThe multitude will follow."}]},{"ch":3,"vn":22,"dev":"न मे पार्थास्ति कर्तव्यं त्रिषु लोकेषु किञ्चन।\nनानवाप्तमवाप्तव्यं वर्त एव च कर्मणि","iast":"na me pārthāsti kartavyaṁ triṣhu lokeṣhu kiñchana\nnānavāptam avāptavyaṁ varta eva cha karmaṇi","v":[{"k":"purohit","t":"There is nothing in this universe, O Arjuna, that I am compelled to do, nor anything for me to attain; yet I persistently remain active."},{"k":"sivananda","t":"There is nothing in the three worlds, O Arjuna, that needs to be done by Me, nor is there anything unattained that needs to be attained; yet I engage Myself in action."},{"k":"adidevananda","t":"For me, Arjuna, there is nothing in all the three worlds that ought to be done, nor is there anything unaccomplished that ought to be accomplished. Yet I continue to work."},{"k":"gambirananda","t":"In all the three worlds, O Partha, there is no duty for Me to fulfill; nothing remains unachieved or to be achieved. (Still,) I continue in action."},{"k":"sankaranarayan","t":"O son of Prtha! For Me, there is nothing to be done in the three worlds, nor is there anything yet to be attained; and yet I am engaged in action."}]},{"ch":3,"vn":23,"dev":"यदि ह्यहं न वर्तेयं जातु कर्मण्यतन्द्रितः।\nमम वर्त्मानुवर्तन्ते मनुष्याः पार्थ सर्वशः","iast":"yadi hyahaṁ na varteyaṁ jātu karmaṇyatandritaḥ\nmama vartmānuvartante manuṣhyāḥ pārtha sarvaśhaḥ","v":[{"k":"purohit","t":"Were I not to act without ceasing, O prince, people would be inclined to do the same."},{"k":"sivananda","t":"For, should I not ever engage myself in action, unwearied, people would in every way follow my path, O Arjuna."},{"k":"adidevananda","t":"If I did not continue to work unweariedly, O Arjuna, people would follow my path."},{"k":"gambirananda","t":"For, O Partha, if at any time I do not continue vigilantly in action, people will follow My path in every way."},{"k":"sankaranarayan","t":"For, if I were ever not to work unwearied, all men would follow My path, O son of Prtha!"}]},{"ch":3,"vn":24,"dev":"उत्सीदेयुरिमे लोका न कुर्यां कर्म चेदहम्।\nसङ्करस्य च कर्ता स्यामुपहन्यामिमाः प्रजाः","iast":"utsīdeyur ime lokā na kuryāṁ karma ched aham\nsankarasya cha kartā syām upahanyām imāḥ prajāḥ","v":[{"k":"purohit","t":"And if I were to refrain from action, the human race would be ruined; I would lead the world to chaos, and destruction would follow."},{"k":"sivananda","t":"These worlds would perish if I did not perform action; I would be the author of confusion of castes and destruction of these beings."},{"k":"adidevananda","t":"If I do not do the work, these people will be lost; and I will be causing chaos in life and thereby ruining all these people."},{"k":"gambirananda","t":"These worlds would be ruined if I did not perform action. And I shall become the agent of intermingling (of castes), and shall be destroying these beings."},{"k":"sankaranarayan","t":"These worlds would perish if I were not to perform action; and I would be the cause of confusion; I would destroy these people."}]},{"ch":3,"vn":25,"dev":"सक्ताः कर्मण्यविद्वांसो यथा कुर्वन्ति भारत।\nकुर्याद्विद्वांस्तथासक्तश्िचकीर्षुर्लोकसंग्रहम्","iast":"saktāḥ karmaṇyavidvānso yathā kurvanti bhārata\nkuryād vidvāns tathāsaktaśh chikīrṣhur loka-saṅgraham","v":[{"k":"purohit","t":"As the ignorant act, out of their fondness for action, so should the wise act without attachment, fixing their eyes, O Arjuna, only on the welfare of the world."},{"k":"sivananda","t":"As the ignorant act out of attachment to action, O Bharata, so should the wise act without attachment, wishing for the welfare of the world."},{"k":"adidevananda","t":"Just as the ignorant, attached to their work, act, O Arjuna, so too the learned should act without any attachment, and only for the welfare of the world."},{"k":"gambirananda","t":"O scion of the Bharata dynasty, as the unenlightened people act with attachment to work, so should the enlightened person act, without attachment, desiring to prevent people from going astray."},{"k":"sankaranarayan","t":"Therefore, just as the unwise persons, being attached to action, do, O son of Prtha, so the wise should perform, but being unattached and desiring to hold the world together."}]},{"ch":3,"vn":26,"dev":"न बुद्धिभेदं जनयेदज्ञानां कर्मसङ्गिनाम्।\nजोषयेत्सर्वकर्माणि विद्वान् युक्तः समाचरन्","iast":"na buddhi-bhedaṁ janayed ajñānāṁ karma-saṅginām\njoṣhayet sarva-karmāṇi vidvān yuktaḥ samācharan","v":[{"k":"purohit","t":"But a wise man should not disturb the minds of the ignorant, who are attached to action; let him perform his own actions in the right spirit, with concentration on Me, thus inspiring all others to do the same."},{"k":"sivananda","t":"Let no wise man unsettle the minds of ignorant people who are attached to action; he should engage them in all actions, himself fulfilling them with devotion."},{"k":"adidevananda","t":"He should not bewilder the minds of the ignorant who are attached to work; rather, he should himself perform work with devotion and cause others to do the same."},{"k":"gambirananda","t":"The enlightened man should not disturb the beliefs of the ignorant, who are attached to work. He should remain diligent himself and make them perform all their duties."},{"k":"sankaranarayan","t":"Let the wise master of Yoga fulfill (or destroy) all actions by performing them all, and let him not create any disturbance in the minds of the ignorant persons attached to action."}]},{"ch":3,"vn":27,"dev":"प्रकृतेः क्रियमाणानि गुणैः कर्माणि सर्वशः।\nअहङ्कारविमूढात्मा कर्ताऽहमिति मन्यते","iast":"prakṛiteḥ kriyamāṇāni guṇaiḥ karmāṇi sarvaśhaḥ\nahankāra-vimūḍhātmā kartāham iti manyate","v":[{"k":"purohit","t":"Action is the product of the qualities inherent in nature. It is only the ignorant man who, misled by personal egotism, says, \"I am the doer.\""},{"k":"sivananda","t":"All actions are wrought in all cases by the qualities of Nature alone. He whose mind is deluded by egoism thinks, \"I am the doer.\""},{"k":"adidevananda","t":"Actions are being performed in every way by the Gunas of Prakrti; he whose nature is deluded by egoism, however, thinks, 'I am the doer.'"},{"k":"gambirananda","t":"While actions are being done in every way by the gunas (qualities) of Nature, one who is deluded by egoism thinks, \"I am the doer.\""},{"k":"sankaranarayan","t":"The actions are performed part by part by the strands of Prakriti; yet, the person, having his self (mind) deluded with egoity, imagines, 'I am the sole doer.'"}]},{"ch":3,"vn":28,"dev":"तत्त्ववित्तु महाबाहो गुणकर्मविभागयोः।\nगुणा गुणेषु वर्तन्त इति मत्वा न सज्जते","iast":"tattva-vit tu mahā-bāho guṇa-karma-vibhāgayoḥ\nguṇā guṇeṣhu vartanta iti matvā na sajjate","v":[{"k":"purohit","t":"But he, O Mighty One, who correctly understands the relationship between the Qualities and action, is not attached to the act, for he perceives that it is merely the action and reaction of the Qualities among themselves."},{"k":"sivananda","t":"But he who knows the Truth, O mighty-armed Arjuna, about the divisions of the qualities and their functions, knowing that the Gunas, as senses, move amidst the Gunas, as the sense-objects, is not attached."},{"k":"adidevananda","t":"But he who knows the truth about the division of the Gunas and works, O mighty-armed one, through his knowledge that the Gunas 'operate on their own products,' is not attached."},{"k":"gambirananda","t":"But, O mighty-armed one, the one who is a knower of the facts about the varieties of the gunas and actions does not become attached, thinking thus: 'The organs act on the objects of the organs.'"},{"k":"sankaranarayan","t":"But, O mighty-armed one, the one who knows the true nature of the strands and their respective divisions of work, realizes: 'The strands are in their respective purposes.' And thus, he is not attached."}]},{"ch":3,"vn":29,"dev":"प्रकृतेर्गुणसम्मूढाः सज्जन्ते गुणकर्मसु।\nतानकृत्स्नविदो मन्दान्कृत्स्नविन्न विचालयेत्","iast":"prakṛiter guṇa-sammūḍhāḥ sajjante guṇa-karmasu\ntān akṛitsna-vido mandān kṛitsna-vin na vichālayet","v":[{"k":"purohit","t":"Those who do not understand the qualities are interested in the act; however, the wise man who knows the truth should not disturb the mind of those who do not."},{"k":"sivananda","t":"Those deluded by the qualities of Nature are attached to the functions of the qualities. The man of perfect knowledge should not unsettle the foolish one who is of imperfect knowledge."},{"k":"adidevananda","t":"Those who are deluded by the Gunas of Prakrti are attached to the works of the Gunas. But he who knows the whole truth should not disturb the ignorant who do not know the whole truth."},{"k":"gambirananda","t":"Those who are completely deluded by the gunas of Nature become attached to the activities of the gunas. The one who knows the All should not disturb those of dull intellect, who do not know the All."},{"k":"sankaranarayan","t":"Men, completely deluded by the strands of Prakrti, are attached to the actions of those strands. Those who know fully should not confuse them, whereas the dullards who do not know fully."}]},{"ch":3,"vn":30,"dev":"मयि सर्वाणि कर्माणि संन्यस्याध्यात्मचेतसा।\nनिराशीर्निर्ममो भूत्वा युध्यस्व विगतज्वरः","iast":"mayi sarvāṇi karmāṇi sannyasyādhyātma-chetasā\nnirāśhīr nirmamo bhūtvā yudhyasva vigata-jvaraḥ","v":[{"k":"purohit","t":"Therefore, surrender your actions to Me, keep your thoughts focused on the Absolute, free from selfishness and without expecting a reward, with a mind free from excitement, begin to fight."},{"k":"sivananda","t":"Renouncing all actions in Me, with the mind centered on the Self, free from hope and egoism, and from mental fever, fight thou."},{"k":"adidevananda","t":"Surrender all your actions to Me, with a mind focused on the Self, free from desire and selfishness, and fight with the heat of excitement abated."},{"k":"gambirananda","t":"Free from the fever of the soul, dedicate all actions to Me, with your mind intent on the Self, and become free from expectations and egoism, and engage in battle."},{"k":"sankaranarayan","t":"Renouncing all actions in Me, with a mind that concentrates on the Self; being free from the act of resting and from the sense of possession; and consequently being free from mental fever; you should fight."}]},{"ch":3,"vn":31,"dev":"ये मे मतमिदं नित्यमनुतिष्ठन्ति मानवाः।\nश्रद्धावन्तोऽनसूयन्तो मुच्यन्ते तेऽपि कर्मभिः","iast":"ye me matam idaṁ nityam anutiṣhṭhanti mānavāḥ\nśhraddhāvanto 'nasūyanto muchyante te 'pi karmabhiḥ","v":[{"k":"purohit","t":"Those who always act in accordance with My precepts, firmly in faith and without caviling, they too are freed from the bondage of action."},{"k":"sivananda","t":"Those who constantly practice this teaching of Mine with faith and without caviling, they too are freed from actions."},{"k":"adidevananda","t":"Those men who, full of faith, ever practice this teaching of Mine and those who receive it without cavil—even they are released from karma."},{"k":"gambirananda","t":"Those who faithfully follow this teaching of Mine without cavil, they too become freed from their actions."},{"k":"sankaranarayan","t":"Those who constantly follow this doctrine of Mine, with faith and without finding fault, are freed from the results of all actions."}]},{"ch":3,"vn":32,"dev":"ये त्वेतदभ्यसूयन्तो नानुतिष्ठन्ति मे मतम्।\nसर्वज्ञानविमूढांस्तान्विद्धि नष्टानचेतसः","iast":"ye tvetad abhyasūyanto nānutiṣhṭhanti me matam\nsarva-jñāna-vimūḍhāns tān viddhi naṣhṭān achetasaḥ","v":[{"k":"purohit","t":"But they who ridicule My word and do not observe it, are ignorant, devoid of wisdom, and blind. They seek only their own destruction."},{"k":"sivananda","t":"But those who criticize My teaching and do not practice it, deprived of all knowledge and lacking discernment, know them to be doomed to destruction."},{"k":"adidevananda","t":"But those who slander it, and those who do not practice this teaching of Mine—know them to be utterly senseless and devoid of all knowledge, and thus lost."},{"k":"gambirananda","t":"But those who, finding fault where there is none, do not follow My teaching, know them—who are deluded about all knowledge concerning the qualified and the unqualified Brahman and who are devoid of discrimination—to have gone to ruin."},{"k":"sankaranarayan","t":"But those who, finding fault, do not follow this doctrine of Mine - be sure that these men are highly deluded in all branches of knowledge and are lost and brainless."}]},{"ch":3,"vn":33,"dev":"सदृशं चेष्टते स्वस्याः प्रकृतेर्ज्ञानवानपि।\nप्रकृतिं यान्ति भूतानि निग्रहः किं करिष्यति","iast":"sadṛiśhaṁ cheṣhṭate svasyāḥ prakṛiter jñānavān api\nprakṛitiṁ yānti bhūtāni nigrahaḥ kiṁ kariṣhyati","v":[{"k":"purohit","t":"Even the wise man acts in accordance with his nature; indeed, all creatures act according to their natures. What is the use of compulsion then?"},{"k":"sivananda","t":"Even a wise man acts in accordance with his own nature; beings will follow their nature; what can restraint do?"},{"k":"adidevananda","t":"Even the man of knowledge acts according to his nature; all beings follow their own nature. What will repression accomplish?"},{"k":"gambirananda","t":"Even a man of wisdom behaves according to his own nature. They follow their nature. What can restraint do?"},{"k":"sankaranarayan","t":"Even a man of knowledge acts in accordance with his own Prakriti; the elements return to Prakriti; what will restraint avail?"}]},{"ch":3,"vn":34,"dev":"इन्द्रियस्येन्द्रियस्यार्थे रागद्वेषौ व्यवस्थितौ।\nतयोर्न वशमागच्छेत्तौ ह्यस्य परिपन्थिनौ","iast":"indriyasyendriyasyārthe rāga-dveṣhau vyavasthitau\ntayor na vaśham āgachchhet tau hyasya paripanthinau","v":[{"k":"purohit","t":"The love and hate that are aroused by the objects of sense arise from Nature; do not yield to them, as they only obstruct the path."},{"k":"sivananda","t":"Attachment and aversion for the objects of the senses abide in the senses; let no one come under their sway; for, they are his enemies."},{"k":"adidevananda","t":"Each sense has a fixed attachment to and aversion for its corresponding object, but one should not come under their sway, for they are enemies."},{"k":"gambirananda","t":"Attraction and repulsion are ordained with respect to the objects of all the organs. One should not be swayed by these two, as they are adversaries."},{"k":"sankaranarayan","t":"For a man of worldly life, there are clearly fixed likes and dislikes with regard to the objects of each of his sense organs. These are the obstacles for him; the wise would not come under their control."}]},{"ch":3,"vn":35,"dev":"श्रेयान्स्वधर्मो विगुणः परधर्मात्स्वनुष्ठितात्।\nस्वधर्मे निधनं श्रेयः परधर्मो भयावहः","iast":"śhreyān swa-dharmo viguṇaḥ para-dharmāt sv-anuṣhṭhitāt\nswa-dharme nidhanaṁ śhreyaḥ para-dharmo bhayāvahaḥ","v":[{"k":"purohit","t":"It is better to do one's own duty, however lacking in merit, than to do that of another, even though efficiently. It is better to die doing one's own duty, for doing the duty of another is fraught with danger."},{"k":"sivananda","t":"Better is one's own duty, though devoid of merit, than the duty of another well discharged. Better is death in one's own duty; the duty of another is fraught with fear."},{"k":"adidevananda","t":"Better is one's own duty, even if done poorly, than the duty of another done well. It is better to die while performing one's own duty; the duty of another is full of fear."},{"k":"gambirananda","t":"One's own duty, though defective, is superior to another's duty well-performed. Death is better while engaged in one's own duty; another's duty is full of fear."},{"k":"sankaranarayan","t":"Better is one's own duty, even if it lacks merit, than the well-performed duty of another; it is better to suffer ruin in one's own duty than to gain success in another's."},{"k":"arnold","t":"Finally, this is better, that one do\nHis own task as he may, even though he fail,\nThan take tasks not his own, though they seem good.\nTo die performing duty is no ill;\nBut who seeks other roads shall wander still."}]},{"ch":3,"vn":36,"dev":"अर्जुन उवाच\nअथ केन प्रयुक्तोऽयं पापं चरति पूरुषः।\nअनिच्छन्नपि वार्ष्णेय बलादिव नियोजितः","iast":"arjuna uvācha\natha kena prayukto 'yaṁ pāpaṁ charati pūruṣhaḥ\nanichchhann api vārṣhṇeya balād iva niyojitaḥ","v":[{"k":"purohit","t":"Arjuna asked, \"My Lord, what is it that drives a person to sin, even against their will and as if by compulsion?\""},{"k":"sivananda","t":"Arjuna said, \"But what compels man to commit sin, even against his wishes, O Varshneya (Krishna), as if constrained by force?\""},{"k":"adidevananda","t":"Arjuna said, \"But, O Krsna, what impels one to commit sin, even against their own will, as if constrained by force?\""},{"k":"gambirananda","t":"Arjuna said, \"Now then, O scion of the Vrsni dynasty (Krsna), what compels this man to commit sin even against his will, as if he were constrained by force?\""},{"k":"sankaranarayan","t":"Arjuna said, \"Then, what induces this person of the world to commit sin, even though they do not desire it, as if they are being overpowered by a force?\""}]},{"ch":3,"vn":37,"dev":"श्री भगवानुवाच\nकाम एष क्रोध एष रजोगुणसमुद्भवः।\nमहाशनो महापाप्मा विद्ध्येनमिह वैरिणम्","iast":"śhrī bhagavān uvācha\nkāma eṣha krodha eṣha rajo-guṇa-samudbhavaḥ\nmahāśhano mahā-pāpmā viddhyenam iha vairiṇam","v":[{"k":"purohit","t":"Lord Shri Krishna: It is desire, it is aversion, born of passion. Desire consumes and corrupts all things. It is the greatest enemy of man."},{"k":"sivananda","t":"The Blessed Lord said, \"It is desire and it is anger, both of the quality of Rajas, all-devouring and all-sinful; know this as the foe here in this world.\""},{"k":"adidevananda","t":"The Lord said, \"It is desire, it is wrath, born of the guna of rajas; it is a great devourer, an impeller of sin. Know this to be the enemy here.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"This desire, this anger, born of the quality of rajas, is a great devourer, a great source of sin. Know this to be the enemy here.\""},{"k":"sankaranarayan","t":"The Bhagavat said, \"This desire, this wrath, born of the Rajas-strand, is a swallower of festivity and a mighty bestower of sins. Know this to be the enemy here.\""}]},{"ch":3,"vn":38,"dev":"धूमेनाव्रियते वह्निर्यथाऽऽदर्शो मलेन च।\nयथोल्बेनावृतो गर्भस्तथा तेनेदमावृतम्","iast":"dhūmenāvriyate vahnir yathādarśho malena cha\nyatholbenāvṛito garbhas tathā tenedam āvṛitam","v":[{"k":"purohit","t":"As fire is shrouded by smoke, a mirror is covered by dust, and a child is enveloped by the womb, so is the universe enveloped in desire."},{"k":"sivananda","t":"As fire is enveloped by smoke, as a mirror is covered by dust, and as an embryo is surrounded by the amniotic sac, so is this enveloped by that."},{"k":"adidevananda","t":"As a fire is enveloped by smoke, as a mirror is covered by dust, and as an embryo is encased in the amniotic sac, so is this world enveloped by desire."},{"k":"gambirananda","t":"As fire is enveloped by smoke, as a mirror is obscured by dirt, and as a fetus remains enclosed in the womb, so is this shrouded by that."},{"k":"sankaranarayan","t":"As fire is concealed by smoke, a mirror by dirt, and an embryo by its membrane-cover, so He is concealed by this foe."}]},{"ch":3,"vn":39,"dev":"आवृतं ज्ञानमेतेन ज्ञानिनो नित्यवैरिणा।\nकामरूपेण कौन्तेय दुष्पूरेणानलेन च","iast":"āvṛitaṁ jñānam etena jñānino nitya-vairiṇā\nkāma-rūpeṇa kaunteya duṣhpūreṇānalena cha","v":[{"k":"purohit","t":"It is the wise man's constant enemy; it tarnishes the face of wisdom, being as insatiable as a flame of fire."},{"k":"sivananda","t":"O Arjuna, wisdom is enveloped by this constant enemy of the wise, in the form of desire, which is insatiable like fire."},{"k":"adidevananda","t":"The knowledge of the intelligent self is enveloped by this constant enemy, O Arjuna, which is of the nature of desire and is difficult to gratify and insatiable."},{"k":"gambirananda","t":"O son of Kunti, knowledge is covered by this constant enemy of the wise, in the form of desire, which is an insatiable fire."},{"k":"sankaranarayan","t":"O son of Kunti! The knowledge of the wise is concealed by this eternal foe, which appears desirable yet is insatiable like fire."}]},{"ch":3,"vn":40,"dev":"इन्द्रियाणि मनो बुद्धिरस्याधिष्ठानमुच्यते।\nएतैर्विमोहयत्येष ज्ञानमावृत्य देहिनम्","iast":"indriyāṇi mano buddhir asyādhiṣhṭhānam uchyate\netair vimohayatyeṣha jñānam āvṛitya dehinam","v":[{"k":"purohit","t":"It works through the senses, the mind, and the reason; and with their help, it destroys wisdom and confounds the soul."},{"k":"sivananda","t":"The senses, the mind, and the intellect are said to be its seat; through these, it deludes the embodied one, veiling their wisdom."},{"k":"adidevananda","t":"The senses, the mind, and the intellect are said to be its instruments; by these, it overpowers the embodied self, enveloping its knowledge."},{"k":"gambirananda","t":"The organs, mind, and intellect are said to be its abode. This one diversely deludes the embodied being, veiling Knowledge with the help of these."},{"k":"sankaranarayan","t":"It is said to be based on the sense-organs, the mind, and the intellect. With these, it deludes the embodied by concealing knowledge."}]},{"ch":3,"vn":41,"dev":"तस्मात्त्वमिन्द्रियाण्यादौ नियम्य भरतर्षभ।\nपाप्मानं प्रजहि ह्येनं ज्ञानविज्ञाननाशनम्","iast":"tasmāt tvam indriyāṇyādau niyamya bharatarṣhabha\npāpmānaṁ prajahi hyenaṁ jñāna-vijñāna-nāśhanam","v":[{"k":"purohit","t":"Therefore, O Arjuna, first control your senses and then slay desire, for it is full of sin and is the destroyer of knowledge and wisdom."},{"k":"sivananda","t":"Therefore, O best of the Bharatas, control your senses first and then kill this sinful thing, which destroys knowledge and realization."},{"k":"adidevananda","t":"Therefore, O Arjuna, control your senses from the outset and slay this sinful thing that destroys both knowledge and discernment."},{"k":"gambirananda","t":"Therefore, O scion of the Bharata dynasty, after first controlling the organs, completely renounce this one which is sinful and a destroyer of learning and wisdom."},{"k":"sankaranarayan","t":"Therefore, O best among the Bharatas, you must avoid this sinful one, destroying knowledge and action, by controlling completely the sense-organs in the beginning itself."}]},{"ch":3,"vn":42,"dev":"इन्द्रियाणि पराण्याहुरिन्द्रियेभ्यः परं मनः।\nमनसस्तु परा बुद्धिर्यो बुद्धेः परतस्तु सः","iast":"indriyāṇi parāṇyāhur indriyebhyaḥ paraṁ manaḥ\nmanasas tu parā buddhir yo buddheḥ paratas tu saḥ","v":[{"k":"purohit","t":"It is said that the senses are powerful; however, beyond the senses is the mind, beyond the mind is the intellect, and greater than the intellect is He."},{"k":"sivananda","t":"They say that the senses are superior to the body; the mind is superior to the senses; the intellect is superior to the mind; and He (the Self) is superior even to the intellect."},{"k":"adidevananda","t":"They say that the senses are high, the mind is higher than the senses, the intellect is higher than the mind, but what is greater than the intellect is that (desire)."},{"k":"gambirananda","t":"They say that the organs are superior to the gross body; the mind is superior to the organs; and the intellect is superior to the mind. However, He is superior to the intellect."},{"k":"sankaranarayan","t":"It is said that the sense-organs are different from their objects; the mind is different from the sense-organs; the intellect is different from the mind; and That (Self) is different from the intellect."}]},{"ch":3,"vn":43,"dev":"एवं बुद्धेः परं बुद्ध्वा संस्तभ्यात्मानमात्मना।\nजहि शत्रुं महाबाहो कामरूपं दुरासदम्","iast":"evaṁ buddheḥ paraṁ buddhvā sanstabhyātmānam ātmanā\njahi śhatruṁ mahā-bāho kāma-rūpaṁ durāsadam","v":[{"k":"purohit","t":"Thus, O Mighty-Armed One, knowing Him to be beyond the intellect, and with His help, subdue your personal ego and kill your enemy, Desire, even though it is extremely difficult."},{"k":"sivananda","t":"Thus, knowing Him who is superior to the intellect and restraining the self by the Self, slay thou, O mighty-armed Arjuna, the enemy in the form of desire, hard to conquer."},{"k":"adidevananda","t":"Thus, knowing that which is higher than the intellect and fixing the mind with the help of the intellect in Karma Yoga, O Arjuna, slay this enemy which takes the form of desire, and which is difficult to overcome."},{"k":"gambirananda","t":"[The Ast, introduces this verse with, 'Tatah kim, what follows from that?'-Tr.] Understanding the Self thus as superior to the intellect, and completely establishing (the Self) through spiritual absorption with the (help of) the mind, O mighty-armed one, the enemy in the form of desire, which is difficult to subdue, vanishes."},{"k":"sankaranarayan","t":"Thus, being conscious that it is different from the intellect, and steadying the self with the self, kill the foe that is of the form of desire and that is hard to approach."}]},{"ch":4,"vn":1,"dev":"श्री भगवानुवाच\nइमं विवस्वते योगं प्रोक्तवानहमव्ययम्।\nविवस्वान् मनवे प्राह मनुरिक्ष्वाकवेऽब्रवीत्","iast":"śhrī bhagavān uvācha\nimaṁ vivasvate yogaṁ proktavān aham avyayam\nvivasvān manave prāha manur ikṣhvākave 'bravīt","v":[{"k":"purohit","t":"Lord Shri Krishna said: I taught this imperishable philosophy to Vivaswān, the founder of the Sun dynasty; Vivaswān gave it to Manu, the lawgiver, and Manu to King Ikshvāku."},{"k":"sivananda","t":"The Blessed Lord said, \"I taught this imperishable Yoga to Vivasvan; he then told it to Manu; Manu proclaimed it to Ikshvaku."},{"k":"adidevananda","t":"The Lord said, \"I taught this imperishable Yoga to Vivasvan; Vivasvan taught it to Manu; Manu declared it to Iksvaku.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"I imparted this imperishable Yoga to Vivasvan, who then taught it to Manu, who in turn transmitted it to Iksavaku."},{"k":"sankaranarayan","t":"The Bhagavad said, \"This changeless Yoga I had properly taught thus to Vivasvat; Vivasvat correctly told it to Manu; and Manu declared it to Iksvaku.\""}]},{"ch":4,"vn":2,"dev":"एवं परम्पराप्राप्तमिमं राजर्षयो विदुः।\nस कालेनेह महता योगो नष्टः परन्तप","iast":"evaṁ paramparā-prāptam imaṁ rājarṣhayo viduḥ\nsa kāleneha mahatā yogo naṣhṭaḥ parantapa","v":[{"k":"purohit","t":"The Divine Kings knew it, for it was their tradition; then, after a long time, it was at last forgotten."},{"k":"sivananda","t":"This, handed down in regular succession by the royal sages, was known. This Yoga, however, has been lost here over time, O Parantapa (burner of the foes)."},{"k":"adidevananda","t":"Thus handed down in succession, the royal sages knew this (Karma Yoga). But with a long lapse of time, O Arjuna, that Yoga was lost to the world."},{"k":"gambirananda","t":"The king-sages knew this yoga, which was received in regular succession. That yoga, O destroyer of foes, is now lost due to a long lapse of time."},{"k":"sankaranarayan","t":"Thus, the regal sages knew this, which was received in regular succession. Over time, however, this Yoga has been lost, O scorcher of enemies!"}]},{"ch":4,"vn":3,"dev":"स एवायं मया तेऽद्य योगः प्रोक्तः पुरातनः।\nभक्तोऽसि मे सखा चेति रहस्यं ह्येतदुत्तमम्","iast":"sa evāyaṁ mayā te 'dya yogaḥ proktaḥ purātanaḥ\nbhakto 'si me sakhā cheti rahasyaṁ hyetad uttamam","v":[{"k":"purohit","t":"It is the same ancient path that I have now revealed to you, for you are my devotee and my friend. It is the supreme secret."},{"k":"sivananda","t":"That same ancient yoga has been today taught to you by me, for you are my devotee and my friend; it is the supreme secret."},{"k":"adidevananda","t":"It is the same ancient Yoga that I am now teaching you, for you are My devotee and My friend. For, this is a supreme mystery."},{"k":"gambirananda","t":"That ancient Yoga itself, which is this, has been taught to you by Me today, considering you to be My devotee and friend, for this Yoga is a profound secret."},{"k":"sankaranarayan","t":"The same ancient Yoga has now been taught to you by Me, on the grounds that you are both My devotee and friend. This is the highest secret."}]},{"ch":4,"vn":4,"dev":"अर्जुन उवाच\nअपरं भवतो जन्म परं जन्म विवस्वतः।\nकथमेतद्विजानीयां त्वमादौ प्रोक्तवानिति","iast":"arjuna uvācha\naparaṁ bhavato janma paraṁ janma vivasvataḥ\nkatham etad vijānīyāṁ tvam ādau proktavān iti","v":[{"k":"purohit","t":"Arjuna asked: My Lord! Vyasawana was born before You; how then can You have revealed it to him?"},{"k":"sivananda","t":"Arjuna said, \"Later was Thy birth, and prior to it was the birth of Vivasvan (the Sun); how am I to understand that Thou hast taught this Yoga from the beginning?\""},{"k":"adidevananda","t":"Arjuna said, \"Your birth was later, and Vivasvan's birth was earlier. How then can I understand that you taught it in the beginning?\""},{"k":"gambirananda","t":"Arjuna said, \"Your birth was later, whereas Vivasvan's birth was earlier. How am I to understand that You instructed him in the beginning?\""},{"k":"sankaranarayan","t":"Arjuna said, \"Your birth is later, while the birth of Vivasvat is earlier; how am I then to understand that You had properly taught him this in the beginning?\""}]},{"ch":4,"vn":5,"dev":"श्री भगवानुवाच\nबहूनि मे व्यतीतानि जन्मानि तव चार्जुन।\nतान्यहं वेद सर्वाणि न त्वं वेत्थ परन्तप","iast":"śhrī bhagavān uvācha\nbahūni me vyatītāni janmāni tava chārjuna\ntānyahaṁ veda sarvāṇi na tvaṁ vettha parantapa","v":[{"k":"purohit","t":"Lord Shri Krishna replied: I have been born again and again, from time to time; thou too, O Arjuna! My births are known to me, but yours are unknown to you."},{"k":"sivananda","t":"The Blessed Lord said, \"Many births of Mine have passed, as well as of thine, O Arjuna; I know them all, but thou knowest not, O Parantapa (scorcher of foes).\""},{"k":"adidevananda","t":"The Lord said, \"Many of My births have passed, O Arjuna, as have yours. I know them all, but you do not know them.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"O Arjuna, many lives of Mine have passed, and so have yours. I know them all, but you do not know, O scorcher of enemies!\""},{"k":"sankaranarayan","t":"The Bhagavat said, \"O Arjuna, many births of Mine as well as yours have passed. All of them I know, but you do not, O scorcher of foes!\""}]},{"ch":4,"vn":6,"dev":"अजोऽपि सन्नव्ययात्मा भूतानामीश्वरोऽपि सन्।\nप्रकृतिं स्वामधिष्ठाय संभवाम्यात्ममायया","iast":"ajo 'pi sannavyayātmā bhūtānām īśhvaro 'pi san\nprakṛitiṁ svām adhiṣhṭhāya sambhavāmyātma-māyayā","v":[{"k":"purohit","t":"There is no beginning to Me. Though I am imperishable and the Lord of all that exists, I manifest Myself by My own will and power."},{"k":"sivananda","t":"Though I am unborn and of imperishable nature, and though I am the Lord of all beings, yet, governing my own nature, I am born by my own Maya."},{"k":"adidevananda","t":"Though I am birthless and of immutable nature, and the Lord of all beings, yet by employing My own Nature (Prakrti), I am born out of My own free will."},{"k":"gambirananda","t":"Though I am birthless and undecaying by nature, and the Lord of beings, yet by subjugating My Prakriti, I take birth through My own Maya."},{"k":"sankaranarayan","t":"Though I am unborn and changeless Self, though I am the Lord of all beings, yet, presiding over My own nature, I take birth by My own trick of illusion."}]},{"ch":4,"vn":7,"dev":"यदा यदा हि धर्मस्य ग्लानिर्भवति भारत।\nअभ्युत्थानमधर्मस्य तदाऽऽत्मानं सृजाम्यहम्","iast":"yadā yadā hi dharmasya glānir bhavati bhārata\nabhyutthānam adharmasya tadātmānaṁ sṛijāmyaham","v":[{"k":"purohit","t":"Whenever spirituality decays and materialism is rampant, then, O Arjuna, I reincarnate myself."},{"k":"sivananda","t":"Whenever there is a decline of righteousness and an increase of unrighteousness, O Arjuna, then I manifest Myself."},{"k":"adidevananda","t":"Whenever there is a decline of Dharma, O Arjuna, and an uprising of Adharma, then I incarnate myself."},{"k":"gambirananda","t":"O scion of the Bharata dynasty, whenever there is a decline in virtue and an increase in vice, then I manifest Myself."},{"k":"sankaranarayan","t":"For, whenever there is a decay of righteousness and the rise of unrighteousness, then, O descendant of Bharata, I send forth that which the Self is unimportant."}]},{"ch":4,"vn":8,"dev":"परित्राणाय साधूनां विनाशाय च दुष्कृताम्।\nधर्मसंस्थापनार्थाय संभवामि युगे युगे","iast":"paritrāṇāya sādhūnāṁ vināśhāya cha duṣhkṛitām\ndharma-sansthāpanārthāya sambhavāmi yuge yuge","v":[{"k":"purohit","t":"To protect the righteous, to destroy the wicked, and to establish the kingdom of God, I am reborn from age to age."},{"k":"sivananda","t":"For the protection of the good, for the destruction of the wicked, and for the establishment of righteousness, I am born in every age."},{"k":"adidevananda","t":"For the protection of the good and the destruction of the wicked, for the establishment of Dharma, I am born from age to age."},{"k":"gambirananda","t":"For the protection of the pious, the destruction of the evil-doers, and the establishment of virtue, I manifest myself in every age."},{"k":"sankaranarayan","t":"For the protection of the good people, and for the destruction of evildoers, and for the purpose of firmly establishing righteousness, I take birth in every age."}]},{"ch":4,"vn":9,"dev":"जन्म कर्म च मे दिव्यमेवं यो वेत्ति तत्त्वतः।\nत्यक्त्वा देहं पुनर्जन्म नैति मामेति सोऽर्जुन","iast":"janma karma cha me divyam evaṁ yo vetti tattvataḥ\ntyaktvā dehaṁ punar janma naiti mām eti so 'rjuna","v":[{"k":"purohit","t":"He who realizes the divine truth concerning My birth and life does not take birth again; and when he leaves his body, he becomes one with Me."},{"k":"sivananda","t":"He who thus knows, in their true light, My divine birth and actions, having abandoned the body, is not born again; he comes to Me, O Arjuna."},{"k":"adidevananda","t":"He who thus knows in truth My divine birth and actions does not get rebirth after leaving the body; he will come to Me, O Arjuna."},{"k":"gambirananda","t":"He who thus knows truly the divine birth and actions of Mine does not get rebirth after casting off the body. He attains Me, O Arjuna."},{"k":"sankaranarayan","t":"Whoever knows correctly the divine birth and action of Mine, he, upon abandoning the body, does not go to rebirth, but goes to Me, O Arjuna!"}]},{"ch":4,"vn":10,"dev":"वीतरागभयक्रोधा मन्मया मामुपाश्रिताः।\nबहवो ज्ञानतपसा पूता मद्भावमागताः","iast":"vīta-rāga-bhaya-krodhā man-mayā mām upāśhritāḥ\nbahavo jñāna-tapasā pūtā mad-bhāvam āgatāḥ","v":[{"k":"purohit","t":"Many have merged their existences in Mine, being freed from desire, fear, and anger, always filled with Me and purified by the illuminating flame of self-abnegation."},{"k":"sivananda","t":"Freed from attachment, fear, and anger, absorbed in Me, taking refuge in Me, purified by the fire of knowledge, many have attained My Being."},{"k":"adidevananda","t":"Freed from desire, fear, and wrath, absorbed in Me, depending upon Me, purified by the austerity of knowledge, many have attained My state."},{"k":"gambirananda","t":"Many who were devoid of attachment, fear, and anger, who were absorbed in Me, who had taken refuge in Me, and were purified by the austerity of knowledge, have attained My state."},{"k":"sankaranarayan","t":"Many persons, who are free from passion, fear, and anger; are full of Me; take refuge in Me; and have become pure through the austerity of wisdom—they have come to My being."}]},{"ch":4,"vn":11,"dev":"ये यथा मां प्रपद्यन्ते तांस्तथैव भजाम्यहम्।\nमम वर्त्मानुवर्तन्ते मनुष्याः पार्थ सर्वशः","iast":"ye yathā māṁ prapadyante tāns tathaiva bhajāmyaham\nmama vartmānuvartante manuṣhyāḥ pārtha sarvaśhaḥ","v":[{"k":"purohit","t":"However men try to worship Me, I welcome them. Whatever path they take, it leads to Me in the end."},{"k":"sivananda","t":"In whatever way men approach Me, even so do I reward them; My path do men tread in all ways, O Arjuna."},{"k":"adidevananda","t":"Whoever resorts to Me in any manner, I favor them in the same manner; men experience Me alone in different ways, O Arjuna."},{"k":"gambirananda","t":"According to the manner in which they approach Me, I favor them in that same manner. O son of Partha, humans follow My path in every way."},{"k":"sankaranarayan","t":"The way in which people resort to Me, in the same way I favor them. O son of Prtha, all kinds of people follow My path."}]},{"ch":4,"vn":12,"dev":"काङ्क्षन्तः कर्मणां सिद्धिं यजन्त इह देवताः।\nक्षिप्रं हि मानुषे लोके सिद्धिर्भवति कर्मजा","iast":"kāṅkṣhantaḥ karmaṇāṁ siddhiṁ yajanta iha devatāḥ\nkṣhipraṁ hi mānuṣhe loke siddhir bhavati karmajā","v":[{"k":"purohit","t":"Those who seek success worship the Powers, and their actions in this world bear immediate fruit."},{"k":"sivananda","t":"Those who long for success in action in this world sacrifice to the gods; for success is quickly attained by men through action."},{"k":"adidevananda","t":"Those who desire the fruits of their ritualistic acts, sacrifice to the gods here; for, success quickly accrues in the world of men."},{"k":"gambirananda","t":"Longing for the fruition of their actions (of their rites and duties), they worship the gods here. For, in the human world, success from action comes quickly."},{"k":"sankaranarayan","t":"Those who desire success in their actions perform sacrifices, intending them for the deities. For, the success born of ritualistic actions is quick in the world of men."}]},{"ch":4,"vn":13,"dev":"चातुर्वर्ण्यं मया सृष्टं गुणकर्मविभागशः।\nतस्य कर्तारमपि मां विद्ध्यकर्तारमव्ययम्","iast":"chātur-varṇyaṁ mayā sṛiṣhṭaṁ guṇa-karma-vibhāgaśhaḥ\ntasya kartāram api māṁ viddhyakartāram avyayam","v":[{"k":"purohit","t":"The four divisions of society—the wise, the soldier, the merchant, and the laborer—were created by Me, according to the natural distribution of qualities and instincts. I am the author of them, though I Myself do not act and am changeless."},{"k":"sivananda","t":"The fourfold caste has been created by Me according to the differentiation of Guna and Karma; though I am the author of it, know Me as non-doer and immutable."},{"k":"adidevananda","t":"The system of four stations was created by Me, according to the distinction of Gunas and Karma. Though I am their creator, know Me to be non-agent and immutable."},{"k":"gambirananda","t":"The four castes have been created by Me through a classification of the gunas and duties. Even though I am the agent of that (act of classification), still know Me to be non-agentive and changeless."},{"k":"sankaranarayan","t":"I have created the four-fold caste structure according to the division of their respective qualities and actions. Though I am the creator of this, know Me as the changeless, non-creator."}]},{"ch":4,"vn":14,"dev":"न मां कर्माणि लिम्पन्ति न मे कर्मफले स्पृहा।\nइति मां योऽभिजानाति कर्मभिर्न स बध्यते","iast":"na māṁ karmāṇi limpanti na me karma-phale spṛihā\niti māṁ yo 'bhijānāti karmabhir na sa badhyate","v":[{"k":"purohit","t":"My actions do not bind Me, nor do I desire anything that they can bring. He who thus realizes Me is not enslaved by action."},{"k":"sivananda","t":"Actions do not taint Me, nor do I have a desire for the fruit of actions. He who knows Me thus is not bound by actions."},{"k":"adidevananda","t":"Works cannot contaminate Me. There is no desire for the fruits of actions in Me. He who understands this is not bound by actions."},{"k":"gambirananda","t":"Actions do not taint Me; for I have no hankering for the results of actions. One who knows Me thus, does not become bound by their actions."},{"k":"sankaranarayan","t":"Actions do not stain me, nor do I have a desire for the fruits of them either. Whoever understands me in this way is not bound by their actions."}]},{"ch":4,"vn":15,"dev":"एवं ज्ञात्वा कृतं कर्म पूर्वैरपि मुमुक्षुभिः।\nकुरु कर्मैव तस्मात्त्वं पूर्वैः पूर्वतरं कृतम्","iast":"evaṁ jñātvā kṛitaṁ karma pūrvair api mumukṣhubhiḥ\nkuru karmaiva tasmāttvaṁ pūrvaiḥ pūrvataraṁ kṛitam","v":[{"k":"purohit","t":"In the light of wisdom, our ancestors who sought deliverance performed their acts. Act thou also as our fathers of old did."},{"k":"sivananda","t":"Having known this, the ancient seekers of freedom also performed action; therefore, do thou also perform action, as the ancients did in days of yore."},{"k":"adidevananda","t":"Knowing thus, even ancient seekers of liberation did their work. Therefore, do your work only as the ancients did in olden times."},{"k":"gambirananda","t":"Thus having known, even the ancient seekers of liberation performed their duties. Therefore, you should undertake action as was performed earlier by the ancients."},{"k":"sankaranarayan","t":"Realizing in this fashion, ancient seekers of salvation also undertook action. Hence, you too should, by all means, perform the action that was performed by the ancients."}]},{"ch":4,"vn":16,"dev":"किं कर्म किमकर्मेति कवयोऽप्यत्र मोहिताः।\nतत्ते कर्म प्रवक्ष्यामि यज्ज्ञात्वा मोक्ष्यसेऽशुभात्","iast":"kiṁ karma kim akarmeti kavayo 'pyatra mohitāḥ\ntat te karma pravakṣhyāmi yaj jñātvā mokṣhyase 'śhubhāt","v":[{"k":"purohit","t":"What is action and what is inaction? This is a question that has bewildered the wise. But I will declare to you the philosophy of action, and knowing it, you will be free from evil."},{"k":"sivananda","t":"What is action? What is inaction? Even the wise are confused about this. Therefore, I shall teach you the nature of action and inaction, by knowing which you will be liberated from the evil of Samsara, the wheel of birth and death."},{"k":"adidevananda","t":"What is action? What is non-action? Even the wise are puzzled in respect of these. I shall declare to you that kind of action, knowing which you will be freed from evil."},{"k":"gambirananda","t":"Even the intelligent are confounded as to what is action and what is inaction. I shall tell you of that action, knowing which you will become free from evil."},{"k":"sankaranarayan","t":"Even the wise are perplexed about what is action and what is non-action; I shall properly teach you the action, by knowing which you will be freed from evil."}]},{"ch":4,"vn":17,"dev":"कर्मणो ह्यपि बोद्धव्यं बोद्धव्यं च विकर्मणः।\nअकर्मणश्च बोद्धव्यं गहना कर्मणो गतिः","iast":"karmaṇo hyapi boddhavyaṁ boddhavyaṁ cha vikarmaṇaḥ\nakarmaṇaśh cha boddhavyaṁ gahanā karmaṇo gatiḥ","v":[{"k":"purohit","t":"It is necessary to consider what is right action, what is wrong action, and what is inaction, for the law of action is mysterious."},{"k":"sivananda","t":"For verily, the true nature of action enjoined by the scriptures should be known, as well as that of forbidden or unlawful action, and of inaction; the nature of action is hard to understand."},{"k":"adidevananda","t":"For, there is what ought to be known in action; likewise, there is what ought to be known in multi-form action; and there is what ought to be understood in non-action. Thus, mysterious is the way of action."},{"k":"gambirananda","t":"For there is something to be known even about action, and something to be known about prohibited action; and something needs to be known about inaction. The true nature of action is inscrutable."},{"k":"sankaranarayan","t":"Something has to be understood about good action; something has to be understood about wrong action; and something has to be understood about non-action. It is difficult to comprehend the way of action."}]},{"ch":4,"vn":18,"dev":"कर्मण्यकर्म यः पश्येदकर्मणि च कर्म यः।\nस बुद्धिमान् मनुष्येषु स युक्तः कृत्स्नकर्मकृत्","iast":"karmaṇyakarma yaḥ paśhyed akarmaṇi cha karma yaḥ\nsa buddhimān manuṣhyeṣhu sa yuktaḥ kṛitsna-karma-kṛit","v":[{"k":"purohit","t":"He who can see inaction in action, and action in inaction, is the wisest among men. He is a saint, even though he still acts."},{"k":"sivananda","t":"He who sees inaction in action and action in inaction, he is wise among men; he is a yogi and performer of all actions."},{"k":"adidevananda","t":"He who sees inaction in action and also action in inaction is wise among men. He is fit for release and has accomplished all actions."},{"k":"gambirananda","t":"He who finds inaction in action, and action in inaction, is the wise one [possessed of the knowledge of Brahman] among men; they are engaged in yoga and are performers of all actions!"},{"k":"sankaranarayan","t":"He who finds non-action in action, and action in non-action, is an intelligent one among men and is said to be a performer or destroyer of all actions."}]},{"ch":4,"vn":19,"dev":"यस्य सर्वे समारम्भाः कामसङ्कल्पवर्जिताः।\nज्ञानाग्निदग्धकर्माणं तमाहुः पण्डितं बुधाः","iast":"yasya sarve samārambhāḥ kāma-saṅkalpa-varjitāḥ\njñānāgni-dagdha-karmāṇaṁ tam āhuḥ paṇḍitaṁ budhāḥ","v":[{"k":"purohit","t":"The wise call him a sage, for whatever he undertakes is free from the motive of desire, and his deeds are purified by the fire of wisdom."},{"k":"sivananda","t":"He whose undertakings are all devoid of desires and selfish purposes, and whose actions have been burned by the fire of knowledge, the wise call him a sage."},{"k":"adidevananda","t":"He whose every undertaking is free from desire and delusive identification (of the body with the self), whose actions are burned up in the fire of knowledge—the wise describe him as a sage."},{"k":"gambirananda","t":"The wise call him learned whose actions are all devoid of desires and their thoughts, and whose actions have been burned away by the fire of wisdom."},{"k":"sankaranarayan","t":"He whose every exertion is devoid of intention for desirable objects, and whose actions are burnt up by the fire of wisdom—the wise call such a person a man of learning."}]},{"ch":4,"vn":20,"dev":"त्यक्त्वा कर्मफलासङ्गं नित्यतृप्तो निराश्रयः।\nकर्मण्यभिप्रवृत्तोऽपि नैव किञ्चित्करोति सः","iast":"tyaktvā karma-phalāsaṅgaṁ nitya-tṛipto nirāśhrayaḥ\nkarmaṇyabhipravṛitto 'pi naiva kiñchit karoti saḥ","v":[{"k":"purohit","t":"Having surrendered all claim to the results of his actions, he is always contented and independent; in reality, he does nothing, even though he appears to be acting."},{"k":"sivananda","t":"Having abandoned attachment to the fruits of the action, ever content, depending on nothing, he does not do anything even while being engaged in activity."},{"k":"adidevananda","t":"Having renounced attachment to the fruits of their actions, ever contented with the eternal self, and dependent on none, one does not act at all, even while being engaged in action."},{"k":"gambirananda","t":"Having given up attachment to the results of action, he who is ever-content, dependent on nothing, does not really do anything even though he is engaged in action."},{"k":"sankaranarayan","t":"By abandoning attachment to the fruits of actions, remaining ever content and depending on nothing, that person, even though they are engaged in action, does not perform anything at all."}]},{"ch":4,"vn":21,"dev":"निराशीर्यतचित्तात्मा त्यक्तसर्वपरिग्रहः।\nशारीरं केवलं कर्म कुर्वन्नाप्नोति किल्बिषम्","iast":"nirāśhīr yata-chittātmā tyakta-sarva-parigrahaḥ\nśhārīraṁ kevalaṁ karma kurvan nāpnoti kilbiṣham","v":[{"k":"purohit","t":"Expecting nothing, his mind and personality controlled, without greed, doing only bodily actions; though he acts, he remains untainted."},{"k":"sivananda","t":"Without hope, controlling the mind and the self, having abandoned all covetousness, and performing only bodily actions, one incurs no sin."},{"k":"adidevananda","t":"Free from desire, his intellect and mind controlled, having given up all possessions, and doing bodily work only, he is not subject to evil."},{"k":"gambirananda","t":"One who is without solicitation, who has the mind and senses under control, and is totally without possessions, incurs no sin by performing actions merely for the maintenance of the body."},{"k":"sankaranarayan","t":"Having rid of cravings, controlling the mind and body, abandoning all sense of possession, and performing actions with the body alone, one does not incur any sin."}]},{"ch":4,"vn":22,"dev":"यदृच्छालाभसन्तुष्टो द्वन्द्वातीतो विमत्सरः।\nसमः सिद्धावसिद्धौ च कृत्वापि न निबध्यते","iast":"yadṛichchhā-lābha-santuṣhṭo dvandvātīto vimatsaraḥ\nsamaḥ siddhāvasiddhau cha kṛitvāpi na nibadhyate","v":[{"k":"purohit","t":"Content with what comes to him without any effort of his own, rising above the pairs of opposites, free from envy, his mind balanced in both success and failure; though he acts, the consequences do not bind him."},{"k":"sivananda","t":"Content with what comes to him without effort, free from the pairs of opposites and envy, even-minded in success and failure, he acts yet is not bound."},{"k":"adidevananda","t":"Content with what chance may bring, rising above the pairs of opposites, free from ill-will, even-minded in success and failure, he acts, yet is not bound."},{"k":"gambirananda","t":"Remaining satisfied with what comes unasked for, having transcended the dualities, being free from spite, and balanced under success and failure, he is not bound even by performing actions."},{"k":"sankaranarayan","t":"Remaining content with the gain brought by chance, transcending the dualities (pairs of opposites), entertaining no jealousy, and remaining equal in success and in failure, he does not get bound, even when he acts."}]},{"ch":4,"vn":23,"dev":"गतसङ्गस्य मुक्तस्य ज्ञानावस्थितचेतसः।\nयज्ञायाचरतः कर्म समग्रं प्रविलीयते","iast":"gata-saṅgasya muktasya jñānāvasthita-chetasaḥ\nyajñāyācharataḥ karma samagraṁ pravilīyate","v":[{"k":"purohit","t":"He who is without attachment, free, his mind centered in wisdom, and his actions done as a sacrifice, leave no trace behind."},{"k":"sivananda","t":"To one who is devoid of attachment, who is liberated, whose mind is established in knowledge, and who works for the sake of sacrifice (for the sake of God), the whole action is dissolved."},{"k":"adidevananda","t":"One whose attachments have been relinquished, who is liberated, whose mind is established in knowledge, and who works only for sacrifices—their Karma is entirely dissolved."},{"k":"gambirananda","t":"The liberated person, who has rid themselves of attachment and whose mind is fixed in knowledge, has their actions undertaken for a sacrifice completely destroyed."},{"k":"sankaranarayan","t":"The action is completely dissolved in the case of the person who undertakes it for the sake of sacrifice; who is free from attachment and has been liberated; and whose mind is fixed in wisdom."}]},{"ch":4,"vn":24,"dev":"ब्रह्मार्पणं ब्रह्महविर्ब्रह्माग्नौ ब्रह्मणा हुतम्।\nब्रह्मैव तेन गन्तव्यं ब्रह्मकर्मसमाधिना","iast":"brahmārpaṇaṁ brahma havir brahmāgnau brahmaṇā hutam\nbrahmaiva tena gantavyaṁ brahma-karma-samādhinā","v":[{"k":"purohit","t":"For him, the sacrifice is the Spirit; the Spirit and the offering are one; it is the Spirit that is sacrificed in its own fire, and the man, even in action, is united with God, since his mind never ceases to be fixed on Him while performing the act."},{"k":"sivananda","t":"Brahman is the oblation; Brahman is the melted butter (ghee); by Brahman is the oblation poured into the fire of Brahman; Brahman indeed shall be attained by one who always sees Brahman in action."},{"k":"adidevananda","t":"Brahman is the instrument with which to offer; Brahman is the oblation. By Brahman is the oblation offered into the fire of Brahman; Brahman alone is to be attained by one who meditates on Him in their works."},{"k":"gambirananda","t":"The ladle is Brahman, the oblations are Brahman, and the offering is poured by Brahman into the fire of Brahman. He who has concentration on Brahman as the objective can only reach Brahman."},{"k":"sankaranarayan","t":"The Brahman-oblation that is to be offered to the Brahman is poured into the Brahman-fire by the Brahman; it is nothing but the Brahman that is to be attained by one whose deep contemplation is the Brahman-action."}]},{"ch":4,"vn":25,"dev":"दैवमेवापरे यज्ञं योगिनः पर्युपासते।\nब्रह्माग्नावपरे यज्ञं यज्ञेनैवोपजुह्वति","iast":"daivam evāpare yajñaṁ yoginaḥ paryupāsate\nbrahmāgnāvapare yajñaṁ yajñenaivopajuhvati","v":[{"k":"purohit","t":"Some sages sacrifice to the powers, while others offer themselves on the altar of the eternal."},{"k":"sivananda","t":"Some yogis perform sacrifice to the gods alone; while others, who have realized the Self, offer the Self as sacrifice in the fire of Brahman alone."},{"k":"adidevananda","t":"Some yogis resort only to the sacrifice relating to gods; others offer sacrifice into the fire of Brahman solely through sacrifice."},{"k":"gambirananda","t":"Other yogis undertake sacrifice to gods alone, while others offer the Self as a sacrifice by themselves, in the fire of Brahman."},{"k":"sankaranarayan","t":"Certain other men of Yoga are completely devoted to yajna, connected with the devas, and offer that yajna, simply as a yajna, into the insatiable fire of the Brahman."}]},{"ch":4,"vn":26,"dev":"श्रोत्रादीनीन्द्रियाण्यन्ये संयमाग्निषु जुह्वति।\nशब्दादीन्विषयानन्य इन्द्रियाग्निषु जुह्वति","iast":"śhrotrādīnīndriyāṇyanye sanyamāgniṣhu juhvati\nśhabdādīn viṣhayānanya indriyāgniṣhu juhvati","v":[{"k":"purohit","t":"Some sacrifice their physical senses in the fire of self-control; others offer up their contact with external objects in the sacrificial fire of their senses."},{"k":"sivananda","t":"Some again offer the organ of hearing and other senses as a sacrifice in the fire of restraint; others offer sound and other objects of the senses as a sacrifice in the fire of the senses."},{"k":"adidevananda","t":"Others offer as oblations hearing and other senses into the fires of restraint. Some others offer as oblations the objects of the senses, such as sound and the rest, into the fires of their senses."},{"k":"gambirananda","t":"Others offer their organs, such as their ears, etc., in the fires of self-control. Others offer the objects, such as sound, etc., in the fires of their organs."},{"k":"sankaranarayan","t":"Others offer their sense-organs such as the sense of hearing and the rest into the fires of restraint; others offer objects such as sound and the rest into the fires of their sense-organs."}]},{"ch":4,"vn":27,"dev":"सर्वाणीन्द्रियकर्माणि प्राणकर्माणि चापरे।\nआत्मसंयमयोगाग्नौ जुह्वति ज्ञानदीपिते","iast":"sarvāṇīndriya-karmāṇi prāṇa-karmāṇi chāpare\nātma-sanyama-yogāgnau juhvati jñāna-dīpite","v":[{"k":"purohit","t":"Others again sacrifice their activities and vitality in the spiritual fire of self-abnegation, kindled by wisdom."},{"k":"sivananda","t":"Others again sacrifice all the functions of the senses and those of the breath (vital energy, or Prana) in the fire of the Yoga of self-restraint, kindled by knowledge."},{"k":"adidevananda","t":"Some again offer as an oblation the functions of the senses and the activity of the vital breaths into the fire of the Yoga of restraint of the mind, kindled by knowledge."},{"k":"gambirananda","t":"Others offer all the activities of the organs and the activities of the vital force into the fire of the yoga of self-control, lit by Knowledge."},{"k":"sankaranarayan","t":"Some others offer all the actions of their sense-organs and the actions of their life-breath into the fire of the Yoga of self-control, ignited by wisdom."}]},{"ch":4,"vn":28,"dev":"द्रव्ययज्ञास्तपोयज्ञा योगयज्ञास्तथापरे।\nस्वाध्यायज्ञानयज्ञाश्च यतयः संशितव्रताः","iast":"dravya-yajñās tapo-yajñā yoga-yajñās tathāpare\nswādhyāya-jñāna-yajñāśh cha yatayaḥ sanśhita-vratāḥ","v":[{"k":"purohit","t":"Others offer as their sacrifice wealth, austerities, and meditation. Monks, wedded to their vows, renounce their scriptural learning and even their spiritual powers."},{"k":"sivananda","t":"Others again offer wealth, austerity, and Yoga as sacrifice, while ascetics of self-restraint and rigid vows offer the study of scriptures and knowledge as sacrifice."},{"k":"adidevananda","t":"Self-controlled and firm of resolve, others perform the sacrifice of material objects or austerities or yoga; while others offer their scriptural study and knowledge."},{"k":"gambirananda","t":"Similarly, others are performers of sacrifices through wealth, through austerity, through yoga, and through study and knowledge; others are ascetics with severe vows."},{"k":"sankaranarayan","t":"These are the performers of sacrifices with material objects, the performers of sacrifices with penance, and the performers of sacrifices with Yoga. Likewise, there are other ascetics with rigid vows whose sacrifices are the svadhyaya-knowledge."}]},{"ch":4,"vn":29,"dev":"अपाने जुह्वति प्राण प्राणेऽपानं तथाऽपरे।\nप्राणापानगती रुद्ध्वा प्राणायामपरायणाः","iast":"apāne juhvati prāṇaṁ prāṇe 'pānaṁ tathāpare\nprāṇāpāna-gatī ruddhvā prāṇāyāma-parāyaṇāḥ\napare niyatāhārāḥ prāṇān prāṇeṣhu juhvati\nsarve 'pyete yajña-vido yajña-kṣhapita-kalmaṣhāḥ","v":[{"k":"purohit","t":"There are some who practice controlling the vital energy and governing the subtle forces of prana and apana, thereby sacrificing their prana to apana, or their apana to prana."},{"k":"sivananda","t":"Others offer as sacrifice the outgoing breath into the incoming, and the incoming into the outgoing, restraining the flow of the outgoing and the incoming breaths, solely absorbed in the restraint of the breath."},{"k":"adidevananda","t":"Others, with restricted diets, are devoted to the control of breath. Some sacrifice the inward breath in the outward breath; similarly, others sacrifice the outward breath in the inward breath. Some others, stopping the flow of both the inward and outward breaths, sacrifice the inward and outward breaths."},{"k":"gambirananda","t":"Constantly practicing control of the vital forces by stopping the movements of the outgoing and incoming breaths, some offer as a sacrifice the outgoing breath into the incoming breath; while still others, the incoming breath into the outgoing breath."},{"k":"sankaranarayan","t":"Some sages offer the prana into the apana; likewise, others offer the apana into the prana. Having controlled both the courses of the prana and apana, the same sages, with their desires fulfilled by the above activities, and with their food restricted, offer the pranas into pranas. All these persons know what sacrifices are and have their sins destroyed by them."}]},{"ch":4,"vn":30,"dev":"अपरे नियताहाराः प्राणान्प्राणेषु जुह्वति।\nसर्वेऽप्येते यज्ञविदो यज्ञक्षपितकल्मषाः","iast":"apare niyatāhārāḥ prāṇān  prāṇeṣu juhvati\nsarve py 'ete yajña-vido yajña-kṣapita-kalmaṣāḥ","v":[{"k":"purohit","t":"Others, controlling their diet, sacrifice their worldly life to the spiritual fire. All understand the principle of sacrifice, and by it their sins are washed away."},{"k":"sivananda","t":"Others who regulate their diet offer life-breaths in each life-breath. All these are knowers of sacrifice, whose sins are destroyed through sacrifice."},{"k":"adidevananda","t":"All these know the meaning of sacrifices, and through sacrifices, their sins are eradicated. Those who subsist on the ambrosial food, the remnants of sacrifices, go to eternal Brahman."},{"k":"gambirananda","t":"Others, having their food regulated, offer the vital forces in the vital forces. All of them are knowers of the sacrifice and have their sins destroyed by the sacrifice."},{"k":"sankaranarayan","t":"- . [Some sages] offer the prana into the apana; likewise, others offer the apana into the prana. Having controlled both the courses of the prana and apana, the same sages, with their desires fulfilled by the above activities, and with their food restricted, offer the pranas into pranas. All these persons know what sacrifices are and have their sins destroyed by them."}]},{"ch":4,"vn":31,"dev":"यज्ञशिष्टामृतभुजो यान्ति ब्रह्म सनातनम्।\nनायं लोकोऽस्त्ययज्ञस्य कुतो़ऽन्यः कुरुसत्तम","iast":"yajña-śhiṣhṭāmṛita-bhujo yānti brahma sanātanam\nnāyaṁ loko 'styayajñasya kuto 'nyaḥ kuru-sattama","v":[{"k":"purohit","t":"Tasting the nectar of immortality, as the reward of sacrifice, they reach the Eternal. This world is not for those who refuse to sacrifice; nor is the other world."},{"k":"sivananda","t":"Those who eat the remnants of the sacrifice, which are like nectar, go to the eternal Brahman. This world is not for the one who does not perform sacrifice; how then can they have the other, O Arjuna?"},{"k":"adidevananda","t":"This world is not for one who makes no sacrifice; how then for the other, O Arjuna?"},{"k":"gambirananda","t":"Those who partake of the nectar left over after a sacrifice reach the eternal Brahman. This world ceases to exist for one who does not perform sacrifices; what, then, to speak of the other world, O best among the Kurus (Arjuna)!"},{"k":"sankaranarayan","t":"The eaters of the sacrifice-ordained nectar attain the eternal Brahman. This world is not for a non-sacrificer; how can there be the other? O best of the Kurus!"}]},{"ch":4,"vn":32,"dev":"एवं बहुविधा यज्ञा वितता ब्रह्मणो मुखे।\nकर्मजान्विद्धि तान्सर्वानेवं ज्ञात्वा विमोक्ष्यसे","iast":"evaṁ bahu-vidhā yajñā vitatā brahmaṇo mukhe\nkarma-jān viddhi tān sarvān evaṁ jñātvā vimokṣhyase","v":[{"k":"purohit","t":"In this way, other sacrifices may also be undertaken for the sake of the Spirit. Know that they all depend on action. Knowing this, you will be free."},{"k":"sivananda","t":"Thus, manifold sacrifices are spread out before Brahman at the face of Brahman. Know them all to be born of action, and thus knowing, you shall be liberated."},{"k":"adidevananda","t":"Thus, many forms of sacrifices have been spread out as means of reaching Brahman (individual self in its own nature). Know that all of these are born of actions. Knowing thus, you will be free."},{"k":"gambirananda","t":"Thus, various kinds of sacrifices are spread at the mouth of the Vedas. Know them all to be born of action. Knowing this, you will become liberated."},{"k":"sankaranarayan","t":"Thus, sacrifices of many varieties have been elaborated upon by the mouth of the Brahman. Know them all as having sprung from actions. By knowing thus, you shall be liberated."}]},{"ch":4,"vn":33,"dev":"श्रेयान्द्रव्यमयाद्यज्ञाज्ज्ञानयज्ञः परन्तप।\nसर्वं कर्माखिलं पार्थ ज्ञाने परिसमाप्यते","iast":"śhreyān dravya-mayād yajñāj jñāna-yajñaḥ parantapa\nsarvaṁ karmākhilaṁ pārtha jñāne parisamāpyate","v":[{"k":"purohit","t":"The sacrifice of wisdom is superior to any material sacrifice, for, O Arjuna, the pinnacle of action is always realization."},{"k":"sivananda","t":"Superior is wisdom-sacrifice to the sacrifice with objects, O Parantapa (scorcher of the foes). All actions in their entirety, O Arjuna, culminate in knowledge."},{"k":"adidevananda","t":"The sacrifice of knowledge is superior to material sacrifice. O Arjuna, all actions and everything else culminate in knowledge."},{"k":"gambirananda","t":"O destroyer of enemies, knowledge considered as a sacrifice is greater than sacrifices requiring materials. O son of Prtha, all actions in their totality culminate in knowledge."},{"k":"sankaranarayan","t":"The sacrifice of knowledge is superior to the sacrifice of material things. O son of Prtha, destroyer of enemies! All actions, leaving nothing behind, come to an end in knowledge."}]},{"ch":4,"vn":34,"dev":"तद्विद्धि प्रणिपातेन परिप्रश्नेन सेवया।\nउपदेक्ष्यन्ति ते ज्ञानं ज्ञानिनस्तत्त्वदर्शिनः","iast":"tad viddhi praṇipātena paripraśhnena sevayā\nupadekṣhyanti te jñānaṁ jñāninas tattva-darśhinaḥ","v":[{"k":"purohit","t":"This you shall learn by prostrating yourself at the master's feet, questioning them, and serving them. The wise who have realized the truth will teach you wisdom."},{"k":"sivananda","t":"Know that the wise who have realized the truth will instruct thee in that knowledge through long prostration, supplication, and service."},{"k":"adidevananda","t":"Know this through prostration, questioning, and service. The wise who have realized the truth will instruct you in knowledge."},{"k":"gambirananda","t":"Know that the wise ones who have realized the Truth will impart the Knowledge to you through prostration, inquiry, and service."},{"k":"sankaranarayan","t":"Learn this from those endowed with knowledge, through prostration, inquiry, and service offered to them. Those who are endowed with knowledge and are capable of showing the truth will give you the truth nearby."}]},{"ch":4,"vn":35,"dev":"यज्ज्ञात्वा न पुनर्मोहमेवं यास्यसि पाण्डव।\nयेन भूतान्यशेषेण द्रक्ष्यस्यात्मन्यथो मयि","iast":"yaj jñātvā na punar moham evaṁ yāsyasi pāṇḍava\nyena bhūtānyaśheṣheṇa drakṣhyasyātmanyatho mayi","v":[{"k":"purohit","t":"Having known That, you shall never again be confounded; and, O Arjuna, by the power of that wisdom, you shall see all these people as if they were your own Self, and therefore as Me."},{"k":"sivananda","t":"Knowing that thou shalt not, O Arjuna, again be deluded like this; and by that thou shalt see all beings in thyself and also in me."},{"k":"adidevananda","t":"Knowing this, O Arjuna, you will not fall again into delusion in this way—by that knowledge, you will see all beings without exception in yourself and then in Me."},{"k":"gambirananda","t":"Knowing this, O Pandava, you will not be deluded again in this way, and through it, you will see all beings, without exception, in the Self and also in Me."},{"k":"sankaranarayan","t":"By knowing this, you will not be deluded again, O son of Pandu; and by this means, you will see all beings without exception in yourself, that is, in Me."}]},{"ch":4,"vn":36,"dev":"अपि चेदसि पापेभ्यः सर्वेभ्यः पापकृत्तमः।\nसर्वं ज्ञानप्लवेनैव वृजिनं सन्तरिष्यसि","iast":"api ched asi pāpebhyaḥ sarvebhyaḥ pāpa-kṛit-tamaḥ\nsarvaṁ jñāna-plavenaiva vṛijinaṁ santariṣhyasi","v":[{"k":"purohit","t":"Even if you are the greatest of sinners, you will cross over all sin by the ferryboat of wisdom."},{"k":"sivananda","t":"Even if thou art the most sinful of all sinners, yet thou shalt surely cross over all sins by the raft of knowledge."},{"k":"adidevananda","t":"Even if you are the most sinful of all sinners, you can cross over all sins by the boat of knowledge alone."},{"k":"gambirananda","t":"Even if you are the worst sinner among all sinners, you can still cross over all wickedness with the raft of Knowledge alone."},{"k":"sankaranarayan","t":"Even if you are the highest sinner among all sinners, you can cross over the ocean of all sins by the boat of knowledge."}]},{"ch":4,"vn":37,"dev":"यथैधांसि समिद्धोऽग्निर्भस्मसात्कुरुतेऽर्जुन।\nज्ञानाग्निः सर्वकर्माणि भस्मसात्कुरुते तथा","iast":"yathaidhānsi samiddho 'gnir bhasma-sāt kurute 'rjuna\njñānāgniḥ sarva-karmāṇi bhasma-sāt kurute tathā","v":[{"k":"purohit","t":"As the kindled fire consumes the fuel, so, O Arjuna, the embers of action are burnt to ashes in the flame of wisdom."},{"k":"sivananda","t":"As the blazing fire reduces fuel to ashes, O Arjuna, so does the fire of knowledge reduce all actions to ash."},{"k":"adidevananda","t":"Just as a burning fire turns fuel to ashes, O Arjuna, so does the fire of knowledge turn all karmas to ashes."},{"k":"gambirananda","t":"O Arjuna, just as a blazing fire reduces wood to ashes, similarly the fire of Knowledge reduces all actions to ashes."},{"k":"sankaranarayan","t":"Just as a fire that is well-inflamed reduces fuel to ashes, so too does the fire of knowledge reduce all actions to ashes."}]},{"ch":4,"vn":38,"dev":"न हि ज्ञानेन सदृशं पवित्रमिह विद्यते।\nतत्स्वयं योगसंसिद्धः कालेनात्मनि विन्दति","iast":"na hi jñānena sadṛiśhaṁ pavitramiha vidyate\ntatsvayaṁ yogasansiddhaḥ kālenātmani vindati","v":[{"k":"purohit","t":"There is nothing in the world so purifying as wisdom; and he who is a perfect saint finds that at last within himself."},{"k":"sivananda","t":"Verily, there is no purifier in this world like knowledge. He who is perfected in Yoga finds it within the Self in due time."},{"k":"adidevananda","t":"For there is no purifier equal to knowledge; he who is perfected in Karma Yoga finds this knowledge of his own accord in himself in due time."},{"k":"gambirananda","t":"Indeed, there is nothing purifying here comparable to Knowledge. One who has become perfected over time through yoga, realizes That in their own heart."},{"k":"sankaranarayan","t":"In this world, there exists no purifier comparable to knowledge. One who becomes perfect in Yoga finds this, of their own accord, in their Self in due course."}]},{"ch":4,"vn":39,"dev":"श्रद्धावाँल्लभते ज्ञानं तत्परः संयतेन्द्रियः।\nज्ञानं लब्ध्वा परां शान्तिमचिरेणाधिगच्छति","iast":"śhraddhāvān labhate jñānaṁ tat-paraḥ sanyatendriyaḥ\njñānaṁ labdhvā parāṁ śhāntim achireṇādhigachchhati","v":[{"k":"purohit","t":"He who is full of faith attains wisdom, and he who can control his senses, having attained that wisdom, will soon attain Supreme Peace."},{"k":"sivananda","t":"The one who is full of faith, devoted to it, and has subdued their senses obtains this knowledge; and upon obtaining the knowledge, they attain the supreme peace immediately."},{"k":"adidevananda","t":"He who has faith, is intent on it, and has mastered his senses, attains knowledge. Having attained knowledge, he quickly goes to supreme peace."},{"k":"gambirananda","t":"The one who has faith, is diligent, and has control over their organs, attains Knowledge. Achieving Knowledge, one soon attains supreme Peace."},{"k":"sankaranarayan","t":"He who has faith gains knowledge, if he is solely intent upon it and has his sense-organs well-controlled. Having gained the knowledge, he soon attains the Supreme Peace."}]},{"ch":4,"vn":40,"dev":"अज्ञश्चाश्रद्दधानश्च संशयात्मा विनश्यति।\nनायं लोकोऽस्ति न परो न सुखं संशयात्मनः","iast":"ajñaśh chāśhraddadhānaśh cha sanśhayātmā vinaśhyati\nnāyaṁ loko 'sti na paro na sukhaṁ sanśhayātmanaḥ","v":[{"k":"purohit","t":"But the ignorant man, and he who has no faith, and the skeptic are lost. Neither in this world nor elsewhere is there any happiness in store for him who always doubts."},{"k":"sivananda","t":"The ignorant, the faithless, and the doubting self go to destruction; there is neither this world nor the other, nor happiness for the doubting one."},{"k":"adidevananda","t":"The ignorant, the faithless, and the doubting one perish; for the doubting one, there is neither this world nor the one beyond, nor happiness."},{"k":"gambirananda","t":"One who is ignorant and faithless, and has a doubting mind, perishes. Neither this world nor the next, nor happiness, exists for one who has a doubting mind."},{"k":"sankaranarayan","t":"But he who is ignorant and has no faith, perishes, with his mind full of doubts. Neither this world nor the other, nor happiness is for a person who is by nature full of doubts."}]},{"ch":4,"vn":41,"dev":"योगसंन्यस्तकर्माणं ज्ञानसंछिन्नसंशयम्।\nआत्मवन्तं न कर्माणि निबध्नन्ति धनञ्जय","iast":"yoga-sannyasta-karmāṇaṁ jñāna-sañchhinna-sanśhayam\nātmavantaṁ na karmāṇi nibadhnanti dhanañjaya","v":[{"k":"purohit","t":"But the one who has renounced their actions for meditation, who has cleaved their doubts in two by the sword of wisdom, and who remains always enthroned in their Self, is not bound by their actions."},{"k":"sivananda","t":"He who has renounced actions through Yoga, whose doubts have been dispelled by knowledge, and who is self-possessed—such a one is not bound by actions, O Arjuna."},{"k":"adidevananda","t":"Actions do not bind him, O Arjuna, who has renounced them through Karma Yoga and whose doubts have been dispelled by knowledge, and who thus possesses a steady mind."},{"k":"gambirananda","t":"O Dhananjaya (Arjuna), actions do not bind one who has renounced actions through yoga, whose doubts have been fully dispelled by Knowledge, and who is not inattentive."},{"k":"sankaranarayan","t":"O Dhananjaya! Actions do not bind him who has renounced all actions through Yoga; who has cut off his doubts by the sword of knowledge; and who is a master of his own self."}]},{"ch":4,"vn":42,"dev":"तस्मादज्ञानसंभूतं हृत्स्थं ज्ञानासिनाऽऽत्मनः।\nछित्त्वैनं संशयं योगमातिष्ठोत्तिष्ठ भारत","iast":"tasmād ajñāna-sambhūtaṁ hṛit-sthaṁ jñānāsinātmanaḥ\nchhittvainaṁ sanśhayaṁ yogam ātiṣhṭhottiṣhṭha bhārata","v":[{"k":"purohit","t":"Therefore, cleave asunder with the sword of wisdom the doubts of the heart, which your own ignorance has engendered, and follow the path of wisdom and arise!"},{"k":"sivananda","t":"Therefore, with the sword of knowledge (of the Self), cut asunder the doubt of the self, born of ignorance, residing in your heart, and take refuge in Yoga. Arise, O Arjuna!"},{"k":"adidevananda","t":"Therefore, sever, with the sword of knowledge, this doubt present in your heart resulting from ignorance concerning the Self. Practice this Yoga, O Arjuna, and arise."},{"k":"gambirananda","t":"Therefore, O scion of the Bharata dynasty, take recourse to yoga and rise up, cutting asunder with the sword of knowledge this doubt in your heart, arising from ignorance."},{"k":"sankaranarayan","t":"Therefore, thus cutting off, by means of the sword of knowledge, the doubt that has sprung from ignorance and exists in your heart, practice the Yoga! Stand up, O descendant of Bharata!"}]},{"ch":5,"vn":1,"dev":"अर्जुन उवाच\nसंन्यासं कर्मणां कृष्ण पुनर्योगं च शंससि।\nयच्छ्रेय एतयोरेकं तन्मे ब्रूहि सुनिश्िचतम्","iast":"arjuna uvācha\nsannyāsaṁ karmaṇāṁ kṛiṣhṇa punar yogaṁ cha śhansasi\nyach chhreya etayor ekaṁ tan me brūhi su-niśhchitam","v":[{"k":"purohit","t":"Arjuna said: My Lord! At one moment, You praise renunciation of action; at another, You praise right action. Tell me truly, I pray, which of these is more conducive to my highest welfare?"},{"k":"sivananda","t":"Arjuna said, \"O Krishna, you praise renunciation of actions and also yoga. Please tell me conclusively which is better of the two.\""},{"k":"adidevananda","t":"Arjuna said, \"O Krsna, you praise the renunciation of actions, and then you also praise Karma Yoga. Please tell me with certainty which of these is the superior one, leading to the ultimate good."},{"k":"gambirananda","t":"Arjuna said, \"O Krsna, you praise renunciation of actions and, at the same time, Karma-yoga. Please tell me for certain which one is better between these two.\""},{"k":"sankaranarayan","t":"Arjuna said, \"O Krsna, you commend both renunciation of action and the Yoga of action; which one of these two is superior?\" Please tell me that for certain."}]},{"ch":5,"vn":2,"dev":"श्री भगवानुवाच\nसंन्यासः कर्मयोगश्च निःश्रेयसकरावुभौ।\nतयोस्तु कर्मसंन्यासात्कर्मयोगो विशिष्यते","iast":"śhrī bhagavān uvācha\nsannyāsaḥ karma-yogaśh cha niḥśhreyasa-karāvubhau\ntayos tu karma-sannyāsāt karma-yogo viśhiṣhyate","v":[{"k":"purohit","t":"Lord Shri Krishna replied: Both renunciation of action and the path of right action lead to the highest; however, right action is the better of the two."},{"k":"sivananda","t":"The Blessed Lord said, \"Renunciation and the Yoga of action both lead to the highest bliss; but of the two, the Yoga of action is superior to the renunciation of action.\""},{"k":"adidevananda","t":"The Lord said, \"Renunciation of actions and Karma Yoga both lead to the highest excellence; however, of the two, Karma Yoga surpasses renunciation of actions.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"Both renunciation of actions and Karma-yoga lead to liberation; however, Karma-yoga excels over renunciation of actions.\""},{"k":"sankaranarayan","t":"The Bhagavat said, \"Both renunciation and the Yoga of action effect salvation; however, of these two, the Yoga of action is superior to renunciation of action.\""}]},{"ch":5,"vn":3,"dev":"ज्ञेयः स नित्यसंन्यासी यो न द्वेष्टि न काङ्क्षति।\nनिर्द्वन्द्वो हि महाबाहो सुखं बन्धात्प्रमुच्यते","iast":"jñeyaḥ sa nitya-sannyāsī yo na dveṣhṭi na kāṅkṣhati\nnirdvandvo hi mahā-bāho sukhaṁ bandhāt pramuchyate","v":[{"k":"purohit","t":"He is a true ascetic who never desires nor dislikes, who is unaffected by the opposites and is easily freed from bondage."},{"k":"sivananda","t":"He should be known as a perpetual Sannyasi who neither hates nor desires; for, free from the pairs of opposites, O mighty-armed Arjuna, he is easily freed from bondage."},{"k":"adidevananda","t":"He who neither hates nor desires, and is beyond the pairs of opposites, is to be understood as an ever-renouncer. Therefore, he is easily set free from bondage, O Arjuna."},{"k":"gambirananda","t":"He who neither hates nor craves should be known as a man of constant renunciation."},{"k":"sankaranarayan","t":"That person may be considered a man of permanent renunciation, who neither hates nor desires. For, O mighty-armed one! He who is free from the pairs of opposites is easily released from bondage of action."}]},{"ch":5,"vn":4,"dev":"सांख्ययोगौ पृथग्बालाः प्रवदन्ति न पण्डिताः।\nएकमप्यास्थितः सम्यगुभयोर्विन्दते फलम्","iast":"sānkhya-yogau pṛithag bālāḥ pravadanti na paṇḍitāḥ\nekamapyāsthitaḥ samyag ubhayor vindate phalam","v":[{"k":"purohit","t":"Only the unenlightened speak of wisdom and right action as separate; the wise do not. If anyone knows one, they enjoy the fruit of both."},{"k":"sivananda","t":"Children, not the wise, speak of knowledge and the Yoga of action, or the performance of action, as though they are distinct and different; he who is truly established in one, obtains the fruits of both."},{"k":"adidevananda","t":"Children, not the learned, speak of Sankhya and Yoga as distinct; however, he who is firmly set in one, attains the fruit of both."},{"k":"gambirananda","t":"The fools, not the learned ones, speak of Sankhya and (Karma-) yoga as being different. Anyone who properly resorts to either one of them gets the results of both."},{"k":"sankaranarayan","t":"The childish, and not the wise, proclaim the paths of knowledge and Yoga to be different. He who has properly resorted to even one of these two, gets the fruit of both."}]},{"ch":5,"vn":5,"dev":"यत्सांख्यैः प्राप्यते स्थानं तद्योगैरपि गम्यते।\nएकं सांख्यं च योगं च यः पश्यति स पश्यति","iast":"yat sānkhyaiḥ prāpyate sthānaṁ tad yogair api gamyate\nekaṁ sānkhyaṁ cha yogaṁ cha yaḥ paśhyati sa paśhyati","v":[{"k":"purohit","t":"The level which is attained through wisdom is also reached through right action. He who perceives that the two are one, knows the truth."},{"k":"sivananda","t":"That place which is reached by the Sankhyas or the Jnanis is also reached by the Yogis (Karma Yogis). He who sees knowledge and the performance of action (Karma Yoga) as one, sees truly."},{"k":"adidevananda","t":"That state which is reached by the Sankhyans, the same is also attained by the Yogins; that is, the same state is achieved by those who are Karma Yogins. He alone is wise who perceives that the Sankhya and the Yoga are one and the same, due to their having the same result."},{"k":"gambirananda","t":"The state that is reached by the Sankhyas, and that is also reached by the yogis, is seen by one who sees Sankhya and yoga as one."},{"k":"sankaranarayan","t":"Those who are knowledgeable reach the same state as those who practice Yoga; so whoever sees the knowledge-path and the Yoga as one, sees correctly."}]},{"ch":5,"vn":6,"dev":"संन्यासस्तु महाबाहो दुःखमाप्तुमयोगतः।\nयोगयुक्तो मुनिर्ब्रह्म नचिरेणाधिगच्छति","iast":"sannyāsas tu mahā-bāho duḥkham āptum ayogataḥ\nyoga-yukto munir brahma na chireṇādhigachchhati","v":[{"k":"purohit","t":"Without concentration, O Mighty One, renunciation is difficult. But the sage who is always meditating on the Divine, shall soon attain the Absolute."},{"k":"sivananda","t":"But, O mighty-armed Arjuna, renunciation is hard to attain without Yoga; the sage who is in harmony with Yoga quickly goes to Brahman."},{"k":"adidevananda","t":"But, O mighty-armed one, renunciation is hard to attain without practicing Yoga. The sage who contemplates and follows Yoga soon reaches the Brahman (the self or Atman)."},{"k":"gambirananda","t":"But, O mighty-armed one, renunciation is hard to attain without (Karma-) yoga. The meditative man equipped with yoga attains Brahman without delay."},{"k":"sankaranarayan","t":"O mighty-armed Arjuna! Renunciation is indeed hard to attain, except through Yoga; the sage who is the master of Yoga quickly attains the Brahman."}]},{"ch":5,"vn":7,"dev":"योगयुक्तो विशुद्धात्मा विजितात्मा जितेन्द्रियः।\nसर्वभूतात्मभूतात्मा कुर्वन्नपि न लिप्यते","iast":"yoga-yukto viśhuddhātmā vijitātmā jitendriyaḥ\nsarva-bhūtātma-bhūtātmā kurvann api na lipyate","v":[{"k":"purohit","t":"He who is spiritual, pure, has overcome his senses and his personal self, and has realized his highest Self as the Self of all—even though he acts, he is not bound by his actions."},{"k":"sivananda","t":"He who is devoted to the path of action, whose mind is pure, who has conquered the self, who has subdued his senses, and who realizes his Self as the Self in all beings, though acting, is not tainted."},{"k":"adidevananda","t":"He who follows the Yoga and is pure in mind, who has subdued his self and has conquered his senses, and whose self has become the self of all beings, even while he is acting, remains untainted."},{"k":"gambirananda","t":"Endowed with yoga, pure in mind, controlled in body, a conqueror of the organs, the Self of the selves of all beings—he does not become tainted even while performing actions. When this person resorts to nitya and naimittika rites and duties as a means to the achievement of full illumination, and thus becomes fully enlightened, then, even when he acts through the apparent functions of the mind, organs, etc., he does not become affected."},{"k":"sankaranarayan","t":"A master of yoga, whose self (mind and intellect) is very pure, the sense-organs are controlled, and the soul is realized to be the soul of all beings—he is not stained, even though he is a performer of actions."}]},{"ch":5,"vn":8,"dev":"नैव किंचित्करोमीति युक्तो मन्येत तत्त्ववित्।\nपश्यन् श्रृणवन्स्पृशञ्जिघ्रन्नश्नन्गच्छन्स्वपन् श्वसन्","iast":"naiva kiñchit karomīti yukto manyeta tattva-vit\npaśhyañ śhṛiṇvan spṛiśhañjighrann aśhnangachchhan svapañśhvasan\npralapan visṛijan gṛihṇann unmiṣhan nimiṣhann api\nindriyāṇīndriyārtheṣhu vartanta iti dhārayan","v":[{"k":"purohit","t":"Though the saint sees, hears, touches, smells, eats, moves, sleeps, and breathes, yet he knows the truth and knows that it is not he who acts."},{"k":"sivananda","t":"I do nothing at all,\" thus would the harmonized knower of Truth think, seeing, hearing, touching, smelling, eating, going, sleeping, and breathing."},{"k":"adidevananda","t":"The one who knows the truth and is devoted to yoga should think, \"I am not doing anything,\" even though they are seeing, hearing, touching, smelling, eating, moving, sleeping, and breathing."},{"k":"gambirananda","t":"- Remaining absorbed in the Self, the knower of Reality should think, 'I certainly do not do anything', even while seeing, hearing, touching, smelling, eating, moving, sleeping, breathing, speaking, releasing, holding, opening, and closing the eyes—remembering that the organs function in relation to the objects of the organs."},{"k":"sankaranarayan","t":"A master of Yoga, knowing the reality, would think, 'I do not perform any action at all.' For, he who, while seeing, hearing, touching, smelling, eating, going, sleeping, and breathing;"}]},{"ch":5,"vn":9,"dev":"प्रलपन्विसृजन्गृह्णन्नुन्मिषन्निमिषन्नपि।\nइन्द्रियाणीन्द्रियार्थेषु वर्तन्त इति धारयन्","iast":"pralapan visṛjan gṛhṇann unmiṣan nimiṣann api indriyāṇīndriyārtheṣu vartanta iti dhārayan","v":[{"k":"purohit","t":"Though he talks, gives, receives, opens his eyes, and shuts them, he still knows that his senses are merely disporting themselves among the objects of perception."},{"k":"sivananda","t":"Speaking, letting go, seizing, opening, and closing the eyes, one should be convinced that the senses move among the sense-objects."},{"k":"adidevananda","t":"Speaking, discharging, grasping, opening, and closing his eyes, etc., he should always bear in mind that the senses operate among sense-objects."},{"k":"gambirananda","t":"- Remaining absorbed in the Self, the knower of Reality should think, 'I certainly do not do anything', even while seeing, hearing, touching, smelling, eating, moving, sleeping, breathing, speaking, releasing, holding, opening, and closing the eyes—remembering that the organs function in relation to the objects of the organs."},{"k":"sankaranarayan","t":"Taking, rejecting, receiving, opening, and closing the eyes, bear in mind that the sense-organs are on their respective objects; and"}]},{"ch":5,"vn":10,"dev":"ब्रह्मण्याधाय कर्माणि सङ्गं त्यक्त्वा करोति यः।\nलिप्यते न स पापेन पद्मपत्रमिवाम्भसा","iast":"brahmaṇyādhāya karmāṇi saṅgaṁ tyaktvā karoti yaḥ\nlipyate na sa pāpena padma-patram ivāmbhasā","v":[{"k":"purohit","t":"He who dedicates his actions to the Spirit, without any personal attachment to them, is no more tainted by sin than the water lily is wetted by water."},{"k":"sivananda","t":"He who does actions, offering them to Brahman and abandoning attachment, is not tainted by sin, just as a lotus leaf is not tainted by water."},{"k":"adidevananda","t":"He who acts without attachment, reposing all actions on Brahman (Prakṛti), is untouched by evil, just as a lotus leaf is untouched by water."},{"k":"gambirananda","t":"One who acts by dedicating their actions to Brahman and by renouncing attachment, they do not become polluted by sin, just as a lotus leaf is not by water."},{"k":"sankaranarayan","t":"Who performs actions by offering them to the Brahman and giving up attachment—they are not stained by sin, just as a lotus leaf is not stained by water."}]},{"ch":5,"vn":11,"dev":"कायेन मनसा बुद्ध्या केवलैरिन्द्रियैरपि।\nयोगिनः कर्म कुर्वन्ति सङ्गं त्यक्त्वाऽऽत्मशुद्धये","iast":"kāyena manasā buddhyā kevalair indriyair api\nyoginaḥ karma kurvanti saṅgaṁ tyaktvātma-śhuddhaye","v":[{"k":"purohit","t":"The sage performs his action dispassionately, using his body, mind, intellect, and even his senses, always as a means for purification."},{"k":"sivananda","t":"Yogis, having abandoned attachment, perform actions only through the body, mind, intellect, and even the senses, for the purification of the self."},{"k":"adidevananda","t":"Yogins, renouncing attachment, do actions with merely the body, mind, intellect, and senses, for the purification of the self."},{"k":"gambirananda","t":"By giving up attachment, the yogis undertake work solely through the body, mind, intellect, and even the organs, for their own purification."},{"k":"sankaranarayan","t":"Having given up attachment, the men of Yoga perform action just with the body, with the mind, with intellect, and also with their sense-organs, for attaining the Self."}]},{"ch":5,"vn":12,"dev":"युक्तः कर्मफलं त्यक्त्वा शान्तिमाप्नोति नैष्ठिकीम्।\nअयुक्तः कामकारेण फले सक्तो निबध्यते","iast":"yuktaḥ karma-phalaṁ tyaktvā śhāntim āpnoti naiṣhṭhikīm\nayuktaḥ kāma-kāreṇa phale sakto nibadhyate","v":[{"k":"purohit","t":"Having abandoned the fruit of action, he wins eternal peace. Others, unacquainted with spirituality, led by desire and clinging to the benefit they think will follow their actions, become entangled in them."},{"k":"sivananda","t":"The one who is united (the well-poised or harmonized) having abandoned the fruit of action attains eternal peace; whereas the one who is not united (the unsteady or unbalanced), impelled by desire and attached to the fruit, is bound."},{"k":"adidevananda","t":"A yogi, renouncing the fruits of their actions, attains lasting peace. But the unsteady person who is attached to the fruits of their actions, being driven by desire, is bound."},{"k":"gambirananda","t":"Giving up the results of work by becoming resolute in faith, one attains peace arising from steadfastness. One who is lacking in resolute faith, being attached to the results under the impulse of desire, becomes bound."},{"k":"sankaranarayan","t":"Having abandoned attachment to the fruit of actions, the master of Yoga attains the highest Peace. But, one who is not a master of Yoga and is attached to the fruit of action, is bound by their actions born of desire."}]},{"ch":5,"vn":13,"dev":"सर्वकर्माणि मनसा संन्यस्यास्ते सुखं वशी।\nनवद्वारे पुरे देही नैव कुर्वन्न कारयन्","iast":"sarva-karmāṇi manasā sannyasyāste sukhaṁ vaśhī\nnava-dvāre pure dehī naiva kurvan na kārayan","v":[{"k":"purohit","t":"Mentally renouncing all actions, the self-controlled soul enjoys bliss in this body, the city of the nine gates, neither doing anything themselves nor causing anything to be done."},{"k":"sivananda","t":"Mentally renouncing all actions and being self-controlled, the embodied one happily rests in the nine-gated city, neither acting nor causing others (body and senses) to act."},{"k":"adidevananda","t":"The embodied self, mentally resigning all actions as belonging to the city of nine gates (i.e., the body) and becoming self-controlled, dwells happily, neither acting himself nor causing the body to act."},{"k":"gambirananda","t":"The embodied man of self-control, having given up all actions mentally, continues happily in the city of nine gates, without doing or causing anyone else to do anything."},{"k":"sankaranarayan","t":"Having renounced all actions by mind, a man of self-control dwells happily in his body, a nine-windowed mansion, neither performing nor causing others to perform any actions."}]},{"ch":5,"vn":14,"dev":"न कर्तृत्वं न कर्माणि लोकस्य सृजति प्रभुः।\nन कर्मफलसंयोगं स्वभावस्तु प्रवर्तते","iast":"na kartṛitvaṁ na karmāṇi lokasya sṛijati prabhuḥ\nna karma-phala-saṅyogaṁ svabhāvas tu pravartate","v":[{"k":"purohit","t":"The Lord of this universe has not ordained activity, nor any incentive thereto, nor any relation between an act and its consequences; all this is the work of Nature."},{"k":"sivananda","t":"Neither does the Lord create agency nor actions for the world, nor union with the fruits of actions; rather, it is Nature that acts."},{"k":"adidevananda","t":"The Lord of the body (the Self, i.e., the Jiva) does not create agency, nor actions, nor union with the fruits of actions in relation to the world of selves; only the inherent tendencies function."},{"k":"gambirananda","t":"The Self does not create agency or any objects of desire for anyone, nor does it associate with the results of actions; rather, it is Nature that acts."},{"k":"sankaranarayan","t":"The Lord (Self) acquires neither the state of being a creator of the world, nor the actions, nor the connection with the fruits of their actions. But it is the inherent nature [in It] that exerts."}]},{"ch":5,"vn":15,"dev":"नादत्ते कस्यचित्पापं न चैव सुकृतं विभुः।\nअज्ञानेनावृतं ज्ञानं तेन मुह्यन्ति जन्तवः","iast":"nādatte kasyachit pāpaṁ na chaiva sukṛitaṁ vibhuḥ\najñānenāvṛitaṁ jñānaṁ tena muhyanti jantavaḥ","v":[{"k":"purohit","t":"The Lord does not accept responsibility for any person's sin or merit; they are deluded, for wisdom is submerged in ignorance within them."},{"k":"sivananda","t":"The Lord takes neither the demerit nor the merit of any; knowledge is enveloped by ignorance, and beings are deluded."},{"k":"adidevananda","t":"The all-pervasive One takes away neither the sin nor the merit of anyone. Knowledge is enveloped by ignorance, and creatures are thereby deluded."},{"k":"gambirananda","t":"The Omnipresent neither accepts anyone's sin nor even virtue; knowledge remains covered by ignorance, thus the creatures become deluded."},{"k":"sankaranarayan","t":"The Omnimanifest Soul takes neither sin nor merit born of any action upon itself. But, perfect knowledge is clouded by Illusion, and thus the creatures are deluded."}]},{"ch":5,"vn":16,"dev":"ज्ञानेन तु तदज्ञानं येषां नाशितमात्मनः।\nतेषामादित्यवज्ज्ञानं प्रकाशयति तत्परम्","iast":"jñānena tu tad ajñānaṁ yeṣhāṁ nāśhitam ātmanaḥ\nteṣhām āditya-vaj jñānaṁ prakāśhayati tat param","v":[{"k":"purohit","t":"Surely, wisdom is like the sun, revealing the supreme truth to those whose ignorance has been dispelled by the wisdom of the Self."},{"k":"sivananda","t":"But to those whose ignorance is destroyed by knowledge of the Self, like the sun, knowledge reveals the Supreme Brahman."},{"k":"adidevananda","t":"But for those in whom this ignorance is destroyed by the knowledge of the Self, that knowledge, in their case, is supreme and shines brightly like the sun."},{"k":"gambirananda","t":"But in the case of those whose ignorance is destroyed by knowledge (of the Self), their knowledge, like the sun, reveals that supreme Reality."},{"k":"sankaranarayan","t":"In the case of those whose illusion has been destroyed by Self-knowledge, that knowledge illuminates itself, like the sun."}]},{"ch":5,"vn":17,"dev":"तद्बुद्धयस्तदात्मानस्तन्निष्ठास्तत्परायणाः।\nगच्छन्त्यपुनरावृत्तिं ज्ञाननिर्धूतकल्मषाः","iast":"tad-buddhayas tad-ātmānas tan-niṣhṭhās tat-parāyaṇāḥ\ngachchhantyapunar-āvṛittiṁ jñāna-nirdhūta-kalmaṣhāḥ","v":[{"k":"purohit","t":"Meditating on the divine, having faith in the divine, concentrating on the divine, and losing themselves in the divine, their sins dissolve in wisdom, and they go from whence there is no return."},{"k":"sivananda","t":"Their intellect absorbed in That, their self being That, established in That, with That as their supreme goal, they go whence there is no return, their sins dispelled by knowledge."},{"k":"adidevananda","t":"Those whose intellects pursue it, whose minds think about it, who undergo discipline for it, and who hold it as their highest object, have their impurities cleansed by knowledge and go from whence there is no return."},{"k":"gambirananda","t":"Those whose intellect is absorbed in That, whose Self is That, who are steadfast in That, and who have That as their supreme Goal—they attain the state of non-returning, their impurities having been removed by Knowledge."},{"k":"sankaranarayan","t":"Those who have their intellect and self (mind) devoted to This; who have established themselves in This and have This [alone] as their supreme goal; and who have washed off their sins through [perfect] knowledge—they reach a state from which there is no more return."}]},{"ch":5,"vn":18,"dev":"विद्याविनयसंपन्ने ब्राह्मणे गवि हस्तिनि।\nशुनि चैव श्वपाके च पण्डिताः समदर्शिनः","iast":"vidyā-vinaya-sampanne brāhmaṇe gavi hastini\nśhuni chaiva śhva-pāke cha paṇḍitāḥ sama-darśhinaḥ","v":[{"k":"purohit","t":"Sages look upon all equally, whether they be a minister of learning and humility, an infidel, a cow, an elephant, or a dog."},{"k":"sivananda","t":"Sages look with an equal eye on a Brahmana endowed with learning and humility, on a cow, an elephant, a dog, and even an outcaste."},{"k":"adidevananda","t":"The sages look with an equal eye on one endowed with learning and humility, a Brahmana, a cow, an elephant, a dog, and a dog-eater."},{"k":"gambirananda","t":"The learned ones look with equanimity on a Brahmana endowed with learning and humility, a cow, an elephant, and even a dog, as well as one who eats dog meat."},{"k":"sankaranarayan","t":"The wise, by nature, look equally upon a Brahmana, rich in learning and humility, a cow, an elephant, and even a dog and a dog-cooker (an outcaste)."}]},{"ch":5,"vn":19,"dev":"इहैव तैर्जितः सर्गो येषां साम्ये स्थितं मनः।\nनिर्दोषं हि समं ब्रह्म तस्माद्ब्रह्मणि ते स्थिताः","iast":"ihaiva tair jitaḥ sargo yeṣhāṁ sāmye sthitaṁ manaḥ\nnirdoṣhaṁ hi samaṁ brahma tasmād brahmaṇi te sthitāḥ","v":[{"k":"purohit","t":"Even in this world, those whose minds remain always balanced, fixed on the Supreme, conquer their earthly life; for the Supreme has neither blemish nor bias."},{"k":"sivananda","t":"Even here in this world, those whose minds rest in reality overcome birth; Brahman is indeed spotless and real; therefore they are established in Brahman."},{"k":"adidevananda","t":"Here itself, those whose minds rest in equanimity overcome samsara. For the Brahman (individual self), when uncontaminated by Prakriti, is the same everywhere; therefore, they abide in Brahman."},{"k":"gambirananda","t":"Here itself is mirth attained by those whose minds are established in sameness. Since Brahman is the same in all and free from defects, they are established in Brahman."},{"k":"sankaranarayan","t":"The one who knows Brahman, who is disillusioned, established in Brahman, and has a firm intellect, would neither rejoice upon meeting a friend nor get agitated upon meeting a foe."}]},{"ch":5,"vn":20,"dev":"न प्रहृष्येत्प्रियं प्राप्य नोद्विजेत्प्राप्य चाप्रियम्।\nस्थिरबुद्धिरसम्मूढो ब्रह्मविद्ब्रह्मणि स्थितः","iast":"na prahṛiṣhyet priyaṁ prāpya nodvijet prāpya chāpriyam\nsthira-buddhir asammūḍho brahma-vid brahmaṇi sthitaḥ","v":[{"k":"purohit","t":"He who knows and lives in the Absolute remains unmoved and unperturbed; he is not elated by pleasure nor depressed by pain."},{"k":"sivananda","t":"Resting in Brahman, with a steady intellect and undeluded, the knower of Brahman neither rejoices upon obtaining what is pleasant nor grieves upon obtaining what is unpleasant."},{"k":"adidevananda","t":"He who knows Brahman (individual self) and abides in Brahman, whose mind is steadfastly focused on the self and undeluded by body consciousness—he neither rejoices at gaining what is pleasant nor grieves on obtaining what is unpleasant."},{"k":"gambirananda","t":"A knower of Brahman, who is established in Brahman, should have their intellect steady and should not be deluded. They should not get delighted by getting what is desirable, nor become dejected by getting what is undesirable."},{"k":"sankaranarayan","t":"He who, with his mind not attached to external contacts, finds happiness in the Self—that person, with his mind engaged in Yoga, easily pervades the Brahman, suffering no loss."}]},{"ch":5,"vn":21,"dev":"बाह्यस्पर्शेष्वसक्तात्मा विन्दत्यात्मनि यत्सुखम्।\nस ब्रह्मयोगयुक्तात्मा सुखमक्षयमश्नुते","iast":"bāhya-sparśheṣhvasaktātmā vindatyātmani yat sukham\nsa brahma-yoga-yuktātmā sukham akṣhayam aśhnute","v":[{"k":"purohit","t":"He finds happiness in his own Self and enjoys eternal bliss, whose heart does not yearn for the contacts of the earth and whose Self is one with the Everlasting."},{"k":"sivananda","t":"With the self unattached to external contacts, he finds happiness in the Self; with the self engaged in the meditation of Brahman, he attains endless happiness."},{"k":"adidevananda","t":"He whose mind is detached from external contact and finds happiness in the Self—he has his mind engaged in the contemplation of Brahman and enjoys undecaying bliss."},{"k":"gambirananda","t":"With his heart unattached to external objects, he gets the bliss that is in the Self. With his heart absorbed in meditation on Brahman, he acquires undying Bliss."},{"k":"sankaranarayan","t":"The enjoyments that arise from contact [with objects] are nothing but sources of misery, having both a beginning and an end. Therefore, an intelligent person does not take delight in them, O son of Kunti!"}]},{"ch":5,"vn":22,"dev":"ये हि संस्पर्शजा भोगा दुःखयोनय एव ते।\nआद्यन्तवन्तः कौन्तेय न तेषु रमते बुधः","iast":"ye hi sansparśha-jā bhogā duḥkha-yonaya eva te\nādyantavantaḥ kaunteya na teṣhu ramate budhaḥ","v":[{"k":"purohit","t":"The joys that spring from external associations bring pain; they have their beginnings and their endings. The wise person does not rejoice in them."},{"k":"sivananda","t":"The enjoyments that arise from contact are only sources of pain, for they have a beginning and an end, O Arjuna; the wise do not rejoice in them."},{"k":"adidevananda","t":"For those pleasures that are born of contact are wombs of pain. They have a beginning and an end, O Arjuna; the wise do not rejoice in them."},{"k":"gambirananda","t":"Since enjoyments that result from contact with objects are indeed the sources of sorrow, having a beginning and an end, O son of Kunti, the wise one does not delight in them."},{"k":"sankaranarayan","t":"Whosoever, right here, before abandoning the body, is capable of bearing the force sprung from desire and wrath—he is considered to be a man of Yoga and a happy man."}]},{"ch":5,"vn":23,"dev":"शक्नोतीहैव यः सोढुं प्राक्शरीरविमोक्षणात्।\nकामक्रोधोद्भवं वेगं स युक्तः स सुखी नरः","iast":"śhaknotīhaiva yaḥ soḍhuṁ prāk śharīra-vimokṣhaṇāt\nkāma-krodhodbhavaṁ vegaṁ sa yuktaḥ sa sukhī naraḥ","v":[{"k":"purohit","t":"He who, before leaving his body, learns to overcome the promptings of desire and anger, is a saint and is happy."},{"k":"sivananda","t":"He who is able, while still here in this world, to withstand the impulse born out of desire and anger before the liberation from the body, he is a Yogi, and he is a happy man."},{"k":"adidevananda","t":"He who is able, even here, before being released from the body, to bear the impulse generated by desire and anger, he is a Yogin (competent for self-realisation); he is the happy man."},{"k":"gambirananda","t":"One who can withstand here itself, before departing from the body, the impulse arising from desire and anger, that person is a yogi; they are happy."},{"k":"sankaranarayan","t":"He, whose pleasure, delight, and light are all within—O son of Prtha!—he attains the supreme Yoga, becoming the Brahman himself."}]},{"ch":5,"vn":24,"dev":"योऽन्तःसुखोऽन्तरारामस्तथान्तर्ज्योतिरेव यः।\nस योगी ब्रह्मनिर्वाणं ब्रह्मभूतोऽधिगच्छति","iast":"yo 'ntaḥ-sukho 'ntar-ārāmas tathāntar-jyotir eva yaḥ\nsa yogī brahma-nirvāṇaṁ brahma-bhūto 'dhigachchhati","v":[{"k":"purohit","t":"He who is happy within himself and has found its peace, and in whom the inner light shines, that sage attains eternal bliss and becomes one with the spirit."},{"k":"sivananda","t":"He who is happy within, who rejoices within, and who is illuminated within, that Yogi attains absolute freedom, or Moksha, becoming Brahman himself."},{"k":"adidevananda","t":"He whose joy is within, whose pleasure is within, and whose light is within—he is a yogin, who, having become Brahman, attains the bliss of Brahman."},{"k":"gambirananda","t":"One who is content within, whose pleasure is within, and whose light is only within, that yogi, having become Brahman, attains absorption into Brahman."},{"k":"sankaranarayan","t":"The seers, whose doubts have decayed; by whom dualities have been cut off; whose minds are controlled; and who delight in the welfare of all; they attain the Brahman, the Transcendent One."}]},{"ch":5,"vn":25,"dev":"लभन्ते ब्रह्मनिर्वाणमृषयः क्षीणकल्मषाः।\nछिन्नद्वैधा यतात्मानः सर्वभूतहिते रताः","iast":"labhante brahma-nirvāṇam ṛiṣhayaḥ kṣhīṇa-kalmaṣhāḥ\nchhinna-dvaidhā yatātmānaḥ sarva-bhūta-hite ratāḥ","v":[{"k":"purohit","t":"Sages whose sins have been washed away, whose sense of separateness has dissipated, who have subdued themselves, and seek only the welfare of all, come to the Eternal Spirit."},{"k":"sivananda","t":"The sages obtain absolute freedom or Moksha when their sins have been destroyed, their dualities have been torn asunder, they are self-controlled, and they are intent on the welfare of all beings."},{"k":"adidevananda","t":"The sages, who are free from the pairs of opposites, whose minds are well subdued, and who are devoted to the welfare of all beings, become cleansed of all impurities and attain the bliss of Brahman."},{"k":"gambirananda","t":"The seers whose sins have been attenuated, who are free from doubt, whose senses are under control, who are engaged in doing good to all beings, attain absorption in Brahman."},{"k":"sankaranarayan","t":"At all times, there is the transcendent Brahman for the ascetics who have severed their connection with desire and anger, who have controlled their minds and have realized their Self."}]},{"ch":5,"vn":26,"dev":"कामक्रोधवियुक्तानां यतीनां यतचेतसाम्।\nअभितो ब्रह्मनिर्वाणं वर्तते विदितात्मनाम्","iast":"kāma-krodha-viyuktānāṁ yatīnāṁ yata-chetasām\nabhito brahma-nirvāṇaṁ vartate viditātmanām","v":[{"k":"purohit","t":"Saints who know themselves, who control their minds, and feel neither desire nor anger, find eternal bliss everywhere."},{"k":"sivananda","t":"Absolute freedom exists on all sides for those self-controlled ascetics who are free from desire and anger, who have controlled their thoughts, and who have realized the Self."},{"k":"adidevananda","t":"To those who are free from desire and wrath, who are accustomed to exerting themselves, whose thoughts are controlled, and who have conquered it—the beatitude of Brahman is close at hand."},{"k":"gambirananda","t":"To those monks who have control over their internal organs, who are free from desire and anger, who have known the Self, there is absorption into Brahman either way."},{"k":"sankaranarayan","t":"Warding off external contacts; keeping the sense of sight between the two wandering ones; counterbalancing both the forward and backward moving forces that travel within what is crooked;"}]},{"ch":5,"vn":27,"dev":"स्पर्शान्कृत्वा बहिर्बाह्यांश्चक्षुश्चैवान्तरे भ्रुवोः।\nप्राणापानौ समौ कृत्वा नासाभ्यन्तरचारिणौ","iast":"sparśhān kṛitvā bahir bāhyānśh chakṣhuśh chaivāntare bhruvoḥ\nprāṇāpānau samau kṛitvā nāsābhyantara-chāriṇau\nyatendriya-mano-buddhir munir mokṣha-parāyaṇaḥ\nvigatechchhā-bhaya-krodho yaḥ sadā mukta eva saḥ","v":[{"k":"purohit","t":"Excluding external objects, with his gaze fixed between the eyebrows, and the inward and outward breathings passing equally through his nostrils;"},{"k":"sivananda","t":"Shutting out all external contacts and fixing the gaze between the eyebrows, realizing the outgoing and incoming breaths moving within the nostrils."},{"k":"adidevananda","t":"Shutting off outward contacts, fixing the gaze between the eyebrows, realizing inward and outward breaths moving in the nostrils;"},{"k":"gambirananda","t":"- Keeping external objects outside, fixing the eyes at the juncture of the eye-brows, and controlling the outgoing and incoming breaths that move through the nostrils, the contemplative who has mastery over his organs, mind, and intellect should be fully intent on Liberation and free from desire, fear, and anger. He who is ever thus is verily free."},{"k":"sankaranarayan","t":"The sage, who has controlled his sense-organs, mind, and intellect; whose chief aim is emancipation; and from whom desire, fear, and wrath have departed—he remains ever free."}]},{"ch":5,"vn":28,"dev":"यतेन्द्रियमनोबुद्धिर्मुनिर्मोक्षपरायणः।\nविगतेच्छाभयक्रोधो यः सदा मुक्त एव सः","iast":"yatendriya-mano-buddhir  munir   mokṣa-parāyaṇaḥ vigatecchā-bhaya-krodho yaḥ sadā    mukta   eva saḥ","v":[{"k":"purohit","t":"Governing sense, mind, and intellect, intent on liberation, free from desire, fear, and anger, the sage is eternally free."},{"k":"sivananda","t":"With the senses, mind, and intellect ever controlled, having liberation as their supreme goal, free from desire, fear, and anger, the sage is truly liberated forever."},{"k":"adidevananda","t":"The sage who has controlled his senses, mind, and intellect, who is intent on release as his final goal, freed forever from desire, fear, and wrath, is indeed liberated forever."},{"k":"gambirananda","t":"- Keeping external objects outside, fixing the eyes at the juncture of the eye-brows, and controlling the outgoing and incoming breaths that move through the nostrils, the contemplative who has mastery over his organs, mind, and intellect should be fully intent on Liberation and free from desire, fear, and anger. He who is ever thus is verily free."},{"k":"sankaranarayan","t":"Having known Me as the Enjoyer of the fruits of sacrifices and austerities, as the great Lord of all the worlds, and as the Friend of all beings, he attains peace."}]},{"ch":5,"vn":29,"dev":"भोक्तारं यज्ञतपसां सर्वलोकमहेश्वरम्।\nसुहृदं सर्वभूतानां ज्ञात्वा मां शान्तिमृच्छति","iast":"bhoktāraṁ yajña-tapasāṁ sarva-loka-maheśhvaram\nsuhṛidaṁ sarva-bhūtānāṁ jñātvā māṁ śhāntim ṛichchhati","v":[{"k":"purohit","t":"Knowing Me as the One who gladly receives all offerings of austerity and sacrifice, as the Mighty Ruler of all the Worlds and the Friend of all beings, he passes to Eternal Peace."},{"k":"sivananda","t":"He who knows Me as the enjoyer of sacrifices and austerities, the great Lord of all the worlds, and the friend of all beings, attains peace."},{"k":"adidevananda","t":"Knowing Me as the enjoyer of all sacrifices and austerities, as the Supreme Lord of all worlds, as the Friend of every being, he attains peace."},{"k":"gambirananda","t":"One attains peace by knowing Me, who am the great Lord of all the worlds, the enjoyer of sacrifices and austerities, and the friend of all creatures."},{"k":"sankaranarayan","t":"There is no such translation for this shloka."}]},{"ch":6,"vn":1,"dev":"श्री भगवानुवाच\nअनाश्रितः कर्मफलं कार्यं कर्म करोति यः।\nस संन्यासी च योगी च न निरग्निर्न चाक्रियः","iast":"śhrī bhagavān uvācha\nanāśhritaḥ karma-phalaṁ kāryaṁ karma karoti yaḥ\nsa sannyāsī cha yogī cha na niragnir na chākriyaḥ","v":[{"k":"purohit","t":"Lord Shri Krishna said: He who acts out of duty, without considering the consequences, is truly spiritual and a true ascetic; not he who merely observes rituals or shuns all action."},{"k":"sivananda","t":"The Blessed Lord said: He who performs his bounden duty without depending on the fruits of his actions—he is a sannyasi and a yogi, not he who is without fire and without action."},{"k":"adidevananda","t":"The Lord said, \"He who performs works that ought to be done without seeking their fruits—he is a sannyasin and yogin, and not he who maintains no sacred fires and performs no actions.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"He who performs an action which is his duty, without depending on the result of the action, is a monk and a yogi; not so in he who does not keep afire and is actionless.\""},{"k":"sankaranarayan","t":"The Bhagavad said, \"He who performs his bounden action without depending on its fruit is the man of renunciation and the man of Yoga, not he who simply remains without his fires and actions.\""}]},{"ch":6,"vn":2,"dev":"यं संन्यासमिति प्राहुर्योगं तं विद्धि पाण्डव।\nन ह्यसंन्यस्तसङ्कल्पो योगी भवति कश्चन","iast":"yaṁ sannyāsam iti prāhur yogaṁ taṁ viddhi pāṇḍava\nna hyasannyasta-saṅkalpo yogī bhavati kaśhchana","v":[{"k":"purohit","t":"O Arjuna, renunciation is indeed what is known as right action. No one can become spiritually enlightened who has not renounced all desires."},{"k":"sivananda","t":"Do you, O Arjuna, know that Yoga is what they call renunciation; no one indeed becomes a Yogi who has not renounced their thoughts."},{"k":"adidevananda","t":"That which is called Sannyasa (Jnana Yoga), know that to be Yoga (Karma Yoga), O Arjuna. For no one, among Karma Yogins, whose delusive identification of the body with the self has not been abandoned, becomes a true Karma Yogin."},{"k":"gambirananda","t":"That which they call monasticism, know that to be Yoga, O Pandava, for nobody who has not given up expectations can be a yogi."},{"k":"sankaranarayan","t":"What the learned call renunciation, O son of Pandu, know that to be the same as the Yoga. For, without renouncing intention for fruit, one does not become a man of Yoga."}]},{"ch":6,"vn":3,"dev":"आरुरुक्षोर्मुनेर्योगं कर्म कारणमुच्यते।\nयोगारूढस्य तस्यैव शमः कारणमुच्यते","iast":"ārurukṣhor muner yogaṁ karma kāraṇam uchyate\nyogārūḍhasya tasyaiva śhamaḥ kāraṇam uchyate","v":[{"k":"purohit","t":"For the sage who seeks the heights of spiritual meditation, practice is the only method, and when they have attained it, they must maintain themselves there through continual self-control."},{"k":"sivananda","t":"For a sage who wishes to attain to Yoga, action is said to be the means; for the same sage who has attained Yoga, inaction is said to be the means."},{"k":"adidevananda","t":"Action is said to be the means for the sage who seeks to climb the heights of Yoga; but when he has climbed the heights of Yoga, tranquility is said to be the means."},{"k":"gambirananda","t":"For the sage who wishes to ascend to (Dhyana-) yoga, action is said to be the means. For that person, once he has ascended to (Dhyana-)yoga, inaction alone is said to be the means."},{"k":"sankaranarayan","t":"For a sage, who is desirous of mounting upon the Yoga, action is said to be the cause; for the same sage, when he has mounted upon the Yoga, stillness is said to be the cause."}]},{"ch":6,"vn":4,"dev":"यदा हि नेन्द्रियार्थेषु न कर्मस्वनुषज्जते।\nसर्वसङ्कल्पसंन्यासी योगारूढस्तदोच्यते","iast":"yadā hi nendriyārtheṣhu na karmasv-anuṣhajjate\nsarva-saṅkalpa-sannyāsī yogārūḍhas tadochyate","v":[{"k":"purohit","t":"When a man renounces even the thought of initiating action, and is not interested in sense objects or any results that may flow from his acts, then he truly understands spirituality."},{"k":"sivananda","t":"When a person is not attached to the sense-objects or to actions, having renounced all thoughts, then they are said to have attained Yoga."},{"k":"adidevananda","t":"For, when one loses attachment to the things of the senses and to actions, then they have abandoned all desires and are said to have climbed the heights of Yoga."},{"k":"gambirananda","t":"Verily, when a man who has given up thought about everything does not get attached to sense-objects or actions, he is then said to be established in Yoga."},{"k":"sankaranarayan","t":"When a person indulges neither in what is desired by the senses nor in the actions for it, then, being a man who has renounced all intentions, he is said to have mounted on the path of Yoga."}]},{"ch":6,"vn":5,"dev":"उद्धरेदात्मनाऽऽत्मानं नात्मानमवसादयेत्।\nआत्मैव ह्यात्मनो बन्धुरात्मैव रिपुरात्मनः","iast":"uddhared ātmanātmānaṁ nātmānam avasādayet\nātmaiva hyātmano bandhur ātmaiva ripur ātmanaḥ","v":[{"k":"purohit","t":"Let him seek liberation with the help of his Highest Self, and never disgrace his own Self. For that Self is his only friend; yet it can also be his enemy."},{"k":"sivananda","t":"One should raise oneself by one's own self alone; let not one lower oneself; for the self alone is one's own friend, and the self alone is one's own enemy."},{"k":"adidevananda","t":"One should raise oneself by one's own mind and not allow oneself to sink; for the mind alone is the friend of the self, and the mind alone is the foe of the self."},{"k":"gambirananda","t":"One should save oneself by oneself; one should not degrade oneself. For oneself is indeed one's own friend; oneself is indeed one's own enemy."},{"k":"sankaranarayan","t":"Let a person lift themselves by themselves and let them not depress themselves. For, the self alone is the friend of the self and the self alone is the foe of the self."}]},{"ch":6,"vn":6,"dev":"बन्धुरात्माऽऽत्मनस्तस्य येनात्मैवात्मना जितः।\nअनात्मनस्तु शत्रुत्वे वर्तेतात्मैव शत्रुवत्","iast":"bandhur ātmātmanas tasya yenātmaivātmanā jitaḥ\nanātmanas tu śhatrutve vartetātmaiva śhatru-vat","v":[{"k":"purohit","t":"To one who has conquered their lower nature with its help, the Self is a friend; but to one who has not done so, it is an enemy."},{"k":"sivananda","t":"The Self is the friend of the self of him by whom the Self has been conquered; but to the unconquered self, this Self stands in the position of an enemy, like an external foe."},{"k":"adidevananda","t":"The mind is the friend of him by whom it has been conquered. But for him whose mind is not conquered, the mind, like an enemy, remains hostile."},{"k":"gambirananda","t":"He who has conquered his own self by the self, his self is his own friend. But for one who has not conquered his own self, his self itself acts like an enemy."},{"k":"sankaranarayan","t":"The Self is the friend of that Self by which the Self has been verily subdued; but in the case of a person with an unsubdued Self, the Self alone would abide in enmity like an enemy."}]},{"ch":6,"vn":7,"dev":"जितात्मनः प्रशान्तस्य परमात्मा समाहितः।\nशीतोष्णसुखदुःखेषु तथा मानापमानयोः","iast":"jitātmanaḥ praśhāntasya paramātmā samāhitaḥ\nśhītoṣhṇa-sukha-duḥkheṣhu tathā mānāpamānayoḥ","v":[{"k":"purohit","t":"The Self of one who is self-controlled and has attained peace is equally unmoved by heat or cold, pleasure or pain, honor or dishonor."},{"k":"sivananda","t":"The Supreme Self of him who is self-controlled and peaceful remains balanced in cold and heat, pleasure and pain, as well as in honor and dishonor."},{"k":"adidevananda","t":"Of him whose mind is conquered and who is serene, the great self is well-secured in heat and cold, in pleasure and pain, and in honor and dishonor."},{"k":"gambirananda","t":"The supreme Self of one who has control over the aggregate of his body and organs, and who is tranquil, becomes manifest. He should be poised in the midst of cold and heat, happiness and sorrow, as well as honor and dishonor."},{"k":"sankaranarayan","t":"The thinking of the person, with a subdued mind and thus with complete calmness, remains in equilibrium in the case of others and himself, in cold and heat, in pleasure and pain, as well as in honor and dishonor."}]},{"ch":6,"vn":8,"dev":"ज्ञानविज्ञानतृप्तात्मा कूटस्थो विजितेन्द्रियः।\nयुक्त इत्युच्यते योगी समलोष्टाश्मकाञ्चनः","iast":"jñāna-vijñāna-tṛiptātmā kūṭa-stho vijitendriyaḥ\nyukta ityuchyate yogī sama-loṣhṭāśhma-kāñchanaḥ","v":[{"k":"purohit","t":"He who desires nothing but wisdom and spiritual insight, who has conquered his senses, and who looks upon a lump of earth, a stone, and fine gold with the same eye, is a real saint."},{"k":"sivananda","t":"The Yogi who is satisfied with the knowledge and wisdom of the Self, who has conquered the senses, and to whom a clod of earth, a piece of stone, and gold are all the same, is said to have attained Nirvikalpa Samadhi."},{"k":"adidevananda","t":"The yogin whose mind is content with knowledge of the self and also with knowledge of the difference between the self and Prakrti, who is established in the self, whose senses are subdued, and to whom earth, stone, and gold all seem alike, is called integrated."},{"k":"gambirananda","t":"One whose mind is satisfied with knowledge and realization, who is unmoved, who has his organs under control, is said to be Self-absorbed. The yogi treats all alike, a lump of earth, a stone, and gold."},{"k":"sankaranarayan","t":"He whose self is satisfied with knowledge and with what consists of varied thoughts; who remains peak-like and has completely subdued his senses; and to whom a clod, a stone, and a piece of gold are the same—that man of Yoga is called a master of Yoga."}]},{"ch":6,"vn":9,"dev":"सुहृन्मित्रार्युदासीनमध्यस्थद्वेष्यबन्धुषु।\nसाधुष्वपि च पापेषु समबुद्धिर्विशिष्यते","iast":"suhṛin-mitrāryudāsīna-madhyastha-dveṣhya-bandhuṣhu\nsādhuṣhvapi cha pāpeṣhu sama-buddhir viśhiṣhyate","v":[{"k":"purohit","t":"He looks impartially on all—lovers, friends, or foes; indifferent, hostile, alien, or relative; virtuous or sinful."},{"k":"sivananda","t":"He who is of the same mind towards the good-hearted, friends, enemies, the indifferent, the neutral, the hateful, the relatives, the righteous, and the unrighteous, excels."},{"k":"adidevananda","t":"He who regards with an equal eye well-wishers, friends, foes, the indifferent, neutrals, the hateful, the relations, and even the good and the sinful—he excels."},{"k":"gambirananda","t":"He excels who has sameness of view with regard to a benefactor, a friend, an enemy, a neutral, an arbiter, the hateful, a relative, good people, and even sinners."},{"k":"sankaranarayan","t":"He whose mind is equal in the case of friend, companion, enemy, the indifferent one, the one who remains in the middle, the foe, the relative, the righteous, and also the sinful—he excels [all]."}]},{"ch":6,"vn":10,"dev":"योगी युञ्जीत सततमात्मानं रहसि स्थितः।\nएकाकी यतचित्तात्मा निराशीरपरिग्रहः","iast":"yogī yuñjīta satatam ātmānaṁ rahasi sthitaḥ\nekākī yata-chittātmā nirāśhīr aparigrahaḥ","v":[{"k":"purohit","t":"Let the student of spirituality try unceasingly to concentrate his mind; let him live in seclusion, absolutely alone, with his mind and personality controlled, free from desire and without possessions."},{"k":"sivananda","t":"Let the yogi constantly strive to keep the mind steady, remaining in solitude, alone, with the body and mind controlled, and free from hope and greed."},{"k":"adidevananda","t":"The yogin should constantly fix his mind on yoga, remaining in a solitary place all alone, controlling his thoughts and mind, free from desire and a sense of possession."},{"k":"gambirananda","t":"A yogi should constantly concentrate his mind by staying in a solitary place, alone, with mind and body controlled, free from expectations, and free from acquisition."},{"k":"sankaranarayan","t":"Let the man of Yoga always yoke the self (mind) by remaining alone in a lonely place, controlling his mind and body, without desire and without a sense of possession."}]},{"ch":6,"vn":11,"dev":"शुचौ देशे प्रतिष्ठाप्य स्थिरमासनमात्मनः।\nनात्युच्छ्रितं नातिनीचं चैलाजिनकुशोत्तरम्","iast":"śhuchau deśhe pratiṣhṭhāpya sthiram āsanam ātmanaḥ\nnātyuchchhritaṁ nāti-nīchaṁ chailājina-kuśhottaram","v":[{"k":"purohit","t":"Having chosen a holy place, let him sit in a firm posture on a seat that is neither too high nor too low, and cover it with a grass mat, a deer skin, and a cloth."},{"k":"sivananda","t":"In a clean spot, having established a firm seat of his own, neither too high nor too low, made of cloth, skin, and kusha grass layered one over the other."},{"k":"adidevananda","t":"Having established for himself, in a clean spot, a firm seat that is neither too high nor too low, and covering it with cloth, deer-skin, and Kusa grass in reverse order—"},{"k":"gambirananda","t":"Having firmly established in a clean place his seat, neither too high nor too low, composed of cloth, skin, and kusa-grass placed successively one below the other;"},{"k":"sankaranarayan","t":"Setting up in a clean place his own suitable, firm seat predominantly made of cloth, skin, and kusa-grass, neither too high nor too low for him;"}]},{"ch":6,"vn":12,"dev":"तत्रैकाग्रं मनः कृत्वा यतचित्तेन्द्रियक्रियः।\nउपविश्यासने युञ्ज्याद्योगमात्मविशुद्धये","iast":"tatraikāgraṁ manaḥ kṛitvā yata-chittendriya-kriyaḥ\nupaviśhyāsane yuñjyād yogam ātma-viśhuddhaye","v":[{"k":"purohit","t":"Seated thus, with his mind concentrated, his functions controlled, and his senses governed, let him practice meditation for the purification of his lower nature."},{"k":"sivananda","t":"There, having made the mind one-pointed, with the actions of the mind and senses controlled, let him, seated on the seat, practice Yoga for the purification of the self."},{"k":"adidevananda","t":"Sitting on the seat, with a concentrated mind, controlling the mind and senses, one should practice Yoga for the purification of the self."},{"k":"gambirananda","t":"Sitting on that seat, he should concentrate his mind for the purification of the internal organ, making the mind one-pointed and keeping the actions of the mind and senses under control."},{"k":"sankaranarayan","t":"Sitting there on the seat and making the mind single-pointed, let him, with the activities of his mind and senses subdued, practice Yoga for self-purification."}]},{"ch":6,"vn":13,"dev":"समं कायशिरोग्रीवं धारयन्नचलं स्थिरः।\nसंप्रेक्ष्य नासिकाग्रं स्वं दिशश्चानवलोकयन्","iast":"samaṁ kāya-śhiro-grīvaṁ dhārayann achalaṁ sthiraḥ\nsamprekṣhya nāsikāgraṁ svaṁ diśhaśh chānavalokayan","v":[{"k":"purohit","t":"Let him hold his body, head, and neck erect, motionless and steady; let him look fixedly at the tip of his nose, turning neither to the right nor to the left."},{"k":"sivananda","t":"Let him firmly hold his body, head, and neck erect and still, gazing at the tip of his nose without looking around."},{"k":"adidevananda","t":"Holding the trunk, head, and neck erect, motionless and steady, gazing at the tip of the nose and not looking in any direction;"},{"k":"gambirananda","t":"Holding the body, head, and neck erect and still, being steady, looking at the tip of his own nose and not looking around."},{"k":"sankaranarayan","t":"Holding the body, head, and neck erect and motionless; remaining firm; looking properly at one's own nose-tip; and not looking in different directions."}]},{"ch":6,"vn":14,"dev":"प्रशान्तात्मा विगतभीर्ब्रह्मचारिव्रते स्थितः।\nमनः संयम्य मच्चित्तो युक्त आसीत मत्परः","iast":"praśhāntātmā vigata-bhīr brahmachāri-vrate sthitaḥ\nmanaḥ sanyamya mach-chitto yukta āsīta mat-paraḥ","v":[{"k":"purohit","t":"With peace in his heart and no fear, observing the vow of celibacy, with his mind controlled and fixed on Me, let the student lose himself in contemplation of Me."},{"k":"sivananda","t":"Serene-minded, fearless, firm in the vow of a Brahmachari, having controlled their mind, thinking of Me and balanced in mind, let them sit, having Me as their supreme goal."},{"k":"adidevananda","t":"Serene and fearless, firm in their vow of celibacy, controlling their minds and fixing their thoughts on Me, they should sit in Yoga, intent on Me."},{"k":"gambirananda","t":"He should remain seated with a placid mind, free from fear, firm in the vow of celibacy, and with the mind fixed on Me by controlling it through concentration, having Me as the supreme goal."},{"k":"sankaranarayan","t":"Being calm-minded, fearless, and firmly devoted to celibacy; controlling the mind completely; let the master of Yoga remain, fixing his mind on Me and having Me as his supreme goal."}]},{"ch":6,"vn":15,"dev":"युञ्जन्नेवं सदाऽऽत्मानं योगी नियतमानसः।\nशान्तिं निर्वाणपरमां मत्संस्थामधिगच्छति","iast":"yuñjann evaṁ sadātmānaṁ yogī niyata-mānasaḥ\nśhantiṁ nirvāṇa-paramāṁ mat-sansthām adhigachchhati","v":[{"k":"purohit","t":"Thus, keeping his mind always in communion with Me and subduing his thoughts, he shall attain that Peace which is Mine and will lead him to liberation at last."},{"k":"sivananda","t":"Thus, always keeping the mind balanced, the yogi, with the mind controlled, attains the peace abiding in Me, culminating in liberation."},{"k":"adidevananda","t":"Applying his mind in this way, the Yogin of controlled mind, ever attains the peace which is the summit of beatitude and which abides in Me."},{"k":"gambirananda","t":"Concentrating the mind thus, forever, the yogi of a controlled mind achieves the peace that culminates in liberation and abides in Me."},{"k":"sankaranarayan","t":"Yoking his mind incessantly in this manner, My devotee, with their mind not attached to anything else, realizes peace which culminates in nirvana and ends in Me."}]},{"ch":6,"vn":16,"dev":"नात्यश्नतस्तु योगोऽस्ति न चैकान्तमनश्नतः।\nन चातिस्वप्नशीलस्य जाग्रतो नैव चार्जुन","iast":"nātyaśhnatastu yogo 'sti na chaikāntam anaśhnataḥ\nna chāti-svapna-śhīlasya jāgrato naiva chārjuna","v":[{"k":"purohit","t":"Meditation is not for him who eats too much, nor for him who eats not at all; not for him who is overly addicted to sleep, nor for him who is always awake."},{"k":"sivananda","t":"Verily, Yoga is not possible for him who eats too much, nor for him who does not eat at all, nor for him who sleeps too much, nor for him who is always awake, O Arjuna."},{"k":"adidevananda","t":"Yoga is not for him who overeats, nor for him who fasts excessively; not for him, O Arjuna, who sleeps too much, nor for him who stays awake too long."},{"k":"gambirananda","t":"But, O Arjuna, Yoga is not for one who eats excessively, nor for one who does not eat at all; neither for one who habitually sleeps too long, nor for one who stays awake."},{"k":"sankaranarayan","t":"Yoga is neither for him who eats too much, nor for him who totally abstains from eating, nor for him who is prone to sleeping too much, nor for him who keeps awake too much."}]},{"ch":6,"vn":17,"dev":"युक्ताहारविहारस्य युक्तचेष्टस्य कर्मसु।\nयुक्तस्वप्नावबोधस्य योगो भवति दुःखहा","iast":"yuktāhāra-vihārasya yukta-cheṣhṭasya karmasu\nyukta-svapnāvabodhasya yogo bhavati duḥkha-hā","v":[{"k":"purohit","t":"But for him who regulates his food and recreation, who is balanced in action, in sleep, and in waking, it shall dispel all unhappiness."},{"k":"sivananda","t":"Yoga becomes the destroyer of pain for him who is moderate in eating and recreation (such as walking, etc.), who exercises moderation in action, and who is moderate in sleep and wakefulness."},{"k":"adidevananda","t":"Yoga becomes the destroyer of sorrows for those who are temperate in food and recreation, temperate in their actions, and temperate in their sleep and wakefulness."},{"k":"gambirananda","t":"Yoga becomes a destroyer of sorrow for one whose eating and movements are regulated, whose effort in works is moderate, and whose sleep and wakefulness are temperate."},{"k":"sankaranarayan","t":"The Yoga becomes a misery-killer for him whose effort for food is appropriate, exertion in activities is proper, and whose sleep and waking are proportionate."}]},{"ch":6,"vn":18,"dev":"यदा विनियतं चित्तमात्मन्येवावतिष्ठते।\nनिःस्पृहः सर्वकामेभ्यो युक्त इत्युच्यते तदा","iast":"yadā viniyataṁ chittam ātmanyevāvatiṣhṭhate\nniḥspṛihaḥ sarva-kāmebhyo yukta ityuchyate tadā","v":[{"k":"purohit","t":"When the mind is completely controlled, centered in the Self, and free from all earthly desires, then the man is truly spiritual."},{"k":"sivananda","t":"When the perfectly controlled mind rests in the Self alone, free from longing for any of the objects of desire, then it is said, 'He is united'."},{"k":"adidevananda","t":"When the subdued mind rests solely on the Self, then, free from all yearning for objects of desire, one is said to be fit for Yoga."},{"k":"gambirananda","t":"A person who has become free from hankering for all desirable objects is said to be Self-absorbed when the controlled mind rests solely in the Self."},{"k":"sankaranarayan","t":"When his mind, well-controlled, is established in nothing but the Self, and he is free from craving for any desired object—at that time he is called a master of Yoga."}]},{"ch":6,"vn":19,"dev":"यथा दीपो निवातस्थो नेङ्गते सोपमा स्मृता।\nयोगिनो यतचित्तस्य युञ्जतो योगमात्मनः","iast":"yathā dīpo nivāta-stho neṅgate sopamā smṛitā\nyogino yata-chittasya yuñjato yogam ātmanaḥ","v":[{"k":"purohit","t":"The wise man who has conquered his mind and is absorbed in the Self is like a lamp that does not flicker, as it stands sheltered from every wind."},{"k":"sivananda","t":"As a lamp placed in a windless spot does not flicker, so is the Yogi of a controlled mind, who practices Yoga in the Self, compared."},{"k":"adidevananda","t":"A lamp does not flicker in a windless place\"—that is the simile used for the tranquil mind of a yogi who practices yoga."},{"k":"gambirananda","t":"As a lamp kept in a windless place does not flicker, so is the simile for the yogi whose mind is under control and who is engaged in concentration on the Self."},{"k":"sankaranarayan","t":"Just as a lamp in a windless place does not shake, this simile is recalled in the case of the man of Yoga, with a subdued mind, practicing Yoga in the Self."}]},{"ch":6,"vn":20,"dev":"यत्रोपरमते चित्तं निरुद्धं योगसेवया।\nयत्र चैवात्मनाऽऽत्मानं पश्यन्नात्मनि तुष्यति","iast":"yatroparamate chittaṁ niruddhaṁ yoga-sevayā\nyatra chaivātmanātmānaṁ paśhyann ātmani tuṣhyati","v":[{"k":"purohit","t":"There, where the whole of nature is seen in the light of the Self, where the person abides within their Self and is satisfied there, their functions restrained by their union with the Divine, the mind finds rest."},{"k":"sivananda","t":"When the mind, restrained by the practice of yoga, attains quietude, and when one sees the Self by the Self, they are satisfied in their own Self."},{"k":"adidevananda","t":"Where the mind, controlled through the practice of Yoga, rests, and where one sees the Self by the Self and is delighted by the Self alone."},{"k":"gambirananda","t":"At the time when the mind, restrained through the practice of Yoga, is withdrawn, and just when one sees the Self by the self and remains contented in the Self alone;"},{"k":"sankaranarayan","t":"Where the mind, restrained through yoga practice, remains still; and where, observing, the yogi finds satisfaction in the Self alone, by perceiving only the Self within."}]},{"ch":6,"vn":21,"dev":"सुखमात्यन्तिकं यत्तद्बुद्धिग्राह्यमतीन्द्रियम्।\nवेत्ति यत्र न चैवायं स्थितश्चलति तत्त्वतः","iast":"sukham ātyantikaṁ yat tad buddhi-grāhyam atīndriyam\nvetti yatra na chaivāyaṁ sthitaśh chalati tattvataḥ","v":[{"k":"purohit","t":"When he enjoys the bliss that surpasses the senses and can only be grasped by the pure intellect, when he comes to rest within his highest self, he will never again stray from reality."},{"k":"sivananda","t":"When he (the Yogi) feels that infinite bliss which can be grasped by the pure intellect and which transcends the senses, and is established therein, never moving away from the reality."},{"k":"adidevananda","t":"Where one knows that infinite happiness which can be grasped by the intellect but is beyond the reach of the senses, and is established in that condition, one does not swerve from it."},{"k":"gambirananda","t":"When one experiences that absolute Bliss, which can be intuited by the intellect and which is beyond the senses, and being thus established, this person surely does not swerve from Reality."},{"k":"sankaranarayan","t":"Where he realizes the limitless Bliss, which is to be grasped by intellect and is beyond the senses; remaining where he does not depart from the Reality."}]},{"ch":6,"vn":22,"dev":"यं लब्ध्वा चापरं लाभं मन्यते नाधिकं ततः।\nयस्मिन्स्थितो न दुःखेन गुरुणापि विचाल्यते","iast":"yaṁ labdhvā chāparaṁ lābhaṁ manyate nādhikaṁ tataḥ\nyasmin sthito na duḥkhena guruṇāpi vichālyate","v":[{"k":"purohit","t":"Finding That, he will realize that there is no possession so precious. And once established there, no calamity can disturb him."},{"k":"sivananda","t":"Having obtained it, he thinks there is no other gain superior to it; established in it, he is not moved even by heavy sorrow."},{"k":"adidevananda","t":"Having gained it, one holds that there is no greater gain; being established in it, one is not moved even by the heaviest sorrow."},{"k":"gambirananda","t":"Obtaining which one does not consider any other acquisition to be superior, and being established in which one is not perturbed even by great sorrow;"},{"k":"sankaranarayan","t":"And having attained it, he does not think of any other gain as superior to that; being established in it, he is not shaken much by misery, however powerful it may be."}]},{"ch":6,"vn":23,"dev":"तं विद्याद् दुःखसंयोगवियोगं योगसंज्ञितम्।\nस निश्चयेन योक्तव्यो योगोऽनिर्विण्णचेतसा","iast":"taṁ vidyād duḥkha-sanyoga-viyogaṁ yogasaṅjñitam\nsa niśhchayena yoktavyo yogo 'nirviṇṇa-chetasā","v":[{"k":"purohit","t":"This inner severance from the affliction of misery is spirituality. It should be practiced with determination and with a heart that refuses to be depressed."},{"k":"sivananda","t":"Let this be known by the name of Yoga, the severance from union with pain. This Yoga should be practiced with determination and with an undespairing mind."},{"k":"adidevananda","t":"Know this deliverance from association with misery to be Yoga. This Yoga must be practiced with determination and with a mind free from despondency."},{"k":"gambirananda","t":"One should know that severance of contact with sorrow to be what is called Yoga. That Yoga should be practiced with perseverance and with an undepressed heart."},{"k":"sankaranarayan","t":"That he would realize to be the cause for his cessation of contact with misery and to be the one made known by Yoga. With determination, that is to be yoked in Yoga by a person of undepressed mind (or of the depressed mind)."}]},{"ch":6,"vn":24,"dev":"सङ्कल्पप्रभवान्कामांस्त्यक्त्वा सर्वानशेषतः।\nमनसैवेन्द्रियग्रामं विनियम्य समन्ततः","iast":"saṅkalpa-prabhavān kāmāns tyaktvā sarvān aśheṣhataḥ\nmanasaivendriya-grāmaṁ viniyamya samantataḥ","v":[{"k":"purohit","t":"Renouncing every desire that can be imagined, controlling the senses at every point through the power of the mind;"},{"k":"sivananda","t":"Abandoning unreservedly all desires born of Sankalpa (thought and imagination) and completely restraining the whole group of senses by the mind from all sides."},{"k":"adidevananda","t":"Renouncing entirely all desires born of volition and restraining the mind from all the senses on all sides,"},{"k":"gambirananda","t":"By totally eschewing all desires that arise from thoughts and restraining all the organs with the mind from every side;"},{"k":"sankaranarayan","t":"In order to renounce completely all desires that are born of intention, let a person restrain the group of sense-organs from all sides by mind alone."}]},{"ch":6,"vn":25,"dev":"शनैः शनैरुपरमेद् बुद्ध्या धृतिगृहीतया।\nआत्मसंस्थं मनः कृत्वा न किञ्चिदपि चिन्तयेत्","iast":"śhanaiḥ śhanair uparamed buddhyā dhṛiti-gṛihītayā\nātma-sansthaṁ manaḥ kṛitvā na kiñchid api chintayet","v":[{"k":"purohit","t":"Little by little, with the help of his reason controlled by fortitude, let him attain peace; and, fixing his mind on the Self, let him not think of anything else."},{"k":"sivananda","t":"Little by little, let him attain steadiness of the intellect by holding it firmly; having made the mind establish itself in the Self, let him not think of anything else."},{"k":"adidevananda","t":"Little by little, one should withdraw oneself from objects other than the self, with the help of the intellect held by firm resolution; and then one should think of nothing else, having fixed the mind upon the Self."},{"k":"gambirananda","t":"One should gradually withdraw with the intellect, endowed with steadiness. Making the mind fixed in the Self, one should not think of anything at all."},{"k":"sankaranarayan","t":"Very slowly remain still, keeping the mind well established in the Self by means of the intellect held in steadiness; and let him not think of anything (object)."}]},{"ch":6,"vn":26,"dev":"यतो यतो निश्चरति मनश्चञ्चलमस्थिरम्।\nततस्ततो नियम्यैतदात्मन्येव वशं नयेत्","iast":"yato yato niśhcharati manaśh chañchalam asthiram\ntatas tato niyamyaitad ātmanyeva vaśhaṁ nayet","v":[{"k":"purohit","t":"When the volatile and wavering mind wanders, let him restrain it and bring it back to its allegiance to the Self."},{"k":"sivananda","t":"From whatever cause the restless and unsteady mind wanders away, let him restrain it from that and bring it under the control of the Self alone."},{"k":"adidevananda","t":"Wherever the fickle and unsteady mind wanders, one should subdue it and then bring it back under the control of the self alone."},{"k":"gambirananda","t":"The yogi should bring this mind under the subjugation of the Self itself, restraining it from all those causes that cause the restless, unsteady mind to wander away."},{"k":"sankaranarayan","t":"By whatever things the shaky and unsteady mind strays, let him restrain it from those things and bring it back under the control of the Self alone."}]},{"ch":6,"vn":27,"dev":"प्रशान्तमनसं ह्येनं योगिनं सुखमुत्तमम्।\nउपैति शान्तरजसं ब्रह्मभूतमकल्मषम्","iast":"praśhānta-manasaṁ hyenaṁ yoginaṁ sukham uttamam\nupaiti śhānta-rajasaṁ brahma-bhūtam akalmaṣham","v":[{"k":"purohit","t":"Supreme bliss is the lot of the sage whose mind attains peace, whose passions subside, who is without sin, and who becomes one with the Absolute."},{"k":"sivananda","t":"Supreme Bliss indeed comes to this Yogi whose mind is made peaceful, whose passion is quelled, who has become Brahman, and who is free from sin."},{"k":"adidevananda","t":"For supreme happiness comes to the Yogin whose mind is at peace, who is free from evil, from whom Rajas has departed, and who has become the Brahman."},{"k":"gambirananda","t":"Supreme Bliss comes to this yogi alone whose mind has become perfectly tranquil, whose quality of rajas has been eliminated, who has become identified with Brahman, and is untainted."},{"k":"sankaranarayan","t":"Indeed, the Supreme Bliss comes to this highly tranquil-minded man of Yoga, whose passions remain stilled, who has become one with the Brahman, and who is free from sins."}]},{"ch":6,"vn":28,"dev":"युञ्जन्नेवं सदाऽऽत्मानं योगी विगतकल्मषः।\nसुखेन ब्रह्मसंस्पर्शमत्यन्तं सुखमश्नुते","iast":"yuñjann evaṁ sadātmānaṁ yogī vigata-kalmaṣhaḥ\nsukhena brahma-sansparśham atyantaṁ sukham aśhnute","v":[{"k":"purohit","t":"Thus, free from sin, abiding always in the Eternal, the saint enjoys, without effort, the bliss that flows from the realization of the Infinite."},{"k":"sivananda","t":"The yogi, always engaging the mind thus (in the practice of yoga), is freed from sins and easily enjoys the infinite bliss of contact with Brahman (the Eternal)."},{"k":"adidevananda","t":"Thus, devoting himself to the Yoga of the Self, freed from impurities, the yogin easily attains the supreme bliss of contact with the Brahman."},{"k":"gambirananda","t":"By constantly concentrating his mind in this way, the taintless yogi easily attains the absolute bliss of contact with Brahman."},{"k":"sankaranarayan","t":"Thus, yoking the self always, the man of Yoga, with a subdued mind, easily attains complete union, that is, the Brahman."}]},{"ch":6,"vn":29,"dev":"सर्वभूतस्थमात्मानं सर्वभूतानि चात्मनि।\nईक्षते योगयुक्तात्मा सर्वत्र समदर्शनः","iast":"sarva-bhūta-stham ātmānaṁ sarva-bhūtāni chātmani\nīkṣhate yoga-yuktātmā sarvatra sama-darśhanaḥ","v":[{"k":"purohit","t":"He who experiences the unity of life sees his own Self in all beings, and all beings in his own Self, and looks upon everything with an impartial eye."},{"k":"sivananda","t":"With the mind harmonized by Yoga, he sees the Self abiding in all beings and all beings in the Self; he sees the same everywhere."},{"k":"adidevananda","t":"He whose mind is fixed in Yoga sees reality everywhere; he sees his Self as abiding in all beings and all beings in his Self."},{"k":"gambirananda","t":"One who has their mind Self-absorbed through Yoga, and who has the vision of sameness everywhere, sees this Self existing in everything, and everything in their Self."},{"k":"sankaranarayan","t":"He who has yoked himself in Yoga and observes everything truly perceives the Self to be abiding in all beings and all beings to be abiding in the Self."}]},{"ch":6,"vn":30,"dev":"यो मां पश्यति सर्वत्र सर्वं च मयि पश्यति।\nतस्याहं न प्रणश्यामि स च मे न प्रणश्यति","iast":"yo māṁ paśhyati sarvatra sarvaṁ cha mayi paśhyati\ntasyāhaṁ na praṇaśhyāmi sa cha me na praṇaśhyati","v":[{"k":"purohit","t":"He who sees Me in everything and everything in Me, I shall never forsake him, nor shall he lose Me."},{"k":"sivananda","t":"He who sees Me everywhere and sees everything in Me, never becomes separated from Me, nor do I from him."},{"k":"adidevananda","t":"To him who sees Me in every self and every self in Me—I am not lost to him, nor is he lost to Me."},{"k":"gambirananda","t":"One who sees Me in everything and sees all things in Me—I do not lose sight of him, and he also is not lost to My vision."},{"k":"sankaranarayan","t":"He who observes Me in all and observes all in Me—for him, I am not lost, and he too is not lost for me."}]},{"ch":6,"vn":31,"dev":"सर्वभूतस्थितं यो मां भजत्येकत्वमास्थितः।\nसर्वथा वर्तमानोऽपि स योगी मयि वर्तते","iast":"sarva-bhūta-sthitaṁ yo māṁ bhajatyekatvam āsthitaḥ\nsarvathā vartamāno 'pi sa yogī mayi vartate","v":[{"k":"purohit","t":"The sage who realizes the unity of life and who worships Me in all beings, lives in Me, no matter what their lot may be."},{"k":"sivananda","t":"He who, being established in unity, worships Me, who dwells in all beings, that yogi abides in Me, whatever their mode of living may be."},{"k":"adidevananda","t":"The yogi who, fixed in oneness, worships Me dwelling in all beings—he abides in Me, no matter how he may live."},{"k":"gambirananda","t":"That yogi, who, being established in unity, adores Me as existing in all things, exists in Me—in whatever condition he may be."},{"k":"sankaranarayan","t":"He who is firmly established in the oneness of Me, experiences Me immanent in all beings—that man of Yoga is never stained, no matter what stage he may be in."}]},{"ch":6,"vn":32,"dev":"आत्मौपम्येन सर्वत्र समं पश्यति योऽर्जुन।\nसुखं वा यदि वा दुःखं सः योगी परमो मतः","iast":"ātmaupamyena sarvatra samaṁ paśhyati yo 'rjuna\nsukhaṁ vā yadi vā duḥkhaṁ sa yogī paramo mataḥ","v":[{"k":"purohit","t":"O Arjuna! He is the perfect saint who, having been taught by the likeness within himself, sees the same Self everywhere, regardless of whether the outer form be pleasurable or painful."},{"k":"sivananda","t":"He who, through the likeness of the Self, O Arjuna, sees reality everywhere, be it pleasure or pain, is regarded as the highest Yogi."},{"k":"adidevananda","t":"He who, due to the similarity of selves everywhere, sees pleasure or pain as the same everywhere—that yogi, O Arjuna, is considered the closest."},{"k":"gambirananda","t":"O Arjuna, that yogi is considered the best who judges what is happiness and sorrow in all beings by the same standard as they would apply to themselves."},{"k":"sankaranarayan","t":"Whoever finds pleasure or pain equally in all, as if it were in themselves—that person is considered to be a great man of Yoga, O Arjuna!"}]},{"ch":6,"vn":33,"dev":"अर्जुन उवाच\nयोऽयं योगस्त्वया प्रोक्तः साम्येन मधुसूदन।\nएतस्याहं न पश्यामि चञ्चलत्वात् स्थितिं स्थिराम्","iast":"arjuna uvācha\nyo 'yaṁ yogas tvayā proktaḥ sāmyena madhusūdana\netasyāhaṁ na paśhyāmi chañchalatvāt sthitiṁ sthirām","v":[{"k":"purohit","t":"Arjuna said: I do not see how I can attain this state of equanimity which You have revealed, owing to the restlessness of my mind."},{"k":"sivananda","t":"Arjuna said, \"O Krishna, I do not see how this Yoga of equanimity, which you have taught me, can be maintained steadily, due to the restlessness of the mind.\""},{"k":"adidevananda","t":"Arjuna said, \"O Krsna, this Yoga of reality, which You have declared, I do not see how it can be steady due to the fickleness of the mind.\""},{"k":"gambirananda","t":"Arjuna said, \"O Madhusudana (Krsna), this Yoga that You have spoken of as sameness, I do not see its steady continuance due to the restlessness of the mind.\""},{"k":"sankaranarayan","t":"Arjuna said, \"O slayer of Mandhu, this Yoga of equanimity which You have spoken of, I do not find a proper foundation for it due to the unsteadiness of the mind.\""}]},{"ch":6,"vn":34,"dev":"चञ्चलं हि मनः कृष्ण प्रमाथि बलवद्दृढम्।\nतस्याहं निग्रहं मन्ये वायोरिव सुदुष्करम्","iast":"chañchalaṁ hi manaḥ kṛiṣhṇa pramāthi balavad dṛiḍham\ntasyāhaṁ nigrahaṁ manye vāyor iva su-duṣhkaram","v":[{"k":"purohit","t":"My Lord! Verily, the mind is fickle and turbulent, obstinate, and strong; indeed, it is extremely difficult to control, like the wind."},{"k":"sivananda","t":"The mind is indeed restless, turbulent, strong, and unyielding, O Krishna; I consider it as difficult to control as controlling the wind."},{"k":"adidevananda","t":"For the mind is fickle, O Krsna, impetuous, powerful, and stubborn; I think that restraining it is as difficult as restraining the wind."},{"k":"gambirananda","t":"For, O Kṛṣṇa, the mind is unsteady, turbulent, strong, and obstinate; I consider its control to be as difficult as that of the wind."},{"k":"sankaranarayan","t":"O Krsna! The mind is indeed unsteady, destructive, strong, and obstinate; I believe it is very difficult to control it, just as it is to control the wind."}]},{"ch":6,"vn":35,"dev":"श्री भगवानुवाच\nअसंशयं महाबाहो मनो दुर्निग्रहं चलं।\nअभ्यासेन तु कौन्तेय वैराग्येण च गृह्यते","iast":"śhrī bhagavān uvācha\nasanśhayaṁ mahā-bāho mano durnigrahaṁ chalam\nabhyāsena tu kaunteya vairāgyeṇa cha gṛihyate","v":[{"k":"purohit","t":"Lord Shri Krishna replied: Doubtless, O Mighty One, the mind is fickle and exceedingly difficult to restrain; however, O Son of Kunti, with practice and renunciation, it can be done."},{"k":"sivananda","t":"The Blessed Lord said, \"Undoubtedly, O mighty-armed Arjuna, the mind is difficult to control and restless; but with practice and dispassion, it can be restrained.\""},{"k":"adidevananda","t":"The Lord said, \"The mind is indeed hard to subdue and fickle, O mighty-armed one, but, O son of Kunti, it can be brought under control through practice and the exercise of dispassion.\""},{"k":"gambirananda","t":"The Blessed Lord said, O mighty-armed one, undoubtedly the mind is untamable and restless. But, O son of Kunti, it can be brought under control through practice and detachment."},{"k":"sankaranarayan","t":"The Bhagavat said, O mighty-armed one! No doubt, the mind is unsteady and hard to control. But it can be controlled through practice and an attitude of desirelessness, O son of Kunti!"}]},{"ch":6,"vn":36,"dev":"असंयतात्मना योगो दुष्प्राप इति मे मतिः।\nवश्यात्मना तु यतता शक्योऽवाप्तुमुपायतः","iast":"asaṅyatātmanā yogo duṣhprāpa iti me matiḥ\nvaśhyātmanā tu yatatā śhakyo 'vāptum upāyataḥ","v":[{"k":"purohit","t":"It is not possible to attain Self-Realization unless one knows how to control oneself; however, for one who, striving by the proper means, learns such control, it is possible."},{"k":"sivananda","t":"I think Yoga is hard to be attained by one with an uncontrolled self, but the self-controlled and striving one can attain it by the appropriate means."},{"k":"adidevananda","t":"In my opinion, Yoga is hard to attain by a person of an unrestrained mind; however, it can be attained through the right means by one who strives for it and has a subdued mind."},{"k":"gambirananda","t":"My conviction is that Yoga is difficult to attain for one with an uncontrolled mind. But it is possible to attain through the aforementioned means for one who strives and has a controlled mind."},{"k":"sankaranarayan","t":"My belief is that attaining Yoga is difficult for a person with an uncontrolled mind; but it is possible to attain by proper means with a subdued self."}]},{"ch":6,"vn":37,"dev":"अर्जुन उवाच\nअयतिः श्रद्धयोपेतो योगाच्चलितमानसः।\nअप्राप्य योगसंसिद्धिं कां गतिं कृष्ण गच्छति","iast":"arjuna uvācha\nayatiḥ śhraddhayopeto yogāch chalita-mānasaḥ\naprāpya yoga-sansiddhiṁ kāṅ gatiṁ kṛiṣhṇa gachchhati","v":[{"k":"purohit","t":"Arjuna asked: What of him who fails to control himself, whose mind falls from spiritual contemplation, yet retains his faith and does not attain perfection?"},{"k":"sivananda","t":"Arjuna said, \"He who is unable to control himself, even though he has faith, and whose mind wanders away from Yoga, what end does he meet, having failed to attain perfection in Yoga, O Krishna?\""},{"k":"adidevananda","t":"Arjuna said, \"If a person who is possessed of faith but has put in only inadequate effort finds his mind wandering away from Yoga, and then fails to attain perfection—what way does he go, O Krishna?\""},{"k":"gambirananda","t":"Arjuna said, \"O Krsna, what goal does one attain who, despite having faith, fails to achieve perfection in Yoga due to lack of diligence, and whose mind becomes deflected from Yoga?\""},{"k":"sankaranarayan","t":"Arjuna said, \"A person who has faith and is desirous of reaching the path of the good, but whose mind has been severed from Yoga—to which goal does he go, having failed to attain success in Yoga? O Krsna!\""}]},{"ch":6,"vn":38,"dev":"कच्चिन्नोभयविभ्रष्टश्छिन्नाभ्रमिव नश्यति।\nअप्रतिष्ठो महाबाहो विमूढो ब्रह्मणः पथि","iast":"kachchin nobhaya-vibhraṣhṭaśh chhinnābhram iva naśhyati\napratiṣhṭho mahā-bāho vimūḍho brahmaṇaḥ pathi","v":[{"k":"purohit","t":"Having failed in both, my Lord, is he without hope, like a riven cloud with no support, lost on the spiritual path?"},{"k":"sivananda","t":"Fallen from both, does he not perish like a rent cloud, supportless, O mighty-armed one, deluded on the path of Brahman?"},{"k":"adidevananda","t":"Without any support, confused in the path leading to the Brahman, and thus having fallen from both, does he not perish, O mighty-armed one, like a rent cloud?"},{"k":"gambirananda","t":"O Mighty-armed one, having fallen from both [paths], without support, deluded on the path to Brahman, does he not get ruined like a scattered cloud?"},{"k":"sankaranarayan","t":"Does he, fallen from both, get lost like a broken cloud? Or, O mighty-armed one! Having no support, does he meet total destruction?"}]},{"ch":6,"vn":39,"dev":"एतन्मे संशयं कृष्ण छेत्तुमर्हस्यशेषतः।\nत्वदन्यः संशयस्यास्य छेत्ता न ह्युपपद्यते","iast":"etan me sanśhayaṁ kṛiṣhṇa chhettum arhasyaśheṣhataḥ\ntvad-anyaḥ sanśhayasyāsya chhettā na hyupapadyate","v":[{"k":"purohit","t":"My Lord! You are worthy to solve this doubt once and for all; there is no one else competent to do so, save Yourself."},{"k":"sivananda","t":"O Krishna, please completely dispel this doubt of mine, for it is not possible for anyone but You to do so."},{"k":"adidevananda","t":"O Krsna, you should altogether remove this doubt of mine, for there is no other remover of this doubt than you."},{"k":"gambirananda","t":"O Krsna, you should totally eradicate this doubt of mine, for none other than yourself can be the dispeller of this doubt!"},{"k":"sankaranarayan","t":"Please dispel this doubt of mine completely. But for You, O Krsna, no one else is capable of eradicating this doubt."}]},{"ch":6,"vn":40,"dev":"श्री भगवानुवाच\nपार्थ नैवेह नामुत्र विनाशस्तस्य विद्यते।\nनहि कल्याणकृत्कश्िचद्दुर्गतिं तात गच्छति","iast":"śhrī bhagavān uvācha\npārtha naiveha nāmutra vināśhas tasya vidyate\nna hi kalyāṇa-kṛit kaśhchid durgatiṁ tāta gachchhati","v":[{"k":"purohit","t":"Lord Shri Krishna replied: My beloved child! There is no destruction for him, either in this world or the next. No evil fate awaits him who treads the path of righteousness."},{"k":"sivananda","t":"The Blessed Lord said, \"O Arjuna, neither in this world nor in the next will there be destruction for him; none, indeed, who does good, O my son, ever comes to grief.\""},{"k":"adidevananda","t":"The Lord said, \"Neither here in this world nor there in the next is there destruction for him. For no one who does good ever comes to an evil end.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"O Partha, there is certainly no ruin for him here or hereafter, for no one engaged in good meets with a deplorable end, my son!\""},{"k":"sankaranarayan","t":"The Bhagavat said, \"O dear Partha! Neither in this world nor in the other is there destruction for him. Certainly, no one who performs an auspicious act ever comes to a grievous state.\""}]},{"ch":6,"vn":41,"dev":"प्राप्य पुण्यकृतां लोकानुषित्वा शाश्वतीः समाः।\nशुचीनां श्रीमतां गेहे योगभ्रष्टोऽभिजायते","iast":"prāpya puṇya-kṛitāṁ lokān uṣhitvā śhāśhvatīḥ samāḥ\nśhuchīnāṁ śhrīmatāṁ gehe yoga-bhraṣhṭo'bhijāyate","v":[{"k":"purohit","t":"Having reached the worlds where the righteous dwell, and having remained there for many years, he who has strayed from the path of spirituality will be born again into the family of the pure, benevolent, and prosperous."},{"k":"sivananda","t":"Having attained to the worlds of the righteous and having dwelt there for everlasting years, he who fell from Yoga is born in a house of the pure and wealthy."},{"k":"adidevananda","t":"He who has fallen away from Yoga is born again in the house of the pure and prosperous, having attained to the worlds of doers of good deeds and dwelled there for many long years."},{"k":"gambirananda","t":"Attaining the worlds of the righteous and residing there for eternal years, the man who has fallen from Yoga is born in the house of the pious and prosperous."},{"k":"sankaranarayan","t":"Having attained the worlds of those who perform pious acts, and having resided there for years of eternity, the one who has fallen from Yoga is born again in the house of the pure and wealthy."}]},{"ch":6,"vn":42,"dev":"अथवा योगिनामेव कुले भवति धीमताम्।\nएतद्धि दुर्लभतरं लोके जन्म यदीदृशम्","iast":"atha vā yoginām eva kule bhavati dhīmatām\netad dhi durlabhataraṁ loke janma yad īdṛiśham","v":[{"k":"purohit","t":"Or, he may be born in the family of wise sages, though such a birth is indeed very difficult to obtain."},{"k":"sivananda","t":"Or he is born in a family of even the wisest of yogis; verily, such a birth is very difficult to obtain in this world."},{"k":"adidevananda","t":"Or he is born into a family of wise yogis. But such a birth in this world is rare."},{"k":"gambirananda","t":"Or, he is born in the family of wise yogis. Such a birth is indeed more difficult to come by in the world."},{"k":"sankaranarayan","t":"Or, he is born nowhere else but in the family of the intelligent men of Yoga; for, this birth is more difficult to obtain in the world."}]},{"ch":6,"vn":43,"dev":"तत्र तं बुद्धिसंयोगं लभते पौर्वदेहिकम्।\nयतते च ततो भूयः संसिद्धौ कुरुनन्दन","iast":"tatra taṁ buddhi-sanyogaṁ labhate paurva-dehikam\nyatate cha tato bhūyaḥ sansiddhau kuru-nandana","v":[{"k":"purohit","t":"Then, the experience acquired in his former life will revive, and with it, he will more eagerly strive for perfection than before."},{"k":"sivananda","t":"Then he comes into contact with the knowledge acquired in his former body and strives even more for perfection, O Arjuna."},{"k":"adidevananda","t":"There, O Arjuna, he regains the disposition of mind that he had in his former body, and from there he strives even more for success in Yoga."},{"k":"gambirananda","t":"There he becomes endowed with the wisdom acquired in the previous body, and he strives even more than before for perfection, O scion of the Kuru dynasty."},{"k":"sankaranarayan","t":"There, in that life, he regains the link of mentality transmitted from his former body. Consequently, once again he strives for full success, O rejoicer of the Kurus!"}]},{"ch":6,"vn":44,"dev":"पूर्वाभ्यासेन तेनैव ह्रियते ह्यवशोऽपि सः।\nजिज्ञासुरपि योगस्य शब्दब्रह्मातिवर्तते","iast":"pūrvābhyāsena tenaiva hriyate hyavaśho 'pi saḥ\njijñāsur api yogasya śhabda-brahmātivartate","v":[{"k":"purohit","t":"Unconsciously, he will return to the practices of his old life; thus, one who strives to attain spiritual consciousness is certainly superior to one who merely talks about it."},{"k":"sivananda","t":"By that same former practice, he is borne on in spite of himself. Even he who merely wishes to know Yoga goes beyond the Brahmanic word."},{"k":"adidevananda","t":"By the power of his earlier practice, he is carried forward even against his will. Even though he is an enquirer about Yoga, he transcends the Sabda-Brahman, i.e., Prakṛti or matter."},{"k":"gambirananda","t":"For, by that very past practice, he is carried forward even in spite of himself! Even a seeker of Yoga transcends the results of the performance of Vedic rituals!"},{"k":"sankaranarayan","t":"Not being a master of himself, he is only dragged by that former practice (its mental impression); only a seeker of the knowledge of Yoga passes beyond what strengthens the [sacred] text."}]},{"ch":6,"vn":45,"dev":"प्रयत्नाद्यतमानस्तु योगी संशुद्धकिल्बिषः।\nअनेकजन्मसंसिद्धस्ततो याति परां गतिम्","iast":"prayatnād yatamānas tu yogī sanśhuddha-kilbiṣhaḥ\naneka-janma-sansiddhas tato yāti parāṁ gatim","v":[{"k":"purohit","t":"Then, after many lives of earnest striving and absolution of sins, the student of spirituality attains perfection and reaches the Supreme."},{"k":"sivananda","t":"But the Yogi who strives assiduously, purified of sins and perfected gradually over many births, reaches the highest goal."},{"k":"adidevananda","t":"But the yogi, striving earnestly, cleansed of all his stains and perfected through many births, reaches the supreme state."},{"k":"gambirananda","t":"However, the yogi, applying himself assiduously, becoming purified from sin and attaining perfection through many births, they achieve the highest Goal."},{"k":"sankaranarayan","t":"After that, the assiduous man of Yoga, having his sins completely cleansed and being perfected through many births, reaches the Supreme Goal."}]},{"ch":6,"vn":46,"dev":"तपस्विभ्योऽधिको योगी ज्ञानिभ्योऽपि मतोऽधिकः।\nकर्मिभ्यश्चाधिको योगी तस्माद्योगी भवार्जुन","iast":"tapasvibhyo 'dhiko yogī\njñānibhyo 'pi mato 'dhikaḥ\nkarmibhyaśh chādhiko yogī\ntasmād yogī bhavārjuna","v":[{"k":"purohit","t":"The wise person is superior to the ascetic, the scholar, and the man of action; therefore, be thou a wise person, O Arjuna!"},{"k":"sivananda","t":"The yogi is thought to be superior to the ascetics, even superior to those who have knowledge obtained through the study of scriptures; he is also superior to men of action; therefore, be thou a yogi, O Arjuna."},{"k":"adidevananda","t":"Greater than the ascetics, greater than those who possess knowledge, greater than the ritualists is the Yogin. Therefore, O Arjuna, become a Yogin."},{"k":"gambirananda","t":"A yogi is higher than those of austerity; they are considered higher even than those of knowledge. The yogi is also higher than those of action. Therefore, O Arjuna, become a yogi."},{"k":"sankaranarayan","t":"The person of Yoga is superior to the persons of austerities and is considered superior even to the persons of knowledge; and the person of Yoga is superior to the persons of action. Therefore, O Arjuna! you should become a person of Yoga."}]},{"ch":6,"vn":47,"dev":"योगिनामपि सर्वेषां मद्गतेनान्तरात्मना।\nश्रद्धावान्भजते यो मां स मे युक्ततमो मतः","iast":"yoginām api sarveṣhāṁ mad-gatenāntar-ātmanā\nśhraddhāvān bhajate yo māṁ sa me yuktatamo mataḥ","v":[{"k":"purohit","t":"I look upon him as the best of mystics, who, full of faith, worships Me and abides in Me."},{"k":"sivananda","t":"And among all the Yogis, he who, full of faith and with his inner self merged in Me, worships Me is deemed by Me to be the most devoted."},{"k":"adidevananda","t":"He who, with faith, worships Me, and whose innermost self is fixed in Me, I consider him to be the greatest of the Yogins."},{"k":"gambirananda","t":"Even among all the yogis, he who adores Me with his mind fixed on Me and with faith is considered by Me to be the best of the yogis."},{"k":"sankaranarayan","t":"He who has faith and serves Me with his inner self devoted to Me, is considered by Me to be the best of all yogis."}]},{"ch":7,"vn":1,"dev":"श्री भगवानुवाच\nमय्यासक्तमनाः पार्थ योगं युञ्जन्मदाश्रयः।\nअसंशयं समग्रं मां यथा ज्ञास्यसि तच्छृणु","iast":"śhrī bhagavān uvācha\nmayyāsakta-manāḥ pārtha yogaṁ yuñjan mad-āśhrayaḥ\nasanśhayaṁ samagraṁ māṁ yathā jñāsyasi tach chhṛiṇu","v":[{"k":"purohit","t":"Lord Shri Krishna said: Listen, O Arjuna! I will tell you how you can know Me in my full perfection. Practice meditation with your mind devoted to Me and take Me as your refuge."},{"k":"sivananda","t":"The Blessed Lord said, \"O Arjuna, hear how you shall, without doubt, know Me fully, with your mind intent on Me, practicing Yoga and taking refuge in Me.\""},{"k":"adidevananda","t":"The Lord said, \"With your mind focused on Me, taking Me as your support, and practicing yoga—how can you, without doubt, know Me fully? Hear, O Arjuna.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"O Partha, hear how, with your mind fixed on Me, practicing the Yoga of Meditation and taking refuge in Me, you will certainly and fully know Me."},{"k":"sankaranarayan","t":"The Bhagavat said, \"O son of Prtha, hear from Me how, with your mind attached to Me, practicing yoga, and taking refuge in Me, you shall understand Me fully, without any doubt.\""}]},{"ch":7,"vn":2,"dev":"ज्ञानं तेऽहं सविज्ञानमिदं वक्ष्याम्यशेषतः।\nयज्ज्ञात्वा नेह भूयोऽन्यज्ज्ञातव्यमवशिष्यते","iast":"jñānaṁ te 'haṁ sa-vijñānam idaṁ vakṣhyāmyaśheṣhataḥ\nyaj jñātvā neha bhūyo 'nyaj jñātavyam-avaśhiṣhyate","v":[{"k":"purohit","t":"I will reveal this knowledge to you and how it can be realized; once accomplished, there is nothing else worth having in this life."},{"k":"sivananda","t":"I will declare to you in full this knowledge combined with realization, after knowing which nothing else remains to be known here."},{"k":"adidevananda","t":"I will declare to you in full this knowledge of God, along with the knowledge that makes it distinguished, knowing which nothing else remains to be known."},{"k":"gambirananda","t":"I shall tell you in detail of this Knowledge, which is combined with realization, after experiencing which there remains nothing else here to be known."},{"k":"sankaranarayan","t":"I shall teach you this knowledge in full, together with action; for a person who has known this, there remains nothing else to be known in this world."}]},{"ch":7,"vn":3,"dev":"मनुष्याणां सहस्रेषु कश्िचद्यतति सिद्धये।\nयततामपि सिद्धानां कश्िचन्मां वेत्ति तत्त्वतः","iast":"manuṣhyāṇāṁ sahasreṣhu kaśhchid yatati siddhaye\nyatatām api siddhānāṁ kaśhchin māṁ vetti tattvataḥ","v":[{"k":"purohit","t":"Among thousands of men, scarcely one strives for perfection, and even among those who gain occult powers, perhaps only one knows me in truth."},{"k":"sivananda","t":"Among thousands of men, one may perchance strive for perfection; even among those successful strivers, only one may perchance know Me in essence."},{"k":"adidevananda","t":"Among thousands of men, some strive for perfection; even among those who strive for perfection, only some know Me; and among those who know Me, only some truly know Me."},{"k":"gambirananda","t":"Among thousands of men, a rare one endeavors for perfection. Even among the perfected ones who are diligent, one perchance knows Me in truth."},{"k":"sankaranarayan","t":"Among thousands of men, perhaps one makes an effort for the determined knowledge. Among those, even though they make an effort, perhaps one realizes Me correctly with the determined knowledge."}]},{"ch":7,"vn":4,"dev":"भूमिरापोऽनलो वायुः खं मनो बुद्धिरेव च।\nअहङ्कार इतीयं मे भिन्ना प्रकृतिरष्टधा","iast":"bhūmir-āpo 'nalo vāyuḥ khaṁ mano buddhir eva cha\nahankāra itīyaṁ me bhinnā prakṛitir aṣhṭadhā","v":[{"k":"purohit","t":"Earth, water, fire, air, ether, mind, intellect, and personality—this is the eightfold division of My manifested nature."},{"k":"sivananda","t":"Earth, water, fire, air, ether, mind, intellect, and egoism—thus is My Nature divided eightfold."},{"k":"adidevananda","t":"Earth, water, fire, air, ether, Manas, Buddhi, and the ego-sense—thus My Prakriti is divided into eight parts."},{"k":"gambirananda","t":"This Prakrti of Mine is divided eightfold thus: earth, water, fire, air, space, mind, intellect, and egoism."},{"k":"sankaranarayan","t":"My nature is divided into eight parts: Earth, Water, Fire, Wind, Ether, Mind, Intellect, and Ego."}]},{"ch":7,"vn":5,"dev":"अपरेयमितस्त्वन्यां प्रकृतिं विद्धि मे पराम्।\nजीवभूतां महाबाहो ययेदं धार्यते जगत्","iast":"apareyam itas tvanyāṁ prakṛitiṁ viddhi me parām\njīva-bhūtāṁ mahā-bāho yayedaṁ dhāryate jagat","v":[{"k":"purohit","t":"This is My inferior nature; however, O valiant one, know that distinct from this is My superior nature, which is the very life that sustains the universe."},{"k":"sivananda","t":"O mighty-armed Arjuna, this is the inferior Prakriti; know it as distinct from My higher Prakriti, the very life-element, by which this world is upheld."},{"k":"adidevananda","t":"This is My lower Prakṛti. But, O mighty-armed one, know that My higher nature is another. It is the life-principle (Jīva-bhūta), by which this universe is sustained."},{"k":"gambirananda","t":"O mighty-armed one, this is the inferior Prakrti. Know the other Prakrti of Mine, which is however higher than this, which has taken the form of individual souls, and by which this world is upheld."},{"k":"sankaranarayan","t":"This is My lower nature. My superior nature, which has become the individual Soul and by which this world is maintained, is not different from this. O mighty-armed Arjuna, you must know this."}]},{"ch":7,"vn":6,"dev":"एतद्योनीनि भूतानि सर्वाणीत्युपधारय।\nअहं कृत्स्नस्य जगतः प्रभवः प्रलयस्तथा","iast":"etad-yonīni bhūtāni sarvāṇītyupadhāraya\nahaṁ kṛitsnasya jagataḥ prabhavaḥ pralayas tathā","v":[{"k":"purohit","t":"It is the womb of all beings; for I am He by Whom the worlds were created and shall be dissolved."},{"k":"sivananda","t":"Know that these two are the womb of all beings; thus, I am the source and dissolution of the whole universe."},{"k":"adidevananda","t":"Know that all beings have these two as the source of their birth. Therefore, I am the origin and the dissolver of the whole universe."},{"k":"gambirananda","t":"Understand thus that all things—sentient and insentient—have these as their source. I am the origin as well as the end of the entire universe."},{"k":"sankaranarayan","t":"All beings are born from this womb; hence, keep them close. I am the origin and dissolution of the entire world."}]},{"ch":7,"vn":7,"dev":"मत्तः परतरं नान्यत्किञ्चिदस्ति धनञ्जय।\nमयि सर्वमिदं प्रोतं सूत्रे मणिगणा इव","iast":"mattaḥ parataraṁ nānyat kiñchid asti dhanañjaya\nmayi sarvam idaṁ protaṁ sūtre maṇi-gaṇā iva","v":[{"k":"purohit","t":"O Arjuna! There is nothing higher than Me; all is strung on Me like rows of pearls on a thread."},{"k":"sivananda","t":"There is nothing higher than Me, O Arjuna. All this is strung on Me, like clusters of gems on a string."},{"k":"adidevananda","t":"There is nothing higher than Me, O Arjuna. All this is strung on Me, like rows of gems on a thread."},{"k":"gambirananda","t":"O Dhananjaya, there is nothing else higher than Myself. All this is strung on Me like pearls on a string."},{"k":"sankaranarayan","t":"There is nothing beyond Me, O Dhananjaya; all this is strung on Me, just as pearls are strung on a string."}]},{"ch":7,"vn":8,"dev":"रसोऽहमप्सु कौन्तेय प्रभास्मि शशिसूर्ययोः।\nप्रणवः सर्ववेदेषु शब्दः खे पौरुषं नृषु","iast":"raso 'ham apsu kaunteya prabhāsmi śhaśhi-sūryayoḥ\npraṇavaḥ sarva-vedeṣhu śhabdaḥ khe pauruṣhaṁ nṛiṣhu","v":[{"k":"purohit","t":"O Arjuna! I am the fluidity in water, the light in the sun and moon, the mystic syllable Om in the Vedic scriptures, the sound in ether, and the virility in man."},{"k":"sivananda","t":"I am the flavor in water, O Arjuna; I am the light in the moon and the sun; I am the syllable Om in all the Vedas, sound in the ether and virility in men."},{"k":"adidevananda","t":"I am the taste in the waters, O Arjuna! I am the light in the sun and the moon; the sacred syllable Om in all the Vedas; sound in the ether; and manhood in men, I am."},{"k":"gambirananda","t":"O son of Kunti, I am the taste of water, I am the effulgence of the moon and the sun; the letter 'Om' in all the Vedas, the sound in space, and manhood in men."},{"k":"sankaranarayan","t":"O son of Kunti! I am the taste in waters, the light in the moon and sun, the best hymn (OM) in the entire Vedas, the sound that exists in the ether, and the manly vigor in men."}]},{"ch":7,"vn":9,"dev":"पुण्यो गन्धः पृथिव्यां च तेजश्चास्मि विभावसौ।\nजीवनं सर्वभूतेषु तपश्चास्मि तपस्विषु","iast":"puṇyo gandhaḥ pṛithivyāṁ cha tejaśh chāsmi vibhāvasau\njīvanaṁ sarva-bhūteṣhu tapaśh chāsmi tapasviṣhu","v":[{"k":"purohit","t":"I am the fragrance of the earth, the brilliance of fire, the life force in all beings, and the austerity of ascetics."},{"k":"sivananda","t":"I am the sweet fragrance in the earth and the brilliance in the fire, the life in all beings, and I am the austerity of ascetics."},{"k":"adidevananda","t":"I am the pure scent in the earth; I am the radiance in the fire; I am the life-force in all beings, and austerity in ascetics."},{"k":"gambirananda","t":"I am also the sweet fragrance in the earth; I am the brilliance in the fire, and the life in all beings; and I am the austerity of the ascetics."},{"k":"sankaranarayan","t":"I am the pure scent in the earth; I am also the radiance in the sun; I am the life in all beings and the austerity in the ascetics."}]},{"ch":7,"vn":10,"dev":"बीजं मां सर्वभूतानां विद्धि पार्थ सनातनम्।\nबुद्धिर्बुद्धिमतामस्मि तेजस्तेजस्विनामहम्","iast":"bījaṁ māṁ sarva-bhūtānāṁ viddhi pārtha sanātanam\nbuddhir buddhimatām asmi tejas tejasvinām aham","v":[{"k":"purohit","t":"Know, O Arjuna, that I am the eternal seed of being; I am the intelligence of the intelligent, the splendour of the resplendent."},{"k":"sivananda","t":"Know Me, O Arjuna, as the eternal seed of all beings; I am the intelligence of the intelligent, and the splendour of the splendid objects."},{"k":"adidevananda","t":"Know Me, O Arjuna, to be the primeval seed of all beings. I am the intelligence of the discerning and the brilliance of the brilliant."},{"k":"gambirananda","t":"O Partha, know Me to be the eternal seed of all beings. I am the intellect of the intelligent, and I am the courage of the courageous."},{"k":"sankaranarayan","t":"O son of Prtha! Know Me as the eternal seed of all beings; I am the intellect of the intellectuals and the brilliance of the brilliant."}]},{"ch":7,"vn":11,"dev":"बलं बलवतां चाहं कामरागविवर्जितम्।\nधर्माविरुद्धो भूतेषु कामोऽस्मि भरतर्षभ","iast":"balaṁ balavatāṁ chāhaṁ kāma-rāga-vivarjitam\ndharmāviruddho bhūteṣhu kāmo 'smi bharatarṣhabha","v":[{"k":"purohit","t":"I am the strength of the strong, those who are free from attachment and desire; and, O Arjuna, I am the desire for righteousness."},{"k":"sivananda","t":"Of the strong, I am the strength devoid of desire and attachment, and in all beings, I am the desire in accordance with Dharma, O Arjuna."},{"k":"adidevananda","t":"In the strong, I am strength, devoid of desire and passion. In all beings, I am the desire which is not contrary to Dharma, O Arjuna."},{"k":"gambirananda","t":"And of the strong, I am the strength that is devoid of passion and attachment. Among creatures, I am desire that is not contrary to righteousness, O scion of the Bharata dynasty."},{"k":"sankaranarayan","t":"Of the strong, I am the strength that is free from desire and attachment. O best of the Bharatas, in all beings, I am the desire that is not contrary to dharma."}]},{"ch":7,"vn":12,"dev":"ये चैव सात्त्विका भावा राजसास्तामसाश्च ये।\nमत्त एवेति तान्विद्धि नत्वहं तेषु ते मयि","iast":"ye chaiva sāttvikā bhāvā rājasās tāmasāśh cha ye\nmatta eveti tān viddhi na tvahaṁ teṣhu te mayi","v":[{"k":"purohit","t":"Whatever be the nature of their life, whether it be pure, passionate, or ignorant, they are all derived from Me. They are in Me, but I am not in them."},{"k":"sivananda","t":"Whatever beings (and objects) that are pure, active, and inert, know that they proceed from Me. They are in Me, yet I am not in them."},{"k":"adidevananda","t":"Know that all those states of Sattva, Rajas, and Tamas are from Me alone; however, I am not in them; rather, they are in Me."},{"k":"gambirananda","t":"Those things that are made of the quality of sattva, and those things that are made of the quality of rajas and tamas, know them to have sprung from Me alone. However, I am not in them; they are within Me!"},{"k":"sankaranarayan","t":"Whatever beings are there—whether they are of the Sattva, Rajas, or Tamas strands—be sure that they are from Me; I am not in them, but they are within Me."}]},{"ch":7,"vn":13,"dev":"त्रिभिर्गुणमयैर्भावैरेभिः सर्वमिदं जगत्।\nमोहितं नाभिजानाति मामेभ्यः परमव्ययम्","iast":"tribhir guṇa-mayair bhāvair ebhiḥ sarvam idaṁ jagat\nmohitaṁ nābhijānāti māmebhyaḥ param avyayam","v":[{"k":"purohit","t":"The inhabitants of the world, misled by the natures engendered by the Qualities, do not know that I am higher than them all and that I do not change."},{"k":"sivananda","t":"Deluded by these Natures, composed of the three qualities of Nature, all this world does not know Me as distinct from them and immutable."},{"k":"adidevananda","t":"The entire universe is deluded by these three states originating from the Gunas (of Prakrti), and fails to recognize Me, who am beyond them and immutable."},{"k":"gambirananda","t":"All this world, deluded as it is by these three qualities made of the gunas, does not know Me, who am transcendental to these and undecaying."},{"k":"sankaranarayan","t":"Being deluded by these three strands of nature, this entire world does not recognize Me, who am eternal and transcend these strands."}]},{"ch":7,"vn":14,"dev":"दैवी ह्येषा गुणमयी मम माया दुरत्यया।\nमामेव ये प्रपद्यन्ते मायामेतां तरन्ति ते","iast":"daivī hyeṣhā guṇa-mayī mama māyā duratyayā\nmām eva ye prapadyante māyām etāṁ taranti te","v":[{"k":"purohit","t":"Verily, this divine illusion of phenomenon manifesting itself in the qualities is difficult to surmount. Only they who devote themselves exclusively to Me can accomplish it."},{"k":"sivananda","t":"Verily, this divine illusion of Mine, composed of the three qualities, is difficult to cross over; those who take refuge in Me alone, can cross over this illusion."},{"k":"adidevananda","t":"(a) For this divine Maya or Mine, consisting of the three Gunas (assumed for purposes of sport), is hard to overcome.\n৷৷\n(b) ৷৷ But those who take refuge in Me alone shall pass beyond the Maya."},{"k":"gambirananda","t":"Since this divine Maya of Mine, which is constituted by the gunas, is difficult to cross over, those who take refuge in Me alone can transcend this Maya."},{"k":"sankaranarayan","t":"This is My divine play, composed of the strands of illusion, and it is hard to cross over. Those who take refuge in Me alone, they cross over the illusion."}]},{"ch":7,"vn":15,"dev":"न मां दुष्कृतिनो मूढाः प्रपद्यन्ते नराधमाः।\nमाययापहृतज्ञाना आसुरं भावमाश्रिताः","iast":"na māṁ duṣhkṛitino mūḍhāḥ prapadyante narādhamāḥ\nmāyayāpahṛita-jñānā āsuraṁ bhāvam āśhritāḥ","v":[{"k":"purohit","t":"The sinner, the ignorant, the vile, deprived of spiritual perception by the glamour of illusion, and he who leads a godless life—none of them shall find me."},{"k":"sivananda","t":"The evil-doers and the deluded, who are the lowest of men, do not seek Me; those whose knowledge is destroyed by illusion follow the ways of demons."},{"k":"adidevananda","t":"The evil-doers, the foolish, the lowest of men, those persons deprived of knowledge by delusion (Maya) and those who are dominated by a demoniac nature - they do not seek refuge in Me."},{"k":"gambirananda","t":"The foolish evildoers, who are the most depraved among men, who are deprived of their wisdom by Maya, and who resort to demonic ways, do not take refuge in Me."},{"k":"sankaranarayan","t":"The deluded evil-doers, the vilest of men, who are robbed of knowledge by the trick of illusion and have taken refuge in the demonic nature—they do not resort to Me."}]},{"ch":7,"vn":16,"dev":"चतुर्विधा भजन्ते मां जनाः सुकृतिनोऽर्जुन।\nआर्तो जिज्ञासुरर्थार्थी ज्ञानी च भरतर्षभ","iast":"chatur-vidhā bhajante māṁ janāḥ sukṛitino 'rjuna\nārto jijñāsur arthārthī jñānī cha bharatarṣhabha","v":[{"k":"purohit","t":"O Arjuna! The righteous who worship Me are grouped in stages: first, those who suffer, next those who desire knowledge, then those who thirst after truth, and lastly those who attain wisdom."},{"k":"sivananda","t":"Four kinds of virtuous men worship Me, O Arjuna, and they are the distressed, the seekers of knowledge, the seekers of wealth, and the wise, O Lord of the Bharatas."},{"k":"adidevananda","t":"Four types of men of good deeds worship Me, O Arjuna: the distressed, the seekers of knowledge, the seekers of wealth, and the men of knowledge."},{"k":"gambirananda","t":"O Arjuna, foremost of the Bharata dynasty, four classes of people of virtuous deeds adore Me: the afflicted, the seekers of Knowledge, the seekers of wealth, and the man of Knowledge."},{"k":"sankaranarayan","t":"Men of good action who always worship Me are of four types: the afflicted, the seeker of knowledge, the seeker of wealth, and the man of wisdom, O best among the Bharatas!"}]},{"ch":7,"vn":17,"dev":"तेषां ज्ञानी नित्ययुक्त एकभक्ितर्विशिष्यते।\nप्रियो हि ज्ञानिनोऽत्यर्थमहं स च मम प्रियः","iast":"teṣhāṁ jñānī nitya-yukta eka-bhaktir viśhiṣhyate\npriyo hi jñānino 'tyartham ahaṁ sa cha mama priyaḥ","v":[{"k":"purohit","t":"Of all these, he who has gained wisdom, who meditates on Me without ceasing, devoting himself solely to Me, is the best; for I am exceedingly beloved by the wise man, and the wise man is also beloved by Me."},{"k":"sivananda","t":"Of them, the wise who are ever steadfast and devoted to the One, excel; for I am exceedingly dear to the wise, and they are dear to Me."},{"k":"adidevananda","t":"Of these, the man of knowledge, who is ever with Me in Yoga and devoted to the One only, is the foremost; for I am very dear to the man of knowledge, and he is also dear to Me."},{"k":"gambirananda","t":"Of them, the man of knowledge, endowed with constant steadfastness and one-pointed devotion, excels. For I am very dear to the man of knowledge, and he too is dear to me."},{"k":"sankaranarayan","t":"Of them, the man of wisdom, being always attached to Me with single-pointed devotion, excels. For, I am dear to the man of wisdom above all personal gains, and he is dear to Me."}]},{"ch":7,"vn":18,"dev":"उदाराः सर्व एवैते ज्ञानी त्वात्मैव मे मतम्।\nआस्थितः स हि युक्तात्मा मामेवानुत्तमां गतिम्","iast":"udārāḥ sarva evaite jñānī tvātmaiva me matam\nāsthitaḥ sa hi yuktātmā mām evānuttamāṁ gatim","v":[{"k":"purohit","t":"Noble-minded are they all, but the wise man I hold as my own self; for he, remaining always at peace with me, makes me his ultimate goal."},{"k":"sivananda","t":"Indeed, all these are noble; however, I consider the wise man as My very Self; for, he is steadfast in mind and established in Me alone as the supreme goal."},{"k":"adidevananda","t":"All these are indeed generous, but I deem the man of knowledge to be My very self; for he, integrated, is devoted solely to Me as the highest end."},{"k":"gambirananda","t":"Indeed, all of these are noble, but the man of Knowledge is the Self itself. This is my opinion. For, with a steadfast mind, he is set on the path leading only to Me, who am the supreme Goal."},{"k":"sankaranarayan","t":"All these are indeed noble persons. But the man of wisdom is considered as the very Soul of Mine. For, with his self (mind) that has mastered the Yoga, he has resorted to Me alone as his most supreme goal."}]},{"ch":7,"vn":19,"dev":"बहूनां जन्मनामन्ते ज्ञानवान्मां प्रपद्यते।\nवासुदेवः सर्वमिति स महात्मा सुदुर्लभः","iast":"bahūnāṁ janmanām ante jñānavān māṁ prapadyate\nvāsudevaḥ sarvam iti sa mahātmā su-durlabhaḥ","v":[{"k":"purohit","t":"After many lives, at last the wise one realizes Me as I am. It is very difficult to find a man so enlightened that he sees God everywhere."},{"k":"sivananda","t":"At the end of many births, the wise man comes to Me, realizing that all this is Vaasudeva (the innermost Self); such a great soul (Mahatma) is very hard to find."},{"k":"adidevananda","t":"At the end of many births, the man of knowledge finds refuge in Me, realizing that 'Vasudeva is all.' It is very difficult to find such a great-souled person."},{"k":"gambirananda","t":"At the end of many births, the man of knowledge attains Me, realizing that Vasudeva is all. Such a high-souled one is very rare."},{"k":"sankaranarayan","t":"At the end of many births, one attains Me with the conviction that 'All is Vasudeva'- that noble soul is very difficult to attain."}]},{"ch":7,"vn":20,"dev":"कामैस्तैस्तैर्हृतज्ञानाः प्रपद्यन्तेऽन्यदेवताः।\nतं तं नियममास्थाय प्रकृत्या नियताः स्वया","iast":"kāmais tais tair hṛita-jñānāḥ prapadyante 'nya-devatāḥ\ntaṁ taṁ niyamam āsthāya prakṛityā niyatāḥ svayā","v":[{"k":"purohit","t":"They in whom wisdom is obscured by one desire or another, worship the lesser powers, practicing many rites that vary according to their temperaments."},{"k":"sivananda","t":"Those whose wisdom has been taken away by this or that desire, go to other gods, following this or that rite, led by their own nature."},{"k":"adidevananda","t":"Controlled by their inherent nature, and deprived of knowledge by various desires, worldly-minded people resort to other gods, observing various disciplines."},{"k":"gambirananda","t":"People, deprived of their wisdom by desires for various objects and guided by their own nature, resort to other deities, following the relevant methods."},{"k":"sankaranarayan","t":"Being robbed of their wisdom by innumerable desires and controlled by their own nature, persons take refuge in other deities, following one or the other religious regulations."}]},{"ch":7,"vn":21,"dev":"यो यो यां यां तनुं भक्तः श्रद्धयार्चितुमिच्छति।\nतस्य तस्याचलां श्रद्धां तामेव विदधाम्यहम्","iast":"yo yo yāṁ yāṁ tanuṁ bhaktaḥ śhraddhayārchitum ichchhati\ntasya tasyāchalāṁ śhraddhāṁ tām eva vidadhāmyaham","v":[{"k":"purohit","t":"But whatever form of worship, if the devotee has faith, then I set My own seal upon their faith in that worship."},{"k":"sivananda","t":"Whatever form any devotee desires to worship with faith, I make that same faith of his firm and unflinching."},{"k":"adidevananda","t":"Whichever devotee seeks to worship with faith whatever form, I make their faith steadfast."},{"k":"gambirananda","t":"Whichever form of a deity any devotee wants to worship with faith, I strengthen that very firm faith of theirs."},{"k":"sankaranarayan","t":"Whatever form of deity a devotee, whomever they may be, desires to worship with faith, I assume that form which is firm and is according to their faith."}]},{"ch":7,"vn":22,"dev":"स तया श्रद्धया युक्तस्तस्याराधनमीहते।\nलभते च ततः कामान्मयैव विहितान् हि तान्","iast":"sa tayā śhraddhayā yuktas tasyārādhanam īhate\nlabhate cha tataḥ kāmān mayaiva vihitān hi tān","v":[{"k":"purohit","t":"If he worships one form alone with real faith, then his desires shall be fulfilled through that alone; for thus I have ordained."},{"k":"sivananda","t":"Endowed with that faith, he engages in the worship of that form and obtains his desired outcome, which is ordained by Me alone."},{"k":"adidevananda","t":"Endowed with that faith, he worships that form and thereby gets the objects of his desire, granted in reality by Me alone."},{"k":"gambirananda","t":"Being imbued with that faith, that person engages in worshipping that form, and they get those very desired results as dispensed by Me alone."},{"k":"sankaranarayan","t":"Endowed with that faith, he seeks to worship that deity and thereby receives his desired objects, which are ordained by none other than Me."}]},{"ch":7,"vn":23,"dev":"अन्तवत्तु फलं तेषां तद्भवत्यल्पमेधसाम्।\nदेवान्देवयजो यान्ति मद्भक्ता यान्ति मामपि","iast":"antavat tu phalaṁ teṣhāṁ tad bhavatyalpa-medhasām\ndevān deva-yajo yānti mad-bhaktā yānti mām api","v":[{"k":"purohit","t":"The fruit that comes to people of limited insight is, after all, finite. Those who worship the Lower Powers attain them; but those who worship Me come to Me alone."},{"k":"sivananda","t":"Verily, the reward (fruit) that accrues to those men of small intelligence is finite. The worshippers of the gods go to them, whereas My devotees come to Me."},{"k":"adidevananda","t":"But the fruit gained by these men of small understanding is limited. The worshippers of the gods will go to the gods, but My devotees will come to Me."},{"k":"gambirananda","t":"The result of those who are of poor intellect is indeed limited. The worshippers of gods go to the gods, while My devotees go to Me alone."},{"k":"sankaranarayan","t":"But the fruit of those of poor intellect is finite; those who perform sacrifices aiming at the gods go to the gods, and My devotees come to Me."}]},{"ch":7,"vn":24,"dev":"अव्यक्तं व्यक्ितमापन्नं मन्यन्ते मामबुद्धयः।\nपरं भावमजानन्तो ममाव्ययमनुत्तमम्","iast":"avyaktaṁ vyaktim āpannaṁ manyante mām abuddhayaḥ\nparaṁ bhāvam ajānanto mamāvyayam anuttamam","v":[{"k":"purohit","t":"The ignorant think of Me, who am the Unmanifested Spirit, as if I were in human form. They do not understand that My Superior Nature is unchanging and most excellent."},{"k":"sivananda","t":"The foolish think of Me, the Unmanifest, as having manifestation, not knowing My higher, immutable, and most excellent nature."},{"k":"adidevananda","t":"Not knowing My higher, immutable, and unsurpassed nature, the ignorant think of Me as an entity that has now become manifest, though I was previously unmanifest."},{"k":"gambirananda","t":"The unintelligent, unaware of My supreme state which is immutable and unsurpassable, think of Me as having become manifest from the unmanifest."},{"k":"sankaranarayan","t":"Those of poor intellect are not aware of My higher, unchanging, and supreme nature; and thus, they consider Me, the Unmanifest, to be manifest."}]},{"ch":7,"vn":25,"dev":"नाहं प्रकाशः सर्वस्य योगमायासमावृतः।\nमूढोऽयं नाभिजानाति लोको मामजमव्ययम्","iast":"nāhaṁ prakāśhaḥ sarvasya yoga-māyā-samāvṛitaḥ\nmūḍho 'yaṁ nābhijānāti loko mām ajam avyayam","v":[{"k":"purohit","t":"I am not visible to all, for I am enveloped by the illusion of the Phenomenon. This deluded world does not know Me as the Unborn and Imperishable."},{"k":"sivananda","t":"I am not manifest to all, veiled as I am by the Yoga-Maya. This deluded world does not know Me, who am unborn and imperishable."},{"k":"adidevananda","t":"Veiled by my Maya, I am not manifest to all; this deluded world does not recognize me as the unborn and immutable."},{"k":"gambirananda","t":"Being enveloped by yoga-maya, I do not become manifest to all. This deluded world does not know Me, who am birthless and undecaying."},{"k":"sankaranarayan","t":"Being surrounded by the trick of yoga-illusion, I am not clear to all; hence, this deluded world of perceivers does not recognize Me, the unborn and undying."}]},{"ch":7,"vn":26,"dev":"वेदाहं समतीतानि वर्तमानानि चार्जुन।\nभविष्याणि च भूतानि मां तु वेद न कश्चन","iast":"vedāhaṁ samatītāni vartamānāni chārjuna\nbhaviṣhyāṇi cha bhūtāni māṁ tu veda na kaśhchana","v":[{"k":"purohit","t":"I know, O Arjuna, all beings in the past, the present, and the future; but they do not know Me."},{"k":"sivananda","t":"I know, O Arjuna, the beings of the past, the present, and the future; however, no one knows Me."},{"k":"adidevananda","t":"I know all beings, O Arjuna, past, present, and those to come; but no one knows Me."},{"k":"gambirananda","t":"O Arjuna, I know the past, present, and future beings; but no one knows Me!"},{"k":"sankaranarayan","t":"O Arjuna, I know the beings that have gone, that are present, and those yet to be born; but no one knows Me."}]},{"ch":7,"vn":27,"dev":"इच्छाद्वेषसमुत्थेन द्वन्द्वमोहेन भारत।\nसर्वभूतानि संमोहं सर्गे यान्ति परन्तप","iast":"ichchhā-dveṣha-samutthena dvandva-mohena bhārata\nsarva-bhūtāni sammohaṁ sarge yānti parantapa","v":[{"k":"purohit","t":"O brave Arjuna! Man lives in a fantastical world, deceived by the glamour of opposing sensations, infatuated by desire and aversion."},{"k":"sivananda","t":"O Bharata, all beings are subject to delusion at birth due to the delusion of the pairs of opposites arising from desire and aversion, O Parantapa."},{"k":"adidevananda","t":"O Arjuna, all beings are deluded as soon as they are born, due to the delusion of the pairs of opposites springing from desire and hate."},{"k":"gambirananda","t":"O scion of the Bharata dynasty, O destroyer of foes, due to the delusion of duality arising from likes and dislikes, all creatures become bewildered upon their birth."},{"k":"sankaranarayan","t":"O descendant of Bharata, O scorcher of foes! At the time of creation, all beings become deluded due to the illusion of pairs of opposites arising from desire and hatred."}]},{"ch":7,"vn":28,"dev":"येषां त्वन्तगतं पापं जनानां पुण्यकर्मणाम्।\nते द्वन्द्वमोहनिर्मुक्ता भजन्ते मां दृढव्रताः","iast":"yeṣhāṁ tvanta-gataṁ pāpaṁ janānāṁ puṇya-karmaṇām\nte dvandva-moha-nirmuktā bhajante māṁ dṛiḍha-vratāḥ","v":[{"k":"purohit","t":"But those who act righteously, in whom sin has been destroyed, who are free from the infatuation of conflicting emotions, they worship Me with a firm resolve."},{"k":"sivananda","t":"But those men of virtuous deeds, whose sins have come to an end and who are freed from the delusion of the pairs of opposites, worship Me steadfastly, with their vows."},{"k":"adidevananda","t":"But those who have done good deeds, whose sins have come to an end, are freed from the delusion of the pairs of opposites. They steadfastly worship Me, adhering to their vows."},{"k":"gambirananda","t":"On the other hand, those persons who have done virtuous deeds, whose sin has come to an end, they, being free from the delusion of duality and firm in their convictions, adore Me."},{"k":"sankaranarayan","t":"But those men of virtuous deeds, whose sin has come to an end—they, being free from the delusion of pairs [of opposites], worship Me with a firm resolve."}]},{"ch":7,"vn":29,"dev":"जरामरणमोक्षाय मामाश्रित्य यतन्ति ये।\nते ब्रह्म तद्विदुः कृत्स्नमध्यात्मं कर्म चाखिलम्","iast":"jarā-maraṇa-mokṣhāya mām āśhritya yatanti ye\nte brahma tadviduḥ kṛitsnam adhyātmaṁ karma chākhilam","v":[{"k":"purohit","t":"Those who make Me their refuge, striving for liberation from decay and death, realize the Supreme Spirit, which is their own real Self, and in which all action finds its consummation."},{"k":"sivananda","t":"Those who strive for liberation from old age and death, taking refuge in Me, realize in full that Brahman, the whole knowledge of the Self, and all action."},{"k":"adidevananda","t":"Those who take refuge in Me and strive for deliverance from old age and death, know Brahman (or the Self) and all about the nature of that Self, and the entire Karma (or activities leading to rebirth)."},{"k":"gambirananda","t":"Those who strive by resorting to Me for becoming free from old age and death, they know Brahman, the individual Self, and all about actions. [They know Brahman as being all the individual entities and all actions. This verse prescribes meditation on the qualified Brahman for aspirants of the middle class. Verses beginning with the 14th speak about the realization of the unqualified Brahman by aspirants of the highest class.]"},{"k":"sankaranarayan","t":"Those who, relying on Me, strive to achieve freedom from old age and death, realize all to be the Brahman and realize all the actions governing the Self."}]},{"ch":7,"vn":30,"dev":"साधिभूताधिदैवं मां साधियज्ञं च ये विदुः।\nप्रयाणकालेऽपि च मां ते विदुर्युक्तचेतसः","iast":"sādhibhūtādhidaivaṁ māṁ sādhiyajñaṁ cha ye viduḥ\nprayāṇa-kāle 'pi cha māṁ te vidur yukta-chetasaḥ","v":[{"k":"purohit","t":"Those who see Me in the life of the world, in the universal sacrifice, and as pure Divinity, keeping their minds steady, they live in Me even in the hour of death's approach."},{"k":"sivananda","t":"Those who know Me with the Adhibhuta (pertaining to the elements), Adhidaiva (pertaining to the gods), and the Adhiyajna (pertaining to the sacrifice) know Me even at the time of death, remaining steadfast in mind."},{"k":"adidevananda","t":"And those who know Me with the Adhibhuta, Adhidaiva, and Adhiyajna, they too, with their minds fixed in meditation, know Me even at the hour of death."},{"k":"gambirananda","t":"Those who know me as existing in both the physical and divine planes, and also in the context of the sacrifice, they with concentrated minds know me even at the time of death."},{"k":"sankaranarayan","t":"Those who realize Me as one [identical] with what governs the beings, deities, and with what governs the sacrifices—they, even at the moment of their departure, experience Me, having mastered the Yoga."}]},{"ch":8,"vn":1,"dev":"अर्जुन उवाच\nकिं तद्ब्रह्म किमध्यात्मं किं कर्म पुरुषोत्तम।\nअधिभूतं च किं प्रोक्तमधिदैवं किमुच्यते","iast":"arjuna uvācha\nkiṁ tad brahma kim adhyātmaṁ kiṁ karma puruṣhottama\nadhibhūtaṁ cha kiṁ proktam adhidaivaṁ kim uchyate","v":[{"k":"purohit","t":"Arjuna asked: O Lord of Lords! What is that which people call the Supreme Spirit, what is humanity's spiritual nature, and what is the law? What is matter and what is divinity?"},{"k":"sivananda","t":"Arjuna said, \"What is Brahman? What is Adhyatma? What is action, O best among men? What is Adhibhuta declared to be? And, what is Adhidaiva said to be?\""},{"k":"adidevananda","t":"Arjuna said, O Supreme Person, what is Brahman? What exists in the individual plane? What is action? What is said to exist in the physical plane? And what is said to exist in the divine plane?"},{"k":"gambirananda","t":"Arjuna said, O Supreme Person, what is Brahman? What exists in the individual plane? What is action? What is said to exist in the physical plane? And what is said to exist in the divine plane?"},{"k":"sankaranarayan","t":"Arjuna said, \"What is Brahman? What is known as the Lord of the Self (Adhyatma)? What is action? O Best of Persons, what is said to be the Lord of material things (Adhibhuta)? What is called the Lord of divinities (Adhidaiva)?\""}]},{"ch":8,"vn":2,"dev":"अधियज्ञः कथं कोऽत्र देहेऽस्मिन्मधुसूदन।\nप्रयाणकाले च कथं ज्ञेयोऽसि नियतात्मभिः","iast":"adhiyajñaḥ kathaṁ ko 'tra dehe 'smin madhusūdana\nprayāṇa-kāle cha kathaṁ jñeyo 'si niyatātmabhiḥ","v":[{"k":"purohit","t":"Who rules the spirit sacrifice in many, and how may those who have learned self-control come to the knowledge of Thee at the time of death?"},{"k":"sivananda","t":"Who and how is Adhiyajna here in this body, O destroyer of Madhu? And how, at the time of death, are You to be known by the self-controlled?"},{"k":"adidevananda","t":"O Madhusudana, how is the entity existing in the sacrifice here in this body, and who is it? And how are You to be known by people of concentrated minds at the time of death?"},{"k":"gambirananda","t":"O Madhusudana, how is the entity existing in the sacrifice here in this body, and who is it? And how are You to be known by people of concentrated minds at the time of death?"},{"k":"sankaranarayan","t":"Who is the Lord of Sacrifices, and how? Who is in this body? O slayer of Madhu, how can the self-controlled realize You at the time of their journey (i.e., death)?"}]},{"ch":8,"vn":3,"dev":"श्री भगवानुवाच\nअक्षरं ब्रह्म परमं स्वभावोऽध्यात्ममुच्यते।\nभूतभावोद्भवकरो विसर्गः कर्मसंज्ञितः","iast":"śhrī bhagavān uvācha\nakṣharaṁ brahma paramaṁ svabhāvo 'dhyātmam uchyate\nbhūta-bhāvodbhava-karo visargaḥ karma-sanjñitaḥ","v":[{"k":"purohit","t":"The Lord Shri Krishna replied: The Supreme Spirit is the Highest Imperishable Self, and Its nature is spiritual consciousness. The worlds have been created and are sustained by an emanation from the Spirit, which is called the Law."},{"k":"sivananda","t":"The Blessed Lord said, \"Brahman is the Imperishable, the Supreme; its essential nature is called Self-knowledge; the offering (to the gods) that causes the existence and manifestation of beings and sustains them is called action.\""},{"k":"adidevananda","t":"The Blessed Lord said, \"The Immutable is the supreme Brahman; selfhood is said to be the entity present in the individual plane. By action is meant the offerings that bring about the origin of existence of things.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"The Immutable is the supreme Brahman; selfhood is said to be the entity present in the individual plane. By action is meant the offerings that bring about the origin of existence of things.\""},{"k":"sankaranarayan","t":"The Bhagavat said, \"The immutable Absolute is the Brahman. Its intrinsic nature is called the Lord of the Self. The emitting activity that causes the birth of both the animate and inanimate is named 'action'.\""}]},{"ch":8,"vn":4,"dev":"अधिभूतं क्षरो भावः पुरुषश्चाधिदैवतम्।\nअधियज्ञोऽहमेवात्र देहे देहभृतां वर","iast":"adhibhūtaṁ kṣharo bhāvaḥ puruṣhaśh chādhidaivatam\nadhiyajño 'ham evātra dehe deha-bhṛitāṁ vara","v":[{"k":"purohit","t":"Matter consists of forms that perish; Divinity is the Supreme Self; and He who inspires the spirit of sacrifice in man, O noblest of their race, is I Myself, Who now stand in human form before thee."},{"k":"sivananda","t":"Adhibhuta—knowledge of the elements—pertains to My perishable nature, and the Purusha, or the Soul, is the Adhidaiva; I alone am the Adhiyajna here in this body, O best among the embodied."},{"k":"adidevananda","t":"That which exists in the physical plane is the mutable entity, and what exists in the divine plane is the Person. O best among the embodied beings, I Myself am the entity that exists in the sacrifice within this body."},{"k":"gambirananda","t":"That which exists in the physical plane is the mutable entity, and what exists in the divine plane is the Person. O best among the embodied beings, I Myself am the entity that exists in the sacrifice within this body."},{"k":"sankaranarayan","t":"The changing nature is the lord of the material beings; the Person alone is the lord of the divinities; I am alone the Lord of sacrifices, and I, the best of the embodied souls, dwell in this body."}]},{"ch":8,"vn":5,"dev":"अन्तकाले च मामेव स्मरन्मुक्त्वा कलेवरम्।\nयः प्रयाति स मद्भावं याति नास्त्यत्र संशयः","iast":"anta-kāle cha mām eva smaran muktvā kalevaram\nyaḥ prayāti sa mad-bhāvaṁ yāti nāstyatra sanśhayaḥ","v":[{"k":"purohit","t":"Whosoever, at the time of death, thinks only of Me and, thinking thus, leaves the body and goes forth, will assuredly know Me."},{"k":"sivananda","t":"And whoever, leaving their body, goes forth remembering Me alone at the time of death, they will attain My Being; there is no doubt about this."},{"k":"adidevananda","t":"And at the time of death, anyone who departs, giving up the body while thinking of Me alone, attains My state; there is no doubt about this."},{"k":"gambirananda","t":"And at the time of death, anyone who departs, giving up the body while thinking of Me alone, attains My state; there is no doubt about this."},{"k":"sankaranarayan","t":"Whosoever, at the time of death, remembering Me alone, sets forth, abandoning their body behind, they attain My being. There is no doubt about it."}]},{"ch":8,"vn":6,"dev":"यं यं वापि स्मरन्भावं त्यजत्यन्ते कलेवरम्।\nतं तमेवैति कौन्तेय सदा तद्भावभावितः","iast":"yaṁ yaṁ vāpi smaran bhāvaṁ tyajatyante kalevaram\ntaṁ tam evaiti kaunteya sadā tad-bhāva-bhāvitaḥ","v":[{"k":"purohit","t":"Whatever sphere of being the mind of a man is intent on at the time of death, to that he will go."},{"k":"sivananda","t":"Whoever at the end leaves the body, thinking of any being, to that being only does he go, O son of Kunti (Arjuna), due to his constant thought of that being."},{"k":"adidevananda","t":"O son of Kunti, thinking of any entity, whichever it may be, one gives up the body at the end; he attains that very one, having been always engrossed in its thought."},{"k":"gambirananda","t":"O son of Kunti, thinking of any entity, whichever it may be, one gives up the body at the end; he attains that very one, having been always engrossed in its thought."},{"k":"sankaranarayan","t":"And also remembering whatever being one has been constantly thinking about, a person leaves his body at the end [of his life], O son of Kunti! That being alone he attains."}]},{"ch":8,"vn":7,"dev":"तस्मात्सर्वेषु कालेषु मामनुस्मर युध्य च।\nमय्यर्पितमनोबुद्धिर्मामेवैष्यस्यसंशयम्","iast":"tasmāt sarveṣhu kāleṣhu mām anusmara yudhya cha\nmayyarpita-mano-buddhir mām evaiṣhyasyasanśhayam","v":[{"k":"purohit","t":"Therefore, always meditate on Me and fight; if your mind and reason are fixed on Me, you will surely come to Me."},{"k":"sivananda","t":"Therefore, at all times, remember Me only and fight. With your mind and intellect fixed on Me, you will undoubtedly come to Me alone."},{"k":"adidevananda","t":"Therefore, think of Me at all times and fight; there is no doubt that by dedicating your mind and intellect to Me, you will attain only Me."},{"k":"gambirananda","t":"Therefore, think of Me at all times and fight; there is no doubt that by dedicating your mind and intellect to Me, you will attain only Me."},{"k":"sankaranarayan","t":"Therefore, at all times keep Me in your mind and fight; then, having your mind and intellect dedicated to Me, you will undoubtedly attain Me alone."}]},{"ch":8,"vn":8,"dev":"अभ्यासयोगयुक्तेन चेतसा नान्यगामिना।\nपरमं पुरुषं दिव्यं याति पार्थानुचिन्तयन्","iast":"abhyāsa-yoga-yuktena chetasā nānya-gāminā\nparamaṁ puruṣhaṁ divyaṁ yāti pārthānuchintayan","v":[{"k":"purohit","t":"He whose mind does not wander, and who is engaged in constant meditation, attains the Supreme Spirit."},{"k":"sivananda","t":"With the mind not moving towards any other thing, made steadfast through the practice of habitual meditation, and constantly meditating, one goes to the Supreme Person, the Resplendent, O Arjuna."},{"k":"adidevananda","t":"O son of Prtha, by meditating with a mind engaged in the yoga of practice and not straying away to anything else, one reaches the supreme Person existing in the effulgent region."},{"k":"gambirananda","t":"O son of Prtha, by meditating with a mind engaged in the yoga of practice and not straying away to anything else, one reaches the supreme Person existing in the effulgent region."},{"k":"sankaranarayan","t":"He who is engaged in reflecting on the Supreme Divine Soul with his mind, remaining fixed in the practice of yoga and not focusing on any other object, that person attains the Supreme, O son of Prtha!"}]},{"ch":8,"vn":9,"dev":"कविं पुराणमनुशासितार\nमणोरणीयांसमनुस्मरेद्यः।\nसर्वस्य धातारमचिन्त्यरूप\nमादित्यवर्णं तमसः परस्तात्","iast":"kaviṁ purāṇam anuśhāsitāram\naṇor aṇīyānsam anusmared yaḥ\nsarvasya dhātāram achintya-rūpam\nāditya-varṇaṁ tamasaḥ parastāt","v":[{"k":"purohit","t":"Whoso meditates on the Omniscient, the Ancient, more minute than an atom, yet the Ruler and Upholder of all, Unimaginable, Brilliant like the Sun, Beyond the reach of darkness;"},{"k":"sivananda","t":"Whosoever meditates on the Omniscient, the Ancient, the Ruler of the whole world, minuter than an atom, the supporter of all, of inconceivable form, effulgent like the sun and beyond the darkness of ignorance."},{"k":"adidevananda","t":"He who meditates on the Omniscient, the Ancient, the Ruler, subtler than the subtle, the Ordainer of everything, of inconceivable form, effulgent like the sun, and beyond darkness—he attains the Supreme Person."},{"k":"gambirananda","t":"He who meditates on the Omniscient, the Ancient, the Ruler, subtler than the subtle, the Ordainer of everything, of inconceivable form, effulgent like the sun, and beyond darkness—he attains the Supreme Person."},{"k":"sankaranarayan","t":"He who meditates continuously on the Ancient Seer, the Ruler, the subtler than the subtle, the supporter of all, the unimaginably formed, the sun-colored, and that which is beyond darkness;"}]},{"ch":8,"vn":10,"dev":"प्रयाणकाले मनसाऽचलेन\nभक्त्या युक्तो योगबलेन चैव।\nभ्रुवोर्मध्ये प्राणमावेश्य सम्यक्\nस तं परं पुरुषमुपैति दिव्यम्","iast":"prayāṇa-kāle manasāchalena\nbhaktyā yukto yoga-balena chaiva\nbhruvor madhye prāṇam āveśhya samyak\nsa taṁ paraṁ puruṣham upaiti divyam","v":[{"k":"purohit","t":"He who leaves the body with an unmoved mind, filled with devotion, and by the power of his meditation gathers his whole vital energy between his eyebrows, attains the Supreme."},{"k":"sivananda","t":"At the time of death, with an unwavering mind, endowed with devotion, by the power of Yoga, fixing the whole life-breath in the middle of the two eyebrows, he reaches that resplendent Supreme Person."},{"k":"adidevananda","t":"At the time of death, having fully fixed the Prana (vital force) between the eyebrows with an unwavering mind, and being imbued with devotion as well as the strength of concentration, he reaches that resplendent Supreme Person."},{"k":"gambirananda","t":"At the time of death, having fully fixed the Prana (vital force) between the eyebrows with an unwavering mind, and being imbued with devotion as well as the strength of concentration, he reaches that resplendent Supreme Person."},{"k":"sankaranarayan","t":"That person, endowed with a steady mind, devotion, and the power of yoga, reaches the Supreme Divine Soul at the time of departure, by properly fixing the life-breath between their eyebrows."}]},{"ch":8,"vn":11,"dev":"यदक्षरं वेदविदो वदन्ति\nविशन्ति यद्यतयो वीतरागाः।\nयदिच्छन्तो ब्रह्मचर्यं चरन्ति\nतत्ते पदं संग्रहेण प्रवक्ष्ये","iast":"yad akṣharaṁ veda-vido vadanti\nviśhanti yad yatayo vīta-rāgāḥ\nyad ichchhanto brahmacharyaṁ charanti\ntat te padaṁ saṅgraheṇa pravakṣhye","v":[{"k":"purohit","t":"Now, I will briefly speak of the imperishable goal, proclaimed by those who are versed in the scriptures, which the mystic attains when free from passion, and for which they are content to undergo the vow of continence."},{"k":"sivananda","t":"That which is declared to be Imperishable by those who know the Vedas, that which the self-controlled (ascetics or Sannyasins) and passion-free enter, that goal, desiring which celibacy is practised, I will declare to thee in brief."},{"k":"adidevananda","t":"I will briefly speak to you of that immutable Goal, which the knowers of the Vedas declare; into which diligent ones, free from attachment, enter, and for which people practice celibacy, aspiring."},{"k":"gambirananda","t":"I will briefly tell you about that immutable Goal which the knowers of the Vedas declare; those who are diligent, free from attachment, and aspire for it, enter into it. People practice celibacy for it."},{"k":"sankaranarayan","t":"That Unchanging One which the Vedic knowers speak of; which the passion-free ascetics enter into, seeking which they practice celibacy (or spiritual life); that Goal together with the means [to reach it] I shall tell you."}]},{"ch":8,"vn":12,"dev":"सर्वद्वाराणि संयम्य मनो हृदि निरुध्य च।\nमूर्ध्न्याधायात्मनः प्राणमास्थितो योगधारणाम्","iast":"sarva-dvārāṇi sanyamya mano hṛidi nirudhya cha\nmūrdhnyādhāyātmanaḥ prāṇam āsthito yoga-dhāraṇām","v":[{"k":"purohit","t":"Closing the gates of the body, drawing the forces of his mind into the heart, and, by the power of meditation, concentrating his vital energy in the brain;"},{"k":"sivananda","t":"Having closed all the gates, confined the mind in the heart, and fixed the life-breath in the head, engage in the practice of concentration."},{"k":"adidevananda","t":"Having controlled all the senses, confined the mind in the heart, and fixed his own vital force in the head, he should remain steadfast in yoga."},{"k":"gambirananda","t":"Having controlled all the senses, confined the mind in the heart, and fixed his own vital force in the head, he should remain firm in yoga."},{"k":"sankaranarayan","t":"Properly controlling all the gates of the body; restraining the mind firmly in the heat; fixing one's own prana in the head; taking refuge in the firmness of Yoga."}]},{"ch":8,"vn":13,"dev":"ओमित्येकाक्षरं ब्रह्म व्याहरन्मामनुस्मरन्।\nयः प्रयाति त्यजन्देहं स याति परमां गतिम्","iast":"oṁ ityekākṣharaṁ brahma vyāharan mām anusmaran\nyaḥ prayāti tyajan dehaṁ sa yāti paramāṁ gatim","v":[{"k":"purohit","t":"Repeating Om, the symbol of eternity, and holding Me always in remembrance, he who thus leaves his body and goes forth reaches the Supreme Spirit."},{"k":"sivananda","t":"Uttering the one-syllabled Om, the Brahman, and remembering Me, he who departs, leaving the body, attains the Supreme Goal."},{"k":"adidevananda","t":"He who departs, leaving the body while uttering the single syllable, viz. \"Om,\" which is Brahman, and thinking of Me, attains the supreme Goal."},{"k":"gambirananda","t":"He who departs, leaving the body while uttering the single syllable, \"Om,\" which is Brahman, and thinking of Me, attains the supreme Goal."},{"k":"sankaranarayan","t":"Reciting the single-syllabled Om, the very Brahman; meditating on Me; whoever travels well, casting away their body—surely they attain My State."}]},{"ch":8,"vn":14,"dev":"अनन्यचेताः सततं यो मां स्मरति नित्यशः।\nतस्याहं सुलभः पार्थ नित्ययुक्तस्य योगिनः","iast":"ananya-chetāḥ satataṁ yo māṁ smarati nityaśhaḥ\ntasyāhaṁ sulabhaḥ pārtha nitya-yuktasya yoginaḥ","v":[{"k":"purohit","t":"To him who constantly thinks of Me and nothing else, to such an ever-faithful devotee, O Arjuna, I am ever accessible."},{"k":"sivananda","t":"I am easily attainable by that ever-steadfast yogi who constantly and daily remembers me for a long time, not thinking of anything else with a single-minded or one-pointed focus, O Partha."},{"k":"adidevananda","t":"O son of Prtha, to that yogi of constant concentration and single-minded attention, who remembers Me uninterruptedly and for a long time, I am easy to attain."},{"k":"gambirananda","t":"O son of Prtha, to that yogi of constant concentration and single-minded attention, who remembers Me uninterruptedly and for a long time, I am easily attained."},{"k":"sankaranarayan","t":"And whoever constantly bears Me in mind, never attached to any other object—for this yogi, ever devoted, I am easy to attain, O son of Prtha!"}]},{"ch":8,"vn":15,"dev":"मामुपेत्य पुनर्जन्म दुःखालयमशाश्वतम्।\nनाप्नुवन्ति महात्मानः संसिद्धिं परमां गताः","iast":"mām upetya punar janma duḥkhālayam aśhāśhvatam\nnāpnuvanti mahātmānaḥ sansiddhiṁ paramāṁ gatāḥ","v":[{"k":"purohit","t":"Coming to Me in this way, these great souls no longer go to the misery and death of earthly life, for they have achieved perfection."},{"k":"sivananda","t":"Having attained Me, these great souls do not take birth again here—a place of pain and impermanence—but have reached the highest perfection of liberation."},{"k":"adidevananda","t":"As a result of reaching Me, the exalted ones who have attained the highest perfection do not get birth, which is an abode of sorrows and is impermanent."},{"k":"gambirananda","t":"As a result of reaching Me, the exalted ones who have attained the highest perfection do not get rebirth, which is an abode of sorrows and is impermanent."},{"k":"sankaranarayan","t":"Having attained Me, the men of great soul who have achieved the supreme perfection do not get the transient birth, a storehouse of all troubles."}]},{"ch":8,"vn":16,"dev":"आब्रह्मभुवनाल्लोकाः पुनरावर्तिनोऽर्जुन।\nमामुपेत्य तु कौन्तेय पुनर्जन्म न विद्यते","iast":"ā-brahma-bhuvanāl lokāḥ punar āvartino 'rjuna\nmām upetya tu kaunteya punar janma na vidyate","v":[{"k":"purohit","t":"The worlds, along with the entire realm of creation, come and go; but, O Arjuna, whoever comes to Me, for them there is no rebirth."},{"k":"sivananda","t":"All the worlds, including the world of Brahma, are subject to return again, O Arjuna; but he who reaches Me, O son of Kunti, has no rebirth."},{"k":"adidevananda","t":"O Arjuna, all the worlds together with the world of Brahma are subject to return. But, O son of Kunti, there is no rebirth after reaching Me."},{"k":"gambirananda","t":"O Arjuna, all the worlds together with the world of Brahma are subject to return. But, O son of Kunti, there is no return after reaching Me."},{"k":"sankaranarayan","t":"Till the Brahman is attained, people return from each and every world, O Arjuna! But there is no return for one who has attained Me, O son of Kunti!"}]},{"ch":8,"vn":17,"dev":"सहस्रयुगपर्यन्तमहर्यद्ब्रह्मणो विदुः।\nरात्रिं युगसहस्रान्तां तेऽहोरात्रविदो जनाः","iast":"sahasra-yuga-paryantam ahar yad brahmaṇo viduḥ\nrātriṁ yuga-sahasrāntāṁ te 'ho-rātra-vido janāḥ","v":[{"k":"purohit","t":"Those who understand the cosmic day and night know that one day of creation is a thousand cycles, and that the night is of equal length."},{"k":"sivananda","t":"Those who know the day of Brahma, which lasts a thousand Yugas, and the night, which also lasts a thousand Yugas, know day and night."},{"k":"adidevananda","t":"Those people who know what day and night are, know the day of Brahma which ends in a thousand yugas [The four yugas (in the human worlds), viz Satya, Treta, Dwapara, and Kali are made up of 4,320,000 years. This period multiplied by a thousand constitutes one day of Brahma. His night also extends over a similar period. See M.S. and V.S.A.], and His night which also ends in a thousand yugas."},{"k":"gambirananda","t":"Those people who know what day and night are, know the day of Brahma which ends in a thousand yugas, and His night which also ends in a thousand yugas."},{"k":"sankaranarayan","t":"Those who know the day of Brahma as encompassing one thousand yugas (world-ages), and night [also] as encompassing one thousand yugas—those people know the day and night of Brahma."}]},{"ch":8,"vn":18,"dev":"अव्यक्ताद्व्यक्तयः सर्वाः प्रभवन्त्यहरागमे।\nरात्र्यागमे प्रलीयन्ते तत्रैवाव्यक्तसंज्ञके","iast":"avyaktād vyaktayaḥ sarvāḥ prabhavantyahar-āgame\nrātryāgame pralīyante tatraivāvyakta-sanjñake","v":[{"k":"purohit","t":"At the dawn of that day, all objects in manifestation stream forth from the Unmanifest, and when evening falls, they are dissolved back into it again."},{"k":"sivananda","t":"From the Unmanifested, all the manifested worlds proceed upon the arrival of the 'day'; upon the arrival of the 'night', they dissolve indeed into that which is known as the Unmanifested."},{"k":"adidevananda","t":"With the coming of day, all manifested things emerge from the Unmanifest, and when night comes, they merge into that which is called the Unmanifested."},{"k":"gambirananda","t":"With the coming of day, all manifested things emerge from the Unmanifest, and when night comes, they merge into that which is called the Unmanifested."},{"k":"sankaranarayan","t":"As the day approaches, all manifestations emerge from the unmanifest, and as the night approaches, they dissolve into the same, which is known as the 'unmanifest.'"}]},{"ch":8,"vn":19,"dev":"भूतग्रामः स एवायं भूत्वा भूत्वा प्रलीयते।\nरात्र्यागमेऽवशः पार्थ प्रभवत्यहरागमे","iast":"bhūta-grāmaḥ sa evāyaṁ bhūtvā bhūtvā pralīyate\nrātryāgame 'vaśhaḥ pārtha prabhavatyahar-āgame","v":[{"k":"purohit","t":"The same multitude of beings, which have lived on earth so often, all are dissolved as the night of the universe approaches, to issue forth anew when morning breaks. Thus, it is ordained."},{"k":"sivananda","t":"This same multitude of beings, being born again and again, helplessly dissolves, O Arjuna, into the Unmanifested at the coming of the night and comes forth at the coming of the day."},{"k":"adidevananda","t":"O son of Prtha, after being born again and again, that very multitude of beings disappears of its own accord at the approach of night. It comes to life again at the approach of day."},{"k":"gambirananda","t":"O son of Prtha, after being born again and again, that very multitude of beings disappears of its own accord at the approach of night. It comes to life again at the approach of day."},{"k":"sankaranarayan","t":"Being born and reborn, the same multitude of beings is dissolved when night approaches and is born again, willy-nilly, when day approaches, O son of Prtha!"}]},{"ch":8,"vn":20,"dev":"परस्तस्मात्तु भावोऽन्योऽव्यक्तोऽव्यक्तात्सनातनः।\nयः स सर्वेषु भूतेषु नश्यत्सु न विनश्यति","iast":"paras tasmāt tu bhāvo 'nyo 'vyakto 'vyaktāt sanātanaḥ\nyaḥ sa sarveṣhu bhūteṣhu naśhyatsu na vinaśhyati","v":[{"k":"purohit","t":"In truth, therefore, there is the eternal, unmanifest, which is beyond and above the unmanifest spirit of creation, and which is never destroyed when all these beings perish."},{"k":"sivananda","t":"But verily, there exists higher than this Unmanifested, another Unmanifested Eternal, which is not destroyed even when all beings are destroyed."},{"k":"adidevananda","t":"But distinct from that Unmanifested is the other eternal, unmanifest Reality, who does not get destroyed when all beings are destroyed."},{"k":"gambirananda","t":"But distinct from that Unmanifested is the other eternal, unmanifest Reality, who does not get destroyed when all beings are destroyed."},{"k":"sankaranarayan","t":"But there exists another Being which is beyond this, and It is both manifest and unmanifest and is eternal. It is this Being that does not perish while all other beings perish."}]},{"ch":8,"vn":21,"dev":"अव्यक्तोऽक्षर इत्युक्तस्तमाहुः परमां गतिम्।\nयं प्राप्य न निवर्तन्ते तद्धाम परमं मम","iast":"avyakto 'kṣhara ityuktas tam āhuḥ paramāṁ gatim\nyaṁ prāpya na nivartante tad dhāma paramaṁ mama","v":[{"k":"purohit","t":"The wise say that the Unmanifest and Indestructible is the highest goal of all; when once that is reached, there is no returning. That is my blessed home."},{"k":"sivananda","t":"What is known as the Unmanifested and the Imperishable, That is said to be the highest goal. Those who reach It do not return (to this Samsara). That is My supreme abode (place or state)."},{"k":"adidevananda","t":"They call Him who has been mentioned as the Unmanifested, the Immutable, the supreme Goal. That is the supreme abode of Mine, from which they do not return once they reach it."},{"k":"gambirananda","t":"They call Him who has been mentioned as the Unmanifested, the Immutable, the supreme Goal. That is the supreme abode of Mine, from which they do not return once they reach it."},{"k":"sankaranarayan","t":"The scriptures speak of This as Unmanifest and Changeless, and declare This to be the highest Goal. Having attained it, people do not return; this is My highest abode."}]},{"ch":8,"vn":22,"dev":"पुरुषः स परः पार्थ भक्त्या लभ्यस्त्वनन्यया।\nयस्यान्तःस्थानि भूतानि येन सर्वमिदं ततम्","iast":"puruṣhaḥ sa paraḥ pārtha bhaktyā labhyas tvananyayā\nyasyāntaḥ-sthāni bhūtāni yena sarvam idaṁ tatam","v":[{"k":"purohit","t":"O Arjuna! That Highest God, in Whom all beings abide, and Who pervades the entire universe, is reached only by wholehearted devotion. *He is the one who determines the course of worldly events and the destiny of all living beings.*"},{"k":"sivananda","t":"That highest Purusha, O Arjuna, is attainable by unswerving devotion to Him alone, within Whom all beings dwell and by Whom all this is pervaded."},{"k":"adidevananda","t":"O son of Prtha, that supreme Person—in whom all beings are included and by whom all this is pervaded—is indeed reached through one-pointed devotion."},{"k":"gambirananda","t":"O son of Prtha, that supreme Person—in whom all beings are included and by whom all this is pervaded—is, indeed, reached through one-pointed devotion."},{"k":"sankaranarayan","t":"O son of Prtha, the Supreme Soul is attainable through devotion that admits no other things; having attained it, the men of Yoga do not get birth again; within it exist the beings, and everything is well established in it, O Arjuna!"}]},{"ch":8,"vn":23,"dev":"यत्र काले त्वनावृत्तिमावृत्तिं चैव योगिनः।\nप्रयाता यान्ति तं कालं वक्ष्यामि भरतर्षभ","iast":"yatra kāle tvanāvṛittim āvṛittiṁ chaiva yoginaḥ\nprayātā yānti taṁ kālaṁ vakṣhyāmi bharatarṣhabha","v":[{"k":"purohit","t":"Now, I will tell you, O Arjuna, the times at which, if the mystics go forth, they do not return, and at which they go forth only to return."},{"k":"sivananda","t":"Now I will tell you, O chief of the Bharatas, the times of departure at which the Yogis will return or not return."},{"k":"adidevananda","t":"O best of the Bharata dynasty, I shall now speak of that time by which the yogis depart and attain the State of Non-return, and also the State of Return."},{"k":"gambirananda","t":"O best of the Bharata dynasty, I shall now speak of that time by which the yogis depart and attain the State of Non-return, and also the State of Return."},{"k":"sankaranarayan","t":"Departing at what times the Yogis attain the non-return or the return only—those times I shall declare to you, O chief of the Bharatas!"}]},{"ch":8,"vn":24,"dev":"अग्निर्ज्योतिरहः शुक्लः षण्मासा उत्तरायणम्।\nतत्र प्रयाता गच्छन्ति ब्रह्म ब्रह्मविदो जनाः","iast":"agnir jyotir ahaḥ śhuklaḥ ṣhaṇ-māsā uttarāyaṇam\ntatra prayātā gachchhanti brahma brahma-vido janāḥ","v":[{"k":"purohit","t":"If the sage, knowing the Supreme Spirit, goes forth with fire and light during the day, in the fortnight of the waxing moon, and in the six months before the Northern summer solstice, he will attain the Supreme."},{"k":"sivananda","t":"Fire, light, daytime, the bright fortnight, the six months of the northern path of the sun (the northern solstice) departing, then men who know Brahman go to Brahman."},{"k":"adidevananda","t":"Fire, light, daytime, the bright fortnight, the six months of the northern solstice—by following this path, persons who are knowers of Brahman attain Brahman when they die."},{"k":"gambirananda","t":"Fire, light, daytime, the bright fortnight, the six months of the northern solstice—by following this path, persons who are knowers of Brahman attain Brahman when they die."},{"k":"sankaranarayan","t":"The northern course consisting of six months is fire, light, day, and bright. Departing in it, the Brahman-knowing men attain Brahman."}]},{"ch":8,"vn":25,"dev":"धूमो रात्रिस्तथा कृष्णः षण्मासा दक्षिणायनम्।\nतत्र चान्द्रमसं ज्योतिर्योगी प्राप्य निवर्तते","iast":"dhūmo rātris tathā kṛiṣhṇaḥ ṣhaṇ-māsā dakṣhiṇāyanam\ntatra chāndramasaṁ jyotir yogī prāpya nivartate","v":[{"k":"purohit","t":"But if he departs in gloom, at night, during the fortnight of the waning moon and in the six months before the winter solstice, then he reaches only lunar light and he will be reborn."},{"k":"sivananda","t":"Attaining the lunar light through smoke, night time, the dark fortnight, and the six months of the southern path of the sun (the southern solstice), the yogi returns."},{"k":"adidevananda","t":"Following this Path, the yogi, having reached the lunar light, returns, smoke, night, as also the dark fortnight and the six months of the Southern solstice."},{"k":"gambirananda","t":"Following this Path, the yogi, having reached the lunar light, returns, smoke, night, as also the dark fortnight and the six months of the Southern solstice."},{"k":"sankaranarayan","t":"The southern course of the sun, consisting of six months, is smoke, night, and darkness. Departing in it, the yogi attains the light of the moon and returns."}]},{"ch":8,"vn":26,"dev":"शुक्लकृष्णे गती ह्येते जगतः शाश्वते मते।\nएकया यात्यनावृत्तिमन्ययाऽऽवर्तते पुनः","iast":"śhukla-kṛiṣhṇe gatī hyete jagataḥ śhāśhvate mate\nekayā yātyanāvṛittim anyayāvartate punaḥ","v":[{"k":"purohit","t":"These bright and dark paths out of the world have always existed. Whoever takes the former, does not return; he who chooses the latter, returns."},{"k":"sivananda","t":"The bright and dark paths of the world are thought to be eternal; one leads to no return, and the other leads to return."},{"k":"adidevananda","t":"These two paths of the world, which are white and black, are indeed considered eternal. Through one, a person goes to the state of non-return; through the other, they return again."},{"k":"gambirananda","t":"These two paths of the world, which are white and black, are indeed considered eternal. Through one, a person goes to the state of non-return; through the other, they return again."},{"k":"sankaranarayan","t":"For, these two bright and dark paths are considered to be perpetual for the world. One attains non-return by the first of these, and one returns back by the other."}]},{"ch":8,"vn":27,"dev":"नैते सृती पार्थ जानन्योगी मुह्यति कश्चन।\nतस्मात्सर्वेषु कालेषु योगयुक्तो भवार्जुन","iast":"naite sṛitī pārtha jānan yogī muhyati kaśhchana\ntasmāt sarveṣhu kāleṣhu yoga-yukto bhavārjuna","v":[{"k":"purohit","t":"O Arjuna! The saint, knowing these paths, is not confused; therefore, meditate perpetually."},{"k":"sivananda","t":"Knowing these paths, O Arjuna, no yogi is deluded; therefore, at all times, be steadfast in yoga."},{"k":"adidevananda","t":"O son of Prtha, no yogi—one steadfast in meditation—whosoever has known these two courses becomes deluded. Therefore, O Arjuna, be steadfast in yoga at all times."},{"k":"gambirananda","t":"O son of Prtha, no yogi—one steadfast in meditation—whosoever has known these two courses becomes deluded. Therefore, O Arjuna, be steadfast in yoga at all times."},{"k":"sankaranarayan","t":"O son of Prtha, no Yogin, knowing these two courses, gets deluded. Therefore, O Arjuna, practice Yoga connected with all times."}]},{"ch":8,"vn":28,"dev":"वेदेषु यज्ञेषु तपःसु चैव\nदानेषु यत्पुण्यफलं प्रदिष्टम्।\nअत्येति तत्सर्वमिदं विदित्वा\nयोगी परं स्थानमुपैति चाद्यम्","iast":"vedeṣhu yajñeṣhu tapaḥsu chaiva\ndāneṣhu yat puṇya-phalaṁ pradiṣhṭam\natyeti tat sarvam idaṁ viditvā\nyogī paraṁ sthānam upaiti chādyam","v":[{"k":"purohit","t":"The sage who knows this passes beyond all merit that comes from the study of the scriptures, from sacrifice, from austerities, and from charity, and reaches the Supreme Primeval Abode."},{"k":"sivananda","t":"Whatever fruit of merit is declared (in the scriptures) to accrue from (the study of) the Vedas, (the performance of) sacrifices, (the practice of) austerities, and gifts, beyond all this goes the Yogi, having known this; and he attains to the Supreme, Primeval (first or ancient) Abode."},{"k":"adidevananda","t":"Having known this, the yogi transcends all the results of righteous deeds declared in the Vedas, sacrifices, austerities, and charities, and reaches the primordial, supreme state."},{"k":"gambirananda","t":"Having known this, the yogi transcends all the results of righteous deeds declared in the Vedas, sacrifices, austerities, and charities, and reaches the primordial, supreme state."},{"k":"sankaranarayan","t":"Having understood all this, the Yogin goes beyond whatever fruit of merit is ordained in the scriptures in case of reciting the Vedas, performing sacrifices, observing austerities, and donating gifts; and he goes to the Supreme Primeval Abode."}]},{"ch":9,"vn":1,"dev":"श्री भगवानुवाच\nइदं तु ते गुह्यतमं प्रवक्ष्याम्यनसूयवे।\nज्ञानं विज्ञानसहितं यज्ज्ञात्वा मोक्ष्यसेऽशुभात्","iast":"śhrī bhagavān uvācha\nidaṁ tu te guhyatamaṁ pravakṣhyāmyanasūyave\njñānaṁ vijñāna-sahitaṁ yaj jñātvā mokṣhyase 'śhubhāt","v":[{"k":"purohit","t":"Lord Shri Krishna said: I will now reveal to you, since you do not doubt, that profound mysticism, which, when followed with experience, will liberate you from sin."},{"k":"sivananda","t":"The Blessed Lord said, \"I shall now declare to thee, who does not cavil, the greatest secret—the knowledge combined with experience (Self-realisation). Having known this, thou shalt be free from evil.\""},{"k":"adidevananda","t":"The Lord said, \"I shall declare to you, who does not cavil, this most mysterious knowledge, together with its special knowledge, knowing which you will be freed from evil.\""},{"k":"gambirananda","t":"The Blessed Lord said: However, to you who are not given to cavilling, I shall speak of this highest secret itself, which is knowledge combined with experience, by realizing which you shall be free from evil."},{"k":"sankaranarayan","t":"The Bhagavat said, \"To you, who are entertaining no displeasure, I shall clearly declare this most secret knowledge, together with action, by knowing which you shall be free from evil.\""}]},{"ch":9,"vn":2,"dev":"राजविद्या राजगुह्यं पवित्रमिदमुत्तमम्।\nप्रत्यक्षावगमं धर्म्यं सुसुखं कर्तुमव्ययम्","iast":"rāja-vidyā rāja-guhyaṁ pavitram idam uttamam\npratyakṣhāvagamaṁ dharmyaṁ su-sukhaṁ kartum avyayam","v":[{"k":"purohit","t":"This is the supreme science, the supreme secret, the purest and best; it is intuitive, righteous, and to those who practice it, it is exceedingly pleasant."},{"k":"sivananda","t":"This is the royal science, the royal secret, the supreme purifier, realizable by direct intuitive knowledge, according to righteousness, very easy to perform and imperishable."},{"k":"adidevananda","t":"This is the royal science, the royal mystery, the supreme purifier. It is realized through direct experience, is in accord with Dharma, is pleasant to practice, and is abiding."},{"k":"gambirananda","t":"This is the sovereign knowledge, the sovereign profundity, the best sanctifier; directly realizable, righteous, very easy to practice, and imperishable."},{"k":"sankaranarayan","t":"This shines among the sciences; it is the secret of monarchs; it is a supreme purifier, comprehensible by immediate perception, righteous, easy to do, and imperishable."}]},{"ch":9,"vn":3,"dev":"अश्रद्दधानाः पुरुषा धर्मस्यास्य परन्तप।\nअप्राप्य मां निवर्तन्ते मृत्युसंसारवर्त्मनि","iast":"aśhraddadhānāḥ puruṣhā dharmasyāsya parantapa\naprāpya māṁ nivartante mṛityu-samsāra-vartmani","v":[{"k":"purohit","t":"They who have no faith in this teaching cannot find Me; they remain lost in the purlieus of this perishable world."},{"k":"sivananda","t":"Those who have no faith in this Dharma, O Parantapa, return to the path of this world without attaining Me."},{"k":"adidevananda","t":"Men devoid of faith in this Dharma, O scorcher of foes, ever remain without attaining Me, on the mortal path of Samsara."},{"k":"gambirananda","t":"O destroyer of foes, those who are disregarding this Dharma (knowledge of the Self) certainly go round and round, without reaching Me, along the path of transmigration which is fraught with death."},{"k":"sankaranarayan","t":"O scorcher of foes! Those who have no faith in this Dharma do not attain Me and remain eternally in the cycle of mundane existence, fraught with death."}]},{"ch":9,"vn":4,"dev":"मया ततमिदं सर्वं जगदव्यक्तमूर्तिना।\nमत्स्थानि सर्वभूतानि न चाहं तेष्ववस्थितः","iast":"mayā tatam idaṁ sarvaṁ jagad avyakta-mūrtinā\nmat-sthāni sarva-bhūtāni na chāhaṁ teṣhvavasthitaḥ","v":[{"k":"purohit","t":"The whole world is pervaded by Me, yet My form is not visible. All living beings have their being in Me, yet I am not confined by them."},{"k":"sivananda","t":"All of this world is pervaded by Me in My unmanifest aspect; all beings exist within Me, but I do not dwell within them."},{"k":"adidevananda","t":"This entire universe is pervaded by Me, in an unmanifest form. All beings abide in Me, but I do not abide in them."},{"k":"gambirananda","t":"This whole world is pervaded by Me in My unmanifest form. All beings exist in Me, but I am not contained within them!"},{"k":"sankaranarayan","t":"This entire universe is pervaded by Me, having an unmanifest form; all beings exist in Me, and I do not exist in them."}]},{"ch":9,"vn":5,"dev":"न च मत्स्थानि भूतानि पश्य मे योगमैश्वरम्।\nभूतभृन्न च भूतस्थो ममात्मा भूतभावनः","iast":"na cha mat-sthāni bhūtāni paśhya me yogam aiśhwaram\nbhūta-bhṛin na cha bhūta-stho mamātmā bhūta-bhāvanaḥ","v":[{"k":"purohit","t":"Nevertheless, they do not consciously abide in Me. Such is My Divine Sovereignty that, though I, the Supreme Self, am the cause and upholder of all, yet I remain outside."},{"k":"sivananda","t":"Nor do beings exist in Me (in reality); behold, My divine Yoga, which supports all beings, but does not dwell in them, is My Self, the efficient cause of beings."},{"k":"adidevananda","t":"Yet, beings do not remain in Me. Behold My divine Yoga. I am the sustainer of all beings, yet I am not in them. It is My will alone that causes their existence."},{"k":"gambirananda","t":"Neither do the beings dwell in Me. Behold My divine Yoga! I am the sustainer and originator of beings, but My Self is not contained within the beings."},{"k":"sankaranarayan","t":"Yet, the beings do not exist in Me. Look at My Sovereign Yoga. My Self is the sustainer of the beings; it does not exist in them, and causes them to be born."}]},{"ch":9,"vn":6,"dev":"यथाऽऽकाशस्थितो नित्यं वायुः सर्वत्रगो महान्।\nतथा सर्वाणि भूतानि मत्स्थानीत्युपधारय","iast":"yathākāśha-sthito nityaṁ vāyuḥ sarvatra-go mahān\ntathā sarvāṇi bhūtāni mat-sthānītyupadhāraya","v":[{"k":"purohit","t":"As the mighty wind, though moving everywhere, has no resting place except in space, so all these beings have no home except in Me."},{"k":"sivananda","t":"As the mighty wind, moving everywhere, always rests in the ether, so too, know that all beings rest in Me."},{"k":"adidevananda","t":"As the powerful element air, moving everywhere, ever remains in the ether, know that so too all beings abide in Me."},{"k":"gambirananda","t":"Understand thus that just as the voluminous wind, moving everywhere, is ever present in space, similarly all beings abide in Me."},{"k":"sankaranarayan","t":"Just as the mighty wind exists in the ether, always moving therein everywhere, in the same manner all beings exist in Me. Be sure of it."}]},{"ch":9,"vn":7,"dev":"सर्वभूतानि कौन्तेय प्रकृतिं यान्ति मामिकाम्।\nकल्पक्षये पुनस्तानि कल्पादौ विसृजाम्यहम्","iast":"sarva-bhūtāni kaunteya prakṛitiṁ yānti māmikām\nkalpa-kṣhaye punas tāni kalpādau visṛijāmyaham","v":[{"k":"purohit","t":"All beings, O Arjuna, return at the end of every cosmic cycle into the realm of Nature, which is a part of Me, and at the start of the next I send them forth again."},{"k":"sivananda","t":"All beings, O Arjuna, go into My Nature at the end of a Kalpa; I send them forth again at the beginning of the next Kalpa."},{"k":"adidevananda","t":"All beings, O Arjuna, enter into My Prakriti at the end of a cycle of time; again, I send them forth at the beginning of a cycle of time."},{"k":"gambirananda","t":"O son of Kunti, all the beings at the end of a cycle go back to My Prakrti. At the beginning of a cycle, I project them forth again."},{"k":"sankaranarayan","t":"O son of Kunti, all beings pass into My nature at the end of the Kalpa (the age of universe); I send them forth again at the beginning of the [next] Kalpa."}]},{"ch":9,"vn":8,"dev":"प्रकृतिं स्वामवष्टभ्य विसृजामि पुनः पुनः।\nभूतग्राममिमं कृत्स्नमवशं प्रकृतेर्वशात्","iast":"prakṛitiṁ svām avaṣhṭabhya visṛijāmi punaḥ punaḥ\nbhūta-grāmam imaṁ kṛitsnam avaśhaṁ prakṛiter vaśhāt","v":[{"k":"purohit","t":"With the help of Nature, I again and again pour forth the whole multitude of beings, whether they will or not, for they are ruled by My will."},{"k":"sivananda","t":"Animating My Nature, I again and again send forth all this multitude of beings, helpless under the force of Nature."},{"k":"adidevananda","t":"Controlling the Prakṛti, which is My own, I send forth again and again this multitude of beings, helpless under the sway of Prakṛti."},{"k":"gambirananda","t":"Keeping My own prakṛti under control, I project forth again and again this multitude of beings, which are powerless due to the influence of their own nature."},{"k":"sankaranarayan","t":"Taking hold of My own nature, I again and again send forth this entire host of beings, which is powerless under the control of My nature."}]},{"ch":9,"vn":9,"dev":"न च मां तानि कर्माणि निबध्नन्ति धनञ्जय।\nउदासीनवदासीनमसक्तं तेषु कर्मसु","iast":"na cha māṁ tāni karmāṇi nibadhnanti dhanañjaya\nudāsīna-vad āsīnam asaktaṁ teṣhu karmasu","v":[{"k":"purohit","t":"But these acts of mine do not bind me; I remain outside and unattached."},{"k":"sivananda","t":"These acts do not bind Me, O Arjuna, sitting as one indifferent, unattached to those acts."},{"k":"adidevananda","t":"But these actions do not bind Me, O Arjuna, for I remain detached from them, as if I were unconcerned."},{"k":"gambirananda","t":"O Dhananjaya, those actions do not bind Me, for I remain unconcerned and unattached to them."},{"k":"sankaranarayan","t":"O Dhananjaya! These acts do not bind me, remaining as if unconcerned and unattached in these actions."}]},{"ch":9,"vn":10,"dev":"मयाऽध्यक्षेण प्रकृतिः सूयते सचराचरम्।\nहेतुनाऽनेन कौन्तेय जगद्विपरिवर्तते","iast":"mayādhyakṣheṇa prakṛitiḥ sūyate sa-charācharam\nhetunānena kaunteya jagad viparivartate","v":[{"k":"purohit","t":"Under my guidance, Nature produces all movable and immovable things. Thus, O Arjuna, this universe revolves."},{"k":"sivananda","t":"Under Me, as supervisor, Nature produces the moving and the unmoving; therefore, O Arjuna, the world revolves."},{"k":"adidevananda","t":"Under My supervision, Prakrti gives birth to all mobile and immobile entities, and thus, O Arjuna, the world revolves."},{"k":"gambirananda","t":"Under Me as the supervisor, the Prakrti produces the world of the moving and the non-moving things. Owing to this, O son of Kunti, the world revolves."},{"k":"sankaranarayan","t":"O son of Kunti! On account of Me, who remain only as an observer and the prime cause, My nature gives birth to both the moving and the unmoving; hence, this world moves in a circle."}]},{"ch":9,"vn":11,"dev":"अवजानन्ति मां मूढा मानुषीं तनुमाश्रितम्।\nपरं भावमजानन्तो मम भूतमहेश्वरम्","iast":"avajānanti māṁ mūḍhā mānuṣhīṁ tanum āśhritam\nparaṁ bhāvam ajānanto mama bhūta-maheśhvaram","v":[{"k":"purohit","t":"Fools disregard Me, seeing Me clad in human form. They do not know that in My higher nature, I am the Lord-God of all."},{"k":"sivananda","t":"Fools disregard Me, clad in human form, not knowing My higher Being as the great Lord of all beings."},{"k":"adidevananda","t":"Fools disregard Me, dwelling in a human form, not knowing My higher nature as the Supreme Lord of all beings."},{"k":"gambirananda","t":"Not knowing My supreme nature as the Lord of all beings, foolish people disregard Me, who have taken a human form."},{"k":"sankaranarayan","t":"Unaware of My immutable, highest Absolute Supreme nature, the deluded ones disregard Me, dwelling in the human body."}]},{"ch":9,"vn":12,"dev":"मोघाशा मोघकर्माणो मोघज्ञाना विचेतसः।\nराक्षसीमासुरीं चैव प्रकृतिं मोहिनीं श्रिताः","iast":"moghāśhā mogha-karmāṇo mogha-jñānā vichetasaḥ\nrākṣhasīm āsurīṁ chaiva prakṛitiṁ mohinīṁ śhritāḥ","v":[{"k":"purohit","t":"Their hopes are futile, their actions worthless, their knowledge ineffective; they are without sense, deceitful, barbaric, and godless."},{"k":"sivananda","t":"They are possessed of the deceitful nature of demons and undivine beings, filled with vain hopes, vain actions, and vain knowledge that is senseless."},{"k":"adidevananda","t":"Senseless people have a nature that is deluding and similar to that of rakshasas and asuras. Their hopes are futile, their actions are futile, and their knowledge is futile."},{"k":"gambirananda","t":"Possessed of vain hopes, vain actions, vain knowledge, and senselessness, they become verily possessed of the deceptive disposition of fiends and demons."},{"k":"sankaranarayan","t":"They are of futile aspirations, futile actions, futile knowledge, and wrong intellect; and they take recourse only to the delusive nature that is both demoniac and devilish."}]},{"ch":9,"vn":13,"dev":"महात्मानस्तु मां पार्थ दैवीं प्रकृतिमाश्रिताः।\nभजन्त्यनन्यमनसो ज्ञात्वा भूतादिमव्ययम्","iast":"mahātmānas tu māṁ pārtha daivīṁ prakṛitim āśhritāḥ\nbhajantyananya-manaso jñātvā bhūtādim avyayam","v":[{"k":"purohit","t":"But the great souls, O Arjuna! Filled with my divine spirit, they worship me, fix their minds on me alone, for they know that I am the imperishable source of being."},{"k":"sivananda","t":"But the great souls, O Arjuna, partaking of My divine nature, worship Me with a single-minded devotion, knowing Me as the imperishable source of all beings."},{"k":"adidevananda","t":"But the great-souled ones, O Arjuna, who are associated with My divine nature, worship Me with an unwavering mind, knowing Me to be the immutable source of all beings."},{"k":"gambirananda","t":"O son of Prtha, the noble ones, being possessed of divine nature, surely adore Me with single-mindedness, knowing Me to be the immutable source of all objects."},{"k":"sankaranarayan","t":"O son of Prtha! The great-souled men, however, taking hold of the divine nature and having nothing else in their minds, adore Me, viewing Me as the imperishable prime cause of beings."}]},{"ch":9,"vn":14,"dev":"सततं कीर्तयन्तो मां यतन्तश्च दृढव्रताः।\nनमस्यन्तश्च मां भक्त्या नित्ययुक्ता उपासते","iast":"satataṁ kīrtayanto māṁ yatantaśh cha dṛiḍha-vratāḥ\nnamasyantaśh cha māṁ bhaktyā nitya-yuktā upāsate","v":[{"k":"purohit","t":"Always extolling Me, they are strenuous and firm in their vows, prostrating themselves before Me, and worshiping Me continually with concentrated devotion."},{"k":"sivananda","t":"Always glorifying Me, striving, firm in their vows, prostrating themselves before Me, they worship Me with steadfast devotion."},{"k":"adidevananda","t":"Aspiring for eternal communion with Me, they worship Me, always singing My praises, striving with steadfast resolution and bowing down to Me in devotion."},{"k":"gambirananda","t":"Always glorifying Me and striving, the men of firm vows worship Me by paying obeisance to Me and being ever endowed with devotion."},{"k":"sankaranarayan","t":"Ever speaking of My glory, striving with firm resolve, paying homage to Me, and being permanently endowed with devotion, they worship Me."}]},{"ch":9,"vn":15,"dev":"ज्ञानयज्ञेन चाप्यन्ये यजन्तो मामुपासते।\nएकत्वेन पृथक्त्वेन बहुधा विश्वतोमुखम्","iast":"jñāna-yajñena chāpyanye yajanto mām upāsate\nekatvena pṛithaktvena bahudhā viśhvato-mukham","v":[{"k":"purohit","t":"Others worship Me with full consciousness as the One, the Manifold, the Omnipresent, and the Universal."},{"k":"sivananda","t":"Others also, sacrificing with the wisdom-sacrifice, worship Me, the All-Faced, as one, distinct, and manifold."},{"k":"adidevananda","t":"Others, besides offering the sacrifice of knowledge, also worship Me as One, who is characterized by diversity in countless ways and is multiform (in My Cosmic aspect)."},{"k":"gambirananda","t":"Others indeed worship Me by exclusively adoring through the sacrifice of the knowledge of oneness; (others worship Me) in many ways, and (others) as the multiform existing in various forms."},{"k":"sankaranarayan","t":"Some worship Me by knowledge-sacrifice, and others by offering sacrifices; thus, they worship Me, the Universally-Faced, either as One or as Many."}]},{"ch":9,"vn":16,"dev":"अहं क्रतुरहं यज्ञः स्वधाऽहमहमौषधम्।\nमंत्रोऽहमहमेवाज्यमहमग्निरहं हुतम्","iast":"ahaṁ kratur ahaṁ yajñaḥ svadhāham aham auṣhadham\nmantro 'ham aham evājyam aham agnir ahaṁ hutam","v":[{"k":"purohit","t":"I am the oblation, the sacrifice, and the worship; I am the fuel and the chant; I am the butter offered to the fire; I am the fire itself, and I am the act of offering."},{"k":"sivananda","t":"I am Kratu; I am Yajna; I am the offering to the manes; I am the medicinal herbs and all plants; I am the Mantra; I am also the ghee or melted butter; I am the fire; I am the oblation."},{"k":"adidevananda","t":"I am Kratu, I am the sacrifice, I am the offering to the manes, I am the herb, I am the Mantra, I am the clarified butter, I am the fire, I am the oblation."},{"k":"gambirananda","t":"I am the ritual, I am the sacrifice, I am the oblation, I am the medicinal herb, I am the mantra, I am the clarified butter, I am the fire, and I am the act of offering."},{"k":"sankaranarayan","t":"I am determination; I am sacrifice; I am Svadha; I am the juice of the herb; I am the Vedic hymn; I am also the clarified butter; I am the sacrificial fire; and I am the act of offering."}]},{"ch":9,"vn":17,"dev":"पिताऽहमस्य जगतो माता धाता पितामहः।\nवेद्यं पवित्रमोंकार ऋक् साम यजुरेव च","iast":"pitāham asya jagato mātā dhātā pitāmahaḥ\nvedyaṁ pavitram oṁkāra ṛik sāma yajur eva cha","v":[{"k":"purohit","t":"I am the Father of the universe, its Mother, Nourisher, and Grandfather; I am the Knowable and the Pure; I am Om, and I am the Sacred Scriptures."},{"k":"sivananda","t":"I am the father of this world, the mother, the dispenser of the fruits of actions, and the grandfather; the one thing to be known, the purifier, the sacred monosyllable (Om), and also the Rik, Sama, and Yajur Vedas."},{"k":"adidevananda","t":"I am the father, mother, creator, and grandfather of the universe; I am the purifier. I am the syllable Om, as well as Rk, Saman, and Yajus."},{"k":"gambirananda","t":"Of this world, I am the father, mother, ordainer, and grandfather; I am the knowable, the sanctifier, the syllable Om, as well as the Rk, Sama, and Yajus."},{"k":"sankaranarayan","t":"I am the father, the mother, the sustainer, and the paternal grandparent of this world; I am the sacred object of knowledge, the syllable Om, the Rk, the Saman, and the Yajus as well."}]},{"ch":9,"vn":18,"dev":"गतिर्भर्ता प्रभुः साक्षी निवासः शरणं सुहृत्।\nप्रभवः प्रलयः स्थानं निधानं बीजमव्ययम्","iast":"gatir bhartā prabhuḥ sākṣhī nivāsaḥ śharaṇaṁ suhṛit\nprabhavaḥ pralayaḥ sthānaṁ nidhānaṁ bījam avyayam","v":[{"k":"purohit","t":"I am the goal, the sustainer, the Lord, the witness, the home, the shelter, the lover, and the origin; I am life and death; I am the fountain and the imperishable seed."},{"k":"sivananda","t":"I am the goal, the supporter, the Lord, the witness, the abode, the shelter, the friend, the origin, the dissolution, the foundation, the treasure-house, and the imperishable seed."},{"k":"adidevananda","t":"I am the goal, the supporter, the Lord, the witness, the abode, the refuge, and the friend. I am the origin, the dissolution, the basis for preservation, and the imperishable seed."},{"k":"gambirananda","t":"I am the fruit of actions, the nourisher, the Lord, witness, abode, refuge, friend, origin, end, foundation, store, and the imperishable seed."},{"k":"sankaranarayan","t":"I am the method, the nourisher, the lord, the witness, the abode, the refuge, the good-hearted friend, the origin, the dissolution, the sustenance, the repository, and the imperishable seed of the world."}]},{"ch":9,"vn":19,"dev":"तपाम्यहमहं वर्षं निगृह्णाम्युत्सृजामि च।\nअमृतं चैव मृत्युश्च सदसच्चाहमर्जुन","iast":"tapāmyaham ahaṁ varṣhaṁ nigṛihṇāmyutsṛijāmi cha\namṛitaṁ chaiva mṛityuśh cha sad asach chāham arjuna","v":[{"k":"purohit","t":"I am the heat of the sun, I release and withhold the rain. I am death and immortality; I am being and non-being."},{"k":"sivananda","t":"As the sun, I give heat; I withhold and send forth the rain; I am immortality and also death, existence and non-existence, O Arjuna."},{"k":"adidevananda","t":"I give heat, I withhold and send forth the rain; I am immortality and also death, O Arjuna. I am the being and the non-being."},{"k":"gambirananda","t":"O Arjuna, I give heat, I withhold and pour down rain; I am verily the nectar, and also death, existence, and non-existence."},{"k":"sankaranarayan","t":"I give heat; I withhold and also send forth rains; I am immortality and also death, the real and the unreal, O Arjuna!"}]},{"ch":9,"vn":20,"dev":"त्रैविद्या मां सोमपाः पूतपापा\nयज्ञैरिष्ट्वा स्वर्गतिं प्रार्थयन्ते।\nते पुण्यमासाद्य सुरेन्द्रलोक\nमश्नन्ति दिव्यान्दिवि देवभोगान्","iast":"trai-vidyā māṁ soma-pāḥ pūta-pāpā\nyajñair iṣhṭvā svar-gatiṁ prārthayante\nte puṇyam āsādya surendra-lokam\naśhnanti divyān divi deva-bhogān","v":[{"k":"purohit","t":"Those who are versed in the scriptures, who drink the mystic Soma-juice and are purified from sin, and who, while worshipping Me with sacrifices, pray that I will lead them to heaven; they reach the holy world where the Controller of the Powers of Nature resides, and they enjoy the feasts of Paradise."},{"k":"sivananda","t":"The knowers of the three Vedas, the drinkers of Soma, purified of all sins, worshipping Me through sacrifices, pray for the way to heaven; they reach the holy world of the Lord of the gods and enjoy the divine pleasures of the gods in heaven."},{"k":"adidevananda","t":"Those who are versed in the three Vedas, having been purified from sin by drinking the Soma juice, pray for passage to heaven and worship Me through sacrifices. Reaching the holy realm of the chief of the gods, they enjoy celestial pleasures in heaven."},{"k":"gambirananda","t":"Those who are versed in the Vedas, who drink Soma and are purified of sin, pray for the heavenly goal by worshipping Me through sacrifices. Having reached the place (world) of the king of gods, which is the result of righteousness, they enjoy the divine pleasure of the gods in heaven."},{"k":"sankaranarayan","t":"The masters of the three Vedas, the soma-drinkers, purified of their sins, aspire for the heavenly goal by offering sacrifices to Me. They attain the meritorious world of the Lord of Gods and taste in the heavens the heavenly pleasures of the gods."}]},{"ch":9,"vn":21,"dev":"ते तं भुक्त्वा स्वर्गलोकं विशालं\nक्षीणे पुण्ये मर्त्यलोकं विशन्ति।\nएव त्रयीधर्ममनुप्रपन्ना\nगतागतं कामकामा लभन्ते","iast":"te taṁ bhuktvā swarga-lokaṁ viśhālaṁ\nkṣhīṇe puṇye martya-lokaṁ viśhanti\nevaṁ trayī-dharmam anuprapannā\ngatāgataṁ kāma-kāmā labhante","v":[{"k":"purohit","t":"Yet, although they enjoy the spacious glories of Paradise, when their merit is exhausted, they are born again into this world of mortals. They have followed the letter of the scriptures, yet, because they have sought to fulfill their own desires, they must depart and return again and again."},{"k":"sivananda","t":"They, having enjoyed the vast heaven, enter the world of mortals when their merit is exhausted; thus abiding by the injunctions of the three (Vedas) and desiring objects of desires, they attain to the state of coming and going."},{"k":"adidevananda","t":"Having enjoyed the spacious world of heaven, they return to the world of mortals, their merit having been exhausted. Thus, those who follow the Vedic rituals and are drawn by desires come and go."},{"k":"gambirananda","t":"After having enjoyed that vast heavenly world, they enter into the human world upon the exhaustion of their merit. Thus, those who follow the rites and duties prescribed in the three Vedas, and are desirous of pleasures, attain the state of coming and going."},{"k":"sankaranarayan","t":"Having enjoyed that vast world of heaven, they, when their merit is exhausted, enter the world of mortals. Thus, those who long for pleasure and continuously take refuge in the code of conduct prescribed by the Three Vedas, attain the state of going and coming."}]},{"ch":9,"vn":22,"dev":"अनन्याश्चिन्तयन्तो मां ये जनाः पर्युपासते।\nतेषां नित्याभियुक्तानां योगक्षेमं वहाम्यहम्","iast":"ananyāśh chintayanto māṁ ye janāḥ paryupāsate\nteṣhāṁ nityābhiyuktānāṁ yoga-kṣhemaṁ vahāmyaham","v":[{"k":"purohit","t":"But if a person meditates on Me and Me alone, worships Me always and everywhere, I will take upon Myself the fulfillment of their aspiration, and I will safeguard whatever they attain."},{"k":"sivananda","t":"For those men who worship Me alone, thinking of no one else, for those ever-united, I secure what they have not already possessed and preserve what they already possess."},{"k":"adidevananda","t":"Those who, excluding all else, think of Me and worship Me, aspiring after eternal union with Me, I look after their prosperity and welfare (Yoga and Ksema)."},{"k":"gambirananda","t":"Those persons who, becoming non-different from Me and meditating, worship Me everywhere, for them, who are ever attached to Me, I arrange for securing what they lack and preserving what they have."},{"k":"sankaranarayan","t":"Those men who, having nothing else as their goal, worship Me everywhere and are constantly thinking of Me alone; to them, who are fully and constantly attached to Me, I bear acquisition and the security of acquisition."}]},{"ch":9,"vn":23,"dev":"येऽप्यन्यदेवता भक्ता यजन्ते श्रद्धयाऽन्विताः।\nतेऽपि मामेव कौन्तेय यजन्त्यविधिपूर्वकम्","iast":"ye 'pyanya-devatā-bhaktā yajante śhraddhayānvitāḥ\nte 'pi mām eva kaunteya yajantyavidhi-pūrvakam","v":[{"k":"purohit","t":"Even those who worship the lesser powers, if they do so with faith, they are thereby worshipping Me, though not in the correct manner."},{"k":"sivananda","t":"Even those devotees who, endowed with faith, worship other gods, worship Me alone, O Arjuna, but by the wrong method."},{"k":"adidevananda","t":"Even those who are devoted to other divinities with faith in their hearts, worship Me alone, O Arjuna, though not in accordance with the Sastras."},{"k":"gambirananda","t":"Even those who, being devoted to other deities and endowed with faith, worship them, they also, O son of Kunti, worship Me alone, though following the wrong method."},{"k":"sankaranarayan","t":"O son of Kunti! Even those who are devotees of other gods and worship them with faith, worship Me alone, but following non-injunctive practices."}]},{"ch":9,"vn":24,"dev":"अहं हि सर्वयज्ञानां भोक्ता च प्रभुरेव च।\nन तु मामभिजानन्ति तत्त्वेनातश्च्यवन्ति ते","iast":"ahaṁ hi sarva-yajñānāṁ bhoktā cha prabhureva cha\nna tu mām abhijānanti tattvenātaśh chyavanti te","v":[{"k":"purohit","t":"I am the willing recipient of sacrifice, and I am its true Lord. But they do not know me truly, so they fall back."},{"k":"sivananda","t":"For I alone am the enjoyer and Lord of all sacrifices; but they do not know Me in reality, and thus they return to this mortal world."},{"k":"adidevananda","t":"For, I am the only enjoyer and the only Lord of all sacrifices. They do not recognize Me in My true nature; hence, they fall."},{"k":"gambirananda","t":"Indeed, I am the enjoyer and the Lord of all sacrifices, but they do not know Me truly. Therefore, they fall."},{"k":"sankaranarayan","t":"For I am the enjoyer and the Lord of all sacrifices, yet they do not recognize Me correctly and thus they turn away."}]},{"ch":9,"vn":25,"dev":"यान्ति देवव्रता देवान् पितृ़न्यान्ति पितृव्रताः।\nभूतानि यान्ति भूतेज्या यान्ति मद्याजिनोऽपि माम्","iast":"yānti deva-vratā devān pitṝīn yānti pitṛi-vratāḥ\nbhūtāni yānti bhūtejyā yānti mad-yājino 'pi mām","v":[{"k":"purohit","t":"The votaries of the lesser powers go to them; the devotees of spirits go to them; they who worship the powers of darkness, to such powers shall they go; and so too, those who worship me shall come to me."},{"k":"sivananda","t":"The worshippers of the gods go to them; the ancestor-worshippers go to the manes; the worshippers of the deities who preside over the elements go to them; but My devotees come to Me."},{"k":"adidevananda","t":"Devotees of gods go to the gods; manes-worshippers go to the manes; worshippers of Bhutas go to the Bhutas; and those who worship Me come to Me."},{"k":"gambirananda","t":"Those who worship the gods reach the gods; the worshippers of the manes go to the manes; the devotees of the Beings reach the Beings; and those who worship Me come to Me."},{"k":"sankaranarayan","t":"The devotees of the gods attain the gods; the devotees of the ancestors attain the ancestors; those who perform sacrifices for the spirits attain the spirits; and those who perform sacrifices for Me attain Me."}]},{"ch":9,"vn":26,"dev":"पत्रं पुष्पं फलं तोयं यो मे भक्त्या प्रयच्छति।\nतदहं भक्त्युपहृतमश्नामि प्रयतात्मनः","iast":"patraṁ puṣhpaṁ phalaṁ toyaṁ yo me bhaktyā prayachchhati\ntadahaṁ bhaktyupahṛitam aśhnāmi prayatātmanaḥ","v":[{"k":"purohit","t":"Whatever a person offers to Me, be it a leaf, flower, fruit, or water, I accept it, for it is offered with devotion and a pure mind."},{"k":"sivananda","t":"Whoever offers Me with devotion a leaf, a flower, a fruit, or a little water, that, so offered devotedly by the pure-minded, I accept."},{"k":"adidevananda","t":"Whoever offers Me with true devotion a leaf, a flower, a fruit, or some water, I accept this offering made with devotion by them who are pure of heart."},{"k":"gambirananda","t":"Whoever offers Me with devotion—a leaf, a flower, a fruit, or water—I accept that gift of the pure-hearted man which has been presented devotionally."},{"k":"sankaranarayan","t":"Whoever offers Me a leaf, a flower, a fruit, or even a little water with devotion, I accept that offering of devotion from one who has a well-controlled mind."}]},{"ch":9,"vn":27,"dev":"यत्करोषि यदश्नासि यज्जुहोषि ददासि यत्।\nयत्तपस्यसि कौन्तेय तत्कुरुष्व मदर्पणम्","iast":"yat karoṣhi yad aśhnāsi yaj juhoṣhi dadāsi yat\nyat tapasyasi kaunteya tat kuruṣhva mad-arpaṇam","v":[{"k":"purohit","t":"Whatever you do, whatever you eat, whatever you sacrifice and give, whatever austerities you practice, do all as an offering to Me."},{"k":"sivananda","t":"Whatever you do, whatever you eat, whatever you offer in sacrifice, whatever you give, whatever austerity you practice, O Arjuna, do it as an offering to Me."},{"k":"adidevananda","t":"Whatever you do, whatever you eat, whatever you offer, whatever you give away, whatever austerity you practice, O Arjuna, do that as an offering to Me."},{"k":"gambirananda","t":"O son of Kunti, whatever you do, whatever you eat, whatever you offer as a sacrifice, whatever you give, and whatever austerities you undertake—all of that you offer to Me."},{"k":"sankaranarayan","t":"Whatever you do, whatever you eat, whatever oblation you offer, whatever gift you make, and whatever austerity you perform, O son of Kunti, do that as an offering to Me."}]},{"ch":9,"vn":28,"dev":"शुभाशुभफलैरेवं मोक्ष्यसे कर्मबन्धनैः।\nसंन्यासयोगयुक्तात्मा विमुक्तो मामुपैष्यसि","iast":"śhubhāśhubha-phalair evaṁ mokṣhyase karma-bandhanaiḥ\nsannyāsa-yoga-yuktātmā vimukto mām upaiṣhyasi","v":[{"k":"purohit","t":"So, your action will have no result, either good or bad; but, through the spirit of renunciation, you will come to Me and be free."},{"k":"sivananda","t":"Thus, you shall be freed from the bonds of actions yielding good and evil fruits; with the mind steadfast in the Yoga of renunciation, and liberated, you shall come to Me."},{"k":"adidevananda","t":"Thus equipped in mind with the Yoga of renunciation, you will free yourself from the bonds of Karma, productive of both auspicious and inauspicious fruits. Thus liberated, you will come to Me."},{"k":"gambirananda","t":"Thus, you will become free from bondage in the form of actions which are productive of good and bad results. Having your mind imbued with the yoga of renunciation and becoming free, you will attain Me."},{"k":"sankaranarayan","t":"Thus, you shall be freed from the good and evil results which are the action-bonds. Having your innate nature immersed in the Yoga of renunciation and, thus, being fully liberated, you shall attain Me."}]},{"ch":9,"vn":29,"dev":"समोऽहं सर्वभूतेषु न मे द्वेष्योऽस्ति न प्रियः।\nये भजन्ति तु मां भक्त्या मयि ते तेषु चाप्यहम्","iast":"samo 'haṁ sarva-bhūteṣhu na me dveṣhyo 'sti na priyaḥ\nye bhajanti tu māṁ bhaktyā mayi te teṣhu chāpyaham","v":[{"k":"purohit","t":"I am the same to all beings; I do not favour any, nor do I hate any. However, those who worship Me devotedly, they live in Me and I in them."},{"k":"sivananda","t":"I am the same to all beings; there is none hateful or dear to Me; but those who worship Me with devotion are in Me, and I am also in them."},{"k":"adidevananda","t":"I am the same to all creation; there is none hateful or dear to me. But those who worship me with devotion abide in me, and I in them."},{"k":"gambirananda","t":"I am impartial towards all beings; to Me there is none detestable or none dear. But those who worship Me with devotion, they exist in Me, and I too exist in them."},{"k":"sankaranarayan","t":"I am the same in all beings; none is hateful to Me and none is dear; but whoever worships Me with devotion, they are in Me and I am in them."}]},{"ch":9,"vn":30,"dev":"अपि चेत्सुदुराचारो भजते मामनन्यभाक्।\nसाधुरेव स मन्तव्यः सम्यग्व्यवसितो हि सः","iast":"api chet su-durāchāro bhajate mām ananya-bhāk\nsādhur eva sa mantavyaḥ samyag vyavasito hi saḥ","v":[{"k":"purohit","t":"Even the most sinful, if he worships Me with his whole heart, shall be considered righteous, for he is treading the right path."},{"k":"sivananda","t":"Even if the most sinful worships Me, with devotion to no one else, he should indeed be regarded as righteous, for he has rightly resolved."},{"k":"adidevananda","t":"If even the most sinful man worships Me with undivided devotion, he should be regarded as holy, for he has rightly resolved."},{"k":"gambirananda","t":"Even if a man of very bad conduct worships Me with single-minded devotion, he is to be considered truly good; for he has rightly resolved."},{"k":"sankaranarayan","t":"Even if an incorrigible evil-doer worships Me, not resorting to any other [goal], he should be deemed to be righteous; for, he has properly undertaken his task."}]},{"ch":9,"vn":31,"dev":"क्षिप्रं भवति धर्मात्मा शश्वच्छान्तिं निगच्छति।\nकौन्तेय प्रतिजानीहि न मे भक्तः प्रणश्यति","iast":"kṣhipraṁ bhavati dharmātmā śhaśhvach-chhāntiṁ nigachchhati\nkaunteya pratijānīhi na me bhaktaḥ praṇaśhyati","v":[{"k":"purohit","t":"He will soon attain spirituality and eternal peace. O Arjuna! Believe me, my devotee is never lost."},{"k":"sivananda","t":"Soon he becomes righteous and attains eternal peace; O Arjuna, proclaim thou for certain that My devotee never perishes."},{"k":"adidevananda","t":"Quickly, he becomes righteous and obtains everlasting peace. Affirm on My behalf, O Arjuna, that My devotee never perishes."},{"k":"gambirananda","t":"He soon becomes possessed of a virtuous mind; he attains everlasting peace. Do you proclaim boldly, O son of Kunti, that My devotee will not be ruined."},{"k":"sankaranarayan","t":"Quickly he becomes righteous-minded and attains permanent peace. O son of Kunti! I swear that my devotee never gets lost."}]},{"ch":9,"vn":32,"dev":"मां हि पार्थ व्यपाश्रित्य येऽपि स्युः पापयोनयः।\nस्त्रियो वैश्यास्तथा शूद्रास्तेऽपि यान्ति परां गतिम्","iast":"māṁ hi pārtha vyapāśhritya ye 'pi syuḥ pāpa-yonayaḥ\nstriyo vaiśhyās tathā śhūdrās te 'pi yānti parāṁ gatim","v":[{"k":"purohit","t":"Even the children of sinful parents, those miscalled the weaker sex, merchants, and laborers, if they make Me their refuge, they shall attain the highest."},{"k":"sivananda","t":"For, taking refuge in Me, they who, O Arjuna, may be of a sinful birth—women, Vaisyas, and Sudras—attain the Supreme Goal."},{"k":"adidevananda","t":"By taking refuge in Me, even those of evil birth, women, Vaisyas, and Sudras, attain the supreme state."},{"k":"gambirananda","t":"For, O son of Prtha, even those who are born of sin-women, Vaisyas, as well as Sudras—[S.'s construction of this portion is: women, Vaisyas as well as Sudras, and even others who are born of sin (i.e., those who are born low and are of vile deeds, viz Mlecchas, Pukkasas and others). M.S. also takes papa-yonayah (born of sin) as a separate phrase, and classifies women and others only as those darred from Vedic study, etc.-Tr.]—even they reach the highest Goal by taking shelter under Me."},{"k":"sankaranarayan","t":"O son of Prtha, even those who are of sinful birth, women, men of working class, and the members of the fourth caste—even they, having taken refuge in Me, attain the highest goal."}]},{"ch":9,"vn":33,"dev":"किं पुनर्ब्राह्मणाः पुण्या भक्ता राजर्षयस्तथा।\nअनित्यमसुखं लोकमिमं प्राप्य भजस्व माम्","iast":"kiṁ punar brāhmaṇāḥ puṇyā bhaktā rājarṣhayas tathā\nanityam asukhaṁ lokam imaṁ prāpya bhajasva mām","v":[{"k":"purohit","t":"What need is there, then, to mention the holy ministers of God, the devotees, and the saintly rulers? Therefore, do you, born in this changing and miserable world, also worship Me."},{"k":"sivananda","t":"How much more easily, then, do Brahmins and devoted royal saints attain the goal? Having come to this impermanent and unhappy world, do thou worship Me."},{"k":"adidevananda","t":"How much more then, for the pure Brahmanas and royal sages who are My devotees! Having obtained this transient and joyless world, they should worship Me."},{"k":"gambirananda","t":"What of the holy Brahmanas and devoted, wise sages? Having come to this fleeting, miserable world, worship Me."},{"k":"sankaranarayan","t":"Certainly, it should be so in the case of the pious men of the priestly class and devoted royal seers. Having come to this transient and joyless world, you should be devoted to Me."}]},{"ch":9,"vn":34,"dev":"मन्मना भव मद्भक्तो मद्याजी मां नमस्कुरु।\nमामेवैष्यसि युक्त्वैवमात्मानं मत्परायणः","iast":"man-manā bhava mad-bhakto mad-yājī māṁ namaskuru\nmām evaiṣhyasi yuktvaivam ātmānaṁ mat-parāyaṇaḥ","v":[{"k":"purohit","t":"Fix your mind on Me, devote yourself to Me, sacrifice for Me, surrender to Me, make Me the object of your aspirations, and you shall assuredly become one with Me, Who am your own Self."},{"k":"sivananda","t":"Fix your mind on Me; be devoted to Me; sacrifice to Me; bow down to Me; having thus united your whole self to Me, taking Me as the supreme goal, you will come to Me."},{"k":"adidevananda","t":"Focus your mind on Me, be My devotee, worship Me. Bow down to Me. Engaging your mind in this manner and regarding Me as the supreme goal, you will come to Me."},{"k":"gambirananda","t":"Having your mind fixed on Me, be devoted to Me, sacrifice to Me, and bow down to Me. By concentrating your mind and accepting Me as the supreme goal, you shall surely attain Me, who am thus the Self."},{"k":"sankaranarayan","t":"Fix your mind on Me; be devoted to Me; offer sacrifice to Me; pay homage to Me. Thus, having your self fixed and Me as your supreme goal, you will certainly attain Me."}]},{"ch":10,"vn":1,"dev":"श्री भगवानुवाच\nभूय एव महाबाहो श्रृणु मे परमं वचः।\nयत्तेऽहं प्रीयमाणाय वक्ष्यामि हितकाम्यया","iast":"śhrī bhagavān uvācha\nbhūya eva mahā-bāho śhṛiṇu me paramaṁ vachaḥ\nyatte 'haṁ prīyamāṇāya vakṣhyāmi hita-kāmyayā","v":[{"k":"purohit","t":"Lord Shri Krishna said: Now, O Prince! Listen to My supreme advice, which I give you for the sake of your welfare, for you are My beloved."},{"k":"sivananda","t":"The Blessed Lord said, Again, O mighty-armed Arjuna, listen to my supreme word which I will declare to you, who are beloved, for your welfare."},{"k":"adidevananda","t":"The Lord said, \"Further, O Arjuna, listen to My Supreme word. Desiring your good, I shall speak to you who loves Me.\""},{"k":"gambirananda","t":"The Blessed Lord said, O mighty-armed one, listen once more to My supreme utterance, which I, wishing for your welfare, shall speak to you who take delight in it."},{"k":"sankaranarayan","t":"The Bhagavat said, \"O mighty-armed Arjuna! Listen to My best message once more, which I shall declare to you with good intention, for you are dear to Me.\""}]},{"ch":10,"vn":2,"dev":"न मे विदुः सुरगणाः प्रभवं न महर्षयः।\nअहमादिर्हि देवानां महर्षीणां च सर्वशः","iast":"na me viduḥ sura-gaṇāḥ prabhavaṁ na maharṣhayaḥ\naham ādir hi devānāṁ maharṣhīṇāṁ cha sarvaśhaḥ","v":[{"k":"purohit","t":"Neither the professors of divinity nor the great ascetics know My origin, for I am the source from which they all originate."},{"k":"sivananda","t":"Neither the hosts of the gods nor the great sages know My origin; for I am the source of all the gods and the great sages in every way."},{"k":"adidevananda","t":"Neither the host of gods nor the great sages know My power; for I am indeed the source of the gods and the great sages."},{"k":"gambirananda","t":"Neither the gods nor the great sages know My majesty, for I am the source of them all in all respects."},{"k":"sankaranarayan","t":"Neither the hosts of gods nor the great sages know My origin, for I am the first in every respect among the gods and great sages."}]},{"ch":10,"vn":3,"dev":"यो मामजमनादिं च वेत्ति लोकमहेश्वरम्।\nअसम्मूढः स मर्त्येषु सर्वपापैः प्रमुच्यते","iast":"yo māmajam anādiṁ cha vetti loka-maheśhvaram\nasammūḍhaḥ sa martyeṣhu sarva-pāpaiḥ pramuchyate","v":[{"k":"purohit","t":"He who knows Me as the unborn, without beginning, the Lord of the universe, he, stripped of his delusions, becomes free from all conceivable sins."},{"k":"sivananda","t":"He who knows Me as unborn and beginningless, as the great Lord of the worlds, he among mortals is undeluded and is liberated from all sins."},{"k":"adidevananda","t":"He who knows Me as unborn, without a beginning, and the great Lord of the worlds—he among mortals is undeluded and is released from all sin."},{"k":"gambirananda","t":"He who knows Me—the birthless, beginningless, and great Lord of the worlds—he, the undeluded one among mortals, becomes freed from all sins."},{"k":"sankaranarayan","t":"Whoever knows Me as the unborn and beginningless Absolute Lord of the universe, that person, not deluded among mortals, is freed from all sins."}]},{"ch":10,"vn":4,"dev":"बुद्धिर्ज्ञानमसंमोहः क्षमा सत्यं दमः शमः।\nसुखं दुःखं भवोऽभावो भयं चाभयमेव च","iast":"buddhir jñānam asammohaḥ kṣhamā satyaṁ damaḥ śhamaḥ\nsukhaṁ duḥkhaṁ bhavo 'bhāvo bhayaṁ chābhayameva cha","v":[{"k":"purohit","t":"Intelligence, wisdom, non-delusion, forgiveness, truth, self-control, calmness, pleasure, pain, birth, death, fear, and fearlessness;"},{"k":"sivananda","t":"Intellect, wisdom, non-delusion, forgiveness, truth, self-restraint, calmness, happiness, pain, existence or birth, non-existence or death, fear, and also fearlessness."},{"k":"adidevananda","t":"Intelligence, knowledge, non-delusion, forbearance, truth, restraint, self-control, pleasure, pain, exaltation, and depression, fear, and fearlessness;"},{"k":"gambirananda","t":"Intelligence, wisdom, non-delusion, forgiveness, truth, control of the external organs, control of the internal organs, happiness, sorrow, birth, death, and fearlessness;"},{"k":"sankaranarayan","t":"Intellect, knowledge, steadiness, patience, truth, control over sense-organs, tranquility of mind, pleasure, pain, birth, death, fear, and courage."}]},{"ch":10,"vn":5,"dev":"अहिंसा समता तुष्टिस्तपो दानं यशोऽयशः।\nभवन्ति भावा भूतानां मत्त एव पृथग्विधाः","iast":"ahiṁsā   samatā  tuṣṭis tapo dānaṁ   yaśo    'yaśaḥ  bhavanti    bhāvā   bhūtānāṁ    matta   eva pṛthag-vidhāḥ","v":[{"k":"purohit","t":"Harmlessness, equanimity, contentment, austerity, beneficence, fame, and failure—all these characteristics of beings spring from Me alone."},{"k":"sivananda","t":"Non-injury, equanimity, contentment, austerity, beneficence, fame, and ill-fame—these different qualities of beings arise from Me alone."},{"k":"adidevananda","t":"Non-violence, reality, cheerfulness, austerity, beneficence, fame, and infamy—these different qualities of beings arise from Me alone."},{"k":"gambirananda","t":"Non-injury, equanimity, satisfaction, austerity, charity, fame, and infamy—these different dispositions of beings spring from Me alone."},{"k":"sankaranarayan","t":"[Also], non-injury, equanimity, contentment, austerity, charity, repute, and ill-repute—all these diverse dispositions of beings emanate from none other than Me."}]},{"ch":10,"vn":6,"dev":"महर्षयः सप्त पूर्वे चत्वारो मनवस्तथा।\nमद्भावा मानसा जाता येषां लोक इमाः प्रजाः","iast":"maharṣhayaḥ sapta pūrve chatvāro manavas tathā\nmad-bhāvā mānasā jātā yeṣhāṁ loka imāḥ prajāḥ","v":[{"k":"purohit","t":"The seven Great Seers, the progenitors of mankind, the Ancient Four, and the Lawgivers were born of My will and come forth directly from Me. The race of mankind has sprung from them. (Mareechi, Atri, Angira, Pulah, Kratu, Pulastya, Vahishta; the Masters: Sanak, Sanandan, Sanatan, Sanatkumar.)"},{"k":"sivananda","t":"The seven great sages, the ancient four, and the Manus, possessing powers like Mine (due to their minds being fixed on Me), were born from My mind; from them, these creatures have been born in this world."},{"k":"adidevananda","t":"The seven great seers of yore, as well as the four Manus, all possessing My mental disposition, were born from My mind. All these creatures of the world are descended from them."},{"k":"gambirananda","t":"The seven great sages, as well as the four Manus of ancient days, from whom all these creatures in the world have descended, had their thoughts fixed on Me, and they were born from My mind."},{"k":"sankaranarayan","t":"The ancient Seven Great Sages and also the Four Manus, from whom these creatures in this world are offspring—they have been born from My mental dispositions."}]},{"ch":10,"vn":7,"dev":"एतां विभूतिं योगं च मम यो वेत्ति तत्त्वतः।\nसोऽविकम्पेन योगेन युज्यते नात्र संशयः","iast":"etāṁ vibhūtiṁ yogaṁ cha mama yo vetti tattvataḥ\nso 'vikampena yogena yujyate nātra sanśhayaḥ","v":[{"k":"purohit","t":"He who rightly understands My manifested glory and My creative power attains perfect peace without a doubt."},{"k":"sivananda","t":"He who truly knows these manifold manifestations of My Being and this Yoga-power of Mine, becomes established in unshakable Yoga; there is no doubt about it."},{"k":"adidevananda","t":"He who truly knows this supreme manifestation and splendor of My auspicious attributes, becomes united with the unshakeable Yoga of Bhakti—there is no doubt of this."},{"k":"gambirananda","t":"One who knows truly this majesty and yoga of Mine, he becomes imbued with unwavering yoga. There is no doubt about it."},{"k":"sankaranarayan","t":"He who knows correctly this extensively manifesting power and My Yogic power—he is endowed with unwavering Yoga; there is no doubt about it."}]},{"ch":10,"vn":8,"dev":"अहं सर्वस्य प्रभवो मत्तः सर्वं प्रवर्तते।\nइति मत्वा भजन्ते मां बुधा भावसमन्विताः","iast":"ahaṁ sarvasya prabhavo mattaḥ sarvaṁ pravartate\niti matvā bhajante māṁ budhā bhāva-samanvitāḥ","v":[{"k":"purohit","t":"I am the source of all; from me everything flows. Therefore, the wise worship me with an unchanging devotion."},{"k":"sivananda","t":"I am the source of all; from me everything evolves; Understanding this, the wise, endowed with meditation, worship me."},{"k":"adidevananda","t":"I am the origin of all; from me everything proceeds. Thinking thus, the wise worship me with all devotion (Bhava)."},{"k":"gambirananda","t":"I am the origin of all; everything moves on due to Me. Realizing this, the wise ones, filled with fervor, adore Me."},{"k":"sankaranarayan","t":"'He is the source of all, and from Him all comes forth' - Thus viewing, the wise revere Me with devotion."}]},{"ch":10,"vn":9,"dev":"मच्चित्ता मद्गतप्राणा बोधयन्तः परस्परम्।\nकथयन्तश्च मां नित्यं तुष्यन्ति च रमन्ति च","iast":"mach-chittā mad-gata-prāṇā bodhayantaḥ parasparam\nkathayantaśh cha māṁ nityaṁ tuṣhyanti cha ramanti cha","v":[{"k":"purohit","t":"With minds concentrated on Me, with lives absorbed in Me, and enlightening one another, they ever feel content and happy."},{"k":"sivananda","t":"With their minds and lives wholly absorbed in Me, they enlighten each other and ever speak of Me, being satisfied and delighted."},{"k":"adidevananda","t":"With their minds focused on Me, their pranas centered in Me, inspiring one another and always speaking of Me, they live in contentment and bliss at all times."},{"k":"gambirananda","t":"With their minds fixed on Me, dedicating their lives to Me, enlightening one another, and always speaking of Me, they derive satisfaction and rejoice."},{"k":"sankaranarayan","t":"Having their minds fixed on Me, having their lives gone into Me, enlightening one another, and constantly talking about Me, they are pleased and delighted."}]},{"ch":10,"vn":10,"dev":"तेषां सततयुक्तानां भजतां प्रीतिपूर्वकम्।\nददामि बुद्धियोगं तं येन मामुपयान्ति ते","iast":"teṣhāṁ satata-yuktānāṁ bhajatāṁ prīti-pūrvakam\ndadāmi buddhi-yogaṁ taṁ yena mām upayānti te","v":[{"k":"purohit","t":"To those who are always devout and who worship Me with love, I give the power of discrimination that leads them to Me."},{"k":"sivananda","t":"To those who are ever steadfast, worshipping me with love, I give the yoga of discrimination, by which they come to me."},{"k":"adidevananda","t":"To those who are ceaselessly united with Me and who worship Me with immense love, I lovingly grant that mental disposition (Buddhi-yoga) which leads them to Me."},{"k":"gambirananda","t":"To those who are ever devoted and worship Me with love, I grant the possession of wisdom that leads them to Me."},{"k":"sankaranarayan","t":"To these persons, who thus mingle with Me and revere Me with love, I grant the knowledge-Yoga by which they can reach Me."}]},{"ch":10,"vn":11,"dev":"तेषामेवानुकम्पार्थमहमज्ञानजं तमः।\nनाशयाम्यात्मभावस्थो ज्ञानदीपेन भास्वता","iast":"teṣhām evānukampārtham aham ajñāna-jaṁ tamaḥ\nnāśhayāmyātma-bhāva-stho jñāna-dīpena bhāsvatā","v":[{"k":"purohit","t":"By My grace, I live in their hearts, and I dispel the darkness of ignorance with the shining light of wisdom."},{"k":"sivananda","t":"Out of mere compassion for them, I, dwelling within their selves, destroy the darkness born of ignorance with the luminous lamp of knowledge."},{"k":"adidevananda","t":"Out of compassion for them alone, I, abiding in their mental activity as its object, dispel the darkness born of ignorance with the brilliant lamp of knowledge."},{"k":"gambirananda","t":"Out of compassion for them alone, I, residing in their hearts, destroy the darkness born of ignorance with the luminous lamp of knowledge."},{"k":"sankaranarayan","t":"Out of compassion only towards these men, I, who remain as their very Self, destroy with the shining light of wisdom, their darkness born of ignorance."}]},{"ch":10,"vn":12,"dev":"अर्जुन उवाच\nपरं ब्रह्म परं धाम पवित्रं परमं भवान्।\nपुरुषं शाश्वतं दिव्यमादिदेवमजं विभुम्","iast":"arjuna uvācha\nparaṁ brahma paraṁ dhāma pavitraṁ paramaṁ bhavān\npuruṣhaṁ śhāśhvataṁ divyam ādi-devam ajaṁ vibhum","v":[{"k":"purohit","t":"Arjuna asked: Thou art the Supreme Spirit, the Eternal Home, the Holiest of Holies, the Eternal Divine Self, the Primal God, the Unborn, and Omnipresent."},{"k":"sivananda","t":"Arjuna said, \"You are the Supreme Brahman, the supreme abode, the supreme purifier, eternal, divine Person, the primeval God, unborn, and omnipresent.\""},{"k":"adidevananda","t":"Arjuna said, \"You are the Supreme Brahman, the Supreme Light, and the Supreme Sanctifier. All the seers proclaim You as the eternal, divine Person, the Primal Lord, the unborn, and all-pervading. So too do the divine sages Narada, Asita, Devala, and Vyasa proclaim. You Yourself also proclaim this.\""},{"k":"gambirananda","t":"Arjuna said, \"You are the supreme Brahman, the supreme Light, the supreme Sanctifier. All the sages, as well as the divine sage Narada, Asita, Devala, and Vyasa [Although Narada and the other sages are already mentioned by the words 'all the sages', they are still named separately due to their eminence. Asita is the father of Devala.] call You the eternal divine Person, the Primal God, the Birthless, the Omnipresent; and You Yourself indeed tell me this.\""},{"k":"sankaranarayan","t":"Arjuna said, \"You are the Supreme Brahman, the Supreme Abode, and the Supreme Purifier. All the seers, as well as the divine seer Narada, Asita Devala, and Vyasa, describe You as the Eternal Divine Soul, the Unborn, and the All-Manifesting First-God. You too have said this to me.\""}]},{"ch":10,"vn":13,"dev":"आहुस्त्वामृषयः सर्वे देवर्षिर्नारदस्तथा।\nअसितो देवलो व्यासः स्वयं चैव ब्रवीषि मे","iast":"āhus tvām ṛiṣhayaḥ sarve devarṣhir nāradas tathā\nasito devalo vyāsaḥ svayaṁ chaiva bravīṣhi me","v":[{"k":"purohit","t":"So have said the seers, the divine sage Narada, Asita, Devala, and Vyasa; and Thou Thyself also sayest it."},{"k":"sivananda","t":"All the sages have thus declared Thee, as also the divine sage Narada; so also Asita, Devala, and Vyasa; and now Thou Thyself dost say so to me."},{"k":"adidevananda","t":"Arjuna said, \"You are the Supreme Brahman, the Supreme Light, and the Supreme Sanctifier. All the seers proclaim You as the eternal, divine Person, the Primal Lord, the unborn, and all-pervading. So too do the divine sages Narada, Asita, Devala, and Vyasa proclaim. You Yourself also proclaim this.\""},{"k":"gambirananda","t":"Arjuna said, \"You are the supreme Brahman, the supreme Light, the supreme Sanctifier. All the sages, as well as the divine sage Narada, Asita, Devala, and Vyasa [Although Narada and the other sages are already mentioned by the words 'all the sages', they are still named separately due to their eminence. Asita is the father of Devala.] call You the eternal divine Person, the Primal God, the Birthless, the Omnipresent; and You Yourself indeed tell me this.\""},{"k":"sankaranarayan","t":"Arjuna said, \"You are the Supreme Brahman, the Supreme Abode, and the Supreme Purifier. All the seers, as well as the divine seer Narada, Asita Devala, and Vyasa, describe You as the Eternal Divine Soul, the Unborn, and the All-Manifesting First-God. You too have said this to me.\""}]},{"ch":10,"vn":14,"dev":"सर्वमेतदृतं मन्ये यन्मां वदसि केशव।\nन हि ते भगवन् व्यक्ितं विदुर्देवा न दानवाः","iast":"sarvam etad ṛitaṁ manye yan māṁ vadasi keśhava\nna hi te bhagavan vyaktiṁ vidur devā na dānavāḥ","v":[{"k":"purohit","t":"I believe in what You have said, my Lord! For neither the godly nor the godless comprehend Your manifestation."},{"k":"sivananda","t":"I believe all that You have said to me to be true, O Krishna; indeed, O blessed Lord! Neither the gods nor the demons know Your manifestation (origin)."},{"k":"adidevananda","t":"I deem as true all that you have said to me, O Krishna. Truly, O Lord, neither the gods nor the demons know your manifestation."},{"k":"gambirananda","t":"O Kesava, I accept as true all that You have told me. Certainly, O Lord, neither the gods nor the demons can comprehend Your glory."},{"k":"sankaranarayan","t":"What You tell me, I take all to be true, O Kesava! For, O Bhagavat, neither the gods nor the great sages know Your manifestation."}]},{"ch":10,"vn":15,"dev":"स्वयमेवात्मनाऽत्मानं वेत्थ त्वं पुरुषोत्तम।\nभूतभावन भूतेश देवदेव जगत्पते","iast":"swayam evātmanātmānaṁ vettha tvaṁ puruṣhottama\nbhūta-bhāvana bhūteśha deva-deva jagat-pate","v":[{"k":"purohit","t":"You alone know Yourself, by the power of Your Self; You are the Supreme Spirit, the Source and Master of all being, the Lord of Lords, the Ruler of the Universe."},{"k":"sivananda","t":"Verily, Thou Thyself knowest Thyself by Thyself, O Supreme Person, O source and Lord of all beings, O God of gods, O ruler of the world!"},{"k":"adidevananda","t":"O Supreme Person, O Creator of beings, O Lord of beings, O God of gods, O Ruler of the universe, You Yourself know Yourself alone."},{"k":"gambirananda","t":"O Supreme Person, Creator of beings, Lord of beings, God of gods, Lord of the worlds, You alone know Yourself by Yourself."},{"k":"sankaranarayan","t":"Only yourself know yourself by yourself, O Supreme Purusha, Creator of all beings, Lord of beings, God of gods, Lord of the universe!"}]},{"ch":10,"vn":16,"dev":"वक्तुमर्हस्यशेषेण दिव्या ह्यात्मविभूतयः।\nयाभिर्विभूतिभिर्लोकानिमांस्त्वं व्याप्य तिष्ठसि","iast":"vaktum arhasyaśheṣheṇa divyā hyātma-vibhūtayaḥ\nyābhir vibhūtibhir lokān imāṁs tvaṁ vyāpya tiṣhṭhasi","v":[{"k":"purohit","t":"Please tell me about all of Your glorious manifestations, through which You pervade the world."},{"k":"sivananda","t":"You should indeed tell, without reserve, of your divine glories by which you exist, pervading all these worlds. (No one else can do so.)"},{"k":"adidevananda","t":"You should tell Me without reserve Your divine manifestations where You abide, pervading all these worlds."},{"k":"gambirananda","t":"Be pleased to speak in full of Your own divine manifestations, through which You exist pervading these worlds."},{"k":"sankaranarayan","t":"You alone are capable of fully declaring the auspicious manifesting powers of Yours, through which manifesting power You remain pervading these worlds."}]},{"ch":10,"vn":17,"dev":"कथं विद्यामहं योगिंस्त्वां सदा परिचिन्तयन्।\nकेषु केषु च भावेषु चिन्त्योऽसि भगवन्मया","iast":"kathaṁ vidyām ahaṁ yogins tvāṁ sadā parichintayan\nkeṣhu keṣhu cha bhāveṣhu chintyo 'si bhagavan mayā","v":[{"k":"purohit","t":"O Master! How can I, through constant meditation, come to know You? My Lord! What are Your various manifestations through which I can meditate on You?"},{"k":"sivananda","t":"How shall I, ever meditating, know you, O Yogin? In what aspects or things, O blessed Lord, should I think of you?"},{"k":"adidevananda","t":"How can I, Your devotee, know You by constantly meditating on You? And in what ways, O Lord, should I meditate on You?"},{"k":"gambirananda","t":"O Yogi, how shall I know You by remaining ever-engaged in meditation? And through what objects, O Lord, should I meditate on You?"},{"k":"sankaranarayan","t":"O Mighty Yogin! How should I know you, meditating on you? In what various forms, O Bhagavat, should I contemplate you?"}]},{"ch":10,"vn":18,"dev":"विस्तरेणात्मनो योगं विभूतिं च जनार्दन।\nभूयः कथय तृप्तिर्हि श्रृण्वतो नास्ति मेऽमृतम्","iast":"vistareṇātmano yogaṁ vibhūtiṁ cha janārdana\nbhūyaḥ kathaya tṛiptir hi śhṛiṇvato nāsti me 'mṛitam","v":[{"k":"purohit","t":"Tell me again, I pray, of Thy power and Thy glory in full; for I feel that I am never satisfied when I listen to Thy immortal words."},{"k":"sivananda","t":"Tell me again in detail, O Krishna, of your yogic power and glory; for I am not satiated with what I have heard of your life-giving and nectar-like speech."},{"k":"adidevananda","t":"Speak to me again in full, O Krishna, about Your attributes and glories. For I am not sated by hearing Your ambrosial words."},{"k":"gambirananda","t":"O Janardana, please narrate to me again in detail Your own yoga and divine manifestations. For, while hearing Your nectar-like words, I am not satiated."},{"k":"sankaranarayan","t":"In detail, please expound once again Your own Yogic power and the manifesting power. O Janardana! I don't feel contented in hearing Your nectar-like exposition."}]},{"ch":10,"vn":19,"dev":"श्री भगवानुवाच\nहन्त ते कथयिष्यामि दिव्या ह्यात्मविभूतयः।\nप्राधान्यतः कुरुश्रेष्ठ नास्त्यन्तो विस्तरस्य मे","iast":"śhrī bhagavān uvācha\nhanta te kathayiṣhyāmi divyā hyātma-vibhūtayaḥ\nprādhānyataḥ kuru-śhreṣhṭha nāstyanto vistarasya me","v":[{"k":"purohit","t":"Lord Shri Krishna replied: So be it, My beloved friend! I will unfold to you some of the chief aspects of My glory. There is no end to its full extent."},{"k":"sivananda","t":"The Blessed Lord said, \"Very well! Now I will declare to you My divine glories in their prominence, O Arjuna; there is no end to their detailed description.\""},{"k":"adidevananda","t":"The Lord said, \"Indeed, I shall tell you, O Arjuna, My auspicious manifestations—those that are most prominent among them. There is no end to their extent.\""},{"k":"gambirananda","t":"The Blessed Lord said, O best of the Kurus, now, according to their importance, I shall describe to you My own glories, which are indeed divine. There is no end to My manifestations."},{"k":"sankaranarayan","t":"The Bhagavat said, \"Yes, O best among the Kurus! I shall expound to you only the chief, auspicious manifesting powers of Mine, for there would be no end to My details.\""}]},{"ch":10,"vn":20,"dev":"अहमात्मा गुडाकेश सर्वभूताशयस्थितः।\nअहमादिश्च मध्यं च भूतानामन्त एव च","iast":"aham ātmā guḍākeśha sarva-bhūtāśhaya-sthitaḥ\naham ādiśh cha madhyaṁ cha bhūtānām anta eva cha","v":[{"k":"purohit","t":"O Arjuna! I am the Self, seated in the hearts of all beings; I am the beginning, the life, and the end of them all."},{"k":"sivananda","t":"I am the Self, O Gudakesa, seated in the hearts of all beings; I am the beginning, the middle, and the end of all beings."},{"k":"adidevananda","t":"I am the Self, O Arjuna, dwelling in the hearts of all beings; I am the beginning, the middle, and the end of all beings."},{"k":"gambirananda","t":"O Gudakesa, I am the Self residing in the hearts of all beings, and I am the beginning, middle, and end of all beings."},{"k":"sankaranarayan","t":"O conqueror of sleep! I am the Soul residing in the hearts of all beings; I am the beginning, the middle, and the very end of all beings."}]},{"ch":10,"vn":21,"dev":"आदित्यानामहं विष्णुर्ज्योतिषां रविरंशुमान्।\nमरीचिर्मरुतामस्मि नक्षत्राणामहं शशी","iast":"ādityānām ahaṁ viṣhṇur jyotiṣhāṁ ravir anśhumān\nmarīchir marutām asmi nakṣhatrāṇām ahaṁ śhaśhī","v":[{"k":"purohit","t":"Of all the creative powers, I am the Creator; of luminaries, the Sun; of winds, the Whirlwind; and of planets, the Moon."},{"k":"sivananda","t":"Among the twelve Adityas, I am Vishnu; among luminaries, the radiant sun; among the seven or forty-nine Maruts, I am Marichi; among stars, I am the moon."},{"k":"adidevananda","t":"Of the Adityas, I am Vishnu; of luminous bodies, I am the radiant sun. Of the Maruts, I am Marici, and among the constellations, I am the moon."},{"k":"gambirananda","t":"Among the Adityas [viz Dhata, Mitra, Aryama, Rudra, Varuna, Surya, Bhaga, Vivasvan, Pusa, Savita, Tvasta, and Visnu.-Tr.], I am Visnu; among the luminaries, the radiant sun; among the (forty-nine) Maruts [The seven groups of Maruts are Avaha, Pravaha, Vivaha, Paravaha, Udvaha, Samvaha, and Parivaha.-Tr.], I am Marici; among the stars, I am the moon."},{"k":"sankaranarayan","t":"Of the sons of Aditi, I am Vishnu; of the luminaries, the radiant Sun; of the Maruts, I am Marici; of the stars, I am the Moon."}]},{"ch":10,"vn":22,"dev":"वेदानां सामवेदोऽस्मि देवानामस्मि वासवः।\nइन्द्रियाणां मनश्चास्मि भूतानामस्मि चेतना","iast":"vedānāṁ sāma-vedo 'smi devānām asmi vāsavaḥ\nindriyāṇāṁ manaśh chāsmi bhūtānām asmi chetanā","v":[{"k":"purohit","t":"Of the Vedas, I am the hymns; I am the electric force in the powers of nature; of the senses, I am the mind; and I am the intelligence in all that lives."},{"k":"sivananda","t":"Among the Vedas, I am the Sama-Veda; among the gods, I am Vasava; among the senses, I am the mind; and among living beings, I am intelligence."},{"k":"adidevananda","t":"Of the Vedas, I am the Samaveda; of gods, I am Indra; of sense-organs, I am the mind; and of living beings, I am consciousness."},{"k":"gambirananda","t":"Among the Vedas, I am the Sama-Veda; among the gods, I am Indra. Among the organs, I am the mind, and I am the intelligence in creatures."},{"k":"sankaranarayan","t":"Of the Vedas, I am the Samaveda; of the gods, I am Vasava (Indra); of the sense-organs, I am the mind; of the beings, I am the consciousness."}]},{"ch":10,"vn":23,"dev":"रुद्राणां शङ्करश्चास्मि वित्तेशो यक्षरक्षसाम्।\nवसूनां पावकश्चास्मि मेरुः शिखरिणामहम्","iast":"rudrāṇāṁ śhaṅkaraśh chāsmi vitteśho yakṣha-rakṣhasām\nvasūnāṁ pāvakaśh chāsmi meruḥ śhikhariṇām aham","v":[{"k":"purohit","t":"Among forces of vitality, I am the life; I am Mammon to the heathens and the godless; I am the energy in fire, earth, wind, sky, heaven, sun, moon, and planets; and among mountains, I am Mount Meru."},{"k":"sivananda","t":"And among the Rudras, I am Sankara; among the Yakshas and Rakshasas, the Lord of Wealth (Kubera); among the Vasus, I am Pavaka (Fire); and among the seven mountains, I am Meru."},{"k":"adidevananda","t":"Of the Rudras, I am Sankara. Of the Yaksas and Raksasas, I am the Lord of Wealth (Kubera). Of the Vasus, I am Agni; of the mountains, I am Meru."},{"k":"gambirananda","t":"Among the Rudras, I am Aja, Ekapada, Ahirbudhnya, Pinaki, Aparajita, Tryam-baka, Mahesvara, Vrsakapi, Sambhu, Harana, and Isvara; among the Yaksas and goblins, I am Kubera; among the Vasus, I am Fire; and among the mountains, I am Meru."},{"k":"sankaranarayan","t":"And of the Rudras, I am Sankara; of the Yaksas and the Raksas, I am the Lord of Wealth (Kubera); of the Vasus, I am the Fire-God; of the mountains, I am Meru."}]},{"ch":10,"vn":24,"dev":"पुरोधसां च मुख्यं मां विद्धि पार्थ बृहस्पतिम्।\nसेनानीनामहं स्कन्दः सरसामस्मि सागरः","iast":"purodhasāṁ cha mukhyaṁ māṁ viddhi pārtha bṛihaspatim\nsenānīnām ahaṁ skandaḥ sarasām asmi sāgaraḥ","v":[{"k":"purohit","t":"Among the priests, know, O Arjuna, that I am the priest Brihaspati; of generals, I am Skanda, the Commander-in-Chief, and of waters, I am the Ocean."},{"k":"sivananda","t":"And, among the household priests of kings, O Arjuna, know Me to be the chief, Brihaspati; among the army generals, I am Skanda; among lakes, I am the ocean."},{"k":"adidevananda","t":"Among family priests, O Arjuna, know Me to be the chief Brhaspati; of generals, I am Skanda; of reservoirs of water, I am the ocean."},{"k":"gambirananda","t":"O son of Prtha, know me to be Brhaspati, the foremost among the priests of kings. Among commanders of armies, I am Skanda; among large expanses of water, I am the sea."},{"k":"sankaranarayan","t":"Of the royal priests, I am the chief, viz., Brhaspati (the priest of gods), O son of Prtha; you should know that. Of the army generals, I am Skanda [the War-god]; of the water reservoirs, I am the ocean."}]},{"ch":10,"vn":25,"dev":"महर्षीणां भृगुरहं गिरामस्म्येकमक्षरम्।\nयज्ञानां जपयज्ञोऽस्मि स्थावराणां हिमालयः","iast":"maharṣhīṇāṁ bhṛigur ahaṁ girām asmyekam akṣharam\nyajñānāṁ japa-yajño 'smi sthāvarāṇāṁ himālayaḥ","v":[{"k":"purohit","t":"Of the great seers, I am Bhrigu; of words, I am Om; of offerings, I am the silent prayer; among things immovable, I am the Himalayas."},{"k":"sivananda","t":"Among the great sages, I am Bhrigu; among words, I am the one syllable (Om); among sacrifices, I am the sacrifice of silent repetition; among the immovable things, I am the Himalayas."},{"k":"adidevananda","t":"Of the great seers, I am Bhrgu; of words, I am the single-lettered word Om; of sacrifices, I am the sacrifice of Japa; of immovable things, I am the Himalayas."},{"k":"gambirananda","t":"Among the great sages, I am Bhrgu; of words, I am the single syllable (Om). Among rituals, I am the ritual of Japa of the immovables, the Himalayas."},{"k":"sankaranarayan","t":"Of the great seers, I am Bhrgu; of the words, I am the single-syllable (Om); of the sacrifices [performed with external objects], I am the sacrifice of muttered prayer; of the immovables, I am the Himalayan range."}]},{"ch":10,"vn":26,"dev":"अश्वत्थः सर्ववृक्षाणां देवर्षीणां च नारदः।\nगन्धर्वाणां चित्ररथः सिद्धानां कपिलो मुनिः","iast":"aśhvatthaḥ sarva-vṛikṣhāṇāṁ devarṣhīṇāṁ cha nāradaḥ\ngandharvāṇāṁ chitrarathaḥ siddhānāṁ kapilo muniḥ","v":[{"k":"purohit","t":"Of trees, I am the sacred fig tree; of divine seers, Narada; of heavenly singers, I am Chitraratha, their leader; and of sages, I am Kapila."},{"k":"sivananda","t":"Among all the trees, I am the Peepul; among the divine sages, I am Narada; among the Gandharvas, I am Chitraratha; among the perfected, I am the sage Kapila."},{"k":"adidevananda","t":"Of trees I am the Asvattha; of celestial seers, I am Narada; of the Gandharvas, I am Citraratha; of the perfected, I am Kapila."},{"k":"gambirananda","t":"Among all trees, I am the Ashvattha tree, and among divine sages, Narada. Among the Gandharvas, I am Citraratha; among the perfected ones, I am the sage Kapila."},{"k":"sankaranarayan","t":"Of all trees, I am the Pipal tree; of the divine seers, Narada; of the Gandharvas, Citraratha; and of the perfected ones, the sage Kapila."}]},{"ch":10,"vn":27,"dev":"उच्चैःश्रवसमश्वानां विद्धि माममृतोद्भवम्।\nऐरावतं गजेन्द्राणां नराणां च नराधिपम्","iast":"uchchaiḥśhravasam aśhvānāṁ viddhi mām amṛitodbhavam\nairāvataṁ gajendrāṇāṁ narāṇāṁ cha narādhipam","v":[{"k":"purohit","t":"Know that among horses I am Pegasus, heaven-born; among the lordly elephants I am the white one, and I am the ruler among men."},{"k":"sivananda","t":"Know Me as Ucchaisravas, born of nectar, among horses; Airavata among lordly elephants; and the king among men."},{"k":"adidevananda","t":"Of horses, know Me to be Uccaihsravas, the nectar-born. Of lordly elephants, I am Airavata, and of men, I am the monarch."},{"k":"gambirananda","t":"Among horses, know Me to be Uccaihsravas, born from nectar; Airavata among the lordly elephants; and among men, the King of men. [Uccaihsravas and Airavata are respectively the divine horse and elephant of Indra.]"},{"k":"sankaranarayan","t":"Of the horses, you should know Me to be the nectar-born Uccaihsravas (Indra's horse); of the best elephants, the Airavata (Indra's elephant); and of the men, their king."}]},{"ch":10,"vn":28,"dev":"आयुधानामहं वज्रं धेनूनामस्मि कामधुक्।\nप्रजनश्चास्मि कन्दर्पः सर्पाणामस्मि वासुकिः","iast":"āyudhānām ahaṁ vajraṁ dhenūnām asmi kāmadhuk\nprajanaśh chāsmi kandarpaḥ sarpāṇām asmi vāsukiḥ","v":[{"k":"purohit","t":"I am the thunderbolt among weapons; I am the Cow of Plenty among cows; I am Passion in those who procreate, and I am the Cobra among serpents."},{"k":"sivananda","t":"Among weapons, I am the thunderbolt; among cows, I am the wish-fulfilling cow called Kamadhenu; I am the progenitor, the god of love; among serpents, I am Vasuki."},{"k":"adidevananda","t":"Of weapons, I am the Vajra (thunderbolt); of cows, I am Kamadhuk; I am Kandarpa, the cause of progeny; of serpents, I am Vasuki."},{"k":"gambirananda","t":"Among weapons I am the thunderbolt; among cows I am Kamadhenu. I am Kandarpa, the Progenitor, and among serpents I am Vasuki."},{"k":"sankaranarayan","t":"Of the weapons, I am the Vajra of Indra; of the cows, I am the Wish-fulfilling Cow of the heavens; of the progenitors, I am Kandarpa (the god of love); of the serpents, I am Vasuki."}]},{"ch":10,"vn":29,"dev":"अनन्तश्चास्मि नागानां वरुणो यादसामहम्।\nपितृ़णामर्यमा चास्मि यमः संयमतामहम्","iast":"anantaśh chāsmi nāgānāṁ varuṇo yādasām aham\npitṝīṇām aryamā chāsmi yamaḥ sanyamatām aham","v":[{"k":"purohit","t":"I am the king-python among snakes, I am the aqueous principle among those that live in water, I am the father of fathers, and among rulers I am death."},{"k":"sivananda","t":"I am Ananta among the Nagas; I am Varuna among water-deities; Aryaman among the Manes; I am Yama among the governors."},{"k":"adidevananda","t":"Of snakes, I am Ananta; of aquatic beings, I am Varuna; of manes, I am Aryama; of subduers, I am Yama."},{"k":"gambirananda","t":"Among snakes, I am Ananta; among gods of the waters, Varuna; among the manes, Aryama; and among the maintainers of law and order, I am Yama (King of death)."},{"k":"sankaranarayan","t":"Of the snakes, I am Ananta; of the water-beings, I am Varuna; of the manes, I am Aryaman; of the controllers, I am Yama (the Death-god)."}]},{"ch":10,"vn":30,"dev":"प्रह्लादश्चास्मि दैत्यानां कालः कलयतामहम्।\nमृगाणां च मृगेन्द्रोऽहं वैनतेयश्च पक्षिणाम्","iast":"prahlādaśh chāsmi daityānāṁ kālaḥ kalayatām aham\nmṛigāṇāṁ cha mṛigendro 'haṁ vainateyaśh cha pakṣhiṇām","v":[{"k":"purohit","t":"And I am the devotee Prahlada among the heathens; of Time I am the Eternal Present; I am the Lion among beasts and the Eagle among birds."},{"k":"sivananda","t":"And I am Prahlada among the demons, I am Time among reckoners, I am the lion among beasts, and Vainateya (Garuda) among birds."},{"k":"adidevananda","t":"Of Daityas, I am Prahlada; of reckoners, I am Death; of beasts, I am the lion; and of birds, I am Garuda, the son of Vinata."},{"k":"gambirananda","t":"Among demons, I am Prahlada, and among reckoners of time, I am Time. Among animals, I am the lion, and among birds, I am Garuda."},{"k":"sankaranarayan","t":"No translation is available for this sloka."}]},{"ch":10,"vn":31,"dev":"पवनः पवतामस्मि रामः शस्त्रभृतामहम्।\nझषाणां मकरश्चास्मि स्रोतसामस्मि जाह्नवी","iast":"pavanaḥ pavatām asmi rāmaḥ śhastra-bhṛitām aham\njhaṣhāṇāṁ makaraśh chāsmi srotasām asmi jāhnavī","v":[{"k":"purohit","t":"I am the wind among purifiers, the king Rama among warriors; I am the crocodile among fishes, and I am the Ganges among rivers."},{"k":"sivananda","t":"Among the purifiers, I am the wind; among the warriors, I am Rama; among the fishes, I am the shark; among the streams, I am the Ganga."},{"k":"adidevananda","t":"Of moving things, I am the wind; of those who bear weapons, I am Rama; of fishers, I am Makara; and of rivers, I am the Ganga."},{"k":"gambirananda","t":"Of the purifiers, I am the air; among the wielders of weapons, I am Rama. Among fishes, I am the shark; among rivers, I am Ganga."},{"k":"sankaranarayan","t":"Of the progeny of Diti, I am Prahlada; of the measuring ones, I am the shark; of rivers, I am the daughter of Jahnu—the Ganga."}]},{"ch":10,"vn":32,"dev":"सर्गाणामादिरन्तश्च मध्यं चैवाहमर्जुन।\nअध्यात्मविद्या विद्यानां वादः प्रवदतामहम्","iast":"sargāṇām ādir antaśh cha madhyaṁ chaivāham arjuna\nadhyātma-vidyā vidyānāṁ vādaḥ pravadatām aham","v":[{"k":"purohit","t":"I am the beginning, the middle, and the end of creation; among sciences, I am the science of spirituality; I am the discussion among disputants."},{"k":"sivananda","t":"Among creations I am the beginning, the middle, and the end, O Arjuna; among the sciences, I am the science of the Self; and I am the logic among controversialists."},{"k":"adidevananda","t":"Of creatures, I am the beginning, the middle, and the end, O Arjuna. Of sciences, I am the science of the Self (of the individual and Universal Self). Of those who argue, I am the fair reasoning."},{"k":"gambirananda","t":"O Arjuna, of creations I am the beginning, the middle, and the end; I am the knowledge of the Self among knowledge; of those who debate, I am vada."},{"k":"sankaranarayan","t":"Of the creations, I am the beginning, the end, and the middle, O Arjuna! Of the sciences, I am the science of the Self; of arguers, I am the argument."}]},{"ch":10,"vn":33,"dev":"अक्षराणामकारोऽस्मि द्वन्द्वः सामासिकस्य च।\nअहमेवाक्षयः कालो धाताऽहं विश्वतोमुखः","iast":"अहमेवाक्षय: कालो धाताहं विश्वतोमुख: || 33||\nakṣharāṇām a-kāro 'smi dvandvaḥ sāmāsikasya cha\naham evākṣhayaḥ kālo dhātāhaṁ viśhvato-mukhaḥ","v":[{"k":"purohit","t":"Of letters, I am A; I am the copulative in compound words; I am inexhaustible Time; and I am the all-pervading Preserver."},{"k":"sivananda","t":"Among the letters of the alphabet, I am the letter 'A' and the dual among compounds. I am verily the inexhaustible and everlasting time; I am the dispenser of the fruits of actions, having faces in all directions."},{"k":"adidevananda","t":"Of letters, I am the alphabet 'A'; of compound words, I am the dvandva (copulative); I am myself imperishable time; I am the creator, facing all sides."},{"k":"gambirananda","t":"Of the letters, I am the letter A, and of the group of compound words, I am the compound called Dvandva. I am Myself the infinite time; I am the Dispenser with faces everywhere."},{"k":"sankaranarayan","t":"Of the syllables, I am A; of the compounds, the Dvandva; none but Me is immortal Time; I am the dispenser of fruits of actions, facing on all sides."}]},{"ch":10,"vn":34,"dev":"मृत्युः सर्वहरश्चाहमुद्भवश्च भविष्यताम्।\nकीर्तिः श्रीर्वाक्च नारीणां स्मृतिर्मेधा धृतिः क्षमा","iast":"mṛityuḥ sarva-haraśh chāham udbhavaśh cha bhaviṣhyatām\nkīrtiḥ śhrīr vāk cha nārīṇāṁ smṛitir medhā dhṛitiḥ kṣhamā","v":[{"k":"purohit","t":"I am all-devouring Death; I am the Origin of all that will happen; I am Fame, Fortune, Speech, Memory, Intellect, Constancy, and Forgiveness."},{"k":"sivananda","t":"And I am the all-devouring Death, and the source of prosperity for those who are to be prosperous; among the feminine qualities, I am fame, prosperity, speech, memory, intelligence, firmness, and forgiveness."},{"k":"adidevananda","t":"I am also death, which snatches away all. I am the origin of all that will be born. Among women, I am fame, prosperity, speech, memory, intelligence, endurance, and forgiveness."},{"k":"gambirananda","t":"And I am Death, the destroyer of all; and the bestower of prosperity to those destined to be prosperous. Of the feminine [Narinam may mean 'of the feminine qualities'. According to Sridhara Swami and S., the words fame etc. signify the goddesses of the respective qualities. According to M.S. these seven goddesses are the wives of the god Dharma.-Tr.] (I am) fame, beauty, speech, memory, intelligence, fortitude, and forbearance."},{"k":"sankaranarayan","t":"I am the Death that carries away all and also the Birth of all that are to be born; of the wives of men, I am Fame, Fortune, Speech, Memory, Wisdom, Constancy, and Patience."}]},{"ch":10,"vn":35,"dev":"बृहत्साम तथा साम्नां गायत्री छन्दसामहम्।\nमासानां मार्गशीर्षोऽहमृतूनां कुसुमाकरः","iast":"bṛihat-sāma tathā sāmnāṁ gāyatrī chhandasām aham\nmāsānāṁ mārga-śhīrṣho 'ham ṛitūnāṁ kusumākaraḥ","v":[{"k":"purohit","t":"Of hymns, I am Brihatsama; of meters, I am Garatri; among months, I am Margasheersha (December); and I am Spring among seasons."},{"k":"sivananda","t":"Among the hymns, I am the Brihatsaman; among meters, I am Gayatri; among months, I am Margasirsha; among seasons, I am the flowery season."},{"k":"adidevananda","t":"Of Saman hymns, I am the Brhatsaman; of meters, I am the Gayatri; of months, I am Margasira (Nov-Dec); and of seasons, I am the season of flowers."},{"k":"gambirananda","t":"I am also the Brhat-sama of the Sama-mantras; of the meters, Gayatri. Of the months, I am Marga-sirsa, and of the seasons, spring."},{"k":"sankaranarayan","t":"Likewise, of the modes of singing, I am the Brhatsaman; of the metres, I am the Gayatri; of the months, I am Margasirsa; of the seasons, I am the season abounding with flowers."}]},{"ch":10,"vn":36,"dev":"द्यूतं छलयतामस्मि तेजस्तेजस्विनामहम्।\nजयोऽस्मि व्यवसायोऽस्मि सत्त्वं सत्त्ववतामहम्","iast":"dyūtaṁ chhalayatām asmi tejas tejasvinām aham\njayo 'smi vyavasāyo 'smi sattvaṁ sattvavatām aham","v":[{"k":"purohit","t":"I am the gambler's cheat and the splendor of the splendid; I am victory; I am effort; and I am the purity of the pure."},{"k":"sivananda","t":"I am the gambling of the deceitful; I am the splendor of the splendid; I am victory; I am the resolve of the resolute; I am the goodness of the good."},{"k":"adidevananda","t":"Of the fraudulent, I am gambling; I am the brilliance of the brilliant; I am victory, I am effort; I am the magnanimity of the magnanimous."},{"k":"gambirananda","t":"Of the fraudulent, I am the gambling; I am the irresistible end of the mighty. I am excellence, I am effort, I am the sattva quality of those possessed of sattva."},{"k":"sankaranarayan","t":"I am the destroyer of the fraudulent; I am the brilliance of the brilliant; I am the victory; I am the determination; I am the strength of the strong."}]},{"ch":10,"vn":37,"dev":"वृष्णीनां वासुदेवोऽस्मि पाण्डवानां धनंजयः।\nमुनीनामप्यहं व्यासः कवीनामुशना कविः","iast":"vṛiṣhṇīnāṁ vāsudevo 'smi pāṇḍavānāṁ dhanañjayaḥ\nmunīnām apyahaṁ vyāsaḥ kavīnām uśhanā kaviḥ","v":[{"k":"purohit","t":"I am Shri Krishna among the Vishnu-clan, Arjuna among the Pandavas, Vyasa among the saints, and Shukracharya among the sages."},{"k":"sivananda","t":"Among the Vrishnis, I am Vaasudeva; among the Pandavas, I am Arjuna; among the sages, I am Vyasa; among the poets, I am Usanas, the poet."},{"k":"adidevananda","t":"Of the Vrsnis, I am Vasudeva; of the Pandavas, I am Arjuna; of sages, I am Vyasa; and of seers, I am Usana (Sukra)."},{"k":"gambirananda","t":"Of the Vrsnis, I am Vasudeva; of the Pandavas, Dhananjaya (Arjuna). Of the wise, I am Vyasa; of the omniscient, the omniscient Usanas."},{"k":"sankaranarayan","t":"Of the Vrsnis, I am the son of Vasudeva; of the sons of Pandu, I am Dhananjaya (Arjuna); of the sages, I am Vyasa; and of the seers, I am Usanas."}]},{"ch":10,"vn":38,"dev":"दण्डो दमयतामस्मि नीतिरस्मि जिगीषताम्।\nमौनं चैवास्मि गुह्यानां ज्ञानं ज्ञानवतामहम्","iast":"daṇḍo damayatām asmi nītir asmi jigīṣhatām\nmaunaṁ chaivāsmi guhyānāṁ jñānaṁ jñānavatām aham","v":[{"k":"purohit","t":"I am the scepter of rulers, the strategy of conquerors, the silence of mystery, and the wisdom of the wise."},{"k":"sivananda","t":"Of those who punish, I am the scepter; among those who seek victory, I am statesmanship; and among secrets, I am silence; I am knowledge among knowers."},{"k":"adidevananda","t":"Of those who punish, I am the principle of punishment. Of those who seek victory, I am policy. Of secrets, I am also silence. And of the wise, I am wisdom."},{"k":"gambirananda","t":"Of the punishers, I am the rod; I am the righteous policy of those who desire to conquer. And of things secret, I am verily silence; I am the knowledge of the wise."},{"k":"sankaranarayan","t":"I am the punishment of the punishers; I am the political wisdom of those seeking victory; I am also the silence of the secret ones; I am the knowledge of the knowers."}]},{"ch":10,"vn":39,"dev":"यच्चापि सर्वभूतानां बीजं तदहमर्जुन।\nन तदस्ति विना यत्स्यान्मया भूतं चराचरम्","iast":"yach chāpi sarva-bhūtānāṁ bījaṁ tad aham arjuna\nna tad asti vinā yat syān mayā bhūtaṁ charācharam","v":[{"k":"purohit","t":"I am the seed of all beings, O Arjuna! No creature, moving or unmoving, can live without Me."},{"k":"sivananda","t":"And whatever is the seed of all beings, that too am I, O Arjuna; there is no being, be it moving or unmoving, that can exist without Me."},{"k":"adidevananda","t":"I am also that which is the seed of all beings, O Arjuna. Nothing that moves or does not move exists without Me."},{"k":"gambirananda","t":"Moreover, O Arjuna, I am the seed of all beings. There is nothing, moving or non-moving, that can exist without Me."},{"k":"sankaranarayan","t":"Further, O Arjuna, I am the seed of all beings; there is no being, whether moving or non-moving, that can exist without Me."}]},{"ch":10,"vn":40,"dev":"नान्तोऽस्ति मम दिव्यानां विभूतीनां परंतप।\nएष तूद्देशतः प्रोक्तो विभूतेर्विस्तरो मया","iast":"nānto 'sti mama divyānāṁ vibhūtīnāṁ parantapa\neṣha tūddeśhataḥ prokto vibhūter vistaro mayā","v":[{"k":"purohit","t":"O Arjuna! The aspects of My divine life are endless; I have mentioned only a few as an example."},{"k":"sivananda","t":"There is no end to My divine glories, O Arjuna, but this is a brief statement by Me of the particulars of My divine glory."},{"k":"adidevananda","t":"There is no limit to My divine manifestations. Here, I have briefly described the extent of such manifestations."},{"k":"gambirananda","t":"O destroyer of enemies, there is no limit to My divine manifestations. This description of My manifestations, however, has been stated by Me as an illustration."},{"k":"sankaranarayan","t":"O scorcher of foes! There is no end to My extraordinary manifesting power. The above details of My manifesting power have been declared by Me only as examples."}]},{"ch":10,"vn":41,"dev":"यद्यद्विभूतिमत्सत्त्वं श्रीमदूर्जितमेव वा।\nतत्तदेवावगच्छ त्वं मम तेजोंऽशसंभवम्","iast":"yad yad vibhūtimat sattvaṁ śhrīmad ūrjitam eva vā\ntat tad evāvagachchha tvaṁ mama tejo 'nśha-sambhavam","v":[{"k":"purohit","t":"Whatever is glorious, excellent, beautiful, and mighty, be assured that it comes from a fragment of My splendor."},{"k":"sivananda","t":"Whatever being there is glorious, prosperous, or powerful, know that to be a manifestation of a part of My splendor."},{"k":"adidevananda","t":"Whatever being is possessed of power, or splendour, or energy, know that as coming from a fragment of My power."},{"k":"gambirananda","t":"Whatever object [all living beings] is verily endowed with majesty, possessed of prosperity, or is energetic, you know for certain each of them as having a part of My power as its source."},{"k":"sankaranarayan","t":"Whatever being exists with manifesting power, beauty, and vigor, be sure that it is born only from a bit of My illumination."}]},{"ch":10,"vn":42,"dev":"अथवा बहुनैतेन किं ज्ञातेन तवार्जुन।\nविष्टभ्याहमिदं कृत्स्नमेकांशेन स्थितो जगत्","iast":"atha vā bahunaitena kiṁ jñātena tavārjuna\nviṣhṭabhyāham idaṁ kṛitsnam ekānśhena sthito jagat","v":[{"k":"purohit","t":"But what is the use of all these details to you, O Arjuna? I sustain this universe with only a small part of Myself."},{"k":"sivananda","t":"But, of what avail is the knowledge of all these details to you, O Arjuna? I exist, supporting this whole world with one part of Myself."},{"k":"adidevananda","t":"But of what use is all this extensive knowledge to you, O Arjuna? I sustain this whole universe with only a fragment of My power."},{"k":"gambirananda","t":"Or, on the other hand, what is the need for you to know this extensively, O Arjuna? I remain sustaining this whole creation in a special way with a part of Myself."},{"k":"sankaranarayan","t":"Or, O Arjuna! Why this detailed explanation? I remain, pervading this entire universe with a single fraction of Myself."}]},{"ch":11,"vn":1,"dev":"अर्जुन उवाच\nमदनुग्रहाय परमं गुह्यमध्यात्मसंज्ञितम्।\nयत्त्वयोक्तं वचस्तेन मोहोऽयं विगतो मम","iast":"arjuna uvācha\nmad-anugrahāya paramaṁ guhyam adhyātma-sanjñitam\nyat tvayoktaṁ vachas tena moho 'yaṁ vigato mama","v":[{"k":"purohit","t":"Arjuna said: My Lord! Your words concerning the Supreme Secret of Self, given for my blessing, have dispelled the illusions that surrounded me."},{"k":"sivananda","t":"Arjuna said, By this explanation of the highest secret concerning the Self which Thou hast spoken, for the sake of blessing me, my delusion has been dispelled."},{"k":"adidevananda","t":"Arjuna said, \"To show favor to me, You have told me that most profound mystery concerning the Self; by that, this delusion of mine has been dispelled.\""},{"k":"gambirananda","t":"Arjuna said, \"This delusion of mine has departed as a result of that speech which is most secret and pertains to the Self, uttered by You for my benefit.\""},{"k":"sankaranarayan","t":"Arjuna said, \"My delusion has completely gone, thanks to the great and mysterious discourse, which is termed as a science governing the soul, and which You have delivered to me as a favor.\""}]},{"ch":11,"vn":2,"dev":"भवाप्ययौ हि भूतानां श्रुतौ विस्तरशो मया।\nत्वत्तः कमलपत्राक्ष माहात्म्यमपि चाव्ययम्","iast":"bhavāpyayau hi bhūtānāṁ śhrutau vistaraśho mayā\ntvattaḥ kamala-patrākṣha māhātmyam api chāvyayam","v":[{"k":"purohit","t":"O Lord, whose eyes are like the lotus petal! You have described in detail the origin and dissolution of beings, and Your own Eternal Majesty."},{"k":"sivananda","t":"The origin and destruction of beings have been heard in detail from You, O lotus-eyed Lord, and also Your inexhaustible greatness."},{"k":"adidevananda","t":"O Krsna, I have heard in detail about the origin and dissolution of all beings, which come from You, as well as Your immutable greatness."},{"k":"gambirananda","t":"O you with eyes like lotus leaves, I have heard in detail from You the origin and dissolution of beings, as well as Your undecaying glory."},{"k":"sankaranarayan","t":"I have listened in detail from You, O Lotus-eyed One, about the origin and dissolution of beings, as well as Your inexhaustible greatness."}]},{"ch":11,"vn":3,"dev":"एवमेतद्यथात्थ त्वमात्मानं परमेश्वर।\nद्रष्टुमिच्छामि ते रूपमैश्वरं पुरुषोत्तम","iast":"evam etad yathāttha tvam ātmānaṁ parameśhvara\ndraṣhṭum ichchhāmi te rūpam aiśhwaraṁ puruṣhottama","v":[{"k":"purohit","t":"I believe all as you have declared it. I now long to have a vision of your divine form, O Most High!"},{"k":"sivananda","t":"Now, O Supreme Lord, as Thou hast thus described Thyself, O Supreme Person, I wish to behold Thy divine form."},{"k":"adidevananda","t":"O Supreme Lord, as You have described Yourself, so You are. I wish to behold Your divine form, O Supreme Person."},{"k":"gambirananda","t":"O Supreme Lord, so it is, as You have spoken of Yourself. O Supreme Person, I wish to behold Your divine form."},{"k":"sankaranarayan","t":"As You describe Yourself to be the Supreme Lord, it must be so. O Supreme Self, I desire to behold Your divine form."}]},{"ch":11,"vn":4,"dev":"मन्यसे यदि तच्छक्यं मया द्रष्टुमिति प्रभो।\nयोगेश्वर ततो मे त्वं दर्शयाऽत्मानमव्ययम्","iast":"manyase yadi tach chhakyaṁ mayā draṣhṭum iti prabho\nyogeśhvara tato me tvaṁ darśhayātmānam avyayam","v":[{"k":"purohit","t":"If you think it is possible for me to see it, show me, O Lord of Lords, your eternal self."},{"k":"sivananda","t":"If Thou, O Lord, thinkest it possible for me to see it, do Thou, then, O Lord of the Yogis, show me Thy imperishable Self."},{"k":"adidevananda","t":"If you think, O Lord, that it can be seen by me, then, O Lord of Yoga, reveal Yourself fully to me."},{"k":"gambirananda","t":"O Lord, if You deem it possible for me to behold You, then, O Lord of Yoga, show me Your eternal Self."},{"k":"sankaranarayan","t":"O Master! If you think it is possible for me to behold that form, then, O Lord of the Yogis, please show me Your Immortal Self."}]},{"ch":11,"vn":5,"dev":"श्री भगवानुवाच\nपश्य मे पार्थ रूपाणि शतशोऽथ सहस्रशः।\nनानाविधानि दिव्यानि नानावर्णाकृतीनि च","iast":"śhrī-bhagavān uvācha\npaśhya me pārtha rūpāṇi śhataśho 'tha sahasraśhaḥ\nnānā-vidhāni divyāni nānā-varṇākṛitīni cha","v":[{"k":"purohit","t":"Lord Shri Krishna replied: \"Behold, O Arjuna! My celestial forms, by the hundreds and thousands, various in kind, color, and shape.\""},{"k":"sivananda","t":"The Blessed Lord said, \"Behold, O Arjuna, forms of Mine, by the hundreds and thousands, of different sorts, divine, and of various colors and shapes.\""},{"k":"adidevananda","t":"The Lord said, \"Behold, O Arjuna, My forms, hundreds upon thousands, manifold, divine, varied in hue and shape.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"O son of Prtha, behold My forms in their hundreds and thousands, of different kinds, celestial, and of various colors and shapes.\""},{"k":"sankaranarayan","t":"The Bhagavat said, \"Behold, O son of Prtha, My divine forms in hundreds and thousands, of varied nature, colors, and shapes.\""}]},{"ch":11,"vn":6,"dev":"पश्यादित्यान्वसून्रुद्रानश्िवनौ मरुतस्तथा।\nबहून्यदृष्टपूर्वाणि पश्याऽश्चर्याणि भारत","iast":"paśhyādityān vasūn rudrān aśhvinau marutas tathā\nbahūny adṛiṣhṭa-pūrvāṇi paśhyāśhcharyāṇi bhārata","v":[{"k":"purohit","t":"Behold, thou seest the powers of Nature: fire, earth, wind, and sky; the sun, the heavens, the moon, the stars; all forces of vitality and healing; and the roving winds. Behold, thou seest the myriad wonders revealed to none but thee."},{"k":"sivananda","t":"Behold the Adityas, the Vasus, the Rudras, the two Asvins, and the Maruts; behold many wonders never before seen, O Arjuna."},{"k":"adidevananda","t":"Behold, O Arjuna, the Adityas, the Vasus, the Rudras, the two Asvins, and the Maruts—many marvels never seen before."},{"k":"gambirananda","t":"Behold the Adityas, the Vasus, the Rudras, the two Ashvins, and the Maruts. O scion of the Bharata dynasty, also behold the many wonders that have never been seen before."},{"k":"sankaranarayan","t":"Behold the Adityas, the Vasus, the Rudras, the twin Ashvins, and the Maruts; O son of Pandu, behold also many wonders that had never been seen before."}]},{"ch":11,"vn":7,"dev":"इहैकस्थं जगत्कृत्स्नं पश्याद्य सचराचरम्।\nमम देहे गुडाकेश यच्चान्यद्द्रष्टुमिच्छसि","iast":"ihaika-sthaṁ jagat kṛitsnaṁ paśhyādya sa-charācharam\nmama dehe guḍākeśha yach chānyad draṣhṭum ichchhasi","v":[{"k":"purohit","t":"Here, living in Me, O Arjuna, behold the entire universe, both movable and immovable, and anything else you would like to see!"},{"k":"sivananda","t":"Now, behold, O Arjuna, in this My body, the entire universe centered in one, including the moving and the unmoving, and whatever else you desire to see."},{"k":"adidevananda","t":"Behold here, O Arjuna, the entire universe with its mobile and immobile things, all centered in My body, and whatever else you desire to see."},{"k":"gambirananda","t":"See now, O Gudakesa, the entire Universe together with the moving and the non-moving, concentrated in the same place here in My body, as also whatever else you would like to see."},{"k":"sankaranarayan","t":"Now, behold the entire universe, including the moving and the unmoving, and whatsoever else you desire to see—all established in Me, O Gudakesa (Arjuna)!"}]},{"ch":11,"vn":8,"dev":"न तु मां शक्यसे द्रष्टुमनेनैव स्वचक्षुषा।\nदिव्यं ददामि ते चक्षुः पश्य मे योगमैश्वरम्","iast":"na tu māṁ śhakyase draṣhṭum anenaiva sva-chakṣhuṣhā\ndivyaṁ dadāmi te chakṣhuḥ paśhya me yogam aiśhwaram","v":[{"k":"purohit","t":"Yet, since you cannot see Me with mortal eyes, behold, I give you divine sight. Now, see the glory of My sovereignty."},{"k":"sivananda","t":"But you are not able to behold Me with these your own eyes; I give you the divine eye; behold My lordly Yoga."},{"k":"adidevananda","t":"But you will not be able to see Me with your own eyes. I give you a divine eye, so behold My Lordly Yoga!"},{"k":"gambirananda","t":"But you are not able to see Me with just this eye of yours. I grant you the divine eye; behold My divine Yoga."},{"k":"sankaranarayan","t":"But you cannot see Me with just this eye of yours; therefore, I give you the divine eye. Now, behold My divine form."}]},{"ch":11,"vn":9,"dev":"सञ्जय उवाच\nएवमुक्त्वा ततो राजन्महायोगेश्वरो हरिः।\nदर्शयामास पार्थाय परमं रूपमैश्वरम्","iast":"sañjaya uvācha\nevam uktvā tato rājan mahā-yogeśhvaro hariḥ\ndarśhayām āsa pārthāya paramaṁ rūpam aiśhwaram","v":[{"k":"purohit","t":"Sanjaya continued: \"Having thus spoken, O King, the Lord Shri Krishna, the Almighty Prince of Wisdom, showed Arjuna the Supreme Form of the Great God."},{"k":"sivananda","t":"Sanjaya said, Having thus spoken, O king, the great Lord of Yoga, Hari (Krishna), showed Arjuna His supreme form as the Lord."},{"k":"adidevananda","t":"Sanjaya said, \"O King, having spoken, Sri Krishna, the great Lord of Yoga, then revealed to Arjuna the supreme, lordly form.\""},{"k":"gambirananda","t":"Sanjaya said, \"O King, having spoken thus, thereafter, Hari, the great Master of Yoga, showed to the son of Prtha the supreme divine form.\""},{"k":"sankaranarayan","t":"Sanjaya said, \"O king! Having thus stated, Hari, the mighty Lord of the Yogins, showed to the son of Prtha His own Supreme Lordly form.\""}]},{"ch":11,"vn":10,"dev":"अनेकवक्त्रनयनमनेकाद्भुतदर्शनम्।\nअनेकदिव्याभरणं दिव्यानेकोद्यतायुधम्","iast":"aneka-vaktra-nayanam anekādbhuta-darśhanam\naneka-divyābharaṇaṁ divyānekodyatāyudham","v":[{"k":"purohit","t":"There were countless eyes, mouths, and innumerable mystic forms, with shining ornaments and flaming celestial weapons."},{"k":"sivananda","t":"With numerous mouths and eyes, with numerous wondrous sights, with numerous divine adornments, with numerous divine weapons uplifted, such a form He showed."},{"k":"adidevananda","t":"With innumerable mouths and eyes, many marvelous aspects, numerous divine ornaments, and numerous divine weapons."},{"k":"gambirananda","t":"Having many faces and eyes, possessing many wondrous sights, adorned with numerous celestial ornaments, and holding many uplifted heavenly weapons;"},{"k":"sankaranarayan","t":"It has many mouths and eyes, wondrous sights, heavenly ornaments, and weapons held ready;"}]},{"ch":11,"vn":11,"dev":"दिव्यमाल्याम्बरधरं दिव्यगन्धानुलेपनम्।\nसर्वाश्चर्यमयं देवमनन्तं विश्वतोमुखम्","iast":"divya-mālyāmbara-dharaṁ divya-gandhānulepanam\nsarvāśhcharya-mayaṁ devam anantaṁ viśhvato-mukham","v":[{"k":"purohit","t":"Crowned with heavenly garlands, clothed in shining garments, anointed with divine unguents, He showed Himself as the Resplendent One, Marvelous, Boundless, and Omnipresent."},{"k":"sivananda","t":"Wearing divine garlands and apparel, anointed with divine unguents, the all-wonderful, resplendent Being is endless with faces on all sides."},{"k":"adidevananda","t":"Wearing celestial garlands and raiments, anointed with divine perfumes, full of wonders, resplendent, boundless, and facing all directions."},{"k":"gambirananda","t":"Wearing heavenly garlands and apparel, anointed with heavenly scents, abounding in all kinds of wonders, resplendent, infinite, and with faces on all sides."},{"k":"sankaranarayan","t":"It wears heavenly garlands and garments, is anointed with heavenly sandal paste, is wondrous, radiant, and infinite, and has faces in all directions."}]},{"ch":11,"vn":12,"dev":"दिवि सूर्यसहस्रस्य भवेद्युगपदुत्थिता।\nयदि भाः सदृशी सा स्याद्भासस्तस्य महात्मनः","iast":"divi sūrya-sahasrasya bhaved yugapad utthitā\nyadi bhāḥ sadṛiśhī sā syād bhāsas tasya mahātmanaḥ","v":[{"k":"purohit","t":"Could a thousand suns blaze forth together, it would be but a faint reflection of the radiance of the Lord God."},{"k":"sivananda","t":"If the splendour of a thousand suns were to blaze out simultaneously in the sky, that would be the splendour of that mighty being."},{"k":"adidevananda","t":"If a thousand suns were to rise at once in the sky, the resulting splendour would be like the splendour of that mighty One."},{"k":"gambirananda","t":"Should the effulgence of a thousand suns blaze forth simultaneously in the sky, that might be akin to the radiance of that exalted One."},{"k":"sankaranarayan","t":"If the splendour of a thousand suns were to burst forth at once in the sky, would that be equal to the splendour of that Mighty Self?"}]},{"ch":11,"vn":13,"dev":"तत्रैकस्थं जगत्कृत्स्नं प्रविभक्तमनेकधा।\nअपश्यद्देवदेवस्य शरीरे पाण्डवस्तदा","iast":"tatraika-sthaṁ jagat kṛitsnaṁ pravibhaktam anekadhā\napaśhyad deva-devasya śharīre pāṇḍavas tadā","v":[{"k":"purohit","t":"In that vision, Arjuna saw the universe, with its manifold shapes, all embraced in one, its Supreme Lord."},{"k":"sivananda","t":"There, in the body of the God of gods, Arjuna then saw the entire universe resting in one, with its myriad of divisions."},{"k":"adidevananda","t":"There, Arjuna beheld the whole universe, with its manifold divisions gathered together in one single spot within the body of the God of gods."},{"k":"gambirananda","t":"At that time, the Pandava saw, in the body of the God of gods, the whole diversely differentiated universe united in one."},{"k":"sankaranarayan","t":"At that time, the son of Pandu beheld, in the body of the God-of-Gods, the entire universe, united yet divided into many groups."}]},{"ch":11,"vn":14,"dev":"ततः स विस्मयाविष्टो हृष्टरोमा धनञ्जयः।\nप्रणम्य शिरसा देवं कृताञ्जलिरभाषत","iast":"tataḥ sa vismayāviṣhṭo hṛiṣhṭa-romā dhanañjayaḥ\npraṇamya śhirasā devaṁ kṛitāñjalir abhāṣhata","v":[{"k":"purohit","t":"Then, Arjuna, filled with awe, his hair standing on end, bowing his head, and clasping his hands in reverence, spoke to the Lord:"},{"k":"sivananda","t":"Then, Arjuna, filled with wonder and his hair standing on end, bowed his head to the God and spoke with palms joined."},{"k":"adidevananda","t":"Then, Arjuna, overcome with amazement, his hairs standing on end, bowed his head to the Lord and spoke with folded hands."},{"k":"gambirananda","t":"Then, filled with wonder and with hairs standing on end, Arjuna, bowing down with his head to the Lord, said with folded hands:"},{"k":"sankaranarayan","t":"Then, possessed by amazement and with his body hair standing on end, Dhananjaya, with his head bowed to the God and with folded hands, spoke to Him."}]},{"ch":11,"vn":15,"dev":"अर्जुन उवाच\nपश्यामि देवांस्तव देव देहे\nसर्वांस्तथा भूतविशेषसङ्घान्।\nब्रह्माणमीशं कमलासनस्थ\nमृषींश्च सर्वानुरगांश्च दिव्यान्","iast":"arjuna uvācha\npaśhyāmi devāns tava deva dehe\nsarvāns tathā bhūta-viśheṣha-saṅghān\nbrahmāṇam īśhaṁ kamalāsana-stham\nṛiṣhīnśh cha sarvān uragānśh cha divyān","v":[{"k":"purohit","t":"Arjuna said: O Almighty God! I see in You the powers of Nature, the various creatures of the world, the Progenitor on His lotus throne, the Sages, and the shining angels."},{"k":"sivananda","t":"Arjuna said, \"O God, I see all the gods in Your body, as well as hosts of various classes of beings, Brahma the Lord seated on the lotus, all the sages, and the celestial serpents.\""},{"k":"adidevananda","t":"Arjuna said, \"O Lord, I behold in Your body all the gods, and all the diverse hosts of beings—Brahma, Siva, who is in Brahma, the seers, and the lustrous snakes.\""},{"k":"gambirananda","t":"Arjuna said, \"O God, I see in Your body all the gods, as well as hosts of various classes of beings; Brahma the ruler, sitting on a lotus seat, and all the heavenly sages and serpents."},{"k":"sankaranarayan","t":"Arjuna said, \"O God! In Your body, I behold all gods and hosts of different kinds of beings—the Lord Brahma seated on the lotus-seat, and all the sages and glowing serpents.\""}]},{"ch":11,"vn":16,"dev":"अनेकबाहूदरवक्त्रनेत्रं\nपश्यामि त्वां सर्वतोऽनन्तरूपम्।\nनान्तं न मध्यं न पुनस्तवादिं\nपश्यामि विश्वेश्वर विश्वरूप","iast":"aneka-bāhūdara-vaktra-netraṁ\npaśhyāmi tvāṁ sarvato 'nanta-rūpam\nnāntaṁ na madhyaṁ na punas tavādiṁ\npaśhyāmi viśhveśhvara viśhva-rūpa","v":[{"k":"purohit","t":"I see You, infinite in form, with faces, eyes, and limbs everywhere; with no beginning, middle, or end. O You, Lord of the Universe, whose form is universal!"},{"k":"sivananda","t":"I see You with boundless form on every side, with many arms, stomachs, mouths, and eyes; neither the end nor the middle nor the beginning do I see, O Lord of the Universe, O Cosmic Form."},{"k":"adidevananda","t":"With manifold arms, stomachs, mouths, and eyes, I behold Your infinite form on all sides. I see no end, no middle, nor the beginning of You, O Lord of the universe, O You of Universal Form."},{"k":"gambirananda","t":"I see You with numerous arms, bellies, mouths, and eyes; with infinite forms all around. O Lord of the Universe, O Cosmic Person, I see no limit, no middle, nor beginning!"},{"k":"sankaranarayan","t":"I behold You with many arms, bellies, mouths, and eyes, and with infinite forms on all sides; I find neither the end nor the center nor the beginning of You, O Lord of the Universe, O Universal-Formed One!"}]},{"ch":11,"vn":17,"dev":"किरीटिनं गदिनं चक्रिणं च\nतेजोराशिं सर्वतोदीप्तिमन्तम्।\nपश्यामि त्वां दुर्निरीक्ष्यं समन्ता\nद्दीप्तानलार्कद्युतिमप्रमेयम्","iast":"kirīṭinaṁ gadinaṁ chakriṇaṁ cha\ntejo-rāśhiṁ sarvato dīptimantam\npaśhyāmi tvāṁ durnirīkṣhyaṁ samantād\ndīptānalārka-dyutim aprameyam","v":[{"k":"purohit","t":"I see you with the crown, the scepter, and the discus; a blaze of splendor. Scarcely can I gaze upon you, so radiant you are, glowing like a blazing fire, brilliant as the sun, immeasurable."},{"k":"sivananda","t":"I see You with the diadem, club, and discus, a mass of radiance shining everywhere, very hard to look at, blazing all around like a burning fire and the sun, and immeasurable."},{"k":"adidevananda","t":"I behold You as a mass of light, shining everywhere, with a diadem, mace, and discus, hard to behold, blazing like a burning fire and the sun, and immeasurable."},{"k":"gambirananda","t":"I see You wearing a diadem, wielding a mace, and holding a disc; a mass of brilliance glowing all around, difficult to look at from all sides, possessing the radiance of the blazing fire and sun, and immeasurable."},{"k":"sankaranarayan","t":"I behold You as having crowns, clubs, and discs; as a mass of radiance, shining on all sides, hard to look at and blazing like burning fire and the sun on each side; and as an immeasurable one."}]},{"ch":11,"vn":18,"dev":"त्वमक्षरं परमं वेदितव्यं\nत्वमस्य विश्वस्य परं निधानम्।\nत्वमव्ययः शाश्वतधर्मगोप्ता\nसनातनस्त्वं पुरुषो मतो मे","iast":"tvam akṣharaṁ paramaṁ veditavyaṁ\ntvam asya viśhvasya paraṁ nidhānam\ntvam avyayaḥ śhāśhvata-dharma-goptā\nsanātanas tvaṁ puruṣho mato me","v":[{"k":"purohit","t":"You are imperishable, the only one worthy of being known, the priceless treasure-house of the universe, the immortal guardian of eternal life, and the everlasting spirit."},{"k":"sivananda","t":"You are the Imperishable, the Supreme Being, worthy of being known. You are the great treasure-house of this universe; You are the imperishable protector of the eternal Dharma; You are the Primal Person, I believe."},{"k":"adidevananda","t":"You are the Imperishable, Supreme One to be realized. You are the Supreme Substratum of this universe. You are immutable, the guardian of the eternal law; I know You are the Supreme Person who is everlasting."},{"k":"gambirananda","t":"You are the Unchanging, the supreme One to be known; You are the most perfect repository of this Universe. You are the Imperishable, the Protector of the ever-existing religion; You are the eternal Person. This is my belief."},{"k":"sankaranarayan","t":"You are the imperishable, the Supreme Being to be known; You are the ultimate place of rest for this universe; You are changeless and the guardian of the pious acts of the Satvatas; You are the everlasting Soul, I believe."}]},{"ch":11,"vn":19,"dev":"अनादिमध्यान्तमनन्तवीर्य\nमनन्तबाहुं शशिसूर्यनेत्रम्।\nपश्यामि त्वां दीप्तहुताशवक्त्रम्\nस्वतेजसा विश्वमिदं तपन्तम्","iast":"स्वतेजसा विश्वमिदं तपन्तम् || 19||","v":[{"k":"purohit","t":"Without beginning, without middle, and without end, infinite in power, with arms all-embracing, the sun and moon as Your eyes, Your face beaming with the fire of sacrifice, flooding the whole universe with light."},{"k":"sivananda","t":"I see You without beginning, middle, or end, infinite in power, with endless arms, the sun and moon as Your eyes, the burning fire Your mouth, heating the entire universe with Your radiance."},{"k":"adidevananda","t":"I behold You as having no beginning, middle, or end; Your might is infinite. You are endowed with an innumerable number of arms. The sun and moon are Your eyes, and Your mouth emits burning fire. With Your own radiance, You are warning the entire universe."},{"k":"gambirananda","t":"I see You as having no beginning, middle, or end, possessing infinite valor, with innumerable arms, the sun and moon as eyes, a mouth like a blazing fire, and heating up this universe with Your own brilliance."},{"k":"sankaranarayan","t":"I observe You with no beginning, no middle, and no end; having infinite creative power and infinite arms; with the moon and the sun as Your eyes and the blazing fire as Your mouth; and scorching this universe with Your radiance."}]},{"ch":11,"vn":20,"dev":"द्यावापृथिव्योरिदमन्तरं हि\nव्याप्तं त्वयैकेन दिशश्च सर्वाः।\nदृष्ट्वाऽद्भुतं रूपमुग्रं तवेदं\nलोकत्रयं प्रव्यथितं महात्मन्","iast":"dyāv ā-pṛithivyor idam antaraṁ hi\nvyāptaṁ tvayaikena diśhaśh cha sarvāḥ\ndṛiṣhṭvādbhutaṁ rūpam ugraṁ tavedaṁ\nloka-trayaṁ pravyathitaṁ mahātman","v":[{"k":"purohit","t":"Alone, you fill all the quarters of the sky, earth, and heaven, and the regions between. O Almighty Lord! Seeing your marvelous and awe-inspiring form, the spheres tremble with fear."},{"k":"sivananda","t":"This space between the earth and the heavens, and all the quarters, is filled by You alone; having seen this, Your wonderful and terrible form, the three worlds are trembling with fear, O great-souled Being."},{"k":"adidevananda","t":"You alone have pervaded the interspace between heaven and earth, and all the quarters. Beholding your marvelous and terrible form, O Mahatman, the three worlds are greatly overwhelmed with fear."},{"k":"gambirananda","t":"Indeed, this intermediate space between heaven and earth, as well as all the directions, are pervaded by You alone. O exalted One, the three worlds are struck with fear upon seeing this strange and fearful form of Yours."},{"k":"sankaranarayan","t":"This space between heaven and earth, as well as all the directions, is pervaded singly by You; seeing this wondrous form of Yours, O Exalted Soul, the triple world is greatly frightened."}]},{"ch":11,"vn":21,"dev":"अमी हि त्वां सुरसङ्घाः विशन्ति\nकेचिद्भीताः प्राञ्जलयो गृणन्ति।\nस्वस्तीत्युक्त्वा महर्षिसिद्धसङ्घाः\nस्तुवन्ति त्वां स्तुतिभिः पुष्कलाभिः","iast":"amī hi tvāṁ sura-saṅghā viśhanti\nkechid bhītāḥ prāñjalayo gṛiṇanti\nsvastīty uktvā maharṣhi-siddha-saṅghāḥ\nstuvanti tvāṁ stutibhiḥ puṣhkalābhiḥ","v":[{"k":"purohit","t":"The troops of celestial beings enter into You, some invoking You in fear, with folded palms; the great seers and adepts sing hymns to Your glory, saying, \"All hail!\""},{"k":"sivananda","t":"Verily, these hosts of gods enter into Thee; some extol Thee with joined palms in fear, saying, 'May it be well!' Bands of great sages and perfected ones praise Thee with complete hymns."},{"k":"adidevananda","t":"Verily, the hosts of Devas enter into You. Some, in fear, extol You with clasped hands, crying \"Hail!\" The bands of great seers and Siddhas praise You with meaningful hymns."},{"k":"gambirananda","t":"Those very groups of gods enter into You; struck with fear, some extol You with joined palms. Groups of great sages and perfected beings praise You with elaborate hymns, saying, 'May it be well!'"},{"k":"sankaranarayan","t":"These hosts of gods enter into You; some, frightened, recite [hymns] with folded palms; simply crying 'Hail!', the hosts of great seers praise You with excellent praising hymns."}]},{"ch":11,"vn":22,"dev":"रुद्रादित्या वसवो ये च साध्या\nविश्वेऽश्िवनौ मरुतश्चोष्मपाश्च।\nगन्धर्वयक्षासुरसिद्धसङ्घा\nवीक्षन्ते त्वां विस्मिताश्चैव सर्वे","iast":"rudrādityā vasavo ye cha sādhyā\nviśhve 'śhvinau marutaśh choṣhmapāśh cha\ngandharva-yakṣhāsura-siddha-saṅghā\nvīkṣhante tvāṁ vismitāśh chaiva sarve","v":[{"k":"purohit","t":"The vital forces, major stars, fire, earth, air, sky, sun, heaven, moon, and planets; the angels, guardians of the universe, divine healers, winds, fathers, heavenly singers, and hosts of mammon-worshippers, demons, and saints are all amazed."},{"k":"sivananda","t":"The Rudras, Adityas, Vasus, Sadhyas, Visvedevas, the two Asvins, Maruts, the Manus, and the hosts of celestial singers, Yakshas, demons, and the perfected ones, all look upon Thee with great amazement."},{"k":"adidevananda","t":"The Rudras, the Adityas, the Vasus, the Sadhyas, the Visvas, the Asvins, the Maruts, and the Manes, as well as the hosts of Gandharvas, Yaksas, Asuras, and Siddhas—all gaze upon You in amazement."},{"k":"gambirananda","t":"Those who are the Rudras, the Adityas, the Vasus, and the Sadhyas, the Visvedevas, the two Asvins, the Maruts, and the Usmapas, and hosts of Gandharvas, Yaksas, demons, and Siddhas—all of those very ones gaze at You, being indeed struck with wonder."},{"k":"sankaranarayan","t":"The Rudras, the Adityas, the Vasus, the Sadhyas, the Visvadevas, the twin Asvins, and the Maruts, the Manes, the hosts of the Gandharvas, the Yaksas, the demons, and the perfected ones—all gaze upon You in amazement."}]},{"ch":11,"vn":23,"dev":"रूपं महत्ते बहुवक्त्रनेत्रं\nमहाबाहो बहुबाहूरुपादम्।\nबहूदरं बहुदंष्ट्राकरालं\nदृष्ट्वा लोकाः प्रव्यथितास्तथाऽहम्","iast":"rūpaṁ mahat te bahu-vaktra-netraṁ\nmahā-bāho bahu-bāhūru-pādam\nbahūdaraṁ bahu-danṣhṭrā-karālaṁ\ndṛiṣhṭvā lokāḥ pravyathitās tathāham","v":[{"k":"purohit","t":"Seeing Thy stupendous Form, O Most Mighty One, with its myriad faces, its innumerable eyes, limbs, and terrible jaws, I myself and all the worlds are overwhelmed with awe."},{"k":"sivananda","t":"Having seen Your immeasurable form with many mouths and eyes, O mighty-armed one, with many arms, thighs, and feet, with many stomachs and fearsome with many teeth, the worlds are terrified, and so am I."},{"k":"adidevananda","t":"Beholding Your great form with many mouths and eyes, many arms, thighs, and feet, many stomachs, and terrible with many teeth, the worlds tremble, and I too quake, O mighty-armed one."},{"k":"gambirananda","t":"O Mighty-Armed One, seeing Your immense form with many mouths, eyes, arms, thighs, feet, bellies, and teeth, the creatures are struck with terror, and so am I."},{"k":"sankaranarayan","t":"O Mighty-armed One! Having seen Your mighty form, with its many faces and eyes, many arms, thighs, feet, and bellies, and its terrible array of tusks, the worlds are frightened, as am I."}]},{"ch":11,"vn":24,"dev":"नभःस्पृशं दीप्तमनेकवर्णं\nव्यात्ताननं दीप्तविशालनेत्रम्।\nदृष्ट्वा हि त्वां प्रव्यथितान्तरात्मा\nधृतिं न विन्दामि शमं च विष्णो","iast":"nabhaḥ-spṛiśhaṁ dīptam aneka-varṇaṁ\nvyāttānanaṁ dīpta-viśhāla-netram\ndṛiṣhṭvā hi tvāṁ pravyathitāntar-ātmā\ndhṛitiṁ na vindāmi śhamaṁ cha viṣhṇo","v":[{"k":"purohit","t":"When I see You, touching the heavens, glowing with color, with open mouth and wide, fiery eyes, I am terrified. O my Lord! My courage and peace of mind abandon me."},{"k":"sivananda","t":"On seeing Thee, touching the sky, shining in many colors, with mouths wide open, with large fiery eyes, I am terrified at heart and find neither courage nor peace, O Vishnu."},{"k":"adidevananda","t":"When I behold You touching the Supreme Heaven, shining, multicolored, with yawning mouths and large, resplendent eyes, my inner being trembles in fear. I am unable to find support or peace, O Vishnu."},{"k":"gambirananda","t":"O Vishnu, indeed, upon seeing Your form touching the heavens, blazing with many colors, open-mouthed, with fiery, large eyes, I become terrified in my mind and do not find steadiness and peace."},{"k":"sankaranarayan","t":"As I observe You, touching the sky, blazing, with many colors, mouths wide open, eyes blazing and large, I am terrified in my inner soul and I do not find courage and peace, O Visnu!"}]},{"ch":11,"vn":25,"dev":"दंष्ट्राकरालानि च ते मुखानि\nदृष्ट्वैव कालानलसन्निभानि।\nदिशो न जाने न लभे च शर्म\nप्रसीद देवेश जगन्निवास","iast":"danṣhṭrā-karālāni cha te mukhāni\ndṛiṣhṭvaiva kālānala-sannibhāni\ndiśho na jāne na labhe cha śharma\nprasīda deveśha jagan-nivāsa","v":[{"k":"purohit","t":"When I see Thy mouths with their fearful jaws, like glowing fires at the dissolution of creation, I lose all sense of place and find no rest. Be merciful, O Lord, in whom this universe abides!"},{"k":"sivananda","t":"Having seen Thy mouths fearful with teeth blazing like the fires of cosmic dissolution, I know not the four quarters, nor do I find peace. Have mercy, O Lord of the gods, O abode of the universe."},{"k":"adidevananda","t":"Viewing Your mouths, presenting awe-generating fangs and looking like the consuming fire of final destruction, I know not the quarters of the globe nor do I find repose. Be gracious, O Lord of the Devas! O Abode of the universe!"},{"k":"gambirananda","t":"Having merely seen Your mouths made terrible with their teeth and resembling the fire of Dissolution, I have lost my sense of direction and find no comfort. Be gracious, O Lord of gods, O Abode of the Universe."},{"k":"sankaranarayan","t":"By merely seeing Your faces, which are frightening with tusks and look like the fire of destruction, I do not know the arters and get no peace. Have mercy, O Lord of gods! O Abode of the Universe!"}]},{"ch":11,"vn":26,"dev":"अमी च त्वां धृतराष्ट्रस्य पुत्राः\nसर्वे सहैवावनिपालसङ्घैः।\nभीष्मो द्रोणः सूतपुत्रस्तथाऽसौ\nसहास्मदीयैरपि योधमुख्यैः","iast":"amī cha tvāṁ dhṛitarāśhtrasya putrāḥ\nsarve sahaivāvani-pāla-saṅghaiḥ\nbhīṣhmo droṇaḥ sūta-putras tathāsau\nsahāsmadīyair api yodha-mukhyaiḥ\nvaktrāṇi te tvaramāṇā viśhanti\ndanṣhṭrā-karālāni bhayānakāni\nkechid vilagnā daśhanāntareṣhu\nsandṛiśhyante chūrṇitair uttamāṅgaiḥ","v":[{"k":"purohit","t":"All these sons of Dhritarashtra, along with the hosts of princes, Bheeshma, Drona, and Karna, as well as the other warrior chiefs on our side;"},{"k":"sivananda","t":"All the sons of Dhritarashtra, along with the hosts of kings of the earth, Bhishma, Drona, and Karna, as well as the chief among our warriors."},{"k":"adidevananda","t":"All these sons of Dhrtarastra, together with the hosts of monarchs, Bhisma, Drona, and Karna, along with the leading warriors of our side,"},{"k":"gambirananda","t":"And into You enter all those sons of Dhrtarastra, along with multitudes of the rulers of the earth, Bhisma, Drona, and that son of a Suta, Karna, together with our prominent warriors."},{"k":"sankaranarayan","t":"All these sons of Dhrtarastra, along with the entire host of kings, Bhisma, Drona, and the son of the charioteer (Karna), together with the chief warriors of ours as well;"}]},{"ch":11,"vn":27,"dev":"वक्त्राणि ते त्वरमाणा विशन्ति\nदंष्ट्राकरालानि भयानकानि।\nकेचिद्विलग्ना दशनान्तरेषु\nसंदृश्यन्ते चूर्णितैरुत्तमाङ्गैः","iast":"vaktrāṇi te  tvaramāṇā   viśanti daṁṣṭrā-karālāni    bhayānakāni kecid   vilagnā daśanāntareṣu   sandṛśyante cūrṇitair   uttamāṅgaiḥ","v":[{"k":"purohit","t":"1\tSee them all rushing headlong into Thy mouths, with terrible tusks, horrible to behold. Some are mangled between Thy jaws, with their heads crushed to atoms."},{"k":"sivananda","t":"Some hurry into Your mouths with their terrible teeth, fearful to behold. Some are found stuck in the gaps between the teeth, their heads crushed to powder."},{"k":"adidevananda","t":"Hasten to enter Your fearful mouths with terrible fangs, crushing some of those caught between the teeth to powder."},{"k":"gambirananda","t":"They rapidly enter into Your terrible mouths with cruel teeth! Some are seen sticking in the gaps between the teeth, with their heads crushed!"},{"k":"sankaranarayan","t":"They hurry into Your fearsome mouths, with tusks that terrify; some of them, stuck between Your teeth, are clearly visible with their heads crushed."}]},{"ch":11,"vn":28,"dev":"यथा नदीनां बहवोऽम्बुवेगाः\nसमुद्रमेवाभिमुखाः द्रवन्ति।\nतथा तवामी नरलोकवीरा\nविशन्ति वक्त्राण्यभिविज्वलन्ति","iast":"yathā nadīnāṁ bahavo 'mbu-vegāḥ\nsamudram evābhimukhā dravanti\ntathā tavāmī nara-loka-vīrā\nviśhanti vaktrāṇy abhivijvalanti","v":[{"k":"purohit","t":"As rivers in flood surge furiously towards the ocean, so these heroes, the greatest among men, fling themselves into Thy flaming mouths."},{"k":"sivananda","t":"Verily, just as many torrents of rivers flow towards the ocean, so too these heroes in the world of men enter Thy flaming mouths."},{"k":"adidevananda","t":"As many torrents of rivers flow towards the ocean, so do these heroes of the world of men enter into Your flaming mouths."},{"k":"gambirananda","t":"As the numerous currents of the waters of rivers rush towards the sea alone, so too do those heroes of the human world enter into Your blazing mouths."},{"k":"sankaranarayan","t":"Just as many water-rapids of the rivers race heading towards the ocean, in the same manner these heroes of the world of men enter into Your mouths, flaming all around."}]},{"ch":11,"vn":29,"dev":"यथा प्रदीप्तं ज्वलनं पतङ्गा\nविशन्ति नाशाय समृद्धवेगाः।\nतथैव नाशाय विशन्ति लोका\nस्तवापि वक्त्राणि समृद्धवेगाः","iast":"yathā pradīptaṁ jvalanaṁ pataṅgā\nviśhanti nāśhāya samṛiddha-vegāḥ\ntathaiva nāśhāya viśhanti lokās\ntavāpi vaktrāṇi samṛiddha-vegāḥ","v":[{"k":"purohit","t":"As moths impetuously fly towards the flame, only to be killed, so these men rush into Your mouths to court their own destruction."},{"k":"sivananda","t":"As moths hurriedly rush into a blazing fire, leading to their own destruction, so too these creatures hurry into Your mouths, leading to their own destruction."},{"k":"adidevananda","t":"As moths rush swiftly into a blazing fire, leading to their destruction, so do these men swiftly rush into Your mouths, leading to their destruction."},{"k":"gambirananda","t":"As moths hasten with increased speed into a blazing fire for destruction, so too do creatures hasten into Your mouths with increased speed for destruction."},{"k":"sankaranarayan","t":"Just as moths, with full speed, enter into the flaming fire for their own destruction, in the same manner the worlds also enter, with full speed, into the mouths of Yours for their own destruction."}]},{"ch":11,"vn":30,"dev":"लेलिह्यसे ग्रसमानः समन्ता\nल्लोकान्समग्रान्वदनैर्ज्वलद्भिः।\nतेजोभिरापूर्य जगत्समग्रं\nभासस्तवोग्राः प्रतपन्ति विष्णो","iast":"lelihyase grasamānaḥ samantāl\nlokān samagrān vadanair jvaladbhiḥ\ntejobhir āpūrya jagat samagraṁ\nbhāsas tavogrāḥ pratapanti viṣhṇo","v":[{"k":"purohit","t":"You seem to swallow up the worlds, lapping them in flame. Your glory fills the universe. Your fierce rays beat down upon it irresistibly."},{"k":"sivananda","t":"Thou lickest up, devouring all the worlds on every side with Thy flaming mouths. Thy fierce rays, filling the whole world with radiance, burn, O Vishnu!"},{"k":"adidevananda","t":"Devouring all the worlds on every side with your flaming mouths, you lick them up. Your fiery rays, filling the whole universe with their radiance, scorch it, O Vishnu."},{"k":"gambirananda","t":"You lick Your lips as You devour all creatures from every side with flaming mouths that fill the entire world with heat."},{"k":"sankaranarayan","t":"Devouring, on all sides with Your blazing mouths, the entire worlds, You are licking up; Your terrible rays scorch the entire universe, filling it with their radiance, O Vishnu!"}]},{"ch":11,"vn":31,"dev":"आख्याहि मे को भवानुग्ररूपो\nनमोऽस्तु ते देववर प्रसीद।\nविज्ञातुमिच्छामि भवन्तमाद्यं\nन हि प्रजानामि तव प्रवृत्तिम्","iast":"ākhyāhi me ko bhavān ugra-rūpo\nnamo 'stu te deva-vara prasīda\nvijñātum ichchhāmi bhavantam ādyaṁ\nna hi prajānāmi tava pravṛittim","v":[{"k":"purohit","t":"Tell me then, who are You, who wears this dreadful form? I bow before You, O Mighty One! Have mercy, I pray, and let me see You as You were at first. I do not know what Your intentions are."},{"k":"sivananda","t":"Tell me, who you are, so fierce of form. I offer my salutations to you, O God Supreme; have mercy on me. I desire to know you, the original Being. I do not indeed know your workings."},{"k":"adidevananda","t":"Tell me, who are You with this terrible form? Salutations to You, O Supreme God. Be gracious to me. I desire to know You, the Primal One. I do not know Your activities."},{"k":"gambirananda","t":"Tell me who You are, fierce in form. Salutations to You, O Supreme God; be gracious. I desire to fully know You, who are the Prime One. For I do not understand Your actions!"},{"k":"sankaranarayan","t":"Please tell me who You are with a terrible form, O Best of gods! Salutations to You; please be merciful. I am desirous of knowing You, the Primal One, in detail, for I do not clearly comprehend Your actions."}]},{"ch":11,"vn":32,"dev":"श्री भगवानुवाच\nकालोऽस्मि लोकक्षयकृत्प्रवृद्धो\nलोकान्समाहर्तुमिह प्रवृत्तः।\nऋतेऽपि त्वां न भविष्यन्ति सर्वे\nयेऽवस्थिताः प्रत्यनीकेषु योधाः","iast":"śhrī-bhagavān uvācha\nkālo 'smi loka-kṣhaya-kṛit pravṛiddho\nlokān samāhartum iha pravṛittaḥ\nṛite 'pi tvāṁ na bhaviṣhyanti sarve\nye 'vasthitāḥ pratyanīkeṣhu yodhāḥ","v":[{"k":"purohit","t":"Lord Shri Krishna replied: I have shown myself to you as the Destroyer who lays waste the world and whose purpose is destruction. In spite of your efforts, all these warriors gathered for battle shall not escape death."},{"k":"sivananda","t":"The Blessed Lord said, \"I am the full-grown, world-destroying Time, now engaged in destroying the worlds. Even without you, none of the warriors arrayed in the hostile armies will live.\""},{"k":"adidevananda","t":"The Lord said, \"I am the world-destroying Time. Manifesting myself fully, I have begun to destroy the worlds here. Even without you, none of the warriors arrayed in the hostile ranks will survive.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"I am the world-destroying Time, grown in stature and now engaged in annihilating the creatures. Even without you, all the warriors arrayed in the confronting armies will cease to exist!\""},{"k":"sankaranarayan","t":"The Bhagavat said, \"I am Time, the world-destroyer, engaged here in withdrawing the worlds that are overgrown. Even without you (your fighting), all the warriors standing in the rival armies would cease to be.\""},{"k":"arnold","t":"Thou seest Me as Time who kills,\nTime who brings all to doom,\nThe Slayer Time, Ancient of Days, come hither to consume;\nExcepting thee, of all these hosts of hostile chiefs arrayed,\nThere stands not one shall leave alive the battlefield!"}]},{"ch":11,"vn":33,"dev":"तस्मात्त्वमुत्तिष्ठ यशो लभस्व\nजित्वा शत्रून् भुङ्क्ष्व राज्यं समृद्धम्।\nमयैवैते निहताः पूर्वमेव\nनिमित्तमात्रं भव सव्यसाचिन्","iast":"tasmāt tvam uttiṣhṭha yaśho labhasva\njitvā śhatrūn bhuṅkṣhva rājyaṁ samṛiddham\nmayaivaite nihatāḥ pūrvam eva\nnimitta-mātraṁ bhava savya-sāchin","v":[{"k":"purohit","t":"Then gird up your loins and conquer. Subdue your foes and enjoy the kingdom in prosperity. I have already doomed them. Be thou my instrument, Arjuna!"},{"k":"sivananda","t":"Therefore, stand up and obtain fame. Conquer the enemies and enjoy the unparalleled kingdom. Verily, by Me they have already been slain; be thou a mere instrument, O Arjuna."},{"k":"adidevananda","t":"Therefore, arise, win glory. Conquering your foes, enjoy a prosperous kingdom. By Me they have already been slain. You be merely an instrument, O Arjuna, you great archer!"},{"k":"gambirananda","t":"Therefore, rise up and gain fame; and, defeating the enemies, enjoy a prosperous kingdom. These have been killed by Me even earlier; be you merely an instrument, O Savyasacin (Arjuna)."},{"k":"sankaranarayan","t":"Therefore, stand up, win glory, and vanquish your foes; enjoy the rich kingdom; for these foes have already been killed by Myself; be a mere token cause in their destruction, O ambidextrous archer!"}]},{"ch":11,"vn":34,"dev":"द्रोणं च भीष्मं च जयद्रथं च\nकर्णं तथाऽन्यानपि योधवीरान्।\nमया हतांस्त्वं जहि मा व्यथिष्ठा\nयुध्यस्व जेतासि रणे सपत्नान्","iast":"droṇaṁ cha bhīṣhmaṁ cha jayadrathaṁ cha\nkarṇaṁ tathānyān api yodha-vīrān\nmayā hatāṁs tvaṁ jahi mā vyathiṣhṭhā\nyudhyasva jetāsi raṇe sapatnān","v":[{"k":"purohit","t":"Drona, Bheeshma, Jayadratha, Karna, and other brave warriors - I have condemned them all. Destroy them; fight without fear. Your foes shall be crushed.\""},{"k":"sivananda","t":"Drona, Bhishma, Jayadratha, Karna, and other brave warriors have already been slain by Me; do not be distressed with fear; fight and you shall conquer your enemies in battle."},{"k":"adidevananda","t":"Slay Drona, Bhisma, Jayadratha, Karna, as well as other mighty warriors who have been doomed by Me. Do not feel distressed. Fight; you shall conquer your rivals in the battle."},{"k":"gambirananda","t":"You destroy Drona, Bhisma, Jayadratha, Karna, and the other heroic warriors who have been killed by Me. Do not be afraid. Fight! You will conquer the enemies in battle."},{"k":"sankaranarayan","t":"Slay Drona, Bhisma, Jayadratha, and Karna, as well as the other heroes of the world—all already slain by Me. Do not be distressed; fight, and you shall vanquish your enemies in the battle."}]},{"ch":11,"vn":35,"dev":"सञ्जय उवाच\nएतच्छ्रुत्वा वचनं केशवस्य\nकृताञ्जलिर्वेपमानः किरीटी।\nनमस्कृत्वा भूय एवाह कृष्णं\nसगद्गदं भीतभीतः प्रणम्य","iast":"sañjaya uvācha\netach chhrutvā vachanaṁ keśhavasya\nkṛitāñjalir vepamānaḥ kirīṭī\nnamaskṛitvā bhūya evāha kṛiṣhṇaṁ\nsa-gadgadaṁ bhīta-bhītaḥ praṇamya","v":[{"k":"purohit","t":"Sanjaya continued: \"Having heard these words from the Lord Shri Krishna, the Prince Arjuna, with folded hands trembling, prostrated himself and with a choked voice, bowing down again and again, and overwhelmed with awe, once more addressed the Lord."},{"k":"sivananda","t":"Sanjaya said, Having heard that speech of Lord Krishna, Arjuna, with joined palms, trembling, prostrated himself, again addressing Krishna in a choked voice, bowing down, overwhelmed with fear."},{"k":"adidevananda","t":"Sanjaya said, Having heard this speech of Krsna, Arjuna did Him obeisance; and trembling with awe, he bowed down again, and with folded palms, his voice choked with emotion, he spoke to Krsna."},{"k":"gambirananda","t":"Sanjaya said: Hearing this utterance of Kesava, Kiriti (Arjuna), with joined palms and trembling, prostrated himself, and then, with a faltering voice, bowed down and overcome by fits of fear, said again to Krsna:"},{"k":"sankaranarayan","t":"Sanjaya said, On hearing this speech of Kesava, the crowned-prince Arjuna had his palms folded; trembling, he prostrated himself to Krsna; stammering, and very much afraid, he bowed down and spoke to Him again."}]},{"ch":11,"vn":36,"dev":"अर्जुन उवाच\nस्थाने हृषीकेश तव प्रकीर्त्या\nजगत् प्रहृष्यत्यनुरज्यते च।\nरक्षांसि भीतानि दिशो द्रवन्ति\nसर्वे नमस्यन्ति च सिद्धसङ्घाः","iast":"arjuna uvācha\nsthāne hṛiṣhīkeśha tava prakīrtyā\njagat prahṛiṣhyaty anurajyate cha\nrakṣhānsi bhītāni diśho dravanti\nsarve namasyanti cha siddha-saṅghāḥ","v":[{"k":"purohit","t":"Arjuna said: My Lord! It is natural for the world to revel and rejoice when singing praises of Your glory; the demons fly in fear and the saints offer You their salutations."},{"k":"sivananda","t":"Arjuna said, \"It is fitting, O Krishna, that the world delights and rejoices in Your praise; demons fly in fear in all directions and the hosts of the perfected ones bow to You.\""},{"k":"adidevananda","t":"Arjuna said, Rightly it is, O Krsna, that Your praise should move the world to joy and love. The rakshasas flee in fear on all sides, and all the hosts of siddhas bow down to You."},{"k":"gambirananda","t":"Arjuna said, \"O Hrsikesa, it is proper that the world be delighted and attracted by Your praise; that the Raksasas, stricken with fear, run in all directions; and that all the groups of the Siddhas bow down to You.\""},{"k":"sankaranarayan","t":"Arjuna said, \"O Lord of sense-organs (Krsna)! The universe is rightly rejoicing and feeling exceedingly delighted by Your high glory; the demons are fleeing in fear in all directions; and the hosts of the perfected ones are bowing down to You.\""}]},{"ch":11,"vn":37,"dev":"कस्माच्च ते न नमेरन्महात्मन्\nगरीयसे ब्रह्मणोऽप्यादिकर्त्रे।\nअनन्त देवेश जगन्निवास\nत्वमक्षरं सदसत्तत्परं यत्","iast":"kasmāch cha te na nameran mahātman\ngarīyase brahmaṇo 'py ādi-kartre\nananta deveśha jagan-nivāsa\ntvam akṣharaṁ sad-asat tat paraṁ yat","v":[{"k":"purohit","t":"How else should they do? O Supreme Self, greater than the powers of creation, the first cause, infinite, the Lord of Lords, the home of the universe, imperishable, being and non-being, yet transcending both."},{"k":"sivananda","t":"And why should they not, O great Soul, bow to Thee Who art greater than all else, the primal cause even of the Creator (Brahma), O Infinite Being, O Lord of the gods, O Abode of the universe; Thou art the imperishable, the Being, the non-being, and That which is supreme—that which is beyond the Being and the non-being."},{"k":"adidevananda","t":"(a) And why should they not, O Mahatma, bow down to You who are great, being the first Creator, even of Brahma?\n(b) O Infinite, Lord of gods, O You who have the universe as Your abode! You are the imperishable individual self, the existent and the non-existent, and that which is beyond both."},{"k":"gambirananda","t":"And why should they not bow down to You, O exalted One, who are greater than all and who are the first Creator even of Brahma! O infinite One, supreme God, Abode of the Universe, You are the Immutable, being and non-being, and that which is Transcendental."},{"k":"sankaranarayan","t":"O Mighty One! Why should they not bow down to You, the Primal Creator, Who is greater than even Brahma (personal god)? O Endless One, O Lord of gods, O Abode of the universe! You are unalterable, existent, non-existent, and also that which is beyond both."}]},{"ch":11,"vn":38,"dev":"त्वमादिदेवः पुरुषः पुराण\nस्त्वमस्य विश्वस्य परं निधानम्।\nवेत्तासि वेद्यं च परं च धाम\nत्वया ततं विश्वमनन्तरूप","iast":"tvam ādi-devaḥ puruṣhaḥ purāṇas\ntvam asya viśhvasya paraṁ nidhānam\nvettāsi vedyaṁ cha paraṁ cha dhāma\ntvayā tataṁ viśhvam ananta-rūpa","v":[{"k":"purohit","t":"You are the Primal God, the Ancient One, the Supreme Abode of this universe, the Knower, the Knowledge, and the Final Home. You fill everything. Your form is infinite."},{"k":"sivananda","t":"You are the primal God, the ancient Purusha, the supreme refuge of this universe, the knower, the knowable, and the supreme Abode. Through You, the universe is pervaded, O Being of infinite forms."},{"k":"adidevananda","t":"(a) You are the Primal God and the Ancient One. You are the Supreme resting place of the universe...\n(b)...You are the Knower and the object of knowledge, and the Supreme Abode. Through You, O infinite of form, is this universe pervaded."},{"k":"gambirananda","t":"You are the primal Deity, the ancient Person; You are the supreme Refuge of this world. You are the knower and the object of knowledge, and the supreme Abode. O You of infinite forms, You pervade the Universe!"},{"k":"sankaranarayan","t":"You are the Primal God; You are the Ancient Soul; You are the transcendent place of rest for this universe; You are the knower and the knowable; You are the Highest Abode; and the universe with its infinite forms is pervaded by You."}]},{"ch":11,"vn":39,"dev":"वायुर्यमोऽग्निर्वरुणः शशाङ्कः\nप्रजापतिस्त्वं प्रपितामहश्च।\nनमो नमस्तेऽस्तु सहस्रकृत्वः\nपुनश्च भूयोऽपि नमो नमस्ते","iast":"vāyur yamo 'gnir varuṇaḥ śhaśhāṅkaḥ\nprajāpatis tvaṁ prapitāmahaśh cha\nnamo namas te 'stu sahasra-kṛitvaḥ\npunaśh cha bhūyo 'pi namo namas te","v":[{"k":"purohit","t":"You are the wind, you are death, you are the fire, the water, the moon, the father, and the grandfather. Honor and glory to you a thousand and a thousand times! Again and again, salutations to you, O my Lord!"},{"k":"sivananda","t":"You are Vayu, Yama, Agni, Varuna, the moon, the Creator, and the great-grandfather. I offer my salutations to You a thousand times, and again I offer my salutations to You."},{"k":"adidevananda","t":"(a) You are Yayu, Yama, Agni, Varuna, Sashanka, Prajapati, and the great-grandsire.\n(b) Hail to You a thousand times! Hail to You again and yet again!"},{"k":"gambirananda","t":"You are air, death, fire, the god of the waters, the moon, the Lord of creatures, and the great-grandfather. Salutations to you a thousand times! Salutations to you again and again! Salutations!"},{"k":"sankaranarayan","t":"You are Vayu, Yama, Agni, Varuna, the Moon, Prajapati, and the great-paternal-grandfather; I offer salutations to You a thousand times, and again, even more salutations to You."}]},{"ch":11,"vn":40,"dev":"नमः पुरस्तादथ पृष्ठतस्ते\nनमोऽस्तु ते सर्वत एव सर्व।\nअनन्तवीर्यामितविक्रमस्त्वं\nसर्वं समाप्नोषि ततोऽसि सर्वः","iast":"namaḥ purastād atha pṛiṣhṭhatas te\nnamo 'stu te sarvata eva sarva\nananta-vīryāmita-vikramas tvaṁ\nsarvaṁ samāpnoṣhi tato 'si sarvaḥ","v":[{"k":"purohit","t":"Salutations to Thee in front and on all sides, Thou who encompasseth me round about. Thy power is infinite; Thy majesty immeasurable; Thou upholdest all things; indeed, Thou Thyself art All."},{"k":"sivananda","t":"Salutations to You in front and behind! Salutations to You on every side! O All! You, infinite in power and prowess, pervade all; therefore You are all."},{"k":"adidevananda","t":"(a) Salutations to You from before and behind! Salutations to You from all sides, O All!৷৷.\n(b) ৷৷. O You of infinite prowess and heroic action, which are measureless! You pervade all beings, and therefore, You are all."},{"k":"gambirananda","t":"Salutations to You in the East and behind. Salutations to You on all sides indeed, O All! You possess infinite strength and infinite heroism. You pervade everything; thus You are all!"},{"k":"sankaranarayan","t":"Salutations to You in front and behind; salutations to You on all sides, O One Who is All! You are of infinite might and immeasurable power; and You pervade all, and thus You are all."}]},{"ch":11,"vn":41,"dev":"सखेति मत्वा प्रसभं यदुक्तं\nहे कृष्ण हे यादव हे सखेति।\nअजानता महिमानं तवेदं\nमया प्रमादात्प्रणयेन वापि","iast":"sakheti matvā prasabhaṁ yad uktaṁ\nhe kṛiṣhṇa he yādava he sakheti\najānatā mahimānaṁ tavedaṁ\nmayā pramādāt praṇayena vāpi","v":[{"k":"purohit","t":"Whatever I have said to you in rashness, taking you only as a friend and addressing you as \"O Krishna! O Yadava! O Friend!\" in thoughtless familiarity, without understanding your greatness;"},{"k":"sivananda","t":"Whatever I have presumptuously said from carelessness or love, addressing You as O Krishna! O Yadava! O Friend! regarding You merely as a friend, unknowing of Your greatness."},{"k":"adidevananda","t":"Unaware of Your majesty, and either out of negligence or love, or considering You to be a friend, whatever I have said rudely, such as 'O Krsna, O Yadava, O Comrade,'"},{"k":"gambirananda","t":"Without knowing Your greatness, whatever I said rashly, inadvertently, or even out of familiarity, thinking You to be a friend, addressing You as 'O Krsna,' 'O Yadava,' 'O friend,' etc."},{"k":"sankaranarayan","t":"Taking You as a companion, not knowing Your greatness, and out of carelessness or even affection, whatever I have importunately called You—O Krsna, O Yadava, O Comrade—"}]},{"ch":11,"vn":42,"dev":"यच्चावहासार्थमसत्कृतोऽसि\nविहारशय्यासनभोजनेषु।\nएकोऽथवाप्यच्युत तत्समक्षं\nतत्क्षामये त्वामहमप्रमेयम्","iast":"yach chāvahāsārtham asat-kṛito 'si\nvihāra-śhayyāsana-bhojaneṣhu\neko 'tha vāpy achyuta tat-samakṣhaṁ\ntat kṣhāmaye tvām aham aprameyam","v":[{"k":"purohit","t":"Whatever insults I have offered to You in jest, in sport, in repose, in conversation, or at a banquet, alone or in a crowd, I ask for Your forgiveness for them all, O You Who are without equal!"},{"k":"sivananda","t":"In whatever way I may have insulted You for the sake of fun, while at play, reposing, sitting, or at meals, when alone (with You), O Krishna, or in company, that I implore You, immeasurable one, to forgive."},{"k":"adidevananda","t":"And whatever disrespect has been shown to You in jest, while playing, resting, sitting, or eating, whether alone or in the presence of others, O Acyuta—I implore You for forgiveness, You who are incomprehensible."},{"k":"gambirananda","t":"And that You have been discourteously treated out of fun—while walking, while on a bed, while on a seat, while eating, in privacy, or, O Acyuta, even in public—for that, I beg pardon of You, the incomprehensible One."},{"k":"sankaranarayan","t":"Whatever disrespect I have shown to You, making fun of You in the course of play, or while on the bed, or on the seat, or at meals, either alone or in the presence of respectable persons—for that, I beg pardon of You, the Unconceivable One, O Acyuta!"}]},{"ch":11,"vn":43,"dev":"पितासि लोकस्य चराचरस्य\nत्वमस्य पूज्यश्च गुरुर्गरीयान्।\nन त्वत्समोऽस्त्यभ्यधिकः कुतोऽन्यो\nलोकत्रयेऽप्यप्रतिमप्रभाव","iast":"pitāsi lokasya charācharasya\ntvam asya pūjyaśh cha gurur garīyān\nna tvat-samo 'sty abhyadhikaḥ kuto 'nyo\nloka-traye 'py apratima-prabhāva","v":[{"k":"purohit","t":"For you are the Father of all things movable and immovable, the Worshipful, the Master of Masters! In all the worlds, there is none equal to you; how then could there be one superior, O you who stand alone, Supreme?"},{"k":"sivananda","t":"Thou art the Father of this world, both moving and unmoving. Thou art to be adored by this world; Thou, the greatest Guru; for none exists who is equal to Thee; how then could there be another superior to Thee in the three worlds, O Being of unrivaled power?"},{"k":"adidevananda","t":"You are the father of this world, of all that moves and does not move. You are its teacher and the one most worthy of reverence. There is none equal to You. How then could there be in the three worlds another greater than You, O Being of matchless greatness?"},{"k":"gambirananda","t":"You are the Father of all beings, both moving and non-moving; to You, the Teacher, are they worthy of worship, and You are greater than a teacher. There is none equal to You; how can there be anyone greater even in all the three worlds, O You of unrivaled power?"},{"k":"sankaranarayan","t":"You are the father of the world of the moving and the unmoving; you are the great preceptor of this universe; in the triad of worlds, there is no one equal to you—how can there be anyone else superior, having greatness not comprehended?"}]},{"ch":11,"vn":44,"dev":"तस्मात्प्रणम्य प्रणिधाय कायं\nप्रसादये त्वामहमीशमीड्यम्।\nपितेव पुत्रस्य सखेव सख्युः\nप्रियः प्रियायार्हसि देव सोढुम्","iast":"tasmāt praṇamya praṇidhāya kāyaṁ\nprasādaye tvām aham īśham īḍyam\npiteva putrasya sakheva sakhyuḥ\npriyaḥ priyāyārhasi deva soḍhum","v":[{"k":"purohit","t":"Therefore, I prostrate myself before You, O Lord! Most Adorable! I salute You, and I ask for Your blessing. Only You can be trusted to bear with me, like a father to a son, like a friend to a friend, and like a lover to his beloved."},{"k":"sivananda","t":"Therefore, bowing down and prostrating my body, I crave Thy forgiveness, O adorable Lord. As a father forgives his son, a friend his dear friend, a lover his beloved, even so may Thou forgive me, O God."},{"k":"adidevananda","t":"Therefore, bowing down and prostrating my body, I implore Your mercy, O adorable Lord. As a father listens to his son or a friend to his friend, it is fitting, O Lord, that You, who are dear to me, should bear with me who am dear to You."},{"k":"gambirananda","t":"Therefore, by bowing down and prostrating my body, I seek to propitiate You who are God and are adorable. O Lord, You should forgive my faults as a father would forgive the faults of a son, as a friend would forgive the faults of a friend, and as a lover would forgive the faults of a beloved."},{"k":"sankaranarayan","t":"Hence, paying homage and prostrating my body, I solicit grace from You, the praiseworthy Lord. O God! Be pleased to bear with me, just as a beloved father would with his beloved son, and just as a dear friend would with his dear friend."}]},{"ch":11,"vn":45,"dev":"अदृष्टपूर्वं हृषितोऽस्मि दृष्ट्वा\nभयेन च प्रव्यथितं मनो मे।\nतदेव मे दर्शय देव रूपं\nप्रसीद देवेश जगन्निवास","iast":"adṛiṣhṭa-pūrvaṁ hṛiṣhito 'smi dṛiṣhṭvā\nbhayena cha pravyathitaṁ mano me\ntad eva me darśhaya deva rūpaṁ\nprasīda deveśha jagan-nivāsa","v":[{"k":"purohit","t":"I rejoice that I have seen what no man has ever seen before; yet, O Lord! I am overwhelmed with fear. Please take on the form I know. Be merciful, O Lord! You who are the home of the entire universe."},{"k":"sivananda","t":"I am delighted, having seen something never seen before; yet my mind is distressed with fear. Show me that form only, O God; have mercy, O God of gods, O Abode of the universe."},{"k":"adidevananda","t":"Seeing something never seen before, I am delighted. But my mind is also filled with awe. Show me, O Lord! Your other form. O Lord of the gods! Be gracious, O Abode of the universe!"},{"k":"gambirananda","t":"I am delighted by seeing something I have not seen before, and my mind is stricken with fear. O Lord, show me that very form; O Supreme God, O Abode of the Universe, be gracious!"},{"k":"sankaranarayan","t":"I am thrilled by what I have not seen before; my mind is greatly distressed with fear; show me Your usual form, O God! Lord of gods! O Abode of the worlds!"}]},{"ch":11,"vn":46,"dev":"किरीटिनं गदिनं चक्रहस्त\nमिच्छामि त्वां द्रष्टुमहं तथैव।\nतेनैव रूपेण चतुर्भुजेन\nसहस्रबाहो भव विश्वमूर्ते","iast":"kirīṭinaṁ gadinaṁ chakra-hastam\nichchhāmi tvāṁ draṣhṭum ahaṁ tathaiva\ntenaiva rūpeṇa chatur-bhujena\nsahasra-bāho bhava viśhva-mūrte","v":[{"k":"purohit","t":"I long to see Thee as Thou wert before, with the crown, the scepter, and the discus in Thy hands; in Thy other form, with Thy four hands, O Thou whose arms are countless and whose forms are infinite."},{"k":"sivananda","t":"I desire to see You as before, crowned, bearing a mace, with the discus in hand, in Your former form only, having four arms, O thousand-armed, Cosmic Being."},{"k":"adidevananda","t":"I wish to see You ever as before, with crown and mace and discus in hand. Assume again that four-armed shape, O Thou the thousand-armed, of Universal Form!"},{"k":"gambirananda","t":"I want to see You just as before, wearing a crown, wielding a mace, and holding a disc in hand. O You with a thousand arms, O You of Cosmic form, appear with that very form with four hands."},{"k":"sankaranarayan","t":"I desire to see You in the same manner, wearing a crown, holding the club and the discus in Your hands; please be with the same form having four hands, O Thousand-armed One! O Universal Form!"}]},{"ch":11,"vn":47,"dev":"श्री भगवानुवाच\nमया प्रसन्नेन तवार्जुनेदं\nरूपं परं दर्शितमात्मयोगात्।\nतेजोमयं विश्वमनन्तमाद्यं\nयन्मे त्वदन्येन न दृष्टपूर्वम्","iast":"śhrī-bhagavān uvācha\nmayā prasannena tavārjunedaṁ\nrūpaṁ paraṁ darśhitam ātma-yogāt\ntejo-mayaṁ viśhvam anantam ādyaṁ\nyan me tvad anyena na dṛiṣhṭa-pūrvam","v":[{"k":"purohit","t":"Lord Shri Krishna replied: My beloved friend! It is only through My grace and power that you have been able to see this vision of splendour, the Universal, the Infinite, the Original. Never has it been seen by anyone else."},{"k":"sivananda","t":"The Blessed Lord said, \"O Arjuna, this Cosmic Form has graciously been shown to you by Me through My own Yogic power. It is full of splendour, primeval, and infinite; this Cosmic Form of Mine has never been seen before by anyone other than you.\""},{"k":"adidevananda","t":"The Lord said, \"By My grace, O Arjuna, this Supreme Form, luminous, universal, infinite, and primal—never seen before by anyone but you—has been revealed to you through My own free will.\""},{"k":"gambirananda","t":"The Blessed Lord said, Out of grace, O Arjuna, this supreme, radiant, cosmic, infinite, primeval form—which no one other than you has seen before—has been shown to you by Me through the power of My own Yoga."},{"k":"sankaranarayan","t":"The Bhagavat said, \"Being gracious towards you, I have shown you, O Arjuna, this supreme form, as a result of your concentration on the Self. This form of Mine, full of universal splendour, unending and primal, has never been seen before by anyone other than yourself.\""}]},{"ch":11,"vn":48,"dev":"न वेदयज्ञाध्ययनैर्न दानै\nर्न च क्रियाभिर्न तपोभिरुग्रैः।\nएवंरूपः शक्य अहं नृलोके\nद्रष्टुं त्वदन्येन कुरुप्रवीर","iast":"na veda-yajñādhyayanair na dānair\nna cha kriyābhir na tapobhir ugraiḥ\nevaṁ-rūpaḥ śhakya ahaṁ nṛi-loke\ndraṣhṭuṁ tvad anyena kuru-pravīra","v":[{"k":"purohit","t":"It is not possible for man on earth to see what thou hast seen, O thou foremost hero of the Kuru-clan, through study of the scriptures, sacrifice or gift, ritual or rigorous austerity!"},{"k":"sivananda","t":"Neither by the study of the Vedas, nor by gifts, nor by sacrifices, nor by severe austerities, can I be seen in this form in the world of men by any other than yourself, O great hero of the Kurus (Arjuna)."},{"k":"adidevananda","t":"Neither through the study of the Vedas, nor by sacrifices, nor by recitations of the scriptures, nor by gifts, nor by rituals, nor by strict austerities can I be realized in a form like this in the world of men by anyone else but you. O Arjuna!"},{"k":"gambirananda","t":"Not by the study of the Vedas and sacrifices, not by gifts, not even by rituals, nor by severe austerities, can I, in this form, be perceived in the human world by anyone other than you, O most valiant among the Kurus, who has not received My grace."},{"k":"sankaranarayan","t":"Not by the knowledge of the Vedas and sacrifices, nor by making gifts, nor by the rituals, nor by severe austerities, can I be seen in this form in the world of men by anyone other than yourself, O great hero of the Kurus!"}]},{"ch":11,"vn":49,"dev":"मा ते व्यथा मा च विमूढभावो\nदृष्ट्वा रूपं घोरमीदृङ्ममेदम्।\nव्यपेतभीः प्रीतमनाः पुनस्त्वं\nतदेव मे रूपमिदं प्रपश्य","iast":"mā te vyathā mā cha vimūḍha-bhāvo\ndṛiṣhṭvā rūpaṁ ghoram īdṛiṅ mamedam\nvyapeta-bhīḥ prīta-manāḥ punas tvaṁ\ntad eva me rūpam idaṁ prapaśhya","v":[{"k":"purohit","t":"Do not be afraid or confused by the terrible vision. Put away your fear and, with a joyful mind, see Me again in My usual form."},{"k":"sivananda","t":"Do not be afraid, nor be bewildered on seeing such a terrible form of Mine; with your fear dispelled and with a gladdened heart, now behold again this former form of Mine."},{"k":"adidevananda","t":"You need not fear any longer, nor be perplexed, looking upon this awe-inspiring form of Mine. Free from fear and with a gladdened heart, behold once again that other form of Mine."},{"k":"gambirananda","t":"May you have no fear, and may there be no bewilderment upon seeing this form of Mine so terrible. Becoming free from fear and gladdened in mind once again, behold this earlier form of Mine."},{"k":"sankaranarayan","t":"Let there be no distress or bewilderment in you upon seeing this terrifying and violent form of Mine; be free from fear, and with a cheerful heart, behold again this form of Mine which is the same as before."}]},{"ch":11,"vn":50,"dev":"सञ्जय उवाच\nइत्यर्जुनं वासुदेवस्तथोक्त्वा\nस्वकं रूपं दर्शयामास भूयः।\nआश्वासयामास च भीतमेनं\nभूत्वा पुनः सौम्यवपुर्महात्मा","iast":"sañjaya uvācha\nity arjunaṁ vāsudevas tathoktvā\nsvakaṁ rūpaṁ darśhayām āsa bhūyaḥ\nāśhvāsayām āsa cha bhītam enaṁ\nbhūtvā punaḥ saumya-vapur mahātmā","v":[{"k":"purohit","t":"Sanjaya continued: \"Having thus spoken to Arjuna, Lord Shri Krishna showed Himself again in His accustomed form; and the Mighty Lord, in gentle tones, softly consoled him who had recently trembled with fear."},{"k":"sivananda","t":"Sanjaya said, Having thus spoken to Arjuna, Krishna again showed His own form. The great Soul, assuming His gentle form, then consoled Arjuna, who was terrified."},{"k":"adidevananda","t":"Sanjaya said, Having thus spoken to Arjuna, Sri Krsna once more revealed His own form. The Mahatman, assuming a benign form again, reassured him who had been struck with awe."},{"k":"gambirananda","t":"Sanjaya said, Thus, having spoken to Arjuna in that manner, Vasudeva showed His own form again. And He, the exalted One, reassured this terrified one by again becoming serene in his form."},{"k":"sankaranarayan","t":"Having said this to Arjuna, Vasudeva revealed His own tiny form; assuming His gentle body once again, the Mighty Soul (Krsna) consoled the frightened Arjuna."}]},{"ch":11,"vn":51,"dev":"अर्जुन उवाच\nदृष्ट्वेदं मानुषं रूपं तवसौम्यं जनार्दन।\nइदानीमस्मि संवृत्तः सचेताः प्रकृतिं गतः","iast":"arjuna uvācha\ndṛiṣhṭvedaṁ mānuṣhaṁ rūpaṁ tava saumyaṁ janārdana\nidānīm asmi saṁvṛittaḥ sa-chetāḥ prakṛitiṁ gataḥ","v":[{"k":"purohit","t":"Arjuna said: Seeing You in Your gentle human form, my Lord, I am myself again, calm once more."},{"k":"sivananda","t":"Arjuna said, \"Having seen this Thy gentle human form, O Krishna, now I am composed and have been restored to my own nature.\""},{"k":"adidevananda","t":"Arjuna said, \"Having beheld Your human and pleasing form, O Krsna, I am now composed in mind and have been restored to my normal nature.\""},{"k":"gambirananda","t":"Arjuna said, \"O Janardana, having seen this serene human form of Yours, I have now become calm in mind and restored to my own nature.\""},{"k":"sankaranarayan","t":"Arjuna said, \"On seeing this gentle human form of Yours, O Janardana, I have now regained my nature and collected my thinking faculty.\""}]},{"ch":11,"vn":52,"dev":"श्री भगवानुवाच\nसुदुर्दर्शमिदं रूपं दृष्टवानसि यन्मम।\nदेवा अप्यस्य रूपस्य नित्यं दर्शनकाङ्क्षिणः","iast":"śhrī-bhagavān uvācha\nsu-durdarśham idaṁ rūpaṁ dṛiṣhṭavān asi yan mama\ndevā apy asya rūpasya nityaṁ darśhana-kāṅkṣhiṇaḥ","v":[{"k":"purohit","t":"Lord Shri Krishna replied: It is difficult to see the vision of Me that thou hast seen. Even the most powerful have longed for it in vain."},{"k":"sivananda","t":"The Blessed Lord said, \"It is very hard indeed to see this form of Mine which thou hast seen; even the gods are ever longing to behold it.\""},{"k":"adidevananda","t":"The Lord said, \"It is very hard to behold this form of Mine which you have seen. Even the gods everlong to behold this form.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"This form of Mine, which you have seen, is very difficult to behold; even the gods are ever desirous of a vision of this form.\""},{"k":"sankaranarayan","t":"The Bhagavat said, \"This form of Mine, which you have just observed, is extremely difficult to behold; even the gods are ever eager to behold it.\""}]},{"ch":11,"vn":53,"dev":"नाहं वेदैर्न तपसा न दानेन न चेज्यया।\nशक्य एवंविधो द्रष्टुं दृष्टवानसि मां यथा","iast":"nāhaṁ vedair na tapasā na dānena na chejyayā\nśhakya evaṁ-vidho draṣhṭuṁ dṛiṣhṭavān asi māṁ yathā","v":[{"k":"purohit","t":"It is not possible to see Me as you have done through studying the scriptures, performing austerities, giving gifts, or making sacrifices."},{"k":"sivananda","t":"Neither by the Vedas, nor by austerity, nor by gift, nor by sacrifice can I be seen in this form as thou hast seen Me so easily."},{"k":"adidevananda","t":"Sri Krishna says, \"I cannot be seen in such a form as You have seen Me, not by the Vedas, nor by austerities, nor by gifts, nor by sacrifice.\""},{"k":"gambirananda","t":"Not through the Vedas, nor by austerity, nor by gifts, nor even by sacrifice can I be seen in this form as you have seen Me."},{"k":"sankaranarayan","t":"Neither by reciting the Vedas, nor by observing austerity, nor by giving gifts, nor by performing sacrifice, can I be seen in this way as you have seen Me now."}]},{"ch":11,"vn":54,"dev":"भक्त्या त्वनन्यया शक्यमहमेवंविधोऽर्जुन।\nज्ञातुं दृष्टुं च तत्त्वेन प्रवेष्टुं च परंतप","iast":"bhaktyā tv ananyayā śhakya aham evaṁ-vidho 'rjuna\njñātuṁ draṣhṭuṁ cha tattvena praveṣhṭuṁ cha parantapa","v":[{"k":"purohit","t":"Only through tireless devotion can I be seen and known; only in this way can a person become one with Me, O Arjuna!"},{"k":"sivananda","t":"But by single-minded devotion, I can be known, seen, and entered into in reality, O Arjuna."},{"k":"adidevananda","t":"But by single-minded devotion, O Arjuna, it is possible to truly know, to see, and to enter into Me, who am of this form, O harasser of foes."},{"k":"gambirananda","t":"But, O Arjuna, by single-minded devotion am I, in this form, able to be known and seen in reality, and also entered into, O destroyer of foes."},{"k":"sankaranarayan","t":"But, through an unwavering devotion, it is possible to know, observe, and even enter into Me, O Arjuna! O scorcher of foes!"}]},{"ch":11,"vn":55,"dev":"मत्कर्मकृन्मत्परमो मद्भक्तः सङ्गवर्जितः।\nनिर्वैरः सर्वभूतेषु यः स मामेति पाण्डव","iast":"mat-karma-kṛin mat-paramo mad-bhaktaḥ saṅga-varjitaḥ\nnirvairaḥ sarva-bhūteṣhu yaḥ sa mām eti pāṇḍava","v":[{"k":"purohit","t":"He who does every action for My sake, to whom I am the final goal, who loves Me alone and hates no one—O My dearest son, only he can realize Me!"},{"k":"sivananda","t":"He who does all actions for Me, who regards Me as the Supreme, who is devoted to Me, who is free from attachment, who bears no enmity towards any creature, he comes to Me, O Arjuna."},{"k":"adidevananda","t":"Whoever works for Me, regards Me as the highest and is devoted to Me, free from attachment and without animosity towards any creature, they come to Me, O Arjuna."},{"k":"gambirananda","t":"O son of Pandu, he who works for Me, accepts Me as the supreme goal, is devoted to Me, is devoid of attachment and free from enmity towards all beings—he attains Me."},{"k":"sankaranarayan","t":"He who performs actions for Me, who regards Me as his supreme goal, who is devoted to Me, who is free from attachment, and who is free from hatred towards all beings—he attains Me, O son of Pandu!"}]},{"ch":12,"vn":1,"dev":"अर्जुन उवाचएवं सततयुक्ता ये भक्तास्त्वां पर्युपासते।येचाप्यक्षरमव्यक्तं तेषां के योगवित्तमाः","iast":"arjuna uvācha\nevaṁ satata-yuktā ye bhaktās tvāṁ paryupāsate\nye chāpy akṣharam avyaktaṁ teṣhāṁ ke yoga-vittamāḥ","v":[{"k":"purohit","t":"Arjuna asked, \"My Lord, which are the better devotees who worship You: those who try to know You as a Personal God, or those who worship You as Impersonal and Indestructible?\""},{"k":"sivananda","t":"Arjuna said, \"Which of them are better versed in Yoga—those who steadfastly worship You, or those who worship the imperishable and the unmanifested?\""},{"k":"adidevananda","t":"Arjuna said: Which of these has greater knowledge of yoga—those devotees who meditate on You, ever integrated, or those who meditate on the Imperishable and the Unmanifest?"},{"k":"gambirananda","t":"Arjuna said: \"Which of these devotees, who are ever dedicated and meditate on You, and those who meditate on the Unmanifested and Immutable, are the best experiencers of yoga [here, yoga means samadhi, spiritual absorption]?\""},{"k":"sankaranarayan","t":"Arjuna said: Who are the best knowers of yoga, those who are constantly attached to You and worship You, or those who worship the motionless Unmanifest?"}]},{"ch":12,"vn":2,"dev":"श्री भगवानुवाचमय्यावेश्य मनो ये मां नित्ययुक्ता उपासते।श्रद्धया परयोपेतास्ते मे युक्ततमा मताः","iast":"śhrī-bhagavān uvācha\nmayy āveśhya mano ye māṁ nitya-yuktā upāsate\nśhraddhayā parayopetās te me yuktatamā matāḥ","v":[{"k":"purohit","t":"Lord Shri Krishna replied: Those who keep their minds fixed on Me, who worship Me always with unwavering faith and concentration, are the very best."},{"k":"sivananda","t":"The Blessed Lord said, \"In My opinion, those who fix their minds on Me, worship Me ever steadfastly, and are endowed with supreme faith, are the best in Yoga.\""},{"k":"adidevananda","t":"The Lord said, \"Those who, ever integrated with Me and possessing supreme faith, worship Me, focusing their minds on Me—these are considered by Me to be the highest among the yogis.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"Those who meditate on Me, fixing their minds on Me with steadfast devotion, endowed with supreme faith—they are considered to be the most perfect yogis according to Me.\""},{"k":"sankaranarayan","t":"The Bhagavat said, \"Those who, causing their mind to enter into Me well, remain permanently attached to Me, and are endowed with an extraordinary faith, worship Me—they are considered by Me to be the best among the masters of Yoga.\""}]},{"ch":12,"vn":3,"dev":"ये त्वक्षरमनिर्देश्यमव्यक्तं पर्युपासते।सर्वत्रगमचिन्त्यं च कूटस्थमचलं ध्रुवम्","iast":"ye tv akṣharam anirdeśhyam avyaktaṁ paryupāsate\nsarvatra-gam achintyañcha kūṭa-stham achalandhruvam\nsanniyamyendriya-grāmaṁ sarvatra sama-buddhayaḥ\nte prāpnuvanti mām eva sarva-bhūta-hite ratāḥ","v":[{"k":"purohit","t":"Those who worship Me as the Indestructible, the Undefinable, the Omnipresent, the Unthinkable, the Primal, the Immutable, and the Eternal;"},{"k":"sivananda","t":"Those who worship the imperishable, the indefinable, the unmanifest, the omnipresent, the unthinkable, the immovable, and the eternal."},{"k":"adidevananda","t":"But those who meditate on the Imperishable, the indefinable, the unmanifest, omnipresent, unthinkable, common to all beings, immovable, and constant—"},{"k":"gambirananda","t":"Those, however, who meditate in every way on the immutable, the indefinable, the unmanifest, which is all-pervasive, incomprehensible, unchanging, immovable, and constant."},{"k":"sankaranarayan","t":"Those who contemplate on the Unmanifest, which is motionless, undefinable, all-pervading, unthinkable, peak-like, unmoving, and fixed."}]},{"ch":12,"vn":4,"dev":"संनियम्येन्द्रियग्रामं सर्वत्र समबुद्धयः।ते प्राप्नुवन्ति मामेव सर्वभूतहिते रताः","iast":"sanniyamyendriya-grāmaṁ  sarvatra    sama-buddhayaḥ  te  prāpnuvanti mām eva sarva-bhūta-hite    ratāḥ","v":[{"k":"purohit","t":"Subduing their senses, viewing all conditions of life with an equal eye, and working for the welfare of all beings, they assuredly come to Me."},{"k":"sivananda","t":"Having restrained all the senses, being even-minded everywhere, and intent on the welfare of all beings, they verily come unto Me."},{"k":"adidevananda","t":"Having subdued all the senses, being even-minded, and engaged in the welfare of all beings, they too come to Me only."},{"k":"gambirananda","t":"By fully controlling all the organs and remaining even-minded at all times, they, engaged in the welfare of all beings, attain Me alone."},{"k":"sankaranarayan","t":"Who, by properly restraining the group of sense-organs, remain equanimous at all stages and find pleasure in the welfare of all beings—they attain nothing but Me."}]},{"ch":12,"vn":5,"dev":"क्लेशोऽधिकतरस्तेषामव्यक्तासक्तचेतसाम्।\nअव्यक्ता हि गतिर्दुःखं देहवद्भिरवाप्यते","iast":"kleśho 'dhikataras teṣhām avyaktāsakta-chetasām\navyaktā hi gatir duḥkhaṁ dehavadbhir avāpyate","v":[{"k":"purohit","t":"But they who fix their attention on the Absolute and Impersonal encounter greater hardships, for it is difficult for those who have a body to realize Me as without one."},{"k":"sivananda","t":"Greater is their trouble whose minds are set on the unmanifested, for the goal of the unmanifested is very hard for the embodied to reach."},{"k":"adidevananda","t":"Greater is the difficulty for those whose minds are thus attached to the unmanifest, for the way of the unmanifest is hard to reach for embodied beings."},{"k":"gambirananda","t":"For those whose minds are attached to the Unmanifested, the struggle is greater; for the Goal, which is the Unmanifest, is attained with difficulty by the embodied ones."},{"k":"sankaranarayan","t":"But the trouble is much greater for those who have their minds fixed on the Unmanifest, for it is difficult for those with physical bodies to attain the Unmanifest goal."}]},{"ch":12,"vn":6,"dev":"ये तु सर्वाणि कर्माणि मयि संन्यस्य मत्पराः।अनन्येनैव योगेन मां ध्यायन्त उपासते","iast":"ye tu sarvāṇi karmāṇi mayi sannyasya mat-paraḥ\nananyenaiva yogena māṁ dhyāyanta upāsate","v":[{"k":"purohit","t":"Verily, those who surrender their actions to Me, who contemplate Me, worship Me, and meditate on Me alone, with no thought other than Me."},{"k":"sivananda","t":"But to those who worship Me, renouncing all actions in Me, regarding Me as the supreme goal, meditating on Me with single-minded yoga."},{"k":"adidevananda","t":"For those who dedicate all their actions to Me, hold Me as their supreme goal, are intent on Me, and worship Me, meditating on Me with exclusive devotion;"},{"k":"gambirananda","t":"As for those who, having dedicated all actions to Me and accepted Me as the supreme, meditate on Me with single-minded concentration only-."},{"k":"sankaranarayan","t":"On the other hand, those who, having renounced all their actions in Me, have Me as their sole goal; and revere Me, meditating on Me through that Yoga alone, which admits no other element but Me in it;"}]},{"ch":12,"vn":7,"dev":"तेषामहं समुद्धर्ता मृत्युसंसारसागरात्।भवामि नचिरात्पार्थ मय्यावेशितचेतसाम्","iast":"teṣhām ahaṁ samuddhartā mṛityu-saṁsāra-sāgarāt\nbhavāmi na chirāt pārtha mayy āveśhita-chetasām","v":[{"k":"purohit","t":"O Arjuna! I rescue them from the ocean of life and death, for their minds are fixed upon Me."},{"k":"sivananda","t":"To those whose minds are set on Me, O Arjuna, verily I soon become the savior out of the ocean of Samsara."},{"k":"adidevananda","t":"Those whose minds are thus focused on Me, I soon become their savior from the ocean of mortal life."},{"k":"gambirananda","t":"O son of Prtha, for those who have their minds absorbed in Me, I become, without delay, the deliverer from the sea of the world, which is fraught with death."},{"k":"sankaranarayan","t":"Of them, with their minds completely entered into Me, I soon become a redeemer from the ocean of the cycle of death, O son of Prtha!"}]},{"ch":12,"vn":8,"dev":"मय्येव मन आधत्स्व मयि बुद्धिं निवेशय।निवसिष्यसि मय्येव अत ऊर्ध्वं न संशयः","iast":"mayy eva mana ādhatsva mayi buddhiṁ niveśhaya\nnivasiṣhyasi mayy eva ata ūrdhvaṁ na sanśhayaḥ","v":[{"k":"purohit","t":"Then let your mind cling only to Me, let your intellect abide in Me; and without doubt, you will live hereafter in Me alone."},{"k":"sivananda","t":"Fix your mind on Me, and your intellect in Me. Then you will certainly live in Me alone hereafter."},{"k":"adidevananda","t":"Focus your mind on Me alone; and let your intellect enter into Me. Then, you will live in Me alone; there is no doubt."},{"k":"gambirananda","t":"Fix the mind on Me alone; in Me alone let the intellect rest. There is no doubt that hereafter you will dwell in Me alone."},{"k":"sankaranarayan","t":"Hence, fix your mind on nothing but Me; cause your thought to settle in Me. Thus, resorting to the best Yoga, you will dwell in Me alone."}]},{"ch":12,"vn":9,"dev":"अथ चित्तं समाधातुं न शक्नोषि मयि स्थिरम्।अभ्यासयोगेन ततो मामिच्छाप्तुं धनञ्जय","iast":"atha chittaṁ samādhātuṁ na śhaknoṣhi mayi sthiram\nabhyāsa-yogena tato mām ichchhāptuṁ dhanañjaya","v":[{"k":"purohit","t":"But if you cannot fix your mind firmly on Me, then, my beloved friend, try to do so through constant practice."},{"k":"sivananda","t":"If you are unable to fix your mind steadily on Me, then seek to reach Me through the yoga of constant practice, O Arjuna."},{"k":"adidevananda","t":"If now you are unable to focus your mind on Me, then seek to reach Me, O Arjuna, through the practice of repetition."},{"k":"gambirananda","t":"If, however, you are unable to establish the mind steadily on Me, then, O Dhananjaya, seek to attain Me through the yoga of practice."},{"k":"sankaranarayan","t":"In case you are not able to cause your mind to enter completely into Me, then, O Dhananjaya! Seek to attain Me through the practice of Yoga."}]},{"ch":12,"vn":10,"dev":"अभ्यासेऽप्यसमर्थोऽसि मत्कर्मपरमो भव।मदर्थमपि कर्माणि कुर्वन् सिद्धिमवाप्स्यसि","iast":"abhyāse 'py asamartho 'si mat-karma-paramo bhava\nmad-artham api karmāṇi kurvan siddhim avāpsyasi","v":[{"k":"purohit","t":"And if you are not strong enough to practice concentration, then devote yourself to My service, do all your acts for My sake, and you will still attain the goal."},{"k":"sivananda","t":"If you are unable to practice even this Abhyasa Yoga, be intent on doing actions for My sake; even by doing actions for My sake, you will attain perfection."},{"k":"adidevananda","t":"If you are incapable of even this practice of repetition, then devote yourself to My deeds. For even by working for My sake, you will attain perfection."},{"k":"gambirananda","t":"If you are unable even to practice, be intent on works for Me. By undertaking works for Me as well, you will attain perfection. [Identify with Brahman.]"},{"k":"sankaranarayan","t":"If you are incapable of doing a steady practice, then have Me as your chief aim in performing actions. Even by performing actions for Me, you shall attain success."}]},{"ch":12,"vn":11,"dev":"अथैतदप्यशक्तोऽसि कर्तुं मद्योगमाश्रितः।सर्वकर्मफलत्यागं ततः कुरु यतात्मवान्","iast":"athaitad apy aśhakto 'si kartuṁ mad-yogam āśhritaḥ\nsarva-karma-phala-tyāgaṁ tataḥ kuru yatātmavān","v":[{"k":"purohit","t":"And if thou art too weak to do even this, then seek refuge in union with Me, and with perfect self-control renounce the fruits of thy actions."},{"k":"sivananda","t":"If you are unable to do even this, then, resort to union with Me and renounce the fruits of all actions with self-control."},{"k":"adidevananda","t":"If you are unable to do even this—that is, take refuge in My Yoga—then, with your self-control, renounce the fruits of every action."},{"k":"gambirananda","t":"If you are unable to do even this, then resort to the Yoga for Me and afterwards, control your mind and renounce the results of all your works."},{"k":"sankaranarayan","t":"Now, if you are not capable of doing this either, then take refuge in My Yoga, renouncing the fruits of all action, with your mind subdued."}]},{"ch":12,"vn":12,"dev":"श्रेयो हि ज्ञानमभ्यासाज्ज्ञानाद्ध्यानं विशिष्यते।ध्यानात्कर्मफलत्यागस्त्यागाच्छान्तिरनन्तरम्","iast":"śhreyo hi jñānam abhyāsāj jñānād dhyānaṁ viśhiṣhyate\ndhyānāt karma-phala-tyāgas tyāgāch chhāntir anantaram","v":[{"k":"purohit","t":"Knowledge is superior to blind action, meditation is superior to knowledge, renunciation of the fruit of action is superior to meditation, and peace follows from renunciation."},{"k":"sivananda","t":"Better indeed is knowledge than practice; better than knowledge is meditation; better than meditation is the renunciation of the fruits of actions: peace immediately follows renunciation."},{"k":"adidevananda","t":"Far better is knowledge of the Self than the repeated practice (of remembrance of the Lord). Better is meditation than this knowledge; better is renunciation of the fruits of action than meditation. From such renunciation, peace ensues."},{"k":"gambirananda","t":"Knowledge is certainly superior to practice; meditation surpasses knowledge. The renunciation of the results of works surpasses meditation. From renunciation, peace follows immediately."},{"k":"sankaranarayan","t":"For, knowledge is superior to practice; due to knowledge, meditation becomes pre-eminent; from meditation arises the renunciation of the fruits of actions; and peace follows renunciation."}]},{"ch":12,"vn":13,"dev":"अद्वेष्टा सर्वभूतानां मैत्रः करुण एव च।निर्ममो निरहङ्कारः समदुःखसुखः क्षमी","iast":"adveṣhṭā sarva-bhūtānāṁ maitraḥ karuṇa eva cha\nnirmamo nirahankāraḥ sama-duḥkha-sukhaḥ kṣhamī","v":[{"k":"purohit","t":"He who is incapable of hatred towards any being, who is kind and compassionate, free from selfishness, without pride, equable in pleasure and pain, and forgiving—"},{"k":"sivananda","t":"He who hates no creature, is friendly and compassionate to all, is free from attachment and egoism, is balanced in pleasure and pain, and is forgiving."},{"k":"adidevananda","t":"He who never hates any being, who is friendly and compassionate, who is free from the feelings of \"I\" and \"mine,\" who looks upon all pain and pleasure equally, and who is enduring;"},{"k":"gambirananda","t":"He who is not hateful towards any creature, who is friendly and compassionate, who has no concept of 'mine' and no sense of egoism, who remains the same in sorrow and happiness, and who is forgiving;"},{"k":"sankaranarayan","t":"He, who is not a hater but a compassionate friend of every being; who is free from the sense of 'mine' and the sense of 'I'; who is even-minded in pain and pleasure and is endowed with forbearance;"}]},{"ch":12,"vn":14,"dev":"सन्तुष्टः सततं योगी यतात्मा दृढनिश्चयः।मय्यर्पितमनोबुद्धिर्यो मद्भक्तः स मे प्रियः","iast":"santuṣhṭaḥ satataṁ yogī yatātmā dṛiḍha-niśhchayaḥ\nmayy arpita-mano-buddhir yo mad-bhaktaḥ sa me priyaḥ","v":[{"k":"purohit","t":"Always content, self-centered, self-controlled, resolute, with mind and reason dedicated to Me, such a devotee of Mine is beloved to Me."},{"k":"sivananda","t":"Ever content, steady in meditation, self-controlled, possessing firm conviction, with the mind and intellect dedicated to Me, he, My devotee, is dear to Me."},{"k":"adidevananda","t":"He who is content, who meditates ever, is self-restrained, and is firm in his convictions, and has his mind and reason dedicated to Me—he is dear to Me."},{"k":"gambirananda","t":"He who is ever content, who is a yogi, who has self-control, who has firm conviction, and who has dedicated his mind and intellect to Me—he who is such a devotee of Mine is dear to Me."},{"k":"sankaranarayan","t":"Who remains well-content and is a practitioner of Yoga at all times; who is self-controlled and is firmly resolute; and who has offered to Me their mind and intellect-that devotee of Mine is dear to Me."}]},{"ch":12,"vn":15,"dev":"यस्मान्नोद्विजते लोको लोकान्नोद्विजते च यः।हर्षामर्षभयोद्वेगैर्मुक्तो यः स च मे प्रियः","iast":"yasmān nodvijate loko lokān nodvijate cha yaḥ\nharṣhāmarṣha-bhayodvegair mukto yaḥ sa cha me priyaḥ","v":[{"k":"purohit","t":"He who does not harm the world, and whom the world cannot harm, who is not carried away by any impulse of joy, anger, or fear; such a one is My beloved."},{"k":"sivananda","t":"He whom the world does not agitate, and who cannot be agitated by the world, and who is freed from joy, anger, fear, and anxiety—he is dear to Me."},{"k":"adidevananda","t":"He from whom the world has no cause to be frightened, who is not frightened by the world, who is free from joy and impatience, fear, and aversion - he is dear to me."},{"k":"gambirananda","t":"He, too, owing to whom the world is not disturbed, and who is not disturbed by the world, who is free from joy, impatience, fear, and anxiety, is dear to me."},{"k":"sankaranarayan","t":"He, on account of whom the world does not become agitated; who also does not become agitated on account of the world; who is free from joy and impatience, fear and anxiety—he is dear to Me."}]},{"ch":12,"vn":16,"dev":"अनपेक्षः शुचिर्दक्ष उदासीनो गतव्यथः।सर्वारम्भपरित्यागी यो मद्भक्तः स मे प्रियः","iast":"anapekṣhaḥ śhuchir dakṣha udāsīno gata-vyathaḥ\nsarvārambha-parityāgī yo mad-bhaktaḥ sa me priyaḥ","v":[{"k":"purohit","t":"He who expects nothing, is pure, watchful, indifferent, unruffled, and renounces all initiative—such a one is My beloved."},{"k":"sivananda","t":"He who is free from wants, pure, expert, unconcerned, and free from pain, renouncing all undertakings and commencements, he who is devoted to Me is dear to Me."},{"k":"adidevananda","t":"He who is free from desires, who is pure, expert, indifferent, and free from agony, who has renounced every undertaking—he is dear to me."},{"k":"gambirananda","t":"He who has no desires, who is pure, dexterous, impartial, free from fear, and who has renounced every undertaking—such a devotee of Mine is dear to Me."},{"k":"sankaranarayan","t":"He who does not expect anything, who is pure, dexterous, unconcerned, and untroubled, and who has renounced all his undertakings all around—that devotee of Mine is dear to Me."}]},{"ch":12,"vn":17,"dev":"यो न हृष्यति न द्वेष्टि न शोचति न काङ्क्षति।शुभाशुभपरित्यागी भक्ितमान्यः स मे प्रियः","iast":"yo na hṛiṣhyati na dveṣhṭi na śhochati na kāṅkṣhati\nśhubhāśhubha-parityāgī bhaktimān yaḥ sa me priyaḥ","v":[{"k":"purohit","t":"He who is beyond joy and hate, who neither laments nor desires, to whom good and evil fortunes are the same, such a one is beloved to Me."},{"k":"sivananda","t":"He who neither rejoices nor hates, nor grieves nor desires, renouncing both good and evil, and who is full of devotion, is dear to Me."},{"k":"adidevananda","t":"He who does not rejoice, nor hate, nor grieve, nor desire, who renounces both good and evil, and who is full of devotion to Me—such a devotee is dear to Me."},{"k":"gambirananda","t":"He who does not rejoice, nor fret, nor lament, nor hanker; who gives up both good and bad, and is filled with devotion—he is dear to Me."},{"k":"sankaranarayan","t":"He who neither delights nor hates, nor grieves nor craves; who has renounced both the good and the bad results [of actions] and is full of devotion [to Me]—he is dear to Me."}]},{"ch":12,"vn":18,"dev":"समः शत्रौ च मित्रे च तथा मानापमानयोः।शीतोष्णसुखदुःखेषु समः सङ्गविवर्जितः","iast":"samaḥ śhatrau cha mitre cha tathā mānāpamānayoḥ\nśhītoṣhṇa-sukha-duḥkheṣhu samaḥ saṅga-vivarjitaḥ","v":[{"k":"purohit","t":"He to whom friend and foe are alike, who welcomes equally honor and dishonor, heat and cold, pleasure and pain, and who is enamored of nothing—"},{"k":"sivananda","t":"He who is the same to foe and friend, and also in honor and dishonor, who is the same in cold and heat, in pleasure and pain, and who is free from attachment."},{"k":"adidevananda","t":"He who is the same to foe and friend, honor and dishonor, who is alike to both cold and heat, pleasure and pain, and who is free from all attachments;"},{"k":"gambirananda","t":"He who is the same towards friend and foe, and in honor and dishonor; who is the same under cold, heat, happiness, and sorrow; who is free from attachment to all."},{"k":"sankaranarayan","t":"He who feels alike to the foe and the friend, to honor and dishonor, to cold and heat, to pleasure and pain; who is totally free from attachment;"}]},{"ch":12,"vn":19,"dev":"तुल्यनिन्दास्तुतिर्मौनी सन्तुष्टो येनकेनचित्।अनिकेतः स्थिरमतिर्भक्ितमान्मे प्रियो नरः","iast":"tulya-nindā-stutir maunī santuṣhṭo yena kenachit\naniketaḥ sthira-matir bhaktimān me priyo naraḥ","v":[{"k":"purohit","t":"Who is indifferent to praise and censure, enjoys silence, is content with every fate, has no fixed abode, is steadfast in mind, and filled with devotion—such a one is My beloved."},{"k":"sivananda","t":"He to whom censure and praise are equal, who is silent, content with anything, homeless, of a steady mind, and full of devotion; that man is dear to me."},{"k":"adidevananda","t":"He who regards both blame and praise alike, who is silent and content with any lot, who has no home, who is firm of mind, and who is devoted to Me - such a man is dear to Me."},{"k":"gambirananda","t":"The person to whom denunciation and praise are the same, who is silent, content with anything, homeless, steadfast-minded, and full of devotion is dear to me."},{"k":"sankaranarayan","t":"To whom blame and praise are equal; who is silent (does not over-speak) and is content with whatever comes to him; who has no fixed thoughts in the mundane life; who is yet steady-minded in spiritual practice and is full of devotion—that man is dear to Me."}]},{"ch":12,"vn":20,"dev":"ये तु धर्म्यामृतमिदं यथोक्तं पर्युपासते।श्रद्दधाना मत्परमा भक्तास्तेऽतीव मे प्रियाः","iast":"ye tu dharmyāmṛitam idaṁ yathoktaṁ paryupāsate\nśhraddadhānā mat-paramā bhaktās te 'tīva me priyāḥ","v":[{"k":"purohit","t":"Verily, those who love the spiritual wisdom as I have taught, whose faith never wavers, and who focus their entire being on Me, they are indeed My most beloved."},{"k":"sivananda","t":"They who follow this immortal Dharma, endowed with faith and regarding Me as their supreme goal, are exceedingly dear to Me."},{"k":"adidevananda","t":"But those devotees who follow this nectar of virtuous duty, as taught above, who are full of faith and regard Me as the Supreme, are exceedingly dear to Me."},{"k":"gambirananda","t":"But those devotees who accept Me as the supreme Goal, and with faith seek for this ambrosia—nectar in the form of virtue—which is indistinguishable from the virtues as stated above, they are very dear to Me."},{"k":"sankaranarayan","t":"Those who, as instructed above, resort to this duty that leads to immortality, who have faith in it and have Me as their only goal—those devotees are exceedingly dear to Me."}]},{"ch":13,"vn":1,"dev":"अर्जुन उवाच\nप्रकृतिं पुरुषं चैव क्षेत्रं क्षेत्रज्ञमेव च।\nएतद्वेदितुमिच्छामि ज्ञानं ज्ञेयं च केशव","iast":"arjuna uvācha\nprakṛitiṁ puruṣhaṁ chaiva kṣhetraṁ kṣhetra-jñam eva cha\netad veditum ichchhāmi jñānaṁ jñeyaṁ cha keśhava","v":[{"k":"purohit","t":"Arjuna asked, \"My Lord, who is God, what is Nature, what is Matter, and what is the Self? What is Wisdom, and what is worth knowing? I wish to have this explained.\""},{"k":"sivananda","t":"Arjuna said, \"I wish to learn about Nature and the Spirit, the field and the knower of the field, knowledge and that which ought to be known, O Kesava.\""},{"k":"adidevananda","t":"This is not a sentence, so there is nothing to fix."},{"k":"gambirananda","t":"Swami Gambhirananda has not translated this verse. Many editions of the Bhagavad Gita do not contain this verse, including the commentary by Shankaracharya. If this verse is included, the total number of verses in the Bhagavad Gita is 701."},{"k":"sankaranarayan","t":"No translation of this sloka is available."}]},{"ch":13,"vn":2,"dev":"श्री भगवानुवाचइदं शरीरं कौन्तेय क्षेत्रमित्यभिधीयते।एतद्यो वेत्ति तं प्राहुः क्षेत्रज्ञ इति तद्विदः","iast":"śhrī-bhagavān uvācha\nidaṁ śharīraṁ kaunteya kṣhetram ity abhidhīyate\netad yo vetti taṁ prāhuḥ kṣhetra-jña iti tad-vidaḥ","v":[{"k":"purohit","t":"Lord Shri Krishna replied: O Arjuna! The body of a person is the playground of the Self; and That which knows the activities of Matter, sages call the Self."},{"k":"sivananda","t":"The Blessed Lord said, \"O Arjuna, this body is called the field; he who knows it is called the knower of the field by those who know them.\""},{"k":"adidevananda","t":"The Lord said, \"O Arjuna, this body is called the Field, Ksetra. Those who know the self call the one who knows it the Field-knower, Ksetrajna.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"O son of Kunti, this body is referred to as the 'field'. Those who are versed in this call him who is conscious of it the 'knower of the field'.\""},{"k":"sankaranarayan","t":"The Bhagavat said, \"O son of Kunti! This physical body is called the 'field' (decayer-cum-protector); He who sensitizes it—His knowers call Him properly the 'Field-sensitizer'."}]},{"ch":13,"vn":3,"dev":"क्षेत्रज्ञं चापि मां विद्धि सर्वक्षेत्रेषु भारत।\nक्षेत्रक्षेत्रज्ञयोर्ज्ञानं यत्तज्ज्ञानं मतं मम","iast":"kṣhetra-jñaṁ chāpi māṁ viddhi sarva-kṣhetreṣhu bhārata\nkṣhetra-kṣhetrajñayor jñānaṁ yat taj jñānaṁ mataṁ mama","v":[{"k":"purohit","t":"I am the omniscient Self that abides in the realm of matter; knowledge of matter and of the all-knowing Self is wisdom."},{"k":"sivananda","t":"Do thou also know Me as the knower of the field in all fields, O Arjuna. Knowledge of both the field and the knower of the field is considered by Me to be the knowledge."},{"k":"adidevananda","t":"And know Me also as the Knower of all Fields, O Arjuna. In My view, the knowledge of the Field and its Knower is the true knowledge."},{"k":"gambirananda","t":"And, O scion of the Bharata dynasty, understand Me to be the 'Knower of the field' in all the fields. In My opinion, that is Knowledge which is the knowledge of the field and the knower of the field."},{"k":"sankaranarayan","t":"O descendant of Bharata! You should know Me to be the one who sensitizes the fields of all. The knowledge of the field and the one who sensitizes it—that knowledge is, in fact, the understanding of Me."}]},{"ch":13,"vn":4,"dev":"तत्क्षेत्रं यच्च यादृक् च यद्विकारि यतश्च यत्।स च यो यत्प्रभावश्च तत्समासेन मे श्रृणु","iast":"tat kṣhetraṁ yach cha yādṛik cha yad-vikāri yataśh cha yat\nsa cha yo yat-prabhāvaśh cha tat samāsena me śhṛiṇu","v":[{"k":"purohit","t":"What is called Matter, of what it is composed, whence it came, and why it changes, what the Self is, and what its power - this I will now briefly set forth."},{"k":"sivananda","t":"Hear from Me in brief what the field is, of what nature it is, what its modifications are, whence it is, who He is, and what His powers are."},{"k":"adidevananda","t":"Listen briefly from Me what the Field is, what it is like, what its modifications are, what purpose it serves, and what it is; as well as who the Self is and what its powers are."},{"k":"gambirananda","t":"Hear from Me in brief about all that, what that field is and how it is; what its changes are, and what causes what effect; and who He is, and what His powers are."},{"k":"sankaranarayan","t":"What is that Field and what is its nature? Why does it undergo modifications, where does it come from, and what is its purpose? Who is the Field-sensitizer and what is His nature? Listen to all this from Me collectively."}]},{"ch":13,"vn":5,"dev":"ऋषिभिर्बहुधा गीतं छन्दोभिर्विविधैः पृथक्।ब्रह्मसूत्रपदैश्चैव हेतुमद्भिर्विनिश्िचतैः","iast":"ṛiṣhibhir bahudhā gītaṁ chhandobhir vividhaiḥ pṛithak\nbrahma-sūtra-padaiśh chaiva hetumadbhir viniśhchitaiḥ","v":[{"k":"purohit","t":"Seers have sung of it in various ways, in many hymns and sacred Vedic songs, weighty in thought and convincing in their arguments."},{"k":"sivananda","t":"Sages have sung in many ways, with various distinctive chants and also with suggestive words indicative of the Absolute, full of reasoning and decisive."},{"k":"adidevananda","t":"It has been sung by seers in various ways, in various distinctive hymns, and also in the well-reasoned and conclusive words of the Brahma-sutras."},{"k":"gambirananda","t":"It has been sung of in various ways by the Rsis, separately by the different branches of Vedic texts, and also by the rational and convincing sentences themselves which are indicative of and lead to Brahman."},{"k":"sankaranarayan","t":"This has been sung many times by sages, and also has been clearly decided in the various Vedas in different contexts by means of their words that are suggestive of the Brahman (i.e. in the Upanishads) and are full of reasoning."}]},{"ch":13,"vn":6,"dev":"महाभूतान्यहङ्कारो बुद्धिरव्यक्तमेव च।इन्द्रियाणि दशैकं च पञ्च चेन्द्रियगोचराः","iast":"mahā-bhūtāny ahankāro buddhir avyaktam eva cha\nindriyāṇi daśhaikaṁ cha pañcha chendriya-gocharāḥ","v":[{"k":"purohit","t":"The five great fundamentals—earth, fire, air, water, and ether—personality, intellect, the mysterious life force, the ten organs of perception and action, the mind, and the five domains of sensation—"},{"k":"sivananda","t":"The great elements, egoism, intellect, and also the Unmanifested Nature, the ten senses, and one mind, and the five objects of the senses."},{"k":"adidevananda","t":"The great elements, the Ahankara, the Buddhi, the Avyakta, the ten senses, and the one, in addition, the five objects of the senses;"},{"k":"gambirananda","t":"The great elements, egoism, intellect, and the Unmanifest itself; the ten organs and the one, and the five objects of the senses;"},{"k":"sankaranarayan","t":"The five great elements, egotism, the intellect, the unmanifest, and the ten organs and the five objects of the senses."}]},{"ch":13,"vn":7,"dev":"इच्छा द्वेषः सुखं दुःखं सङ्घातश्चेतनाधृतिः।एतत्क्षेत्रं समासेन सविकारमुदाहृतम्","iast":"ichchhā dveṣhaḥ sukhaṁ duḥkhaṁ saṅghātaśh chetanā dhṛitiḥ\netat kṣhetraṁ samāsena sa-vikāram udāhṛitam","v":[{"k":"purohit","t":"Desire, aversion, pleasure, pain, sympathy, vitality, and the persistent clinging to life—these are, in brief, the constituents of changing matter."},{"k":"sivananda","t":"Desire, hatred, pleasure, pain, the aggregate (body), intelligence, and fortitude—the field has thus been briefly described with its modifications."},{"k":"adidevananda","t":"Desire, hatred, pleasure, and pain, and the combination that constitutes the basis of consciousness—or the individual self—have been briefly described here, along with their modifications."},{"k":"gambirananda","t":"Desire, repulsion, happiness, sorrow, the aggregate (of body and organs), sentience, fortitude—this field, together with its modifications, has been spoken of briefly."},{"k":"sankaranarayan","t":"The desire, the hatred, the pleasure, the pain, the aggregate, the sensibility, and the feeling of satisfaction (or self-find): This, together with its modifications, is collectively called 'the Field'."}]},{"ch":13,"vn":8,"dev":"अमानित्वमदम्भित्वमहिंसा क्षान्तिरार्जवम्।आचार्योपासनं शौचं स्थैर्यमात्मविनिग्रहः","iast":"amānitvam adambhitvam ahinsā kṣhāntir ārjavam\nāchāryopāsanaṁ śhauchaṁ sthairyam ātma-vinigrahaḥ","v":[{"k":"purohit","t":"Humility, sincerity, harmlessness, forgiveness, rectitude, service to the Master, purity, steadfastness, and self-control;"},{"k":"sivananda","t":"Humility, unpretentiousness, non-injury, forgiveness, uprightness, service to the teacher, purity, steadfastness, and self-control."},{"k":"adidevananda","t":"Modesty, absence of ostentation, non-injury, patience, sincerity, service to the preceptor, purity, firmness, and self-restraint;"},{"k":"gambirananda","t":"Humility, unpretentiousness, non-injury, forbearance, sincerity, service to the teacher, cleanliness, steadiness, and control of the body and its organs;"},{"k":"sankaranarayan","t":"Absence of pride, absence of hypocrisy, harmlessness, patience, uprightness, service to the preceptor, purity of mind and body, steadfastness, and self-control."}]},{"ch":13,"vn":9,"dev":"इन्द्रियार्थेषु वैराग्यमनहङ्कार एव च।जन्ममृत्युजराव्याधिदुःखदोषानुदर्शनम्","iast":"indriyārtheṣhu vairāgyam anahankāra eva cha\njanma-mṛityu-jarā-vyādhi-duḥkha-doṣhānudarśhanam","v":[{"k":"purohit","t":"Renouncing the delights of the senses, being without pride, having a right understanding of the painful problem of birth and death, and of age and sickness;"},{"k":"sivananda","t":"Indifference to the objects of the senses and also absence of egoism; perceiving the evil in birth, death, old age, sickness, and pain."},{"k":"adidevananda","t":"Absence of desire for sense-objects, and also absence of egotism, the recognition of evil in birth, death, old age, disease, and sorrow;"},{"k":"gambirananda","t":"Non-attachment to objects of the senses, and also the absence of egotism; seeing the evil in birth, death, aging, diseases, and miseries;"},{"k":"sankaranarayan","t":"Absence of desire for sense-objects, and also absence of egotism; pondering over the evils of birth, death, old age, sickness, and sorrow;"}]},{"ch":13,"vn":10,"dev":"असक्ितरनभिष्वङ्गः पुत्रदारगृहादिषु।नित्यं च समचित्तत्वमिष्टानिष्टोपपत्तिषु","iast":"asaktir anabhiṣhvaṅgaḥ putra-dāra-gṛihādiṣhu\nnityaṁ cha sama-chittatvam iṣhṭāniṣhṭopapattiṣhu","v":[{"k":"purohit","t":"Indifference, non-attachment to sex, progeny, or home, equanimity in both good fortune and bad;"},{"k":"sivananda","t":"Non-attachment, non-identification of the Self with son, wife, home, and the rest, and constant even-mindedness in the face of the attainment of both desirable and undesirable."},{"k":"adidevananda","t":"Non-attachment, absence of clinging to son, wife, home, and the like, and constant even-mindedness in regard to all desirable and undesirable events;"},{"k":"gambirananda","t":"Non-attachment and absence of fondness with regard to sons, wives, homes, etc., and constant equanimity of the mind with regard to the attainment of both the desirable and the undesirable;"},{"k":"sankaranarayan","t":"Non-attachment, detachment towards one's children, wives, houses, and the like; and a constant even-mindedness in the occurrence of desirable and undesirable things."}]},{"ch":13,"vn":11,"dev":"मयि चानन्ययोगेन भक्ितरव्यभिचारिणी।विविक्तदेशसेवित्वमरतिर्जनसंसदि","iast":"mayi chānanya-yogena bhaktir avyabhichāriṇī\nvivikta-deśha-sevitvam aratir jana-sansadi","v":[{"k":"purohit","t":"Unswerving devotion to Me, with concentration on Me and Me alone, a love for solitude, and indifference to social life;"},{"k":"sivananda","t":"Unswerving devotion to Me through the Yoga of non-separation, resorting to solitary places, and a distaste for the company of people."},{"k":"adidevananda","t":"Constantly devote yourself to Me alone, resort to solitary places, and dislike crowds."},{"k":"gambirananda","t":"And unwavering devotion to Me with single-minded concentration; inclination to retreat to a clean place; lack of delight in a crowd of people;"},{"k":"sankaranarayan","t":"And an unwavering devotion to Me, with the Yoga of non-duality; taking refuge in a solitary place; disinterest in a crowd of people;"}]},{"ch":13,"vn":12,"dev":"अध्यात्मज्ञाननित्यत्वं तत्त्वज्ञानार्थदर्शनम्।एतज्ज्ञानमिति प्रोक्तमज्ञानं यदतोन्यथा","iast":"adhyātma-jñāna-nityatvaṁ tattva-jñānārtha-darśhanam\netaj jñānam iti proktam ajñānaṁ yad ato 'nyathā","v":[{"k":"purohit","t":"Constant yearning for the knowledge of the Self, and pondering over the lessons of the great Truth—this is wisdom; all else is ignorance."},{"k":"sivananda","t":"Constancy in Self-knowledge, the perception of the end of true knowledge—this is declared to be knowledge, and what is opposed to it is ignorance."},{"k":"adidevananda","t":"Constant contemplation on the knowledge pertaining to the self, reflection for the attainment of knowledge of the truth—this is declared to be knowledge, and what is contrary to it is ignorance."},{"k":"gambirananda","t":"Steadfastness in the knowledge of the Self, contemplation on the Goal of the knowledge of Reality—this is spoken of as Knowledge. Ignorance is that which is other than this."},{"k":"sankaranarayan","t":"Constancy in Self-knowledge, and viewing things with the aim of knowing the Reality—all this is declared to be conducive to true knowledge, and what is opposed to this is conducive to wrong knowledge."}]},{"ch":13,"vn":13,"dev":"ज्ञेयं यत्तत्प्रवक्ष्यामि यज्ज्ञात्वाऽमृतमश्नुते।अनादिमत्परं ब्रह्म न सत्तन्नासदुच्यते","iast":"jñeyaṁ yat tat pravakṣhyāmi yaj jñātvāmṛitam aśhnute\nanādi mat-paraṁ brahma na sat tan nāsad uchyate","v":[{"k":"purohit","t":"I will now speak to you of that great truth which one ought to know, since by it one will attain immortal bliss—that which is without beginning, the eternal spirit which dwells in me, neither with form nor without it."},{"k":"sivananda","t":"I will declare that which is to be known, knowing which one attains immortality; the beginningless Supreme Brahman, which is neither being nor non-being."},{"k":"adidevananda","t":"I shall declare that which is to be known, knowing which one attains the immortal Self. It is beginningless Brahman, having Me as the Highest (Anadi Matparam); it is said to be neither being nor non-being."},{"k":"gambirananda","t":"I shall speak of that which is to be known, by realizing which one attains immortality. The supreme Brahman is without any beginning; that is called neither being nor non-being."},{"k":"sankaranarayan","t":"I shall describe that which is to be known, by knowing which one attains freedom from death: the Supreme Brahman is beginningless and is said to be neither existent nor non-existent."}]},{"ch":13,"vn":14,"dev":"सर्वतः पाणिपादं तत्सर्वतोऽक्षिशिरोमुखम्।सर्वतः श्रुतिमल्लोके सर्वमावृत्य तिष्ठति","iast":"sarvataḥ pāṇi-pādaṁ tat sarvato 'kṣhi-śhiro-mukham\nsarvataḥ śhrutimal loke sarvam āvṛitya tiṣhṭhati","v":[{"k":"purohit","t":"Everywhere are Its hands and feet; everywhere It has eyes that see, heads that think, and mouths that speak; everywhere It listens; It dwells in all the worlds and envelops them all."},{"k":"sivananda","t":"With hands and feet everywhere, with eyes, heads, and mouths everywhere, with ears everywhere, He exists in the worlds, enveloping all."},{"k":"adidevananda","t":"Its hands and feet are everywhere; Its eyes, heads, and mouths are everywhere; Its ears are on all sides; and It exists, encompassing all things."},{"k":"gambirananda","t":"That Knowable, which has hands and feet everywhere, which has eyes, heads, and mouths everywhere, which has ears everywhere, exists in creatures by pervading them all."},{"k":"sankaranarayan","t":"It has hands and feet of all, has eyes, heads, and faces of all, has ears of all in the world; It envelops all."}]},{"ch":13,"vn":15,"dev":"सर्वेन्द्रियगुणाभासं सर्वेन्द्रियविवर्जितम्।असक्तं सर्वभृच्चैव निर्गुणं गुणभोक्तृ च","iast":"sarvendriya-guṇābhāsaṁ sarvendriya-vivarjitam\nasaktaṁ sarva-bhṛich chaiva nirguṇaṁ guṇa-bhoktṛi cha","v":[{"k":"purohit","t":"Beyond the senses, it yet shines through every sense perception; bound to nothing, it yet sustains everything; unaffected by the qualities, it still enjoys them all."},{"k":"sivananda","t":"Shining by the functions of all the senses, yet without being attached to them; unattached, yet supporting all; devoid of qualities, yet the experiencer of them."},{"k":"adidevananda","t":"Shining by the functions of the senses, yet devoid of the senses, detached yet supporting all, devoid of the Gunas yet experiencing the Gunas;"},{"k":"gambirananda","t":"Shining through the functions of all the organs, yet devoid of all the organs; unattached, and verily the supporter of all; without quality, and the perceiver of qualities."},{"k":"sankaranarayan","t":"It illuminates all the senses; yet it has no sense organs; it is unattached, yet supports all; it is free from the bonds, yet enjoys the bonds."}]},{"ch":13,"vn":16,"dev":"बहिरन्तश्च भूतानामचरं चरमेव च।सूक्ष्मत्वात्तदविज्ञेयं दूरस्थं चान्तिके च तत्","iast":"bahir antaśh cha bhūtānām acharaṁ charam eva cha\nsūkṣhmatvāt tad avijñeyaṁ dūra-sthaṁ chāntike cha tat","v":[{"k":"purohit","t":"It is within all beings, yet outside; motionless yet moving; too subtle to be perceived; far away yet ever near."},{"k":"sivananda","t":"It is within and without all beings, both the unmoving and the moving; It is subtle and unknowable, and It is near and far away."},{"k":"adidevananda","t":"It is within and without all beings; It is unmoving yet moving; It is so subtle that none can comprehend it; It is far away yet very near."},{"k":"gambirananda","t":"Existing both outside and inside all beings, moving and non-moving, It is incomprehensible due to Its subtlety. It is far away, yet near."},{"k":"sankaranarayan","t":"It is without and within every being, unmoving yet moving; due to its subtle nature, it is incomprehensible; it exists far away yet is near."}]},{"ch":13,"vn":17,"dev":"अविभक्तं च भूतेषु विभक्तमिव च स्थितम्।भूतभर्तृ च तज्ज्ञेयं ग्रसिष्णु प्रभविष्णु च","iast":"avibhaktaṁ cha bhūteṣhu vibhaktam iva cha sthitam\nbhūta-bhartṛi cha taj jñeyaṁ grasiṣhṇu prabhaviṣhṇu cha","v":[{"k":"purohit","t":"In all beings, undivided yet living in division, it is the upholder of all, both creator and destroyer alike."},{"k":"sivananda","t":"Undivided yet, It exists as if divided in beings; It is to be known as the supporter of beings; It devours and It generates."},{"k":"adidevananda","t":"Undivided yet appearing as if divided among beings, this Self is to be known as the supporter of the elements. It devours them and causes their generation."},{"k":"gambirananda","t":"The Knowable, though undivided, appears to exist as divided in all beings, and It is the sustainer, devourer, and originator of all beings."},{"k":"sankaranarayan","t":"It remains undistinguished among the distinguished beings, and appears as if distinguished. It is to be known as the supporter of beings, and also as their swallower and originator."}]},{"ch":13,"vn":18,"dev":"ज्योतिषामपि तज्ज्योतिस्तमसः परमुच्यते।ज्ञानं ज्ञेयं ज्ञानगम्यं हृदि सर्वस्य विष्ठितम्","iast":"jyotiṣhām api taj jyotis tamasaḥ param uchyate\njñānaṁ jñeyaṁ jñāna-gamyaṁ hṛidi sarvasya viṣhṭhitam","v":[{"k":"purohit","t":"It is the light of lights, beyond the reach of darkness; the wisdom, the only thing worth knowing or that wisdom can teach; the presence in the hearts of all."},{"k":"sivananda","t":"That Light of all lights is said to be beyond darkness: knowledge, the knowable, and the goal of knowledge, seated in the hearts of all."},{"k":"adidevananda","t":"The light of all lights is said to be beyond Tamas (darkness); it is known to be knowledge, to be attained through knowledge, and to be present in the hearts of all."},{"k":"gambirananda","t":"That is the Light of all lights; It is spoken of as beyond darkness. It is Knowledge, the Knowable, and the Known. It is specially situated in the hearts of all."},{"k":"sankaranarayan","t":"This is the Light of all lights, stated to be beyond darkness; it is to be known by the above knowledge; it is to be attained only through knowledge; and it distinctly remains in the heart of all."}]},{"ch":13,"vn":19,"dev":"इति क्षेत्रं तथा ज्ञानं ज्ञेयं चोक्तं समासतः।मद्भक्त एतद्विज्ञाय मद्भावायोपपद्यते","iast":"iti kṣhetraṁ tathā jñānaṁ jñeyaṁ choktaṁ samāsataḥ\nmad-bhakta etad vijñāya mad-bhāvāyopapadyate","v":[{"k":"purohit","t":"Thus, I have briefly told you what Matter is, the Self worth realizing, and what Wisdom is. He who is devoted to Me knows, and he will assuredly enter into Me."},{"k":"sivananda","t":"Thus, the field, as well as knowledge and the knowable, have been briefly stated. My devotee, knowing this, enters into My being."},{"k":"adidevananda","t":"Thus, the Ksetra, knowledge, and the object of knowledge have been briefly set forth. On knowing this, My devotee becomes fit to attain My state."},{"k":"gambirananda","t":"Thus, in brief, the field, Knowledge, and the Knowable have been spoken of. By understanding this, My devotee becomes qualified for My state."},{"k":"sankaranarayan","t":"This field, as well as the knowledge and what is to be known, are all mentioned collectively; clearly understanding this, My devotee becomes worthy of My state."}]},{"ch":13,"vn":20,"dev":"प्रकृतिं पुरुषं चैव विद्ध्यनादी उभावपि।विकारांश्च गुणांश्चैव विद्धि प्रकृतिसंभवान्","iast":"prakṛitiṁ puruṣhaṁ chaiva viddhy anādī ubhāv api\nvikārānśh cha guṇānśh chaiva viddhi prakṛiti-sambhavān","v":[{"k":"purohit","t":"Know further that Nature and God have no beginning, and that differences in character and quality originate from Nature only."},{"k":"sivananda","t":"Know that Nature (matter) and the Spirit are both beginningless, and know also that all modifications and qualities are born from Nature."},{"k":"adidevananda","t":"Know that both Prakṛti and the Self (Puruṣa) are without beginning; know that all modifications and the attributes are born from Prakṛti."},{"k":"gambirananda","t":"Know both Nature and the individual soul to be verily without beginning; know the modifications as well as the qualities to be born of Nature."},{"k":"sankaranarayan","t":"Both the Material Cause and the Soul are beginningless; you should know this. You should also know that the modifications and strands are born from the Material Cause."}]},{"ch":13,"vn":21,"dev":"कार्यकारणकर्तृत्वे हेतुः प्रकृतिरुच्यते।पुरुषः सुखदुःखानां भोक्तृत्वे हेतुरुच्यते","iast":"kārya-kāraṇa-kartṛitve hetuḥ prakṛitir uchyate\npuruṣhaḥ sukha-duḥkhānāṁ bhoktṛitve hetur uchyate","v":[{"k":"purohit","t":"Nature is the law that generates cause and effect; God is the source of all pleasure and pain."},{"k":"sivananda","t":"In the production of the effect and the cause, Nature (matter) is said to be the cause; in the experience of pleasure and pain, the soul is said to be the one responsible."},{"k":"adidevananda","t":"The Prakṛti is said to be the cause of agency to the body (Kārya) and sense-organs (Karaṇa); the Self is said to be the cause of experiencing pleasure and pain."},{"k":"gambirananda","t":"With regard to the source of the body and its organs, Nature is said to be the cause; the soul is the cause so far as the enjoyment of happiness and sorrow is concerned."},{"k":"sankaranarayan","t":"In creating the process of cause and effect, the material cause is said to be the basis; and in experiencing pleasure and pain, the soul is said to be the basis."}]},{"ch":13,"vn":22,"dev":"पुरुषः प्रकृतिस्थो हि भुङ्क्ते प्रकृतिजान्गुणान्।कारणं गुणसङ्गोऽस्य सदसद्योनिजन्मसु","iast":"puruṣhaḥ prakṛiti-stho hi bhuṅkte prakṛiti-jān guṇān\nkāraṇaṁ guṇa-saṅgo 'sya sad-asad-yoni-janmasu","v":[{"k":"purohit","t":"God, dwelling in the heart of Nature, experiences the qualities that Nature brings forth; and His affinity towards these qualities is the reason for His living in a good or evil body."},{"k":"sivananda","t":"The soul seated in Nature experiences the qualities born of Nature; attachment to the qualities is the cause of its birth in good and evil wombs."},{"k":"adidevananda","t":"(a) Indeed, the self seated in Prakrti experiences the Gunas born of Prakrti.\n(b) Its attachment to these Gunas is the cause of birth in good and evil wombs."},{"k":"gambirananda","t":"Since the soul is seated in Nature, therefore it experiences the qualities born of Nature. Contact with the qualities is the cause of its births in good and evil wombs."},{"k":"sankaranarayan","t":"For, the soul, seated on the material cause, enjoys the strands born of the material cause; His attachment to the strands is the cause of his births in good and evil wombs."}]},{"ch":13,"vn":23,"dev":"उपद्रष्टाऽनुमन्ता च भर्ता भोक्ता महेश्वरः।परमात्मेति चाप्युक्तो देहेऽस्मिन्पुरुषः परः","iast":"upadraṣhṭānumantā cha bhartā bhoktā maheśhvaraḥ\nparamātmeti chāpy ukto dehe 'smin puruṣhaḥ paraḥ","v":[{"k":"purohit","t":"Thus, in the body of man dwells the Supreme God; He who sees, permits, upholds, and enjoys is the Highest God and the Highest Self."},{"k":"sivananda","t":"The Supreme Soul in this body is also called the observer, the permitter, the sustainer, the enjoyer, the great Lord, and the Supreme Self."},{"k":"adidevananda","t":"The self in the body is called the spectator, approver, supporter, experiencer, great lord, and supreme self."},{"k":"gambirananda","t":"He who is the Witness, the Permitter, the Sustainer, the Experiencer, the great Lord, and who is also spoken of as the transcendental Self, is the supreme Person in this body."},{"k":"sankaranarayan","t":"The Supreme Soul in this corporeal body is called the Spectator, the Assenter, the Supporter, the Experiencer, the Mighty Lord, and also the Supreme Self."}]},{"ch":13,"vn":24,"dev":"य एवं वेत्ति पुरुषं प्रकृतिं च गुणैःसह।सर्वथा वर्तमानोऽपि न स भूयोऽभिजायते","iast":"ya evaṁ vetti puruṣhaṁ prakṛitiṁ cha guṇaiḥ saha\nsarvathā vartamāno 'pi na sa bhūyo 'bhijāyate","v":[{"k":"purohit","t":"He who understands God and Nature, along with her qualities, whatever his condition in life may be, will not come back to earth."},{"k":"sivananda","t":"He who thus knows the Spirit and Matter together with their qualities, in whatever condition he may be, he is not reborn."},{"k":"adidevananda","t":"He who understands the Self and Prakriti, along with the Gunas, will not be born again, no matter what state he may be in."},{"k":"gambirananda","t":"He who knows thus the Person, Nature, and Qualities will not be born again, no matter how he may live."},{"k":"sankaranarayan","t":"He who knows, in this manner, the Soul and the Material Cause together with their strands—he is not reborn, even though he may act in various ways."}]},{"ch":13,"vn":25,"dev":"ध्यानेनात्मनि पश्यन्ति केचिदात्मानमात्मना।अन्ये सांख्येन योगेन कर्मयोगेन चापरे","iast":"dhyānenātmani paśhyanti kechid ātmānam ātmanā\nanye sānkhyena yogena karma-yogena chāpare","v":[{"k":"purohit","t":"Some realize the Supreme by meditating, with its aid, on the Self within; others by pure reason; and still others by right action."},{"k":"sivananda","t":"Some behold the Self within themselves through meditation, others through the Yoga of knowledge, and still others through the Yoga of action."},{"k":"adidevananda","t":"Some perceive the Self within the self (body) through meditation of the mind, others through Sankhya Yoga, and still others through Karma Yoga."},{"k":"gambirananda","t":"Some realize the Self in their intellect through meditation, others through Sankhya-Yoga, and still others through Karma-Yoga, with the help of the internal organ."},{"k":"sankaranarayan","t":"However, some yogis perceive the Self as the Self within the self through meditation, others through knowledge-yoga, and still others through action-yoga."}]},{"ch":13,"vn":26,"dev":"अन्ये त्वेवमजानन्तः श्रुत्वाऽन्येभ्य उपासते।तेऽपि चातितरन्त्येव मृत्युं श्रुतिपरायणाः","iast":"anye tv evam ajānantaḥ śhrutvānyebhya upāsate\nte 'pi chātitaranty eva mṛityuṁ śhruti-parāyaṇāḥ","v":[{"k":"purohit","t":"Others, again, having no direct knowledge but only hearing from others, still worship, and, if they are true to the teachings, they too will cross the sea of death."},{"k":"sivananda","t":"Others, too, who do not know thus, worship, having heard of It from others; they, too, cross beyond death, regarding what they have heard as the supreme refuge."},{"k":"adidevananda","t":"But some, who do not know this, having heard from others, worship accordingly—these too, devoted to what they hear, pass beyond death."},{"k":"gambirananda","t":"Others, again, who do not know thus, take to thinking after hearing from others; they too, who are devoted to hearing, certainly overcome death."},{"k":"sankaranarayan","t":"But others, who have no knowledge of this nature, listen from others and reflect [accordingly]; they too, being devoted to what they have heard, do cross over death."}]},{"ch":13,"vn":27,"dev":"यावत्सञ्जायते किञ्चित्सत्त्वं स्थावरजङ्गमम्।क्षेत्रक्षेत्रज्ञसंयोगात्तद्विद्धि भरतर्षभ","iast":"yāvat sañjāyate kiñchit sattvaṁ sthāvara-jaṅgamam\nkṣhetra-kṣhetrajña-sanyogāt tad viddhi bharatarṣhabha","v":[{"k":"purohit","t":"Wherever life is seen in things movable or immovable, it is the result of the combination of Matter and Spirit."},{"k":"sivananda","t":"Wherever a being is born, whether unmoving or moving, know thou, O best of the Bharatas (Arjuna), that it is from the union of the field and its knower."},{"k":"adidevananda","t":"Whatever being is born, whether it be moving or stationary, know, O Arjuna, that it is through the combination of the Ksetra (body) and Ksetrajna (knower of the Field)."},{"k":"gambirananda","t":"O scion of the Bharata dynasty, whatever object, moving or non-moving, comes into existence, know that to be from the combination of the field and the Knower of the field!"},{"k":"sankaranarayan","t":"Whatever living being is born, stationary or moving, you should know that all this has a close connection with the Field and the Field-sensitizer, O best of the Bharatas!"}]},{"ch":13,"vn":28,"dev":"समं सर्वेषु भूतेषु तिष्ठन्तं परमेश्वरम्।विनश्यत्स्वविनश्यन्तं यः पश्यति स पश्यति","iast":"samaṁ sarveṣhu bhūteṣhu tiṣhṭhantaṁ parameśhvaram\nvinaśhyatsv avinaśhyantaṁ yaḥ paśhyati sa paśhyati","v":[{"k":"purohit","t":"He who can see the Supreme Lord in all beings, the Imperishable amidst the perishable, he is the one who truly sees."},{"k":"sivananda","t":"He who sees the Supreme Lord existing truly in all beings, the imperishable within the perishable, sees indeed."},{"k":"adidevananda","t":"Who sees the supreme ruler dwelling alike in all bodies and never perishing, even when they perish, he indeed sees."},{"k":"gambirananda","t":"He who sees the Supreme Lord existing truly in all beings, and the Imperishable among the perishable, sees indeed."},{"k":"sankaranarayan","t":"Whoever perceives the Supreme Lord as abiding and non-perishing in all beings, even as they perish, perceives properly."}]},{"ch":13,"vn":29,"dev":"समं पश्यन्हि सर्वत्र समवस्थितमीश्वरम्।न हिनस्त्यात्मनाऽऽत्मानं ततो याति परां गतिम्","iast":"samaṁ paśhyan hi sarvatra samavasthitam īśhvaram\nna hinasty ātmanātmānaṁ tato yāti parāṁ gatim","v":[{"k":"purohit","t":"Beholding the Lord equally in all things, his actions do not mar his spiritual life but lead him to the heights of bliss."},{"k":"sivananda","t":"For he who truly sees the same Lord dwelling everywhere does not destroy the Self by the self; rather, he attains the highest goal."},{"k":"adidevananda","t":"For, seeing the ruler abiding alike in every place, he does not injure himself with his own mind and therefore reaches the highest goal."},{"k":"gambirananda","t":"Since, by truly seeing God, who is present everywhere alike, he does not injure the Self by the Self, he therefore attains the supreme Goal."},{"k":"sankaranarayan","t":"Whoever, perceiving the Lord as abiding in all alike, does not harm themselves by themselves, they attain, on that account, the Supreme Goal."}]},{"ch":13,"vn":30,"dev":"प्रकृत्यैव च कर्माणि क्रियमाणानि सर्वशः।यः पश्यति तथाऽऽत्मानमकर्तारं स पश्यति","iast":"prakṛityaiva cha karmāṇi kriyamāṇāni sarvaśhaḥ\nyaḥ paśhyati tathātmānam akartāraṁ sa paśhyati","v":[{"k":"purohit","t":"He who understands that it is only the Law of Nature that brings action to fruition, and that the Self never acts, alone knows the Truth."},{"k":"sivananda","t":"He sees, who sees that all actions are performed solely by Nature and that the Self is without action."},{"k":"adidevananda","t":"He who sees that all acts are done universally by Prakrti alone, and likewise that the self is not the doer, he indeed sees."},{"k":"gambirananda","t":"And he who sees actions being done in various ways by Nature itself, and also the Self as the non-agent, he sees."},{"k":"sankaranarayan","t":"Whoever views all actions as being performed (or all objects as being created) by the Material Cause itself, and at the same time views their own Self as a non-performer (or non-creator) - they view properly."}]},{"ch":13,"vn":31,"dev":"यदा भूतपृथग्भावमेकस्थमनुपश्यति।तत एव च विस्तारं ब्रह्म सम्पद्यते तदा","iast":"yadā bhūta-pṛithag-bhāvam eka-stham anupaśhyati\ntata eva cha vistāraṁ brahma sampadyate tadā","v":[{"k":"purohit","t":"He who sees the diverse forms of life all rooted in One and growing forth from Him, shall indeed find the Absolute."},{"k":"sivananda","t":"When a person sees all beings as resting in the One and emanating from the One alone, they then become Brahman."},{"k":"adidevananda","t":"When he perceives the independent modes of existence of all beings centered in one, and their expansion from it alone, then he attains Brahman."},{"k":"gambirananda","t":"When one realizes that the state of diversity of living things is rooted in the One, and that their manifestation also comes from That, then one becomes identified with Brahman."},{"k":"sankaranarayan","t":"When he perceives the mutual difference of beings as abiding in One, and its expansion from That alone, at that time he becomes the Brahman."}]},{"ch":13,"vn":32,"dev":"अनादित्वान्निर्गुणत्वात्परमात्मायमव्ययः।शरीरस्थोऽपि कौन्तेय न करोति न लिप्यते","iast":"anāditvān nirguṇatvāt paramātmāyam avyayaḥ\nśharīra-stho 'pi kaunteya na karoti na lipyate","v":[{"k":"purohit","t":"The Supreme Spirit, O Prince, is without beginning, has no qualities, and is imperishable. Though it is within the body, it does not act, nor is it affected by action."},{"k":"sivananda","t":"Being without beginning, devoid of any qualities, the Supreme Self, imperishable, though dwelling in the body, O Arjuna, neither acts nor is tainted."},{"k":"adidevananda","t":"This supreme Self, though dwelling in the body, is immutable, O Arjuna, being without beginning. It neither acts nor is tainted, as it is without Gunas."},{"k":"gambirananda","t":"Being without beginning and without end, O son of Kunti, this immutable, supreme Self does not act, nor is It affected [Also translated as tainted.-Tr.], although It exists in the body."},{"k":"sankaranarayan","t":"Because this is beginningless, and because this has no qualities, this Supreme Self is changeless and it neither acts nor gets stained [by actions], even though it dwells in the body, O son of Kunti!"}]},{"ch":13,"vn":33,"dev":"यथा सर्वगतं सौक्ष्म्यादाकाशं नोपलिप्यते।सर्वत्रावस्थितो देहे तथाऽऽत्मा नोपलिप्यते","iast":"yathā sarva-gataṁ saukṣhmyād ākāśhaṁ nopalipyate\nsarvatrāvasthito dehe tathātmā nopalipyate","v":[{"k":"purohit","t":"As space, though present everywhere, remains unaffected due to its subtlety, so too the Self, though present in all forms, retains its purity unalloyed."},{"k":"sivananda","t":"As the all-pervading ether is not tainted, due to its subtlety, so the Self seated everywhere in the body is not tainted either."},{"k":"adidevananda","t":"As the all-pervading ether is not tainted due to its subtlety, even so, the self abiding in the body is not tainted everywhere."},{"k":"gambirananda","t":"As the all-pervading space is not defiled, due to its subtlety, similarly the Self, present everywhere in bodies, is not defiled."},{"k":"sankaranarayan","t":"Just as the all-pervasive Ether is not stained due to its subtlety, in the same way the Self, abiding in the body everywhere, is not stained."}]},{"ch":13,"vn":34,"dev":"यथा प्रकाशयत्येकः कृत्स्नं लोकमिमं रविः।क्षेत्रं क्षेत्री तथा कृत्स्नं प्रकाशयति भारत","iast":"yathā prakāśhayaty ekaḥ kṛitsnaṁ lokam imaṁ raviḥ\nkṣhetraṁ kṣhetrī tathā kṛitsnaṁ prakāśhayati bhārata","v":[{"k":"purohit","t":"As the one Sun illuminates the entire earth, so the Lord illuminates the entire universe."},{"k":"sivananda","t":"Just as the one sun illuminates the entire world, so too does the Lord of the field (Supreme Self) illuminate the entire field, O Arjuna."},{"k":"adidevananda","t":"As the one sun illuminates this entire world, so does the Knower of the Field (Ksetrin, the self), O Arjuna, illuminate the entire Field (the body)."},{"k":"gambirananda","t":"As the single sun illuminates this entire world, similarly, O descendant of the Bharata dynasty, the Knower of the field illuminates the entire field."},{"k":"sankaranarayan","t":"Just as a single sun illuminates this entire world, so too does the Lord of the Field illuminate the entire Field, O descendant of Bharata!"}]},{"ch":13,"vn":35,"dev":"क्षेत्रक्षेत्रज्ञयोरेवमन्तरं ज्ञानचक्षुषा।भूतप्रकृतिमोक्षं च ये विदुर्यान्ति ते परम्","iast":"kṣhetra-kṣhetrajñayor evam antaraṁ jñāna-chakṣhuṣhā\nbhūta-prakṛiti-mokṣhaṁ cha ye vidur yānti te param","v":[{"k":"purohit","t":"Those who, with the eyes of wisdom, thus see the difference between Matter and Spirit, and know how to liberate life from the Law of Nature, attain the Supreme."},{"k":"sivananda","t":"They who, by the eye of knowledge, perceive the distinction between the field and its knower, as well as the liberation from the Nature of being, go to the Supreme."},{"k":"adidevananda","t":"Those who thus discern, with the eye of knowledge, the difference between the body or the Field (Ksetra) and the knower of the body or Field-knower (Ksetrajna), and the means of deliverance from the manifested Prakrti, they attain the Supreme."},{"k":"gambirananda","t":"Those who, through the eye of wisdom, know the distinction between the field and the Knower of the field, and the annihilation of the Matrix of beings, reach the Supreme."},{"k":"sankaranarayan","t":"Those who thus understand, with the knowledge-eye, the inner Soul of the Field and the Field-sensitizer, as well as the deliverance from the Material Cause of the elements—they attain the Supreme."}]},{"ch":14,"vn":1,"dev":"श्री भगवानुवाचपरं भूयः प्रवक्ष्यामि ज्ञानानां ज्ञानमुत्तमम्।यज्ज्ञात्वा मुनयः सर्वे परां सिद्धिमितो गताः","iast":"śhrī-bhagavān uvācha\nparaṁ bhūyaḥ pravakṣhyāmi jñānānāṁ jñānam uttamam\nyaj jñātvā munayaḥ sarve parāṁ siddhim ito gatāḥ","v":[{"k":"purohit","t":"Lord Shri Krishna continued: Now I will reveal to you the wisdom that is beyond knowledge, by attaining which the sages have reached perfection."},{"k":"sivananda","t":"The Blessed Lord said, \"I will again declare to thee that supreme knowledge, the best of all knowledge, having known which all the sages have gone to supreme perfection after this life.\""},{"k":"adidevananda","t":"The Lord said, \"I shall declare again another kind of knowledge: It is the best of all forms of knowledge, by knowing which all the sages have attained the state of perfection beyond this world.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"I shall speak again of the supreme knowledge, the best of all knowledge, by realizing which all the contemplatives have reached the highest perfection from here.\""},{"k":"sankaranarayan","t":"The Bhagavat said: Further, once again I shall explain the supreme knowledge, the best among knowledges, by knowing which all the seers have gone from here to the Supreme Success."}]},{"ch":14,"vn":2,"dev":"इदं ज्ञानमुपाश्रित्य मम साधर्म्यमागताः।सर्गेऽपि नोपजायन्ते प्रलये न व्यथन्ति च","iast":"idaṁ jñānam upāśhritya mama sādharmyam āgatāḥ\nsarge 'pi nopajāyante pralaye na vyathanti cha","v":[{"k":"purohit","t":"Dwelling in wisdom and realizing My divinity, they are not reborn when the universe is recreated at the beginning of every cycle, nor are they affected when it is dissolved."},{"k":"sivananda","t":"Those who, having taken refuge in this knowledge, have attained unity with Me, are neither born at the time of creation nor disturbed at the time of dissolution."},{"k":"adidevananda","t":"Resorting to this knowledge, partaking in My Nature, they are not born at the time of creation nor do they suffer at the time of dissolution."},{"k":"gambirananda","t":"Those who attain identity with Me by resorting to this Knowledge are not born even during creation, nor do they suffer pain during dissolution."},{"k":"sankaranarayan","t":"Holding onto this knowledge, they have attained a state with attributes common to Me; they are neither born at the time of creation nor grieve at the time of dissolution."}]},{"ch":14,"vn":3,"dev":"मम योनिर्महद्ब्रह्म तस्मिन् गर्भं दधाम्यहम्।संभवः सर्वभूतानां ततो भवति भारत","iast":"mama yonir mahad brahma tasmin garbhaṁ dadhāmy aham\nsambhavaḥ sarva-bhūtānāṁ tato bhavati bhārata","v":[{"k":"purohit","t":"The eternal cosmos is My womb, in which I plant the seed from which all beings are born, O prince!"},{"k":"sivananda","t":"My womb is the great Brahma; in it I place the germ; thence, O Arjuna, is the birth of all beings."},{"k":"adidevananda","t":"My womb is the great Brahman (i.e. Prakṛti). In it, I lay the germ. From that, O Arjuna, comes the birth of all beings."},{"k":"gambirananda","t":"My womb is the great sustainer. In it, I place the seed. From that, O scion of the Bharata dynasty, all things are born."},{"k":"sankaranarayan","t":"The mighty Brahman is a womb for Me; and in it I lay seed; from which is the birth of all beings, O descendant of Bharata!"}]},{"ch":14,"vn":4,"dev":"सर्वयोनिषु कौन्तेय मूर्तयः सम्भवन्ति याः।तासां ब्रह्म महद्योनिरहं बीजप्रदः पिता","iast":"sarva-yoniṣhu kaunteya mūrtayaḥ sambhavanti yāḥ\ntāsāṁ brahma mahad yonir ahaṁ bīja-pradaḥ pitā","v":[{"k":"purohit","t":"O illustrious son of Kunti! Through whatever wombs men are born, it is the Spirit itself that conceives, and I am their father."},{"k":"sivananda","t":"Whatever forms are produced, O Arjuna, in any womb whatsoever, the great Brahma is their womb, and I am the seed-giving father."},{"k":"adidevananda","t":"Whatever forms are produced in any womb, O Arjuna, the Prakṛti is their great womb, and I am the sowing father."},{"k":"gambirananda","t":"O son of Kunti, whatever forms are born from all the wombs, of them the great sustainer is the womb; I am the father who deposits the seed."},{"k":"sankaranarayan","t":"O son of Kunti! Whatever manifestations spring up in all the wombs, the mighty Brahman is the womb, and I am the father who sows the seed."}]},{"ch":14,"vn":5,"dev":"सत्त्वं रजस्तम इति गुणाः प्रकृतिसंभवाः।निबध्नन्ति महाबाहो देहे देहिनमव्ययम्","iast":"sattvaṁ rajas tama iti guṇāḥ prakṛiti-sambhavāḥ\nnibadhnanti mahā-bāho dehe dehinam avyayam","v":[{"k":"purohit","t":"Purity, passion, and ignorance are the qualities that the law of nature brings forth. They fetter the free spirit in all beings."},{"k":"sivananda","t":"These qualities, O Arjuna, born of Nature, bind fast in the body of the embodied, the indestructible: purity, passion, and inertia."},{"k":"adidevananda","t":"The Gunas of Sattva, Rajas, and Tamas arise from Prakrti and bind the immutable Self in the body, O Arjuna."},{"k":"gambirananda","t":"O mighty-armed one, the qualities, viz. sattva, rajas, and tamas, born of Nature, are the immutable embodiments belonging to the body."},{"k":"sankaranarayan","t":"The strands, namely the sattva, rajas, and tamas, born from the prime cause (the said mother), bind the changeless embodied soul to the body, O mighty-armed one!"}]},{"ch":14,"vn":6,"dev":"तत्र सत्त्वं निर्मलत्वात्प्रकाशकमनामयम्।सुखसङ्गेन बध्नाति ज्ञानसङ्गेन चानघ","iast":"tatra sattvaṁ nirmalatvāt prakāśhakam anāmayam\nsukha-saṅgena badhnāti jñāna-saṅgena chānagha","v":[{"k":"purohit","t":"O Sinless One! Of these, purity, being luminous, strong, and invulnerable, binds one with its yearning for happiness and illumination."},{"k":"sivananda","t":"Of these, sattva, which is luminous and healthy due to its stainlessness, binds one by attachment to happiness and knowledge, O sinless one."},{"k":"adidevananda","t":"Of these, sattva, being without impurity, is luminous and free from morbidity. It binds, O Arjuna, through attachment to pleasure and knowledge."},{"k":"gambirananda","t":"Among them, sattva, being pure and nirmala (pure-transparent, i.e., capable of resisting any form of ignorance, and hence an illuminator, i.e. a revealer of Consciousness), is harmless. O sinless one, it binds through attachment to happiness and attachment to knowledge."},{"k":"sankaranarayan","t":"Among them, the Sattva, being free from impurity, is illuminating and health-giving; and it binds the embodied one with attachment to happiness and also with attachment to knowledge, O sinless one!"}]},{"ch":14,"vn":7,"dev":"रजो रागात्मकं विद्धि तृष्णासङ्गसमुद्भवम्।तन्निबध्नाति कौन्तेय कर्मसङ्गेन देहिनम्","iast":"rajo rāgātmakaṁ viddhi tṛiṣhṇā-saṅga-samudbhavam\ntan nibadhnāti kaunteya karma-saṅgena dehinam","v":[{"k":"purohit","t":"Passion, engendered by thirst for pleasure and attachment, binds the soul through its fondness for activities."},{"k":"sivananda","t":"Know, O Arjuna, that Rajas is of the nature of passion, the source of thirst and attachment; it binds fast the embodied one by attachment to action."},{"k":"adidevananda","t":"Know, O Arjuna, that Rajas is of the nature of passion springing from thirst and attachment. It binds the embodied self with attachment to action."},{"k":"gambirananda","t":"Know rajas to be of the nature of passion, born of hankering and attachment. O son of Kunti, it binds the embodied one through attachment to action."},{"k":"sankaranarayan","t":"You should know that Rajas is of the nature of desire and is a source of craving-attachment; and it binds the embodied one by attachment to action, O son of Kunti!"}]},{"ch":14,"vn":8,"dev":"तमस्त्वज्ञानजं विद्धि मोहनं सर्वदेहिनाम्।प्रमादालस्यनिद्राभिस्तन्निबध्नाति भारत","iast":"tamas tv ajñāna-jaṁ viddhi mohanaṁ sarva-dehinām\npramādālasya-nidrābhis tan nibadhnāti bhārata","v":[{"k":"purohit","t":"But Ignorance, the product of darkness, stupefies the senses of all embodied beings, binding them with chains of folly, indolence, and lethargy."},{"k":"sivananda","t":"But know thou Tamas to be born of ignorance, deluding all embodied beings; it binds fast, O Arjuna, through heedlessness, indolence, and sleep."},{"k":"adidevananda","t":"Know that Tamas is born of false knowledge and deludes all embodied beings. It binds, O Arjuna, with negligence, indolence, and sleep."},{"k":"gambirananda","t":"On the other hand, know tamas, which deludes all embodied beings, to be born of ignorance. O scion of the Bharata dynasty, it binds through inadvertence, laziness, and sleep."},{"k":"sankaranarayan","t":"But, you should also know that Tamas is born of ignorance and deludes all the Embodied; it binds them with negligence, laziness, and sleep, O descendant of Bharata!"}]},{"ch":14,"vn":9,"dev":"सत्त्वं सुखे सञ्जयति रजः कर्मणि भारत।ज्ञानमावृत्य तु तमः प्रमादे सञ्जयत्युत","iast":"sattvaṁ sukhe sañjayati rajaḥ karmaṇi bhārata\njñānam āvṛitya tu tamaḥ pramāde sañjayaty uta","v":[{"k":"purohit","t":"Purity brings happiness, passion brings commotion, and ignorance, which obscures wisdom, leads to a life of failure."},{"k":"sivananda","t":"Sattva attaches to happiness, Rajas to action, O Arjuna, while Tamas, verily shrouding knowledge, attaches to heedlessness."},{"k":"adidevananda","t":"Sattva generates attachment to pleasure, Rajas to action, O Arjuna. But Tamas, obscuring knowledge, generates attachment to negligence."},{"k":"gambirananda","t":"O scion of the Bharata dynasty, sattva attaches one to happiness, rajas to action, while tamas, obscuring knowledge, leads to inadvertence as well."},{"k":"sankaranarayan","t":"O descendant of Bharata! The Sattva fully dominates the Embodied in the field of happiness; the Rajas in action; but the Tamas also totally dominates in the field of negligence, by veiling knowledge."}]},{"ch":14,"vn":10,"dev":"रजस्तमश्चाभिभूय सत्त्वं भवति भारत।रजः सत्त्वं तमश्चैव तमः सत्त्वं रजस्तथा","iast":"rajas tamaśh chābhibhūya sattvaṁ bhavati bhārata\nrajaḥ sattvaṁ tamaśh chaiva tamaḥ sattvaṁ rajas tathā","v":[{"k":"purohit","t":"O Prince! Purity prevails when passion and ignorance are overcome; passion, when purity and ignorance are overcome; and ignorance when it is overcome by purity and passion."},{"k":"sivananda","t":"Now, O Arjuna, Sattva prevails, having overpowered Rajas and Tamas; then Rajas, having overpowered Sattva and Tamas; and then Tamas, having overpowered Sattva and Rajas."},{"k":"adidevananda","t":"Prevailing over Rajas and Tamas, Sattva predominates, O Arjuna. Prevailing over Tamas and Sattva, Rajas predominates. Prevailing over Rajas and Sattva, Tamas predominates."},{"k":"gambirananda","t":"O scion of the Bharata dynasty, sattva increases by subduing rajas and tamas; rajas increases by overpowering sattva and tamas; and tamas increases by dominating over sattva and rajas."},{"k":"sankaranarayan","t":"O descendant of Bharata! The Sattva increases by overpowering the Rajas and the Tamas; the Rajas increases by overpowering the Sattva and the Tamas; and the Tamas increases likewise by overpowering the Sattva and the Rajas."}]},{"ch":14,"vn":11,"dev":"सर्वद्वारेषु देहेऽस्मिन्प्रकाश उपजायते।ज्ञानं यदा तदा विद्याद्विवृद्धं सत्त्वमित्युत","iast":"sarva-dvāreṣhu dehe 'smin prakāśha upajāyate\njñānaṁ yadā tadā vidyād vivṛiddhaṁ sattvam ity uta","v":[{"k":"purohit","t":"When the light of knowledge gleams forth from all the gates of the body, then be sure that purity prevails."},{"k":"sivananda","t":"When the wisdom-light shines through every gate of this body, then it may be known that Sattva is predominant."},{"k":"adidevananda","t":"When knowledge, like light, illuminates from all gateways (i.e., the senses), then one should know that Sattva prevails."},{"k":"gambirananda","t":"When the illumination of knowledge radiates through all the doors of the senses in this body, then one should know that sattva has greatly increased."},{"k":"sankaranarayan","t":"When the knowledge-light arises in all the gates of this body, then one should also know that the Sattva has predominantly increased."}]},{"ch":14,"vn":12,"dev":"लोभः प्रवृत्तिरारम्भः कर्मणामशमः स्पृहा।रजस्येतानि जायन्ते विवृद्धे भरतर्षभ","iast":"lobhaḥ pravṛittir ārambhaḥ karmaṇām aśhamaḥ spṛihā\nrajasy etāni jāyante vivṛiddhe bharatarṣhabha","v":[{"k":"purohit","t":"O best of Indians! Avarice, the impulse to act, and the beginning of action itself are all due to the dominance of passion."},{"k":"sivananda","t":"Greed, activity, the undertaking of actions, restlessness, and longing—these arise when Rajas is predominant, O Arjuna."},{"k":"adidevananda","t":"Greed, activity, undertaking of work, restlessness, and longing—these arise, O Arjuna, when Rajas predominates."},{"k":"gambirananda","t":"O best of the Bharata dynasty, when rajas becomes predominant, these come into being: avarice, restlessness, undertaking of actions, agitation, and craving."},{"k":"sankaranarayan","t":"Greed, exertion, undertaking of actions, restlessness, and craving—these are born when Rajas predominates, O chief of the Bharatas!"}]},{"ch":14,"vn":13,"dev":"अप्रकाशोऽप्रवृत्तिश्च प्रमादो मोह एव च।तमस्येतानि जायन्ते विवृद्धे कुरुनन्दन","iast":"aprakāśho 'pravṛittiśh cha pramādo moha eva cha\ntamasy etāni jāyante vivṛiddhe kuru-nandana","v":[{"k":"purohit","t":"Darkness, stagnation, folly, and infatuation are the results of the dominance of ignorance, O joy of the Kuru clan!"},{"k":"sivananda","t":"Darkness, inertia, carelessness, and delusion—these arise when Tamas is predominant, O Arjuna."},{"k":"adidevananda","t":"Non-illumination, inactivity, negligence, and even delusion—these arise, O Arjuna, when Tamas prevails."},{"k":"gambirananda","t":"O descendant of the Kuru dynasty, when tamas predominates, these come into being without exception: non-discrimination, inactivity, inadvertence, and delusion."},{"k":"sankaranarayan","t":"Absence of mental illumination, lack of exertion, negligence, and mere delusion—these are born when Tamas predominates, O darling of the Kurus!"}]},{"ch":14,"vn":14,"dev":"यदा सत्त्वे प्रवृद्धे तु प्रलयं याति देहभृत्।तदोत्तमविदां लोकानमलान्प्रतिपद्यते","iast":"yadā sattve pravṛiddhe tu pralayaṁ yāti deha-bhṛit\ntadottama-vidāṁ lokān amalān pratipadyate","v":[{"k":"purohit","t":"When purity prevails, the soul, upon leaving the body, passes on to the pure regions where those who know the Highest reside."},{"k":"sivananda","t":"If the embodied one meets death when Sattva is predominant, then they attain the spotless worlds of the knowers of the Highest."},{"k":"adidevananda","t":"If the embodied self dissolves when Sattva prevails, then it proceeds to the pure worlds of those who know the highest."},{"k":"gambirananda","t":"When an embodied one undergoes death while sattva is exclusively predominant, then he attains the untainted worlds of those who know the highest (entities)."},{"k":"sankaranarayan","t":"But if the body-bearer dies when sattva is on the increase, then he attains to the spotless worlds of those who know the highest."}]},{"ch":14,"vn":15,"dev":"रजसि प्रलयं गत्वा कर्मसङ्गिषु जायते।तथा प्रलीनस्तमसि मूढयोनिषु जायते","iast":"rajasi pralayaṁ gatvā karma-saṅgiṣhu jāyate\ntathā pralīnas tamasi mūḍha-yoniṣhu jāyate","v":[{"k":"purohit","t":"When passion prevails, the soul is reborn among those who love activity; when ignorance rules, it enters the wombs of the ignorant."},{"k":"sivananda","t":"Meeting death in Rajas, he is born among those who are attached to action; and dying in Tamas, he is born in the womb of the thoughtless."},{"k":"adidevananda","t":"(a) When Rajas is prevalent, one meets with dissolution and is born among those attached to work.\n(b) Similarly, when Tamas prevails, one who has met with dissolution is born in the womb of beings lacking intelligence."},{"k":"gambirananda","t":"When one dies while rajas predominates, they are born among people attached to activity. Similarly, when one dies while tamas predominates, they take birth among the stupid species."},{"k":"sankaranarayan","t":"By meeting death when Rajas is on the increase, he is born among those who are attached to action; likewise, by meeting death when Tamas is on the increase, he is born in the wombs of the deluded."}]},{"ch":14,"vn":16,"dev":"कर्मणः सुकृतस्याहुः सात्त्विकं निर्मलं फलम्।रजसस्तु फलं दुःखमज्ञानं तमसः फलम्","iast":"karmaṇaḥ sukṛitasyāhuḥ sāttvikaṁ nirmalaṁ phalam\nrajasas tu phalaṁ duḥkham ajñānaṁ tamasaḥ phalam","v":[{"k":"purohit","t":"They say the fruit of a meritorious action is spotless and pure; the outcome of passion is misery, and of ignorance, darkness."},{"k":"sivananda","t":"They say that the fruit of good action is Sattvic and pure; indeed, the fruit of Rajas is pain, and the fruit of Tamas is ignorance."},{"k":"adidevananda","t":"It is said that the fruit of a good deed is pure and of the nature of Sattva; the fruit of Rajas is pain; and the fruit of Tamas is ignorance."},{"k":"gambirananda","t":"They say that the result of good work is pure and is born of Sattva. But the result of Rajas is sorrow; the result of Tamas is ignorance."},{"k":"sankaranarayan","t":"It is said that the fruit of good action is spotless and of the Sattva nature; whereas the fruit of Rajas is pain, and the fruit of Tamas is ignorance."}]},{"ch":14,"vn":17,"dev":"सत्त्वात्सञ्जायते ज्ञानं रजसो लोभ एव च।प्रमादमोहौ तमसो भवतोऽज्ञानमेव च","iast":"sattvāt sañjāyate jñānaṁ rajaso lobha eva cha\npramāda-mohau tamaso bhavato 'jñānam eva cha","v":[{"k":"purohit","t":"Purity engenders wisdom, passion avarice, and ignorance folly, infatuation, and darkness."},{"k":"sivananda","t":"From Sattva arises knowledge, and greed from Rajas; heedlessness and delusion arise from Tamas, and also ignorance."},{"k":"adidevananda","t":"From Sattva arises knowledge, from Rajas arises greed, from Tamas arises negligence and delusion, and from it arises ignorance."},{"k":"gambirananda","t":"From sattva is born knowledge, and from rajas, avarice indeed. From tamas are born inadvertence, delusion, and ignorance, to be sure."},{"k":"sankaranarayan","t":"From Sattva arises wisdom; from Rajas, only greed; and from Tamas arise negligence, delusion, and ignorance."}]},{"ch":14,"vn":18,"dev":"ऊर्ध्वं गच्छन्ति सत्त्वस्था मध्ये तिष्ठन्ति राजसाः।जघन्यगुणवृत्तिस्था अधो गच्छन्ति तामसाः","iast":"ūrdhvaṁ gachchhanti sattva-sthā madhye tiṣhṭhanti rājasāḥ\njaghanya-guṇa-vṛitti-sthā adho gachchhanti tāmasāḥ","v":[{"k":"purohit","t":"When purity is in the ascendant, the man evolves; when passion is in the ascendant, he neither evolves nor degenerates; when ignorance is in the ascendant, he is lost."},{"k":"sivananda","t":"Those seated in Sattva ascend; those of Rajasic nature dwell in the middle; and those of Tamasic nature, abiding in the function of the lowest Guna, descend."},{"k":"adidevananda","t":"Those who rest in Sattva ascend upwards; those who abide in Rajas stay in the middle; and those, abiding in the tendencies of Tamas descend downwards."},{"k":"gambirananda","t":"People who conform to sattva go higher up; those who conform to rajas stay in the middle; those who conform to tamas, who conform to the actions of the lowest quality, go down."},{"k":"sankaranarayan","t":"Those established in Sattva ascend; those given to Rajas remain in the middle; those given to Tamas, established in the tendencies of bad qualities, descend."}]},{"ch":14,"vn":19,"dev":"नान्यं गुणेभ्यः कर्तारं यदा द्रष्टानुपश्यति।गुणेभ्यश्च परं वेत्ति मद्भावं सोऽधिगच्छति","iast":"nānyaṁ guṇebhyaḥ kartāraṁ yadā draṣhṭānupaśhyati\nguṇebhyaśh cha paraṁ vetti mad-bhāvaṁ so 'dhigachchhati","v":[{"k":"purohit","t":"As soon as one understands that it is only the qualities that act and nothing else, and perceives that which is beyond, they attain My divine nature."},{"k":"sivananda","t":"When the seer beholds no agent other than the Gunas and knows that which is higher than them, he attains to My Being."},{"k":"adidevananda","t":"When the seer beholds no agent of action other than the Gunas, and knows what is beyond the Gunas, he attains to My state."},{"k":"gambirananda","t":"When the witness sees none other than the qualities as the agent, and knows that which is superior to the qualities, he attains My nature."},{"k":"sankaranarayan","t":"When the Perceiver (the Self) finds no agent other than the Strands, and realizes That which is beyond the Strands, then he attains My state."}]},{"ch":14,"vn":20,"dev":"गुणानेतानतीत्य त्रीन्देही देहसमुद्भवान्।जन्ममृत्युजरादुःखैर्विमुक्तोऽमृतमश्नुते","iast":"guṇān etān atītya trīn dehī deha-samudbhavān\njanma-mṛityu-jarā-duḥkhair vimukto 'mṛitam aśhnute","v":[{"k":"purohit","t":"When the soul transcends the Qualities, which are the real cause of physical existence, then, freed from birth and death, from old age and misery, he drinks the nectar of immortality."},{"k":"sivananda","t":"The embodied one, having crossed beyond these three Gunas from which the body is evolved, is freed from birth, death, decay, and pain, and attains immortality."},{"k":"adidevananda","t":"The embodied Self, crossing beyond these three Gunas that arise in the body, and being freed from birth, death, aging, and pain, attains immortality."},{"k":"gambirananda","t":"Having transcended these three qualities, which are the origin of the body, the embodied one becomes free from birth, death, old age, and sorrows, and experiences Immortality."},{"k":"sankaranarayan","t":"Transcending these three strands, from which the body [etc.] is born, the embodied (the soul) is freed from birth, death, old age, and sorrow, and attains immortality."}]},{"ch":14,"vn":21,"dev":"अर्जुन उवाचकैर्लिंगैस्त्रीन्गुणानेतानतीतो भवति प्रभो।किमाचारः कथं चैतांस्त्रीन्गुणानतिवर्तते","iast":"arjuna uvācha\nkair liṅgais trīn guṇān etān atīto bhavati prabho\nkim āchāraḥ kathaṁ chaitāns trīn guṇān ativartate","v":[{"k":"purohit","t":"Arjuna asked, \"My Lord, how can one recognize someone who has transcended the qualities? How do they act and live beyond them?\""},{"k":"sivananda","t":"Arjuna said, \"What are the marks of one who has transcended the three qualities, O Lord? What is their conduct, and how do they go beyond these three qualities?\""},{"k":"adidevananda","t":"Arjuna said, \"What are the marks of a person who has transcended the three Gunas? What is their behavior? And how do they transcend the three Gunas?\""},{"k":"gambirananda","t":"Arjuna said, \"O Lord, by what signs is one known who has gone beyond these three qualities? What is their behavior, and how do they transcend these three qualities?\""},{"k":"sankaranarayan","t":"Arjuna said, \"O Master! With what characteristic marks does he who has transcended these three strands exist? What is his behavior? How does he pass beyond these three strands?\""}]},{"ch":14,"vn":22,"dev":"श्री भगवानुवाचप्रकाशं च प्रवृत्तिं च मोहमेव च पाण्डव।न द्वेष्टि सम्प्रवृत्तानि न निवृत्तानि काङ्क्षति","iast":"śhrī-bhagavān uvācha\nprakāśhaṁ cha pravṛittiṁ cha moham eva cha pāṇḍava\nna dveṣhṭi sampravṛittāni na nivṛittāni kāṅkṣhati","v":[{"k":"purohit","t":"Lord Shri Krishna replied: O Prince! He who does not shun the quality that is present and does not long for that which is absent;"},{"k":"sivananda","t":"The Blessed Lord said, \"When light, activity, and delusion are present, he does not hate them, nor does he long for them when they are absent."},{"k":"adidevananda","t":"The Lord said, \"He does not hate illumination, nor activity, nor even delusion, O Arjuna, while these prevail, nor does He long for them when they cease.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"O son of Pandu, he neither dislikes illumination (knowledge), activity, nor delusion when they appear, nor does he long for them when they disappear.\""},{"k":"sankaranarayan","t":"The Bhagavat said, \"O son of Pandu! He neither abhors nor craves for illumination, exertion, and delusion, as and when they arise or cease to be.\""}]},{"ch":14,"vn":23,"dev":"उदासीनवदासीनो गुणैर्यो न विचाल्यते।गुणा वर्तन्त इत्येव योऽवतिष्ठति नेङ्गते","iast":"udāsīna-vad āsīno guṇair yo na vichālyate\nguṇā vartanta ity evaṁ yo 'vatiṣhṭhati neṅgate","v":[{"k":"purohit","t":"He who maintains an attitude of indifference, who is not disturbed by the qualities, who realizes that it is only they who act, and remains calm;"},{"k":"sivananda","t":"He who, seated like one unconcerned, is not moved by the dualities, and who, knowing that the dualities are active, is self-centered and does not move."},{"k":"adidevananda","t":"He who sits like one unconcerned, undisturbed by the Gunas; who knows, 'It is the Gunas that are in motion,' and so remains unshaken;"},{"k":"gambirananda","t":"He who, sitting like one indifferent, is not distracted by the three qualities; he who, thinking that the qualities alone act, remains firm and does not move surely;"},{"k":"sankaranarayan","t":"He who, sitting like an unconcerned person, is not perturbed by the strands; who is ignorant of the existence of the strands; or who remains simply aware that the strands alone exist; who is not shaken;"}]},{"ch":14,"vn":24,"dev":"समदुःखसुखः स्वस्थः समलोष्टाश्मकाञ्चनः।तुल्यप्रियाप्रियो धीरस्तुल्यनिन्दात्मसंस्तुतिः","iast":"sama-duḥkha-sukhaḥ sva-sthaḥ sama-loṣhṭāśhma-kāñchanaḥ\ntulya-priyāpriyo dhīras tulya-nindātma-sanstutiḥ","v":[{"k":"purohit","t":"Who accepts pain and pleasure as they come, is centered in their Self, to whom a piece of clay, stone, or gold are all the same, who neither likes nor dislikes, who is steadfast, indifferent alike to praise or censure;"},{"k":"sivananda","t":"Who is the same in pleasure and pain, who dwells in the Self, to whom a clod of earth, a stone, and gold are all alike, who is the same to the dear and the unfriendly, who is firm, and to whom censure and praise are one and the same."},{"k":"adidevananda","t":"He who is alike in pleasure and pain, who dwells in his Self, who looks upon a clod, a stone, and a piece of gold as of equal value, who remains the same towards things dear and hateful, and who is intelligent, who regards both blame and praise of himself as equal."},{"k":"gambirananda","t":"He to whom sorrow and happiness are alike, who is established in his own Self, to whom a lump of earth, iron, and gold are the same, to whom the agreeable and the disagreeable are the same, who is wise, to whom censure and his own praise are the same;"},{"k":"sankaranarayan","t":"To whom pain, pleasure, and sleep are all the same; to whom a cold, a stone, and a lump of gold are all the same; to whom both the pleasant and unpleasant things are equal; who is firm-minded; to whom blame and personal commendation are equal."}]},{"ch":14,"vn":25,"dev":"मानापमानयोस्तुल्यस्तुल्यो मित्रारिपक्षयोः।सर्वारम्भपरित्यागी गुणातीतः स उच्यते","iast":"mānāpamānayos tulyas tulyo mitrāri-pakṣhayoḥ\nsarvārambha-parityāgī guṇātītaḥ sa uchyate","v":[{"k":"purohit","t":"Who looks equally upon honor and dishonor, loves friends and foes alike, and abandons all initiative, such is he who transcends the qualities."},{"k":"sivananda","t":"Who is the same in honor and dishonor, the same to friend and foe, abandoning all undertakings, he is said to have transcended the dualities."},{"k":"adidevananda","t":"He who is the same in honor and dishonor, and the same to friend and foe, and who has abandoned all enterprises—he is said to have risen above the Gunas."},{"k":"gambirananda","t":"He who is the same under honor and dishonor, who is equitably disposed towards both friends and foes, who has renounced all undertakings—he is said to have gone beyond dualities."},{"k":"sankaranarayan","t":"Who remains equal to honor and dishonor, and equal to the sides of both the friend and the foe; and who has given up all fruits of his actions—he is said to have transcended the bonds."}]},{"ch":14,"vn":26,"dev":"मां च योऽव्यभिचारेण भक्ितयोगेन सेवते।स गुणान्समतीत्यैतान् ब्रह्मभूयाय कल्पते","iast":"māṁ cha yo 'vyabhichāreṇa bhakti-yogena sevate\nsa guṇān samatītyaitān brahma-bhūyāya kalpate","v":[{"k":"purohit","t":"And he who serves Me alone, with unwavering devotion, shall overcome the Qualities and become one with the Eternal."},{"k":"sivananda","t":"And he who serves Me with unwavering devotion, he, crossing beyond the dualities, is fit for becoming Brahman."},{"k":"adidevananda","t":"And he who, with unwavering devotion through Yoga, serves Me, he, transcending the Gunas, becomes fit for the state of Brahman."},{"k":"gambirananda","t":"And he who serves Me through the unswerving Yoga of Devotion, he, having gone beyond these qualities, qualifies for becoming Brahman."},{"k":"sankaranarayan","t":"Whoever serves me alone with an unwavering devotion to yoga, they will transcend these strands and become Brahman."}]},{"ch":14,"vn":27,"dev":"ब्रह्मणो हि प्रतिष्ठाऽहममृतस्याव्ययस्य च।शाश्वतस्य च धर्मस्य सुखस्यैकान्तिकस्य च","iast":"brahmaṇo hi pratiṣhṭhāham amṛitasyāvyayasya cha\nśhāśhvatasya cha dharmasya sukhasyaikāntikasya cha","v":[{"k":"purohit","t":"For I am the home of the spirit, the continual source of immortality, eternal righteousness, and infinite joy."},{"k":"sivananda","t":"For I am the abode of Brahman, the immortal, immutable, and everlasting Dharma, and absolute bliss."},{"k":"adidevananda","t":"For I am the ground of Brahman, the immortal, immutable, and eternal Dharma, and perfect bliss."},{"k":"gambirananda","t":"For I am the Abode of Brahman—the indestructible, immutable, eternal, Dharma, and absolute Bliss."},{"k":"sankaranarayan","t":"'I' am the support for the immortal and changeless Brahman and for its eternal attribute, the unalloyed happiness."}]},{"ch":15,"vn":1,"dev":"श्री भगवानुवाचऊर्ध्वमूलमधःशाखमश्वत्थं प्राहुरव्ययम्।छन्दांसि यस्य पर्णानि यस्तं वेद स वेदवित्","iast":"śhrī-bhagavān uvācha\nūrdhva-mūlam adhaḥ-śhākham aśhvatthaṁ prāhur avyayam\nchhandānsi yasya parṇāni yas taṁ veda sa veda-vit","v":[{"k":"purohit","t":"Lord Shri Krishna continued: This phenomenal creation, which is both ephemeral and eternal, is like a tree, with its seed above in the Highest and its ramifications below on this earth. The scriptures are its leaves, and he who understands this knows."},{"k":"sivananda","t":"The Blessed Lord said: They (the wise) speak of the indestructible peepul tree, with its roots above and branches below, whose leaves are the meters or hymns; he who knows it is a knower of the Vedas."},{"k":"adidevananda","t":"The Lord said, \"They speak of an immutable Asvattha tree with its roots above and branches below; its leaves are the Vedas. He who knows it knows the Vedas.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"They say that the peepul tree, which has its roots upward and its branches downward, and of which the Vedas are the leaves, is imperishable. He who realizes it is a knower of the Vedas.\""},{"k":"sankaranarayan","t":"The Bhagavat said, [The scriptures] speak of a non-perishing holy fig tree, whose roots are high and branches are low, and of which the [Vedic] hymns are the leaves. He who knows this tree is the knower of the Vedas."}]},{"ch":15,"vn":2,"dev":"अधश्चोर्ध्वं प्रसृतास्तस्य शाखा     गुणप्रवृद्धा विषयप्रवालाः।अधश्च मूलान्यनुसन्ततानि     कर्मानुबन्धीनि मनुष्यलोके","iast":"adhaśh chordhvaṁ prasṛitās tasya śhākhā\nguṇa-pravṛiddhā viṣhaya-pravālāḥ\nadhaśh cha mūlāny anusantatāni\nkarmānubandhīni manuṣhya-loke","v":[{"k":"purohit","t":"Its branches shoot upwards and downwards, deriving their nourishment from the qualities; its buds are the objects of sense; and its roots, which follow the law, causing man's regeneration and degeneration, pierce downwards into the soil."},{"k":"sivananda","t":"Its branches spread below and above, nourished by the Gunas; its buds are sense-objects, and its roots stretch forth below in the world of men, originating action."},{"k":"adidevananda","t":"(a) Its branches extend both above and below, nourished by the Gunas. Their shoots are sense objects.\n(b) And their secondary roots extend downwards, resulting in actions that bind in the world of humans."},{"k":"gambirananda","t":"The branches of that Tree, extending downwards and upwards, are strengthened by the qualities and have sense-objects as their shoots. And the roots, which are followed by actions, spread downwards in the human world [According to A.G. and M.S. manusya-loke means a body distinguished by Brahminhood etc.]."},{"k":"sankaranarayan","t":"Of which tree, the branches spreading downward and upward, well-developed with strands, have sense objects as sprouts; and its roots below in the human world, stretching successively, have actions as their sub-knots."}]},{"ch":15,"vn":3,"dev":"न रूपमस्येह तथोपलभ्यते    नान्तो न चादिर्न च संप्रतिष्ठा।अश्वत्थमेनं सुविरूढमूल    मसङ्गशस्त्रेण दृढेन छित्त्वा","iast":"na rūpam asyeha tathopalabhyate\nnānto na chādir na cha sampratiṣhṭhā\naśhvattham enaṁ su-virūḍha-mūlam\nasaṅga-śhastreṇa dṛiḍhena chhittvā","v":[{"k":"purohit","t":"In this world, its true form is not known, neither its origin nor its end, and its strength is not understood—until the tree, with its roots striking deep into the earth, is hewn down by the sharp axe of non-attachment."},{"k":"sivananda","t":"Its form is not perceived here as such, nor its end, origin, foundation, or resting place; having cut asunder this firmly rooted peepul tree with the strong axe of non-attachment."},{"k":"adidevananda","t":"Its form is not perceived here, nor its end, nor its beginning, nor its support. Having cut off this firmly-rooted Asvattha with the strong axe of detachment."},{"k":"gambirananda","t":"Its form is not perceived here in that way; nor its end, nor beginning, nor its continuance. After felling this Peepul tree whose roots are well developed, with the strong sword of detachment."},{"k":"sankaranarayan","t":"The nature of this is not perceived in that way, nor its end, nor its beginning, nor its center (middle). Cutting this holy fig tree, with its firmly and variedly grown roots, by means of the sharp (or strong) axe of non-attachment;"}]},{"ch":15,"vn":4,"dev":"ततः पदं तत्परिमार्गितव्य    यस्मिन्गता न निवर्तन्ति भूयः।तमेव चाद्यं पुरुषं प्रपद्ये    यतः प्रवृत्तिः प्रसृता पुराणी","iast":"tataḥ padaṁ tat parimārgitavyaṁ\nyasmin gatā na nivartanti bhūyaḥ\ntam eva chādyaṁ puruṣhaṁ prapadye\nyataḥ pravṛittiḥ prasṛitā purāṇī","v":[{"k":"purohit","t":"Beyond lies the path, from which, once found, there is no return. This is the Primal God from whom this ancient creation has sprung."},{"k":"sivananda","t":"Then, that goal should be sought for, to which, having gone, none returns again. I seek refuge in that Primeval Purusha, from whence streamed forth the ancient activity or energy."},{"k":"adidevananda","t":"Then, one should seek that goal, attaining which one never returns. One should seek refuge with that Primal Person from whom this ancient activity streamed forth."},{"k":"gambirananda","t":"Thereafter, that state must be sought, going where they do not return again: I take refuge in that Primeval Person Himself, from whom the eternal Manifestation has ensued."},{"k":"sankaranarayan","t":"Then, that Abode must be sought, having reached which one would not return. The Yogin would attain nothing but that Primal Person, from Whom the old activity (world creation) commences."}]},{"ch":15,"vn":5,"dev":"निर्मानमोहा जितसङ्गदोषा    अध्यात्मनित्या विनिवृत्तकामाः।द्वन्द्वैर्विमुक्ताः सुखदुःखसंज्ञै    र्गच्छन्त्यमूढाः पदमव्ययं तत्","iast":"nirmāna-mohā jita-saṅga-doṣhā\nadhyātma-nityā vinivṛitta-kāmāḥ\ndvandvair vimuktāḥ sukha-duḥkha-sanjñair\ngachchhanty amūḍhāḥ padam avyayaṁ tat","v":[{"k":"purohit","t":"The wise attain Eternity when, freed from pride and delusion, they have conquered their love for the things of sense; when, renouncing desire and fixing their gaze on the Self, they cease to be tossed to and fro by the opposing sensations, such as pleasure and pain."},{"k":"sivananda","t":"Free from pride and delusion, victorious over the evil of attachment, dwelling constantly in the Self, their desires having completely turned away, freed from the pairs of opposites known as pleasure and pain, they, the undeluded, reach the eternal goal."},{"k":"adidevananda","t":"Without the delusion of perverse notions concerning the self, victorious over the evil of attachment, ever devoted to the Self, turned away from desires and liberated from dualities such as pleasure and pain, the undeluded go to that imperishable state."},{"k":"gambirananda","t":"The wise ones, free from pride and non-discrimination, who have conquered the evil of association [hatred and love arising from association with foes and friends], who are ever devoted to spirituality, completely free from desires, and free from the dualities of happiness and sorrow, reach that undecaying state."},{"k":"sankaranarayan","t":"Those who are rid of pride and delusion, have put down the evils of attachment, remain constantly in their own nature of the Self, have their desires completely departed, and are fully liberated from the pairs known as pleasures and pains—these undeluded men go to that changeless Abode."}]},{"ch":15,"vn":6,"dev":"न तद्भासयते सूर्यो न शशाङ्को न पावकः।यद्गत्वा न निवर्तन्ते तद्धाम परमं मम","iast":"na tad bhāsayate sūryo na śhaśhāṅko na pāvakaḥ\nyad gatvā na nivartante tad dhāma paramaṁ mama","v":[{"k":"purohit","t":"Neither the sun, nor the moon, nor fire shines there. Those who go there never come back. For, O Arjuna, that is my celestial home!"},{"k":"sivananda","t":"Neither does the sun illuminate there, nor the moon, nor the fire; having gone there, they do not return; that is My supreme abode."},{"k":"adidevananda","t":"That supreme light, upon reaching which they do not return any more, is Mine; neither the sun nor the moon nor the fire illuminates It."},{"k":"gambirananda","t":"Neither the sun nor the moon nor fire illuminates That. That is My supreme Abode, to which they do not return."},{"k":"sankaranarayan","t":"The sun does not illuminate That; nor the moon nor the fire; That is My Supreme Abode, having gone to Which they (Yogins) never return."}]},{"ch":15,"vn":7,"dev":"ममैवांशो जीवलोके जीवभूतः सनातनः।मनःषष्ठानीन्द्रियाणि प्रकृतिस्थानि कर्षति","iast":"mamaivānśho jīva-loke jīva-bhūtaḥ sanātanaḥ\nmanaḥ-ṣhaṣhṭhānīndriyāṇi prakṛiti-sthāni karṣhati","v":[{"k":"purohit","t":"It is only a very small part of My Eternal Self, which is the life of the universe, that draws around itself the six senses, with the mind being the last, which have their source in Nature."},{"k":"sivananda","t":"An eternal portion of Myself having become a living soul in the world of life, draws to itself the five senses, with the mind as the sixth, abiding in Nature."},{"k":"adidevananda","t":"An everlasting part of Myself, having become the bound self in the world of life, attracts the senses, of which the mind is the sixth, and which abide in Prakriti."},{"k":"gambirananda","t":"It is indeed a part of Mine that, becoming the eternal individual soul in the region of living beings, draws the organs, which have the mind as their sixth, and which abide in Nature."},{"k":"sankaranarayan","t":"A portion of My own Self, having become the eternal individual Soul in the world of the living beings, draws [into service] the sense organs, of which the sixth is the mind, and which rest in Prakriti."}]},{"ch":15,"vn":8,"dev":"शरीरं यदवाप्नोति यच्चाप्युत्क्रामतीश्वरः।गृहीत्वैतानि संयाति वायुर्गन्धानिवाशयात्","iast":"śharīraṁ yad avāpnoti yach chāpy utkrāmatīśhvaraḥ\ngṛihītvaitāni sanyāti vāyur gandhān ivāśhayāt","v":[{"k":"purohit","t":"When the Supreme Lord enters a body or leaves it, He gathers these senses together and travels with them, as the wind gathers perfume while passing through the flowers."},{"k":"sivananda","t":"When the Lord, as the individual soul, obtains a body and when He leaves it, He takes these with Him, just as the wind takes the scents from their seats (flowers, etc.)."},{"k":"adidevananda","t":"Whatever body its lord acquires and from whatever body it departs, it goes on its way, taking these senses as the wind carries scents from their places."},{"k":"gambirananda","t":"When the master leaves it and even when he assumes a body, he departs taking these with him, just as the wind carries away odours from their receptacles."},{"k":"sankaranarayan","t":"Whatever body He attains to and also from whatever He goes up, the Lord proceeds taking them with Him just as the wind takes odours from their receptacle."}]},{"ch":15,"vn":9,"dev":"श्रोत्रं चक्षुः स्पर्शनं च रसनं घ्राणमेव च।अधिष्ठाय मनश्चायं विषयानुपसेवते","iast":"śhrotraṁ chakṣhuḥ sparśhanaṁ cha rasanaṁ ghrāṇam eva cha\nadhiṣhṭhāya manaśh chāyaṁ viṣhayān upasevate","v":[{"k":"purohit","t":"He is the perception of the ear, the eye, the touch, the taste, the smell, and the mind; and the enjoyment of the things they perceive is also His."},{"k":"sivananda","t":"Presiding over the ears, eyes, touch, taste, smell, and mind, it enjoys the objects of the senses."},{"k":"adidevananda","t":"Presiding over the ear, the eye, the sense of touch, the tongue, the nose, and the mind, It experiences these objects of the senses."},{"k":"gambirananda","t":"This one enjoys the objects by presiding over the ears, eyes, skin, tongue, nose, and mind."},{"k":"sankaranarayan","t":"Presiding over the ear, the eye, the sense of touch, the sense of taste, the sense of smell, and the mind, He enjoys the sense objects."}]},{"ch":15,"vn":10,"dev":"उत्क्रामन्तं स्थितं वापि भुञ्जानं वा गुणान्वितम्।विमूढा नानुपश्यन्ति पश्यन्ति ज्ञानचक्षुषः","iast":"utkrāmantaṁ sthitaṁ vāpi bhuñjānaṁ vā guṇānvitam\nvimūḍhā nānupaśhyanti paśhyanti jñāna-chakṣhuṣhaḥ","v":[{"k":"purohit","t":"The ignorant do not see that it is He who is present in life and departs at death, or even that it is He who enjoys pleasure through the qualities. Only the eye of wisdom sees this."},{"k":"sivananda","t":"The deluded do not see Him who departs, stays, and enjoys; but those who possess the eye of knowledge behold Him."},{"k":"adidevananda","t":"The deluded do not perceive it conjoined with the Gunas when departing, staying, or experiencing. Those who have the eye of knowledge, however, see it."},{"k":"gambirananda","t":"Persons who are diversely deluded do not see it even when it is leaving, residing, experiencing, or in association with the qualities; those with the eye of knowledge see."},{"k":"sankaranarayan","t":"The deluded do not perceive Him; [but] the men of knowledge-eye do see Him, as He dwells, rises up, or enjoys what is endowed with strands."}]},{"ch":15,"vn":11,"dev":"यतन्तो योगिनश्चैनं पश्यन्त्यात्मन्यवस्थितम्।यतन्तोऽप्यकृतात्मानो नैनं पश्यन्त्यचेतसः","iast":"yatanto yoginaśh chainaṁ paśhyanty ātmany avasthitam\nyatanto 'py akṛitātmāno nainaṁ paśhyanty achetasaḥ","v":[{"k":"purohit","t":"The saints, with great effort, find Him within themselves; however, the unintelligent, despite their efforts, cannot control their minds."},{"k":"sivananda","t":"The yogis striving for perfection behold Him dwelling in the Self; but, the unrefined and unintelligent, even though striving, do not see Him."},{"k":"adidevananda","t":"The striving yogis perceive it established in themselves. But, though striving, those of unrefined minds, devoid of intelligence, do not perceive it."},{"k":"gambirananda","t":"And the diligent yogis see this one existing within themselves. The non-discriminating ones who lack self-control, however, do not see this one, even though they are diligent."},{"k":"sankaranarayan","t":"The exerting men of Yoga perceive Him dwelling in the Self; [however], the unintelligent men, with their uncontrolled selves, do not perceive Him, even though they exert."}]},{"ch":15,"vn":12,"dev":"यदादित्यगतं तेजो जगद्भासयतेऽखिलम्।यच्चन्द्रमसि यच्चाग्नौ तत्तेजो विद्धि मामकम्","iast":"yad āditya-gataṁ tejo jagad bhāsayate 'khilam\nyach chandramasi yach chāgnau tat tejo viddhi māmakam","v":[{"k":"purohit","t":"Remember that the light which proceeds from the sun, illuminating the whole world, and the light which is in the moon, and that which is in the fire, all are born of me."},{"k":"sivananda","t":"That light which resides in the sun, illuminating the whole world; that which is in the moon and in the fire—know that light to be Mine."},{"k":"adidevananda","t":"Know that the brilliance which illumines the whole universe in the sun, the moon, and fire is Mine."},{"k":"gambirananda","t":"That light in the sun which illuminates the whole world, that which is in the moon, and that which is in fire—know that light to be Mine."},{"k":"sankaranarayan","t":"That light which is found in the sun, which is in the moon, and which is also in fire—illuminating the entire world—know that light to be of Mine."}]},{"ch":15,"vn":13,"dev":"गामाविश्य च भूतानि धारयाम्यहमोजसा।पुष्णामि चौषधीः सर्वाः सोमो भूत्वा रसात्मकः","iast":"gām āviśhya cha bhūtāni dhārayāmy aham ojasā\npuṣhṇāmi chauṣhadhīḥ sarvāḥ somo bhūtvā rasātmakaḥ","v":[{"k":"purohit","t":"I enter this world and animate all My creatures with My vitality; and by My cool moonbeams, I nourish the plants."},{"k":"sivananda","t":"Permeating the earth, I support all beings with My energy; and having become the watery moon, I nourish all herbs."},{"k":"adidevananda","t":"And, entering the earth, I uphold all beings with My strength. I nourish all herbs, becoming the juicy Soma."},{"k":"gambirananda","t":"And entering the Earth, I sustain the beings through My power; and nourish all the plants by becoming Soma, which is of the nature of sap."},{"k":"sankaranarayan","t":"And, penetrating the earth, I support all beings with My energy; being the sap-filled moon, I nourish all plants."}]},{"ch":15,"vn":14,"dev":"अहं वैश्वानरो भूत्वा प्राणिनां देहमाश्रितः।प्राणापानसमायुक्तः पचाम्यन्नं चतुर्विधम्","iast":"ahaṁ vaiśhvānaro bhūtvā prāṇināṁ deham āśhritaḥ\nprāṇāpāna-samāyuktaḥ pachāmy annaṁ chatur-vidham","v":[{"k":"purohit","t":"Becoming the fire of life, I pass into their bodies and, uniting with the vital streams of Prāṇa and Apāna, I digest the various kinds of food."},{"k":"sivananda","t":"Having become the fire Vaisvanara, I abide in the bodies of living beings and, associated with the Prana and the Apana, digest the fourfold food."},{"k":"adidevananda","t":"Becoming the digestive fire, I function within the bodies of all living beings. In union with the inward and outward breath, I digest the four kinds of food."},{"k":"gambirananda","t":"Taking the form of Vaisvanara, and residing in the bodies of creatures, I, in association with Prana and Apana, digest the four kinds of food."},{"k":"sankaranarayan","t":"Being the digestive fire dwelling within the bodies of living creatures, and being in association with the upward and downward winds [of the body], I digest the four kinds of food."}]},{"ch":15,"vn":15,"dev":"सर्वस्य चाहं हृदि सन्निविष्टो    मत्तः स्मृतिर्ज्ञानमपोहनं च।वेदैश्च सर्वैरहमेव वेद्यो    वेदान्तकृद्वेदविदेव चाहम्","iast":"sarvasya chāhaṁ hṛidi sanniviṣhṭo\nmattaḥ smṛitir jñānam apohanaṁ cha\nvedaiśh cha sarvair aham eva vedyo\nvedānta-kṛid veda-vid eva chāham","v":[{"k":"purohit","t":"I am enthroned in the hearts of all; memory, wisdom, and discrimination owe their origins to Me. I am He Who is to be realized in the scriptures; I inspire their wisdom, and I know their truth."},{"k":"sivananda","t":"And I am seated in the hearts of all; from Me come memory and knowledge, as well as their absence. I am verily That which has to be known by all the Vedas; I am indeed the author of the Vedanta and the knower of the Vedas."},{"k":"adidevananda","t":"And I am seated in the hearts of all. From Me come memory, knowledge, and their removal too. Indeed, I alone am to be known from all the Vedas. I bring about the fruition of the Vedic rituals; I alone am the knower of the Vedas."},{"k":"gambirananda","t":"And I am seated in the hearts of all. From Me come memory, knowledge, and their loss. I alone am the object to be known through all the Vedas; I am also the originator of the Vedanta, and I Myself am the knower of the Vedas."},{"k":"sankaranarayan","t":"I am entered in the hearts of all; from Me come the faculties of memory, knowledge, and discernment; none but Me is to be known by means of all the Vedas, and I am alone the author of the final part of the Vedas and also the author of the Vedas themselves."}]},{"ch":15,"vn":16,"dev":"द्वाविमौ पुरुषौ लोके क्षरश्चाक्षर एव च।क्षरः सर्वाणि भूतानि कूटस्थोऽक्षर उच्यते","iast":"dvāv imau puruṣhau loke kṣharaśh chākṣhara eva cha\nkṣharaḥ sarvāṇi bhūtāni kūṭa-stho 'kṣhara uchyate","v":[{"k":"purohit","t":"There are two aspects in Nature: the perishable and the imperishable. All life in this world belongs to the former, while the unchanging element belongs to the latter."},{"k":"sivananda","t":"Two Purushas there are in this world: the perishable and the imperishable. All beings are perishable, and the Kutastha—the unchanging—is called the imperishable."},{"k":"adidevananda","t":"There are two kinds of persons spoken of in the sastra: the perishable (ksara) and the imperishable (aksara). All beings are perishable, while the imperishable is called the unchanging (kutastha)."},{"k":"gambirananda","t":"There are two kinds of people in the world: the mutable and the immutable. The mutable consists of all things; the one existing as Maya is referred to as the immutable."},{"k":"sankaranarayan","t":"There are two people in the world: the perishable and the imperishable. The perishable is all elements, and the one that speaks is called the imperishable."}]},{"ch":15,"vn":17,"dev":"उत्तमः पुरुषस्त्वन्यः परमात्मेत्युदाहृतः।यो लोकत्रयमाविश्य बिभर्त्यव्यय ईश्वरः","iast":"uttamaḥ puruṣhas tv anyaḥ paramātmety udāhṛitaḥ\nyo loka-trayam āviśhya bibharty avyaya īśhvaraḥ","v":[{"k":"purohit","t":"But I am higher than all, the Supreme God, the Absolute Self, the Eternal Lord, who pervades and upholds all the worlds."},{"k":"sivananda","t":"But distinct is the Supreme Purusha, called the highest Self, indestructible and Lord, who pervades the three worlds and sustains them."},{"k":"adidevananda","t":"There is a Supreme Person other than these. He is referred to as the Supreme Self (Paramatma) in all the Vedas. He, as the Immutable One and the Lord, enters the threefold world and supports it."},{"k":"gambirananda","t":"But the Supreme Person is different; He is spoken of as the transcendental Self, permeating the three worlds and upholding them, and He is the imperishable God."},{"k":"sankaranarayan","t":"But the Highest Person, distinct from both [this], is spoken of as the Supreme Self, which, being the changeless Lord, sustains the triad of the world by entering into it."}]},{"ch":15,"vn":18,"dev":"यस्मात्क्षरमतीतोऽहमक्षरादपि चोत्तमः।अतोऽस्मि लोके वेदे च प्रथितः पुरुषोत्तमः","iast":"yasmāt kṣharam atīto 'ham akṣharād api chottamaḥ\nato 'smi loke vede cha prathitaḥ puruṣhottamaḥ","v":[{"k":"purohit","t":"I am beyond comparison with the Eternal and the non-eternal; I am known as the Supreme Personality, the Highest God, by scriptures and sages."},{"k":"sivananda","t":"As I transcend the perishable and am even higher than the imperishable, I am declared to be the highest Purusha in the world and in the Vedas."},{"k":"adidevananda","t":"Because I transcend the perishable person and am also higher than the imperishable one, therefore I am referred to in the Smrti and the Veda as the Supreme Person (Purusotama)."},{"k":"gambirananda","t":"Since I am transcendental to the mutable and above even the immutable, therefore I am well known in the world and in the Vedas as the supreme Person."},{"k":"sankaranarayan","t":"Because I have transcended both the perishable and the imperishable, I am acclaimed in the world and in the Vedas as the highest of persons."}]},{"ch":15,"vn":19,"dev":"यो मामेवमसम्मूढो जानाति पुरुषोत्तमम्।स सर्वविद्भजति मां सर्वभावेन भारत","iast":"yo mām evam asammūḍho jānāti puruṣhottamam\nsa sarva-vid bhajati māṁ sarva-bhāvena bhārata","v":[{"k":"purohit","t":"He who, with unclouded vision, sees Me as the Lord-God, knows all that there is to be known and will always worship Me with his whole heart."},{"k":"sivananda","t":"He who, undeluded, knows Me as the highest Purusha, he, knowing all, worships Me with his whole being (heart), O Arjuna."},{"k":"adidevananda","t":"He who, without delusion, thus knows Me as the Supreme Self, knows all, O Arjuna, and worships Me in every way."},{"k":"gambirananda","t":"O scion of the Bharata dynasty, he who, being free from delusion, knows Me, the supreme Person, thus, is all-knowing and adores Me with his whole being."},{"k":"sankaranarayan","t":"He who, not being deluded, thus knows Me as the Highest of persons—he knows all and serves Me with his entire being, O descendant of Bharata!"}]},{"ch":15,"vn":20,"dev":"इति गुह्यतमं शास्त्रमिदमुक्तं मयाऽनघ।एतद्बुद्ध्वा बुद्धिमान्स्यात्कृतकृत्यश्च भारत","iast":"iti guhyatamaṁ śhāstram idam uktaṁ mayānagha\netad buddhvā buddhimān syāt kṛita-kṛityaśh cha bhārata","v":[{"k":"purohit","t":"Thus, O sinless one, I have revealed this most mystic knowledge to thee. He who understands it gains wisdom and attains the consummation of life."},{"k":"sivananda","t":"Thus, I have imparted to you this most secret science, O sinless one; by knowing this, one becomes wise, and all their duties are accomplished, O Arjuna."},{"k":"adidevananda","t":"Thus, O sinless one, this most mysterious doctrine has been imparted by Me. By understanding this, one will become truly wise and fulfill their duty."},{"k":"gambirananda","t":"O sinless one, I have thus uttered this most secret scripture. Understanding this, one becomes wise and fulfills their duties, O scion of the Bharata dynasty."},{"k":"sankaranarayan","t":"Thus, O sinless one, I have imparted to you the most secret scripture; by understanding this, let a man become wise and also become one who has accomplished what needs to be accomplished, O descendant of Bharata!"}]},{"ch":16,"vn":1,"dev":"श्री भगवानुवाच\nअभयं सत्त्वसंशुद्धिः ज्ञानयोगव्यवस्थितिः।\nदानं दमश्च यज्ञश्च स्वाध्यायस्तप आर्जवम्","iast":"śhrī-bhagavān uvācha\nabhayaṁ sattva-sanśhuddhir jñāna-yoga-vyavasthitiḥ\ndānaṁ damaśh cha yajñaśh cha svādhyāyas tapa ārjavam","v":[{"k":"purohit","t":"Lord Shri Krishna continued: Fearlessness, clean living, unceasing concentration on wisdom, readiness to give, self-control, a spirit of sacrifice, regular study of the scriptures, austerity, candor,"},{"k":"sivananda","t":"The Blessed Lord said: Fearlessness, purity of heart, steadfastness in knowledge and yoga, almsgiving, control of the senses, sacrifice, study of scriptures, austerity, and straightforwardness."},{"k":"adidevananda","t":"The Lord said, \"Fearlessness, purity of mind, devotion to meditation on the knowledge of the self, alms-giving, self-control, worship, study of the Vedas, austerity, and uprightness—"},{"k":"gambirananda","t":"The Blessed Lord said: Fearlessness, purity of mind, persistence in knowledge and yoga, charity, control of the external organs, sacrifice, scriptural study, austerity, and rectitude."},{"k":"sankaranarayan","t":"The Bhagavat said: Fearlessness, complete purity of the Sattva, steadfastness in knowledge-Yoga, charity, self-restraint, Vedic sacrifice, recitation of scriptures, austerity, and uprightness."}]},{"ch":16,"vn":2,"dev":"अहिंसा सत्यमक्रोधस्त्यागः शान्तिरपैशुनम्।दया भूतेष्वलोलुप्त्वं मार्दवं ह्रीरचापलम्","iast":"ahinsā satyam akrodhas tyāgaḥ śhāntir apaiśhunam\ndayā bhūteṣhv aloluptvaṁ mārdavaṁ hrīr achāpalam","v":[{"k":"purohit","t":"Harmlessness, truth, absence of wrath, renunciation, contentment, straightforwardness, compassion towards all, uncovetousness, courtesy, modesty, and constancy."},{"k":"sivananda","t":"Harmlessness, truth, absence of anger, renunciation, peacefulness, absence of crookedness, compassion for beings, non-covetousness, gentleness, modesty, and absence of fickleness."},{"k":"adidevananda","t":"Non-injury, truth, freedom from anger, renunciation, tranquility, non-slandering of others, compassion for all beings, freedom from desire, gentleness, a sense of shame, and freedom from fickleness;"},{"k":"gambirananda","t":"Non-injury, truthfulness, absence of anger, renunciation, control of the inner self, absence of vilification, kindness to creatures, non-covetousness, gentleness, modesty, and freedom from restlessness;"},{"k":"sankaranarayan","t":"Harmlessness, truth, absence of anger, renunciation, absence of attachment, absence of slander, compassion for living beings, and absence of greed, gentleness, modesty, and absence of thoughtlessness;"}]},{"ch":16,"vn":3,"dev":"तेजः क्षमा धृतिः शौचमद्रोहो नातिमानिता।\nभवन्ति सम्पदं दैवीमभिजातस्य भारत","iast":"tejaḥ kṣhamā dhṛitiḥ śhaucham adroho nāti-mānitā\nbhavanti sampadaṁ daivīm abhijātasya bhārata","v":[{"k":"purohit","t":"Valor, forgiveness, fortitude, purity, freedom from hate and vanity—these are the qualities of one who possesses the divine, O Arjuna!"},{"k":"sivananda","t":"Vigor, forgiveness, fortitude, purity, absence of hatred, absence of pride—these belong to one born for a divine state, O Arjuna."},{"k":"adidevananda","t":"Grandeur, patience, fortitude, purity, freedom from hatred and over-pride—these, O Arjuna, belong to one who is born to a divine destiny."},{"k":"gambirananda","t":"Vigour, forgiveness, fortitude, purity, freedom from malice, absence of haughtiness—these, O scion of the Bharata dynasty, are the qualities of one born destined to have the divine nature."},{"k":"sankaranarayan","t":"Vital power, forgiveness, fortitude, contentment, absence of treachery, and absence of excessive pride—these are in the person who is born for divine wealth, O Descendant of Bharata!"}]},{"ch":16,"vn":4,"dev":"दम्भो दर्पोऽभिमानश्च क्रोधः पारुष्यमेव च।अज्ञानं चाभिजातस्य पार्थ सम्पदमासुरीम्","iast":"dambho darpo 'bhimānaśh cha krodhaḥ pāruṣhyam eva cha\najñānaṁ chābhijātasya pārtha sampadam āsurīm","v":[{"k":"purohit","t":"Hypocrisy, pride, insolence, cruelty, and ignorance belong to those born of godless qualities."},{"k":"sivananda","t":"Hypocrisy, arrogance, and self-conceit, anger, harshness, and ignorance—these belong to one who is born for a demoniacal state, O Partha."},{"k":"adidevananda","t":"Pompousness, arrogance, self-conceit, wrath, rudeness, and ignorance—these, O Arjuna, belong to one who is born with a demonic destiny."},{"k":"gambirananda","t":"O son of Prtha, the attributes of one destined to have the demoniacal nature are religious ostentation, pride, haughtiness, self-conceit, anger, rudeness, and ignorance."},{"k":"sankaranarayan","t":"Ostentation, arrogance, pride, anger, and harshness, as well as ignorance, are characteristics of a person born of demoniac wealth, O son of Prtha!"}]},{"ch":16,"vn":5,"dev":"दैवी सम्पद्विमोक्षाय निबन्धायासुरी मता।मा शुचः सम्पदं दैवीमभिजातोऽसि पाण्डव","iast":"daivī sampad vimokṣhāya nibandhāyāsurī matā\nmā śhuchaḥ sampadaṁ daivīm abhijāto 'si pāṇḍava","v":[{"k":"purohit","t":"Godly qualities lead to liberation; godless ones lead to bondage. Do not be anxious, Prince! You have the Godly qualities."},{"k":"sivananda","t":"The divine nature is deemed conducive to liberation, and the demonic to bondage. Grieve not, O Arjuna, for you are born with divine endowments."},{"k":"adidevananda","t":"The divine destiny is said to lead to liberation, while the demoniac to bondage. Do not grieve, O Arjuna, for you are born with a divine destiny."},{"k":"gambirananda","t":"The divine nature is Liberation, while the demoniacal is considered to be an inevitable bondage. Do not grieve, O son of Pandu! You are destined to possess the divine nature."},{"k":"sankaranarayan","t":"The divine wealth is meant for total emancipation, and the demoniac one for complete bondage. Grieve not, O son of Pandu, for the divine wealth you are born."}]},{"ch":16,"vn":6,"dev":"द्वौ भूतसर्गौ लोकेऽस्मिन् दैव आसुर एव च।दैवो विस्तरशः प्रोक्त आसुरं पार्थ मे श्रृणु","iast":"dvau bhūta-sargau loke 'smin daiva āsura eva cha\ndaivo vistaraśhaḥ prokta āsuraṁ pārtha me śhṛiṇu","v":[{"k":"purohit","t":"No changes needed."},{"k":"sivananda","t":"There are two types of beings in this world: the divine and the demoniacal. The divine has been described at length; hear from Me, O Arjuna, about the demoniacal."},{"k":"adidevananda","t":"There are two types of beings in this world: the divine and the demoniac. The divine have been described at length. Hear from Me, O Arjuna, about the demoniac."},{"k":"gambirananda","t":"In this world, there are two kinds of creation of beings: the divine and the demoniacal. The divine has been spoken of elaborately. Hear about the demoniacal from Me, O son of Prtha."},{"k":"sankaranarayan","t":"There are two types of creations of beings in this world: the divine and the demoniac. The divine one has been described in detail; hear now the demoniac one from Me, O son of Prtha!"}]},{"ch":16,"vn":7,"dev":"प्रवृत्तिं च निवृत्तिं च जना न विदुरासुराः।न शौचं नापि चाचारो न सत्यं तेषु विद्यते","iast":"pravṛittiṁ cha nivṛittiṁ cha janā na vidur āsurāḥ\nna śhauchaṁ nāpi chāchāro na satyaṁ teṣhu vidyate","v":[{"k":"purohit","t":"The godless do not know how to act or renounce; they lack both purity and truth. They do not understand the right principles of conduct."},{"k":"sivananda","t":"The demoniacal do not know what to do and what to refrain from; they have neither purity, nor right conduct, nor truth."},{"k":"adidevananda","t":"The demoniacal men neither know action nor renunciation. They have no cleanliness, nor right conduct, nor truth."},{"k":"gambirananda","t":"Neither do the demoniacal persons understand what should be done and what should not be done; nor do they possess purity, good conduct, or truthfulness."},{"k":"sankaranarayan","t":"The demoniac do not know the origin and the dissolution; neither purity, nor good conduct, nor truth exists in them."}]},{"ch":16,"vn":8,"dev":"असत्यमप्रतिष्ठं ते जगदाहुरनीश्वरम्।अपरस्परसम्भूतं किमन्यत्कामहैतुकम्","iast":"asatyam apratiṣhṭhaṁ te jagad āhur anīśhvaram\naparaspara-sambhūtaṁ kim anyat kāma-haitukam","v":[{"k":"purohit","t":"They say the universe is an accident with no purpose and no God. Life is created through sexual union, a product of lust and nothing else."},{"k":"sivananda","t":"They say, \"This universe is without truth, without a moral basis, without a God, brought about by mutual union, with lust as its cause; what else?\""},{"k":"adidevananda","t":"They maintain: 'The universe is without truth, with no foundation, and without a Lord (Isvara). What else could exist without mutual causation? It has lust as its cause.'"},{"k":"gambirananda","t":"They say that the world is unreal, having no basis, and without a God. It is born of mutual union brought about by passion! What other cause could there be?"},{"k":"sankaranarayan","t":"They say that this world is without truth; has no basis; and has no Lord; this is not born on the basis of the mutual cause-and-effect-relation [of the things]; it has nothing [beyond] and has no cause."}]},{"ch":16,"vn":9,"dev":"एतां दृष्टिमवष्टभ्य नष्टात्मानोऽल्पबुद्धयः।प्रभवन्त्युग्रकर्माणः क्षयाय जगतोऽहिताः","iast":"etāṁ dṛiṣhṭim avaṣhṭabhya naṣhṭātmāno 'lpa-buddhayaḥ\nprabhavanty ugra-karmāṇaḥ kṣhayāya jagato 'hitāḥ","v":[{"k":"purohit","t":"Thinking thus, these degraded souls, these enemies of mankind—whose intelligence is negligible and whose deeds are monstrous—come into the world only to destroy."},{"k":"sivananda","t":"Holding this view, these ruined souls of small intellect and fierce deeds come forth as enemies of the world, intent on its destruction."},{"k":"adidevananda","t":"Holding this view, these men of lost souls and feeble understanding do cruel deeds, leading to the destruction of the world."},{"k":"gambirananda","t":"Holding onto this view, those of depraved character, poor intellect, and given to fearful and harmful actions, wax strong and bring ruin to the world."},{"k":"sankaranarayan","t":"Clinging to this view, the inauspicious men of ruined souls, poor intellect, and cruel deeds strive to destroy the world."}]},{"ch":16,"vn":10,"dev":"काममाश्रित्य दुष्पूरं दम्भमानमदान्विताः।मोहाद्गृहीत्वासद्ग्राहान्प्रवर्तन्तेऽशुचिव्रताः","iast":"kāmam āśhritya duṣhpūraṁ dambha-māna-madānvitāḥ\nmohād gṛihītvāsad-grāhān pravartante 'śhuchi-vratāḥ","v":[{"k":"purohit","t":"Giving themselves up to insatiable passions, hypocritically, self-sufficiently, and arrogantly, cherishing false conceptions founded on delusion, they work only to carry out their own unholy purposes."},{"k":"sivananda","t":"Filled with insatiable desires, full of hypocrisy, pride, and arrogance, holding evil ideas due to delusion, they work with impure intentions."},{"k":"adidevananda","t":"Turning to insatiable desires, seizing through delusion unjustly acquired wealth, and following impious vows, they act, full of ostentation, pride, and arrogance."},{"k":"gambirananda","t":"Giving themselves up to insatiable passion, filled with vanity, pride, and arrogance, adopting bad adjectives due to delusion, and having impure resolves, they engage in actions."},{"k":"sankaranarayan","t":"Holding to their insatiable desires, being possessed by hypocrisy, avarice, and pride, and holding evil intentions, these cruel men wander with impure resolves."}]},{"ch":16,"vn":11,"dev":"चिन्तामपरिमेयां च प्रलयान्तामुपाश्रिताः।कामोपभोगपरमा एतावदिति निश्िचताः","iast":"chintām aparimeyāṁ cha pralayāntām upāśhritāḥ\nkāmopabhoga-paramā etāvad iti niśhchitāḥ","v":[{"k":"purohit","t":"Poring anxiously over evil resolutions that only end in death, seeking only the gratification of desire as the highest goal, and seeing nothing beyond—"},{"k":"sivananda","t":"Giving themselves over to immeasurable cares that end only with death, regarding the gratification of lust as their highest aim, and feeling sure that that is all."},{"k":"adidevananda","t":"Obsessed by unlimited cares that end with dissolution, looking upon the enjoyment of desires as their highest aim, and convinced that this is all;"},{"k":"gambirananda","t":"Beset with innumerable cares that end only with death, holding that the enjoyment of desirable objects is the highest goal, they feel sure that this is all."},{"k":"sankaranarayan","t":"Adhering to their ultimate and unending anxiety; viewing the gratification of their desires as their highest goal; believing that this is all that exists;"}]},{"ch":16,"vn":12,"dev":"आशापाशशतैर्बद्धाः कामक्रोधपरायणाः।ईहन्ते कामभोगार्थमन्यायेनार्थसञ्चयान्","iast":"āśhā-pāśha-śhatair baddhāḥ kāma-krodha-parāyaṇāḥ\nīhante kāma-bhogārtham anyāyenārtha-sañchayān","v":[{"k":"purohit","t":"Caught in the toils of a hundred vain hopes, enslaved by passion and wrath, they accumulate hoards of unjust wealth, only to indulge their sensual desires."},{"k":"sivananda","t":"Bound by a hundred ties of hope, given over to lust and anger, they strive to obtain hoards of wealth by unlawful means for sensual enjoyment."},{"k":"adidevananda","t":"Bound by hundreds of fetters of hopes, given over to desire and anger, they strive unjustly to gather wealth for the gratification of their desires."},{"k":"gambirananda","t":"Bound by hundreds of shackles in the form of hope, giving themselves wholly to passion and anger, they endeavor to amass wealth through foul means for the enjoyment of desirable objects."},{"k":"sankaranarayan","t":"Bound by hundreds of ropes of longing, devoted to their desire and anger, they seek, by unjust means, hoards of wealth for the gratification of their desires."}]},{"ch":16,"vn":13,"dev":"इदमद्य मया लब्धमिमं प्राप्स्ये मनोरथम्।इदमस्तीदमपि मे भविष्यति पुनर्धनम्","iast":"idam adya mayā labdham imaṁ prāpsye manoratham\nidam astīdam api me bhaviṣhyati punar dhanam","v":[{"k":"purohit","t":"Today I have gained this; tomorrow I will fulfill another desire; this wealth is mine now, and the rest will soon be mine."},{"k":"sivananda","t":"\"I have gained this today; I will fulfill this desire of mine; this is mine, and this wealth will be mine in the future.\""},{"k":"adidevananda","t":"'This I have gained today, and this desire I shall attain. This wealth is mine, and this will also be mine hereafter."},{"k":"gambirananda","t":"'I have gained this today; I will acquire this desired object. This is in hand; and this wealth will also come to me.'"},{"k":"sankaranarayan","t":"'I have gained this today; I will attain this object of my desire in the future; this is mine now; and this wealth will also be mine soon.'"}]},{"ch":16,"vn":14,"dev":"असौ मया हतः शत्रुर्हनिष्ये चापरानपि।ईश्वरोऽहमहं भोगी सिद्धोऽहं बलवान्सुखी","iast":"asau mayā hataḥ śhatrur haniṣhye chāparān api\nīśhvaro 'ham ahaṁ bhogī siddho 'haṁ balavān sukhī","v":[{"k":"purohit","t":"I have slain one enemy; I will slay the others too. I am worthy of enjoying; I am the Almighty, perfect, powerful, and happy."},{"k":"sivananda","t":"\"I have slain that enemy, and I shall slay others too. I am the Lord; I enjoy, I am perfect, powerful, and happy.\""},{"k":"adidevananda","t":"'I have slain this enemy, and I shall slay others too. I am the Lord, the enjoyer, the successful one, the strong one, and the happy one.'"},{"k":"gambirananda","t":"'I have slain that enemy, and I shall slay others too. I am the Lord, the Enjoyer, firmly established, powerful and joyous.'"},{"k":"sankaranarayan","t":"'I have slain that enemy; and I shall slay others too; I am the Lord; I am a man of pleasure; I am victorious, powerful, and content.'"}]},{"ch":16,"vn":15,"dev":"आढ्योऽभिजनवानस्मि कोऽन्योऽस्ति सदृशो मया।यक्ष्ये दास्यामि मोदिष्य इत्यज्ञानविमोहिताः","iast":"āḍhyo 'bhijanavān asmi ko 'nyo 'sti sadṛiśho mayā\nyakṣhye dāsyāmi modiṣhya ity ajñāna-vimohitāḥ\naneka-chitta-vibhrāntā moha-jāla-samāvṛitāḥ\nprasaktāḥ kāma-bhogeṣhu patanti narake 'śhuchau","v":[{"k":"purohit","t":"I am wealthy, I am of noble birth; who can compare with me? I will sacrifice, I will give, I will pay—and I will enjoy. Thus blinded by ignorance,"},{"k":"sivananda","t":"\"I am wealthy and born into a noble family. Who is my equal? I shall perform sacrifices, give charity, and rejoice,\" thus deluded by ignorance."},{"k":"adidevananda","t":"'I am wealthy and high-born; who else is equal to me? I shall sacrifice, I shall give alms, I shall rejoice.' Thus they think, deluded by ignorance."},{"k":"gambirananda","t":"'I am wealthy and of noble birth; who else is like me? I shall perform sacrifices; I shall give, I shall rejoice'- thus, they are deluded by a lack of discernment in diverse ways."},{"k":"sankaranarayan","t":"'I am wealthy; I am of noble birth; who else is equal to me? I shall perform sacrifices; I shall give gifts; and I shall rejoice' - deluded by these wrong ideas;"}]},{"ch":16,"vn":16,"dev":"अनेकचित्तविभ्रान्ता मोहजालसमावृताः।प्रसक्ताः कामभोगेषु पतन्ति नरकेऽशुचौ","iast":"aneka-citta-vibhrāntā    moha-jāla-samāvṛtāḥ prasaktāḥ   kāma-bhogeṣu    patanti narake  'śucau","v":[{"k":"purohit","t":"Perplexed by discordant thoughts, entangled in the snares of desire, infatuated by passion, they sink into the depths of hell."},{"k":"sivananda","t":"Bewildered by many fancies, entangled in the snare of delusion, addicted to the gratification of lust, they fall into a foul hell."},{"k":"adidevananda","t":"Bewildered by numerous thoughts, ensnared in the net of delusion, addicted to sensual pleasures, they fall into a wretched Naraka."},{"k":"gambirananda","t":"Bewildered by numerous thoughts, ensnared in the net of delusion, and engrossed in the enjoyment of desirable objects, they fall into a foul hell."},{"k":"sankaranarayan","t":"Endowed with many thoughts, highly confused, enslaved by their delusion, and addicted to the gratification of desires, they fall into the hellish and foul."}]},{"ch":16,"vn":17,"dev":"आत्मसम्भाविताः स्तब्धा धनमानमदान्विताः।यजन्ते नामयज्ञैस्ते दम्भेनाविधिपूर्वकम्","iast":"ātma-sambhāvitāḥ stabdhā dhana-māna-madānvitāḥ\nyajante nāma-yajñais te dambhenāvidhi-pūrvakam","v":[{"k":"purohit","t":"Self-conceited, stubborn, wealthy, proud, and insolent, they make a show of their patronage, disregarding the norms of propriety."},{"k":"sivananda","t":"Self-conceited, stubborn, filled with pride and intoxication of wealth, they perform sacrifices in name only for ostentation, contrary to scriptural ordinances."},{"k":"adidevananda","t":"Self-conceited, self-sufficient, intoxicated by wealth and pride, they perform sacrifices in name only, ostentatiously and not according to the injunctions of the scriptures."},{"k":"gambirananda","t":"Self-conceited, haughty, filled with pride and intoxicated by wealth, they perform sacrifices that are only in name, ostentatiously and without regard for the injunctions."},{"k":"sankaranarayan","t":"Self-conceited, stubborn, filled with pride and arrogance of wealth, they pretend to perform sacrifices hypocritically, not following the injunctions of the Vedas."}]},{"ch":16,"vn":18,"dev":"अहङ्कारं बलं दर्पं कामं क्रोधं च संश्रिताः।मामात्मपरदेहेषु प्रद्विषन्तोऽभ्यसूयकाः","iast":"ahankāraṁ balaṁ darpaṁ kāmaṁ krodhaṁ cha sanśhritāḥ\nmām ātma-para-deheṣhu pradviṣhanto 'bhyasūyakāḥ","v":[{"k":"purohit","t":"Puffed up by power and inordinate conceit, swayed by lust and wrath, these wicked people hate Me, Who am within them as I am within all."},{"k":"sivananda","t":"Given over to egoism, power, haughtiness, lust, and anger, these malicious people hate Me in their own bodies and in the bodies of others."},{"k":"adidevananda","t":"Depending on their egoism, power, and pride, as well as their desires and wrath, these malicious men hate Me in their own bodies and in those of others."},{"k":"gambirananda","t":"Resorting to egotism, power, arrogance, passion, and anger, hating Me in their own and others' bodies, they become envious by nature."},{"k":"sankaranarayan","t":"Clinging fast to egotism, force, pride, craving, and anger, these envious people hate Me in the bodies of their own and of others."}]},{"ch":16,"vn":19,"dev":"तानहं द्विषतः क्रूरान्संसारेषु नराधमान्।क्षिपाम्यजस्रमशुभानासुरीष्वेव योनिषु","iast":"tān ahaṁ dviṣhataḥ krūrān sansāreṣhu narādhamān\nkṣhipāmy ajasram aśhubhān āsurīṣhv eva yoniṣhu","v":[{"k":"purohit","t":"Those who thus hate Me, who are cruel, the dregs of mankind, I condemn them to a continuous, miserable, and godless rebirth."},{"k":"sivananda","t":"Those cruel haters, the worst among men in the world, I hurl those evil-doers into the wombs of demons only."},{"k":"adidevananda","t":"Those who are hateful, cruel, the vilest and most inauspicious of mankind, I hurl forever into the cycles of births and deaths, into the wombs of demons."},{"k":"gambirananda","t":"I cast forever those hateful, cruel, evil-doers in the worlds, the vilest of human beings, verily into the demonic classes."},{"k":"sankaranarayan","t":"These hateful, cruel, and base men, I hurl incessantly into the inauspicious, demoniac wombs, alone in the cycle of birth and death."}]},{"ch":16,"vn":20,"dev":"असुरीं योनिमापन्ना मूढा जन्मनि जन्मनि।मामप्राप्यैव कौन्तेय ततो यान्त्यधमां गतिम्","iast":"āsurīṁ yonim āpannā mūḍhā janmani janmani\nmām aprāpyaiva kaunteya tato yānty adhamāṁ gatim","v":[{"k":"purohit","t":"So, reborn, they spend life after life enveloped in delusion, and they never reach Me, O Prince, but degenerate into even lower forms of life."},{"k":"sivananda","t":"Entering into demoniacal wombs and deluded, birth after birth, they do not attain Me, thus falling, O Arjuna, into a condition still lower than that."},{"k":"adidevananda","t":"Fallen into demoniac wombs in birth after birth, these deluded men, not attaining Me, further sink down to the lowest level, O Arjuna."},{"k":"gambirananda","t":"Being born among the demoniacal species in birth after birth, the souls, without ever reaching Me, O son of Kunti, attain conditions lower than that."},{"k":"sankaranarayan","t":"Having come to the demoniac womb, birth after birth, and not attaining Me at all, these deluded persons, therefore, pass to the lowest state, O son of Kunti!"}]},{"ch":16,"vn":21,"dev":"त्रिविधं नरकस्येदं द्वारं नाशनमात्मनः।कामः क्रोधस्तथा लोभस्तस्मादेतत्त्रयं त्यजेत्","iast":"tri-vidhaṁ narakasyedaṁ dvāraṁ nāśhanam ātmanaḥ\nkāmaḥ krodhas tathā lobhas tasmād etat trayaṁ tyajet","v":[{"k":"purohit","t":"The gates of hell are three: lust, wrath, and avarice; they destroy the Self, so avoid them."},{"k":"sivananda","t":"There are three gates to this hell, destructive of the self: lust, anger, and greed; therefore, one should abandon these three."},{"k":"adidevananda","t":"Desire, wrath, and greed—these are the three gateways to Naraka, ruinous to the self. Therefore, one should abandon these three."},{"k":"gambirananda","t":"This door to hell, which destroys the soul, is of three kinds—passion, anger, and greed. Therefore, one should forsake these three."},{"k":"sankaranarayan","t":"To the hell, there are three gates that ruin the Self: desire, anger, and greed. Hence, one should avoid these three."}]},{"ch":16,"vn":22,"dev":"एतैर्विमुक्तः कौन्तेय तमोद्वारैस्त्रिभिर्नरः।आचरत्यात्मनः श्रेयस्ततो याति परां गतिम्","iast":"etair vimuktaḥ kaunteya tamo-dvārais tribhir naraḥ\nācharaty ātmanaḥ śhreyas tato yāti parāṁ gatim","v":[{"k":"purohit","t":"These are the gates that lead to darkness; if one avoids them, they will ensure their own welfare and eventually attain liberation."},{"k":"sivananda","t":"A person who is liberated from these three gates of darkness, O Arjuna, practices what is beneficial for them and thus goes to the Supreme Goal."},{"k":"adidevananda","t":"One who has been released from these three gates of darkness, O Arjuna, works for the benefit of the self; thus, they reach the supreme state."},{"k":"gambirananda","t":"O son of Kunti, a person who is free from these three doors to darkness strives for the good of the soul; thereby, they attain the highest Goal."},{"k":"sankaranarayan","t":"O son of Kunti! A man who has deserted these three gates of darkness does what is good for his Self and thereby reaches the highest goal."}]},{"ch":16,"vn":23,"dev":"यः शास्त्रविधिमुत्सृज्य वर्तते कामकारतः।न स सिद्धिमवाप्नोति न सुखं न परां गतिम्","iast":"yaḥ śhāstra-vidhim utsṛijya vartate kāma-kārataḥ\nna sa siddhim avāpnoti na sukhaṁ na parāṁ gatim","v":[{"k":"purohit","t":"But he who neglects the commands of the scriptures and follows the promptings of passion does not attain perfection, happiness, or the final goal."},{"k":"sivananda","t":"He who, having cast aside the ordinances of the scriptures, acts under the impulse of desire, does not attain perfection, nor happiness, nor the Supreme Goal."},{"k":"adidevananda","t":"He who, abandoning the injunctions of the Sastras, acts under the influence of desire, attains neither perfection nor pleasure, nor the supreme state."},{"k":"gambirananda","t":"Ignoring the precepts of the scriptures, he who acts under the impulse of passion does not attain perfection, nor happiness, nor the supreme goal."},{"k":"sankaranarayan","t":"He who neglects the injunctions of the scriptures and acts according to his own will, attains neither success nor happiness nor the highest goal of emancipation."}]},{"ch":16,"vn":24,"dev":"तस्माच्छास्त्रं प्रमाणं ते कार्याकार्यव्यवस्थितौ।ज्ञात्वा शास्त्रविधानोक्तं कर्म कर्तुमिहार्हसि","iast":"tasmāch chhāstraṁ pramāṇaṁ te kāryākārya-vyavasthitau\njñātvā śhāstra-vidhānoktaṁ karma kartum ihārhasi","v":[{"k":"purohit","t":"Therefore, whenever there is doubt as to whether you should do something or not, let the scriptures guide your conduct. In the light of the scriptures, you should labor your whole life."},{"k":"sivananda","t":"Therefore, let the scripture be thy authority in determining what ought to be done and what ought not to be done. Having known what is said in the ordinance of the scriptures, thou shouldst act in this world."},{"k":"adidevananda","t":"Therefore, let the Sastra be your authority for determining what should be done and what should not be done. Knowing what is enjoined in the injunctions of the Sastra, you should perform work here."},{"k":"gambirananda","t":"Therefore, the scripture is your authority as regards determining what should be done and what should not be done. After understanding your duty as presented by scriptural injunction, you ought to perform it here."},{"k":"sankaranarayan","t":"Therefore, by considering the scripture as your authority in determining what should be done and what should not be done, you should perform actions laid down by the regulations of the scriptures."}]},{"ch":17,"vn":1,"dev":"अर्जुन उवाचये शास्त्रविधिमुत्सृज्य यजन्ते श्रद्धयाऽन्विताः।तेषां निष्ठा तु का कृष्ण सत्त्वमाहो रजस्तमः","iast":"arjuna uvācha\nye śhāstra-vidhim utsṛijya yajante śhraddhayānvitāḥ\nteṣhāṁ niṣhṭhā tu kā kṛiṣhṇa sattvam āho rajas tamaḥ","v":[{"k":"purohit","t":"Arjuna asked, \"My Lord, what is the condition of those who perform acts of sacrifice not according to the scriptures, but with implicit faith? Is it one of purity, passion, or ignorance?\""},{"k":"sivananda","t":"Arjuna said, \"What is the condition of those who, disregarding the injunctions of the scriptures, perform sacrifice with faith—is it Sattva, Rajas, or Tamas, O Krishna?\""},{"k":"adidevananda","t":"Arjuna said, \"Now, O Krsna, what is the position or basis of those who, despite leaving aside the injunction of the Sastra, still worship with faith? Is it Sattva, Rajas, or Tamas?\""},{"k":"gambirananda","t":"Arjuna said, But, O Krsna, what is the state of those who, endued with faith, perform sacrifices, distribute wealth, etc. in honour of gods and others, while ignoring the injunctions of the scriptures? Is it sattva, rajas, or tamas?"},{"k":"sankaranarayan","t":"Arjuna said: \"What is the state of those who remain faithful but neglect the scriptural injunctions—is it sattva, rajas, or tamas? O Krsna!\""}]},{"ch":17,"vn":2,"dev":"श्री भगवानुवाचत्रिविधा भवति श्रद्धा देहिनां सा स्वभावजा।सात्त्विकी राजसी चैव तामसी चेति तां श्रृणु","iast":"śhrī-bhagavān uvācha\ntri-vidhā bhavati śhraddhā dehināṁ sā svabhāva-jā\nsāttvikī rājasī chaiva tāmasī cheti tāṁ śhṛiṇu","v":[{"k":"purohit","t":"Lord Shri Krishna replied: Man has an inherent faith in one or another of the qualities—purity, passion, and ignorance. Now, listen."},{"k":"sivananda","t":"The Blessed Lord said, \"There are threefold faiths inherent in the nature of the embodied: the sattvic (pure), the rajasic (passionate), and the tamasic (dark). Hear of them.\""},{"k":"adidevananda","t":"The Lord said, \"The faith of embodied beings is threefold, born of their own nature and constituted of Sattva, Rajas, and Tamas. Now, listen to me about it.\""},{"k":"gambirananda","t":"The Blessed Lord said, \"That faith of the embodied beings, born of their own nature, is threefold—born of sattva, rajas, and tamas. Hear about it.\""},{"k":"sankaranarayan","t":"The Bhagavat said, \"The faith of the embodied persons is born of their nature and is of three kinds [viz.]: that which is made of Sattva; that which is made of Rajas; and that which is made of Tamas. Listen about them.\""}]},{"ch":17,"vn":3,"dev":"सत्त्वानुरूपा सर्वस्य श्रद्धा भवति भारत।श्रद्धामयोऽयं पुरुषो यो यच्छ्रद्धः स एव सः","iast":"sattvānurūpā sarvasya śhraddhā bhavati bhārata\nśhraddhā-mayo 'yaṁ puruṣho yo yach-chhraddhaḥ sa eva saḥ","v":[{"k":"purohit","t":"Every person's faith conforms to their nature. By nature, they are full of faith. They are, in fact, what their faith makes them."},{"k":"sivananda","t":"The faith of each is in accordance with their nature, O Arjuna. People consist of their faith; as a person's faith is, so are they."},{"k":"adidevananda","t":"O Arjuna, the faith of everyone is in accordance with their inner organ (Antahkarana). Each person consists of faith; whatever their faith is, that is who they are."},{"k":"gambirananda","t":"O scion of the Bharata dynasty, the faith of all beings is in accordance with their minds. This person is composed of faith as the dominant factor. He is indeed what his faith is."},{"k":"sankaranarayan","t":"Corresponding to one's own sattva, O descendant of Bharata, everybody has faith. The person predominantly consists of faith. Whatever one has faith in, that he becomes certainly."}]},{"ch":17,"vn":4,"dev":"यजन्ते सात्त्विका देवान्यक्षरक्षांसि राजसाः।प्रेतान्भूतगणांश्चान्ये यजन्ते तामसा जनाः","iast":"yajante sāttvikā devān yakṣha-rakṣhānsi rājasāḥ\npretān bhūta-gaṇānśh chānye yajante tāmasā janāḥ","v":[{"k":"purohit","t":"The pure worship the true God; the passionate, the powers of wealth and magic; the ignorant, the spirits of the dead and lower orders of nature."},{"k":"sivananda","t":"The sattvic, or pure, men worship the gods; the rajasic, or passionate, worship the yakshas and rakshasas; the others, the tamasic or deluded people, worship ghosts and hosts of nature-spirits."},{"k":"adidevananda","t":"The sattvic types worship the gods; the rajasic types worship yaksas and rakshasas; and the others, the tamasic types, worship the departed ancestors and hosts of bhutas."},{"k":"gambirananda","t":"Those with sattva quality worship the gods; those with rajas, the demigods and demons; and those with tamas, ghosts and hosts of spirits."},{"k":"sankaranarayan","t":"The men of the Sattva strand perform sacrifices intending for the gods; the men of the Rajas strand do so for the spirits and demons; and the men of the Tamas strand perform sacrifices intending for the imps, the dead, and the ghosts."}]},{"ch":17,"vn":5,"dev":"अशास्त्रविहितं घोरं तप्यन्ते ये तपो जनाः।दम्भाहङ्कारसंयुक्ताः कामरागबलान्विताः","iast":"aśhāstra-vihitaṁ ghoraṁ tapyante ye tapo janāḥ\ndambhāhankāra-sanyuktāḥ kāma-rāga-balānvitāḥ","v":[{"k":"purohit","t":"Those who practice austerities not commanded by scripture, who are enslaved to hypocrisy and egotism, who are carried away by the fury of desire and passion,"},{"k":"sivananda","t":"Those men who practice terrific austerities not prescribed by the scriptures, given to hypocrisy and egoism, driven by the force of lust and attachment."},{"k":"adidevananda","t":"Those men who practice terrible austerities not enjoined by the scriptures, given to ostentation and conceit, and prompted by the force of sensual desires and passions;"},{"k":"gambirananda","t":"Those persons who, given to ostentation and pride, and possessed of passion, attachment, and strength, undertake severe austerities not sanctioned by the scriptures;"},{"k":"sankaranarayan","t":"Those men who practise terrible austerities not as enjoined in the scriptures, who are bound by hypocrisy and conceit, and are impelled by the force of passion for desired objects;"}]},{"ch":17,"vn":6,"dev":"कर्षयन्तः शरीरस्थं भूतग्राममचेतसः।मां चैवान्तःशरीरस्थं तान्विद्ध्यासुरनिश्चयान्","iast":"karṣhayantaḥ śharīra-sthaṁ bhūta-grāmam achetasaḥ\nmāṁ chaivāntaḥ śharīra-sthaṁ tān viddhy āsura-niśhchayān","v":[{"k":"purohit","t":"They are ignorant and torment the organs of the body, harassing Me who lives within. Know that they are devoted to evil."},{"k":"sivananda","t":"Know thou these to be of demonical resolves, senselessly torturing all the elements in the body and Me who dwell in the body."},{"k":"adidevananda","t":"These foolish men, who torture the group of elements in their bodies and Me, who dwell within the body—know them to be demoniacal in their resolves."},{"k":"gambirananda","t":"(And those who,) being non-discriminating, torture all the organs in the body as well as even Me who reside in the body—know them to be possessed of demoniacal conviction."},{"k":"sankaranarayan","t":"Those who unintelligently emaciate the conglomeration of elements in their physical body and emaciate Me, dwelling within the physical body—know them to be of a demoniac resolve."}]},{"ch":17,"vn":7,"dev":"आहारस्त्वपि सर्वस्य त्रिविधो भवति प्रियः।यज्ञस्तपस्तथा दानं तेषां भेदमिमं श्रृणु","iast":"āhāras tv api sarvasya tri-vidho bhavati priyaḥ\nyajñas tapas tathā dānaṁ teṣhāṁ bhedam imaṁ śhṛiṇu","v":[{"k":"purohit","t":"The food that people enjoy is also threefold, like the ways of sacrifice, austerity, and almsgiving. Listen to the distinction."},{"k":"sivananda","t":"The food that is dear to each is threefold, as well as sacrifice, austerity, and almsgiving. Hear the distinction of these."},{"k":"adidevananda","t":"Even the food that is dear to all is threefold; so too are sacrifices, austerities, and gifts. Listen to this distinction among them."},{"k":"gambirananda","t":"Food, which is dear to all, is of three kinds; likewise, sacrifices, austerity, and charity are also of three kinds. Listen to this classification of them."},{"k":"sankaranarayan","t":"Further, the food which is dear to all is of three kinds. So too are their sacrifice, austerity, and charity. Listen to this distinction of them."}]},{"ch":17,"vn":8,"dev":"आयुःसत्त्वबलारोग्यसुखप्रीतिविवर्धनाः।रस्याः स्निग्धाः स्थिरा हृद्या आहाराः सात्त्विकप्रियाः","iast":"āyuḥ-sattva-balārogya-sukha-prīti-vivardhanāḥ\nrasyāḥ snigdhāḥ sthirā hṛidyā āhārāḥ sāttvika-priyāḥ","v":[{"k":"purohit","t":"The foods that prolong life, increase purity, vigour, health, cheerfulness, and happiness are those that are delicious, soothing, substantial, and agreeable; these are loved by the pure."},{"k":"sivananda","t":"The foods that increase life, purity, strength, health, joy, and cheerfulness (good appetite), which are savory, oily, substantial, and agreeable, are dear to the Sattvic (pure) people."},{"k":"adidevananda","t":"Foods that promote longevity, intellectual alertness, strength, health, pleasure, and happiness, and those that are sweet, oily, substantial, and agreeable, are dear to sattvic men."},{"k":"gambirananda","t":"Foods that augment life, firmness of mind, strength, health, happiness, and delight, and which are succulent, oleaginous, substantial, and agreeable, are dear to one endowed with sattva."},{"k":"sankaranarayan","t":"The foods that increase life, energy, strength, good health, happiness, and satisfaction; which are delicious, soft, substantial, and pleasant to the heart (stomach); they are dear to the men of the Sattva strand."}]},{"ch":17,"vn":9,"dev":"कट्वम्ललवणात्युष्णतीक्ष्णरूक्षविदाहिनः।आहारा राजसस्येष्टा दुःखशोकामयप्रदाः","iast":"kaṭv-amla-lavaṇāty-uṣhṇa- tīkṣhṇa-rūkṣha-vidāhinaḥ\nāhārā rājasasyeṣhṭā duḥkha-śhokāmaya-pradāḥ","v":[{"k":"purohit","t":"Those in whom passion is dominant like foods that are bitter, sour, salty, overly hot, pungent, dry, and burning. These produce unhappiness, repentance, and disease."},{"k":"sivananda","t":"The foods that are bitter, sour, salty, overly hot, pungent, dry, and burning are liked by the Rajasic and are productive of pain, grief, and disease."},{"k":"adidevananda","t":"Foods that are bitter, sour, very salty, excessively heating, highly pungent, dry, and burning are all dear to Rajasika men; they cause pain, sorrow, and disease."},{"k":"gambirananda","t":"Foods that are bitter, sour, salty, very hot, pungent, dry, and burning, producing pain, sorrow, and disease, are dear to one who has rajas."},{"k":"sankaranarayan","t":"The foods killed by men of the Rajas strand are those that are bitter, sour, salty, very hot, harsh, dry, and burning; and which cause pain, grief, and disease."}]},{"ch":17,"vn":10,"dev":"यातयामं गतरसं पूति पर्युषितं च यत्।उच्छिष्टमपि चामेध्यं भोजनं तामसप्रियम्","iast":"yāta-yāmaṁ gata-rasaṁ pūti paryuṣhitaṁ cha yat\nuchchhiṣhṭam api chāmedhyaṁ bhojanaṁ tāmasa-priyam","v":[{"k":"purohit","t":"The ignorant love food that is stale, not nourishing, putrid, and corrupt; the leftovers of others, and unclean."},{"k":"sivananda","t":"That which is stale, tasteless, putrid, rotten, rejected, and impure is the food liked by the Tamasic."},{"k":"adidevananda","t":"That food which is stale, tasteless, putrid, decayed, rejected, unclean, is dear to those of a Tamasic nature."},{"k":"gambirananda","t":"Food that is not properly cooked, lacking in essence, putrid and stale, as well as that which is unfit for sacrifice, is dear to one possessed of tamas."},{"k":"sankaranarayan","t":"What is old, tasteless, foul-smelling, and stale; what is also left over after eating, and is impure - such food is dear to the men of Tamas (Strand)."}]},{"ch":17,"vn":11,"dev":"अफलाकाङ्क्षिभिर्यज्ञो विधिदृष्टो य इज्यते।यष्टव्यमेवेति मनः समाधाय स सात्त्विकः","iast":"aphalākāṅkṣhibhir yajño vidhi-driṣhṭo ya ijyate\nyaṣhṭavyam eveti manaḥ samādhāya sa sāttvikaḥ","v":[{"k":"purohit","t":"Sacrifice is pure when it is offered by one who does not covet the fruit of it, when it is done according to the commands of scripture, and with implicit faith that the sacrifice is a duty."},{"k":"sivananda","t":"That sacrifice which is offered by men without desire for reward, as enjoined by the ordinance (scripture), with a firm faith that doing so is their duty, is Sattvic or pure."},{"k":"adidevananda","t":"The sacrifice (worship) marked by Sattva is what is offered by those who desire no fruit and have the conviction that it should be performed as prescribed in the scriptures."},{"k":"gambirananda","t":"That sacrifice which is in accordance with the injunctions, performed by persons who do not hanker after results, and with the mental conviction that it is surely obligatory, is done through sattva."},{"k":"sankaranarayan","t":"That sacrifice of the Sattva (Strand) is offered, as prescribed, by those who desire no reward, steadying their minds with the thought that it is simply something to be offered."}]},{"ch":17,"vn":12,"dev":"अभिसंधाय तु फलं दम्भार्थमपि चैव यत्।इज्यते भरतश्रेष्ठ तं यज्ञं विद्धि राजसम्","iast":"abhisandhāya tu phalaṁ dambhārtham api chaiva yat\nijyate bharata-śhreṣhṭha taṁ yajñaṁ viddhi rājasam","v":[{"k":"purohit","t":"Sacrifice which is performed for the sake of its results, or for self-glorification - that, O best of Aryans, is the product of passion."},{"k":"sivananda","t":"The sacrifice that is offered, O Arjuna, seeking a reward and for show, know that to be a Rajasic Yajna."},{"k":"adidevananda","t":"But that sacrifice which is offered with the intention of gaining a reward and for the sake of show, know it, O Arjuna, to be Rajasic."},{"k":"gambirananda","t":"But that sacrifice which is performed with an aim for a result, as well as for show—know that sacrifice to be done through rajas, O greatest among the descendants of Bharata."},{"k":"sankaranarayan","t":"What is offered aiming at fruit and also only for the sake of display—know that sacrifice to be of the Rajas strand and to be transitory and impermanent."}]},{"ch":17,"vn":13,"dev":"विधिहीनमसृष्टान्नं मन्त्रहीनमदक्षिणम्।श्रद्धाविरहितं यज्ञं तामसं परिचक्षते","iast":"vidhi-hīnam asṛiṣhṭānnaṁ mantra-hīnam adakṣhiṇam\nśhraddhā-virahitaṁ yajñaṁ tāmasaṁ parichakṣhate","v":[{"k":"purohit","t":"Sacrifice that is contrary to scriptural command, that is unaccompanied by prayers or gifts of food or money, and is without faith—that is the product of ignorance."},{"k":"sivananda","t":"They declare that sacrifice to be Tamasic which is contrary to the ordinances of the scriptures, in which no food is distributed, and which is devoid of mantras, gifts, and faith."},{"k":"adidevananda","t":"That sacrifice which is devoid of authority, which uses offerings not sanctioned by the Sastras, which is performed without recitation of hymns and devoid of gifts and faith - that, they say, is marked by Tamas."},{"k":"gambirananda","t":"They declare that sacrifice as 'done through tamas' which is contrary to injunction, in which no food is distributed, in which no mantras are used, in which no offerings are made to priests, and which is devoid of faith."},{"k":"sankaranarayan","t":"They declare that sacrifice to be of the Tamas (Strand) which is devoid of scriptural injunction, in which there is no recitation of Vedic hymns, where no food and sacrificial fee are distributed, and which is completely devoid of faith."}]},{"ch":17,"vn":14,"dev":"देवद्विजगुरुप्राज्ञपूजनं शौचमार्जवम्।ब्रह्मचर्यमहिंसा च शारीरं तप उच्यते","iast":"deva-dwija-guru-prājña- pūjanaṁ śhaucham ārjavam\nbrahmacharyam ahinsā cha śhārīraṁ tapa uchyate","v":[{"k":"purohit","t":"Worship of God and the Master; respect for the preacher and the philosopher; purity, rectitude, continence, and harmlessness—all of these constitute physical austerity."},{"k":"sivananda","t":"Worship of the gods, the twice-born, the teachers, and the wise; purity, straightforwardness, celibacy, and non-injury are all called the austerities of the body."},{"k":"adidevananda","t":"Worshiping the gods, the twice-born, the preceptors, the enlightened ones, practicing purity, uprightness, continence, and non-injury—these are called austerity of the body."},{"k":"gambirananda","t":"The worship of gods, twice-borns, venerable persons, and the wise; purity, straightforwardness, celibacy, and non-injury—these are said to be bodily austerities."},{"k":"sankaranarayan","t":"The worship of the gods, the twice-born, the elders, and the wise; purity, honesty, continence, and harmlessness—all this is said to be bodily austerity."}]},{"ch":17,"vn":15,"dev":"अनुद्वेगकरं वाक्यं सत्यं प्रियहितं च यत्।स्वाध्यायाभ्यसनं चैव वाङ्मयं तप उच्यते","iast":"anudvega-karaṁ vākyaṁ satyaṁ priya-hitaṁ cha yat\nsvādhyāyābhyasanaṁ chaiva vāṅ-mayaṁ tapa uchyate","v":[{"k":"purohit","t":"Speech that hurts no one, that is true, pleasant to listen to, and beneficial, and the constant study of the scriptures—this is austerity of speech."},{"k":"sivananda","t":"Speech that causes no excitement, is truthful, pleasant, and beneficial; the practice of studying the Vedas is called austerity of speech."},{"k":"adidevananda","t":"Speech that causes no shock, is true, pleasant, and beneficial, and also the practice of reciting scriptures, is called the austerity of speech."},{"k":"gambirananda","t":"That speech which causes no pain, which is true, agreeable, and beneficial; as well as the practice of studying the scriptures—is said to be the austerity of speech."},{"k":"sankaranarayan","t":"The unoffending speech which is true, pleasant, and beneficial; as well as the practice of regular recitation of the Vedas—all this is said to be an austerity of the speech-sense."}]},{"ch":17,"vn":16,"dev":"मनःप्रसादः सौम्यत्वं मौनमात्मविनिग्रहः।भावसंशुद्धिरित्येतत्तपो मानसमुच्यते","iast":"manaḥ-prasādaḥ saumyatvaṁ maunam ātma-vinigrahaḥ\nbhāva-sanśhuddhir ity etat tapo mānasam uchyate","v":[{"k":"purohit","t":"Serenity, kindness, silence, self-control, and purity—these are the austerities of the mind."},{"k":"sivananda","t":"Serenity of mind, good-heartedness, self-control, and purity of nature—this is called mental austerity."},{"k":"adidevananda","t":"Serenity of mind, benevolence, silence, self-control, and purity of mind—these are known as austerity of the mind."},{"k":"gambirananda","t":"Tranquility of mind, gentleness, reticence, withdrawal of the mind, purity of heart—these are what are called mental austerities."},{"k":"sankaranarayan","t":"The serenity of mind, the stillness, the taciturnity, the self-control, the purity of thought—all this is called mental austerity."}]},{"ch":17,"vn":17,"dev":"श्रद्धया परया तप्तं तपस्तत्ित्रविधं नरैः।अफलाकाङ्क्षिभिर्युक्तैः सात्त्विकं परिचक्षते","iast":"śhraddhayā parayā taptaṁ tapas tat tri-vidhaṁ naraiḥ\naphalākāṅkṣhibhir yuktaiḥ sāttvikaṁ parichakṣhate","v":[{"k":"purohit","t":"These threefold austerities, performed with faith and without thought of reward, can truly be considered pure."},{"k":"sivananda","t":"This threefold austerity, practiced by steadfast men, with the utmost faith, desiring no reward, is called Sattvic."},{"k":"adidevananda","t":"The threefold austerity, practiced with supreme faith by men who desire no fruit and are devoted—they call it austerity of Sattva."},{"k":"gambirananda","t":"When that threefold austerity is undertaken with supreme faith by people who do not hanker after results and are self-controlled, they speak of it as being born of sattva."},{"k":"sankaranarayan","t":"This three-fold austerity, observed with best faith, by men who are masters of Yoga and have no desire for its fruits—they call it to be of the Sattva."}]},{"ch":17,"vn":18,"dev":"सत्कारमानपूजार्थं तपो दम्भेन चैव यत्।क्रियते तदिह प्रोक्तं राजसं चलमध्रुवम्","iast":"satkāra-māna-pūjārthaṁ tapo dambhena chaiva yat\nkriyate tad iha proktaṁ rājasaṁ chalam adhruvam","v":[{"k":"purohit","t":"Austerity coupled with hypocrisy, or performed for the sake of self-glorification, popularity, or vanity, comes from passion, and its result is always uncertain and temporary."},{"k":"sivananda","t":"The austerity that is practiced with the aim of gaining good reception, honor, and worship, and with hypocrisy, is said to be Rajasic, unstable, and transient."},{"k":"adidevananda","t":"That austerity, practiced with ostentation for the sake of gaining respect, praise, and reverence, is here said to be Rajasa. It is unsteady and impermanent."},{"k":"gambirananda","t":"That austerity which is undertaken for earning a name, being honored and worshipped, and also ostentatiously—that is spoken of as born of rajas, belonging to this world, uncertain, and transitory."},{"k":"sankaranarayan","t":"The austerity that is practiced for gaining respect, honor, and reverence, and with sheer show—that is called here [austerity] of the Rajas, and it is unstable and impermanent."}]},{"ch":17,"vn":19,"dev":"मूढग्राहेणात्मनो यत्पीडया क्रियते तपः।परस्योत्सादनार्थं वा तत्तामसमुदाहृतम्","iast":"mūḍha-grāheṇātmano yat pīḍayā kriyate tapaḥ\nparasyotsādanārthaṁ vā tat tāmasam udāhṛitam","v":[{"k":"purohit","t":"Austerity done under delusion, and accompanied with sorcery or the infliction of pain upon oneself or another, may be assumed to spring from ignorance."},{"k":"sivananda","t":"That austerity which is practised out of a foolish notion, with self-torture, or for the purpose of destroying another, is declared to be of the Tamasic nature."},{"k":"adidevananda","t":"That austerity which is practised from deluded notions by means of self-torture or to injure another is said to be Tamasika."},{"k":"gambirananda","t":"That austerity which is undertaken with a foolish intent, causing pain to oneself or for the destruction of others, is said to be born of tamas."},{"k":"sankaranarayan","t":"What austerity is practised with foolish obstinacy and self-torture only in order to destroy others—that is declared to be of the Tamas."}]},{"ch":17,"vn":20,"dev":"दातव्यमिति यद्दानं दीयतेऽनुपकारिणे।देशे काले च पात्रे च तद्दानं सात्त्विकं स्मृतम्","iast":"dātavyam iti yad dānaṁ dīyate 'nupakāriṇe\ndeśhe kāle cha pātre cha tad dānaṁ sāttvikaṁ smṛitam","v":[{"k":"purohit","t":"The gift that is given without thought of recompense, believing it should be made, in an appropriate place, at an opportune time, and to a deserving person—such a gift is pure."},{"k":"sivananda","t":"That gift which is given to one who does nothing in return, knowing it to be a duty to give in a suitable place and time to a worthy person, is held to be Sattvic."},{"k":"adidevananda","t":"Gifts given with the feeling that it is one's own duty to give, to one who makes no return, at the proper place and time to the deserving person—that is said to be sattvika."},{"k":"gambirananda","t":"That gift is referred to as born of sattva which is given with the idea that it should be given, to one who will not serve in return, at the right place, right time, and to the right person."},{"k":"sankaranarayan","t":"A gift that is given with the thought that 'one must give' and is given in an appropriate place and at the right time to a worthy person who is unable to repay—that gift is considered to be of the Sattva."}]},{"ch":17,"vn":21,"dev":"यत्तु प्रत्युपकारार्थं फलमुद्दिश्य वा पुनः।दीयते च परिक्लिष्टं तद्दानं राजसं स्मृतम्","iast":"yat tu pratyupakārārthaṁ phalam uddiśhya vā punaḥ\ndīyate cha parikliṣhṭaṁ tad dānaṁ rājasaṁ smṛitam","v":[{"k":"purohit","t":"That which is given for the sake of the results it will produce, or with the hope of recompense, or grudgingly—that may truly be said to be the outcome of passion."},{"k":"sivananda","t":"And, that gift which is given with the intention of receiving something in return, or expecting a reward, or begrudgingly, is considered to be Rajasic."},{"k":"adidevananda","t":"But that which is given as a consideration for something received or in expectation of a future reward, or grudgingly, is called a Rajasika gift."},{"k":"gambirananda","t":"But the gift which is given expecting reciprocation, or with a desire for its result, and grudgingly, is considered to be born of rajas."},{"k":"sankaranarayan","t":"But what is given in return for a favor, or with the expectation of a reward, and which is done with much agitation—that gift is said to be of the Rajas."}]},{"ch":17,"vn":22,"dev":"अदेशकाले यद्दानमपात्रेभ्यश्च दीयते।असत्कृतमवज्ञातं तत्तामसमुदाहृतम्","iast":"adeśha-kāle yad dānam apātrebhyaśh cha dīyate\nasat-kṛitam avajñātaṁ tat tāmasam udāhṛitam","v":[{"k":"purohit","t":"And that which is given at an inappropriate place or time or to one who is undeserving, or with disrespect or contempt - such a gift is the result of ignorance."},{"k":"sivananda","t":"The gift that is given in the wrong place and at the wrong time, to unworthy persons, without respect or with insult, is declared to be of a Tamasic nature."},{"k":"adidevananda","t":"That gift which is given at the wrong place, wrong time, to an unworthy recipient, without due respect and with contempt, is called the gift of a Tamasa nature."},{"k":"gambirananda","t":"The gift which is made at an inappropriate place and time, and to undeserving persons, without proper respect and with disdain, is declared to be born of tamas."},{"k":"sankaranarayan","t":"The gift which is given at an inappropriate place, time, and to unworthy persons, and which is converted into a bad act and is disrespected—that is declared to be of the Tamas."}]},{"ch":17,"vn":23,"dev":"तत्सदिति निर्देशो ब्रह्मणस्त्रिविधः स्मृतः।ब्राह्मणास्तेन वेदाश्च यज्ञाश्च विहिताः पुरा","iast":"oṁ tat sad iti nirdeśho brahmaṇas tri-vidhaḥ smṛitaḥ\nbrāhmaṇās tena vedāśh cha yajñāśh cha vihitāḥ purā","v":[{"k":"purohit","t":"Om Tat Sat is the triple designation of the Eternal Spirit, by which the Vedic Scriptures, ceremonials, and sacrifices were ordained of old."},{"k":"sivananda","t":"\"Om Tat Sat\": This has been declared to be the triple designation of Brahman. By that, the Brahmanas, the Vedas, and the sacrifices were created formerly."},{"k":"adidevananda","t":"Om, Tat, Sat—thus, Brahman is denoted by this threefold expression. In the past, Brahmanas, the Vedas, and sacrifices were ordained in association with these."},{"k":"gambirananda","t":"\"Om-tat-sat\" - this is considered to be the threefold designation of Brahman. The Brahmanas, Vedas, and sacrifices were ordained by that in days of yore."},{"k":"sankaranarayan","t":"OM TAT SAT: This is held to be the three-fold indication of Brahman. Through this, the Vedas and sacrifices were fashioned by Brahma in the past."}]},{"ch":17,"vn":24,"dev":"तस्मादोमित्युदाहृत्य यज्ञदानतपःक्रियाः।प्रवर्तन्ते विधानोक्ताः सततं ब्रह्मवादिनाम्","iast":"tasmād oṁ ity udāhṛitya yajña-dāna-tapaḥ-kriyāḥ\npravartante vidhānoktāḥ satataṁ brahma-vādinām","v":[{"k":"purohit","t":"Therefore, all acts of sacrifice, gifts, and austerities prescribed by the scriptures are always begun by those who understand the Spirit with the word \"Om.\""},{"k":"sivananda","t":"Therefore, with the utterance of \"Om,\" the acts of sacrifice, gift, and austerity, as enjoined in the scriptures, are always begun by the students of Brahman."},{"k":"adidevananda","t":"Therefore, the Veda-enjoined sacrificial acts, gifts, and austerities, expounded by the Vedas, or those belonging to the first three stations, are always begun after pronouncing Om at the beginning."},{"k":"gambirananda","t":"Therefore, acts of sacrifice, charity, and austerity, as prescribed through injunctions, of those who study and expound the Vedas, always commence after uttering the syllable 'Om'."},{"k":"sankaranarayan","t":"Therefore, the scripture-prescribed acts of sacrifice, gift, and austerity of those who are habituated to having Brahman-discourses invariably commence with the utterance of OM."}]},{"ch":17,"vn":25,"dev":"तदित्यनभिसन्धाय फलं यज्ञतपःक्रियाः।दानक्रियाश्च विविधाः क्रियन्ते मोक्षकाङ्क्षि","iast":"tad ity anabhisandhāya phalaṁ yajña-tapaḥ-kriyāḥ\ndāna-kriyāśh cha vividhāḥ kriyante mokṣha-kāṅkṣhibhiḥ","v":[{"k":"purohit","t":"Those who desire deliverance begin their acts of sacrifice, austerity, or gift with the word \"Tat\" (meaning \"That\"), without thought of reward."},{"k":"sivananda","t":"Uttering \"Tat,\" without aiming for the fruits, are the acts of sacrifice, austerity, and the various acts of gifts performed by those seeking liberation."},{"k":"adidevananda","t":"Acts of sacrifice, austerity, and various gifts are performed without aiming at a reward by those who seek release, after pronouncing Tat."},{"k":"gambirananda","t":"After uttering the word \"tat,\" acts of sacrifice and austerity, as well as various acts of charity, are performed without regard for results by persons aspiring for liberation."},{"k":"sankaranarayan","t":"With the utterance of TAT, and without aiming for the fruit, those who seek emancipation perform acts of sacrifice, austerity, and various acts of giving."}]},{"ch":17,"vn":26,"dev":"सद्भावे साधुभावे च सदित्येतत्प्रयुज्यते।प्रशस्ते कर्मणि तथा सच्छब्दः पार्थ युज्यते","iast":"sad-bhāve sādhu-bhāve cha sad ity etat prayujyate\npraśhaste karmaṇi tathā sach-chhabdaḥ pārtha yujyate","v":[{"k":"purohit","t":"Sat' means Reality or the highest Good, and also, O Arjuna, it is used to denote an action of exceptional merit."},{"k":"sivananda","t":"The word \"Sat\" is used to refer to reality and goodness; likewise, O Arjuna, the word \"Sat\" is used to refer to an auspicious act."},{"k":"adidevananda","t":"This term \"Sat\" is used in the sense of existence and goodness. And so also, O Arjuna, the word \"Sat\" is applied to an auspicious action."},{"k":"gambirananda","t":"This word \"sat\" is used with regard to something coming into being and someone becoming good. Likewise, O son of Prtha, the word \"sat\" is used with regard to an auspicious rite."},{"k":"sankaranarayan","t":"In the sense of 'right' (or 'manifesting as being') and in the sense of 'proper' (or 'manifesting perfectly'), this word SAT is employed. Likewise, the word SAT is used with regard to the praiseworthy act; O son of Prtha!"}]},{"ch":17,"vn":27,"dev":"यज्ञे तपसि दाने च स्थितिः सदिति चोच्यते।कर्म चैव तदर्थीयं सदित्येवाभिधीयते","iast":"yajñe tapasi dāne cha sthitiḥ sad iti chochyate\nkarma chaiva tad-arthīyaṁ sad ity evābhidhīyate","v":[{"k":"purohit","t":"Conviction in sacrifice, austerity, and giving is also called Sat. So too, an action done only for the Lord's sake."},{"k":"sivananda","t":"Steadfastness in sacrifice, austerity, and gift is also called 'Sat', and action in connection with these, or for the sake of the Supreme, is also called 'Sat'."},{"k":"adidevananda","t":"Devotion to sacrifice, austerity, and gifts is also referred to as Sat; and thus, any action for such purposes is known as Sat."},{"k":"gambirananda","t":"And the steadfastness in sacrifice, austerity, and charity is spoken of as sat (good). And even the action meant for these is, indeed, called as sat."},{"k":"sankaranarayan","t":"Steadfastness is performing sacrifice, austerity, and giving gifts; this act is hence justly called SAT."}]},{"ch":17,"vn":28,"dev":"अश्रद्धया हुतं दत्तं तपस्तप्तं कृतं च यत्।असदित्युच्यते पार्थ न च तत्प्रेत्य नो इह","iast":"aśhraddhayā hutaṁ dattaṁ tapas taptaṁ kṛitaṁ cha yat\nasad ity uchyate pārtha na cha tat pretya no iha","v":[{"k":"purohit","t":"Whatever is done without faith, whether it be sacrifice, austerity, gift, or anything else, is called Asat (meaning \"Unreal\"), for it is the negation of Sat, O Arjuna! Such an act has no significance, here or hereafter."},{"k":"sivananda","t":"Whatever is sacrificed, given, or performed, and whatever austerity is practiced without faith, it is called 'Asat', O Arjuna; it is of no value here or hereafter (after death)."},{"k":"adidevananda","t":"Whatever offering or gift is made, whatever austerity is practiced, and whatever action is performed without faith, that is called Asat, O Arjuna. It is of no value here or hereafter."},{"k":"gambirananda","t":"O son of Prtha, whatever is offered in sacrifice and given in charity, as also whatever austerity is undertaken or whatever is done without faith, is said to be of no avail. And it is of no consequence after death, nor here."},{"k":"sankaranarayan","t":"Without faith, whatever oblation is offered, whatever gift is made, whatever austerity is practiced, and whatever action is undertaken, that is called ASAT and it is of no avail after one's death or in this world."}]},{"ch":18,"vn":1,"dev":"अर्जुन उवाच\nसंन्यासस्य महाबाहो तत्त्वमिच्छामि वेदितुम्।\nत्यागस्य च हृषीकेश पृथक्केशिनिषूदन","iast":"arjuna uvācha\nsannyāsasya mahā-bāho tattvam ichchhāmi veditum\ntyāgasya cha hṛiṣhīkeśha pṛithak keśhi-niṣhūdana","v":[{"k":"purohit","t":"Arjuna asked, \"O Mighty One! I desire to know how relinquishment is distinguished from renunciation."},{"k":"sivananda","t":"Arjuna said, \"O mighty-armed Hrishikesa, I desire to know the essence or truth of renunciation and abandonment severally, O slayer of Kesi.\""},{"k":"adidevananda","t":"Arjuna said, \"I desire to know the truth about renunciation and abnegation separately, O Krishna.\""},{"k":"gambirananda","t":"Arjuna said, O mighty-armed Hrsikesa, O slayer of Kesi, I want to know separately the truth about sannyasa as well as about tyaga."},{"k":"sankaranarayan","t":"Arjuna said, O Mighty-armed One! I desire to know, in detail, the distinctive nature of renunciation and relinquishment, O Hrsikesa! O Slayer of Kesin!"}]},{"ch":18,"vn":2,"dev":"श्री भगवानुवाच\nकाम्यानां कर्मणां न्यासं संन्यासं कवयो विदुः।\nसर्वकर्मफलत्यागं प्राहुस्त्यागं विचक्षणाः","iast":"śhrī-bhagavān uvācha\nkāmyānāṁ karmaṇāṁ nyāsaṁ sannyāsaṁ kavayo viduḥ\nsarva-karma-phala-tyāgaṁ prāhus tyāgaṁ vichakṣhaṇāḥ","v":[{"k":"purohit","t":"Lord Shri Krishna replied: The sages say that renunciation is forgoing an action that springs from desire, and relinquishing is the surrender of its fruit."},{"k":"sivananda","t":"The Blessed Lord said, \"The sages understand sannyasa to be the renunciation of action with desire; the wise declare the abandonment of the fruits of all actions to be tyaga.\""},{"k":"adidevananda","t":"The Lord said, \"The sages hold that Sannyasa is the giving up of all works motivated by desire, and the wise declare Tyaga to be the abandonment of the fruits of all works."},{"k":"gambirananda","t":"The Blessed Lord said, \"The learned ones know sannyasa to be the giving up of actions done with a desire for reward. The adepts call the abandonment of the results of all works 'tyaga'.\""},{"k":"sankaranarayan","t":"The Bhagavat said, \"The seers understand the act of renouncing desire-motivated actions as renunciation; the experts declare the relinquishment of the fruits of all actions to be relinquishment.\""}]},{"ch":18,"vn":3,"dev":"त्याज्यं दोषवदित्येके कर्म प्राहुर्मनीषिणः।\nयज्ञदानतपःकर्म न त्याज्यमिति चापरे","iast":"tyājyaṁ doṣha-vad ity eke karma prāhur manīṣhiṇaḥ\nyajña-dāna-tapaḥ-karma na tyājyam iti chāpare","v":[{"k":"purohit","t":"Some philosophers say that all action is evil and should be abandoned, whereas others maintain that acts of sacrifice, benevolence, and austerity should not be given up."},{"k":"sivananda","t":"Some philosophers declare that actions should be abandoned as evil; while others declare that acts of sacrifice, gift, and austerity should not be relinquished."},{"k":"adidevananda","t":"Some sages say that all actions should be abandoned as evil; others declare that works such as sacrifices, gifts, and austerities should not be abandoned."},{"k":"gambirananda","t":"Some learned persons say that action, beset with evil as it is, should be abandoned, and others say that the practice of sacrifice, charity, and austerity should not be abandoned."},{"k":"sankaranarayan","t":"Certain wise men declare that the harmful action should be relinquished, while others say that the actions of performing sacrifices, giving gifts, and observing austerities should not be relinquished."}]},{"ch":18,"vn":4,"dev":"निश्चयं श्रृणु मे तत्र त्यागे भरतसत्तम।त्यागो हि पुरुषव्याघ्र त्रिविधः संप्रकीर्तितः","iast":"niśhchayaṁ śhṛiṇu me tatra tyāge bharata-sattama\ntyāgo hi puruṣha-vyāghra tri-vidhaḥ samprakīrtitaḥ","v":[{"k":"purohit","t":"O best of Indians! Listen to my judgment regarding this problem. It has a threefold aspect."},{"k":"sivananda","t":"Hear from Me the conclusion or the final truth about this abandonment, O best of the Bharatas; abandonment, indeed, O best of men, has been declared to be of three kinds."},{"k":"adidevananda","t":"Listen to My decision, O Arjuna, concerning abandonment; for abandonment is declared to be of three kinds."},{"k":"gambirananda","t":"O the most excellent among the descendants of Bharata, hear from Me the firm conclusion regarding that tyaga. For, O greatest among men, tyaga has been clearly declared to be of three kinds."},{"k":"sankaranarayan","t":"O best of Bharata's descendants! Listen to My considered view about relinquishing: Indeed, the act of relinquishing is rightly spoken to be threefold, O best among men!"}]},{"ch":18,"vn":5,"dev":"यज्ञदानतपःकर्म न त्याज्यं कार्यमेव तत्।यज्ञो दानं तपश्चैव पावनानि मनीषिणाम्","iast":"yajña-dāna-tapaḥ-karma na tyājyaṁ kāryam eva tat\nyajño dānaṁ tapaśh chaiva pāvanāni manīṣhiṇām","v":[{"k":"purohit","t":"Acts of sacrifice, benevolence, and austerity should not be given up, but should be performed, for they purify the aspiring soul."},{"k":"sivananda","t":"Acts of sacrifice, gift, and austerity should not be abandoned, but should be performed; for sacrifice, gift, and austerity are the purifiers of the wise."},{"k":"adidevananda","t":"(a) The acts of sacrifice, gifts, and austerities should not be relinquished; but should be performed...\n(b) ...For sacrifices, gifts, and austerities are the means of purification for the wise."},{"k":"gambirananda","t":"The practice of sacrifice, charity, and austerity should not be abandoned; it should certainly be undertaken. Sacrifice, charity, and austerity are indeed the purifiers of the wise."},{"k":"sankaranarayan","t":"The actions of Vedic sacrifice, gift, and austerity should not be relinquished and they must necessarily be performed; for the men of wisdom, the Vedic sacrifice, gift, and austerity are the means of purification."}]},{"ch":18,"vn":6,"dev":"एतान्यपि तु कर्माणि सङ्गं त्यक्त्वा फलानि च।कर्तव्यानीति मे पार्थ निश्िचतं मतमुत्तमम्","iast":"etāny api tu karmāṇi saṅgaṁ tyaktvā phalāni cha\nkartavyānīti me pārtha niśhchitaṁ matam uttamam","v":[{"k":"purohit","t":"But they should be done with detachment and without thought of reward. This is my final judgement."},{"k":"sivananda","t":"But even these actions should be performed, leaving aside attachment and the desire for rewards, O Arjuna; this is my certain and most assured conviction."},{"k":"adidevananda","t":"It is My decided and final view that even these acts should be done, O Arjuna, with relinquishment of attachment and the forsaking of the fruits thereof."},{"k":"gambirananda","t":"But even these actions must be undertaken by renouncing attachment and hankering for results. This is My firm and definitive conclusion, O Partha."},{"k":"sankaranarayan","t":"Even these actions should be performed by relinquishing attachment and the fruits thereof; this is my considered best opinion, O son of Prtha!"}]},{"ch":18,"vn":7,"dev":"नियतस्य तु संन्यासः कर्मणो नोपपद्यते।मोहात्तस्य परित्यागस्तामसः परिकीर्तितः","iast":"niyatasya tu sannyāsaḥ karmaṇo nopapadyate\nmohāt tasya parityāgas tāmasaḥ parikīrtitaḥ","v":[{"k":"purohit","t":"It is not right to give up actions which are obligatory; and if they are misunderstood, it is the result of sheer ignorance."},{"k":"sivananda","t":"Verily, the renunciation of obligatory action is not proper; the abandonment of the same out of delusion is declared to be Tamasic."},{"k":"adidevananda","t":"But the renunciation of obligatory acts is not proper; abandonment of these through delusion is declared to be of a Tamasic nature."},{"k":"gambirananda","t":"Abandoning one's daily obligatory acts is not justifiable; giving up those through delusion is said to be rooted in tamas."},{"k":"sankaranarayan","t":"The renunciation of the enjoined action does not make sense; and completely relinquishing it, out of ignorance, is proclaimed on all sides as an act of Tamas (Strand)."}]},{"ch":18,"vn":8,"dev":"दुःखमित्येव यत्कर्म कायक्लेशभयात्त्यजेत्।स कृत्वा राजसं त्यागं नैव त्यागफलं लभेत्","iast":"duḥkham ity eva yat karma kāya-kleśha-bhayāt tyajet\nsa kṛitvā rājasaṁ tyāgaṁ naiva tyāga-phalaṁ labhet","v":[{"k":"purohit","t":"To avoid an action out of fear of physical suffering, as it is likely to be painful, is to act out of passion, and the benefit of renunciation will not be gained."},{"k":"sivananda","t":"He who abandons action out of fear of bodily trouble (because it is painful), does not obtain the merit of renunciation by performing such Rajasic renunciation."},{"k":"adidevananda","t":"He who renounces acts that are painful out of fear of bodily suffering performs a Rajasika abandonment; however, he does not gain the fruit of such abandonment."},{"k":"gambirananda","t":"Whatever action one may relinquish merely as being painful, out of fear of physical suffering, he, having resorted to renunciation based on rajas, will surely not acquire the fruits of renunciation."},{"k":"sankaranarayan","t":"He who would, out of fear of bodily exertion, relinquish an action just because it is painful—that person, having thus made relinquishment an act of the Rajas (Strand), would not at all gain the fruit of that relinquishment."}]},{"ch":18,"vn":9,"dev":"कार्यमित्येव यत्कर्म नियतं क्रियतेऽर्जुन।सङ्गं त्यक्त्वा फलं चैव स त्यागः सात्त्विको मतः","iast":"kāryam ity eva yat karma niyataṁ kriyate 'rjuna\nsaṅgaṁ tyaktvā phalaṁ chaiva sa tyāgaḥ sāttviko mataḥ","v":[{"k":"purohit","t":"He who performs an obligatory action, believing it to be a duty that ought to be done, without any personal desire to do the act or to receive any return—such renunciation is pure."},{"k":"sivananda","t":"Whatever obligatory action is done, O Arjuna, merely because it ought to be done, abandoning attachment and also the desire for reward, that renunciation is regarded as sattvic (pure)."},{"k":"adidevananda","t":"When actions are performed as they ought to be done, O Arjuna, renouncing attachment and the results thereof, such abandonment is regarded as Sattvika."},{"k":"gambirananda","t":"Whatever obligatory duty is performed just because it is a bounden duty, O Arjuna, by giving up attachment and the results as well—that renunciation is considered to be based on sattva."},{"k":"sankaranarayan","t":"\"This is a thing to be performed\" - just on that ground, whatever usual action is performed, relinquishing attachment and also fruit - that act of relinquishment is deemed to be of the Sattva (strand)."}]},{"ch":18,"vn":10,"dev":"न द्वेष्ट्यकुशलं कर्म कुशले नानुषज्जते।त्यागी सत्त्वसमाविष्टो मेधावी छिन्नसंशयः","iast":"na dveṣhṭy akuśhalaṁ karma kuśhale nānuṣhajjate\ntyāgī sattva-samāviṣhṭo medhāvī chhinna-sanśhayaḥ","v":[{"k":"purohit","t":"The wise man who has attained purity, whose doubts are resolved, who is filled with the spirit of self-abnegation, does not shy away from action due to its pain, nor does he crave it due to its pleasure."},{"k":"sivananda","t":"The man of renunciation, pervaded by purity, intelligent, and with his doubts cut asunder, does not hate an unpleasant task nor is he attached to a pleasant one."},{"k":"adidevananda","t":"One who has abandoned, imbued with Sattva, wise, and whose doubts have been dispelled—such a person neither hates disagreeable acts nor clings to agreeable ones."},{"k":"gambirananda","t":"The man of renunciation, imbued with sattva, wise and free from doubts, does not hate unbecoming action, nor does he become attached to becoming activity."},{"k":"sankaranarayan","t":"The man of renunciation, who is well-possessed of Sattva, is wise and has his doubts destroyed—he does not hate unskilled action and does not cling to skilled action."}]},{"ch":18,"vn":11,"dev":"न हि देहभृता शक्यं त्यक्तुं कर्माण्यशेषतः।यस्तु कर्मफलत्यागी स त्यागीत्यभिधीयते","iast":"na hi deha-bhṛitā śhakyaṁ tyaktuṁ karmāṇy aśheṣhataḥ\nyas tu karma-phala-tyāgī sa tyāgīty abhidhīyate","v":[{"k":"purohit","t":"But since those still in the body cannot entirely avoid action, in their case, the abandonment of the fruit of action is considered as complete renunciation."},{"k":"sivananda","t":"Indeed, it is not possible for an embodied being to completely abandon actions; however, he who relinquishes the rewards of actions is truly called a man of renunciation."},{"k":"adidevananda","t":"For, it is impossible for one who has a body to completely abandon actions. But he who gives up the results of his works is called the one who has abandoned them."},{"k":"gambirananda","t":"Since it is not possible for one who holds onto a body to give up actions entirely, therefore he who renounces the results of his actions is called a man of renunciation."},{"k":"sankaranarayan","t":"Indeed, to relinquish actions entirely is not possible for a body-bearing one; but whoever relinquishes the fruits of actions, he is said to be a man of [true] relinquishment."}]},{"ch":18,"vn":12,"dev":"अनिष्टमिष्टं मिश्रं च त्रिविधं कर्मणः फलम्।भवत्यत्यागिनां प्रेत्य न तु संन्यासिनां क्वचित्","iast":"aniṣhṭam iṣhṭaṁ miśhraṁ cha tri-vidhaṁ karmaṇaḥ phalam\nbhavaty atyāgināṁ pretya na tu sannyāsināṁ kvachit","v":[{"k":"purohit","t":"For those who cannot renounce all desires, the fruit of action hereafter is threefold—good, evil, and partly good and partly evil. But for him who has renounced, there is none."},{"k":"sivananda","t":"The threefold fruit of action (evil, good, and mixed) accrues after death to those who do not abandon it, but never to those who do."},{"k":"adidevananda","t":"Undesirable, desirable, and mixed—thus, threefold is the fruit of work that accrues after death to those who have not renounced; but to those who have renounced, none accrues whatsoever."},{"k":"gambirananda","t":"The threefold results of actions—the undesirable, the desirable, and the mixed—accrue after death to those who do not resort to renunciation, but never to those who resort to renunciation."},{"k":"sankaranarayan","t":"The three-fold fruit of action—the undesired, the desired, and the mixed—accrues even after death to those who are not men of renunciation, but never to those who are men of renunciation."}]},{"ch":18,"vn":13,"dev":"पञ्चैतानि महाबाहो कारणानि निबोध मे।सांख्ये कृतान्ते प्रोक्तानि सिद्धये सर्वकर्मणाम्","iast":"pañchaitāni mahā-bāho kāraṇāni nibodha me\nsānkhye kṛitānte proktāni siddhaye sarva-karmaṇām","v":[{"k":"purohit","t":"I will now tell you, O Mighty Man, the five causes that must come together, according to the final decision of philosophy, for an action to be accomplished."},{"k":"sivananda","t":"Learn from Me, O mighty-armed Arjuna, these five causes, as declared in the Sankhya system, for the accomplishment of all actions."},{"k":"adidevananda","t":"Learn from Me, O Arjuna, these five causes for the accomplishment of all acts, as described in Sankhya-krtanta—the science of exact understanding of things—for the accomplishment of works."},{"k":"gambirananda","t":"O mighty-armed one, learn from Me these five factors for the accomplishment of all actions, which have been spoken of in the Vedanta, in which actions terminate."},{"k":"sankaranarayan","t":"O mighty-armed one! Learn from Me these five causes, declared in the conclusion of deliberations on proper knowledge, for the accomplishment of all actions."}]},{"ch":18,"vn":14,"dev":"अधिष्ठानं तथा कर्ता करणं च पृथग्विधम्।विविधाश्च पृथक्चेष्टा दैवं चैवात्र पञ्चमम्","iast":"adhiṣhṭhānaṁ tathā kartā karaṇaṁ cha pṛithag-vidham\nvividhāśh cha pṛithak cheṣhṭā daivaṁ chaivātra pañchamam","v":[{"k":"purohit","t":"They have a body, a personality, physical organs, and manifold activities and destinies."},{"k":"sivananda","t":"The body, the doer, the various senses, the different functions of various kinds, and the presiding deity—the fifth."},{"k":"adidevananda","t":"The seat of action, the agent, the various kinds of organs, the different and distinctive functions of vital air, and the fifth among these—Divinity—all these."},{"k":"gambirananda","t":"The locus, the agent, the different kinds of organs, the many and varied activities, and the divine are the fifth here."},{"k":"sankaranarayan","t":"The basis, the agent, the various instruments, the distinct activities of various kinds, and Destiny, which is the fifth factor, are all present."}]},{"ch":18,"vn":15,"dev":"शरीरवाङ्मनोभिर्यत्कर्म प्रारभते नरः।न्याय्यं वा विपरीतं वा पञ्चैते तस्य हेतवः","iast":"śharīra-vāṅ-manobhir yat karma prārabhate naraḥ\nnyāyyaṁ vā viparītaṁ vā pañchaite tasya hetavaḥ","v":[{"k":"purohit","t":"Whatever action a person performs, whether by muscular effort, speech, or thought, and whether it be right or wrong, these five are the essential causes."},{"k":"sivananda","t":"Whatever action a person performs with their body, speech, and mind, whether right or wrong, these five are its causes."},{"k":"adidevananda","t":"For whatever action a person undertakes with their body, speech, and mind, whether right or wrong, i.e., enjoined or forbidden by the Sastras, the following five are its causes:"},{"k":"gambirananda","t":"Whatever action a person performs with their body, speech, and mind, whether it be just or its opposite, these five are the causes of it."},{"k":"sankaranarayan","t":"O Arjuna! Whatever action is undertaken with the body, speech, or mind, whether it is lawful or otherwise, its factors are these five."}]},{"ch":18,"vn":16,"dev":"तत्रैवं सति कर्तारमात्मानं केवलं तु यः।पश्यत्यकृतबुद्धित्वान्न स पश्यति दुर्मतिः","iast":"tatraivaṁ sati kartāram ātmānaṁ kevalaṁ tu yaḥ\npaśhyaty akṛita-buddhitvān na sa paśhyati durmatiḥ","v":[{"k":"purohit","t":"But the fool, who, due to his immature judgment, supposes that it is his own Self alone that acts, perverts the truth and does not see rightly."},{"k":"sivananda","t":"Now, such being the case, verily he who, owing to an untrained understanding, looks upon his Self, which is isolated, as the agent, he of perverted intelligence does not see."},{"k":"adidevananda","t":"Therefore, he who, due to his uncultivated understanding, perceives only the self as the agent, he of wicked mind does not truly perceive."},{"k":"gambirananda","t":"Therefore, anyone whose intellect is imperfect and perceives the Absolute Self as the agent, does not perceive properly and has a distorted intellect."},{"k":"sankaranarayan","t":"But this being the case, whoever views himself as the sole agent due to their imperfect intellect—they, the defective-minded ones, do not view things rightly."}]},{"ch":18,"vn":17,"dev":"यस्य नाहंकृतो भावो बुद्धिर्यस्य न लिप्यते।हत्वापि स इमाँल्लोकान्न हन्ति न निबध्यते","iast":"yasya nāhankṛito bhāvo buddhir yasya na lipyate\nhatvā 'pi sa imāl lokān na hanti na nibadhyate","v":[{"k":"purohit","t":"He who has no pride and whose intellect is unalloyed by attachment, even though he kills these people, he does not kill them, and his act does not bind him."},{"k":"sivananda","t":"He who is free from the egoistic notion, whose intelligence is not tainted by good or evil, though he slays these people, he does not slay, nor is he bound by the action."},{"k":"adidevananda","t":"He who is free from the notion of 'I am the doer,' and whose understanding is not tainted, does not slay, even though he slays all these men, nor is he bound."},{"k":"gambirananda","t":"He who has no feeling of egoism, whose intellect is untainted, he does not kill, nor does he become bound—even by killing these creatures!"},{"k":"sankaranarayan","t":"He whose mental disposition is not dominated by the sense of 'I', and whose intellect is not stained—he, even if he slays these worlds, does not [really] slay any and is not fettered."}]},{"ch":18,"vn":18,"dev":"ज्ञानं ज्ञेयं परिज्ञाता त्रिविधा कर्मचोदना।करणं कर्म कर्तेति त्रिविधः कर्मसंग्रहः","iast":"jñānaṁ jñeyaṁ parijñātā tri-vidhā karma-chodanā\nkaraṇaṁ karma karteti tri-vidhaḥ karma-saṅgrahaḥ","v":[{"k":"purohit","t":"Knowledge, the knower, and the object of knowledge are the three incentives to action; and the act, the actor, and the instrument are the threefold constituents."},{"k":"sivananda","t":"Knowledge, the knowable, and the knower form the threefold impulse for action; the organ, the action, and the agent form the threefold basis of action."},{"k":"adidevananda","t":"Knowledge, the object of knowledge, and the knower are the threefold incitements to action. The instrument, the act, and the agent are the threefold constituents of action."},{"k":"gambirananda","t":"Knowledge, the object of knowledge, and the knower—these are the threefold inducements to action. The comprehension of actions comes under three heads: the instruments, the object, and the subject."},{"k":"sankaranarayan","t":"The instrument of knowledge, the object of knowledge, and the knowing subject—the prompting in action, consisting of these threefold elements—is the proper grasping of action with threefold elements, namely, the instrument, the object, and the agent."}]},{"ch":18,"vn":19,"dev":"ज्ञानं कर्म च कर्ता च त्रिधैव गुणभेदतः।प्रोच्यते गुणसंख्याने यथावच्छृणु तान्यपि","iast":"jñānaṁ karma cha kartā cha tridhaiva guṇa-bhedataḥ\nprochyate guṇa-saṅkhyāne yathāvach chhṛiṇu tāny api","v":[{"k":"purohit","t":"The knowledge, the action, and the doer differ according to their qualities. Listen to this as well."},{"k":"sivananda","t":"Knowledge, action, and actor are declared in the science of the Gunas (Sankhya philosophy) to be of three kinds only, according to the distinction of the Gunas. Of these, hear duly."},{"k":"adidevananda","t":"Knowledge, action, and agent are declared in the science of the Gunas to be of three kinds, according to the difference in the Gunas. Listen to them also as they are."},{"k":"gambirananda","t":"Knowledge, action, and agent are stated in the teaching about the gunas to be only of three kinds, according to the differences of the gunas. Hear about them also as they are."},{"k":"sankaranarayan","t":"The instrument of knowledge, the object, and the agent are just three kinds due to the differences in the strands—thus it is declared in enumerating the strands. You must also listen to these [from Me] as they are."}]},{"ch":18,"vn":20,"dev":"सर्वभूतेषु येनैकं भावमव्ययमीक्षते।अविभक्तं विभक्तेषु तज्ज्ञानं विद्धि सात्त्विकम्","iast":"sarva-bhūteṣhu yenaikaṁ bhāvam avyayam īkṣhate\navibhaktaṁ vibhakteṣhu taj jñānaṁ viddhi sāttvikam","v":[{"k":"purohit","t":"That knowledge which sees the One Indestructible in all beings, the One Indivisible in all separate lives, can be truly called Pure Knowledge."},{"k":"sivananda","t":"That by which one sees the indestructible Reality in all beings, not separate in any of them—know that knowledge to be Sattvic."},{"k":"adidevananda","t":"Know that knowledge to be sattvika, by which one sees in all beings an immutable existence, undivided even in the divided."},{"k":"gambirananda","t":"Know that knowledge to originate from sattva, through which one sees a single, undecaying, undivided entity in all the diversified things."},{"k":"sankaranarayan","t":"That instrument of knowledge, by means of which one perceives the singular, immutable existence in all beings, the unclassified among the classified ones—that you must know to be born of the Sattva (Strand)."}]},{"ch":18,"vn":21,"dev":"पृथक्त्वेन तु यज्ज्ञानं नानाभावान्पृथग्विधान्।वेत्ति सर्वेषु भूतेषु तज्ज्ञानं विद्धि राजसम्","iast":"pṛithaktvena tu yaj jñānaṁ nānā-bhāvān pṛithag-vidhān\nvetti sarveṣhu bhūteṣhu taj jñānaṁ viddhi rājasam","v":[{"k":"purohit","t":"The knowledge that perceives the manifold existence in all beings as separate comes from passion."},{"k":"sivananda","t":"But that knowledge which sees in all beings various entities of distinct kinds as being distinct from one another, know thou that knowledge to be Rajasic."},{"k":"adidevananda","t":"But that knowledge which sees all beings, due to their individual nature, as distinct entities—know that knowledge to be Rajasic."},{"k":"gambirananda","t":"But know that knowledge to originate from rajas, which amidst all things apprehends the different entities of various kinds as distinct [as possessing distinct selves]."},{"k":"sankaranarayan","t":"That instrument of knowledge, by means of which one considers the varied natures of different sorts in all beings as truly distinct—that is regarded to be of the Rajas strand."}]},{"ch":18,"vn":22,"dev":"यत्तु कृत्स्नवदेकस्मिन्कार्ये सक्तमहैतुकम्।अतत्त्वार्थवदल्पं च तत्तामसमुदाहृतम्","iast":"yat tu kṛitsna-vad ekasmin kārye saktam ahaitukam\natattvārtha-vad alpaṁ cha tat tāmasam udāhṛitam","v":[{"k":"purohit","t":"But that which clings blindly to one idea as if it were all, without logic, truth, or insight, has its origin in darkness."},{"k":"sivananda","t":"But that which clings to one single effect as if it were the whole, without reason, without any foundation in Truth, and is trivial—that is declared to be Tamasic."},{"k":"adidevananda","t":"But that knowledge is declared to be Tamasika which clings to one single act as if it were the whole, which is not based on reason, and which is false and insignificant."},{"k":"gambirananda","t":"But that (knowledge) is said to be born of tamas which is confined to one form as if it were all, which is irrational, unconcerned with truth, and trivial."},{"k":"sankaranarayan","t":"That [instrument-of-knowledge], because of which one, not realizing the whole, gets indulged without reason in a particular activity, and which is unconcerned with the real nature of things and is insignificant—that is declared to be of the Tamas (Strand)."}]},{"ch":18,"vn":23,"dev":"नियतं सङ्गरहितमरागद्वेषतः कृतम्।अफलप्रेप्सुना कर्म यत्तत्सात्त्विकमुच्यते","iast":"niyataṁ saṅga-rahitam arāga-dveṣhataḥ kṛitam\naphala-prepsunā karma yat tat sāttvikam uchyate","v":[{"k":"purohit","t":"An obligatory action done by one who is disinterested, who neither likes nor dislikes it, and gives no thought to the consequences that may follow, such an action is Pure."},{"k":"sivananda","t":"An action that is ordained, free from attachment, done without love or hatred, and without desire for reward is declared to be Sattvic."},{"k":"adidevananda","t":"That obligatory act is said to be Sattvika, which is done without attachment, without desire or aversion, and by one who seeks no fruit."},{"k":"gambirananda","t":"The daily obligatory action which is performed without attachment and without likes or dislikes, by one who does not hanker for rewards, is said to be born of sattva."},{"k":"sankaranarayan","t":"The object that has been acquired with determination, without attachment and without desire or hatred, by one who does not crave to reap the fruit of their action - that is declared to be of the Sattva (Strand)."}]},{"ch":18,"vn":24,"dev":"यत्तु कामेप्सुना कर्म साहङ्कारेण वा पुनः।क्रियते बहुलायासं तद्राजसमुदाहृतम्","iast":"yat tu kāmepsunā karma sāhankāreṇa vā punaḥ\nkriyate bahulāyāsaṁ tad rājasam udāhṛitam","v":[{"k":"purohit","t":"But even though an action involves the most strenuous endeavor, yet if the doer is seeking to gratify their desires and is filled with personal vanity, it may be assumed to originate in passion."},{"k":"sivananda","t":"But that action which is done by one longing for the fulfillment of desires or gain with egotism or with much effort is declared to be Rajasic (passionate)."},{"k":"adidevananda","t":"But that act is said to be Rajasic, which is performed with great effort by one who seeks to gratify their desires and under the prompting of egoism."},{"k":"gambirananda","t":"But that action is said to be born of rajas which is done by one desirous of results or by one who is egotistical, and which is highly strenuous."},{"k":"sankaranarayan","t":"The object which is abundant in afflictions and which is further desired by one who craves to attain the desired thing with the feeling of 'I'—that is considered to be of the Rajas (Strand)."}]},{"ch":18,"vn":25,"dev":"अनुबन्धं क्षयं हिंसामनपेक्ष्य च पौरुषम्।मोहादारभ्यते कर्म यत्तत्तामसमुच्यते","iast":"anubandhaṁ kṣhayaṁ hinsām anapekṣhya cha pauruṣham\nmohād ārabhyate karma yat tat tāmasam uchyate","v":[{"k":"purohit","t":"An action undertaken through delusion, with no regard to the spiritual implications, the capacity of the doer, or the potential harm that may follow, is assumed to be a product of ignorance."},{"k":"sivananda","t":"That action which is undertaken from delusion, without regard for the consequences, loss, injury, and one's own ability, is declared to be Tamasic (dark)."},{"k":"adidevananda","t":"That act is said to be Tamasika which is undertaken through delusion, without regard to consequences, loss, injury, and one's own capacity."},{"k":"gambirananda","t":"That action is said to be born of tamas which is undertaken out of delusion, without consideration of its consequences, loss, harm, and ability."},{"k":"sankaranarayan","t":"The object which is gained, due to ignorance, without considering the result, the loss, the injury to others, and one's own strength—that is declared to be of the Tamas (Strand)."}]},{"ch":18,"vn":26,"dev":"मुक्तसङ्गोऽनहंवादी धृत्युत्साहसमन्वितः।सिद्ध्यसिद्ध्योर्निर्विकारः कर्ता सात्त्विक उच्यते","iast":"mukta-saṅgo 'nahaṁ-vādī dhṛity-utsāha-samanvitaḥ\nsiddhy-asiddhyor nirvikāraḥ kartā sāttvika uchyate","v":[{"k":"purohit","t":"But when a person has no sentiment or ego, when they possess courage and confidence, not caring whether they succeed or fail, then their action arises from purity."},{"k":"sivananda","t":"An agent who is free from attachment, non-egoistic, endowed with firmness and enthusiasm, and unaffected by success or failure, is considered to be of a Sattvic (pure) nature."},{"k":"adidevananda","t":"That agent is said to be Sattvika, who is free from attachment, who does not boast of himself, who is endowed with steadiness and zeal, and who is unaffected by success and failure."},{"k":"gambirananda","t":"[Ast. introduces this verse with 'Idanim kartrbhedah ucyate, Now is being stated the distinctions among the agents.'-Tr.] The agent who is free from attachment [Attachment to results or the idea of agentship.], not egotistical, endowed with fortitude and diligence, and unperturbed by success and failure is said to be possessed of sattva."},{"k":"sankaranarayan","t":"The agent who is free from attachment, who does not make any speech of egoism, who is full of contentment and enthusiasm, and who does not change mentally in success or failure—that agent is said to be of the Sattva nature."}]},{"ch":18,"vn":27,"dev":"रागी कर्मफलप्रेप्सुर्लुब्धो हिंसात्मकोऽशुचिः।हर्षशोकान्वितः कर्ता राजसः परिकीर्तितः","iast":"rāgī karma-phala-prepsur lubdho hinsātmako 'śhuchiḥ\nharṣha-śhokānvitaḥ kartā rājasaḥ parikīrtitaḥ","v":[{"k":"purohit","t":"In one who is impulsive, greedy, looking for reward, violent, impure, and torn between joy and sorrow, it may be assumed that Passion is predominant."},{"k":"sivananda","t":"Passionate, desiring to obtain the reward of their actions, greedy, cruel, impure, moved by joy and sorrow, such an agent is said to be Rajasic."},{"k":"adidevananda","t":"That doer is called Rajasika who is passionate, who seeks the fruits of his actions, who is greedy, harmful, and impure, and who is swayed by delight and grief."},{"k":"gambirananda","t":"The agent who has attachment, who is desirous of the results of actions, covetous, cruel by nature, unclean, and subject to joy and sorrow, is declared to be possessed of rajas."},{"k":"sankaranarayan","t":"The agent, who is a man of passion, who craves the fruit of his actions, and is avaricious; who is injurious by nature, impure, and is overpowered by joy and grief—that agent is proclaimed to be of the Rajas (Strand)."}]},{"ch":18,"vn":28,"dev":"अयुक्तः प्राकृतः स्तब्धः शठो नैष्कृतिकोऽलसः।विषादी दीर्घसूत्री च कर्ता तामस उच्यते","iast":"ayuktaḥ prākṛitaḥ stabdhaḥ śhaṭho naiṣhkṛitiko 'lasaḥ\nviṣhādī dīrgha-sūtrī cha kartā tāmasa uchyate","v":[{"k":"purohit","t":"While he whose purpose is weak, who is low-minded, stubborn, dishonest, malicious, lazy, despondent, and procrastinating—he may be assumed to be in darkness."},{"k":"sivananda","t":"Unsteady, vulgar, inflexible, deceitful, malicious, lazy, despondent, and procrastinating—such an agent is called Tamasic."},{"k":"adidevananda","t":"That doer is said to be Tamasika who is unqualified, unrefined, obstinate, depraved, dishonest, indolent, despondent, and lethargic."},{"k":"gambirananda","t":"The agent who is unsteady, naive, inflexible, deceitful, wicked, lazy, sullen, and procrastinating is said to be possessed of tamas."},{"k":"sankaranarayan","t":"The agent who does not exert is vulgar, obstinate, and deceitful; they are a man of wickedness and are lazy, sorrowful, and procrastinating—such an agent is said to be of the Tamas strand."}]},{"ch":18,"vn":29,"dev":"बुद्धेर्भेदं धृतेश्चैव गुणतस्त्रिविधं श्रृणु।प्रोच्यमानमशेषेण पृथक्त्वेन धनञ्जय","iast":"buddher bhedaṁ dhṛiteśh chaiva guṇatas tri-vidhaṁ śhṛiṇu\nprochyamānam aśheṣheṇa pṛithaktvena dhanañjaya","v":[{"k":"purohit","t":"Reason and conviction are threefold, according to the quality that is dominant. I will explain them fully and separately, O Arjuna!"},{"k":"sivananda","t":"Hear thou the threefold division of intellect and firmness, according to the Gunas, as I declare them fully and distinctly, O Arjuna."},{"k":"adidevananda","t":"Hear now, O Arjuna, the threefold division of Buddhi (reason) and Dhrti (fortitude) according to the Gunas, to be fully and severally set forth."},{"k":"gambirananda","t":"O Dhananjaya, listen to the classification of the intellect and fortitude, which is threefold according to the gunas, while it is being stated in detail and separately."},{"k":"sankaranarayan","t":"You must listen to Me as I expound the three-fold division of the intellect and content, both completely and individually, based on the Strands, O Dhananjaya!"}]},{"ch":18,"vn":30,"dev":"प्रवृत्तिं च निवृत्तिं च कार्याकार्ये भयाभये।बन्धं मोक्षं च या वेत्ति बुद्धिः सा पार्थ सात्त्विकी","iast":"pravṛittiṁ cha nivṛittiṁ cha kāryākārye bhayābhaye\nbandhaṁ mokṣhaṁ cha yā vetti buddhiḥ sā pārtha sāttvikī","v":[{"k":"purohit","t":"That intellect which understands the creation and dissolution of life, what actions should be done and what not, which discriminates between fear and fearlessness, bondage and deliverance, is Pure."},{"k":"sivananda","t":"The intellect which knows the path of work and renunciation, what should be done and what should not be done, fear and fearlessness, bondage and liberation—that intellect is Sattvic (pure), O Arjuna."},{"k":"adidevananda","t":"That Buddhi, O Arjuna, which knows activity and renunciation, what should be done and what should not be done, fear and fearlessness, bondage and release—that Buddhi is Sattvika."},{"k":"gambirananda","t":"O Partha, that intellect is born of sattva which understands action and withdrawal, duty and what is not duty, the sources of fear and fearlessness, as well as bondage and freedom."},{"k":"sankaranarayan","t":"The intellect which knows the activity and the cessation from activity, the proper and improper actions, the fear and non-fear, and the bondage and emancipation—that intellect is considered to be of the Sattva (Strand)."}]},{"ch":18,"vn":31,"dev":"यया धर्ममधर्मं च कार्यं चाकार्यमेव च।अयथावत्प्रजानाति बुद्धिः सा पार्थ राजसी","iast":"yayā dharmam adharmaṁ cha kāryaṁ chākāryam eva cha\nayathāvat prajānāti buddhiḥ sā pārtha rājasī","v":[{"k":"purohit","t":"The intellect that does not understand what is right and wrong, and what should be done and not done, is under the sway of Passion."},{"k":"sivananda","t":"That by which one wrongly understands dharma and adharma, and also what ought to be done and what ought not to be done—that intellect, O Arjuna, is rajasic (passionate)."},{"k":"adidevananda","t":"The Buddhi that gives an erroneous knowledge of Dharma and Adharma (its opposite) and also of what should be done and what should not be done, O Arjuna, is Rajasic."},{"k":"gambirananda","t":"O Partha, that intellect is born of rajas with which one wrongly understands virtue and vice, as well as what ought to be done and ought not to be done."},{"k":"sankaranarayan","t":"The intellect, by means of which one decides incorrectly between the righteous and the unrighteous, and what is a proper action and an improper one—that intellect is of the Rajas, O son of Prtha!"}]},{"ch":18,"vn":32,"dev":"अधर्मं धर्ममिति या मन्यते तमसाऽऽवृता।सर्वार्थान्विपरीतांश्च बुद्धिः सा पार्थ तामसी","iast":"adharmaṁ dharmam iti yā manyate tamasāvṛitā\nsarvārthān viparītānśh cha buddhiḥ sā pārtha tāmasī","v":[{"k":"purohit","t":"And that which, shrouded in Ignorance, thinks wrong to be right, and sees everything perversely, O Arjuna, that intellect is ruled by Darkness."},{"k":"sivananda","t":"That intellect, O Arjuna, which is enveloped in darkness and sees Adharma as Dharma and all things perverted, is Tamasic (dark)."},{"k":"adidevananda","t":"That Buddhi, O Arjuna, which, enveloped in darkness, regards Adharma as Dharma and reverses every value, is Tamasika."},{"k":"gambirananda","t":"O Partha, that intellect is born of tamas which, being covered by darkness, considers vice as virtue, and indeed perceives all things contrary to what they are."},{"k":"sankaranarayan","t":"The intellect which, containing darkness (ignorance), conceives the unrighteous one as righteous and all things topsy-turvy—that intellect is deemed to be of the Tamas (Strand)."}]},{"ch":18,"vn":33,"dev":"धृत्या यया धारयते मनःप्राणेन्द्रियक्रियाः।योगेनाव्यभिचारिण्या धृतिः सा पार्थ सात्त्विकी","iast":"dhṛityā yayā dhārayate manaḥ-prāṇendriya-kriyāḥ\nyogenāvyabhichāriṇyā dhṛitiḥ sā pārtha sāttvikī","v":[{"k":"purohit","t":"The conviction and steady concentration with which the mind, the energy, and the senses are controlled—O Arjuna!—are the result of purity."},{"k":"sivananda","t":"The unwavering firmness, through which Yoga restrains the functions of the mind, life-force, and senses—that firmness, O Arjuna, is Sattvic (pure)."},{"k":"adidevananda","t":"That fortitude, by which one maintains the unwavering activities of the mind and vital force, and these sense-organs, through yoga—that fortitude is of the nature of sattva."},{"k":"gambirananda","t":"O Partha, the firmness that is unfailing through concentration, with which one restrains the functions of the mind, vital forces, and the organs—that firmness is born of sattva."},{"k":"sankaranarayan","t":"The unfailing content, by which one restrains, through Yoga, the activities of the mind, the living breath, and the senses, is considered to be of the Sattva (strand)."}]},{"ch":18,"vn":34,"dev":"यया तु धर्मकामार्थान् धृत्या धारयतेऽर्जुन।प्रसङ्गेन फलाकाङ्क्षी धृतिः सा पार्थ राजसी","iast":"yayā tu dharma-kāmārthān dhṛityā dhārayate 'rjuna\nprasaṅgena phalākāṅkṣhī dhṛitiḥ sā pārtha rājasī","v":[{"k":"purohit","t":"The conviction that always holds fast to rituals, self-interest, and wealth for the sake of what they may bring forth comes from passion."},{"k":"sivananda","t":"But that, O Arjuna, by which one holds fast to Dharma (duty), enjoyment of pleasures, and earning of wealth, on account of attachment and desire for reward—that firmness, O Arjuna, is Rajasic (passionate)."},{"k":"adidevananda","t":"That dhṛti, O Arjuna, by which one, who is desirous of fruits, longs for them with intense attachment and holds fast to duty, desire, and wealth—that dhṛti is rajasika."},{"k":"gambirananda","t":"But, O Partha, the steadfastness with which one holds on to righteousness, covetable things, and wealth, desiring their fruits as the occasion for each arises, that steadfastness is born of rajas."},{"k":"sankaranarayan","t":"O Arjuna! The contentment by which one restrains one's bounden duty, pleasure, and wealth, and consequently desires the fruits of action—that contentment is of the Rajas strand, O son of Prtha!"}]},{"ch":18,"vn":35,"dev":"यया स्वप्नं भयं शोकं विषादं मदमेव च।न विमुञ्चति दुर्मेधा धृतिः सा पार्थ तामसी","iast":"yayā svapnaṁ bhayaṁ śhokaṁ viṣhādaṁ madam eva cha\nna vimuñchati durmedhā dhṛitiḥ sā pārtha tāmasī","v":[{"k":"purohit","t":"And that which clings perversely to false idealism, fear, grief, despair, and vanity is the product of ignorance."},{"k":"sivananda","t":"That firmness, O Arjuna, by which a stupid man does not abandon sleep, fear, grief, despair, and conceit, is Tamasic."},{"k":"adidevananda","t":"That Dhrti, by which a foolish person does not give up sleep, fear, grief, depression, and passion, O Arjuna, is of the nature of Tamas."},{"k":"gambirananda","t":"That firmness is considered to be born of tamas, due to which a person with a corrupt intellect does not give up sleep, fear, sorrow, despondency, as well as sensuality."},{"k":"sankaranarayan","t":"The contentment where a foolish man does not give up his sleep, fear, grief, despondency, and arrogance—that contentment is deemed to be of the Tamas (Strand)."}]},{"ch":18,"vn":36,"dev":"सुखं त्विदानीं त्रिविधं श्रृणु मे भरतर्षभ।अभ्यासाद्रमते यत्र दुःखान्तं च निगच्छति","iast":"sukhaṁ tv idānīṁ tri-vidhaṁ śhṛiṇu me bharatarṣhabha\nabhyāsād ramate yatra duḥkhāntaṁ cha nigachchhati\nyat tad agre viṣham iva pariṇāme 'mṛitopamam\ntat sukhaṁ sāttvikaṁ proktam ātma-buddhi-prasāda-jam","v":[{"k":"purohit","t":"Hear further the three kinds of pleasure. That which increases day by day delivers one from misery."},{"k":"sivananda","t":"And now, O Arjuna, hear from Me of the threefold pleasure, in which one rejoices through practice and surely comes to the end of pain."},{"k":"adidevananda","t":"Now hear from Me, O Arjuna, the threefold division of pleasure৷৷ that in which one rejoices through long practice and in which one comes to the end of pain."},{"k":"gambirananda","t":"Now hear from Me, O scion of the Bharata dynasty, as regards the three kinds of joy: That in which one delights due to habit, and certainly attains the cessation of sorrows; [S. and S.S. take the second line of this verse along with the next verse referring to sattvika happiness.-Tr.]"},{"k":"sankaranarayan","t":"O best among the Bharatas! Now, you must also listen to Me about the three-fold happiness, wherein one delights in practice and attains the end of suffering."}]},{"ch":18,"vn":37,"dev":"यत्तदग्रे विषमिव परिणामेऽमृतोपमम्।तत्सुखं सात्त्विकं प्रोक्तमात्मबुद्धिप्रसादजम्","iast":"yat  tad agre    viṣam   iva pariṇāme    'mṛtopamam  tat sukhaṁ  sāttvikaṁ   proktam ātma-buddhi-prasāda-jam","v":[{"k":"purohit","t":"Which at first seems like poison but afterwards acts like nectar—that pleasure is pure, for it is born of wisdom."},{"k":"sivananda","t":"That which is like poison at first but in the end like nectar—that happiness is declared to be sattvic, born of the purity of one's own mind due to self-realization."},{"k":"adidevananda","t":"That which, at first, is like a poison but becomes like an elixir in the end, born from the serene state of mind focused on the Self—such pleasure is said to be Sattvika."},{"k":"gambirananda","t":"That which is like poison in the beginning, but is likened to nectar in the end, and which arises from the purity of one's intellect—that joy is spoken of as born of sattva."},{"k":"sankaranarayan","t":"[The happiness] which is like poison in the moment but is like nectar in the result—that happiness, born of serenity of the soul and intellect, you must know to be of the sattva (strand)."}]},{"ch":18,"vn":38,"dev":"विषयेन्द्रियसंयोगाद्यत्तदग्रेऽमृतोपमम्।परिणामे विषमिव तत्सुखं राजसं स्मृतम्","iast":"viṣhayendriya-sanyogād yat tad agre 'mṛitopamam\npariṇāme viṣham iva tat sukhaṁ rājasaṁ smṛitam","v":[{"k":"purohit","t":"That which, at first, is like nectar, as the senses revel in their objects, but in the end acts like poison—that pleasure arises from Passion."},{"k":"sivananda","t":"That happiness which arises from the contact of the senses with the objects, which is initially like nectar but eventually like poison, is said to be Rajasic."},{"k":"adidevananda","t":"That pleasure which arises from the contact of senses with their objects, which is like elixir at first but like poison in the end, is said to be Rajasic."},{"k":"gambirananda","t":"That joy is referred to as born of rajas, which, arising from the contact of the organs and their objects, is like nectar in the beginning but like poison in the end."},{"k":"sankaranarayan","t":"[The happiness] which is like nectar at its due time due to the contact between the senses and sense-objects; but which is like poison at the time of its result—that is considered to be of the Rajas (Strand)."}]},{"ch":18,"vn":39,"dev":"यदग्रे चानुबन्धे च सुखं मोहनमात्मनः।निद्रालस्यप्रमादोत्थं तत्तामसमुदाहृतम्","iast":"yad agre chānubandhe cha sukhaṁ mohanam ātmanaḥ\nnidrālasya-pramādotthaṁ tat tāmasam udāhṛitam","v":[{"k":"purohit","t":"While the pleasure that drugs the senses from start to finish, which springs from indolence, lethargy, and folly—that pleasure flows from Ignorance."},{"k":"sivananda","t":"That happiness which at first, as well as in the end, deludes the self, and which arises from sleep, indolence, and heedlessness—that is declared to be Tamasic."},{"k":"adidevananda","t":"That pleasure which, at the beginning and end, deludes the self, through sleep, sloth, and error, is declared to be tamasic."},{"k":"gambirananda","t":"That joy is said to be born of tamas, which, both in the beginning and in the end, is delusive to oneself and arises from sleep, laziness, and inadvertence."},{"k":"sankaranarayan","t":"The happiness that, both initially and subsequently, is of the nature of deluding the Self; and which results from sleep, indolence, and heedlessness—that is stated to be of the Tamas (Strand)."}]},{"ch":18,"vn":40,"dev":"न तदस्ति पृथिव्यां वा दिवि देवेषु वा पुनः।सत्त्वं प्रकृतिजैर्मुक्तं यदेभिः स्यात्ित्रभिर्गुणैः","iast":"na tad asti pṛithivyāṁ vā divi deveṣhu vā punaḥ\nsattvaṁ prakṛiti-jair muktaṁ yad ebhiḥ syāt tribhir guṇaiḥ","v":[{"k":"purohit","t":"There is nothing anywhere on earth or in the higher worlds that is free from the three Qualities, for they are born of Nature."},{"k":"sivananda","t":"There is no being on earth or in heaven among the gods that is liberated from the three qualities born of Nature."},{"k":"adidevananda","t":"There is no creature, on earth or among the gods in heaven, that is exempt from these three Gunas born of Prakrti."},{"k":"gambirananda","t":"There is no entity in the world, nor among the gods in heaven, that can be free from these three gunas born of Nature."},{"k":"sankaranarayan","t":"Whether on earth or among the gods in heaven, there is not a single being that is free from these three strands born of material nature."}]},{"ch":18,"vn":41,"dev":"ब्राह्मणक्षत्रियविशां शूद्राणां च परंतप।कर्माणि प्रविभक्तानि स्वभावप्रभवैर्गुणैः","iast":"brāhmaṇa-kṣhatriya-viśhāṁ śhūdrāṇāṁ cha parantapa\nkarmāṇi pravibhaktāni svabhāva-prabhavair guṇaiḥ","v":[{"k":"purohit","t":"O Arjuna! The duties of spiritual teachers, the soldiers, the traders, and the servants have all been fixed according to the dominant quality in their nature."},{"k":"sivananda","t":"Of Brahmanas, Kshatriyas, Vaisyas, and Sudras, O Arjuna, the duties are distributed according to the qualities born of their own nature."},{"k":"adidevananda","t":"The duties of the Brahmanas, Ksatriyas, Vaisyas, and Sudras are clearly divided, O Arjuna, according to their Gunas, born of their nature."},{"k":"gambirananda","t":"O scorcher of enemies, the duties of the Brahmanas, Ksatriyas, Vaisyas, and Sudras have been fully classified according to the gunas born from Nature."},{"k":"sankaranarayan","t":"The duties of the Brahmanas, the Kshatriyas, the Vaishyas, and the Shudras are properly classified according to the qualities that are the sources of their nature, O scorcher of foes!"}]},{"ch":18,"vn":42,"dev":"शमो दमस्तपः शौचं क्षान्तिरार्जवमेव च।ज्ञानं विज्ञानमास्तिक्यं ब्रह्मकर्म स्वभावजम्","iast":"śhamo damas tapaḥ śhauchaṁ kṣhāntir ārjavam eva cha\njñānaṁ vijñānam āstikyaṁ brahma-karma svabhāva-jam","v":[{"k":"purohit","t":"Serenity, self-restraint, austerity, purity, forgiveness, uprightness, knowledge, wisdom, and faith in God—these constitute the duty of a spiritual teacher."},{"k":"sivananda","t":"Serenity, self-restraint, austerity, purity, forgiveness, and uprightness, as well as knowledge, realization, and belief in God, are the duties of Brahmanas, born of their own nature."},{"k":"adidevananda","t":"The control of the senses and mind, austerity, purity, forbearance, uprightness, knowledge, special knowledge, and faith—all these constitute the duty of a Brahmana, born of his inherent nature."},{"k":"gambirananda","t":"The natural duties of the Brahmanas are the control of the internal and external organs, austerity, purity, forgiveness, straightforwardness, knowledge, as well as wisdom [Knowledge refers to the understanding of subjects presented by the scriptures; wisdom means making them matters of one's own experience.], and faith."},{"k":"sankaranarayan","t":"Quietude, self-control, purity, forbearance, straightforwardness, knowledge, wisdom, and faith in another world are the duties of the Brahmanas, born of their nature."}]},{"ch":18,"vn":43,"dev":"शौर्यं तेजो धृतिर्दाक्ष्यं युद्धे चाप्यपलायनम्।दानमीश्वरभावश्च क्षात्रं कर्म स्वभावजम्","iast":"śhauryaṁ tejo dhṛitir dākṣhyaṁ yuddhe chāpy apalāyanam\ndānam īśhvara-bhāvaśh cha kṣhātraṁ karma svabhāva-jam","v":[{"k":"purohit","t":"Valor, glory, firmness, skill, generosity, steadiness in battle, and the ability to rule—these constitute the duty of a soldier. They flow from his own nature."},{"k":"sivananda","t":"Prowess, splendor, firmness, dexterity, and not fleeing from battle, generosity, and lordliness are the duties of the Kshatriyas, born of their own nature."},{"k":"adidevananda","t":"Valor, invincibility, steadiness, dexterity, and not fleeing in battle, generosity, and regality are the duties of a Kshatriya, born of his inherent nature."},{"k":"gambirananda","t":"The natural duties of the Ksatriyas are heroism, boldness, fortitude, capability, and not retreating from battle, generosity, and lordliness."},{"k":"sankaranarayan","t":"Heroic deeds, fiery energy, firmness, dexterity, and also non-attachment form the duties of the Ksatriyas, born of their nature, in battle, giving gifts, and overlordship."}]},{"ch":18,"vn":44,"dev":"कृषिगौरक्ष्यवाणिज्यं वैश्यकर्म स्वभावजम्।परिचर्यात्मकं कर्म शूद्रस्यापि स्वभावजम्","iast":"kṛiṣhi-gau-rakṣhya-vāṇijyaṁ vaiśhya-karma svabhāva-jam\nparicharyātmakaṁ karma śhūdrasyāpi svabhāva-jam","v":[{"k":"purohit","t":"Agriculture, the protection of cows, and trade are the duties of a trader, in accordance with his nature. The duty of a servant is to serve, which also agrees with his nature."},{"k":"sivananda","t":"Agriculture, cattle-rearing, and trade are the duties of the Vaisya (merchant), born of their own nature; and service is the duty of the Sudra (servant-class), born of their own nature."},{"k":"adidevananda","t":"Agriculture, cattle-breeding, and trade are the duties of the Vaisya, born of their nature. And the duty of a Sudra is one of service, born of their nature."},{"k":"gambirananda","t":"The natural duties of the Vaisyas are agriculture, cattle-rearing, and trading. The natural duty of the Sudras, too, is in the form of service."},{"k":"sankaranarayan","t":"Ploughing, tending to cattle, and trading are the actions of the Vaisyas, born of their nature. The action of service is of the Sudras, born of their nature."}]},{"ch":18,"vn":45,"dev":"स्वे स्वे कर्मण्यभिरतः संसिद्धिं लभते नरः।स्वकर्मनिरतः सिद्धिं यथा विन्दति तच्छृणु","iast":"sve sve karmaṇy abhirataḥ sansiddhiṁ labhate naraḥ\nsva-karma-nirataḥ siddhiṁ yathā vindati tach chhṛiṇu","v":[{"k":"purohit","t":"Perfection is attained when one diligently attends to their duty. Listen, and I will tell you how it is attained by one who always minds their own duty."},{"k":"sivananda","t":"Each person devoted to their own duty attains perfection. How they attain perfection while being engaged in their own duty, hear now."},{"k":"adidevananda","t":"Devoting oneself to one's duty, one attains perfection. Hear now how one devoted to their own duty attains perfection."},{"k":"gambirananda","t":"Being devoted to his own duty, one attains complete success. Hear how one devoted to their own duty achieves success."},{"k":"sankaranarayan","t":"A person, devoted to their own respective action, attains success. How one attains success through devotion to their own action, that you must hear from Me."}]},{"ch":18,"vn":46,"dev":"यतः प्रवृत्तिर्भूतानां येन सर्वमिदं ततम्।स्वकर्मणा तमभ्यर्च्य सिद्धिं विन्दति मानवः","iast":"yataḥ pravṛittir bhūtānāṁ yena sarvam idaṁ tatam\nsva-karmaṇā tam abhyarchya siddhiṁ vindati mānavaḥ","v":[{"k":"purohit","t":"One reaches perfection by dedicating their actions to God, Who is the source of all being and fills everything."},{"k":"sivananda","t":"He from whom all the beings have evolved and by whom all this is pervaded, worshipping Him with his own duty, one attains perfection."},{"k":"adidevananda","t":"From whom all beings arise and by whom all this is pervaded—by worshipping Him with one's own duty, one reaches perfection."},{"k":"gambirananda","t":"A human being achieves success by adoring, through his own duties, Him from whom is the origin of creatures and by whom all this is pervaded."},{"k":"sankaranarayan","t":"From whence the activities of the beings arise, and by which this universe is pervaded—worshipping That by one's own prescribed action, one attains success."}]},{"ch":18,"vn":47,"dev":"श्रेयान्स्वधर्मो विगुणः परधर्मात्स्वनुष्ठितात्।स्वभावनियतं कर्म कुर्वन्नाप्नोति किल्बिषम्","iast":"śhreyān swa-dharmo viguṇaḥ para-dharmāt sv-anuṣhṭhitāt\nsvabhāva-niyataṁ karma kurvan nāpnoti kilbiṣham","v":[{"k":"purohit","t":"It is better to do one's own duty, however defective it may be, than to follow the duty of another, however well one may perform it. He who does his duty as his own nature reveals it, never commits a sin."},{"k":"sivananda","t":"Better is one's own duty, even if it is destitute of merits, than the duty of another well performed. He who does the duty ordained by his own nature incurs no sin."},{"k":"adidevananda","t":"Better is one's own duty, though ill done, than the duty of another, though well-performed. When one does the duty ordained by their own nature, they incur no stain."},{"k":"gambirananda","t":"One's own duty, though defective, is superior to another's duty well performed. By performing a duty according to one's own nature, one does not incur sin."},{"k":"sankaranarayan","t":"Better is one's own prescribed duties, born of one's nature, even though it is devoid of excellence, than another's duty well executed; the doer of duty, dependent on one's own nature, does not incur sin."}]},{"ch":18,"vn":48,"dev":"सहजं कर्म कौन्तेय सदोषमपि न त्यजेत्।सर्वारम्भा हि दोषेण धूमेनाग्निरिवावृताः","iast":"saha-jaṁ karma kaunteya sa-doṣham api na tyajet\nsarvārambhā hi doṣheṇa dhūmenāgnir ivāvṛitāḥ","v":[{"k":"purohit","t":"The duty that falls to one's lot of its own accord should not be abandoned, though it may have its defects. All acts are marred by defects, just as fire is obscured by smoke."},{"k":"sivananda","t":"One should not, O Arjuna, abandon the duty to which one is born, though it may be faulty; for, all undertakings are enveloped by evil, just as fire is by smoke."},{"k":"adidevananda","t":"One should not relinquish one's work, O Arjuna, though it may be imperfect; for, all endeavors are enveloped by imperfections as fire is by smoke."},{"k":"gambirananda","t":"O son of Kunti, one should not give up the duty to which one is born, even though it be imperfect. For all undertakings are surrounded by evil, as fire is with smoke."},{"k":"sankaranarayan","t":"O son of Kunti! One should not give up their nature-born duty, even if it appears to be defective. For, all beginnings are enveloped by harm, just as fire is by smoke."}]},{"ch":18,"vn":49,"dev":"असक्तबुद्धिः सर्वत्र जितात्मा विगतस्पृहः।नैष्कर्म्यसिद्धिं परमां संन्यासेनाधिगच्छति","iast":"asakta-buddhiḥ sarvatra jitātmā vigata-spṛihaḥ\nnaiṣhkarmya-siddhiṁ paramāṁ sannyāsenādhigachchhati","v":[{"k":"purohit","t":"He whose mind is entirely detached, who has conquered himself, and whose desires have vanished, reaches that stage of perfect freedom through his renunciation, where action completes itself and leaves no seed."},{"k":"sivananda","t":"He whose intellect is unattached everywhere, who has subdued his self, from whom desire has fled, he attains the supreme state of freedom from action through renunciation."},{"k":"adidevananda","t":"He whose understanding is unattached on all sides, whose self is controlled, who is free from desires—he attains the supreme perfection transcending all activity through renunciation."},{"k":"gambirananda","t":"He whose intellect remains unattached to everything, who has conquered his internal organs and is desireless, attains through monasticism the supreme perfection consisting of the state of one free from duties."},{"k":"sankaranarayan","t":"He, whose mind entertains no attachment to anything, who is self-controlled and is free from craving—he attains, by means of renunciation, the supreme success of actionlessness."}]},{"ch":18,"vn":50,"dev":"सिद्धिं प्राप्तो यथा ब्रह्म तथाप्नोति निबोध मे।समासेनैव कौन्तेय निष्ठा ज्ञानस्य या परा","iast":"siddhiṁ prāpto yathā brahma tathāpnoti nibodha me\nsamāsenaiva kaunteya niṣhṭhā jñānasya yā parā","v":[{"k":"purohit","t":"I will now state briefly how one who has reached perfection finds the Eternal Spirit, the state of Supreme Wisdom."},{"k":"sivananda","t":"Learn from Me, O Arjuna, in brief how one who has attained perfection reaches Brahman—the Eternal, that supreme state of knowledge."},{"k":"adidevananda","t":"Learn from me, O Arjuna, in brief how one who has attained perfection attains the Brahman—the supreme consummation of knowledge."},{"k":"gambirananda","t":"Understand for certain from Me, in brief indeed, O son of Kunti, that process by which one who has achieved success attains Brahman, which is the supreme consummation of knowledge."},{"k":"sankaranarayan","t":"Having attained success, how one attains Brahman—an attainment which is confirmed to be the final beatitude of true knowledge—that you must learn from Me briefly."}]},{"ch":18,"vn":51,"dev":"बुद्ध्या विशुद्धया युक्तो धृत्याऽऽत्मानं नियम्य च।शब्दादीन् विषयांस्त्यक्त्वा रागद्वेषौ व्युदस्य च","iast":"buddhyā viśhuddhayā yukto dhṛityātmānaṁ niyamya cha\nśhabdādīn viṣhayāns tyaktvā rāga-dveṣhau vyudasya cha","v":[{"k":"purohit","t":"Guided always by pure reason, bravely restraining himself, renouncing the objects of sense and giving up attachment and hatred; he attains peace."},{"k":"sivananda","t":"Endowed with a pure intellect, controlling the self through firmness, relinquishing sound and other objects and abandoning attraction and hatred."},{"k":"adidevananda","t":"Endowed with a purified understanding, subduing the mind with steadiness, relinquishing sound and other objects of the senses and casting aside love and hate;"},{"k":"gambirananda","t":"Endowed with a pure intellect and controlling oneself with fortitude, one should reject the objects beginning from sound [sound, touch, form, color, taste, and smell - Tr.] and eliminate attachment and hatred."},{"k":"sankaranarayan","t":"He who has attained a completely pure intellect by firmly controlling his mind and renouncing sense-objects, sound, and driving out desire and hatred;"}]},{"ch":18,"vn":52,"dev":"विविक्तसेवी लघ्वाशी यतवाक्कायमानसः।ध्यानयोगपरो नित्यं वैराग्यं समुपाश्रितः","iast":"vivikta-sevī laghv-āśhī yata-vāk-kāya-mānasaḥ\ndhyāna-yoga-paro nityaṁ vairāgyaṁ samupāśhritaḥ","v":[{"k":"purohit","t":"Enjoying solitude, being abstemious, having his body, mind, and speech under perfect control, and being absorbed in meditation, he becomes free—always filled with the spirit of renunciation."},{"k":"sivananda","t":"Dwelling in solitude, eating sparingly, with speech, body, and mind subdued, always engaged in meditation and concentration, and resorting to dispassion."},{"k":"adidevananda","t":"Resorting to solitude, eating sparingly, restraining speech, body, and mind, ever engaged in the yoga of meditation and taking refuge in dispassion;"},{"k":"gambirananda","t":"One who resorts to solitude, eats sparingly, has control over their speech, body, and mind, for whom meditation and concentration are ever the highest duty, and who is possessed of dispassion;"},{"k":"sankaranarayan","t":"Who enjoys solitude, eats sparingly, has controlled their speech, body, and mind; who is devoted to the practice of meditation and yoga; and who has taken refuge in perpetual desirelessness;"}]},{"ch":18,"vn":53,"dev":"अहङ्कारं बलं दर्पं कामं क्रोधं परिग्रहम्।विमुच्य निर्ममः शान्तो ब्रह्मभूयाय कल्पते","iast":"ahankāraṁ balaṁ darpaṁ kāmaṁ krodhaṁ parigraham\nvimuchya nirmamaḥ śhānto brahma-bhūyāya kalpate","v":[{"k":"purohit","t":"Having abandoned selfishness, power, arrogance, anger, and desire, possessing nothing of his own, and having attained peace, he is fit to join the Eternal Spirit."},{"k":"sivananda","t":"Having abandoned egoism, strength, arrogance, desire, anger, and covetousness, and being free from the notion of 'mine' and peaceful, he is fit for becoming Brahman."},{"k":"adidevananda","t":"Forsaking egoism, power, pride, desire, wrath, and possessions, with no feeling of 'mine' and tranquil, he becomes worthy of the state of Brahman."},{"k":"gambirananda","t":"Having discarded egotism, force, pride, desire, anger, and superfluous possessions, and being free from the idea of possession and serene, that person is fit for becoming Brahman."},{"k":"sankaranarayan","t":"Relinquishing egotism, violence, pride, desire, wrath, and the sense of possession - he, the unselfish and calm one, is capable of becoming the Brahman."}]},{"ch":18,"vn":54,"dev":"ब्रह्मभूतः प्रसन्नात्मा न शोचति न काङ्क्षति।समः सर्वेषु भूतेषु मद्भक्तिं लभते पराम्","iast":"brahma-bhūtaḥ prasannātmā na śhochati na kāṅkṣhati\nsamaḥ sarveṣhu bhūteṣhu mad-bhaktiṁ labhate parām","v":[{"k":"purohit","t":"When he unites with the Eternal and his soul knows the bliss of the Self, he feels no desire or regret, he regards all beings equally, and enjoys the blessing of supreme devotion to Me."},{"k":"sivananda","t":"Becoming Brahman, serene in the Self, he neither grieves nor desires; he is the same to all beings, and obtains supreme devotion to Me."},{"k":"adidevananda","t":"Having realized the state of Brahman, tranquil, he neither grieves nor craves. Regarding all beings alike, he attains supreme devotion to Me."},{"k":"gambirananda","t":"One who has become Brahman and has attained the blissful Self does not grieve nor desire. Becoming the same towards all beings, he attains supreme devotion to Me."},{"k":"sankaranarayan","t":"Having become the Brahman, the serene-minded one neither grieves nor rejoices; remaining equal to all beings, he gains the highest devotion to Me."}]},{"ch":18,"vn":55,"dev":"भक्त्या मामभिजानाति यावान्यश्चास्मि तत्त्वतः।ततो मां तत्त्वतो ज्ञात्वा विशते तदनन्तरम्","iast":"bhaktyā mām abhijānāti yāvān yaśh chāsmi tattvataḥ\ntato māṁ tattvato jñātvā viśhate tad-anantaram","v":[{"k":"purohit","t":"By such devotion, he sees Me, who I am and what I am; and thus realizing the truth, he enters into My kingdom."},{"k":"sivananda","t":"By devotion, he knows Me in truth, who and what I am; then, having known Me in truth, he immediately enters into the Supreme."},{"k":"adidevananda","t":"Through devotion, he comes to know Me fully—who and what I am in reality, who I am and how I am. Knowing Me thus in truth, he forthwith enters into Me."},{"k":"gambirananda","t":"Through devotion, he knows Me in reality, as to what and who I am. Then, having known Me truly, he enters into Me immediately afterward."},{"k":"sankaranarayan","t":"Through devotion he comes to know of Me: Who I am and how, in fact, I am—having correctly known Me, he enters into Me. Then afterwards,"}]},{"ch":18,"vn":56,"dev":"सर्वकर्माण्यपि सदा कुर्वाणो मद्व्यपाश्रयः।मत्प्रसादादवाप्नोति शाश्वतं पदमव्ययम्","iast":"sarva-karmāṇy api sadā kurvāṇo mad-vyapāśhrayaḥ\nmat-prasādād avāpnoti śhāśhvataṁ padam avyayam","v":[{"k":"purohit","t":"Relying on Me in all his actions and doing them for My sake, he attains, by My grace, eternal and unchangeable life."},{"k":"sivananda","t":"Having taken refuge in Me and doing all actions, by My grace he obtains the eternal, indestructible state of being."},{"k":"adidevananda","t":"Taking refuge in Me and performing all works constantly, one, by My grace, attains the eternal and immutable abode."},{"k":"gambirananda","t":"Ever engaging in all actions, one to whom I am the refuge, attains the eternal, immutable state through my grace."},{"k":"sankaranarayan","t":"Performing all his actions all the time and taking refuge in Me, he attains, through My grace, the eternal, changeless state."}]},{"ch":18,"vn":57,"dev":"चेतसा सर्वकर्माणि मयि संन्यस्य मत्परः।बुद्धियोगमुपाश्रित्य मच्चित्तः सततं भव","iast":"chetasā sarva-karmāṇi mayi sannyasya mat-paraḥ\nbuddhi-yogam upāśhritya mach-chittaḥ satataṁ bhava","v":[{"k":"purohit","t":"Surrender your actions to Me, live in Me, focus your intellect on Me, and always think of Me."},{"k":"sivananda","t":"Mentally renouncing all actions in Me, having Me as the highest goal, and resorting to the yoga of discrimination, do thou ever fix thy mind on Me."},{"k":"adidevananda","t":"Surrender all your actions to Me with your mind, keep Me as your goal, and practice Buddhi-yoga, focusing your thoughts on Me always."},{"k":"gambirananda","t":"Mentally surrendering all actions to Me and accepting Me as the supreme, keep your mind ever fixed on Me by resorting to the concentration of your intellect."},{"k":"sankaranarayan","t":"Hence, O descendant of Bharata, renounce all actions in Me by your mind and take hold of the knowledge-Yoga. Always keep your thought-organ directed towards Me."}]},{"ch":18,"vn":58,"dev":"मच्चित्तः सर्वदुर्गाणि मत्प्रसादात्तरिष्यसि।अथ चेत्त्वमहङ्कारान्न श्रोष्यसि विनङ्क्ष्यसि","iast":"mach-chittaḥ sarva-durgāṇi mat-prasādāt tariṣhyasi\natha chet tvam ahankārān na śhroṣhyasi vinaṅkṣhyasi","v":[{"k":"purohit","t":"Fix your mind on Me, and by My grace you will overcome the obstacles in your path. But if, misled by pride, you do not listen, then you will indeed be lost."},{"k":"sivananda","t":"Fixing your mind on Me, you shall, by My grace, overcome all obstacles; but if you will not hear Me due to egoism, you shall perish."},{"k":"adidevananda","t":"Focusing your thoughts on Me, you shall, by My grace, cross over all difficulties. If, however, out of self-conceit, you do not heed Me, you will perish."},{"k":"gambirananda","t":"Having your mind fixed on Me, you will cross over all difficulties by My grace. If, however, you do not listen out of egotism, you will be destroyed."},{"k":"sankaranarayan","t":"Having your thought-organ turned towards Me, you shall pass over all obstacles by My Grace. On the other hand, if you don't give up your sense of ego, you will not liberate yourself; instead, you will perish."}]},{"ch":18,"vn":59,"dev":"यदहङ्कारमाश्रित्य न योत्स्य इति मन्यसे।मिथ्यैष व्यवसायस्ते प्रकृतिस्त्वां नियोक्ष्यति","iast":"yad ahankāram āśhritya na yotsya iti manyase\nmithyaiṣha vyavasāyas te prakṛitis tvāṁ niyokṣhyati","v":[{"k":"purohit","t":"If you in your vanity think of avoiding this fight, your will shall not be fulfilled, for Nature herself will compel you."},{"k":"sivananda","t":"If, filled with egoism, thou thinkest, \"I will not fight,\" then thy resolve is vain; nature will compel thee."},{"k":"adidevananda","t":"If, in your self-conceit, you think, 'I will not fight,' your resolve is futile. Nature will compel you."},{"k":"gambirananda","t":"Though you think 'I shall not fight', relying on egotism, this determination of yours is vain. Your nature will impel you!"},{"k":"sankaranarayan","t":"In case, holding fast to the sense of ego, you think, 'I shall not fight,' that resolve of yours will be useless. Your own natural condition will incite you to fight."}]},{"ch":18,"vn":60,"dev":"स्वभावजेन कौन्तेय निबद्धः स्वेन कर्मणा।कर्तुं नेच्छसि यन्मोहात्करिष्यस्यवशोऽपि तत्","iast":"swbhāva-jena kaunteya nibaddhaḥ svena karmaṇā\nkartuṁ nechchhasi yan mohāt kariṣhyasy avaśho 'pi tat","v":[{"k":"purohit","t":"O Arjuna! Your duty binds you. It has arisen from your own nature, and that which you do not desire to do in your delusion, you will do that very thing. You are helpless."},{"k":"sivananda","t":"O Arjuna, bound by your own Karma (action) born of your own nature, that which from delusion you wish not to do, even that you shall do helplessly."},{"k":"adidevananda","t":"O Arjuna, bound by your own duty born out of your own inner disposition, and having no control over your own will, you will be compelled to do that very thing which you now do not desire to do through delusion."},{"k":"gambirananda","t":"Being bound by your own duty, born of nature, O son of Kunti, you will, being helpless, verily do that which you do not wish to do, owing to indiscretion."},{"k":"sankaranarayan","t":"O son of Kunti! Being firmly bound by your own duty, born of your own nature, and thus not being independent, you would perform what you do not wish to do, due to your delusion."}]},{"ch":18,"vn":61,"dev":"ईश्वरः सर्वभूतानां हृद्देशेऽर्जुन तिष्ठति।भ्रामयन्सर्वभूतानि यन्त्रारूढानि मायया","iast":"īśhvaraḥ sarva-bhūtānāṁ hṛid-deśhe 'rjuna tiṣhṭhati\nbhrāmayan sarva-bhūtāni yantrārūḍhāni māyayā","v":[{"k":"purohit","t":"God dwells in the hearts of all beings, O Arjuna! He causes them to revolve, as it were, on a wheel, by His mystic power."},{"k":"sivananda","t":"The Lord dwells in the hearts of all beings, O Arjuna, causing all beings, by His illusory power, to revolve as if mounted on a machine."},{"k":"adidevananda","t":"The Lord, O Arjuna, abides in the heart of every being, spinning them round and round, as if mounted on a wheel, by His power."},{"k":"gambirananda","t":"O Arjuna, the Lord resides in the region of the hearts of all creatures, revolving through Maya all the creatures as though mounted on a machine!"},{"k":"sankaranarayan","t":"O Arjuna! This Lord dwells in the hearts of all beings, causing, by His trick of illusion, all beings to whirl round as if they are mounted on a revolving mechanical contrivance."}]},{"ch":18,"vn":62,"dev":"तमेव शरणं गच्छ सर्वभावेन भारत।तत्प्रसादात्परां शान्तिं स्थानं प्राप्स्यसि शाश्वतम्","iast":"tam eva śharaṇaṁ gachchha sarva-bhāvena bhārata\ntat-prasādāt parāṁ śhāntiṁ sthānaṁ prāpsyasi śhāśhvatam","v":[{"k":"purohit","t":"With all your strength, fly to Him and surrender yourself, and by His grace you will attain Supreme Peace and reach the Eternal Home."},{"k":"sivananda","t":"Fly to Him for refuge with all your being, O Arjuna; by His grace you will obtain supreme peace and the eternal abode."},{"k":"adidevananda","t":"Seek refuge in Him alone, O Arjuna, with the entirety of your being. By His grace, you shall find supreme peace and an eternal abode."},{"k":"gambirananda","t":"Take refuge in Him alone with your whole being, O scion of the Bharata dynasty. Through His grace, you will attain supreme peace and the eternal abode."},{"k":"sankaranarayan","t":"To Him alone, O descendant of Bharata, you must go for refuge with all your thoughts. Through My grace, you will attain success and the eternal abode."}]},{"ch":18,"vn":63,"dev":"इति ते ज्ञानमाख्यातं गुह्याद्गुह्यतरं मया।विमृश्यैतदशेषेण यथेच्छसि तथा कुरु","iast":"iti te jñānam ākhyātaṁ guhyād guhyataraṁ mayā\nvimṛiśhyaitad aśheṣheṇa yathechchhasi tathā kuru","v":[{"k":"purohit","t":"Thus, I have revealed to you the truth, the mystery of mysteries. Having thought it over, you are free to act as you wish."},{"k":"sivananda","t":"Thus, wisdom more secret than secrecy itself has been declared to you by me. Reflect on it fully, then act as you wish."},{"k":"adidevananda","t":"Thus, the knowledge, the mystery of mysteries, has been declared to you by Me. Reflecting on it fully, do as you will."},{"k":"gambirananda","t":"To you I have imparted this knowledge, which is more secret than any secret. Ponder over this as a whole and do as you like."},{"k":"sankaranarayan","t":"Thus, the path of wisdom, a better secret than all other secrets, has been expounded to you by Me; comprehend it fully and then act as you wish."}]},{"ch":18,"vn":64,"dev":"सर्वगुह्यतमं भूयः श्रृणु मे परमं वचः।इष्टोऽसि मे दृढमिति ततो वक्ष्यामि ते हितम्","iast":"sarva-guhyatamaṁ bhūyaḥ śhṛiṇu me paramaṁ vachaḥ\niṣhṭo 'si me dṛiḍham iti tato vakṣhyāmi te hitam","v":[{"k":"purohit","t":"Listen to My last word once more, the deepest secret of all; you are My beloved, you are My friend, and I speak for your welfare."},{"k":"sivananda","t":"Hear again My supreme word, most secret of all; for you are dearly beloved of Me, I will tell you what is good."},{"k":"adidevananda","t":"Hear again My supreme word, the most secret of all; as I am exceedingly fond of you, I am telling you what is good for you."},{"k":"gambirananda","t":"Listen again to My highest utterance, which is the most profound of all. Since you are ever dear to Me, I shall speak what is beneficial to you."},{"k":"sankaranarayan","t":"Yet again, you must listen to My ultimate, supreme message—the highest secret of all. You are My dear one and have a firm intellect, so I shall tell you what is good for you."}]},{"ch":18,"vn":65,"dev":"मन्मना भव मद्भक्तो मद्याजी मां नमस्कुरु।मामेवैष्यसि सत्यं ते प्रतिजाने प्रियोऽसि मे","iast":"man-manā bhava mad-bhakto mad-yājī māṁ namaskuru\nmām evaiṣhyasi satyaṁ te pratijāne priyo 'si me","v":[{"k":"purohit","t":"Dedicate yourself to Me, worship Me, sacrifice all for Me, prostrate yourself before Me, and you will surely come to Me. I truly pledge to you; you are My beloved."},{"k":"sivananda","t":"Fix your mind on Me, be devoted to Me, sacrifice to Me, bow down to Me. You will come to Me; I truly promise you this, for you are dear to Me."},{"k":"adidevananda","t":"Focus your mind on Me. Be My devotee. Worship Me. Prostrate before Me. You will come to Me alone. I promise you truly; for you are dear to Me."},{"k":"gambirananda","t":"Fix your mind on Me, be devoted to Me, offer sacrifices to Me, and bow down to Me. Thus, you will come to Me alone. I promise you this truth, for you are dear to Me."},{"k":"sankaranarayan","t":"Fix your mind on Me; be devoted to Me; offer oblations to Me and bow down to Me; you will come to Me alone. I promise you this truly, for you are dear to Me."}]},{"ch":18,"vn":66,"dev":"सर्वधर्मान्परित्यज्य मामेकं शरणं व्रज।अहं त्वा सर्वपापेभ्यो मोक्षयिष्यामि मा शुचः","iast":"sarva-dharmān parityajya mām ekaṁ śharaṇaṁ vraja\nahaṁ tvāṁ sarva-pāpebhyo mokṣhayiṣhyāmi mā śhuchaḥ","v":[{"k":"purohit","t":"Give up your earthly duties, surrender yourself to Me alone. Do not be anxious; I will absolve you from all your sins."},{"k":"sivananda","t":"Abandon all duties and take refuge in Me alone; I will liberate you from all sins; do not grieve."},{"k":"adidevananda","t":"Relinquishing all Dharmas completely, seek Me alone for refuge. I will release you from all sins; grieve not."},{"k":"gambirananda","t":"Abandon all forms of rites and duties, and take refuge in Me alone. I will free you from all sins; do not grieve."},{"k":"sankaranarayan","t":"Abandon all attributes and come to Me as your only refuge; I will rescue you from all sins; do not be sorrowful."},{"k":"arnold","t":"And let go those--\nRites and writ duties! Fly to Me alone!\nMake Me thy single refuge! I will free\nThy soul from all its sins! Be of good cheer!"}]},{"ch":18,"vn":67,"dev":"इदं ते नातपस्काय नाभक्ताय कदाचन।न चाशुश्रूषवे वाच्यं न च मां योऽभ्यसूयति","iast":"idaṁ te nātapaskyāya nābhaktāya kadāchana\nna chāśhuśhruṣhave vāchyaṁ na cha māṁ yo 'bhyasūtayi","v":[{"k":"purohit","t":"Do not speak this to one who has not practiced austerities, or to one who does not love, or who will not listen, or who mocks."},{"k":"sivananda","t":"Never speak this to one who is devoid of austerities or devotion, who does not render service, who does not desire to listen, or who cavils at Me."},{"k":"adidevananda","t":"Never should this be told by you to one who is not austere, who is not a devotee, nor to one who has no desire to listen, nor certainly to him who speaks ill of Me."},{"k":"gambirananda","t":"This (that I have taught) should never be taught to one who is devoid of austerities, one who is not a devotee, one who does not render service, or one who cavils at Me."},{"k":"sankaranarayan","t":"This knowledge is for you, and it should never be imparted to one who does not observe austerities; to one who has no devotion; to one who has no desire to listen; and to one who is indignant towards Me."}]},{"ch":18,"vn":68,"dev":"य इमं परमं गुह्यं मद्भक्तेष्वभिधास्यति।भक्ितं मयि परां कृत्वा मामेवैष्यत्यसंशयः","iast":"ya idaṁ paramaṁ guhyaṁ mad-bhakteṣhv abhidhāsyati\nbhaktiṁ mayi parāṁ kṛitvā mām evaiṣhyaty asanśhayaḥ","v":[{"k":"purohit","t":"But he who teaches this great secret to My devotees, his is the highest devotion, and he shall surely come to Me."},{"k":"sivananda","t":"He who, with supreme devotion to Me, teaches this supreme secret to My devotees, shall undoubtedly come to Me."},{"k":"adidevananda","t":"He who proclaims this supreme mystery among My devotees shall come to Me, acquiring supreme devotion towards Me. There is no doubt about this."},{"k":"gambirananda","t":"He who, entertaining supreme devotion to Me, speaks of this highest secret to My devotees, will without doubt reach Me alone."},{"k":"sankaranarayan","t":"Whoever declares this highest secret to My devotees, cultivating an utmost devotion towards Me and not entertaining any doubt, shall reach Me."}]},{"ch":18,"vn":69,"dev":"न च तस्मान्मनुष्येषु कश्िचन्मे प्रियकृत्तमः।भविता न च मे तस्मादन्यः प्रियतरो भुवि","iast":"na cha tasmān manuṣhyeṣhu kaśhchin me priya-kṛittamaḥ\nbhavitā na cha me tasmād anyaḥ priyataro bhuvi","v":[{"k":"purohit","t":"There is no one among men who can perform a service dearer to Me than this, nor is there any man on earth more beloved by Me than him."},{"k":"sivananda","t":"There is no one among men who does service dearer to Me, nor shall there be anyone on earth dearer to Me than him."},{"k":"adidevananda","t":"There is no one among men who does dearer service to Me than him. Nor shall there be anyone on earth dearer to Me than him."},{"k":"gambirananda","t":"And compared to him, no other human is better at accomplishing what is dear to Me. Furthermore, there will be no one else in the world dearer to Me than him."},{"k":"sankaranarayan","t":"And, except for him, there would be no one among men who is the best performer of what is dear to Me; and there shall be no one else dearer to Me on earth."}]},{"ch":18,"vn":70,"dev":"अध्येष्यते च य इमं धर्म्यं संवादमावयोः।ज्ञानयज्ञेन तेनाहमिष्टः स्यामिति मे मतिः","iast":"adhyeṣhyate cha ya imaṁ dharmyaṁ saṁvādam āvayoḥ\njñāna-yajñena tenāham iṣhṭaḥ syām iti me matiḥ","v":[{"k":"purohit","t":"He who will study this spiritual discourse of ours, I assure you, they shall thereby worship Me at the altar of Wisdom."},{"k":"sivananda","t":"And he who studies this sacred dialogue of ours, by him I shall have been worshipped through the sacrifice of wisdom; such is my conviction."},{"k":"adidevananda","t":"And he who will study our dialogue, which is consistent with Dharma, by him I shall be worshipped through the sacrifice of knowledge; that is My view."},{"k":"gambirananda","t":"And he who will study this sacred conversation between us two, which is conducive to virtue, by him I shall be adored through the Sacrifice of Knowledge. This is My judgment."},{"k":"sankaranarayan","t":"Whoever would learn this sacred dialogue of both of us, by them I am delighted through the knowledge-sacrifice: This is my opinion."}]},{"ch":18,"vn":71,"dev":"श्रद्धावाननसूयश्च श्रृणुयादपि यो नरः।सोऽपि मुक्तः शुभाँल्लोकान्प्राप्नुयात्पुण्यकर्मणाम्","iast":"śhraddhāvān anasūyaśh cha śhṛiṇuyād api yo naraḥ\nso 'pi muktaḥ śhubhāl lokān prāpnuyāt puṇya-karmaṇām","v":[{"k":"purohit","t":"Yes, he who listens to it with faith and without doubt, even he, freed from evil, will rise to the worlds which the virtuous attain through righteous deeds."},{"k":"sivananda","t":"Also, the man who hears this, full of faith and free from malice, shall attain to the happy worlds of those of righteous deeds, and be liberated."},{"k":"adidevananda","t":"And the man who listens to it with faith and without cavil, he too shall be released and shall reach the auspicious realms of those who have performed virtuous deeds."},{"k":"gambirananda","t":"Any man who, being reverent and free from caviling, listens to this (teaching) with reverence, he too, becoming free, shall attain the blessed worlds of those who perform virtuous deeds."},{"k":"sankaranarayan","t":"A man who would at least hear this with faith and without indignation—he too, freed from sins, will attain the auspicious worlds of those who have performed meritorious acts."}]},{"ch":18,"vn":72,"dev":"कच्चिदेतच्छ्रुतं पार्थ त्वयैकाग्रेण चेतसा।कच्चिदज्ञानसंमोहः प्रनष्टस्ते धनञ्जय","iast":"kachchid etach chhrutaṁ pārtha tvayaikāgreṇa chetasā\nkachchid ajñāna-sammohaḥ pranaṣhṭas te dhanañjaya","v":[{"k":"purohit","t":"O Arjuna, have you listened attentively to My words? Has your ignorance and delusion gone?"},{"k":"sivananda","t":"Has this been heard, O Arjuna, with one-pointed focus? Has the delusion of your ignorance been destroyed, O Dhananjaya?"},{"k":"adidevananda","t":"Have you heard this, O Arjuna, with a single-minded focus? Has your delusion, caused by ignorance, been dispelled?"},{"k":"gambirananda","t":"O Partha, have you listened to this with a one-pointed mind? O Dhananjaya, has your delusion caused by ignorance been dispelled?"},{"k":"sankaranarayan","t":"O son of Prtha! Have you heard this with an attentive mind? O Dhananjaya! Has your strong delusion, born of ignorance, been completely destroyed?"}]},{"ch":18,"vn":73,"dev":"अर्जुन उवाचनष्टो मोहः स्मृतिर्लब्धा त्वत्प्रसादान्मयाच्युत।स्थितोऽस्मि गतसन्देहः करिष्ये वचनं तव","iast":"arjuna uvācha\nnaṣhṭo mohaḥ smṛitir labdhā tvat-prasādān mayāchyuta\nsthito 'smi gata-sandehaḥ kariṣhye vachanaṁ tava","v":[{"k":"purohit","t":"Arjuna replied: \"My Lord! O Immutable One! My delusion has fled. By Your Grace, O Changeless One, the light has dawned. My doubts have been dispelled, and I stand before You ready to do Your will.\""},{"k":"sivananda","t":"Arjuna said, \"My delusion has been destroyed, for I have gained my knowledge (memory) through Your grace, O Krishna. I am now free from doubts. I will act according to Your word.\""},{"k":"adidevananda","t":"Arjuna said, \"My delusion has been destroyed, and, by Your grace, O Krsna, I have gained knowledge (Smrti). Freed from doubts, I stand steadfast, and I will fulfill Your will.\""},{"k":"gambirananda","t":"Arjuna said, \"O Acyuta, my delusion has been destroyed and my memory has been regained through Your grace. I stand with my doubt removed; I shall follow Your instructions.\""},{"k":"sankaranarayan","t":"Arjuna said, \"My delusion is destroyed; I have regained my recollection through your grace, O Acyuta! I stand firm, free of doubts; I shall execute your command.\""}]},{"ch":18,"vn":74,"dev":"सञ्जय उवाचइत्यहं वासुदेवस्य पार्थस्य च महात्मनः।संवादमिममश्रौषमद्भुतं रोमहर्षणम्","iast":"sañjaya uvācha\nity ahaṁ vāsudevasya pārthasya cha mahātmanaḥ\nsaṁvādam imam aśhrauṣham adbhutaṁ roma-harṣhaṇam","v":[{"k":"purohit","t":"Sanjaya said: \"I heard this rare, wonderful, and soul-stirring discourse between Lord Shri Krishna and the great-souled Arjuna."},{"k":"sivananda","t":"Sanjaya said, Thus, I have heard this wonderful dialogue between Krishna and the high-souled Arjuna, which causes one's hair to stand on end."},{"k":"adidevananda","t":"Sanjaya said, Thus I have heard this wondrous dialogue between Vasudeva and the great-minded Arjuna, which makes my hair stand on end."},{"k":"gambirananda","t":"Sanjaya said, \"I thus heard this conversation between Vasudeva and the great-souled Partha, which is unique and makes one's hair stand on end.\""},{"k":"sankaranarayan","t":"Sanjaya said: Thus, I have heard this wonderful and thrilling dialogue between Vasudeva and the mighty-minded son of Prtha."}]},{"ch":18,"vn":75,"dev":"व्यासप्रसादाच्छ्रुतवानेतद्गुह्यमहं परम्।योगं योगेश्वरात्कृष्णात्साक्षात्कथयतः स्वयम्","iast":"vyāsa-prasādāch chhrutavān etad guhyam ahaṁ param\nyogaṁ yogeśhvarāt kṛiṣhṇāt sākṣhāt kathayataḥ svayam","v":[{"k":"purohit","t":"Through the blessing of the sage Vyasa, I heard this secret and noble science from the lips of its Master, Lord Shri Krishna."},{"k":"sivananda","t":"Through the grace of Vyasa, I have heard this supreme and most secret Yoga, directly from Krishna, the Lord of Yoga, Himself declaring it."},{"k":"adidevananda","t":"By the grace of Vyasa, I have heard this supreme mystery of Yoga, declared in person by Krsna, the Lord of Yoga."},{"k":"gambirananda","t":"Through the favor of Vyasa, I heard this secret concerning the supreme Yoga from Krishna, the Lord of Yogas, while He Himself was speaking!"},{"k":"sankaranarayan","t":"Through the grace of Vyasa, I have heard this highly secret supreme Yoga from Krsna, the Lord of Yogis, while He was imparting it personally."}]},{"ch":18,"vn":76,"dev":"राजन्संस्मृत्य संस्मृत्य संवादमिममद्भुतम्।केशवार्जुनयोः पुण्यं हृष्यामि च मुहुर्मुहुः","iast":"rājan sansmṛitya sansmṛitya saṁvādam imam adbhutam\nkeśhavārjunayoḥ puṇyaṁ hṛiṣhyāmi cha muhur muhuḥ","v":[{"k":"purohit","t":"O King! The more I think of that marvelous and holy discourse, the more I lose myself in joy."},{"k":"sivananda","t":"O King, remembering this wonderful and holy dialogue between Krishna and Arjuna, I continually rejoice."},{"k":"adidevananda","t":"O King, remembering again and again this wondrous and auspicious dialogue between Sri Krishna and Arjuna, I rejoice time and again."},{"k":"gambirananda","t":"And, O King, while repeatedly remembering this unique, sacred dialogue between Kesava and Arjuna, I rejoice every moment."},{"k":"sankaranarayan","t":"O King! By repeatedly recollecting this wonderful, pious dialogue between Kesava and Arjuna, I am filled with delight again and again."}]},{"ch":18,"vn":77,"dev":"तच्च संस्मृत्य संस्मृत्य रूपमत्यद्भुतं हरेः।\nविस्मयो मे महान् राजन् हृष्यामि च पुनः पुनः","iast":"tach cha sansmṛitya saṁsmṛitya rūpam aty-adbhutaṁ hareḥ\nvismayo ye mahān rājan hṛiṣhyāmi cha punaḥ punaḥ","v":[{"k":"purohit","t":"As I recall again and again the exceeding beauty of the Lord, I am filled with amazement and joy."},{"k":"sivananda","t":"And, remembering again and again that most wonderful form of Hari, I am filled with great wonder, O King; and I rejoice again and again."},{"k":"adidevananda","t":"And, remembering over and over again that most marvelous form of Hari, great is my amazement, O King, and I rejoice again and again."},{"k":"gambirananda","t":"O King, repeatedly recollecting that greatly extraordinary form of Hari, I am struck with wonder and rejoice again and again."},{"k":"sankaranarayan","t":"O great king! On recalling in my mind that extremely wonderful, supreme form of Hari, I am amazed and experience joy again and again."}]},{"ch":18,"vn":78,"dev":"यत्र योगेश्वरः कृष्णो यत्र पार्थो धनुर्धरः।\nतत्र श्रीर्विजयो भूतिर्ध्रुवा नीतिर्मतिर्मम।।18.78।","iast":"yatra yogeśhvaraḥ kṛiṣhṇo yatra pārtho dhanur-dharaḥ\ntatra śhrīr vijayo bhūtir dhruvā nītir matir mama","v":[{"k":"purohit","t":"Wherever Lord Shri Krishna, the Prince of Wisdom, and Arjuna, the Great Archer, are, I am certain that good fortune, victory, happiness, and righteousness will follow."},{"k":"sivananda","t":"Wherever Krishna, the Lord of Yoga, is; and wherever Arjuna, the wielder of the bow, is; there is prosperity, victory, happiness, and a firm policy; this is my conviction."},{"k":"adidevananda","t":"Wherever there is Sri Krsna, the Lord of Yoga, and Arjuna the archer, there is always fortune, victory, wealth, and sound morality. This is my firm conviction."},{"k":"gambirananda","t":"Where there is Krishna, the Lord of yogas, and where there is Partha, the wielder of the bow, there is fortune, victory, prosperity, and unfailing prudence. Such is my conviction."},{"k":"sankaranarayan","t":"Where Krishna, the Lord of Yogis, remains, where the son of Prtha holds his bow, there lies fortune, victory, prosperity, and firm justice—so I believe."}]}]};
